        DEFW    RAISE_GRAPHICS_STATEMENT_NOT_IMPLEMENTED  ; HPLOT -> not-implemented stub
        DEFW    RAISE_GRAPHICS_STATEMENT_NOT_IMPLEMENTED  ; HCOLOR-> not-implemented stub
    ENDIF
