L_0CC3:
        DEFS    10, $00                  ; fill
        DEFS    16, $00                  ; fill
L_0CDD:
        DEFB    "\0\0\0\0\0\0"
L_0CE3:
        DEFB    "\0"
L_0CE4:
        DEFS    9, $00                   ; fill
L_0CED:
        DEFB    " in "
EMPTY_STRING_DESC:
        DEFB    "\0"
; [RE] The 'Ok' ready-prompt string (Ok CR LF NUL), printed by the READY loop / direct-mode return.
MSG_OK:
        DEFB    "Ok\r\n\0"
; [RE] The 'Break' message string, printed by STOP / Ctrl-C ('Break' [+ ' in <line>']).
MSG_BREAK:
        DEFB    "Break"                  ; string
        DEFB    $00                      ; terminator
; [RE] Entry to FOR/GOSUB stack-frame fixup: HL = SP+4, fall into STKFRAME_SCAN to walk the runtime stack.
STKFRAME_SCAN_INIT:
        LD HL,$0004
        ADD HL,SP
; [RE] Walk runtime stack frames: skip FOR frames (token $AF, +16/+6 bytes), find GOSUB markers ($82), compare each frame's text pointer vs HL via FNDLIN-cmp ($691F) to fix up frames after a program edit/delete.
STKFRAME_SCAN:
        LD A,(HL)
        INC HL
        CP $AF
STKFRAME_SCAN_1:
        JR NZ,STKFRAME_SCAN_3
        LD BC,$0006
        ADD HL,BC
STKFRAME_SCAN_2:
        JR STKFRAME_SCAN
STKFRAME_SCAN_3:
        CP $82
        RET NZ
        LD C,(HL)
        INC HL
        LD B,(HL)
        INC HL
        PUSH HL
        LD L,C
        LD H,B
        LD A,D
        OR E
        EX DE,HL
        JR Z,STKFRAME_SCAN_5
        EX DE,HL
STKFRAME_SCAN_4:
        CALL CMP_HL_DE
STKFRAME_SCAN_5:
        LD BC,$0010
        POP HL
        RET Z
        ADD HL,BC
        JR STKFRAME_SCAN
SUB_0D28:
        LD BC,ERROR_RESUME_FROM_DIRECT_3+1
        JP ERROR_PRINT_SETUP_1
; [RE] PROGRAM_END: reached from NEWSTT (JP Z) when a line link is $0000 -- execution ran off the end of the program. If SAVTXT is $FFFF (direct mode), fall through to the ready/Ok-prompt return; otherwise, if an error handler is active (ONEFLG set) it ran off the end without RESUME, so raise 'No RESUME' (ERR_NO_RESUME). The CONT command and its 'Can't continue' error live in STMT_CONT, not here.
PROGRAM_END:
        LD HL,(SAVTXT)
        LD A,H
        AND L
        INC A
        JR Z,PROGRAM_END_1
        LD A,(ONEFLG)
        OR A
        LD E,ERR_NO_RESUME
        JR NZ,RAISE_ERROR
PROGRAM_END_1:
        JP RESUME_AT_DIRECT
; Named-error entry stubs: each loads an error code into E (LD E,ERR_* via the $1E opcode of the next LD BC) then falls through to RAISE_ERROR. Overlapping table of error vectors -- code JPs to a specific entry to raise that error.
RAISE_DISK_FULL:
        LD E,ERR_DISK_FULL               ; raise error 61
        DEFB    $01                      ; LD BC opcode = skip the next LD E
RAISE_DISK_I_O_ERROR:
        LD E,ERR_DISK_I_O_ERROR          ; raise error 57
        DEFB    $01                      ; LD BC opcode = skip the next LD E
RAISE_BAD_FILE_MODE:
        LD E,ERR_BAD_FILE_MODE           ; raise error 54
        DEFB    $01                      ; LD BC opcode = skip the next LD E
RAISE_FILE_NOT_FOUND:
        LD E,ERR_FILE_NOT_FOUND          ; raise error 53
        DEFB    $01                      ; LD BC opcode = skip the next LD E
RAISE_BAD_FILE_NUMBER:
        LD E,ERR_BAD_FILE_NUMBER         ; raise error 52
        DEFB    $01                      ; LD BC opcode = skip the next LD E
RAISE_INTERNAL_ERROR:
        LD E,ERR_INTERNAL_ERROR          ; raise error 51
        DEFB    $01                      ; LD BC opcode = skip the next LD E
RAISE_INPUT_PAST_END:
        LD E,ERR_INPUT_PAST_END          ; raise error 62
        DEFB    $01                      ; LD BC opcode = skip the next LD E
RAISE_FILE_ALREADY_OPEN:
        LD E,ERR_FILE_ALREADY_OPEN       ; raise error 55
        DEFB    $01                      ; LD BC opcode = skip the next LD E
RAISE_BAD_FILE_NAME:
        LD E,ERR_BAD_FILE_NAME           ; raise error 64
        DEFB    $01                      ; LD BC opcode = skip the next LD E
RAISE_BAD_RECORD_NUMBER:
        LD E,ERR_BAD_RECORD_NUMBER       ; raise error 63
        DEFB    $01                      ; LD BC opcode = skip the next LD E
RAISE_FIELD_OVERFLOW:
        LD E,ERR_FIELD_OVERFLOW          ; raise error 50
        DEFB    $01                      ; LD BC opcode = skip the next LD E
RAISE_TOO_MANY_FILES:
        LD E,ERR_TOO_MANY_FILES          ; raise error 67
        DEFB    $01                      ; LD BC opcode = skip the next LD E
RAISE_FILE_ALREADY_EXISTS:
        LD E,ERR_FILE_ALREADY_EXISTS     ; raise error 58
        JR RAISE_ERROR
; [RE] Restore saved program pointer ($0B50 -> $0844) on the no-continue path before re-entering the error/ready flow.
CONT_RESUME_RESTORE:
        LD HL,(DATA_LINE_TXTPTR)
        LD (SAVTXT),HL
; Syntax-error entry: LD E,ERR_SYNTAX_ERROR then fall through the coded-error table into RAISE_ERROR. Common target of statement parsers (JP RAISE_SYNTAX_ERROR).
RAISE_SYNTAX_ERROR:
        LD E,ERR_SYNTAX_ERROR            ; raise error 2
        DEFB    $01                      ; LD BC opcode = skip the next LD E
RAISE_DIVISION_BY_ZERO:
        LD E,ERR_DIVISION_BY_ZERO        ; raise error 11
        DEFB    $01                      ; LD BC opcode = skip the next LD E
RAISE_NEXT_WITHOUT_FOR:
        LD E,ERR_NEXT_WITHOUT_FOR        ; raise error 1
        DEFB    $01                      ; LD BC opcode = skip the next LD E
RAISE_DUPLICATE_DEFINITION:
        LD E,ERR_DUPLICATE_DEFINITION    ; raise error 10
        DEFB    $01                      ; LD BC opcode = skip the next LD E
RAISE_UNDEFINED_USER_FUNCTION:
        LD E,ERR_UNDEFINED_USER_FUNCTION ; raise error 18
        DEFB    $01                      ; LD BC opcode = skip the next LD E
RAISE_RESUME_WITHOUT_ERROR:
        LD E,ERR_RESUME_WITHOUT_ERROR    ; raise error 20
        DEFB    $01                      ; LD BC opcode = skip the next LD E
RAISE_OVERFLOW:
        LD E,ERR_OVERFLOW                ; raise error 6
        DEFB    $01                      ; LD BC opcode = skip the next LD E
RAISE_MISSING_OPERAND:
        LD E,ERR_MISSING_OPERAND         ; raise error 22
        DEFB    $01                      ; LD BC opcode = skip the next LD E
RAISE_TYPE_MISMATCH:
        LD E,ERR_TYPE_MISMATCH           ; raise error 13
; [RE] Raise/report error #E (entered with the error code in E). Saves the current text pointer (SAVTXT) to ERR_SAVTXT, clears the ON-ERROR/CHAIN flags (CHAIN_PRESERVE_FLAG / CHAIN_BREAK_FLAG), records the offending line in ERRLIN, then either dispatches to the ON ERROR handler or prints '?<message> Error[ in <line>]' and returns to direct mode via RESET_RUN_STATE. The message is found by scanning E entries from ERROR_MESSAGE_TABLE; the error codes are the ERR_* equates.
RAISE_ERROR:
        LD HL,(SAVTXT)
        LD (ERR_SAVTXT),HL
        XOR A
        LD (CHAIN_PRESERVE_FLAG),A
        LD (CHAIN_BREAK_FLAG),A
        LD A,H
        AND L
        INC A
        JR Z,ERROR_PRINT_SETUP
        LD (ERRLIN),HL
; [RE] ERROR_PRINT_SETUP: stages BC=ERROR_REPORT_BODY and HL=(SAVSTK), then JP RESET_RUN_STATE. Prints nothing itself; there is no '?'+mnemonic+' Error' assembly here (BASIC-80 uses full-word error messages).
ERROR_PRINT_SETUP:
        LD BC,ERROR_REPORT_BODY
ERROR_PRINT_SETUP_1:
        LD HL,(SAVSTK)
        JP RESET_RUN_STATE
; [RE] ERROR_REPORT_BODY: the error-print body, reached via RESET_RUN_STATE's RET. Indexes ERROR_MESSAGE_TABLE by the clamped/remapped error code and prints the full-word message string. There is NO packed 2-letter-mnemonic table and no ERROR_PRINT_MSG routine (those belong to the smaller 4K/8K BASIC; this is BASIC-80).
ERROR_REPORT_BODY:
        POP BC
        LD A,E
        LD C,E
        LD (ERRFLG),A
        LD HL,(OLDTXT)
        LD (RESUME_TXTPTR),HL
        EX DE,HL
        LD HL,(ERR_SAVTXT)
        LD A,H
        AND L
        INC A
        JR Z,ERROR_REPORT_BODY_1
        LD (SAVED_ERR_TXTPTR),HL
        EX DE,HL
        LD (CONT_TXTPTR),HL
ERROR_REPORT_BODY_1:
        LD HL,(ON_ERROR_LINE)
        LD A,H
        OR L
        EX DE,HL
        LD HL,ONEFLG
        JR Z,ERROR_REPORT_BODY_2
        AND (HL)
        JR NZ,ERROR_REPORT_BODY_2
        DEC (HL)
        EX DE,HL
        JP NEWSTT_NEXTLINE
ERROR_REPORT_BODY_2:
        XOR A
        LD (HL),A
        LD E,C
        LD (CTRL_O_SUPPRESS),A
        CALL PRINT_CRLF_IF_COL
        LD HL,ERROR_MESSAGE_TABLE
        LD A,E
        CP $47
        JR NC,ERROR_REPORT_BODY_3
        CP $32
        JR NC,ERROR_REPORT_BODY_4
    IFDEF GBASIC
        CP $20                           ; (printable-range upper bound)
    ELSE
        CP $21                           ;        MBASIC: +1, the code-32 graphics slot
    ENDIF
        JR C,ERROR_REPORT_BODY_5
ERROR_REPORT_BODY_3:
    IFDEF GBASIC
        LD A,$27                         ; (clamp index for codes >= $20)
    ELSE
        LD A,$26                         ;        MBASIC: -1 (one more printable slot)
    ENDIF
ERROR_REPORT_BODY_4:
    IFDEF GBASIC
        SUB $12                          ; (disk-code -> message-index bias)
    ELSE
        SUB $11                          ;        MBASIC: -1, the code-32 graphics slot
    ENDIF
        LD E,A
ERROR_REPORT_BODY_5:
        CALL STMT_DATA+2
        INC HL
        DEC E
        JR NZ,ERROR_REPORT_BODY_5
        PUSH HL
ERROR_REPORT_BODY_6:
        LD HL,(ERR_SAVTXT)
        EX (SP),HL
; [RE] After error message: if current line is direct (text begins '?'), point at the canned direct-mode message ($0521); else print ' in <line>' and drop to READY.
ERROR_RESUME_FROM_DIRECT:
        LD A,(HL)
        CP $3F
        JR NZ,STOP_BREAK
        POP HL
        LD HL,ERROR_MESSAGE_TABLE
        JR ERROR_REPORT_BODY_3
; [RE] STOP/Ctrl-C break: print 'Break' message ($6C40 STROUT), compute/print the current line number, then fall into the READY prompt and NEWSTT main loop.
STOP_BREAK:
        CALL STROUT
        POP HL
        LD DE,$FFFE
        CALL CMP_HL_DE
        CALL Z,CRLF
        JP Z,STMT_SYSTEM_WBOOT
        LD A,H
        AND L
        INC A
ERROR_RESUME_FROM_DIRECT_2:
        CALL NZ,PRINT_IN_LINENO
ERROR_RESUME_FROM_DIRECT_3:
        DEFB    $3E                      ; LD A,# cover -- the fall-through loads A=$C1 from the next byte
; ----------------------------------------------------------------------
; READY_POP_FRAME -- discard one stacked word, then fall into the READY prompt loop.
;   In:        SP -> a 2-byte word to be discarded (a stale return/expression frame left by an
;              aborted statement, e.g. a LIST that ran to end-of-program via JP C,READY_POP_FRAME).
;   Out:       Falls into NEWSTT_READY (never returns to a caller).
;   Clobbers:  BC (loaded with the popped word), then everything NEWSTT_READY clobbers.
;   Algorithm: POP BC throws away the top stack word so the interpreter restarts with a clean stack,
;              then drops into the main READY loop. Reached via JP/JR from several tails (LIST done,
;              error/quit paths). It is also entered one byte early as the $C1 operand of the
;              'DEFB $3E' (LD A,#) cover at ERROR_RESUME_FROM_DIRECT_3: that cover's straight-line
;              fall-through instead executes 'LD A,$C1' (coded overlap).
;   [RE] The fall-through value A=$C1 is described elsewhere as a default prompt char; that role is
;        not confirmed by these bytes -- treat the prompt-char reading as inference, not OBSERVED.
; ----------------------------------------------------------------------
READY_POP_FRAME:
        ; Drop the stale top-of-stack word so the READY loop restarts with a balanced stack.
        POP BC                           ; the LD operand byte, entered here as an opcode (coded overlap)
; ----------------------------------------------------------------------
; NEWSTT_READY -- main READY loop: reset output state, print 'Ok', then read/process a console line.
;   In:        Entered after a statement error, a STOP/END, program completion, or a direct line.
;   Out:       Does not return; falls into DIRECT_LINE_DISPATCH to classify the next console line
;              (edit/insert a numbered line, or execute a direct statement).
;   Clobbers:  AF,BC,DE,HL,SP (full interpreter reset).
;   Algorithm: Reset the output column (OUTDO_RESET_COL), clear the CTRL_O_SUPPRESS cell, run the
;              load/file cleanup + run-state reset (LOAD_CLEANUP_RESET), emit a CRLF if mid-line
;              (PRINT_CRLF_IF_COL), then print MSG_OK ('Ok',CR,LF) through the cold-patched STROUT
;              call vector (NEWSTT_READY_1). Then re-read ERRFLG and, at NEWSTT_READY_2, if it is 2
;              resume the line editor before falling into DIRECT_LINE_DISPATCH.
;   [RE] CTRL_O_SUPPRESS is named for a Ctrl-O print-suppress flag; the file's own notes on the
;        related PRTFLG cell flag a suppress-vs-printer-select ambiguity, so treat 'clears the
;        Ctrl-O suppress flag' as inference for this cell's exact semantics.
; ----------------------------------------------------------------------
NEWSTT_READY:
        ; Return the console to the start of a fresh line before prompting.
        CALL OUTDO_RESET_COL
        XOR A
        LD (CTRL_O_SUPPRESS),A
        ; Close the open file, reset print state, and re-establish the run-state stack.
        CALL LOAD_CLEANUP_RESET
        CALL PRINT_CRLF_IF_COL
        ; Point at the 'Ok' ready-prompt string for the print call below.
        LD HL,MSG_OK
; ----------------------------------------------------------------------
; NEWSTT_READY_1 -- print the message at HL through the cold-patched STROUT call vector.
;   In:        HL -> a NUL-terminated message string (e.g. MSG_OK from NEWSTT_READY).
;   Out:       The string is printed; execution continues at the following LD A,(ERRFLG).
;   Clobbers:  per STROUT.
;   Algorithm: A 'CALL <vector>' whose 16-bit operand is the data cell STROUT_CALL_VECTOR. The
;              on-disk operand is $0000; cold start patches it ONCE to STROUT ($6C40) (single writer
;              at $83E8, confirmed by byte scan) and never re-points it, so after init this is
;              effectively 'CALL STROUT'. The $CD opcode is emitted as a DEFB so the next word can
;              serve as both the CALL operand and the named data cell.
;   [RE] Why the original used a patchable cell here instead of a direct CALL is not determinable
;        from the bytes.
; ----------------------------------------------------------------------
NEWSTT_READY_1:
        DEFB    $CD                      ; LL opcode -- target word self-modified at runtime (patched via LD (next),HL)
; [RE] Self-modified operand word of the CALL at $0E33 in the prompt/message print path (LD HL,<msg> / CALL through here). The cold sign-on patches it ONCE to STROUT ($6C40), via LD HL,STROUT / LD (STROUT_CALL_VECTOR),HL at $83E8 -- byte-scan confirms a SINGLE writer in both builds and it is never re-pointed, so after init the call is effectively CALL STROUT, not a runtime-varying dispatch. The indirection is NOT an address-resolution workaround: low-RAM JPs into the relocated body directly elsewhere (e.g. JP RESET_RUN_STATE = $68F4 at $0DA4). Why the original used a patchable cell here rather than a direct CALL is not determinable from the bytes. Init $0000.
STROUT_CALL_VECTOR:
        DEFW    $0000                    ; the patched CALL target (init $0000)
        LD A,(ERRFLG)
; ----------------------------------------------------------------------
; NEWSTT_READY_2 -- post-'Ok' tail: if ERRFLG==2 run the line editor, then process the input line.
;   In:        A = ERRFLG (the value just loaded by NEWSTT_READY).
;   Out:       Falls into DIRECT_LINE_DISPATCH to read and classify the next console line.
;   Clobbers:  AF,DE,HL (plus whatever STMT_EDIT_LINENUM touches).
;   Algorithm: SUB 2 from A; if the result is zero (ERRFLG==2) CALL STMT_EDIT_LINENUM to re-enter
;              the line editor, then continue into DIRECT_LINE_DISPATCH for the normal
;              read/tokenize/execute path.
;   [RE] ERRFLG==2 selecting a deferred-EDIT re-entry is inferred from the conditional editor call;
;        the exact ERRFLG code map is not asserted here.
; ----------------------------------------------------------------------
NEWSTT_READY_2:
        ; Test ERRFLG against 2 (Z set means the EDIT-pending case).
        SUB $02
        ; ERRFLG==2: re-enter the line editor before reading the next input line.
        CALL Z,STMT_EDIT_LINENUM
; [RE] Process the input line: FOUT the leading line number, FNDLIN to locate it, CRUNCH-tokenize ($3000), then insert/replace/delete in the program or execute as a direct statement.
DIRECT_LINE_DISPATCH:
        LD HL,$FFFF
        LD (SAVTXT),HL
        LD A,(AUTFLG)
        OR A
        JR Z,SUB_0E7B_2
        LD HL,(AUTLIN)
        PUSH HL
        CALL FOUT
        POP DE
        PUSH DE
        CALL FNDLIN
        LD A,$2A
        JR C,DIRECT_LINE_DISPATCH_1
        LD A,$20
DIRECT_LINE_DISPATCH_1:
        CALL OUTCHR
        CALL INLIN_RESET_LINE
        POP DE
        JR NC,DIRECT_LINE_DISPATCH_3
        XOR A
        LD (AUTFLG),A
        JR NEWSTT_READY
DIRECT_LINE_DISPATCH_2:
        XOR A
        LD (AUTFLG),A
        JR SUB_0E7B_1
DIRECT_LINE_DISPATCH_3:
        LD HL,(AUTINC)
        ADD HL,DE
        JR C,DIRECT_LINE_DISPATCH_2
        PUSH DE
        LD DE,$FFF9
        CALL CMP_HL_DE
        POP DE
        JR NC,DIRECT_LINE_DISPATCH_2
        LD (AUTLIN),HL
SUB_0E7B_1:
        LD A,(BUF)
        OR A
        JR Z,DIRECT_LINE_DISPATCH
        JP PRINT_LIST_ENTRY
SUB_0E7B_2:
        CALL INLIN_RESET_LINE
        JR C,DIRECT_LINE_DISPATCH
        CALL CHRGET
        INC A
        DEC A
        JR Z,DIRECT_LINE_DISPATCH
        PUSH AF
        CALL LINGET
        CALL CRUNCH_SKIP_BLANKS_BACK
        LD A,(HL)
        CP $20
        CALL Z,FP_LOAD_DONE
; [RE] Execute a tokenized direct-mode statement: CHRGET-prime and call the statement dispatcher; on a bare line number fall to edit/insert.
DIRECT_EXEC_STMT:
        PUSH DE
        CALL CRUNCH
        POP DE
        POP AF
        LD (OLDTXT),HL
        JP NC,DIRECT_STMT_EXEC
        PUSH DE
        PUSH BC
        CALL ILLEGAL_DIRECT_CHECK
        CALL CHRGET
        OR A
        PUSH AF
        EX DE,HL
        LD (ERRLIN),HL
        EX DE,HL
        CALL FNDLIN
        JR C,SUB_0EB7_1
        POP AF
        PUSH AF
        JP Z,ERROR_UL
        OR A
SUB_0EB7_1:
        PUSH BC
        PUSH AF
        PUSH HL
        CALL RENUM_FIXUP_IF_PENDING
        POP HL
        POP AF
        POP BC
        PUSH BC
        CALL C,BLOCK_MOVE_TO_VARTAB
        POP DE
        POP AF
        PUSH DE
        JR Z,SUB_0EB7_4
        POP DE
        LD A,(CHAIN_BREAK_FLAG)
        OR A
        JR NZ,SUB_0EB7_2
        LD HL,(MEMSIZ)
        LD (FRETOP),HL
SUB_0EB7_2:
        LD HL,(VARTAB)
        EX (SP),HL
        POP BC
        PUSH HL
        ADD HL,BC
        PUSH HL
        CALL STR_COPY_DOWN
        POP HL
        LD (VARTAB),HL
        EX DE,HL
        LD (HL),H                        ; store a BASLINE.LINK placeholder here; CHEAD ($0F39) rebuilds the real forward link
        POP BC
        POP DE
        PUSH HL
        INC HL
        INC HL
        LD (HL),E                        ; write BASLINE.LINENUM (the two INC HL at $0EFF/$0F00 skipped past BASLINE.LINK)
        INC HL
        LD (HL),D
        INC HL
        LD DE,KBUF
        DEC BC
        DEC BC
        DEC BC
        DEC BC
SUB_0EB7_3:
        LD A,(DE)
        LD (HL),A
        INC HL
        INC DE
        DEC BC
        LD A,C
        OR B
        JR NZ,SUB_0EB7_3
SUB_0EB7_4:
        POP DE
        CALL CHEAD_LOOP
        LD HL,$0080
        LD (HL),$00
SUB_0EB7_5:
        LD (FILTAB),HL
        LD HL,(PTRFIL)
        LD (FOUT_DP_POSITION),HL
        CALL CLEAR_RESET_DATAPTR
        LD HL,(FILTAB_SLOT0_SEED)
        LD (FILTAB),HL
        LD HL,(FOUT_DP_POSITION)
        LD (PTRFIL),HL
        JP DIRECT_LINE_DISPATCH
; [RE] CHEAD: relink the BASLINE program-line list from TXTTAB ($0846). Walk each node to its $00 token terminator and rewrite its BASLINE.LINK (the forward-link word) to address the next node, so the singly-linked chain stays contiguous after an insert/delete; stops at the $0000 link (end of program). See msbasic_line.inc.
CHEAD:
        LD HL,(TXTTAB)
        EX DE,HL
; [RE] CHEAD scan loop: for each line walk to its terminating $00, fold embedded tokens, and write the next-line link pointer; stop at the program's double-zero end marker.
CHEAD_LOOP:
        LD H,D
        LD L,E
        LD A,(HL)                        ; read BASLINE.LINK low (OR its high byte next: a $0000 link = end of program)
        INC HL
        OR (HL)
        RET Z
        INC HL
        INC HL
CHEAD_LOOP_1:
        INC HL
        LD A,(HL)
CHEAD_LOOP_2:
        OR A
        JR Z,CHEAD_LOOP_3
        CP $20
        JR NC,CHEAD_LOOP_1
        CP $0B
        JR C,CHEAD_LOOP_1
        CALL CHRGOT
        CALL CHRGET
        JR CHEAD_LOOP_2
CHEAD_LOOP_3:
        INC HL
        EX DE,HL
        LD (HL),E                        ; write the rebuilt BASLINE.LINK (forward link to the next node)
        INC HL
        LD (HL),D
        JR CHEAD_LOOP
; [RE] Parse an optional 'start[-end]' line-number range (LIST/DELETE): get first line# ($34D5), accept ',' / '-' ($F3) separator, get second; syntax-error to $0D6F on malformed input.
SCAN_LINE_RANGE:
        LD DE,$0000
        PUSH DE
        JR Z,SCAN_LINE_RANGE_2
        POP DE
        CALL LINGET_DOT
        PUSH DE
        JR Z,SCAN_LINE_RANGE_3
        LD A,(HL)
        CP $2C
        JR Z,SCAN_LINE_RANGE_1
        CP TOK_MINUS
        JP NZ,RAISE_SYNTAX_ERROR
SCAN_LINE_RANGE_1:
        CALL CHRGET
SCAN_LINE_RANGE_2:
        LD DE,$FFFA
        CALL NZ,LINGET_DOT
        JP NZ,RAISE_SYNTAX_ERROR
SCAN_LINE_RANGE_3:
        EX DE,HL
        POP DE
; [RE] FNDLIN entry that takes the line number already in DE (via the stack) before searching the program.
FNDLIN_FROM_TEXT:
        EX (SP),HL
        PUSH HL
; FNDLIN: find a program line by number -- walk the singly-linked BASLINE list from TXTTAB ($0846) via each node's BASLINE.LINK, comparing BASLINE.LINENUM against the target; returns C set/clear and BC = the prior node (the insert point). A $0000 BASLINE.LINK ends the search (past end of program). See msbasic_line.inc.
FNDLIN:
        LD HL,(TXTTAB)
; FNDLIN inner loop: follow each node's BASLINE.LINK, load its BASLINE.LINENUM, FNDLIN-compare vs target; return when found or when the number passes the target.
FNDLIN_LOOP:
        LD B,H
        LD C,L
        LD A,(HL)                        ; read BASLINE.LINK low byte (BC = this node, the prospective insert point)
        INC HL
        OR (HL)                          ; OR BASLINE.LINK high byte: a $0000 link = end of program -> return
        DEC HL
        RET Z
        INC HL                           ; advance past BASLINE.LINK to BASLINE.LINENUM (+2)
        INC HL
        LD A,(HL)                        ; read BASLINE.LINENUM (low here, high at $0F96) to compare vs target
        INC HL
        LD H,(HL)
        LD L,A
        CALL CMP_HL_DE
        LD H,B
        LD L,C
        LD A,(HL)
        INC HL
        LD H,(HL)
        LD L,A
        CCF
        RET Z
        CCF
        RET NC
        JR FNDLIN_LOOP
; [RE] Evaluate a PRINT/INPUT-style item with optional '#'(file/channel $23) prefix: CHRGOT, FRMEVL the operand ($3A75), branch on numeric vs string ($3DC8), and stage it into the string/var area ($0B6F).
EVAL_CHANNEL_OR_ITEM:
        CALL CHRGOT
        CP $23
        RET Z
        PUSH HL
        CALL FRMEVL_NOPAREN
        CALL FRMEVL_TEST_TYPE
        JR Z,EVAL_CHANNEL_OR_ITEM_1
        CALL FILE_NUM_TO_FCB_NZ
        POP DE
        POP DE
        JP GET_PUT_RECORD_CORE
EVAL_CHANNEL_OR_ITEM_1:
        POP HL
        CALL PTRGET_1+1
        CALL FRMEVL_TEST_TYPE
        JP NZ,ERROR_FC
        PUSH HL
        LD A,(DE)
        OR A
        JR Z,EVAL_CHANNEL_OR_ITEM_2
        PUSH DE
        EX DE,HL
        INC HL
        LD E,(HL)
        INC HL
        LD D,(HL)
        LD HL,(VARTAB)
        CALL CMP_HL_DE
        POP DE
        JR C,EVAL_CHANNEL_OR_ITEM_3+1
EVAL_CHANNEL_OR_ITEM_2:
        LD A,$01
        PUSH DE
        CALL GETSPA
        POP HL
        CALL STR_DESC_STORE
; [RE] Flag-skip: FE EB at $0FE6 is CP $EB whose $EB immediate is the EX DE,HL opcode. The new-descriptor fall-through ($0FE3 CALL STR_DESC_STORE, which RETs with HL = descriptor pointer) lands on $0FE6, where CP $EB harmlessly swallows the EX DE,HL and runs straight into LD (HL),$01. The reuse-in-place branch (JR C at $0FDA, carry from CMP_HL_DE vs VARTAB, with the descriptor pointer in DE after POP DE at $0FD9) enters at +1 ($0FE7) to execute EX DE,HL first. Both paths converge at $0FE8 LD (HL),$01. Cover is genuinely executed via fall-through; byte readings verified; MBASIC confirms identical structure at $1009.
EVAL_CHANNEL_OR_ITEM_3:
        CP $EB
        LD (HL),$01
        INC HL
        LD E,(HL)
        INC HL
        LD D,(HL)
        CALL GET_PENDING_KEY
        CALL Z,INCHR
        LD (DE),A
        POP HL
        POP BC
        RET
    IFDEF GBASIC
        DEFS    8, $00                   ; fill

; ======================================================================
; SELF-RELOCATOR (runs at load address $1000)
; ======================================================================
; ----------------------------------------------------------------------
; RELOCATE_AND_RUN -- GBASIC startup stub: lift the interpreter body up to its run address, then cold-start it.
;   In:        Reached by JP from the CP/M entry point at $0100 (TPA, GBASIC build only). The whole .COM image is loaded contiguously from $0100, so the interpreter body sits as a packed blob at its on-disk load position INTERP_LOAD_START ($100E) and must be moved before it can run at its assembled address.
;   Out:       The interpreter body (run-addresses $3000..$8482, $5483 = 21635 bytes) is copied from the load image to its assembled run location, then control transfers via JP to COLD_START ($81D3). This routine never returns.
;   Clobbers:  HL, DE, BC (all consumed by LDDR), F (LDDR clears P/V), and destination memory $3000..$8482. The stub bytes ($1000..$100D) are not touched by the copy (both source $100E..$6490 and destination $3000..$8482 lie above it). [RE] The $1000 region is reused later as the base of the hi-res page buffer (see GFX page-clear code that bases on RELOCATE_AND_RUN); inference from the layout.
;   Algorithm: One descending block copy. GBASIC is assembled with the body DISPlaced to run at $3000 while it is loaded at $100E, so the loader cannot place it; this stub relocates it at startup. It loads HL = source end $6490 (= INTERP_LOAD_START + count - 1), DE = destination end $8482 (= INTERP_COPY_END - 1), BC = count $5483 (= INTERP_COPY_END - INTERP_RUN_START), then LDDR copies BC bytes high-to-low. High-to-low is REQUIRED, not incidental: source $100E..$6490 and destination $3000..$8482 overlap in $3000..$6490 with the destination ABOVE the source, so copying downward from the top avoids overwriting source bytes before they are read. Then JP COLD_START to initialize the now-relocated interpreter.
; ----------------------------------------------------------------------
RELOCATE_AND_RUN:
        ; Source pointer = last byte of the body in the load image ($6490); LDDR copies top-down so HL/DE start at the high ends.
        LD HL,INTERP_LOAD_START+(INTERP_COPY_END-INTERP_RUN_START)-1
        LD DE,INTERP_COPY_END-1
        LD BC,INTERP_COPY_END-INTERP_RUN_START
        ; Block-copy the body from the load image up to run location $3000-$8482; descending direction is required because source and destination overlap with the destination above the source.
        LDDR
        ; Hand off to the relocated interpreter's cold-start entry ($81D3); the stub does not run again.
        JP COLD_START

INTERP_LOAD_START:           ; physical $100E -- interpreter's first .COM byte (LDDR source)
    DISP $3000               ; runs at $3000 (the $1000 relocator LDDRs it up, then JP $81D3)
    ENDIF
INTERP_RUN_START:

; ======================================================================
; TOKENIZER (CRUNCH) -- run $3000+
; ======================================================================
; ----------------------------------------------------------------------
; CRUNCH -- tokenize one source line of BASIC text into the crunch buffer.
;   In:        HL -> source text (raw input line), NUL-terminated.
;   Out:       crunched/tokenized line built at KBUF; reserved words folded to single-byte tokens, string/REM/DATA text and digits passed through. Exits through CRUNCH_FINALIZE_LINE (end-of-line) which sets A=0, appends three trailing NUL bytes, and recomputes BC = bytes-emitted for the caller; DE then points at the last of those NUL slots.
;   Clobbers:  AF, BC, DE, HL; CRUNCH_LINENUM_MODE, CRUNCH_LITERAL_MODE; the crunch buffer at KBUF.
;   Algorithm: Reset both crunch-mode flags (line-number-introducer and literal-passthrough), set the output byte budget BC=$013B (315) and aim the output pointer DE at KBUF. Then fall into the per-character scan loop (CRUNCH_SCAN): classify each source char as quote / blank / end-of-line / (when not in literal mode) a candidate reserved word, and dispatch; reserved words are folded to tokens, '?' shorthand to PRINT.
; ----------------------------------------------------------------------
CRUNCH:
        ; Clear both crunch-mode flags: not after a line-number-introducing keyword, and not in literal (REM/DATA/string) passthrough.
        XOR A
        LD (CRUNCH_LINENUM_MODE),A
        LD (CRUNCH_LITERAL_MODE),A
        ; Remaining output budget = 315 bytes; CRUNCH_EMIT decrements it per emitted byte and raises ERR_LINE_BUFFER_OVERFLOW if it reaches 0.
        LD BC,$013B
        ; Aim the output pointer at the crunch/tokenize work buffer; the tokenized line is built forward from here.
        LD DE,KBUF
; ----------------------------------------------------------------------
; CRUNCH_SCAN -- per-character scan/dispatch at the top of the crunch loop.
;   In:        HL -> current source char; DE -> next output slot; BC = remaining output budget; CRUNCH_LITERAL_MODE = passthrough flag.
;   Out:       branches to the handler for the current char class; on a reserved-word candidate, falls into CRUNCH_RESWORD_BEGIN with A = TOK_PRINT preloaded and Z set iff the char is '?'.
;   Clobbers:  AF.
;   Algorithm: Read (HL); dispatch: '"' -> string-literal copy (CRUNCH_COPY_QUOTED); ' ' -> verbatim blank (CRUNCH_PASS_CHAR); NUL -> end-of-line finish (CRUNCH_FINALIZE_LINE). Otherwise, if literal-passthrough mode is set, copy the char verbatim (CRUNCH_PASS_CHAR); else compare the char to '?' then preload A=TOK_PRINT (the CP's Z flag survives the LD; Z => emit PRINT) before entering the reserved-word fold.
; ----------------------------------------------------------------------
CRUNCH_SCAN:
        ; Fetch the current source character (HL walks the raw input line).
        LD A,(HL)
        ; A double-quote opens a string literal: copy it through verbatim (CRUNCH_COPY_QUOTED).
        CP $22
        JP Z,CRUNCH_COPY_QUOTED
        ; A blank is copied through unchanged (CRUNCH_PASS_CHAR).
        CP $20
        JP Z,CRUNCH_PASS_CHAR
        ; NUL marks end of the source line: finish the crunched line (CRUNCH_FINALIZE_LINE).
        OR A
        JP Z,CRUNCH_FINALIZE_LINE
        ; In literal-passthrough mode (inside REM/DATA text) emit the raw char verbatim (CRUNCH_PASS_CHAR) instead of attempting a reserved-word match.
        LD A,(CRUNCH_LITERAL_MODE)
        OR A
        LD A,(HL)
        JP NZ,CRUNCH_PASS_CHAR
        ; '?' is shorthand for PRINT: this CP sets Z iff the char is '?'; the following LD A,$91 preloads TOK_PRINT without disturbing Z, so CRUNCH_RESWORD_BEGIN can emit PRINT directly.
        CP $3F
        LD A,$91
; ----------------------------------------------------------------------
; CRUNCH_RESWORD_BEGIN -- start the reserved-word fold for the current candidate.
;   In:        HL -> first char of candidate word; DE/BC = output pointer/budget; A = TOK_PRINT and Z set iff the char was '?'.
;   Out:       If '?' : emits PRINT (jumps CRUNCH_CLASSIFY_TOKEN with A=TOK_PRINT). If NOT a letter (operator/punctuation/digit) : CRUNCH_17. If a letter : either runs the 'GO TO'/'GO SUB' two-word recognizer or arms CRUNCH_RESWORD_TAIL (via LD BC,CRUNCH_RESWORD_TAIL / PUSH BC / RET) to look the word up in the keyword name table.
;   Clobbers:  AF, BC, DE, HL (saved copies of DE/BC pushed for the matcher to restore).
;   Algorithm: Save the output pointer/budget (PUSH DE / PUSH BC). If the char was '?', emit PRINT. Else upcase the current char and test it with IS_LETTER_A. If it is NOT a letter A-Z, hand it to CRUNCH_17 (operators/punctuation/digits). If it IS a letter, push HL and arm CRUNCH_RESWORD_TAIL as the continuation (LD BC,CRUNCH_RESWORD_TAIL / PUSH BC); then test for a leading 'G' to enter the 'GO TO'/'GO SUB' two-word recognizer; any non-'G' letter RETs into CRUNCH_RESWORD_TAIL for the ordinary keyword lookup.
; ----------------------------------------------------------------------
CRUNCH_RESWORD_BEGIN:
        ; Save the output pointer and budget; the keyword matcher restores them on success (token replaces the spelled-out word) or failure (word copied verbatim).
        PUSH DE
        PUSH BC
        ; '?' shorthand: emit the PRINT token (A=TOK_PRINT) and skip the table lookup.
        JP Z,CRUNCH_CLASSIFY_TOKEN
        ; [RE] Loads DE=RESWORD_OPS (operator sub-table at $04D8) but, in every path through this cluster, DE is overwritten before any read: the letter path reloads DE from RESWORD_INDEX in CRUNCH_RESWORD_TAIL; the digit path does POP DE in CRUNCH_18; and the operator path (CRUNCH_17->CRUNCH_26) reloads DE=KWGRP_Z and scans the operators itself. So this load appears dead/vestigial here. UNKNOWN why it is loaded; do not assume it feeds the operator match.
        LD DE,RESWORD_OPS
        CALL CHRGET_UPCASE
        ; Carry set means NOT 'A'..'Z': hand operators/punctuation/digits to CRUNCH_17 instead of the keyword matcher (carry clear = letter, continue the fold).
        CALL IS_LETTER_A
        JP C,CRUNCH_17
        PUSH HL
        ; Arm CRUNCH_RESWORD_TAIL as the continuation: a following RET (taken on any non-'GO' word) drops into the first-letter keyword-table lookup.
        LD BC,CRUNCH_RESWORD_TAIL
        PUSH BC
        ; Leading 'G' opens the 'GO TO'/'GO SUB' two-word recognizer; RET NZ falls through (into CRUNCH_RESWORD_TAIL) for any other first letter.
        CP $47
        RET NZ
        INC HL
        CALL CHRGET_UPCASE
        ; Require 'O' after 'G' ("GO"); otherwise abandon the two-word path (RET NZ).
        CP $4F
        RET NZ
        INC HL
        CALL CHRGET_UPCASE
        ; Require a blank after "GO" (the two-word forms are spelled "GO TO"/"GO SUB"); otherwise fall back to the keyword lookup (RET NZ).
        CP $20
        RET NZ
        INC HL
; ----------------------------------------------------------------------
; CRUNCH_GOTO_SUB_SCAN -- recognize 'GO TO' / 'GO SUB' after a confirmed leading "GO ".
;   In:        HL -> first char after "GO " (the mandatory single blank already consumed in CRUNCH_RESWORD_BEGIN).
;   Out:       On "GO SUB" -> CRUNCH_GOSUB_TAIL (GOSUB tail). On "GO TO" -> A=TOK_GOTO, then CRUNCH_GOTO_SUB_COMMIT. On anything else: RET NZ, returning into CRUNCH_RESWORD_TAIL to try an ordinary keyword.
;   Clobbers:  AF, HL.
;   Algorithm: Skip any further run of blanks after the first "GO " blank. On 'S' branch to the GOSUB recognizer (CRUNCH_GOSUB_TAIL). On 'T' continue the GOTO recognizer: read the next char (expect 'O'), preload TOK_GOTO (preserving the compare's Z), and join CRUNCH_GOTO_SUB_COMMIT which commits only if the 'O' matched. Any other char aborts the special case (RET NZ).
; ----------------------------------------------------------------------
CRUNCH_GOTO_SUB_SCAN:
        CALL CHRGET_UPCASE
        INC HL
        CP $20
        ; Allow extra blanks between "GO" and "TO"/"SUB" beyond the first mandatory one (keep skipping spaces).
        JR Z,CRUNCH_GOTO_SUB_SCAN
        ; 'S' -> the "GO SUB" recognizer (CRUNCH_GOSUB_TAIL).
        CP $53
        JR Z,CRUNCH_GOSUB_TAIL
        ; 'T' -> the "GO TO" recognizer; any other character aborts the two-word special case (RET NZ).
        CP $54
        RET NZ
        CALL CHRGET_UPCASE
        CP $4F
        ; Preload the GOTO token (does not disturb the preceding CP $4F flags); CRUNCH_GOTO_SUB_COMMIT commits it only if that 'O' matched (Z set).
        LD A,TOK_GOTO
        JR CRUNCH_GOTO_SUB_COMMIT
; ----------------------------------------------------------------------
; CRUNCH_GOSUB_TAIL -- match the 'UB' tail of 'GO SUB' and stage the GOSUB token.
;   In:        HL -> char after the 'S' of "GO S...".
;   Out:       If "...UB" matches: A=TOK_GOSUB and falls into CRUNCH_GOTO_SUB_COMMIT (commit). Otherwise RET NZ (abandon the special case, fall back to ordinary keyword lookup).
;   Clobbers:  AF, HL.
;   Algorithm: Require 'U' (RET NZ on mismatch) then 'B' after "GO S"; load TOK_GOSUB ($8D) without disturbing the 'B' compare's flags and fall through to CRUNCH_GOTO_SUB_COMMIT, which commits only when that final 'B' compared equal.
; ----------------------------------------------------------------------
CRUNCH_GOSUB_TAIL:
        CALL CHRGET_UPCASE
        ; Require 'U' after "GO S"; otherwise abandon (RET NZ) and try an ordinary keyword.
        CP $55
        RET NZ
        INC HL
        CALL CHRGET_UPCASE
        ; Require the final 'B' of "SUB"; CRUNCH_GOTO_SUB_COMMIT commits GOSUB only if this compares equal.
        CP $42
        ; Stage the GOSUB token (TOK_GOSUB=$8D) for CRUNCH_GOTO_SUB_COMMIT; the LD leaves the preceding 'B' compare's Z flag intact.
        LD A,$8D
; ----------------------------------------------------------------------
; CRUNCH_GOTO_SUB_COMMIT -- commit the recognized GOTO/GOSUB token, discarding the keyword-lookup continuation.
;   In:        A = TOK_GOTO or TOK_GOSUB; Z set iff the final keyword char matched; the stack holds (top-down) the armed CRUNCH_RESWORD_TAIL return address, then the saved HL (PUSH HL in CRUNCH_RESWORD_BEGIN), then the saved budget BC and output pointer DE.
;   Out:       On match: pops the two staged stack words (the CRUNCH_RESWORD_TAIL return address and the saved HL) and jumps to CRUNCH_CLASSIFY_TOKEN to emit the token (leaving the saved BC/DE on the stack for CRUNCH_STORE_FLAG_AND_EMIT to restore). On mismatch: RET NZ, returning into CRUNCH_RESWORD_TAIL to fall back to the ordinary keyword table lookup.
;   Clobbers:  AF, BC (two stack pops).
;   Algorithm: If the trailing char did not match (NZ), bail out via RET into the keyword-lookup continuation. Otherwise drop the CRUNCH_RESWORD_TAIL return word and the saved-HL word from the stack (the two-word form is fully matched, no table lookup needed) and emit the token through CRUNCH_CLASSIFY_TOKEN.
; ----------------------------------------------------------------------
CRUNCH_GOTO_SUB_COMMIT:
        ; Trailing char mismatched: return into CRUNCH_RESWORD_TAIL to retry as an ordinary keyword.
        RET NZ
        ; Two-word form fully matched: discard the armed CRUNCH_RESWORD_TAIL return address and the saved HL (no table lookup needed); the second POP BC drops the second of these.
        POP BC
        POP BC
        ; Emit the recognized GOTO/GOSUB token (A); CRUNCH_CLASSIFY_TOKEN matches it in its keyword list and marks it a line-number-introducing keyword.
        JP CRUNCH_CLASSIFY_TOKEN
; ----------------------------------------------------------------------
; CRUNCH_RESWORD_TAIL -- look the candidate word up in the keyword name table, indexed by its first letter.
;   In:        Reached by RET through the armed LD BC,CRUNCH_RESWORD_TAIL / PUSH BC continuation. Stack top holds the saved HL (HL -> first letter of the candidate, pushed in CRUNCH_RESWORD_BEGIN); the output pointer/budget were saved earlier (PUSH DE / PUSH BC).
;   Out:       DE -> the keyword name-table group for the candidate's first letter; HL -> the second char of the candidate (first letter consumed). Falls into the per-keyword comparison loop (CRUNCH_RESWORD_TRY_ENTRY/CRUNCH_RESWORD_CMP_LOOP).
;   Clobbers:  AF, BC, DE, HL.
;   Algorithm: Recover HL (saved candidate pointer), read+upcase its first letter (CHRGET_UPCASE does not advance HL), re-save HL, then index RESWORD_INDEX by (letter-'A')*2 to fetch the 16-bit group pointer for that letter into DE. Restore HL and INC past the first letter (which the group implies, so name entries store only the tail), then drop into the per-keyword comparison loop.
; ----------------------------------------------------------------------
CRUNCH_RESWORD_TAIL:
        ; Recover the candidate pointer saved by CRUNCH_RESWORD_BEGIN (HL -> first letter of the word).
        POP HL
        CALL CHRGET_UPCASE
        PUSH HL
        ; Base of the per-letter group-pointer table (A->Z); each entry is a 16-bit pointer to that letter's keyword group.
        LD HL,RESWORD_INDEX
        ; Convert the first letter to a 0-based index ('A'->0 ... 'Z'->25).
        SUB $41
        ; Double the index because each group pointer is two bytes.
        ADD A,A
        LD C,A
        LD B,$00
        ADD HL,BC
        ; Fetch the 16-bit pointer to this letter's keyword group into DE (E here, D from the next byte) -- the group of tail+token entries to match against.
        LD E,(HL)
        INC HL
        LD D,(HL)
        POP HL
        ; Skip the implied first letter: name-table entries store only the keyword tail, so matching starts at the candidate's second char.
        INC HL
; ----------------------------------------------------------------------
; CRUNCH_RESWORD_TRY_ENTRY -- per-candidate setup for the reserved-word name match loop
;   In:        HL = source text pointer at the 2nd character of the candidate word (the first
;              letter already selected the keyword group via RESWORD_INDEX). DE = pointer into the
;              current keyword group (KWGRP_x), positioned at the first stored character of the next
;              candidate name. Stack carries the CRUNCH_RESWORD_BEGIN-saved DE (output cursor) and BC (count).
;   Out:       Falls through to CRUNCH_RESWORD_CMP_LOOP with HL (source pointer) saved on the stack.
;   Clobbers:  none here; pushes HL.
;   Algorithm: Re-entered once per candidate name in the letter's group (looped back from
;              CRUNCH_RESWORD_NEXT_ENTRY). Pushes the source pointer so that on a mismatch (CRUNCH_RESWORD_MISMATCH) it can be
;              restored to the word start before trying the next candidate.
; ----------------------------------------------------------------------
CRUNCH_RESWORD_TRY_ENTRY:
        ; remember the word start so a mismatch can rewind to try the next keyword in this letter group
        PUSH HL
; ----------------------------------------------------------------------
; CRUNCH_RESWORD_CMP_LOOP -- compare the candidate keyword name against the source word
;   In:        HL -> current source char (uppercased on read). DE -> current char of the candidate
;              name in the keyword group. Name chars are stored ASCII with the FINAL char's high
;              bit set as terminator; the byte AFTER the terminated name is the token value; a $00
;              byte ends the letter group.
;   Out:       Full name matched: falls through with C = last matched source char and DE -> the
;              token byte, into the follow-char acceptance checks below. Char mismatch: JR CRUNCH_RESWORD_MISMATCH
;              (try next candidate). Group exhausted ($00 end marker): JP CRUNCH_COPY_IDENT (not a
;              keyword; emit verbatim).
;   Clobbers:  A, C, HL, DE.
;   Algorithm: Character loop. Reads one uppercased source char (saved in C), reads the table name
;              char and masks the terminator bit (AND $7F): a 0 result is the group-end $00 marker
;              -> word is not in this group. Otherwise compares the masked table char to C; on
;              inequality goes to the next candidate. On equality it reloads the UNMASKED table byte
;              and advances DE: high bit clear -> more name chars remain (loop); high bit set -> that
;              was the terminator (last char) and DE now points at the token byte -> fall through.
; ----------------------------------------------------------------------
CRUNCH_RESWORD_CMP_LOOP:
        ; fetch and fold the source char to uppercase for case-insensitive keyword matching
        CALL CHRGET_UPCASE
        LD C,A
        LD A,(DE)
        ; drop the name-terminator high bit; a zero result is the group-end ($00) marker = word not found in this group
        AND $7F
        ; ran off the end of the letter group with no match: treat the word as an ordinary identifier
        JP Z,CRUNCH_COPY_IDENT
        INC HL
        CP C
        ; this char differs: abandon this candidate and skip to the next keyword in the group
        JR NZ,CRUNCH_RESWORD_MISMATCH
        LD A,(DE)
        INC DE
        OR A
        ; unmasked table byte still positive: not the terminator yet, more name characters follow, keep comparing
        JP P,CRUNCH_RESWORD_CMP_LOOP
        LD A,C
        CP $28
        JR Z,CRUNCH_RESWORD_EMIT_TOKEN
        LD A,(DE)
        CP $E2
        JR Z,CRUNCH_RESWORD_EMIT_TOKEN
        CP $E1
        JR Z,CRUNCH_RESWORD_EMIT_TOKEN
        CALL CHRGET_UPCASE
        CP $2E
        JR Z,CRUNCH_RESWORD_REJECT_PREFIX
        CALL IS_ALNUM_CHAR
; ----------------------------------------------------------------------
; CRUNCH_RESWORD_REJECT_PREFIX -- reject a name match that is only a prefix of a longer identifier
;   In:        Reached after a full keyword name matched and the acceptance exceptions failed: the
;              keyword's own last char C was not '(' and its token byte was not $E1 (USR) / $E2 (FN).
;              Carry from IS_ALNUM_CHAR reports whether the NEXT source char continues an identifier;
;              the '.' branch ($2E) jumps in directly with NC (CP-equal clears carry).
;   Out:       Next source char is alphanumeric or '.' (NC): JP CRUNCH_COPY_IDENT with A=0 -> emit the
;              word as an identifier, not the keyword. Next char ends the word (C set): fall into
;              CRUNCH_RESWORD_EMIT_TOKEN to accept the token.
;   Clobbers:  A.
;   Algorithm: Pre-loads A=0 (so CRUNCH_COPY_IDENT's DEC A stores the $FF 'no line-number' sentinel) and
;              takes the verbatim-emit exit when the matched keyword is actually the start of a
;              longer variable name (e.g. 'ANDY' must not tokenize as AND followed by 'Y').
; ----------------------------------------------------------------------
CRUNCH_RESWORD_REJECT_PREFIX:
        ; seed A=0 so the verbatim-emit path (CRUNCH_COPY_IDENT DEC A) records the $FF no-line-number sentinel
        LD A,$00
        ; the word continues with another alnum/'.' char, so it is an identifier, not this keyword: emit it as text
        JP NC,CRUNCH_COPY_IDENT
; ----------------------------------------------------------------------
; CRUNCH_RESWORD_EMIT_TOKEN -- a keyword was confirmed; emit its token byte(s)
;   In:        DE -> the matched name's token byte. HL -> source char just past the keyword (the
;              advanced compare-loop pointer). Stack top = the CRUNCH_RESWORD_TRY_ENTRY-saved word-start HL
;              (discarded here).
;   Out:       Ordinary token (byte >= $80, sign bit set) case: JP M,CRUNCH_RESWORD_FIXUP_HL (back up HL then
;              classify/emit via CRUNCH_RESWORD_FIXUP_HL/14). Extended token (byte < $80) case: pops the
;              CRUNCH_RESWORD_BEGIN-saved cursor/count, emits $FF then (token|$80), clears CRUNCH_LINENUM_MODE,
;              and loops to CRUNCH_SCAN.
;   Clobbers:  A, BC, DE, HL, the crunch output cursor.
;   Algorithm: Discards the saved word-start pointer (keeps the advanced HL). Reads the token byte:
;              if its high bit is set it is a normal one-byte token -> CRUNCH_RESWORD_FIXUP_HL/CRUNCH_CLASSIFY_TOKEN. If
;              positive (< $80) it is an extended/secondary token: pops the saved cursor/count, emits
;              the $FF escape prefix, then emits the token with bit7 forced on, and resumes scanning.
; ----------------------------------------------------------------------
CRUNCH_RESWORD_EMIT_TOKEN:
        ; drop the saved word-start pointer: the match is good, keep the advanced HL
        POP AF
        LD A,(DE)
        OR A
        ; ordinary one-byte token (bit7 set): hand off to the token classifier
        JP M,CRUNCH_RESWORD_FIXUP_HL
        POP BC
        POP DE
        ; force bit7 on the stored secondary-token value
        OR $80
        PUSH AF
        ; extended token: emit the $FF escape prefix before the secondary token byte
        LD A,$FF
        CALL CRUNCH_EMIT
        XOR A
        LD (CRUNCH_LINENUM_MODE),A
        POP AF
        CALL CRUNCH_EMIT
        JP CRUNCH_SCAN
; ----------------------------------------------------------------------
; CRUNCH_RESWORD_MISMATCH -- restore the source pointer after a character mismatch
;   In:        Stack top = the CRUNCH_RESWORD_TRY_ENTRY-saved word-start HL. DE -> somewhere mid-name in the failed
;              candidate.
;   Out:       HL rewound to the word start; falls into CRUNCH_RESWORD_NEXT_ENTRY to skip past the rest of the
;              failed candidate's bytes.
;   Clobbers:  HL.
;   Algorithm: Pops the saved source pointer so the next candidate is compared from the same word
;              start (the 2nd char).
; ----------------------------------------------------------------------
CRUNCH_RESWORD_MISMATCH:
        ; rewind to the word start so the next keyword is matched from the same first letter
        POP HL
; ----------------------------------------------------------------------
; CRUNCH_RESWORD_NEXT_ENTRY -- advance DE to the next keyword entry in the group
;   In:        DE -> mid-name in the failed candidate.
;   Out:       DE -> first character of the next candidate name; jumps to CRUNCH_RESWORD_TRY_ENTRY to retry.
;   Clobbers:  A, DE.
;   Algorithm: Skips remaining name bytes (high bit clear) until it consumes the high-bit terminator
;              char, then skips the one token byte, leaving DE on the next entry. If that entry is
;              actually the trailing $00 group-end marker, CRUNCH_RESWORD_CMP_LOOP's AND-$7F test catches it next
;              pass, not here.
; ----------------------------------------------------------------------
CRUNCH_RESWORD_NEXT_ENTRY:
        LD A,(DE)
        INC DE
        OR A
        ; skip name characters until the high-bit-set terminator is passed
        JP P,CRUNCH_RESWORD_NEXT_ENTRY
        ; step over the entry's token byte; DE now points at the next keyword
        INC DE
        JR CRUNCH_RESWORD_TRY_ENTRY
; ----------------------------------------------------------------------
; CRUNCH_RESWORD_FIXUP_HL -- back up HL by one before token classification
;   In:        A = matched token byte (>= $80). HL = source char just past the keyword (left by the
;              compare loop's per-char INC HL).
;   Out:       HL decremented to point AT the keyword's last character; falls into CRUNCH_CLASSIFY_TOKEN.
;   Clobbers:  HL.
;   Algorithm: Backs HL up one so it sits on the keyword's final char; the generic emit path
;              (CRUNCH_PASS_CHAR) does a matching INC HL to step past it before writing the token. The
;              non-table entrants into CRUNCH_CLASSIFY_TOKEN ('?'->PRINT and GO TO/GO SUB) bypass this DEC HL
;              because their HL is already correctly positioned.
; ----------------------------------------------------------------------
CRUNCH_RESWORD_FIXUP_HL:
        ; rewind onto the keyword's last char (the name-compare loop overshot by one; CRUNCH_PASS_CHAR will re-advance)
        DEC HL
; ----------------------------------------------------------------------
; CRUNCH_CLASSIFY_TOKEN -- classify the just-matched token and set the line-number-mode flag
;   In:        A = token byte about to be emitted (>= $80). Entered from CRUNCH_RESWORD_FIXUP_HL for table matches,
;              and directly from the '?'->PRINT shortcut (A=$91) and the GO TO/GO SUB folder
;              (A=GOTO/GOSUB). Stack below the entry holds the CRUNCH_RESWORD_BEGIN-saved BC (count) and DE
;              (output cursor).
;   Out:       Via the cover idiom at CRUNCH_LINENUM_FLAG_COVER/CRUNCH_STORE_FLAG_AND_EMIT: A=1 (token introduces a line number) or
;              A=0 (not) is written to CRUNCH_LINENUM_MODE, then CRUNCH_STORE_FLAG_AND_EMIT handles the ELSE/apostrophe
;              special cases and finishes emitting.
;   Clobbers:  A, BC; pushes the token (PUSH AF) for CRUNCH_STORE_FLAG_AND_EMIT.
;   Algorithm: Saves the token, then pushes CRUNCH_LINENUM_FLAG_COVER+1 ($311A) as a fake return so that each
;              'CP nn / RET Z' in the ladder that MATCHES returns INTO the operand of the CRUNCH_LINENUM_FLAG_COVER
;              JP-NZ cover, executing its LD A,$01 (flag=1) and skipping the C2 jump opcode. The 14
;              listed values decode to RESTORE($8C), AUTO($A7), RENUM($A8), DELETE($A6), EDIT($A3),
;              RESUME($A5), ERL($E5), ELSE, RUN($8A), LIST($93), LLIST($9C), GOTO, THEN, GOSUB($8D)
;              -- the keywords followed by a line number. No match runs POP AF (discarding the cover
;              address) / XOR A -> flag=0.
; ----------------------------------------------------------------------
CRUNCH_CLASSIFY_TOKEN:
        ; stash the token byte; CRUNCH_STORE_FLAG_AND_EMIT re-reads it for the ELSE / apostrophe-REM cases and the final emit
        PUSH AF
        ; fake return ($311A): a matching RET Z below lands on the LD A,$01 operand of CRUNCH_LINENUM_FLAG_COVER's JP-NZ (flag=1), past the C2 jump opcode
        LD BC,CRUNCH_LINENUM_FLAG_COVER+1
        PUSH BC
        ; test the token against the line-number-introducer set (RESTORE/AUTO/RENUM/DELETE/EDIT/RESUME/ERL/ELSE/RUN/LIST/LLIST/GOTO/THEN/GOSUB)
        CP $8C
        RET Z
        CP $A7
        RET Z
        CP $A8
        RET Z
        CP $A6
        RET Z
        CP $A3
        RET Z
        CP $A5
        RET Z
        CP $E5
        RET Z
        CP TOK_ELSE
        RET Z
        CP $8A
        RET Z
        CP $93
        RET Z
        CP $9C
        RET Z
        CP TOK_GOTO
        RET Z
        CP TOK_THEN
        RET Z
        CP $8D
        RET Z
        POP AF
        ; no line-number keyword matched: clear A so CRUNCH_STORE_FLAG_AND_EMIT records flag=0
        XOR A
; ----------------------------------------------------------------------
; CRUNCH_LINENUM_FLAG_COVER -- one-byte cover whose JP-NZ operand doubles as 'flag := 1'
;   In:        Two entry forms. A matching RET Z from CRUNCH_CLASSIFY_TOKEN returns to CRUNCH_LINENUM_FLAG_COVER+1 ($311A),
;              executing the operand bytes 3E 01 ('LD A,$01'). The no-match fall-through arrives at
;              CRUNCH_LINENUM_FLAG_COVER ($3119) itself with A=0 and Z set.
;   Out:       Reaches CRUNCH_STORE_FLAG_AND_EMIT with A = 1 (line-number keyword) or A = 0 (other). The JP NZ is
;              never taken (Z is set on the fall-through entrant).
;   Clobbers:  A (on the matched path only).
;   Algorithm: Data-as-cover idiom. The C2 opcode of 'JP NZ,$013E' is the single byte the matched
;              entrant skips over by returning to +1, so the 3E 01 tail sets the flag; the unmatched
;              entrant executes the JP NZ but never branches. $013E is not a real target (it only
;              coincides with an entry in the statement dispatch table).
; ----------------------------------------------------------------------
CRUNCH_LINENUM_FLAG_COVER:
        JP NZ,$013E
; ----------------------------------------------------------------------
; CRUNCH_STORE_FLAG_AND_EMIT -- store the line-number flag, handle ELSE / apostrophe-REM, emit the token
;   In:        A = line-number flag (0 or 1) from the cover. Stack: token byte (PUSH AF in
;              CRUNCH_CLASSIFY_TOKEN), then the CRUNCH_RESWORD_BEGIN-saved BC (count) and DE (output cursor).
;   Out:       CRUNCH_LINENUM_MODE updated. ELSE ($9E) gets a leading ':' emitted. The apostrophe
;              remark token ($EA, TOK_REM_QUOTE) is rewritten to ':' + the REM token ($8F) and
;              continues into the verbatim remark-text copier (CRUNCH_EMIT_AND_LOOP). All other tokens jump to
;              CRUNCH_AMP_HEX_OCT to emit normally.
;   Clobbers:  A, BC, DE; manipulates the crunch output cursor.
;   Algorithm: Writes the flag, restores the token and output state (count/cursor), then special-
;              cases two tokens: ELSE (a statement separator, so prefix a colon) and the apostrophe
;              form of REM ($EA) which is emitted as ':' + the $8F REM token followed by the rest of
;              the line copied literally. Everything else is routed to the generic single-token
;              emitter at CRUNCH_AMP_HEX_OCT.
; ----------------------------------------------------------------------
CRUNCH_STORE_FLAG_AND_EMIT:
        ; record whether the next digits form a line number (set for GOTO/THEN/ELSE/RUN/LIST/RESTORE/... )
        LD (CRUNCH_LINENUM_MODE),A
        POP AF
        POP BC
        POP DE
        CP TOK_ELSE
        PUSH AF
        ; ELSE acts as a statement separator: emit an implicit ':' before it
        CALL Z,CRUNCH_EMIT_COLON
        POP AF
        CP $EA
        ; not the apostrophe-REM token: emit this token through the generic path
        JP NZ,CRUNCH_AMP_HEX_OCT
        PUSH AF
        CALL CRUNCH_EMIT_COLON
        ; apostrophe (') remark: after the ':' emit the canonical REM token ($8F), then copy the remark text verbatim via CRUNCH_EMIT_AND_LOOP
        LD A,TOK_REM
        CALL CRUNCH_EMIT
        POP AF
        PUSH AF
        JP CRUNCH_EMIT_AND_LOOP
; ----------------------------------------------------------------------
; CRUNCH_17 -- decide whether the current source character begins a number/line-number that CRUNCH must convert to a packed numeric token.
;   In:        HL -> current source character in the input line; reached from CRUNCH_RESWORD_BEGIN via JP C,CRUNCH_17 (IS_LETTER_A returned carry = NOT a letter). The DE(crunch-dest)/BC(remaining) pair is on the stack (DE PUSHed first, BC on top) from CRUNCH_RESWORD_BEGIN.
;   Out:       Falls into CRUNCH_18 if the char is a numeric-constant lead ('.', or a digit '0'-'9'); jumps to CRUNCH_26 (operator/punctuation reserved-word rescan) otherwise.
;   Clobbers:  A.
;   Algorithm: Re-load (HL) into A and classify: a leading '.' is accepted as a possible decimal point (JR Z,CRUNCH_18); bytes >= ':' ($3A) and bytes < '0' ($30) are not digits, so route to CRUNCH_26 which retries the char against the operator name-table (catches +-*/^=<>'\ that IS_LETTER_A rejected); '0'-'9' fall through to CRUNCH_18.
; ----------------------------------------------------------------------
CRUNCH_17:
        LD A,(HL)
        ; a leading '.' may start a fractional constant like .5 -> treat as numeric
        CP $2E
        JR Z,CRUNCH_18
        CP $3A
        ; char is >= ':' (past the digits): not a number, retry it as an operator char
        JP NC,CRUNCH_26
        CP $30
        ; char is below '0': not a digit either, retry it as an operator char
        JP C,CRUNCH_26
; ----------------------------------------------------------------------
; CRUNCH_18 -- tokenize a numeric constant or a line-number reference at (HL).
;   In:        HL -> first character of the number; CRUNCH_LINENUM_MODE ($0B16) holds the line-number-introducer flag (set to $01 when the preceding crunched token was GOTO/GOSUB/THEN/RUN/LIST/RESTORE/etc., $00 otherwise -- the only values written by CRUNCH_STORE_FLAG_AND_EMIT/CRUNCH_PASS_CHAR in normal operation); DE(dest)/BC(count) on the stack from CRUNCH_RESWORD_BEGIN.
;   Out:       Restores BC(count)/DE(dest) from the stack, then either: emits a line-number-reference token ($0E + 2-byte line number) when the flag is positive nonzero, or hands an ordinary numeric literal to CRUNCH_22 when the flag is zero. A stray '.' in line-number mode escapes to CRUNCH_PASS_CHAR (copy the char verbatim).
;   Clobbers:  A, DE, BC, HL.
;   Algorithm: OR A on CRUNCH_LINENUM_MODE sets flags that survive the LD A,(HL)/POP BC/POP DE that follow. If zero -> ordinary numeric literal (JR Z,CRUNCH_22, FIN parse + packed token). If positive nonzero (line-number mode) and the char is not '.' -> emit token $0E, CALL LINGET to read the decimal line number into DE, trim trailing blanks, and fall into CRUNCH_19/20/21 to emit the 2-byte line number. [RE] A JP M,CRUNCH_PASS_CHAR also guards the sign-bit-set case (flag value $80-$FF), but the documented flag writers only ever store $00/$01, so this passthrough branch is not exercised by those paths; UNKNOWN which writer (if any) leaves the flag negative.
; ----------------------------------------------------------------------
CRUNCH_18:
        ; is the preceding keyword one that introduces a target line number?
        LD A,(CRUNCH_LINENUM_MODE)
        OR A
        LD A,(HL)
        POP BC
        POP DE
        ; [RE] flag has its sign bit set: copy this char verbatim (documented writers store only $00/$01, so this branch is normally unreached)
        JP M,CRUNCH_PASS_CHAR
        ; ordinary numeric literal (not a line number): pack it via FIN in CRUNCH_22
        JR Z,CRUNCH_22
        CP $2E
        JP Z,CRUNCH_PASS_CHAR
        ; emit the line-number-reference token ($0E) ahead of the 2-byte line number
        LD A,$0E
        CALL CRUNCH_EMIT
        PUSH DE
        ; parse the decimal line number into DE
        CALL LINGET
        CALL CRUNCH_SKIP_BLANKS_BACK
; ----------------------------------------------------------------------
; CRUNCH_19 -- emit a 2-byte little-endian constant (line number or &-radix value) into the crunch buffer.
;   In:        DE = the 16-bit value to emit; HL -> source text continuation (just past the number); top of stack = the crunch write-cursor saved by the caller (CRUNCH_18's PUSH DE at $3161, or CRUNCH_AMP_EMIT_AND_SCAN's PUSH DE at $31E8).
;   Out:       Falls into CRUNCH_20/CRUNCH_21 which emit the value's low then high byte and resume the main scan at CRUNCH_SCAN.
;   Clobbers:  HL, DE, A.
;   Algorithm: EX (SP),HL swaps the live source pointer onto the stack and brings the saved crunch write-cursor into HL; EX DE,HL then puts the 16-bit value into HL and the write-cursor into DE. Net result entering CRUNCH_20: HL = value, DE = write-cursor, stack top = post-number source pointer (which CRUNCH_21 POPs back).
; ----------------------------------------------------------------------
CRUNCH_19:
        ; swap source pointer onto the stack; bring the saved write-cursor into HL
        EX (SP),HL
        ; move the 16-bit value into HL (and the write-cursor into DE) so CRUNCH_20/21 can emit its two bytes
        EX DE,HL
; ----------------------------------------------------------------------
; CRUNCH_20 -- emit the low byte of a 2-byte numeric token payload, then set up the high byte.
;   In:        HL = the 16-bit value to emit (L = low byte, H = high byte); DE -> crunch-buffer write cursor; BC = remaining buffer count.
;   Out:       Low byte (L) written via CRUNCH_EMIT; A loaded with H ready for CRUNCH_21 to write the high byte.
;   Clobbers:  A, DE, BC.
;   Algorithm: Write L to the output, then load A=H and fall into CRUNCH_21 to write the high byte and resume scanning. Also the join point for the integer '10 <= value <= 255' path from CRUNCH_22, where HL was pre-arranged so L = $0F (the 1-byte-integer token) and H = the value byte: here LD A,L emits the $0F token and CRUNCH_21 emits the value.
; ----------------------------------------------------------------------
CRUNCH_20:
        ; emit the low byte first (little-endian); on the CRUNCH_22 path this is the $0F 1-byte-int token
        LD A,L
        CALL CRUNCH_EMIT
        LD A,H
; ----------------------------------------------------------------------
; CRUNCH_21 -- emit the high (second) byte of a 2-byte numeric token payload and return to the main scan.
;   In:        A = the byte to emit; the post-number source pointer is on top of stack; DE/BC = crunch cursor/count.
;   Out:       Byte emitted; HL reloaded with the saved source pointer; control rejoins the tokenizer loop at CRUNCH_SCAN.
;   Clobbers:  HL, DE, BC, A.
;   Algorithm: POP the saved source pointer back into HL, emit A (the high byte / second payload byte), then JP CRUNCH_SCAN to continue tokenizing. Also reached from CRUNCH_22's small-integer path with A = value+$11 (the single-byte embedded constants $11-$1A for digits 0-9).
; ----------------------------------------------------------------------
CRUNCH_21:
        ; restore the source pointer to just past the number
        POP HL
        CALL CRUNCH_EMIT
        ; number fully emitted: resume scanning the rest of the line
        JP CRUNCH_SCAN
; ----------------------------------------------------------------------
; CRUNCH_22 -- parse a numeric literal with FIN and emit it as the smallest MS-BASIC packed numeric token.
;   In:        HL -> first char of the numeric literal; DE = crunch write-cursor, BC = remaining count (live registers restored at CRUNCH_18; CRUNCH_22 re-PUSHes them around the FIN call).
;   Out:       The constant is parsed into the FAC (VALTYP = VALTYP ($0B14); 16-bit int in FAC ($0CB1)); the correctly-sized token is emitted: $11-$1A for integers 0-9, $0F+byte for 10-255, $1C+word for 16-bit ints, or via CRUNCH_23 for single/double; control returns to CRUNCH_SCAN.
;   Clobbers:  A, HL, DE, BC, FAC cells.
;   Algorithm: PUSH dest/count, CALL FIN_1+1 (the FIN numeric scanner entered at its +1 byte so the XOR-A flag-skip pre-seeds the FAC integer), trim trailing blanks, restore dest/count, PUSH the post-number source pointer. If VALTYP is integer ($02): read the 16-bit value from $0CB1; when the high byte is zero, values 0-9 emit as the compact $11-$1A tokens (ADD A,$11 -> CRUNCH_21) and 10-255 as the $0F 1-byte-int token + the byte (pre-staged HL then CRUNCH_20); when the high byte is nonzero the full 16-bit value goes to CRUNCH_23 (with A reloaded to $02). Non-integer (single/double) literals always go to CRUNCH_23.
; ----------------------------------------------------------------------
CRUNCH_22:
        PUSH DE
        PUSH BC
        LD A,(HL)
        ; parse the literal into the FAC (FIN entered +1 so XOR-A pre-seeds the integer FAC), setting VALTYP and the value cells
        CALL FIN_1+1
        CALL CRUNCH_SKIP_BLANKS_BACK
        POP BC
        POP DE
        PUSH HL
        LD A,(VALTYP)
        ; integer literal? non-integers (single/double) emit via CRUNCH_23
        CP VT_INT
        JR NZ,CRUNCH_23
        LD HL,(FAC)
        LD A,H
        ; test the value's high byte: nonzero -> needs the full 2-byte integer token ($1C)
        OR A
        LD A,$02
        JR NZ,CRUNCH_23
        LD A,L
        ; value 0-255: stage HL as (H=value, L=$0F 1-byte-int token) for the emit helpers
        LD H,L
        LD L,$0F
        ; values 0-9 get the ultra-compact $11-$1A tokens; 10-255 use $0F + one byte
        CP $0A
        JR NC,CRUNCH_20
        ; map digit value 0..9 to its embedded constant token $11..$1A
        ADD A,$11
        JR CRUNCH_21
; ----------------------------------------------------------------------
; CRUNCH_23 -- emit a wide numeric constant token ($1C 2-byte int / $1D single / $1F double) followed by its raw FAC bytes.
;   In:        A = the width code to encode: $02 (2-byte int), $04 (single) or $08 (double); the FAC holds the value (int/single at $0CB1, double field at $0CAD); the post-number source pointer is on the stack.
;   Out:       The type token and exactly VALTYP value-bytes are copied into the crunch buffer; control returns to CRUNCH_SCAN via CRUNCH_24/CRUNCH_25.
;   Clobbers:  A, HL, DE, BC.
;   Algorithm: PUSH A (the width, so the FRMEVL_TEST_TYPE call below can clobber it). RRCA halves the width ($02->$01, $04->$02, $08->$04) and ADD $1B yields the token $1C (2-byte int), $1D (single) or $1F (double); emit it. Select the FAC source: set HL=$0CB1, then FRMEVL_TEST_TYPE returns carry SET for VALTYP < $08 (int/single) and CLEAR for VALTYP >= $08 (double); on carry (int/single) JR C,CRUNCH_24 keeps HL=$0CB1, otherwise LD HL,$0CAD selects the wider double field. CRUNCH_24 then POPs the width back into A for the copy loop.
; ----------------------------------------------------------------------
CRUNCH_23:
        PUSH AF
        ; halve the width code so $02/$04/$08 map onto the constant-token range
        RRCA
        ; form the wide-constant token: $1C=2-byte int, $1D=single, $1F=double
        ADD A,$1B
        CALL CRUNCH_EMIT
        LD HL,FAC
        ; carry SET if VALTYP<8 (int/single -> use $0CB1), CLEAR if VALTYP>=8 (double -> use $0CAD)
        CALL FRMEVL_TEST_TYPE
        JR C,CRUNCH_24
        ; double precision: copy from the wider FAC field at $0CAD instead of $0CB1
        LD HL,FAC_DBL
; ----------------------------------------------------------------------
; CRUNCH_24 -- recover the value-byte count after the FAC source pointer has been selected.
;   In:        The width code (VALTYP) PUSHed at CRUNCH_23 is on the stack; HL -> the chosen FAC source field.
;   Out:       A = the byte count (VALTYP); falls into CRUNCH_25 to perform the copy loop.
;   Clobbers:  A.
;   Algorithm: POP the width that CRUNCH_23 saved (so the FRMEVL_TEST_TYPE call could clobber A) back into A, then drop into the byte-copy loop CRUNCH_25. This is the merge point of the int/single (carry, JR C) and double (no-carry, fell through LD HL,$0CAD) source-select branches.
; ----------------------------------------------------------------------
CRUNCH_24:
        POP AF
; ----------------------------------------------------------------------
; CRUNCH_25 -- copy A raw value-bytes from the FAC into the crunch buffer (the wide-constant payload loop).
;   In:        A = number of bytes to copy (VALTYP width: 2 int / 4 single / 8 double); HL -> FAC source field; DE/BC = crunch cursor/count; the post-number source pointer is on the stack.
;   Out:       A bytes emitted via CRUNCH_EMIT; HL (source text) restored; control returns to CRUNCH_SCAN.
;   Clobbers:  A, HL, DE, BC.
;   Algorithm: Loop: PUSH the remaining count, load (HL) and emit it via CRUNCH_EMIT, POP the count, INC HL, DEC A, repeat while nonzero. When done, POP the saved source-text pointer into HL and JP CRUNCH_SCAN to continue tokenizing.
; ----------------------------------------------------------------------
CRUNCH_25:
        PUSH AF
        ; copy the next raw value byte from the FAC into the line
        LD A,(HL)
        CALL CRUNCH_EMIT
        POP AF
        INC HL
        DEC A
        ; loop until all VALTYP bytes of the constant are emitted
        JR NZ,CRUNCH_25
        ; restore the source-text pointer past the number
        POP HL
        JP CRUNCH_SCAN
; ----------------------------------------------------------------------
; CRUNCH_26 -- match the current character against the operator/punctuation reserved-word table (the non-letter keyword scan).
;   In:        HL -> current source character; reached from CRUNCH_17 for characters that are neither letters nor digits.
;   Out:       On a match, emits the operator token (CRUNCH_EMIT_OP with A = the token); on no match (table terminator), passes the character through as-is (CRUNCH_NORMALIZE_CTRL).
;   Clobbers:  A, DE.
;   Algorithm: Load DE with KWGRP_Z ($04D7), the $00 Z-group terminator that sits immediately before the operator (char,token) table RESWORD_OPS ($04D8); CRUNCH_27's leading INC DE advances DE onto the first operator entry. This gives non-letter chars (+ - * / ^ = < > backslash quote-rem) a chance to tokenize as operators before being copied through verbatim.
; ----------------------------------------------------------------------
CRUNCH_26:
        ; point DE at the $00 group-terminator that precedes the operator table RESWORD_OPS; CRUNCH_27's INC DE steps onto the first operator entry
        LD DE,KWGRP_Z
; ----------------------------------------------------------------------
; CRUNCH_27 -- inner scan of the operator name-table, comparing each entry's char to (HL).
;   In:        DE -> the byte just before a (char+$80, token) operator entry; HL -> the source character to match.
;   Out:       On the table terminator ($00) -> CRUNCH_NORMALIZE_CTRL (pass the char through); on a char match -> CRUNCH_EMIT_OP with A = the entry's token byte.
;   Clobbers:  A, DE.
;   Algorithm: INC DE to the entry's char byte; read it and AND $7F to drop the always-set high bit (the marker that flags a name char) -- if the result is $00 the byte was the table terminator, so no operator matched and the char is copied verbatim. Otherwise INC DE to the token byte, CP (HL) the masked char against the source char, then LD A,(token) (does not disturb the CP flags) so a hit leaves the token in A; loop on mismatch, fall through to CRUNCH_EMIT_OP on a match.
;   Note:      This walks the operator sub-table RESWORD_OPS (anchored just past KWGRP_Z), the same (char+$80, token) layout used by the per-letter keyword groups.
; ----------------------------------------------------------------------
CRUNCH_27:
        INC DE
        ; preload A with the entry's token byte (keeps the CP flags) so a match emits it
        LD A,(DE)
        ; drop the high bit that marks every name char; a resulting $00 is the table-end terminator
        AND $7F
        ; end of operator table, nothing matched: pass the character through unchanged
        JP Z,CRUNCH_NORMALIZE_CTRL
        INC DE
        ; does this entry's operator char match the source character?
        CP (HL)
        LD A,(DE)
        JR NZ,CRUNCH_27
        JP CRUNCH_EMIT_OP
; ----------------------------------------------------------------------
; CRUNCH_AMP_HEX_OCT -- post-keyword char/token emit router: special-case an '&' (&H hex / &O octal radix literal), otherwise emit the byte verbatim.
;   In:        A = the byte routed in through CRUNCH_STORE_FLAG_AND_EMIT from CRUNCH_EMIT_OP -- either an operator token (operator-match path) or a normalized source char (non-operator CRUNCH_NORMALIZE_CTRL path); HL -> the source char. DE/BC are LIVE (already POPped from the stack by CRUNCH_STORE_FLAG_AND_EMIT), DE = output cursor, BC = remaining count. Reached only from CRUNCH_STORE_FLAG_AND_EMIT when A is neither ELSE nor $EA (TOK_REM_QUOTE).
;   Out:       if A != '&' ($26), branches to CRUNCH_PASS_CHAR to emit the byte (char or token). If '&', emits the radix marker token ($0B octal / $0C hex), scans and converts the radix digits, and rejoins the numeric-literal emit path at CRUNCH_19.
;   Clobbers:  A, HL (advanced past the digits by SCAN_AMP_RADIX_CONST in the '&' case), DE/BC (saved/restored across the scan).
;   Algorithm: Test for '&' ($26). On '&', peek the next char (CHRGET), upper-case it (TOUPPER_A), and choose the marker: $0C if 'H' (hex), else $0B (octal). Fall into CRUNCH_AMP_EMIT_AND_SCAN to emit the marker and parse the constant. Note '&' is NOT in RESWORD_OPS, so it arrives here as a normalized char via CRUNCH_NORMALIZE_CTRL.
; ----------------------------------------------------------------------
CRUNCH_AMP_HEX_OCT:
        ; is this byte an '&' radix-constant prefix (&H hex / &O octal)?
        CP $26
        ; not '&': branch to CRUNCH_PASS_CHAR to emit the byte (ordinary char or operator token)
        JR NZ,CRUNCH_PASS_CHAR
        PUSH HL
        ; peek the char after '&' to distinguish &H from &O
        CALL CHRGET
        POP HL
        CALL TOUPPER_A
        ; 'H' -> hex; otherwise treat as octal
        CP $48
        ; default radix marker = octal ($0B), loaded before the branch resolves
        LD A,$0B
        JR NZ,CRUNCH_AMP_EMIT_AND_SCAN
        ; 'H' matched: override with the hex radix marker ($0C)
        LD A,$0C
; ----------------------------------------------------------------------
; CRUNCH_AMP_EMIT_AND_SCAN -- emit the chosen &-radix marker, parse the radix digits, and rejoin the numeric emit path.
;   In:        A = radix marker ($0B octal / $0C hex) chosen by CRUNCH_AMP_HEX_OCT; HL -> first radix digit in source; DE/BC live (DE = output cursor, BC = remaining count).
;   Out:       radix marker written to the output buffer; the 16-bit converted value handed to CRUNCH_19 (which emits it low byte then high byte via CRUNCH_20/21); HL advanced past the constant.
;   Clobbers:  A, HL, DE/BC (saved across the scan; BC restored by POP, DE left on the stack for CRUNCH_19 to recover).
;   Algorithm: Write the radix marker via CRUNCH_EMIT, PUSH DE/BC to preserve the output cursor, CALL SCAN_AMP_RADIX_CONST to convert the hex/octal digits to a 16-bit integer, POP BC, then JP CRUNCH_19. [RE] CRUNCH_19 (EX (SP),HL recovering the saved DE) emits the value through CRUNCH_20/21; the exact register holding the converted value depends on SCAN_AMP_RADIX_CONST's contract (not re-verified here).
; ----------------------------------------------------------------------
CRUNCH_AMP_EMIT_AND_SCAN:
        ; write the &O/&H radix-marker byte to the crunch buffer
        CALL CRUNCH_EMIT
        PUSH DE
        PUSH BC
        ; convert the following hex/octal digits to a 16-bit integer
        CALL SCAN_AMP_RADIX_CONST
        POP BC
        ; rejoin the numeric-literal path to emit the converted value's two bytes
        JP CRUNCH_19
; ----------------------------------------------------------------------
; CRUNCH_PASS_CHAR -- emit the byte in A (an ordinary char, a space, or an operator/radix token) to the output buffer and update the literal/line-number mode flags it triggers.
;   In:        A = the byte to emit; HL -> that char in the source line; DE = output cursor, BC = remaining count (live working values; reached from CRUNCH_SCAN, CRUNCH_18, CRUNCH_AMP_HEX_OCT, or CRUNCH_VERBATIM_LOOP).
;   Out:       byte written to (DE) with DE advanced / BC decremented (CRUNCH_EMIT); CRUNCH_LITERAL_MODE and CRUNCH_LINENUM_MODE updated for ':' and the DATA token; control returns to CRUNCH_SCAN for the next char, EXCEPT when the byte is the REM token ($8F = TOK_REM), which falls into the verbatim copy loop (CRUNCH_VERBATIM_LOOP) to copy the rest of the line.
;   Clobbers:  A, HL (INC'd past the char), DE/BC (advanced by emit).
;   Algorithm: INC HL past the char, copy A to the output via CRUNCH_EMIT (AF preserved across the call by PUSH/POP). Then classify by subtracting code points: SUB $3A == 0 means ':' (statement separator) -> arm both modes with A=$00; CP $4A (testing char == $3A+$4A = $84 = TOK_DATA) means DATA -> set A=$01 and arm both modes (DATA text is copied raw). Finally at CRUNCH_CHECK_REM_TEXT the residual (char-$3A) SUB $55 == 0 means char == $8F = TOK_REM -> enter the verbatim copy-to-end-of-line loop (CRUNCH_VERBATIM_LOOP); any other byte loops back to CRUNCH_SCAN.
; ----------------------------------------------------------------------
CRUNCH_PASS_CHAR:
        ; consume this source char
        INC HL
        PUSH AF
        ; copy the byte through to the output buffer unchanged (AF preserved across the call)
        CALL CRUNCH_EMIT
        POP AF
        ; classify the char: $3A == ':' arms literal+linenum modes
        SUB $3A
        JR Z,CRUNCH_SET_LITERAL_MODE
        ; residual $4A means char == $84 = TOK_DATA: DATA text is also copied raw
        CP $4A
        JR NZ,CRUNCH_CHECK_REM_TEXT
        ; DATA: flag value 1 to arm literal mode below
        LD A,$01
; ----------------------------------------------------------------------
; CRUNCH_SET_LITERAL_MODE -- arm both CRUNCH mode flags so following text is passed through and a following number is treated as a line number.
;   In:        A = flag value ($00 from the ':' / SUB $3A == 0 path, $01 from the DATA token).
;   Out:       CRUNCH_LITERAL_MODE ($0B15) and CRUNCH_LINENUM_MODE ($0B16) both set to A.
;   Clobbers:  (memory only) the two mode cells; A unchanged, then falls into CRUNCH_CHECK_REM_TEXT.
;   Algorithm: Store A into both mode flags, then fall into CRUNCH_CHECK_REM_TEXT. For ':' A is already $00; the DATA path enters with A=$01.
; ----------------------------------------------------------------------
CRUNCH_SET_LITERAL_MODE:
        ; arm verbatim pass-through for the text that follows ':' or DATA
        LD (CRUNCH_LITERAL_MODE),A
        ; also arm line-number mode (a following digit run becomes a line number)
        LD (CRUNCH_LINENUM_MODE),A
; ----------------------------------------------------------------------
; CRUNCH_CHECK_REM_TEXT -- decide whether the just-emitted byte is the REM token (and thus starts verbatim REM text), else resume the main loop.
;   In:        A = the char's residual after the SUB $3A classification in CRUNCH_PASS_CHAR (so A = char - $3A on the fall-through path, or $00/$01 from the ':' / DATA paths).
;   Out:       SUB $55; if non-zero, jumps to CRUNCH_SCAN (continue normal crunching); if zero (the byte was $8F = TOK_REM), PUSH AF (saving A=$00, the REM verbatim-loop's stop byte) and fall into CRUNCH_VERBATIM_LOOP to copy the rest of the line raw.
;   Clobbers:  A.
;   Algorithm: SUB $55. A non-zero result returns to the main per-char loop. A zero result (char == $8F = TOK_REM) identifies REM, so push the now-zero AF as the verbatim loop's saved stop byte ($00) and drop into the raw copy loop.
; ----------------------------------------------------------------------
CRUNCH_CHECK_REM_TEXT:
        SUB $55
        ; not the REM token: continue the normal per-char crunch loop
        JP NZ,CRUNCH_SCAN
        ; REM: save A=$00 as the verbatim loop's stop byte and copy the line tail raw
        PUSH AF
; ----------------------------------------------------------------------
; CRUNCH_VERBATIM_LOOP -- copy source characters to the output unchanged until end-of-line, or until a saved stop/delimiter byte is hit.
;   In:        HL -> next source char; DE = output cursor, BC = remaining count; top of stack holds the saved stop byte ($00 for the REM/apostrophe-comment paths, the closing quote $22 for the string-literal path, $EA for the apostrophe-REM path), re-pushed each iteration by CRUNCH_COPY_QUOTED.
;   Out:       on $00 (end of line) -> CRUNCH_FINALIZE_LINE to finalize; on a char equal to the saved stop byte -> CRUNCH_PASS_CHAR to emit that delimiter and resume normal crunching; otherwise the char is emitted and the loop repeats.
;   Clobbers:  A, HL, DE/BC (advanced by CRUNCH_EMIT_AND_LOOP emit), and the top stack slot via EX (SP),HL.
;   Algorithm: LD A,(HL); OR A tests for the $00 line terminator (and leaves A=char). The EX (SP),HL / LD A,H / POP HL idiom swaps the saved stop byte off the stack: HL = saved AF (H = the stop byte), then A = H = stop byte, then POP HL restores the source pointer; the source char's Z-flag from OR A survives. If the char was $00, finalize (CRUNCH_FINALIZE_LINE). If the char equals the stop byte, emit it via CRUNCH_PASS_CHAR (ending the run). Otherwise fall into CRUNCH_COPY_QUOTED/CRUNCH_EMIT_AND_LOOP to emit it and loop.
; ----------------------------------------------------------------------
CRUNCH_VERBATIM_LOOP:
        ; fetch the next source char of the literal/REM run
        LD A,(HL)
        ; test for the end-of-line $00 (leaves A = the char)
        OR A
        ; swap the saved stop byte off the stack while keeping the source pointer accessible
        EX (SP),HL
        LD A,H
        POP HL
        ; end of line: go finalize the crunched line
        JR Z,CRUNCH_FINALIZE_LINE
        ; did we reach the stop byte (e.g. the matching quote)?
        CP (HL)
        ; stop byte reached: emit it via CRUNCH_PASS_CHAR and leave the verbatim run
        JR Z,CRUNCH_PASS_CHAR
; ----------------------------------------------------------------------
; CRUNCH_COPY_QUOTED -- string-literal entry AND per-iteration delimiter re-push for the verbatim loop.
;   In:        as a CRUNCH_SCAN entry: (HL)=='"' with A = the quote ($22) and HL -> the opening quote; DE/BC live. As the loop continuation from CRUNCH_VERBATIM_LOOP: A = the saved stop byte (from LD A,H) and HL -> the source char to emit.
;   Out:       PUSH AF re-saves the stop/delimiter byte for the next iteration; A reloaded from (HL) (the char to emit); falls into CRUNCH_EMIT_AND_LOOP to write it and loop in CRUNCH_VERBATIM_LOOP until the stop byte or end-of-line.
;   Clobbers:  A, HL, DE/BC.
;   Algorithm: PUSH AF saves the delimiter (the quote $22 on string entry, or the same stop byte each loop iteration); LD A,(HL) loads the source char to emit. Fall into CRUNCH_EMIT_AND_LOOP. On the CRUNCH_SCAN quote entry this copies the opening quote first and uses $22 as the closing delimiter.
; ----------------------------------------------------------------------
CRUNCH_COPY_QUOTED:
        ; save the current stop/delimiter byte (the quote $22 on entry) for the next loop iteration
        PUSH AF
        ; load the source char to copy (the opening quote on first entry)
        LD A,(HL)
; ----------------------------------------------------------------------
; CRUNCH_EMIT_AND_LOOP -- emit one verbatim char and continue the literal copy loop.
;   In:        A = char/byte to write; HL -> the source char (advanced here); DE/BC live.
;   Out:       byte written via CRUNCH_EMIT, HL advanced past it, loops back to CRUNCH_VERBATIM_LOOP.
;   Clobbers:  A, HL, DE/BC.
;   Algorithm: INC HL to consume the source char, copy A to the output through CRUNCH_EMIT, then JR back to CRUNCH_VERBATIM_LOOP for the next char. Also reached from CRUNCH_STORE_FLAG_AND_EMIT's $EA (TOK_REM_QUOTE, apostrophe-comment) handler, which has just emitted ':' + REM and re-pushed $EA as the loop stop byte.
; ----------------------------------------------------------------------
CRUNCH_EMIT_AND_LOOP:
        ; consume this source char
        INC HL
        CALL CRUNCH_EMIT
        ; continue copying the literal/REM run
        JR CRUNCH_VERBATIM_LOOP
; ----------------------------------------------------------------------
; CRUNCH_FINALIZE_LINE -- terminate the crunched line, compute its stored length in BC, and return the tokenized line pointer.
;   In:        DE -> just past the last emitted token byte (output cursor); BC = remaining buffer count, started at $013B in CRUNCH and decremented once per emitted byte.
;   Out:       three $00 bytes written at (DE) (the line's terminating NUL plus two zero bytes); BC = $0140 - BC = (bytes emitted) + 5; HL = L_08CE ($08CE) = KBUF-1, a CHRGET-style 'line minus one' pointer (it holds a ':' guard byte, so an INC HL/LD A,(HL) lands on the first token).
;   Clobbers:  A (zeroed), HL, BC, DE (advanced by the three stores).
;   Algorithm: Compute BC = $0140 - BC via L-then-H subtract-with-borrow. Since BC = $013B - emitted, this yields emitted + 5 ([RE] the +5 corresponds to the 4-byte stored-line header (link word + line-number word) plus the terminating NUL). Point HL at L_08CE = $08CE (the ':' guard one byte before KBUF). Zero A and store it three times at the output: the terminating NUL plus two zero bytes ([RE] the zero link that marks end-of-program when this line is later inserted). RET.
; ----------------------------------------------------------------------
CRUNCH_FINALIZE_LINE:
        ; compute stored length: BC = $0140 - BC = (bytes emitted) + 5 ([RE] header + NUL bias)
        LD HL,$0140
        LD A,L
        SUB C
        LD C,A
        LD A,H
        SBC A,B
        LD B,A
        ; return HL = $08CE = KBUF-1 (the ':' guard) so CHRGET lands on the first token
        LD HL,L_08CE
        ; write the terminating NUL plus two zero bytes ([RE] the end-of-program zero link)
        XOR A
        LD (DE),A
        INC DE
        LD (DE),A
        INC DE
        LD (DE),A
        RET
; ----------------------------------------------------------------------
; CRUNCH_EMIT_COLON -- emit a statement-separator colon (':') into the crunch output buffer
;   In:        DE = next free byte of the crunch output buffer (KBUF/$0140-sized window); BC = bytes of buffer space remaining
;   Out:       ':' ($3A) appended; DE advanced by 1; BC decremented by 1 (does not return on buffer exhaustion -- falls into the overflow tail of CRUNCH_EMIT)
;   Clobbers:  A (loaded with $3A), then whatever CRUNCH_EMIT clobbers (A,DE,BC,(DE))
;   Algorithm: Load A=':' and fall straight into CRUNCH_EMIT. Called only from CRUNCH_STORE_FLAG_AND_EMIT to synthesize the implicit ':' inserted before an ELSE clause (CP TOK_ELSE / CALL Z) and the ':' that prefixes the apostrophe-comment token $EA before its emitted REM ($EA -> :REM), so the runtime sees a real statement boundary.
; ----------------------------------------------------------------------
CRUNCH_EMIT_COLON:
        LD A,$3A
; ----------------------------------------------------------------------
; CRUNCH_EMIT -- append one tokenized byte to the crunch output buffer with overflow check
;   In:        A = byte to store; DE = next free output position in the crunch buffer; BC = remaining output-buffer space
;   Out:       On success: byte stored at (DE), DE incremented, BC decremented, returns to caller. When BC reaches 0 it does NOT return -- it falls into CRUNCH_EMIT_OVERFLOW and raises error 23.
;   Clobbers:  A (reloaded with C then OR'd with B for the zero test); memory at (DE); DE; BC
;   Algorithm: Store A->(DE); INC DE; DEC BC; if BC != 0 (LD A,C / OR B / RET NZ) return. The single low-level writer for every byte the tokenizer emits (token bytes, copied identifier characters, line-number constants); centralizing it gives one overflow guard for the whole CRUNCH pass.
; ----------------------------------------------------------------------
CRUNCH_EMIT:
        LD (DE),A
        INC DE
        ; one fewer byte of output-buffer room; falls into the overflow tail when it reaches zero
        DEC BC
        LD A,C
        OR B
        RET NZ
; ----------------------------------------------------------------------
; CRUNCH_EMIT_OVERFLOW -- raise "Line buffer overflow" (error 23) when the crunch/input line is too long
;   In:        (no register inputs of interest -- entered on output-buffer exhaustion, or jumped to directly from the line-input path)
;   Out:       Never returns; transfers to the error dispatcher RAISE_ERROR with E = ERR_LINE_BUFFER_OVERFLOW (23 = $17)
;   Clobbers:  E
;   Algorithm: Load E = 23 (ERR_LINE_BUFFER_OVERFLOW) and JP RAISE_ERROR. Reached two ways: (1) fall-through from CRUNCH_EMIT when the crunched line would overrun the output buffer; (2) an explicit JP from INLIN_STORE_CHAR when a line being read FROM AN ACTIVE FILE (PTRFIL != 0) exceeds 255 characters -- [RE] note: the console/no-file case (PTRFIL == 0) does NOT reach here, it rings the bell at INLIN_ECHO_AND_TEST_LF instead. Either way the line is too long to tokenize.
; ----------------------------------------------------------------------
CRUNCH_EMIT_OVERFLOW:
        LD E,ERR_LINE_BUFFER_OVERFLOW
        JP RAISE_ERROR
; ----------------------------------------------------------------------
; CRUNCH_COPY_IDENT -- begin copying a non-keyword word (variable/identifier) to the output verbatim
;   In:        On stack (top-down): saved word-start text pointer (pushed at CRUNCH_RESWORD_TRY_ENTRY), then saved BC (remaining output space) and DE (output ptr) pushed at the top of the per-token loop (CRUNCH_RESWORD_BEGIN); A = 0 (both entries set A=0 -- via AND $7F yielding Z at $3098, or explicit LD A,$00 at $30BF)
;   Out:       Falls into CRUNCH_COPY_IDENT_LOOP with HL at the word's first character, BC/DE restored, A = that first character, and CRUNCH_LINENUM_MODE = $FF (the "just-emitted-an-identifier" sentinel)
;   Clobbers:  A, HL, BC, DE, CRUNCH_LINENUM_MODE
;   Algorithm: Reached when the reserved-word matcher found the word matches NO keyword (the name table ran out at CRUNCH_RESWORD_CMP_LOOP, or a non-abbreviated word ran past with no match). POP the saved word-start pointer; [RE] DEC HL backs it up one so the first letter is re-read (the saved pointer had been advanced past the first char during matching). DEC A turns the incoming A=0 into $FF and stores it into CRUNCH_LINENUM_MODE to record that an identifier was just emitted (so a following digit run is NOT taken as a target line number). Restore the output cursor (BC,DE); prime A with the first character via CHRGET_UPCASE (which reads (HL), does not advance); fall into the copy loop.
; ----------------------------------------------------------------------
CRUNCH_COPY_IDENT:
        ; word matched no keyword: recover the saved pointer to the word's start
        POP HL
        DEC HL
        DEC A
        ; A=$FF here (0 then DEC A): mark "an identifier was just emitted" so a following digit run is not treated as a target line number
        LD (CRUNCH_LINENUM_MODE),A
        POP BC
        POP DE
        CALL CHRGET_UPCASE
; ----------------------------------------------------------------------
; CRUNCH_COPY_IDENT_LOOP -- copy an identifier (letters, digits, '.') to the output verbatim
;   In:        A = current character to emit; HL -> that character in the source text; DE/BC = crunch output cursor/room
;   Out:       Each accepted character appended via CRUNCH_EMIT and HL advanced; on the first character outside {A-Z, 0-9, '.'} it exits to CRUNCH_COPY_IDENT_DONE (-> CRUNCH_SCAN) with HL at that terminating character
;   Clobbers:  A, HL, DE, BC, flags
;   Algorithm: Loop: emit A; INC HL and fetch+upcase the next char (CHRGET_UPCASE). IS_LETTER_A returns carry CLEAR for a letter A-Z and SET for a non-letter, so JR NC loops on letters. Otherwise the char is accepted only if it is a digit ($30-$39, after rejecting >= ':' first) or a literal '.' ($2E), both legal in BASIC variable names, and the loop continues on those; any other byte (space, ':', operator, end) terminates the name.
; ----------------------------------------------------------------------
CRUNCH_COPY_IDENT_LOOP:
        ; append this identifier character to the output line
        CALL CRUNCH_EMIT
        INC HL
        CALL CHRGET_UPCASE
        CALL IS_LETTER_A
        ; carry clear = letter (A-Z): still inside the identifier, keep copying
        JR NC,CRUNCH_COPY_IDENT_LOOP
        CP $3A
        ; char >= ':' (and not a letter) ends the name -- stop copying
        JR NC,CRUNCH_COPY_IDENT_DONE
        CP $30
        ; digit 0-9: a legal identifier continuation character, keep copying
        JR NC,CRUNCH_COPY_IDENT_LOOP
        CP $2E
        ; '.' is allowed inside BASIC variable names, keep copying
        JR Z,CRUNCH_COPY_IDENT_LOOP
; ----------------------------------------------------------------------
; CRUNCH_COPY_IDENT_DONE -- identifier fully copied; resume the main tokenizer scan
;   In:        HL -> the first character that is not part of the identifier
;   Out:       Jumps to CRUNCH_SCAN to tokenize from that character
;   Clobbers:  (none beyond the jump)
;   Algorithm: Single JP CRUNCH_SCAN. Common exit for the identifier-copy loop, reached when the next source character is outside {A-Z, 0-9, '.'}.
; ----------------------------------------------------------------------
CRUNCH_COPY_IDENT_DONE:
        JP CRUNCH_SCAN
; ----------------------------------------------------------------------
; CRUNCH_NORMALIZE_CTRL -- normalize an unmatched punctuation/control character before emitting it
;   In:        HL -> the current (unmatched) source character; reached from CRUNCH_27 when the operator table scan (which walks RESWORD_OPS, starting one past the KWGRP_Z $00 terminator) hit its terminator with no match
;   Out:       Falls into CRUNCH_EMIT_OP with A = the character to emit: the original byte if printable ($20+) or TAB/LF, otherwise $20 (space)
;   Clobbers:  A, flags
;   Algorithm: Load the source byte (HL). If >= $20 (printable) keep it. Otherwise keep it only if it is TAB ($09) or LF ($0A); any other control character is replaced by a space ($20) so stray control bytes do not leak into the tokenized line. Then fall through to the single-character emit path.
; ----------------------------------------------------------------------
CRUNCH_NORMALIZE_CTRL:
        ; no operator matched: take the raw source character
        LD A,(HL)
        CP $20
        JR NC,CRUNCH_EMIT_OP
        CP $09
        JR Z,CRUNCH_EMIT_OP
        CP $0A
        JR Z,CRUNCH_EMIT_OP
        ; a stray control char (not TAB/LF): substitute a space
        LD A,$20
; ----------------------------------------------------------------------
; CRUNCH_EMIT_OP -- finalize a single-character operator/punctuation byte and rejoin the matched-token epilogue
;   In:        A = byte to emit -- the operator TOKEN byte loaded from the RESWORD_OPS table by CRUNCH_27 on a match, or a normalized punctuation/control char from CRUNCH_NORMALIZE_CTRL
;   Out:       Pushes A (byte to emit), recomputes the line-number-mode flag into A, then JP CRUNCH_STORE_FLAG_AND_EMIT where the byte is popped and emitted by the shared token epilogue
;   Clobbers:  A, stack (one PUSH AF consumed by CRUNCH_STORE_FLAG_AND_EMIT's POP AF), flags
;   Algorithm: Save the byte to emit (PUSH AF). Read CRUNCH_LINENUM_MODE: INC A maps the $FF "identifier-just-emitted" sentinel to 0 (Z set -> JR Z skips the following DEC A, committing 0), while any other value (0 normal, 1 line-number-keyword) is restored by the DEC A. Carry the resulting flag in A into CRUNCH_STORE_FLAG_AND_EMIT, which stores it back to CRUNCH_LINENUM_MODE and emits the saved byte. This funnels single-char operators through the same ELSE/REM-colon-aware epilogue used by reserved-word tokens.
; ----------------------------------------------------------------------
CRUNCH_EMIT_OP:
        ; stash the byte to emit; CRUNCH_STORE_FLAG_AND_EMIT will POP and write it
        PUSH AF
        LD A,(CRUNCH_LINENUM_MODE)
        ; if line-number-mode held the $FF identifier sentinel, INC->0 (Z) clears it and skips the DEC that restores 0/1 values
        INC A
        JR Z,CRUNCH_EMIT_OP_1
        DEC A
; ----------------------------------------------------------------------
; CRUNCH_EMIT_OP_1 -- shared tail of CRUNCH_EMIT_OP: jump into the matched-token epilogue with the flag already in A
;   In:        A = line-number-mode flag value to commit; byte to emit on the stack
;   Out:       Jumps to CRUNCH_STORE_FLAG_AND_EMIT (stores A to CRUNCH_LINENUM_MODE, pops and emits the stacked byte, handles ELSE/REM colon insertion)
;   Clobbers:  (none beyond the jump)
;   Algorithm: Single JP CRUNCH_STORE_FLAG_AND_EMIT, reached both by the JR Z that skips DEC A (when the $FF sentinel was just folded to 0) and by fall-through after DEC A.
; ----------------------------------------------------------------------
CRUNCH_EMIT_OP_1:
        JP CRUNCH_STORE_FLAG_AND_EMIT
; ----------------------------------------------------------------------
; CRUNCH_SKIP_BLANKS_BACK -- back HL up over trailing whitespace, leaving it just past the last non-blank
;   In:        HL -> one past the end of a just-scanned token (e.g. after LINGET parsed a line number, or after a numeric/reserved-word scan)
;   Out:       HL points to the first character AFTER the last non-blank character (trailing space/TAB/LF trimmed); A = that last NON-blank byte (the byte that stopped the backward walk)
;   Clobbers:  A, HL, flags
;   Algorithm: Walk backward (DEC HL) skipping space ($20), TAB ($09), and LF ($0A); on the first non-whitespace byte (still in A), step forward once (INC HL) and return. Effectively trims trailing blanks so the tokenizer resumes immediately after the meaningful text rather than re-scanning the gap.
; ----------------------------------------------------------------------
CRUNCH_SKIP_BLANKS_BACK:
        ; step back over a trailing whitespace byte
        DEC HL
        LD A,(HL)
        CP $20
        JR Z,CRUNCH_SKIP_BLANKS_BACK
        CP $09
        JR Z,CRUNCH_SKIP_BLANKS_BACK
        CP $0A
        JR Z,CRUNCH_SKIP_BLANKS_BACK
        ; hit a non-blank: re-advance one so HL sits just past the last real character
        INC HL
        RET
; ----------------------------------------------------------------------
; STMT_FOR -- FOR statement handler (token $82): begin building the FOR/NEXT loop frame.
;   In:        HL -> crunched text just past the FOR token (at the index variable name).
;   Out:       Falls through to the FOR-frame reuse scan (STMT_FOR_1). On completion a FOR
;              frame is pushed on the runtime stack and control enters the NEXT body for the
;              zero-trip test.
;   Clobbers:  AF,BC,DE,HL,SP,FAC; PTRGET_SUBSCRIPT_FLAG, OPEN_RESUME_TEXT_PTR, FOR_NEXT_VALUE_TEMP, L_0B4E, VALTYP.
;   Algorithm: Parse 'FOR var = init'. Force scalar-variable context (PTRGET_SUBSCRIPT_FLAG=$64 so
;              PTRGET rejects an array element), PTRGET the index variable -> its address in DE.
;              SYNCHR the '=' token. Save the index-variable address (via OPEN_RESUME_TEXT_PTR).
;              [RE] Evaluate the initial expression (FRMEVL_NOPAREN) into the FAC, coerce it to
;              the index variable's type (FRMEVL_APPLY_OP dispatched by the saved VALTYP), and copy
;              the coerced FAC into the scratch numeric cell FOR_NEXT_VALUE_TEMP. [RE] Then CALL STMT_DATA to
;              scan forward over the rest of the FOR statement and record the resulting text
;              pointer in L_0B4E (used as this loop's frame-match key). HL=SP+2 prepares the
;              runtime-stack walk in STMT_FOR_1. UNKNOWN: the precise field-by-field frame layout
;              and exactly where the init value is ultimately written into the variable are not
;              fully pinned by static reading; treat the cell roles as [RE].
; ----------------------------------------------------------------------
STMT_FOR:
        ; Force scalar (non-array) variable resolution in PTRGET so the FOR index cannot be an array element.
        LD A,$64
        LD (PTRGET_SUBSCRIPT_FLAG),A
        ; Resolve the index variable name -> its storage address in DE; HL advances past the name.
        CALL PTRGET_1+1
        ; Require the '=' token after the index variable (syntax error otherwise).
        CALL SYNCHR
        DEFB    TOK_EQ                   ; inline keyword-token arg consumed by the preceding CALL
        PUSH DE
        EX DE,HL
        ; [RE] Save the index-variable address here (HL holds the var address after the EX DE,HL above, not a text pointer).
        LD (OPEN_RESUME_TEXT_PTR),HL
        EX DE,HL
        LD A,(VALTYP)
        PUSH AF
        ; Evaluate the initial-value expression into the FAC.
        CALL FRMEVL_NOPAREN
        POP AF
        PUSH HL
        ; [RE] Coerce the FAC to the index variable's type: the saved VALTYP (AND $07) indexes the type-conversion entries of OPERATOR_ROUTINE_TBL (CINT/CSNG/CDBL).
        CALL FRMEVL_APPLY_OP
        ; [RE] Copy the coerced FAC into the scratch numeric cell FOR_NEXT_VALUE_TEMP (FP_MOVE_TO_FAC copies FAC->here); reused later by NEXT, not a write into the variable itself.
        LD HL,FOR_NEXT_VALUE_TEMP
        CALL FP_MOVE_TO_FAC
        POP HL
        POP DE
        POP BC
        PUSH HL
        ; [RE] Scan forward over the remainder of the FOR statement; the returned text pointer becomes this loop's frame key.
        CALL STMT_DATA
        ; [RE] Record that scanned text pointer as the frame-match key for the reuse scan.
        LD (L_0B4E),HL
        ; Point HL at the live runtime stack (SP+2) to begin the open-frame scan.
        LD HL,$0002
        ADD HL,SP
; ----------------------------------------------------------------------
; STMT_FOR_1 -- FOR-frame reuse scan: discard any open FOR frame on the same loop key.
;   In:        HL -> a runtime-stack position to scan; L_0B4E = this loop's frame-match key (set by STMT_FOR).
;   Out:       On a match, SP/SAVSTK are rewound to drop the stale frame (and the frames pushed
;              inside it); always continues into STMT_FOR_2 to push the new frame.
;   Clobbers:  AF,BC,DE,HL,SP,SAVSTK.
;   Algorithm: [RE] Call STKFRAME_SCAN to find the next open FOR marker ($82) frame on the stack;
;              if none (NZ) go push a fresh frame. Otherwise read that frame's stored key pointer
;              and compare it (CMP_HL_DE) to L_0B4E: mismatch -> keep scanning outward; match -> a
;              re-entered loop, so reset SP to that frame (discarding it and everything pushed
;              inside) before pushing anew. This prevents a GOTO back into a FOR from leaking
;              stack frames. UNKNOWN: STKFRAME_SCAN and STMT_FOR_1 read two different frame fields
;              (the marker-adjacent word vs a word near the 16-byte frame top); the exact field
;              each matches is not fully disambiguated statically.
; ----------------------------------------------------------------------
STMT_FOR_1:
        ; Find the next open FOR frame on the runtime stack.
        CALL STKFRAME_SCAN
        POP DE
        ; No more FOR frames found: this is a brand-new loop, go push its frame.
        JR NZ,STMT_FOR_2
        ADD HL,BC
        PUSH DE
        DEC HL
        LD D,(HL)
        DEC HL
        LD E,(HL)
        INC HL
        INC HL
        PUSH HL
        ; [RE] Compare the scanned frame's key against this loop's key.
        LD HL,(L_0B4E)
        CALL CMP_HL_DE
        POP HL
        ; Different loop: keep scanning further out on the stack.
        JP NZ,STMT_FOR_1
        POP DE
        ; Same loop re-entered: rewind the stack to drop the stale frame and any nested frames.
        LD SP,HL
        LD (SAVSTK),HL
; ----------------------------------------------------------------------
; STMT_FOR_2 -- push the FOR frame header (key word + body text pointer) and parse TO.
;   In:        Comes from STMT_FOR_1; L_0B4E = the loop key; SAVTXT = current line text pointer.
;   Out:       8 stack bytes reserved; the frame's key word and the SAVTXT word are pushed; the
;              TO limit expression has been evaluated into the FAC.
;   Clobbers:  AF,BC,DE,HL,SP,FAC.
;   Algorithm: Ensure 8 bytes of stack headroom (CHECK_STACK_ROOM). Push L_0B4E and the current
;              SAVTXT into the new frame (via the PUSH/EX (SP),HL idiom). SYNCHR the 'TO' token.
;              [RE] FRMEVL_TEST_TYPE then JP Z/JP NC reject a non-acceptable limit type (string
;              gives Z; the NC arm also rejects, e.g. a double-precision limit) with TYPE
;              MISMATCH. Evaluate the TO limit expression into the FAC for STMT_FOR_3/_4.
; ----------------------------------------------------------------------
STMT_FOR_2:
        EX DE,HL
        ; Reserve 8 bytes of stack room for the next part of the FOR frame.
        LD C,$08
        CALL CHECK_STACK_ROOM
        PUSH HL
        ; [RE] Push this loop's key pointer into the frame.
        LD HL,(L_0B4E)
        EX (SP),HL
        PUSH HL
        ; Push the current line text pointer (SAVTXT) into the frame.
        LD HL,(SAVTXT)
        EX (SP),HL
        ; Require the 'TO' token before the limit expression.
        CALL SYNCHR
        DEFB    TOK_TO                   ; inline keyword-token arg consumed by the preceding CALL
        ; [RE] Test the limit's VALTYP: reject a string (Z) or the NC type with TYPE MISMATCH (the limit must be an acceptable numeric type).
        CALL FRMEVL_TEST_TYPE
        JP Z,RAISE_TYPE_MISMATCH
        JP NC,RAISE_TYPE_MISMATCH
        PUSH AF
        ; Evaluate the TO limit expression into the FAC.
        CALL FRMEVL_NOPAREN
        POP AF
        PUSH HL
        JP P,STMT_FOR_3
        CALL FN_CINT
        EX (SP),HL
        LD DE,$0001
        LD A,(HL)
        CP TOK_STEP
        CALL Z,GETINT_CHRGET
        PUSH DE
        PUSH HL
        EX DE,HL
        CALL FP_MANT_SIGN
        JR STMT_FOR_4
; ----------------------------------------------------------------------
; STMT_FOR_3 -- single-precision TO/STEP path: capture a floating limit and STEP value.
;   In:        FAC = TO limit (numeric); HL -> text after the limit; entered when the limit type's
;              sign flag was positive (single/general path).
;   Out:       Limit (single) and a STEP value pushed; STEP sign computed; A = $01 (single marker).
;   Clobbers:  AF,BC,DE,HL,SP,FAC.
;   Algorithm: Coerce the limit to single (FN_CSNG), load it from the FAC (FP_LOAD_FAC), push it.
;              Default STEP = +1.0 (BC=$8100 seeds single exponent $81 / mantissa, spread to D,E;
;              A=$01). If a STEP token follows, evaluate the STEP expression (FRMEVL_LOWPREC),
;              coerce to single, load it, and take its sign (FP_SIGN, -1/0/+1) so NEXT knows the
;              loop direction. Joins STMT_FOR_5 to push the frame tail.
; ----------------------------------------------------------------------
STMT_FOR_3:
        ; Coerce the TO limit to single precision.
        CALL FN_CSNG
        CALL FP_LOAD_FAC
        POP HL
        PUSH BC
        PUSH DE
        ; Seed the default STEP of +1.0 (single: exponent $81, zero mantissa spread into D,E).
        LD BC,$8100
        LD D,C
        LD E,D
        LD A,(HL)
        ; Is an explicit STEP clause present?
        CP TOK_STEP
        LD A,$01
        JR NZ,STMT_FOR_5
        ; Evaluate the explicit STEP expression.
        CALL FRMEVL_LOWPREC
        PUSH HL
        CALL FN_CSNG
        CALL FP_LOAD_FAC
        ; Compute the STEP's sign (-1/0/+1) so NEXT knows whether the loop counts up or down.
        CALL FP_SIGN
; ----------------------------------------------------------------------
; STMT_FOR_4 -- integer-path STEP join point: recover the text pointer before pushing the frame tail.
;   In:        Stack top = text pointer saved on the integer (FN_CINT) branch.
;   Out:       HL = text pointer; falls into STMT_FOR_5.
;   Clobbers:  HL.
;   Algorithm: One-instruction landing pad (POP HL) for the integer branch (the FN_CINT path that
;              defaulted STEP=$0001 and took its sign via FP_MANT_SIGN); pops the saved text
;              pointer and continues into the common frame-tail push.
; ----------------------------------------------------------------------
STMT_FOR_4:
        POP HL
; ----------------------------------------------------------------------
; STMT_FOR_5 -- push the FOR frame tail (STEP value, STEP sign, VALTYP, key/marker) and verify end-of-statement.
;   In:        BC/DE = STEP value bytes; A = STEP sign/direction marker; HL -> text after TO/STEP clause.
;   Out:       STEP value, STEP sign and the loop variable's VALTYP pushed; HL re-fetched; SYNTAX
;              ERROR unless at end-of-statement; control jumps into the NEXT body for the
;              zero-trip test.
;   Clobbers:  AF,BC,DE,HL,SP.
;   Algorithm: Push the STEP value (BC,DE) and the STEP-sign byte (A). Push the loop variable's
;              VALTYP (FRMEVL_TEST_TYPE -> A). Re-fetch the text (DEC HL; CHRGET) and require
;              end-of-statement (Z) or raise SYNTAX ERROR. [RE] CALL BLOCK_SCAN_FORNEXT (which
;              records the current line text pointer in L_0C71 as it scans the line); store that
;              into SAVTXT, push OPEN_RESUME_TEXT_PTR (the saved index-variable address) and the
;              $82 FOR marker, then jump into the NEXT body (STMT_NEXT_1+1) to run the zero-trip
;              test. UNKNOWN: BLOCK_SCAN_FORNEXT's exact role here (it is a THEN/ELSE/line scanner,
;              not obviously a 'find matching NEXT' search) is not fully pinned.
; ----------------------------------------------------------------------
STMT_FOR_5:
        PUSH BC
        PUSH DE
        ; Stage the STEP value and its sign byte to push into the frame.
        LD C,A
        ; Push the loop variable's VALTYP (type/precision) into the frame.
        CALL FRMEVL_TEST_TYPE
        LD B,A
        PUSH BC
        DEC HL
        ; Re-fetch the text; require end-of-statement after the FOR clause.
        CALL CHRGET
        ; Anything other than end-of-statement after the FOR clause is a syntax error.
        JP NZ,RAISE_SYNTAX_ERROR
        ; [RE] Scan the line, tracking the current line text pointer in L_0C71.
        CALL BLOCK_SCAN_FORNEXT
        CALL CHRGET
        PUSH HL
        PUSH HL
        ; Use the tracked line pointer as SAVTXT for the frame.
        LD HL,(L_0C71)
        LD (SAVTXT),HL
        ; [RE] Push the saved index-variable address into the frame.
        LD HL,(OPEN_RESUME_TEXT_PTR)
        EX (SP),HL
        ; Tag the frame with the $82 FOR marker so STKFRAME_SCAN/NEXT recognize it.
        LD B,$82
        PUSH BC
        INC SP
        PUSH AF
        PUSH AF
        ; Enter the NEXT body to run the zero-trip test and start the loop (NEXT flag byte = 0).
        JP STMT_NEXT_1+1
; ----------------------------------------------------------------------
; STMT_FOR_6 -- loop re-iteration entry from NEXT: re-tag the FOR frame and resume the body.
;   In:        HL -> the loop body's resume text pointer (set up by NEXT before jumping here).
;   Out:       Re-stamps the FOR marker on the retained frame; falls into STMT_FOR_7 to execute
;              the next statement.
;   Clobbers:  BC,SP.
;   Algorithm: When NEXT decides the loop continues (JP STMT_FOR_6 from NEXT_LOOP_BODY), re-stamp
;              the $82 FOR marker on the kept frame (PUSH BC then INC SP trims the high byte of
;              the pushed pair) and drop into the per-statement executor with HL at the loop
;              body's first statement.
; ----------------------------------------------------------------------
STMT_FOR_6:
        ; Re-stamp the $82 FOR marker on the retained frame as the loop continues.
        LD B,$82
        PUSH BC
        INC SP
; ----------------------------------------------------------------------
; STMT_FOR_7 -- per-statement execution entry: poll the console, then run the next statement.
;   In:        HL -> the next statement's crunched text (at ':' or a statement token).
;   Out:       Dispatches the statement; services a pending key via INKEY_SCAN (Ctrl-C/break/pause);
;              refreshes OLDTXT and SAVSTK for error recovery and CONT.
;   Clobbers:  AF,HL (plus whatever the dispatched statement clobbers).
;   Algorithm: The universal 'execute next statement' re-entry. Save HL, call the BIOS
;              console-status routine (the cold-start-patched CALL at STMT_FOR_8), and if a key is
;              waiting run INKEY_SCAN. Record OLDTXT (current statement) and SAVSTK (stack mark).
;              If the next char is ':' continue with the next statement on the same line
;              (NEWSTT_NEXTLINE_2); if end-of-line ($00) advance to the next line (NEWSTT_NEXTLINE);
;              anything else is a SYNTAX ERROR.
; ----------------------------------------------------------------------
STMT_FOR_7:
        PUSH HL
; ----------------------------------------------------------------------
; STMT_FOR_8 -- self-modified console-status poll site (the cold-start-patched CALL).
;   In:        Operand at STMT_FOR_8+1 patched at cold start to the BIOS CONST routine address.
;   Out:       A/flags = console status (nonzero if a key is pending).
;   Clobbers:  per the BIOS CONST routine.
;   Algorithm: The on-disk operand is $0000 (placeholder); COLD_START stores the BIOS CONST
;              address into STMT_FOR_8+1 (LD (STMT_FOR_8+1),HL at $81F9 -> patch slot $336D; the
;              same HL is written to INKEY_SCAN_2+1 and RPC_CONST_POLL_1+1). Every statement then
;              polls the keyboard here without re-walking the BIOS jump table; the literal CALL
;              $0000 is never executed. (Corroborated by the existing VERIFIED [RE] comment above.)
; ----------------------------------------------------------------------
STMT_FOR_8:
        CALL $0000
        POP HL
        OR A
        CALL NZ,INKEY_SCAN
        LD (OLDTXT),HL
        LD (SAVSTK),SP
        LD A,(HL)
        CP $3A
        JR Z,NEWSTT_NEXTLINE_2
        OR A
        JP NZ,RAISE_SYNTAX_ERROR
        INC HL
; ----------------------------------------------------------------------
; NEWSTT_NEXTLINE -- advance to the next program line and optionally emit a TRON trace.
;   In:        HL -> the link field at the start of the next program line.
;   Out:       SAVTXT = the new line's text pointer; control resumes the statement executor; or
;              jumps to PROGRAM_END if the line link is $0000 (ran off the end of the program).
;   Clobbers:  AF,DE,HL.
;   Algorithm: Read the 2-byte next-line link; if zero, jump to PROGRAM_END. Otherwise read the
;              line-number word, stash the line's text pointer in SAVTXT, and if TRCFLG is set
;              print '[<linenum>]' (OUTCHR '[', FOUT, OUTCHR ']') before continuing into the
;              statement fetch/dispatch.
; ----------------------------------------------------------------------
NEWSTT_NEXTLINE:
        LD A,(HL)
        INC HL
        ; A $0000 line link marks end-of-program.
        OR (HL)
        ; Ran off the end: go to the program-end/ready path.
        JP Z,PROGRAM_END
        INC HL
        LD E,(HL)
        INC HL
        LD D,(HL)
        EX DE,HL
        ; Record this line's text pointer as the current statement source.
        LD (SAVTXT),HL
        ; If TRON tracing is on, print the line number in brackets before executing the line.
        LD A,(TRCFLG)
        OR A
        JR Z,NEWSTT_NEXTLINE_1
        PUSH DE
        LD A,$5B
        CALL OUTCHR
        CALL FOUT
        LD A,$5D
        CALL OUTCHR
        POP DE
; ----------------------------------------------------------------------
; NEWSTT_NEXTLINE_1 -- post-trace join: restore the text pointer into HL.
;   In:        DE -> the new line's text (preserved across the optional trace print).
;   Out:       HL -> the new line's text; falls into NEWSTT_NEXTLINE_2.
;   Clobbers:  HL,DE (swapped).
;   Algorithm: Single EX DE,HL landing pad so the trace and no-trace paths converge with HL at
;              the line's first statement.
; ----------------------------------------------------------------------
NEWSTT_NEXTLINE_1:
        EX DE,HL
; ----------------------------------------------------------------------
; NEWSTT_NEXTLINE_2 -- fetch the next statement token and route to the dispatcher.
;   In:        HL -> crunched text at the next statement (after ':' or at line start).
;   Out:       STMT_FOR_7 pushed as the post-statement return; on end-of-statement returns to it
;              immediately; otherwise falls into NEWSTT_DISPATCH with the token in A.
;   Clobbers:  AF,DE,HL.
;   Algorithm: CHRGET the next token. Push STMT_FOR_7 so the dispatched statement returns into the
;              per-statement executor. On end-of-statement ($00, Z) RET immediately to STMT_FOR_7
;              (empty statement / trailing ':'); otherwise fall through to decode and dispatch.
; ----------------------------------------------------------------------
NEWSTT_NEXTLINE_2:
        CALL CHRGET
        ; Arrange to return to the per-statement executor after this statement runs.
        LD DE,STMT_FOR_7
        PUSH DE
        ; Empty statement (end-of-line): return straight to the executor for the next statement/line.
        RET Z
; ----------------------------------------------------------------------
; NEWSTT_DISPATCH -- decode a statement token and jump through the statement-handler table.
;   In:        A = the leading token of the statement; HL -> text just past it.
;   Out:       Transfers to the matching statement handler (HL advanced by the falling-through CHRGET).
;   Clobbers:  AF,BC,DE,HL.
;   Algorithm: Bias the token by $81 (first statement token). On underflow (carry) the line does
;              not start with a statement keyword -> implied LET (STMT_LET). If >= $5B (past the
;              table) -> GETVAR_NAME_1 (non-statement/variable path). Otherwise scale by 2 (RLCA),
;              index STMT_DISPATCH_TBL ($0108), load the handler address into BC, PUSH it, and fall
;              into CHRGET so the handler starts at the first argument character and returns via
;              the previously pushed STMT_FOR_7.
; ----------------------------------------------------------------------
NEWSTT_DISPATCH:
        ; Bias to a 0-based statement index (first statement token = $81).
        SUB $81
        ; Not a statement keyword: treat the line as an implied LET assignment.
        JP C,STMT_LET
        ; Reject tokens past the end of the statement-handler table.
        CP $5B
        JP NC,GETVAR_NAME_1
        ; Scale the index by 2 for the word-wide DEFW table.
        RLCA
        LD C,A
        LD B,$00
        EX DE,HL
        ; Index the statement-handler table; load the handler address into BC.
        LD HL,STMT_DISPATCH_TBL
        ADD HL,BC
        LD C,(HL)
        INC HL
        LD B,(HL)
        PUSH BC
        EX DE,HL

; ======================================================================
; CHARACTER FETCH (CHRGET / CHRGOT) + reserved-word fold
; ======================================================================
; ----------------------------------------------------------------------
; CHRGET -- advance the BASIC text pointer one byte, then fall into CHRGOT to fetch/classify it.
;   In:        HL -> current byte in the crunched program/text line.
;   Out:       HL incremented to the next byte, then (via CHRGOT) A = next significant char; C set iff A is an ASCII digit '0'-'9'; Z set at end-of-line/statement ($00); embedded constant tokens are expanded (see CHRGOT).
;   Clobbers:  A, HL, flags (plus the CHRGOT constant-staging cells on a constant token).
;   Algorithm: INC HL to step over the just-consumed byte, then drop straight into CHRGOT so a single fall-through path does the fetch, space-skipping, digit test and embedded-constant decode. The workhorse 'get next char' primitive called pervasively by the tokenizer, statement executor and expression evaluator.
; ----------------------------------------------------------------------
CHRGET:
        ; advance past the byte just consumed, then fall into CHRGOT to fetch the next one
        INC HL
; ----------------------------------------------------------------------
; CHRGOT -- re-fetch the CURRENT text char at (HL) into A without advancing, skipping spaces and expanding embedded constant tokens.
;   In:        HL -> current byte in the crunched program/text line.
;   Out:       A = next significant char (spaces skipped); C set iff A is an ASCII digit '0'-'9'; Z set at end-of-line/statement ($00). If (HL) is an embedded numeric-constant token ($0B-$1F) the staged constant is decoded into the CHRGOT_CONST_* cells, A returns the token byte (carry clear), and HL is loaded with the CHRGOT_11 continuation address.
;   Clobbers:  A, flags; on a constant token also HL and the CHRGOT_CONST_* staging cells.
;   Algorithm: Load (HL). Fast-path: if the char is >= ':' ($3A) RET NC -- carry is CLEAR there, which correctly reports 'not a digit' for keywords/operators/letters. Otherwise enter CHRGOT_1 to handle spaces, the $00 terminator, the digit range and the $0B-$1F embedded-constant tokens. CHRGET enters here after its INC HL; callers needing the current char without advancing call CHRGOT directly.
; ----------------------------------------------------------------------
CHRGOT:
        ; fetch the current text character
        LD A,(HL)
        ; fast exit for anything >= ':' (keywords, operators, letters): RET NC leaves carry clear = 'not a digit'
        CP $3A
        RET NC
; ----------------------------------------------------------------------
; CHRGOT_1 -- classify a char below ':' : skip spaces, detect end-of-line, split digits from the embedded constant tokens.
;   In:        A = char (< $3A) from CHRGOT; HL -> that char.
;   Out:       Spaces are skipped (loops back through CHRGET). $00 returns Z. Chars $21-$39 fall to the digit classifier CHRGOT_10 (C set iff digit). Tokens $01-$0A go to CHRGOT_9. Token $1E re-returns the prior decoded token byte. Other $0B-$1D (and $1F) tokens are decoded by CHRGOT_2..CHRGOT_8.
;   Clobbers:  A, flags; HL on the space-skip and constant-decode paths.
;   Algorithm: If char == ' ' ($20) loop to CHRGET to swallow the blank. If char > ' ' (so $21-$39) it is printable below ':' -> CHRGOT_10 digit test. Otherwise it is a control byte/token (< $20): OR A returns Z on the $00 terminator; CP $0B sends the very low control bytes ($01-$0A) to CHRGOT_9; the special $1E token re-loads and returns the previously decoded token byte from CHRGOT_CONST_TOKEN; all remaining tokens ($0B-$1D and $1F) fall to CHRGOT_2.
; ----------------------------------------------------------------------
CHRGOT_1:
        CP $20
        ; skip a literal space: loop back to CHRGET to fetch the following char
        JR Z,CHRGET
        ; printable char in $21-$39: go classify it as digit vs non-digit
        JR NC,CHRGOT_10
        OR A
        ; $00 = end of line / end of statement: return with Z set
        RET Z
        CP $0B
        ; control bytes $01-$0A (below the constant-token range): handle in CHRGOT_9
        JR C,CHRGOT_9
        ; $1E = 're-emit the last decoded constant token byte'
        CP $1E
        JR NZ,CHRGOT_2
        ; return the token byte that was stashed when this constant was first decoded
        LD A,(CONST_TOKEN)
        OR A
        RET
; ----------------------------------------------------------------------
; CHRGOT_2 -- handle the $10 'resume at saved pointer' marker, else dispatch a fresh constant token to CHRGOT_4.
;   In:        A = embedded token ($0B-$1D or $1F, already excluding $1E); HL -> that token byte.
;   Out:       For $10, jump to CHRGOT_3 to reload the saved post-constant text pointer and re-scan. For any other token, fall into CHRGOT_4 to decode and stage the constant.
;   Clobbers:  A, HL, flags.
;   Algorithm: CP $10: if the token is $10 (the marker meaning 'the real next char lives at the saved continuation pointer'), branch to CHRGOT_3 which reloads CHRGOT_CONST_TXTPTR and loops back into CHRGOT; otherwise this is a genuine constant token to expand, so fall through to CHRGOT_4.
; ----------------------------------------------------------------------
CHRGOT_2:
        ; $10 = 'resume scan at the saved text pointer' marker
        CP $10
        JR NZ,CHRGOT_4
; ----------------------------------------------------------------------
; CHRGOT_3 -- reload the saved post-constant text pointer and re-enter the scanner.
;   In:        CHRGOT_CONST_TXTPTR = text pointer just past a previously decoded embedded constant.
;   Out:       HL = that saved pointer; control falls into CHRGOT to fetch the next char from there.
;   Clobbers:  HL (and whatever CHRGOT clobbers).
;   Algorithm: After a constant has been expanded and consumed, scanning must continue at the byte following the constant. CHRGOT_3 loads HL from CHRGOT_CONST_TXTPTR and jumps to CHRGOT to resume. Reached from the $10 marker (CHRGOT_2) and as the common return target of all CHRGOT_CONST_VALUE paths after they materialize the value into the FAC.
; ----------------------------------------------------------------------
CHRGOT_3:
        ; restore the scan position to just past the decoded constant
        LD HL,(CONST_TEXT_RESUME)
        JR CHRGOT
; ----------------------------------------------------------------------
; CHRGOT_4 -- decode one embedded numeric-constant token, staging its value/type/text-pointer for the caller.
;   In:        A = token byte ($0B-$1D or $1F, not $10/$1E); HL -> the token byte (CHRGOT_4 immediately INC HLs past it); the token is also pushed (PUSH AF).
;   Out:       The decoded constant is staged: CHRGOT_CONST_TOKEN = token, CHRGOT_CONST_VALUE_CELL = value word (or FP bytes), CHRGOT_CONST_VALTYP = width/valtyp, CHRGOT_CONST_TXTPTR = text pointer past the constant; HL = CHRGOT_11; A = token (POPped), carry CLEAR; RET to caller.
;   Clobbers:  A, HL, flags, the CHRGOT_CONST_* cells (CHRGOT_8 also touches but restores DE/BC).
;   Algorithm: PUSH the token (AF) and INC HL past it. Stash the token in CHRGOT_CONST_TOKEN. Classify by range arithmetic (verified by exhaustive simulation): SUB $1C -> NC selects the wide forms $1C/$1D/$1F (CHRGOT_8). Else SUB $F5 -> NC selects the compact single-byte integer tokens, decoded value left in A (CHRGOT_5; $11..$1A -> 0..9, $1B -> 10). Else CP $FE detects the $0F token (1-byte int 10-255): read the value byte from (HL), INC HL, fall into CHRGOT_5. All remaining values ($0B-$0E) take CHRGOT_7 to read a 2-byte word.
; ----------------------------------------------------------------------
CHRGOT_4:
        ; preserve the token byte (and flags) to hand back to the caller after staging
        PUSH AF
        INC HL
        ; record which constant token this is, for the FAC-materialize step and the LIST/GOTO/IF discriminators
        LD (CONST_TOKEN),A
        ; tokens >= $1C ($1C 2-byte int, $1D single, $1F double) are the wide multi-byte forms -> CHRGOT_8
        SUB $1C
        JR NC,CHRGOT_8
        ; after the SUB $1C, NC here selects the compact integer tokens $11-$1B mapping to value 0-10 in A -> CHRGOT_5
        SUB $F5
        JR NC,CHRGOT_5
        ; the $0F token (1-byte int 10-255): the value byte follows inline in the text
        CP $FE
        JR NZ,CHRGOT_7
        ; fetch the inline 1-byte integer value
        LD A,(HL)
        INC HL
; ----------------------------------------------------------------------
; CHRGOT_5 -- stage a 1-byte integer constant value held in A (entry for the compact / $0F int tokens).
;   In:        A = the 8-bit integer value (0-255); HL -> the byte just past the constant in the text.
;   Out:       CHRGOT_CONST_TXTPTR = HL (post-constant pointer); H cleared to $00, then falls into CHRGOT_6 to set L=value and mark VALTYP=integer.
;   Clobbers:  H, CHRGOT_CONST_TXTPTR.
;   Algorithm: Save the continuation text pointer, zero the high byte (H=$00) so the byte in A becomes the low half of a 16-bit integer, and fall into CHRGOT_6 which sets L=A and records the value/type. Common tail for the $11-$1B compact integers and the $0F one-byte integer.
; ----------------------------------------------------------------------
CHRGOT_5:
        ; save where scanning resumes after this constant
        LD (CONST_TEXT_RESUME),HL
        ; zero-extend the 8-bit value to 16 bits (low byte set in CHRGOT_6)
        LD H,$00
; ----------------------------------------------------------------------
; CHRGOT_6 -- finalize a 16-bit integer constant: store the value, mark VALTYP=integer, return the token to the caller.
;   In:        H = high byte (already set), A = low byte; the original token is on the stack (PUSHed at CHRGOT_4).
;   Out:       CHRGOT_CONST_VALUE_CELL = HL (the 16-bit value); CHRGOT_CONST_VALTYP = $02 (VT_INT); HL = CHRGOT_11; A = token (POPped), carry CLEAR; RET to caller.
;   Clobbers:  A, L, HL, flags, CHRGOT_CONST_VALUE_CELL, CHRGOT_CONST_VALTYP.
;   Algorithm: Set L = A to complete the 16-bit value in HL, store it in CHRGOT_CONST_VALUE_CELL, and record VALTYP=2 (integer) in CHRGOT_CONST_VALTYP. Load HL=CHRGOT_11, POP the token back into A, OR A to clear carry (caller sees 'not a digit'), and RET. Shared tail for all integer-valued embedded tokens decoded as compact / 2-byte ints. UNKNOWN: the HL=CHRGOT_11 handoff is not consumed by the current callers (FRMEVL and LIST jump to CHRGOT_CONST_VALUE directly), so its original purpose is unclear.
; ----------------------------------------------------------------------
CHRGOT_6:
        ; combine low byte (A) with high byte (H) to form the 16-bit value
        LD L,A
        LD (CONST_VALUE),HL
        ; mark the staged constant as integer (VT_INT, 2-byte width)
        LD A,$02
        LD (CONST_VALTYP),A
        ; load the CHRGOT_11 continuation address (handoff unused by current callers)
        LD HL,CHRGOT_11
        POP AF
        ; clear carry so the caller does not mistake the token for a digit; A = the token byte
        OR A
        RET
; ----------------------------------------------------------------------
; CHRGOT_7 -- decode a 2-byte embedded constant ($0B-$0E) into a 16-bit integer value.
;   In:        HL -> the first of the two value bytes (CHRGOT_4 already advanced past the token); token in CHRGOT_CONST_TOKEN.
;   Out:       CHRGOT_CONST_TXTPTR = pointer just past the 2-byte value; A = low byte, H = high byte; falls into CHRGOT_6 to store the value and mark VALTYP=integer.
;   Clobbers:  A, H, HL, CHRGOT_CONST_TXTPTR.
;   Algorithm: Read the low byte into A; INC HL twice to position just past the 2-byte field and save that as CHRGOT_CONST_TXTPTR; DEC HL back to the high byte and load it into H. Falling into CHRGOT_6 (LD L,A) assembles HL = the little-endian 16-bit word and stages it as an integer. Path for the four 2-byte tokens: $0B = &O OCTAL radix constant, $0C = &H HEX radix constant, $0D = cached resolved line-pointer, $0E = 2-byte line-number constant.
; ----------------------------------------------------------------------
CHRGOT_7:
        ; read the low byte of the 16-bit operand
        LD A,(HL)
        INC HL
        INC HL
        ; HL now points just past both value bytes: save the resume position
        LD (CONST_TEXT_RESUME),HL
        DEC HL
        ; read the high byte; CHRGOT_6 supplies the low byte to complete HL
        LD H,(HL)
        JR CHRGOT_6
; ----------------------------------------------------------------------
; CHRGOT_8 -- decode a wide multi-byte numeric constant ($1C 2-byte int / $1D single / $1F double) by block-copying its bytes into the staging cell.
;   In:        A = token-$1C (0 for $1C, 1 for $1D, 3 for $1F); HL -> the first value byte; original token on the stack; DE/BC live (saved and restored here).
;   Out:       CHRGOT_CONST_VALTYP = width in bytes (2 for $1C, 4 for $1D, 8 for $1F); the value bytes copied to CHRGOT_CONST_VALUE_CELL; CHRGOT_CONST_TXTPTR = pointer past the value; HL = CHRGOT_11; A = token (POPped), carry CLEAR; RET. DE and BC are restored (POPped) before return.
;   Clobbers:  A, HL, flags, CHRGOT_CONST_* cells. DE/BC preserved (saved/restored).
;   Algorithm: INC A then RLCA converts the index 0/1/3 into a byte width 2/4/8 and stores it in CHRGOT_CONST_VALTYP. PUSH DE/BC, LD DE,CHRGOT_CONST_VALUE_CELL then EX DE,HL so DE=text source / HL=staging dest, LD B=width, CALL FP_MOVE_LOOP to copy width bytes text->staging. EX DE,HL leaves HL at the byte past the constant; save it to CHRGOT_CONST_TXTPTR, POP BC/DE, POP the token, load HL=CHRGOT_11, clear carry and RET. (Widths 2/4/8 verified by simulation of INC A;RLCA over indices 0/1/3.)
; ----------------------------------------------------------------------
CHRGOT_8:
        ; convert the wide-token index 0/1/3 into the byte width 2/4/8 (INC then RLCA = 2*(index+1))
        INC A
        RLCA
        ; record the constant's width / value-type for the FAC-materialize step
        LD (CONST_VALTYP),A
        PUSH DE
        PUSH BC
        ; destination = the constant staging cell; EX DE,HL then makes DE=text source, HL=dest
        LD DE,CONST_VALUE
        EX DE,HL
        LD B,A
        ; block-copy the constant's raw value bytes from the text into the staging cell
        CALL FP_MOVE_LOOP
        EX DE,HL
        POP BC
        POP DE
        ; save the resume position just past the multi-byte constant
        LD (CONST_TEXT_RESUME),HL
        POP AF
        ; load the CHRGOT_11 continuation address (handoff unused by current callers)
        LD HL,CHRGOT_11
        OR A
        RET
; ----------------------------------------------------------------------
; CHRGOT_9 -- handle the low control bytes ($01-$0A): skip $09/$0A, else fall into the digit classifier.
;   In:        A = control byte (< $0B); HL -> that byte.
;   Out:       For A >= $09 ($09/$0A) loop back to CHRGET to skip it. For A < $09, fall into CHRGOT_10 which returns NC (not a digit) with Z reflecting A.
;   Clobbers:  A, flags; HL on the skip path.
;   Algorithm: CP $09: if the byte is $09 or $0A, JP CHRGET to fetch the next char (these two low controls are skipped like spaces -- [RE] their precise original role is unconfirmed); otherwise ($01-$08) drop into CHRGOT_10 to run it through the digit/zero classifier (which reports not-a-digit).
; ----------------------------------------------------------------------
CHRGOT_9:
        ; $09/$0A are skipped like spaces ([RE] exact original meaning unconfirmed)
        CP $09
        JP NC,CHRGET
; ----------------------------------------------------------------------
; CHRGOT_10 -- the shared digit classifier: set carry iff the char in A is an ASCII digit, set Z iff A is zero.
;   In:        A = char known to be < $3A (':'), reached for $21-$39 from CHRGOT_1 or for low controls via CHRGOT_9.
;   Out:       Carry SET iff A is an ASCII digit '0'-'9' ($30-$39); carry CLEAR otherwise; Z set iff A == 0; A unchanged.
;   Clobbers:  flags only (A preserved by the INC A/DEC A pair).
;   Algorithm: CP $30 sets carry when A < '0'; CCF inverts it so carry is set when A >= '0'. Because the entry guarantees A < ':' , 'A >= $30' is exactly the digit range $30-$39, so carry now means 'is a digit'. INC A then DEC A restores A while re-deriving Z (Z iff A==0) without disturbing carry. This is the carry=digit contract every CHRGET/CHRGOT caller relies on.
; ----------------------------------------------------------------------
CHRGOT_10:
        ; compare against '0'; combined with the <':' entry this isolates the digit range
        CP $30
        ; invert so carry SET == 'char is a digit 0-9'
        CCF
        ; INC/DEC pair restores A and sets Z iff A==0, leaving carry intact
        INC A
        DEC A
        RET
; ----------------------------------------------------------------------
; CHRGOT_11 / CHRGOT_CONST_VALUE -- materialize the staged embedded constant into the floating-point accumulator (FAC) and resume scanning.
;   In:        The CHRGOT_CONST_* cells hold the decoded constant (CHRGOT_CONST_TOKEN, CHRGOT_CONST_VALTYP, CHRGOT_CONST_VALUE_CELL/_HI).
;   Out:       The constant is loaded into the FAC (and VALTYP set for the wide forms); control resumes at CHRGOT_3 (reload CHRGOT_CONST_TXTPTR and re-scan).
;   Clobbers:  A, DE, HL, FAC, VALTYP.
;   Algorithm: Read CHRGOT_CONST_TOKEN. Tokens $0D and $0E take the INT_TO_SNG path: $0D (the cached resolved line-pointer) DEREFERENCES the cached pointer in CHRGOT_CONST_VALUE_CELL (INC HL x3 then load the 2-byte line number) before INT_TO_SNG; $0E uses the staged 16-bit line number directly. All other tokens ($0B,$0C and >= $0F) go to CHRGOT_CONST_VALUE_2, which copies CHRGOT_CONST_VALTYP into the global VALTYP and either moves the single bytes into the FAC cells $0CB1/$0CB3 (VALTYP != 8) or runs the typed double move via FP_ARG_SETUP1 (VALTYP == 8). Then JP CHRGOT_3 to continue scanning. This is the consumer half that FRMEVL_EVAL_OPERAND (CP $20 / JP C,CHRGOT_CONST_VALUE) and the LIST emitter reach directly. UNKNOWN: the leading LD E,$10 at CHRGOT_11 is not consumed before E is reloaded (vestigial), and the HL=CHRGOT_11 handoff from the decode is never used by the current callers.
; ----------------------------------------------------------------------
CHRGOT_11:
        LD E,$10
; ----------------------------------------------------------------------
; CHRGOT_CONST_VALUE -- materialize a scanner-staged embedded numeric-constant token into the FAC.
;   In:        CONST_TOKEN ($0B19) = the constant-form token the scanner last saw ($0B-$1F, excluding $10/$1E); CONST_VALUE ($0B1B)/CONST_VALUE_HI ($0B1D) = the staged value bytes (or, for token $0D, a -1-biased pointer to the located BASLINE node); CONST_VALTYP ($0B1A) = the value width (VT_INT/VT_SNG/VT_DBL), consumed only on the binary-copy path.
;   Out:       FAC ($0CB1) holds the constant; VALTYP ($0B14) set to its type; character scan resumed at CHRGOT_3 (which reloads CONST_TEXT_RESUME, the text pointer just past the constant).
;   Clobbers:  A, HL, DE, VALTYP, FAC cells.
;   Algorithm: Branch on CONST_TOKEN. Tokens $0D/$0E denote a line number that must become a float: float the 16-bit value through INT_TO_SNG (CHRGOT_CONST_VALUE_1). Token $0E carries the line number directly in CONST_VALUE; token $0D carries the runtime-resolved line-link cache pointer, so the line number is fetched from the located node's BASLINE.LINENUM. All other tokens ($0B octal, $0C hex, $0F/$11-$1A/$1C int, $1D single, $1F double) already hold the value in final binary form and go to CHRGOT_CONST_VALUE_2 to copy the FAC bytes by width. Called by FRMEVL_EVAL_OPERAND ($3BF6, via 'JP C,CHRGOT_CONST_VALUE' at $3C07) to evaluate an in-expression constant, and by the LIST detokenizer (CONST_FMT_BEGIN, 'CALL CHRGOT_CONST_VALUE' at $41F3) to recover a constant's value for printing.
; ----------------------------------------------------------------------
CHRGOT_CONST_VALUE:
        ; select the materialize path by the staged constant-form token
        LD A,(CONST_TOKEN)
        CP $0F
        ; tokens >= $0F ($0F/$11-$1A int, $1C int, $1D single, $1F double): value is already in final binary form -> copy it into the FAC
        JR NC,CHRGOT_CONST_VALUE_2
        CP $0D
        ; tokens < $0D ($0B octal &O, $0C hex &H): a 2-byte integer literal -> also copy it into the FAC; only $0D/$0E fall through
        JR C,CHRGOT_CONST_VALUE_2
        ; $0D/$0E line-number form: load the staged value (for $0E the line number itself; for $0D the runtime-cached, -1-biased pointer to the located line node)
        LD HL,(CONST_VALUE)
        ; token $0E (NZ from the CP $0D): line number is already in HL, go float it directly
        JR NZ,CHRGOT_CONST_VALUE_1
        ; token $0D (cached line-link, pointer = node_base - 1): step +3 to reach BASLINE.LINENUM (struct offset +2 after undoing the -1 bias) and read the line number into HL
        INC HL
        INC HL
        INC HL
        LD E,(HL)
        INC HL
        LD D,(HL)
        EX DE,HL
; ----------------------------------------------------------------------
; CHRGOT_CONST_VALUE_1 -- float a 16-bit line number into the FAC as single precision, then resume scanning.
;   In:        HL = the 16-bit line number to materialize (from token $0E directly, or token $0D via the BASLINE.LINENUM fetch).
;   Out:       FAC holds the value as a single-precision float; VALTYP set to VT_SNG ($04) by INT_TO_SNG; control returns to the char scanner at CHRGOT_3.
;   Clobbers:  A, HL, DE, FAC cells, VALTYP.
;   Algorithm: Call INT_TO_SNG to convert the signed 16-bit integer in HL to a single-precision FAC value (INT_TO_SNG sets VALTYP=VT_SNG via SET_TYPE_DOUBLE_1+1 = LD A,$04), then JP CHRGOT_3 to reload the post-constant text pointer and continue the scan. Line numbers appearing in an expression are always promoted to a float here.
; ----------------------------------------------------------------------
CHRGOT_CONST_VALUE_1:
        ; promote the line number to a single-precision float in the FAC (line numbers are evaluated as floats; INT_TO_SNG sets VALTYP=VT_SNG)
        CALL INT_TO_SNG
        ; resume the character scan just past the consumed constant
        JP CHRGOT_3
; ----------------------------------------------------------------------
; CHRGOT_CONST_VALUE_2 -- copy an already-binary integer/single constant from the staging cells into the FAC, then resume scanning.
;   In:        CONST_VALTYP ($0B1A) = the value width (VT_INT=2 for $0B/$0C/$0F/$11-$1A/$1C, VT_SNG=4 for $1D, VT_DBL=8 for $1F); CONST_VALUE ($0B1B)/CONST_VALUE_HI ($0B1D) = the staged value bytes.
;   Out:       VALTYP ($0B14) set from CONST_VALTYP; for int/single the value words are stored into FAC ($0CB1) and FAC+2 ($0CB3); double precision is diverted to CHRGOT_CONST_VALUE_3; control returns to the scanner at CHRGOT_3.
;   Clobbers:  A, HL, VALTYP, FAC cells.
;   Algorithm: Set VALTYP from the staged width. If the width is VT_DBL, hand off to CHRGOT_CONST_VALUE_3 (the 8-byte path). Otherwise copy the staged value as two 16-bit words: CONST_VALUE -> FAC and CONST_VALUE_HI -> FAC+2. This covers both the 2-byte integer (where the upper word written to FAC+2 is stale/irrelevant, since VALTYP=int) and the 4-byte single (where FAC+2 receives the sign byte + exponent). Then JP CHRGOT_3 to continue the scan.
; ----------------------------------------------------------------------
CHRGOT_CONST_VALUE_2:
        ; publish the constant's value type (width) into VALTYP for the evaluator
        LD A,(CONST_VALTYP)
        LD (VALTYP),A
        CP VT_DBL
        ; double precision (VALTYP=VT_DBL) needs the full 8-byte move -> divert to the FP_ARG_SETUP1 path
        JR Z,CHRGOT_CONST_VALUE_3
        ; copy the staged value into the FAC: low word to FAC, high word to FAC+2 (handles both 2-byte int and 4-byte single)
        LD HL,(CONST_VALUE)
        LD (FAC),HL
        LD HL,(CONST_VALUE_HI)
        LD (FACHI),HL
        JP CHRGOT_3
; ----------------------------------------------------------------------
; CHRGOT_CONST_VALUE_3 -- materialize a staged double-precision constant into the FAC, then resume scanning.
;   In:        CONST_VALUE ($0B1B) = the base of the 8-byte double-precision value staged by the scanner; VALTYP already set to VT_DBL by CHRGOT_CONST_VALUE_2.
;   Out:       FAC double field populated from the staged bytes via FP_ARG_SETUP1; control returns to the scanner at CHRGOT_3.
;   Clobbers:  A, HL, DE, BC, FAC cells.
;   Algorithm: Point HL at CONST_VALUE (the move SOURCE) and call FP_ARG_SETUP1, the standard FP operand-setup helper that type-checks (FRMEVL_TEST_TYPE picks the FAC double field $0CAD for VALTYP>=8) and returns into the typed move routine (FP_MOVE4_1) to copy the staged operand into the FAC's working field. Then JP CHRGOT_3 to continue scanning past the constant. This is the 8-byte counterpart of the 2/4-byte copy in CHRGOT_CONST_VALUE_2.
; ----------------------------------------------------------------------
CHRGOT_CONST_VALUE_3:
        ; point at the staged 8-byte double value as the FP move source
        LD HL,CONST_VALUE
        ; type-checked, width-driven move of the double-precision operand into the FAC double field
        CALL FP_ARG_SETUP1
        JP CHRGOT_3
; ----------------------------------------------------------------------
; STMT_DEFSTR -- DEFSTR/DEFINT/DEFSNG/DEFDBL handler: set the default value-type for a letter range.
;   In:        Four entry points select the type code in E: DEFSTR ($A9) enters here (E=$03);
;              DEFINT/DEFSNG/DEFDBL enter at the +1 aliases (E=$02 / $04 / $08).
;              HL -> the statement text after the keyword (a letter, optionally 'letter-letter').
;   Out:       DEFTYPE_TBL[letter..letter] := E for each letter in each comma-separated range;
;              RET to the per-statement executor (STMT_FOR_7).
;   Clobbers:  AF,BC,DE,HL.
;   Algorithm: Load the type code into E (one of four entry points), then fall into the shared range
;              scanner STMT_DEFSTR_4. The +1 aliases exploit the 'LD BC,nn' ($01) opcode as a 2-byte
;              skip so the unwanted 'LD E,nn' instructions are stepped over and all four variants
;              converge on the same scanner carrying the correct code.
;   [RE] The codes 3/2/4/8 are the values stored into DEFTYPE_TBL; the file's own type-code notes
;        are inconsistent about the exact code->precision mapping, so the precise VALTYP meaning of
;        each code is UNKNOWN here -- the handler only writes the code, it does not interpret it.
; ----------------------------------------------------------------------
STMT_DEFSTR:
        ; DEFSTR: default type code = 3.
        LD E,$03
; [RE] Dual-entry type-code skip. DEFSTR (token $A9) enters at STMT_DEFSTR ($3484, LD E,$03); the $01 (LD BC,nn) opcodes act as 2-byte skips over each following LD E,nn. DEFINT (token $AA) is dispatched to STMT_DEFSTR_1+1 ($3487), which decodes 1E 02 as LD E,$02 (type code 2). All four entries converge at STMT_DEFSTR_4 ($348F). The DEFW is written +1 so it relocates.
STMT_DEFSTR_1:
        LD BC,$021E
; [RE] DEFSNG entry of the DEFxxx type-code skip chain. Token $AB dispatches to STMT_DEFSTR_2+1 ($348A) which decodes 1E 04 as LD E,$04 (single-precision code), then the $01 (LD BC) at $348C skips the next LD E. Joins the shared scanner at STMT_DEFSTR_4 ($348F).
STMT_DEFSTR_2:
        LD BC,$041E
; [RE] DEFDBL entry of the DEFxxx skip chain. Token $AC dispatches to STMT_DEFSTR_3+1 ($348D) which decodes 1E 08 as LD E,$08 (double-precision code), then falls into the shared CALL IS_LETTER at STMT_DEFSTR_4 ($348F). The four DEFxxx variants (string/int/sng/dbl) differ only by which LD E,nn they land on.
STMT_DEFSTR_3:
        LD BC,$081E
; ----------------------------------------------------------------------
; STMT_DEFSTR_4 -- DEFxxx range scanner: parse 'letter[-letter]' clauses and stamp the type code.
;   In:        E = the type code to assign; HL -> the first letter of a range clause.
;   Out:       DEFTYPE_TBL entries for every letter in the range set to E; loops back on a comma;
;              RET (to STMT_FOR_7) at end of statement.
;   Clobbers:  AF,BC,DE,HL.
;   Algorithm: Require a letter (IS_LETTER; carry => not a letter). RAISE_SYNTAX_ERROR is PUSHed as
;              the return so the following RET C lands there on a non-letter. Convert the letter to a
;              0-based index (-$41='A') and set both C (low bound) and B (provisional high bound). If
;              the next char is '-' (TOK_MINUS), require a second letter and use it as the high bound
;              B. Fall into STMT_DEFSTR_5 to fill DEFTYPE_TBL[C..B]:=E, then on a trailing ',' CHRGET
;              past it and re-enter here for the next clause.
; ----------------------------------------------------------------------
STMT_DEFSTR_4:
        ; A DEFxxx range must start with a letter A-Z (carry = not a letter).
        CALL IS_LETTER
        ; Pre-stage the syntax-error handler as the return taken by the RET C below if a letter is missing.
        LD BC,RAISE_SYNTAX_ERROR
        PUSH BC
        RET C
        ; Convert the start letter to a 0-based DEFTYPE_TBL index (letter - 'A').
        SUB $41
        LD C,A
        LD B,A
        CALL CHRGET
        ; A '-' introduces an explicit upper bound (e.g. DEFINT I-N).
        CP TOK_MINUS
        JR NZ,STMT_DEFSTR_5
        CALL CHRGET
        CALL IS_LETTER
        RET C
        SUB $41
        LD B,A
        CALL CHRGET
; ----------------------------------------------------------------------
; STMT_DEFSTR_5 -- compute the inclusive letter span, then point at the table and fill.
;   In:        C = low letter index, B = high letter index (B==C for a single letter), E = type code;
;              SP -> the saved text pointer was just swapped in by RAISE_SYNTAX_ERROR push at _4.
;   Out:       A = span length (B-C+1); HL := DEFTYPE_TBL+C; falls into the fill loop STMT_DEFSTR_6.
;   Clobbers:  AF,BC,DE,HL.
;   Algorithm: Compute B-C; a negative result (high < low, e.g. DEFINT N-A) RET C through the pushed
;              RAISE_SYNTAX_ERROR. INC A makes the span inclusive. EX (SP),HL stashes the text pointer
;              on the stack (discarding the pushed error-return), then LD HL,DEFTYPE_TBL / LD B,$00 /
;              ADD HL,BC points HL at DEFTYPE_TBL+low (B forced 0 so BC = the low index in C).
; ----------------------------------------------------------------------
STMT_DEFSTR_5:
        LD A,B
        ; Span = high index - low index; negative (high<low) is a syntax error via the pushed handler.
        SUB C
        RET C
        ; Make the span inclusive of both endpoints.
        INC A
        EX (SP),HL
        ; Point at DEFTYPE_TBL[low] (ADD HL,BC with B=0 adds the low letter index in C).
        LD HL,DEFTYPE_TBL
        LD B,$00
        ADD HL,BC
; ----------------------------------------------------------------------
; STMT_DEFSTR_6 -- write the type code across one letter range, then look for the next clause.
;   In:        HL -> DEFTYPE_TBL[low], A = inclusive count, E = type code; the text pointer is the
;              top stack word (stashed by _5).
;   Out:       DEFTYPE_TBL[low..high] all set to E; RET (to STMT_FOR_7) if no comma follows, else
;              CHRGET past the ',' and JR back to STMT_DEFSTR_4 for the next clause.
;   Clobbers:  AF,HL (and DE/BC via CHRGET).
;   Algorithm: Store E into successive table bytes, INC HL / DEC A until the count is exhausted. POP
;              the saved text pointer; if the current char is ',' ($2C) chain to the next range
;              clause; otherwise the statement is complete.
; ----------------------------------------------------------------------
STMT_DEFSTR_6:
        ; Set this letter's default type code.
        LD (HL),E
        INC HL
        DEC A
        JR NZ,STMT_DEFSTR_6
        POP HL
        LD A,(HL)
        ; A ',' chains another letter-range clause; anything else ends the statement.
        CP $2C
        RET NZ
        CALL CHRGET
        JR STMT_DEFSTR_4
; [RE] CHRGET then GETINT-positive: advances the text pointer, evaluates an expr to a signed 16-bit int (via GETINT_POSITIVE); used where a leading char must be skipped first (e.g. WIDTH/coord parsers at $60DD/$60F5/$7F41/$7F7F)
GETINT_CHRGET_POS:
        CALL CHRGET
; [RE] GETINT requiring a non-negative result: CALL GETINT; RET P if the high byte (D) is sign-positive (0..$7FFF), else fall into GETINT_POSITIVE_1 which loads E=$05 and JP RAISE_ERROR -> 'Illegal function call' (FC). Widely used by graphics/coord and array parsers
GETINT_POSITIVE:
        CALL GETINT
        RET P
; [RE] 'Illegal function call' (FC, error $05) trap: LD E,$05; JP RAISE_ERROR. Common target of the range/argument guards throughout the interpreter.
ERROR_FC:
        LD E,ERR_ILLEGAL_FUNCTION_CALL
        JP RAISE_ERROR
; [RE] LINGET entry handling the '.' shortcut: if current char is '.' ($2E) substitute the current line number from $0B62 and CHRGET past it; otherwise fall into LINGET to parse an explicit decimal line number into DE.
LINGET_DOT:
        LD A,(HL)
        CP $2E
        EX DE,HL
        LD HL,(ERRLIN)
        EX DE,HL
        JP Z,CHRGET
; LINGET: DEC HL then parse a decimal line number from the text at (HL) into DE (range-checked); standard MS BASIC line-number reader used by GOTO/GOSUB/ON/RESUME/THEN.
LINGET:
        DEC HL
; LINGET entry without the leading DEC HL: CHRGET the first char then parse the decimal line number into DE (LINGET re-entry used by ON-GOTO list scanning).
LINGET_NEXT:
        CALL CHRGET
        CP $0E
        JP Z,LINGET_TOKLINE
        CP $0D
; [RE] LINGET digit-accumulation loop: read ASCII digits, DE = DE*10 + digit (via the *10 sequence and $1998 overflow guard at CMP_HL_DE) until a non-digit; returns the parsed line number in DE.
LINGET_TOKLINE:
        EX DE,HL
        LD HL,(CONST_VALUE)
        EX DE,HL
        JP Z,CHRGET
        DEC HL
        LD DE,$0000
LINGET_TOKLINE_1:
        CALL CHRGET
        RET NC
        PUSH HL
        PUSH AF
        LD HL,$1998
        CALL CMP_HL_DE
        JR C,LINGET_TOKLINE_2
        LD H,D
        LD L,E
        ADD HL,DE
        ADD HL,HL
        ADD HL,DE
        ADD HL,HL
        POP AF
        SUB $30
        LD E,A
        LD D,$00
        ADD HL,DE
        EX DE,HL
        POP HL
        JR LINGET_TOKLINE_1
LINGET_TOKLINE_2:
        POP AF
        POP HL
        RET
; ----------------------------------------------------------------------
; STMT_RUN -- RUN handler (token $8A): clear variables and start program execution.
;   In:        A = first char after RUN (Z if end-of-statement), HL -> text past it. The dispatcher
;              entered the handler via CHRGET (so the arg char is already fetched) and pushed
;              STMT_FOR_7 as the post-statement return.
;   Out:       Begins execution; does not return normally (transfers to the program start, a given
;              start line, or the file loader for RUN "file").
;   Clobbers:  AF,BC,DE,HL,SP (full storage reset).
;   Algorithm: Classify the RUN argument: bare RUN (Z) -> JP CLEAR_RESET_DATAPTR (run from start);
;              RUN with a $0E (line-number token) or $0D (cached line token) -> STMT_RUN_1 (clear
;              storage and GOTO that line); otherwise -> JP LOAD_PROGRAM (filename: load/chain-run).
; ----------------------------------------------------------------------
STMT_RUN:
        ; Bare RUN: reset storage and run from the first program line.
        JP Z,CLEAR_RESET_DATAPTR
        ; RUN <line-number>: a line-number token follows.
        CP $0E
        JR Z,STMT_RUN_1
        CP $0D
        ; Neither end-of-statement nor a line token: treat the argument as a filename (RUN "file").
        JP NZ,LOAD_PROGRAM
; ----------------------------------------------------------------------
; STMT_RUN_1 -- RUN <line>: full storage reset, then transfer control to the requested line.
;   In:        HL -> the line-number argument text (a $0E or $0D line token).
;   Out:       Variables/arrays/strings/stack reset; control transfers to the target line via
;              STMT_GOSUB_1 -> STMT_GOTO (no GOSUB return frame is built).
;   Clobbers:  AF,BC,DE,HL,SP.
;   Algorithm: CALL CLEAR_RESET_STORAGE, preload BC = STMT_FOR_7, and JR STMT_GOSUB_1, which PUSHes
;              BC as the post-transfer resume address and falls into STMT_GOTO to parse and locate
;              the line. Net effect: RUN <line> = CLEAR + GOTO <line> with the per-statement executor
;              as the continuation.
; ----------------------------------------------------------------------
STMT_RUN_1:
        ; RUN always starts cold: clear variables, arrays, strings, and reset the stack.
        CALL CLEAR_RESET_STORAGE
        ; Resume into the per-statement executor after the transfer (no GOSUB return frame).
        LD BC,STMT_FOR_7
        JR STMT_GOSUB_1
; ----------------------------------------------------------------------
; STMT_GOSUB -- GOSUB handler (token $8D): build a return frame, then transfer like GOTO.
;   In:        A = first char after GOSUB, HL -> text past it; STMT_FOR_7 pushed by the dispatcher.
;   Out:       A GOSUB return frame (resume text pointer, SAVTXT, $8D marker byte, resume address) is
;              left on the stack; control transfers to the target line via STMT_GOTO_1.
;   Clobbers:  AF,BC,DE,HL,SP.
;   Algorithm: CHECK_STACK_ROOM (C=3 words) for the frame. LINGET parses the destination line number
;              into DE. POP BC recovers the pushed STMT_FOR_7 resume address, then build the frame:
;              PUSH HL twice and EX (SP),HL with SAVTXT so the stack carries the post-GOSUB text
;              pointer and SAVTXT; PUSH the $8D marker byte (PUSH AF / INC SP keeps only the byte);
;              PUSH BC (the resume address). Finally JP STMT_GOTO_1 to locate the target line.
;   [RE] The frame's $8D marker is the byte that STMT_POP/STMT_RETURN later test with CP $8D; note
;        STKFRAME_SCAN's own internal frame marker is $82, a different value (see those routines).
; ----------------------------------------------------------------------
STMT_GOSUB:
        ; Reserve stack room for the GOSUB return frame before pushing it.
        LD C,$03
        CALL CHECK_STACK_ROOM
        ; Parse the destination line number into DE.
        CALL LINGET
        POP BC
        PUSH HL
        PUSH HL
        LD HL,(SAVTXT)
        EX (SP),HL
        ; Tag the frame with $8D so RETURN/POP can recognize a GOSUB frame.
        LD A,$8D
        PUSH AF
        ; Keep only the marker byte (drop the high byte of the pushed AF word).
        INC SP
        PUSH BC
        ; Frame built: transfer to the subroutine's first line exactly like GOTO.
        JP STMT_GOTO_1
; ----------------------------------------------------------------------
; STMT_GOSUB_1 -- shared 'push resume address then GOTO' tail used by RUN <line>.
;   In:        BC = the address to resume at after the transfer (STMT_FOR_7 for RUN); HL -> the
;              pending line-number argument text.
;   Out:       BC pushed onto the stack as the continuation; falls into STMT_GOTO to parse the line
;              number and transfer.
;   Clobbers:  per STMT_GOTO.
;   Algorithm: PUSH BC then fall into STMT_GOTO. This is the no-frame variant reached from
;              STMT_RUN_1; the full GOSUB path reaches STMT_GOTO_1 directly after building a complete
;              return frame.
; ----------------------------------------------------------------------
STMT_GOSUB_1:
        ; Push the post-transfer resume address before STMT_GOTO consumes the line number.
        PUSH BC
; ----------------------------------------------------------------------
; STMT_GOTO -- GOTO handler (token $89): parse a line number and transfer to that line.
;   In:        HL -> the line-number argument text; STMT_FOR_7 pushed as the resume address.
;   Out:       On success returns with HL/BC -> the target line node (the executor continues there);
;              raises 'Undefined line number' (ERROR_UL) if the line does not exist.
;   Clobbers:  AF,BC,DE,HL.
;   Algorithm: LINGET parses the destination line number into DE, then fall into STMT_GOTO_1 to
;              locate the line (with the forward/backward search optimization) and cache it.
; ----------------------------------------------------------------------
STMT_GOTO:
        ; Parse the GOTO target line number into DE.
        CALL LINGET
; ----------------------------------------------------------------------
; STMT_GOTO_1 -- locate a target program line, cache the resolved reference, set the run cursor.
;   In:        DE = target line number; CONST_TOKEN = the constant token the scanner last decoded for
;              the line-number operand ($0D if it was already a cached/resolved line link, $0E if a
;              raw line number).
;   Out:       On a cached token, returns with HL = the cached line pointer. Otherwise HL/BC -> the
;              located line node and RET to the executor. Raises ERROR_UL if not found.
;   Clobbers:  AF,BC,DE,HL.
;   Algorithm: If CONST_TOKEN is already $0D, the reference was resolved on a prior pass -- EX DE,HL
;              and RET Z with the cached pointer. Otherwise search the program: stage the search
;              start via CONST_TEXT_RESUME, then compare the target line against the current line
;              (SAVTXT, via CMP_HL_DE) -- if carry, search forward from here (FNDLIN_LOOP), else from
;              the program start (FNDLIN). On a hit, decrement the found node pointer (DEC BC), set
;              RENUM_PENDING_FLAG, and RENUM_STORE_LINEREF writes $0D + the 2-byte (node-1) address
;              back into the source token stream so subsequent jumps skip the search; load HL=BC for
;              the executor.
;   [RE] This is MS BASIC's line-number-cache optimization: the first GOTO/GOSUB to a line resolves
;        it by search, then stores the resolved (biased) node pointer back into the tokenized line
;        ($0D + address) for O(1) re-execution. The exact role of the CALL STMT_DATA+2 / CONST_TEXT_RESUME
;        sequence in re-positioning HL before the search is inferred, not fully pinned.
; ----------------------------------------------------------------------
STMT_GOTO_1:
        ; Already resolved? CONST_TOKEN==$0D means the line reference was cached on a prior pass.
        LD A,(CONST_TOKEN)
        CP $0D
        EX DE,HL
        RET Z
        EX DE,HL
        PUSH HL
        LD HL,(CONST_TEXT_RESUME)
        EX (SP),HL
        CALL STMT_DATA+2
        INC HL
        PUSH HL
        ; Decide search direction by comparing the target line against the current line.
        LD HL,(SAVTXT)
        CALL CMP_HL_DE
        POP HL
        ; Target is at/after the current line: search forward from here.
        CALL C,FNDLIN_LOOP
        ; Target is earlier: search from the start of the program.
        CALL NC,FNDLIN
        ; Not found: 'Undefined line number'.
        JR NC,ERROR_UL
        DEC BC
        LD A,$0D
        LD (RENUM_PENDING_FLAG),A
        POP HL
        ; Cache the resolved node back into the token stream ($0D + biased node address).
        CALL RENUM_STORE_LINEREF
        LD H,B
        LD L,C
        RET
; [RE] 'Undefined line number' (error $08) trap: LD E,$08; JP RAISE_ERROR. Reached when FNDLIN cannot locate a target line (GOTO/GOSUB/ON/RESUME).
ERROR_UL:
        LD E,ERR_UNDEFINED_LINE_NUMBER
        JP RAISE_ERROR
; ----------------------------------------------------------------------
; STMT_POP -- POP handler (token $AE): discard the most recent GOSUB frame without resuming at the call.
;   In:        HL -> the statement text after POP; the runtime stack holds zero or more FOR/GOSUB
;              frames above the current scratch.
;   Out:       The top GOSUB frame (if any) is removed and SP/SAVSTK rewound past it; control
;              continues at the next statement (STMT_FOR_7). If none, falls into STMT_RETURN_1 which
;              raises 'RETURN without GOSUB'.
;   Clobbers:  AF,BC,DE,HL,SP.
;   Algorithm: Save the current text pointer (OPEN_RESUME_TEXT_PTR). Set D=$FF, then STKFRAME_SCAN_INIT
;              walks the stack, skipping FOR ($AF) frames and returning A = the first non-FOR frame
;              marker; set SP/SAVSTK to that point. If that marker is $8D (CP $8D), drop the 4-byte
;              GOSUB frame (LD HL,$0004 / ADD HL,SP / set SP,SAVSTK), restore the text pointer, and
;              JP STMT_FOR_7 -- unlike RETURN it does NOT resume at the call site. If the marker is
;              not $8D, STMT_RETURN_1 raises the error.
;   [RE] STKFRAME_SCAN returns at the FIRST non-FOR frame (its own RET NZ after CP $82); the line
;        comparison inside the scanner is only exercised for its internal $82 marker, so for finding
;        a $8D GOSUB frame the D/E target value is not actually consulted. The purpose of D=$FF here
;        is UNKNOWN beyond 'DE nonzero'.
; ----------------------------------------------------------------------
STMT_POP:
        ; Stash the text pointer; POP keeps executing the current statement's successors.
        LD (OPEN_RESUME_TEXT_PTR),HL
        LD D,$FF
        CALL STKFRAME_SCAN_INIT
        LD SP,HL
        LD (SAVSTK),HL
        ; Is the unwound frame a GOSUB frame ($8D)? If not, fall to the RETURN-without-GOSUB error.
        CP $8D
        JR NZ,STMT_RETURN_1
        ; Discard the 4-byte GOSUB frame (two saved pointers + marker) from the stack.
        LD HL,$0004
        ADD HL,SP
        LD (SAVSTK),HL
        LD SP,HL
        LD HL,(OPEN_RESUME_TEXT_PTR)
        ; POP does not transfer control: resume at the statement after POP.
        JP STMT_FOR_7
; ----------------------------------------------------------------------
; STMT_RETURN -- RETURN handler (token $8E): pop the GOSUB frame and resume after the GOSUB call.
;   In:        A/flags from the dispatcher's CHRGET (NZ if a trailing token follows RETURN); the
;              stack holds the active GOSUB return frame.
;   Out:       Restores the GOSUB caller's text pointer (SAVTXT) and resumes at the statement after
;              the GOSUB. Raises 'RETURN without GOSUB' if no GOSUB frame is found.
;   Clobbers:  AF,BC,DE,HL,SP.
;   Algorithm: RET NZ rejects a trailing argument (a bare RETURN is expected here). Set D=$FF, then
;              STKFRAME_SCAN_INIT walks the stack skipping FOR ($AF) frames and returns A = the first
;              non-FOR frame marker; set SP/SAVSTK there. CP $8D, then fall into STMT_RETURN_1.
;   [RE] Same caveat as STMT_POP: the scanner returns at the first non-FOR frame regardless of the
;        D/E target, so D=$FF's role is UNKNOWN beyond making DE nonzero.
; ----------------------------------------------------------------------
STMT_RETURN:
        ; RETURN takes no argument: a trailing token returns early (back to the executor).
        RET NZ
        ; Set D=$FF before the stack walk that finds the first non-FOR frame.
        LD D,$FF
        CALL STKFRAME_SCAN_INIT
        LD SP,HL
        LD (SAVSTK),HL
        CP $8D
; ----------------------------------------------------------------------
; STMT_RETURN_1 -- shared frame-found tail for RETURN/POP: error if no GOSUB, else restore and resume.
;   In:        Zero flag = whether the unwound frame marker matched $8D (Z=GOSUB frame found); SP
;              rewound to that frame.
;   Out:       On no match, raises ERR_RETURN_WITHOUT_GOSUB. On success, SAVTXT := the GOSUB's saved
;              text pointer and control resumes after the original GOSUB statement via STMT_FOR_7.
;   Clobbers:  AF,DE,HL,SP.
;   Algorithm: LD E,ERR_RETURN_WITHOUT_GOSUB then JP NZ,RAISE_ERROR if the marker did not match.
;              Otherwise POP the saved resume text pointer into SAVTXT, then LD HL,STMT_FOR_7 /
;              EX (SP),HL installs STMT_FOR_7 as the eventual return. Execution then continues with
;              'LD A,$E1' (a cover; A is immediately overwritten) and FALLS INTO the STMT_DATA
;              statement scanner, which advances the text pointer past the remainder of the GOSUB
;              statement to the next ':' or end-of-line and RETs to STMT_FOR_7 -- so RETURN resumes
;              at the statement following the original GOSUB.
;   [RE] The 'LD A,$E1' is the MS BASIC LD-A,(POP-HL-opcode) cover idiom; here it is reached by
;        fall-through, so its functional effect is just a (dead) LD A and a clean fall into
;        STMT_DATA, NOT an executed POP HL. The exact provenance of HL handed to the STMT_DATA scan
;        (set by EX (SP),HL) is UNKNOWN/not fully pinned.
; ----------------------------------------------------------------------
STMT_RETURN_1:
        ; No matching GOSUB frame: this is a RETURN (or POP) without GOSUB.
        LD E,ERR_RETURN_WITHOUT_GOSUB
        JP NZ,RAISE_ERROR
        POP HL
        LD (SAVTXT),HL
        ; Install the per-statement executor as the return after the resumed GOSUB statement.
        LD HL,STMT_FOR_7
        EX (SP),HL
        LD A,$E1
; ----------------------------------------------------------------------
; STMT_DATA -- DATA/REM run-time scanner: skip the body of a DATA/COMMON/REM statement (or any statement) to its terminator, while counting nested IF tokens for the IF...ELSE matcher.
;   In:        HL -> crunched text just after the statement token. Entered three ways: (a) STMT_DATA proper ($35B4) for token $84 DATA and token $B3 COMMON -- LD BC,$0E3A (C=':') then NOP then LD B,$00, then FALLS INTO STMT_DATA_1 which swaps B<->C leaving B=':' as the active terminator, so the scan stops at a colon OR end-of-line; (b) STMT_DATA+2 ($35B6): the LD BC opcode is side-stepped so the bytes $0E $00 decode as LD C,$00, then LD B,$00 and the STMT_DATA_1 swap leave B=C=$00, so the scan stops only at end-of-line ($00) -- the generic 'skip to next statement' used by REM/' , GOTO line-search, ERROR_REPORT_BODY message walking, and STMT_IF_4's false-branch skip; (c) STMT_RESUME and STMT_IF_4 JP/CALL here.
;   Out:       HL -> the terminating byte (the ':' or the $00). A = that terminator char. [RE] Z is set on BOTH RET Z exits (A=0 for end-of-line via OR A; A=':' equal to B for DATA via CP B), so Z alone does not distinguish them -- test A. D = the running IF-nesting count (see Algorithm); it is an in/out accumulator for STMT_IF_4, not a documented general output.
;   Clobbers:  A, B, C, D, HL, flags.
;   Algorithm: CHRGET-walk the text. RET on $00 (end-of-line) or on the B-register terminator (':' for DATA). A double-quote ($22) enters STMT_DATA_1 to swap B/C so ':' is ignored inside a quoted string until the closing quote. INC A skips a $FF byte. The SUB $8C test isolates the IF token ($8B): when the scanned token is $8B, CP B / ADC A,D / LD D,A increments D, so D counts nested IFs -- STMT_IF_4 starts D=1 and uses this count to pair each ELSE with the correct IF. Pure scanner: emits nothing, just advances HL to the statement boundary.
; ----------------------------------------------------------------------
STMT_DATA:
        ; DATA/COMMON entry: loads C=':'; after the NOP, LD B,$00 and the STMT_DATA_1 swap leave B=':' as the active terminator (stop at a colon as well as end-of-line)
        LD BC,$0E3A
        NOP
        LD B,$00
; ----------------------------------------------------------------------
; STMT_DATA_1 -- terminator-pair swap (string-mode toggle) for the DATA/skip scanner.
;   In:        B/C hold the active vs inactive terminator pair.
;   Out:       B and C exchanged, then falls into the scan loop at STMT_DATA_2/_3.
;   Clobbers:  A, B, C.
;   Algorithm: Rotate A<-C, C<-B, B<-A to swap the two terminator candidates. Reached two ways: (1) by fall-through from the STMT_DATA / STMT_DATA+2 entry, where it performs the INITIAL setup that promotes ':'/$00 into the active terminator B; and (2) on every double-quote during the scan, so an opening quote suppresses the ':' test (string mode) and the closing quote restores it.
; ----------------------------------------------------------------------
STMT_DATA_1:
        LD A,C
        LD C,B
        LD B,A
; ----------------------------------------------------------------------
; STMT_DATA_2 -- scanner step-back entry: DEC HL then fall into the fetch loop.
;   In:        HL -> current text byte.
;   Out:       falls into STMT_DATA_3 with HL backed up one, compensating the INC HL the loop performed on a non-special byte so CHRGET re-reads from the right place.
;   Clobbers:  HL.
;   Algorithm: Counterpart to the INC HL taken after a normal byte; keeps the net advance at one byte per scanned character.
; ----------------------------------------------------------------------
STMT_DATA_2:
        DEC HL
; ----------------------------------------------------------------------
; STMT_DATA_3 -- main fetch/classify loop of the DATA/skip scanner.
;   In:        HL -> text; B = active terminator; C = inactive terminator; D = running IF-nesting count.
;   Out:       on a terminator, RET with HL -> terminator and A = terminator (Z set on both exits -- see STMT_DATA).
;   Clobbers:  A, D, HL, flags.
;   Algorithm: CHRGET the next char; RET on $00 or on the B terminator; route $22 to the string toggle, skip $FF, count the IF token ($8B) into D; otherwise loop. Statement tokens other than IF are passed over transparently because only $00 and the active separator end the body.
; ----------------------------------------------------------------------
STMT_DATA_3:
        CALL CHRGET
        ; stop at the end-of-line terminator ($00)
        OR A
        RET Z
        ; stop at the active separator: ':' for the DATA entry, $00-only for the STMT_DATA+2 (REM-class) entry
        CP B
        RET Z
        INC HL
        ; a double-quote opens/closes a string constant: swap B/C so colons inside the quoted text are passed over verbatim
        CP $22
        JR Z,STMT_DATA_1
        INC A
        JR Z,STMT_DATA_3
        ; isolate the IF token: $8B+1-$8C == 0 marks an IF, whose nesting is then counted in D for STMT_IF_4's ELSE matcher
        SUB $8C
        JR NZ,STMT_DATA_2
        CP B
        ADC A,D
        LD D,A
        JR STMT_DATA_2
; ----------------------------------------------------------------------
; STMT_DATA_4 -- LINE INPUT# value-store finisher: store the line just read from a file into the target string variable.
;   In:        Reached by RET into this address (pushed as BC=STMT_DATA_4 by LINE_INPUT_FILE). Top of stack = a saved AF whose A is 0 (LINE_INPUT_FILE did XOR A before joining the scan); below it the target variable address; the assembled string descriptor is current.
;   Out:       A = 0+3 = $03 = VT_STR, then JR STMT_LET_1 to perform the typed (string) store into the variable.
;   Clobbers:  A, F, then whatever STMT_LET_1 clobbers.
;   Algorithm: POP AF recovers the saved A (=0 for the line-input path); ADD A,$03 makes A = VT_STR; JR STMT_LET_1 joins the shared LET store so the captured line lands in the string variable. [RE] Only caller is LINE_INPUT_FILE; the +3 here yields the string type rather than 'biasing an arbitrary VALTYP'. UNKNOWN whether any other caller reuses this entry with a non-zero saved A.
; ----------------------------------------------------------------------
STMT_DATA_4:
        ; recover the saved A (0 on the LINE INPUT# path)
        POP AF
        ; 0+3 = VT_STR: store the captured line as a string, via the shared LET store
        ADD A,$03
        JR STMT_LET_1
; ----------------------------------------------------------------------
; STMT_LET -- LET / implicit assignment handler (token $88, and the fall-through reached by NEWSTT_DISPATCH for any line that does not start with a statement keyword): evaluate the RHS expression and store it into the target variable with type coercion.
;   In:        HL -> text at the target variable name (after the optional LET token).
;   Out:       the evaluated, type-coerced value stored into the variable's cell; HL -> text after the statement; RET to the per-statement executor (STMT_FOR_7).
;   Clobbers:  A, B, C, D, E, H, L, FAC/FAC_DBL, VALTYP, OPEN_RESUME_TEXT_PTR, flags, stack temporaries.
;   Algorithm: PTRGET (entered at PTRGET_1+1) resolves the L-value to its storage address in DE. SYNCHR consumes the '=' token (inline TOK_EQ=$F0). The target address is saved BOTH into OPEN_RESUME_TEXT_PTR and pushed on the stack; the target's current VALTYP is pushed; FRMEVL_NOPAREN evaluates the right-hand side into FAC. From STMT_LET_1 on: if the result VALTYP differs from the target VALTYP, FRMEVL_APPLY_OP coerces it. For a string target it runs the descriptor-management path (alias vs copy, see STMT_LET_5); finally FP_MOVE_TYPED copies VALTYP bytes from FAC/FAC_DBL (or the 3-byte string descriptor) into the variable.
; ----------------------------------------------------------------------
STMT_LET:
        ; resolve the assignment target (L-value) to its storage address in DE
        CALL PTRGET_1+1
        ; require and consume the '=' token (TOK_EQ) between target and expression
        CALL SYNCHR
        DEFB    TOK_EQ                   ; inline keyword-token arg consumed by the preceding CALL
        EX DE,HL
        ; stash the target variable's storage address (also pushed) while the RHS is evaluated
        LD (OPEN_RESUME_TEXT_PTR),HL
        EX DE,HL
        PUSH DE
        LD A,(VALTYP)
        PUSH AF
        ; evaluate the right-hand-side expression into FAC
        CALL FRMEVL_NOPAREN
        POP AF
; ----------------------------------------------------------------------
; STMT_LET_1 -- typed-store entry: recover the target address from the stack and coerce/store the value.
;   In:        A = target value type (VALTYP code); top of stack = target storage address; FAC/FAC_DBL = evaluated value with its own VALTYP.
;   Out:       value coerced to the target type and copied into the target cell; the assignment stack frame popped; RET.
;   Clobbers:  A, B, C, D, E, H, L, flags, FAC, VALTYP.
;   Algorithm: EX (SP),HL brings the target address into HL. If the current VALTYP already equals the target type (A), skip coercion; otherwise FRMEVL_APPLY_OP converts (it dispatches OPERATOR_ROUTINE_TBL[A&7]). Select FAC (int/single) or FAC_DBL (double, VALTYP>=5) as the source, run the string-descriptor copy decision, then FP_MOVE_TYPED moves the bytes. Shared by STMT_LET and the LINE INPUT# store at STMT_DATA_4.
; ----------------------------------------------------------------------
STMT_LET_1:
        ; bring the saved target storage address into HL
        EX (SP),HL
STMT_LET_2:
        LD B,A
        LD A,(VALTYP)
        ; if the evaluated VALTYP already matches the target type, skip the coercion call
        CP B
        LD A,B
        JR Z,STMT_LET_4
        ; coerce the value to the target's type (dispatch OPERATOR_ROUTINE_TBL[A&7])
        CALL FRMEVL_APPLY_OP
STMT_LET_3:
        LD A,(VALTYP)
STMT_LET_4:
        LD DE,FAC
        CP $05
        JR C,STMT_LET_5
        LD DE,FAC_DBL
; ----------------------------------------------------------------------
; STMT_LET_5 -- string-vs-scalar store dispatch: route a string assignment through descriptor management, scalars through a direct copy.
;   In:        A = target value type; DE = source FAC base (FAC or FAC_DBL); HL/stack = target address.
;   Out:       for VT_STR, the source string is aliased or copied and its descriptor stored; for scalars, falls to STMT_LET_8 for a plain typed copy.
;   Clobbers:  A, B, C, D, E, H, L, flags, the temp string-descriptor stack.
;   Algorithm: PUSH the target address. If VALTYP != VT_STR ($03), JR to STMT_LET_8 (scalar copy). Otherwise read the source string descriptor's data pointer (DE) and order it against three pointers via CMP_HL_DE. [RE] alias (no copy, STMT_LET_7) when the string body sits in the program/variable/array region -- roughly TXTTAB <= DE <= STREND (or the DSCTMP working cell); copy via STR_BUILD_FROM_DESC (STMT_LET_6 path) when DE is BELOW TXTTAB (the volatile direct-mode/input buffer) or in the high temporary string heap (DE above that range). NOTE: the exact boundary semantics of the three compares (TXTTAB / STREND / DSCTMP) are only partly understood; the alias-vs-copy direction stated here is taken from the branch targets, but a precise 'which region is which' mapping is UNKNOWN.
; ----------------------------------------------------------------------
STMT_LET_5:
        PUSH HL
        ; string target takes the descriptor-management path; scalars fall through to the plain typed copy
        CP VT_STR
        JR NZ,STMT_LET_8
        LD HL,(FAC)
        PUSH HL
        INC HL
        LD E,(HL)
        INC HL
        LD D,(HL)
        ; first bound: a source string at/below program start (the volatile input buffer) must be copied, not aliased
        LD HL,(TXTTAB)
        CALL CMP_HL_DE
        JR NC,STMT_LET_6+1
        ; second bound: a string inside the program/variable/array area is stable and can be aliased without copying
        LD HL,(STREND)
        CALL CMP_HL_DE
        POP DE
        JR NC,STMT_LET_7
        LD HL,DSCTMP
        CALL CMP_HL_DE
        JR NC,STMT_LET_7
; ----------------------------------------------------------------------
; STMT_LET_6 -- materialise a string value into owned heap before storing, with a coded-overlap dual entry.
;   In:        DE = source string descriptor data pointer; on the fall-through entry the source pointer pushed at $3611 has already been POPped at $3624 (stack balanced); on the +1 entry it has not.
;   Out:       a heap-resident copy of the string built (STR_BUILD_FROM_DESC); falls into STMT_LET_7 to free the temp descriptor and store.
;   Clobbers:  A, D, E, H, L, flags, heap allocation pointers.
;   Algorithm: On fall-through, LD A,$D1 executes as a harmless instruction (the value loaded into A is a don't-care -- FREE_TOP_TEMP_DESCR takes its candidate descriptor in DE, not A). When entered at STMT_LET_6+1 (JR NC at the TXTTAB compare), the same $D1 byte instead decodes as POP DE, discarding the source pointer that the matching POP DE at $3624 did not consume on that branch -- a pure stack-balancing coded overlap. Either way STR_BUILD_FROM_DESC then copies the string body into freshly allocated heap before the shared free-and-store tail.
; ----------------------------------------------------------------------
STMT_LET_6:
        LD A,$D1
        CALL FREE_TOP_TEMP_DESCR
        EX DE,HL
        ; copy the source string body into freshly owned heap so the variable does not alias volatile/temp space
        CALL STR_BUILD_FROM_DESC
; ----------------------------------------------------------------------
; STMT_LET_7 -- common string-store tail: release the temporary string descriptor and recover the target address.
;   In:        the evaluated string descriptor live; target address one level down the stack.
;   Out:       top temp descriptor freed (if it matches); target address restored into HL; falls into STMT_LET_8 to copy the descriptor.
;   Clobbers:  A, D, E, H, L, flags, temp-descriptor stack.
;   Algorithm: FREE_TOP_TEMP_DESCR pops the just-consumed temporary string descriptor off the TEMPPT stack (if DE matches the top), EX (SP),HL recovers the target variable address, then STMT_LET_8 copies the now-stable descriptor bytes into the variable.
; ----------------------------------------------------------------------
STMT_LET_7:
        CALL FREE_TOP_TEMP_DESCR
        EX (SP),HL
; ----------------------------------------------------------------------
; STMT_LET_8 -- final typed copy of the value into the target variable.
;   In:        HL = target storage address; DE = source FAC/descriptor base; VALTYP = byte width.
;   Out:       VALTYP bytes copied into the target; the two pushed stack words popped; RET to the executor.
;   Clobbers:  A, B, D, E, H, L, flags.
;   Algorithm: FP_MOVE_TYPED copies VALTYP bytes from DE to HL (2/3/4/8 for int / string-descriptor / single / double), then POP DE / POP HL unwinds the assignment frame and returns.
; ----------------------------------------------------------------------
STMT_LET_8:
        ; copy VALTYP bytes (the value, or its 3-byte string descriptor) into the target variable
        CALL FP_MOVE_TYPED
        POP DE
        POP HL
        RET
; ----------------------------------------------------------------------
; STMT_ON -- ON statement handler (token $95): dispatches ON ERROR GOTO <line> and ON <expr> GOTO/GOSUB <list>.
;   In:        HL -> text after the ON token; A = the char already fetched (CP $A4 tests for the ERROR keyword).
;   Out:       ON ERROR: ON_ERROR_LINE set to the handler line's BASLINE pointer (0 disables the trap); ON <expr> GOTO/GOSUB: control transferred to the Nth line in the list (or fall through to the next statement if N exceeds the list).
;   Clobbers:  A, B, C, D, E, H, L, flags; ON_ERROR_LINE, ERRFLG.
;   Algorithm: If the next token is ERROR ($A4): consume it, SYNCHR the GOTO token, LINGET the handler line number; if 0, skip FNDLIN (disable); else FNDLIN_FROM_TEXT resolves it to a BASLINE pointer (not found -> Undefined Line). STMT_ON_1 stores it into ON_ERROR_LINE and, if a handler was already active (ONEFLG) with an armed code (ERRFLG), re-dispatches through ERROR_PRINT_SETUP. Otherwise (ON <expr> GOTO/GOSUB): STMT_ON_2 evaluates the selector with GETBYT and walks the comma-separated line list, taking the Nth line as the GOTO/GOSUB target via NEWSTT_DISPATCH.
; ----------------------------------------------------------------------
STMT_ON:
        ; ON ERROR vs ON <expr>: $A4 is the ERROR keyword token
        CP $A4
        JR NZ,STMT_ON_2
        CALL CHRGET
        CALL SYNCHR
        DEFB    TOK_GOTO                 ; inline keyword-token arg consumed by the preceding CALL
        CALL LINGET
        LD A,D
        OR E
        JR Z,STMT_ON_1
        ; resolve the ON ERROR handler line number to its BASLINE pointer
        CALL FNDLIN_FROM_TEXT
        LD D,B
        LD E,C
        POP HL
        JP NC,ERROR_UL
; ----------------------------------------------------------------------
; STMT_ON_1 -- ON ERROR arm/re-dispatch tail.
;   In:        HL = resolved handler BASLINE pointer (or 0); carry set when disabling (line 0); ONEFLG/ERRFLG reflect any pending error.
;   Out:       ON_ERROR_LINE updated; if a handler was active with a code armed, JP ERROR_PRINT_SETUP to run it; else RET.
;   Clobbers:  A, D, E, H, L, flags.
;   Algorithm: Store HL into ON_ERROR_LINE. RET C when disabling. If ONEFLG is zero (no error currently being handled) RET (A=E preserved). Otherwise load the saved code from ERRFLG into E and JP ERROR_PRINT_SETUP so the freshly-set handler takes effect at once.
; ----------------------------------------------------------------------
STMT_ON_1:
        EX DE,HL
        ; arm (or, if 0, disable) the error-trap target line
        LD (ON_ERROR_LINE),HL
        EX DE,HL
        RET C
        ; if an error is currently being handled, the new ON ERROR target takes effect immediately
        LD A,(ONEFLG)
        OR A
        LD A,E
        RET Z
        LD A,(ERRFLG)
        LD E,A
        ; re-enter the error dispatcher with the armed code so the handler runs
        JP ERROR_PRINT_SETUP
; ----------------------------------------------------------------------
; STMT_ON_2 -- ON <expr> GOTO/GOSUB selector and list walk.
;   In:        HL -> text at the selector expression; the GOTO ($89) or GOSUB ($8D) token follows it.
;   Out:       transfers to the Nth line of the list via NEWSTT_DISPATCH, or RETs (falls to the next statement) if the selector exceeds the list length.
;   Clobbers:  A, B, C, D, E, H, L, flags.
;   Algorithm: GETBYT evaluates the selector (returned in A=E). Save the following token in B; if it is GOSUB ($8D) accept it directly (JR Z,STMT_ON_3), otherwise SYNCHR-require GOTO ($89). STMT_ON_3/_4: set C = selector and DEC C each entry; when C reaches zero, JP NEWSTT_DISPATCH with A = B (the GOTO/GOSUB token) so the located line is taken. Each iteration LINGET_NEXT reads a line number and a ',' must follow (RET if not -- the list ran out before the selector, so the statement is a no-op).
; ----------------------------------------------------------------------
STMT_ON_2:
        ; evaluate the ON selector (1-based index into the line list)
        CALL GETBYT
        LD A,(HL)
        LD B,A
        ; $8D is GOSUB: accept it directly; otherwise require GOTO ($89) via SYNCHR
        CP $8D
        JR Z,STMT_ON_3
        CALL SYNCHR
        DEFB    TOK_GOTO                 ; inline keyword-token arg consumed by the preceding CALL
        DEC HL
STMT_ON_3:
        LD C,E
STMT_ON_4:
        ; count down to the selected list entry; zero => take this line as the GOTO/GOSUB target
        DEC C
        LD A,B
        JP Z,NEWSTT_DISPATCH
        CALL LINGET_NEXT
        CP $2C
        RET NZ
        JR STMT_ON_4
; ----------------------------------------------------------------------
; STMT_RESUME -- RESUME statement handler (token $A5): leave an active ON ERROR handler and resume execution (RESUME, RESUME NEXT, or RESUME <line>).
;   In:        HL -> text after the RESUME token; ONEFLG nonzero (a handler is running); ERR_SAVTXT/RESUME_TXTPTR hold the error-time text pointers.
;   Out:       execution resumed: at the offending statement (plain RESUME, via the RET NZ in STMT_RESUME_2 to RESUME_TXTPTR), at the statement after it (RESUME NEXT), or at <line> (RESUME <line> -> STMT_GOTO_1); ERRFLG/ONEFLG updated; SAVTXT reloaded from ERR_SAVTXT.
;   Clobbers:  A, D, E, H, L, flags; ERRFLG, ONEFLG, SAVTXT.
;   Algorithm: If ONEFLG is 0 there is no error to resume -> RAISE_RESUME_WITHOUT_ERROR. Otherwise INC A and store the result into both ERRFLG and ONEFLG (mark the handler exited). If the next token is NEXT ($83) -> STMT_RESUME_1 (RESUME NEXT). Else LINGET a line number: if nonzero, RESUME <line> -> STMT_GOTO_1; if absent (plain RESUME) INC A (force NZ) and join STMT_RESUME_2. STMT_RESUME_2 reloads SAVTXT from ERR_SAVTXT and, on NZ (plain RESUME), RETs immediately so execution restarts at RESUME_TXTPTR (the exact offending statement); on Z (RESUME NEXT) it falls into the line/statement-advance code and STMT_RESUME_3 -> JP STMT_DATA.
; ----------------------------------------------------------------------
STMT_RESUME:
        LD DE,ONEFLG
        LD A,(DE)
        OR A
        ; RESUME outside an active error handler is an error
        JP Z,RAISE_RESUME_WITHOUT_ERROR
        INC A
        LD (ERRFLG),A
        LD (DE),A
        LD A,(HL)
        ; RESUME NEXT (token $83 = NEXT): resume at the statement AFTER the one that failed
        CP $83
        JR Z,STMT_RESUME_1
        CALL LINGET
        RET NZ
        LD A,D
        OR E
        ; RESUME <line>: transfer like GOTO to the given line
        JP NZ,STMT_GOTO_1
        INC A
        JR STMT_RESUME_2
; ----------------------------------------------------------------------
; STMT_RESUME_1 -- RESUME NEXT branch.
;   In:        HL -> the NEXT token ($83) just matched at STMT_RESUME.
;   Out:       CHRGET past it; RET NZ if non-end-of-statement junk follows; else falls into STMT_RESUME_2 with Z set, so the resume positions at the statement following the error.
;   Clobbers:  A, HL, flags.
;   Algorithm: Consume the NEXT keyword and verify end-of-statement, then join the common resume-pointer reload (the Z flag from this CHRGET drives STMT_RESUME_2's RET NZ test).
; ----------------------------------------------------------------------
STMT_RESUME_1:
        CALL CHRGET
        RET NZ
STMT_RESUME_2:
        LD HL,(RESUME_TXTPTR)
        EX DE,HL
        LD HL,(ERR_SAVTXT)
        LD (SAVTXT),HL
        EX DE,HL
        RET NZ
        LD A,(HL)
        OR A
        JR NZ,STMT_RESUME_3
        INC HL
        INC HL
        INC HL
        INC HL
; ----------------------------------------------------------------------
; STMT_RESUME_3 -- RESUME NEXT statement-advance tail: position the text pointer at the statement after the error and re-enter execution.
;   In:        HL = RESUME_TXTPTR (error-time cursor); reached only on the RESUME NEXT path (the RET NZ in STMT_RESUME_2 already returned plain RESUME). SAVTXT was reloaded from ERR_SAVTXT in STMT_RESUME_2.
;   Out:       HL stepped over the rest of the failed statement (and, when the error was at end-of-line, over the next BASLINE's 4-byte link+linenum header), then JP STMT_DATA scans to the next statement boundary so the executor continues there.
;   Clobbers:  A, H, L, flags.
;   Algorithm: If (HL) is nonzero the error was mid-line, so a single INC HL then JP STMT_DATA skips to the next ':'/end. If (HL) is $00 (error at end of its line), four INC HL skip the next line's BASLINE header (link word + line-number word) before STMT_RESUME_3's INC HL and JP STMT_DATA, restarting at that next line. [RE] the precise byte counts were read from the code; the line-crossing case is the RESUME-NEXT-at-end-of-line path.
; ----------------------------------------------------------------------
STMT_RESUME_3:
        INC HL
        ; scan to the next statement boundary, then the executor continues from there
        JP STMT_DATA
; ----------------------------------------------------------------------
; STMT_ERROR -- ERROR statement handler (token $A4): raise the user-specified error code through the normal error machinery.
;   In:        HL -> text after the ERROR token; the operand is a byte expression (the error code).
;   Out:       does not return normally: JP RAISE_ERROR with the code in E (GETBYT leaves A=E), or JP ERROR_FC if the code is 0.
;   Clobbers:  A, E, flags (then control leaves via RAISE_ERROR/ERROR_FC).
;   Algorithm: GETBYT evaluates the code into A (=E); RET NZ rejects trailing junk; code 0 is itself illegal (JP ERROR_FC, Illegal Function Call); otherwise JP RAISE_ERROR to report/trap exactly as if BASIC had raised that error -- how programs simulate or re-raise errors.
; ----------------------------------------------------------------------
STMT_ERROR:
        ; evaluate the ERROR statement's code operand into A (=E)
        CALL GETBYT
        RET NZ
        OR A
        JP Z,ERROR_FC
        ; drive the code (in E) through the normal error dispatcher (ON ERROR trap or '?... Error' report)
        JP RAISE_ERROR
; ----------------------------------------------------------------------
; STMT_AUTO -- AUTO command handler (token $A7): begin auto line-numbering for program entry.
;   In:        HL -> text after the AUTO token. Operands: optional start line and optional ',' increment. Z (from the dispatcher's CHRGET) indicates AUTO with no arguments.
;   Out:       AUTLIN = starting line number, AUTINC = increment (default 10 / $000A), AUTFLG set nonzero (auto mode on); then JP DIRECT_LINE_DISPATCH to re-enter the line-input loop pre-numbered.
;   Clobbers:  A, B, C, D, E, H, L, flags; AUTLIN, AUTINC, AUTFLG.
;   Algorithm: Push the default increment $000A. With no start, jump straight to the store. Otherwise LINGET_DOT parses the start ('.' = current line) into HL and swaps it onto the stack; an optional ',' (SYNCHR ',') then introduces an explicit increment via LINGET (default kept = the prior AUTINC). A zero start or increment is rejected (ERROR_FC). Store AUTINC, set AUTFLG nonzero, POP the start into AUTLIN, discard the caller return (POP BC), then JP DIRECT_LINE_DISPATCH so subsequent input lines are auto-numbered. This is the AUTO command, not a RESUME/line-scan helper.
; ----------------------------------------------------------------------
STMT_AUTO:
        ; default AUTO increment = 10
        LD DE,$000A
        PUSH DE
        JR Z,STMT_AUTO_1
        ; parse the optional starting line number ('.' = current line)
        CALL LINGET_DOT
        EX DE,HL
        EX (SP),HL
        JR Z,STMT_AUTO_2
        EX DE,HL
        CALL SYNCHR
        ; an optional comma introduces an explicit increment
        DEFB    ','                      ; inline char arg consumed by the preceding CALL
        EX DE,HL
        LD HL,(AUTINC)
        EX DE,HL
        JR Z,STMT_AUTO_1
        CALL LINGET
        JP NZ,RAISE_SYNTAX_ERROR
STMT_AUTO_1:
        EX DE,HL
STMT_AUTO_2:
        LD A,H
        OR L
        JP Z,ERROR_FC
        LD (AUTINC),HL
        ; turn AUTO line-numbering mode on (A = nonzero increment)
        LD (AUTFLG),A
        POP HL
        LD (AUTLIN),HL
        POP BC
        ; re-enter the interactive line-input loop, now issuing auto line numbers
        JP DIRECT_LINE_DISPATCH
; ----------------------------------------------------------------------
; STMT_IF -- IF statement handler (token $8B): evaluate the condition and branch to the THEN clause, an ELSE clause, or the next line.
;   In:        HL -> text after the IF token (the condition expression).
;   Out:       if true, executes the THEN clause (GOTO a line, a pre-resolved line, or inline statements); if false, scans forward past the matching ELSE (honouring nested IF/ELSE depth) to the alternate clause or end of line.
;   Clobbers:  A, B, C, D, E, H, L, flags, FAC.
;   Algorithm: FRMEVL_NOPAREN evaluates the condition into FAC. Skip an optional ','; if the following token is GOTO ($89) go to STMT_IF_1, else SYNCHR-require THEN. STMT_IF_1 tests the condition with FP_TEST_SIGN: nonzero (true) -> STMT_IF_2 runs the consequent; zero (false) -> STMT_IF_3/_4 scan forward via STMT_DATA to the matching ELSE ($9E), using D as the IF-nesting depth so a nested IF's ELSE is not mistaken for ours.
; ----------------------------------------------------------------------
STMT_IF:
        ; evaluate the IF condition into FAC
        CALL FRMEVL_NOPAREN
        LD A,(HL)
        CP $2C
        CALL Z,CHRGET
        CP TOK_GOTO
        JR Z,STMT_IF_1
        CALL SYNCHR
        DEFB    TOK_THEN                 ; inline keyword-token arg consumed by the preceding CALL
        DEC HL
; ----------------------------------------------------------------------
; STMT_IF_1 -- IF condition-test entry (after the THEN/GOTO token consumed).
;   In:        HL -> the consequent text; FAC = condition value.
;   Out:       Z reflects the condition (Z = false); HL preserved; branches to STMT_IF_3 on false, falls into STMT_IF_2 on true.
;   Clobbers:  A, flags (HL saved/restored across the test).
;   Algorithm: PUSH/POP HL around FP_TEST_SIGN so the consequent pointer survives the floating-point sign test.
; ----------------------------------------------------------------------
STMT_IF_1:
        PUSH HL
        ; test the condition: nonzero = true (run THEN), zero = false (skip to ELSE/next line)
        CALL FP_TEST_SIGN
        POP HL
        JR Z,STMT_IF_3
; ----------------------------------------------------------------------
; STMT_IF_2 -- execute the true (THEN) clause.
;   In:        HL -> consequent text (after THEN/GOTO).
;   Out:       transfers to the THEN target: GOTO a line ($0E line-number token), resume an already-resolved line ($0D cached-pointer token), or execute inline statements via NEWSTT_DISPATCH; RET on end-of-line.
;   Clobbers:  A, H, L, flags.
;   Algorithm: CHRGET the first consequent char. End-of-line -> RET. $0E (a 2-byte line-number constant token) -> JP STMT_GOTO ('IF c THEN 100'). If not $0D -> JP NEWSTT_DISPATCH (inline statement list). If $0D (a line reference already resolved to a cached BASLINE node pointer) -> LD HL,(CONST_VALUE) and RET, so the caller resumes at that pre-resolved node like a fast GOTO.
; ----------------------------------------------------------------------
STMT_IF_2:
        CALL CHRGET
        RET Z
        ; 'THEN <line-number>' shorthand ($0E line-number token) -> treat as GOTO
        CP $0E
        JP Z,STMT_GOTO
        CP $0D
        ; not a line reference: the THEN clause is an inline statement list -> execute it
        JP NZ,NEWSTT_DISPATCH
        LD HL,(CONST_VALUE)
        RET
STMT_IF_3:
        LD D,$01
; ----------------------------------------------------------------------
; STMT_IF_4 -- false-branch skip: scan forward to the matching ELSE (or end of line), honouring nested IF/ELSE depth.
;   In:        D = nesting depth counter (1 on entry from STMT_IF_3); HL -> text to scan.
;   Out:       on finding the matching-depth ELSE, joins STMT_IF_2 to run the ELSE clause; if end-of-line is reached first, RET (fall through to the next line).
;   Clobbers:  A, B, C, D, H, L, flags.
;   Algorithm: CALL STMT_DATA skips a statement's worth of text (and, via STMT_DATA's IF-counter, increments D for each nested IF token encountered). At end-of-line (A=0) RET. CHRGET the terminator; an ELSE ($9E) decrements D -- depth 0 means this ELSE pairs with our IF, so jump to STMT_IF_2 to execute the ELSE clause; otherwise keep scanning so inner ELSEs are skipped.
; ----------------------------------------------------------------------
STMT_IF_4:
        ; skip one statement's worth of text (which also counts nested IF tokens into D) while hunting for our ELSE
        CALL STMT_DATA
        OR A
        RET Z
        CALL CHRGET
        ; an ELSE at matching nesting depth pairs with this IF -> run the ELSE clause
        CP TOK_ELSE
        JR NZ,STMT_IF_4
        ; track IF/ELSE nesting so a nested IF's ELSE is not mistaken for ours
        DEC D
        JR NZ,STMT_IF_4
        JR STMT_IF_2
; ----------------------------------------------------------------------
; STMT_LPRINT -- LPRINT statement handler (token $9B): direct PRINT output to the line printer, then fall into the shared PRINT engine.
;   In:        HL -> text after the LPRINT token (the print list).
;   Out:       PRTFLG set to 1 (route output to the printer); JP STMT_PRINT_1 to run the common print-list walker (skipping the file-number parse).
;   Clobbers:  A; PRTFLG.
;   Algorithm: Set PRTFLG=1 so OUTCHR sends to the printer device, then join STMT_PRINT_1. LPRINT is PRINT with the printer flag set; PRTFLG is cleared again by the PRINT epilogue when the statement finishes.
; ----------------------------------------------------------------------
STMT_LPRINT:
        LD A,$01
        ; route output to the line printer, then run the shared PRINT engine
        LD (PRTFLG),A
        JP STMT_PRINT_1
; PRINT statement engine (shared by PRINT/LPRINT/PRINT#): walk the print list emitting expressions, honour ',' tab zones and ';' (no-space), TAB($E8)/SPC($DF)/USING($E3) functions, and emit CRLF unless suppressed; column tracking via $0837/$0B11.
STMT_PRINT:
        LD C,$02
        CALL PARSE_FILENUM_HASH
STMT_PRINT_1:
        DEC HL
        CALL CHRGET
        CALL Z,CRLF
STMT_PRINT_2:
        JP Z,PRINT_RESET_STATE
        CP TOK_USING
        JP Z,PRINT_USING
        CP $DF
        JP Z,STMT_PRINT_11
        CP $E3
        JP Z,STMT_PRINT_11
        PUSH HL
        CP $2C
        JR Z,STMT_PRINT_7
        CP $3B
        JP Z,STMT_PRINT_20
        POP BC
        CALL FRMEVL_NOPAREN
        PUSH HL
        CALL FRMEVL_TEST_TYPE
        JR Z,STMT_PRINT_3
        CALL FOUT_2
        CALL SCAN_STR_LITERAL
        LD (HL),$20
        LD HL,(FAC)
        INC (HL)
STMT_PRINT_3:
        LD HL,(PTRFIL)
        LD A,H
        OR L
        JR NZ,STMT_PRINT_6
        LD HL,(FAC)
        LD A,(PRTFLG)
        OR A
        JR Z,STMT_PRINT_4
        LD A,(PRINTER_WIDTH)
        LD B,A
        INC A
        JP Z,STMT_PRINT_6
        LD A,(OUTPUT_COLUMN)
        OR A
        JP Z,STMT_PRINT_6
        ADD A,(HL)
        CCF
        JR NC,STMT_PRINT_5
        CP B
        JR STMT_PRINT_5
STMT_PRINT_4:
        LD A,(PRINT_WIDTH)
        LD B,A
        INC A
        JR Z,STMT_PRINT_6
        LD A,(CURSOR_POS)
        OR A
        JR Z,STMT_PRINT_6
        ADD A,(HL)
        CCF
        JR NC,STMT_PRINT_5
        DEC A
        CP B
STMT_PRINT_5:
        CALL NC,CRLF
STMT_PRINT_6:
        CALL STRPRT
        POP HL
        JP STMT_PRINT_1
STMT_PRINT_7:
        LD HL,(PTRFIL)
        LD A,H
        OR L
        LD BC,FCB.BUF_REM
        ADD HL,BC
        LD A,(HL)
        JR NZ,STMT_PRINT_10
        LD A,(PRTFLG)
        OR A
        JR Z,STMT_PRINT_8
        LD A,(LPRINT_ZONE_WIDTH)
        LD B,A
        INC A
        LD A,(OUTPUT_COLUMN)
        JR Z,STMT_PRINT_10
        CP B
        JP STMT_PRINT_9
STMT_PRINT_8:
        LD A,(WIDTH_FILE)
        LD B,A
        LD A,(CURSOR_POS)
        CP $FF
        JR Z,STMT_PRINT_10
        CP B
STMT_PRINT_9:
        CALL NC,CRLF
        JP NC,STMT_PRINT_20
STMT_PRINT_10:
        SUB $0E
        JR NC,STMT_PRINT_10
        CPL
        JP STMT_PRINT_18
STMT_PRINT_11:
        PUSH AF
        CALL CHRGET
        CALL GETINT
        POP AF
        PUSH AF
        CP $E3
        JR Z,STMT_PRINT_12
        DEC DE
STMT_PRINT_12:
        LD A,D
        OR A
        JP P,STMT_PRINT_13
        LD DE,$0000
STMT_PRINT_13:
        PUSH HL
        LD HL,(PTRFIL)
        LD A,H
        OR L
        JR NZ,STMT_PRINT_15
        LD A,(PRTFLG)
        OR A
        LD A,(PRINTER_WIDTH)
        JR NZ,STMT_PRINT_14
        LD A,(PRINT_WIDTH)
STMT_PRINT_14:
        LD L,A
        INC A
        JR Z,STMT_PRINT_15
        LD H,$00
        CALL INT_DIV_ROUND
        EX DE,HL
STMT_PRINT_15:
        POP HL
        CALL SYNCHR
        DEFB    ')'                      ; inline char arg consumed by the preceding CALL
        DEC HL
        POP AF
        SUB $E3
        PUSH HL
        JR Z,STMT_PRINT_17
        LD HL,(PTRFIL)
        LD A,H
        OR L
        LD BC,FCB.BUF_REM
        ADD HL,BC
        LD A,(HL)
        JR NZ,STMT_PRINT_17
        LD A,(PRTFLG)
        OR A
        JP Z,STMT_PRINT_16
        LD A,(OUTPUT_COLUMN)
        JR STMT_PRINT_17
STMT_PRINT_16:
        LD A,(CURSOR_POS)
STMT_PRINT_17:
        CPL
        ADD A,E
        JR C,STMT_PRINT_18
        INC A
        JR Z,STMT_PRINT_20
        CALL CRLF
        LD A,E
        DEC A
        JP M,STMT_PRINT_20
STMT_PRINT_18:
        INC A
        LD B,A
        LD A,$20
STMT_PRINT_19:
        CALL OUTCHR
        DJNZ STMT_PRINT_19
STMT_PRINT_20:
        POP HL
        CALL CHRGET
        JP STMT_PRINT_2
; [RE] PRINT epilogue/reset: clear the LPRINT-direction flag $0838 and the file/device pointer $0840 back to console defaults at the end of a PRINT statement.
PRINT_RESET_STATE:
        XOR A                            ; [RE] PRINT epilogue/reset: clear the printer-output selector PRTFLG ($0838) and the current-file pointer PTRFIL ($0840) back to console defaults (0) at the end of a PRINT statement.
        LD (PRTFLG),A
        PUSH HL
        LD H,A
        LD L,A
        LD (PTRFIL),HL
        POP HL
        RET
; ----------------------------------------------------------------------
; STMT_LINE -- LINE INPUT statement handler (token LINE, $AD): read one whole console line (or one whole file line) verbatim into a single string variable.
;   In:        HL -> program text just past the LINE token (the next token must be INPUT). A = current char.
;   Out:       The destination string variable is assigned the entire typed/read line as a string (VALTYP=VT_STR). On an aborted console read (INLIN returns carry) control diverts to STMT_END_2+1 (statement ends with the break flag, value unset). HL advanced past the statement.
;   Clobbers:  AF, BC, DE, HL; the leading-';' flag L_0C93 (via INPUT_PROMPT_SEP) and CTRL_O_SUPPRESS/L_0C94 (via INPUT_PROMPT); the target variable's value.
;   Algorithm: SYNCHR-assert the INPUT keyword follows LINE (the inline DEFB TOK_INPUT is the token CALL SYNCHR consumes). If the next char is '#' ($23) this is LINE INPUT# -> JP LINE_INPUT_FILE. Otherwise: INPUT_PROMPT_SEP records an optional leading ';' (sets L_0C93 to suppress the closing CR/LF), INPUT_PROMPT emits an optional quoted prompt, PTRGET resolves the target variable and REQUIRE_STRING checks it is a string. Save var ptr + text ptr, INLIN reads one edited console line into BUF; a carry return (Ctrl-C / aborted) jumps to STMT_END_2+1. Then SCAN_STR_TERM with B=0 (so SCAN_STR_TERM's LD D,B leaves D=0 too -> stops only at the line's NUL) builds a STRDESC spanning the whole line, and JP STMT_LET_1 with A=VT_STR=3 assigns it to the variable.
; ----------------------------------------------------------------------
STMT_LINE:
        CALL SYNCHR
        DEFB    TOK_INPUT                ; inline keyword-token arg consumed by the preceding CALL
        ; LINE INPUT#: a '#' here means read from a file, not the console -- hand off to the file path
        CP $23
        JP Z,LINE_INPUT_FILE
        ; record an optional leading ';' (it sets L_0C93 to suppress the closing CR/LF), then INPUT_PROMPT emits the optional quoted prompt
        CALL INPUT_PROMPT_SEP
        CALL INPUT_PROMPT
        ; resolve the destination variable; REQUIRE_STRING then rejects a numeric target (LINE INPUT only stores strings)
        CALL PTRGET_1+1
        CALL REQUIRE_STRING
        PUSH DE
        PUSH HL
        ; read one fully-edited console line into BUF; carry on return means the input was aborted (Ctrl-C) -> end the statement
        CALL INLIN
        POP DE
        POP BC
        JP C,STMT_END_2+1
        PUSH BC
        PUSH DE
        ; B=0 (and so D=0 inside SCAN_STR_TERM): no extra delimiter, capture the whole line up to its NUL as one string field
        LD B,$00
        CALL SCAN_STR_TERM
        POP HL
        ; assign the captured line (VALTYP=VT_STR=3) to the variable via the LET store tail
        LD A,$03
        JP STMT_LET_1
; INPUT error literal "?Redo from start" + CR/LF; STROUT'd by the INPUT re-prompt path (STMT_LINE_2) when the user's typed reply does not parse. The INPUT value-parse code follows the $00 terminator.
MSG_REDO_FROM_START:
        DEFB    "?Redo from start"       ; string
        DEFB    $0D                      ; terminator
        DEFB    "\n\0"
; ----------------------------------------------------------------------
; STMT_LINE_1 -- skip a quoted-string literal embedded in the INPUT variable list's array-subscript expression (in the PROGRAM text), then rejoin the paren-balancing subscript scan.
;   In:        HL -> the opening '"' of a quoted literal inside a subscript expression in the crunched program text (entered from INPUT_PROMPT_8 on CP $22 while it is walking the parenthesized subscript that follows an array variable in the INPUT list). [RE]
;   Out:       HL advanced to the closing '"'; control returns to INPUT_PROMPT_8 (via JP) to continue the subscript scan. A NUL before the closing quote raises Syntax error.
;   Clobbers:  AF, HL.
;   Algorithm: Walk forward (INC HL / LD A,(HL)) over the quoted-string body verbatim. A NUL ($00) before the close means the program text is malformed -> JP RAISE_SYNTAX_ERROR. On the matching '"' ($22) JP INPUT_PROMPT_8 (a backward jump -- INPUT_PROMPT_8 sits physically above this routine) to resume balancing parens of the subscript.
; ----------------------------------------------------------------------
STMT_LINE_1:
        INC HL
        LD A,(HL)
        OR A
        ; unterminated quoted literal inside the subscript expression -> Syntax error
        JP Z,RAISE_SYNTAX_ERROR
        CP $22
        ; skip the quoted-string body verbatim until its closing quote
        JR NZ,STMT_LINE_1
        JP INPUT_PROMPT_8
STMT_LINE_2:
        POP HL
        POP HL
        JP STMT_LINE_4
; ----------------------------------------------------------------------
; STMT_LINE_3 -- malformed READ/INPUT field fork: route the error to either the program-DATA error path (READ) or the console re-prompt (INPUT).
;   In:        L_0B53 = source flag (0 = console INPUT, nonzero = program DATA/READ). Stack holds the saved INPUT/READ context (consumed by STMT_LINE_4's POP).
;   Out:       READ case: JP CONT_RESUME_RESTORE, which re-points SAVTXT at the saved DATA line then falls into RAISE_SYNTAX_ERROR (so the Syntax error is reported against the DATA line). INPUT case: falls into STMT_LINE_4 to print '?Redo from start' and re-enter the INPUT statement.
;   Clobbers:  AF (READ path continues into the error machinery).
;   Algorithm: Read L_0B53; if nonzero (a READ of program DATA produced a bad value) JP CONT_RESUME_RESTORE, which loads DATA_LINE_TXTPTR into SAVTXT and raises Syntax error so the message blames the DATA line. If zero (console INPUT) fall through to STMT_LINE_4, the '?Redo from start' re-prompt.
; ----------------------------------------------------------------------
STMT_LINE_3:
        LD A,(L_0B53)
        OR A
        ; a bad value came from program DATA: re-point SAVTXT at the DATA line so the Syntax error blames it, then raise
        JP NZ,CONT_RESUME_RESTORE
; ----------------------------------------------------------------------
; STMT_LINE_4 -- INPUT re-prompt: print '?Redo from start' and re-execute the INPUT statement from its start.
;   In:        Stack top = the saved INPUT context word (discarded). OLDTXT = text pointer to the start of the current statement.
;   Out:       MSG_REDO_FROM_START printed via STROUT; HL := OLDTXT; RET (so the interpreter re-runs the INPUT statement, re-reading the line).
;   Clobbers:  AF, BC, HL.
;   Algorithm: POP the stale context word, STROUT the '?Redo from start' message, load HL from OLDTXT (the statement's start) and RET -- the statement is then re-entered so the user re-types the reply.
; ----------------------------------------------------------------------
STMT_LINE_4:
        POP BC
        LD HL,MSG_REDO_FROM_START
        CALL STROUT
        LD HL,(OLDTXT)
        RET
; ----------------------------------------------------------------------
; STMT_LINE_5 -- INPUT# entry: read fields from a file (rather than the console) into the variable list.
;   In:        HL -> the '#' of an INPUT# statement (STMT_INPUT jumped here on CP $23).
;   Out:       PTRFIL selected to the named file's FCB; control enters the shared field-binding tail seeded with the in-image fixed ',' at L_0A0D (so the first field reads as if a separator preceded it).
;   Clobbers:  AF, BC, DE, HL; PTRFIL.
;   Algorithm: GET_FILENUM_PREFIX_C1 parses the '#file,' channel prefix (requiring sequential-input mode, though a RANDOM file is also tolerated) and sets PTRFIL to that file's FCB. Push the text pointer, point HL at the fixed comma byte L_0A0D (a constant ',' that primes the field scanner), and JP INPUT_PROMPT_12, which stores ',' there and joins STMT_READ_1+1 -- the shared READ/INPUT variable walk -- now sourcing characters from the file because PTRFIL is nonzero.
; ----------------------------------------------------------------------
STMT_LINE_5:
        ; parse the '#file,' prefix (default/required mode = sequential input; RANDOM also accepted) and select it via PTRFIL
        CALL GET_FILENUM_PREFIX_C1
        PUSH HL
        LD HL,BUF_INPUT_RESET_PTR
        JP INPUT_PROMPT_12
; ----------------------------------------------------------------------
; STMT_INPUT -- INPUT statement handler (token INPUT, $85): emit an optional prompt, read one console line, then parse comma-separated fields into the variable list.
;   In:        HL -> program text just past the INPUT token. A = current char.
;   Out:       Each named variable receives its parsed field (numeric via FIN, string via SCAN_STR_BODY). On a short/over-long reply the user is re-prompted ('?Redo from start'); on Ctrl-C the statement aborts via STMT_END_2+1. HL advanced past the statement.
;   Clobbers:  AF, BC, DE, HL; L_0C93/L_0C94/CTRL_O_SUPPRESS/L_0B53 and the assigned variables.
;   Algorithm: If the next char is '#' ($23) this is INPUT# -> JP STMT_LINE_5 (file path). Otherwise INPUT_PROMPT_SEP records an optional leading ';' (CR/LF-suppress, in L_0C93), then push INPUT_EMIT_PROMPT as the continuation and fall into INPUT_PROMPT. INPUT_PROMPT parses/emits the optional quoted prompt and sets L_0C94 (whether the automatic '? ' marker is shown); INPUT_EMIT_PROMPT then emits the marker, reads the line and drives the value-parse loop.
; ----------------------------------------------------------------------
STMT_INPUT:
        CP $23
        ; INPUT#: '#' means read fields from a file instead of the console
        JP Z,STMT_LINE_5
        CALL INPUT_PROMPT_SEP
        ; queue the line-read+parse continuation to run after the optional prompt string is emitted
        LD BC,INPUT_EMIT_PROMPT
        PUSH BC
; ----------------------------------------------------------------------
; INPUT_PROMPT -- INPUT/LINE-INPUT prompt parser: emit an optional quoted prompt string and decide whether the automatic '? ' marker is shown.
;   In:        A = current char; HL -> program text. Reached with INPUT_EMIT_PROMPT (or the LINE INPUT body) queued as the caller.
;   Out:       CTRL_O_SUPPRESS cleared; L_0C94 = show-'?' flag (preset $FF=show). If a quoted prompt is present it is printed via STRPRT; a following ',' clears L_0C94 (suppress the '?'), a following ';' is required and keeps the '?'. If no quote, RET immediately with the marker enabled.
;   Clobbers:  AF, HL; CTRL_O_SUPPRESS, L_0C94.
;   Algorithm: Compare the char to '"' ($22) first; the result is preserved across the next two LDs, which unconditionally clear CTRL_O_SUPPRESS and set L_0C94=$FF (default: show the '? ' marker). RET NZ if there was no quote (plain INPUT with the marker). On a quote, SCAN_STR_QUOTE captures the prompt literal; if the delimiter after it is ',' clear L_0C94 (trailing comma means 'no question mark') and CHRGET past it; otherwise SYNCHR-require ';'. Either way STRPRT prints the prompt string and RET.
; ----------------------------------------------------------------------
INPUT_PROMPT:
        CP $22
        LD A,$00
        LD (CTRL_O_SUPPRESS),A
        ; default: show the automatic '? ' input marker (L_0C94 nonzero); a trailing ',' below will clear it
        LD A,$FF
        LD (L_0C94),A
        ; no quoted prompt (the saved CP $22 was not equal): plain INPUT, return with the '?' marker enabled
        RET NZ
        ; capture the quoted prompt literal into a string descriptor
        CALL SCAN_STR_QUOTE
        LD A,(HL)
        CP $2C
        JR NZ,INPUT_PROMPT_2
        ; prompt followed by ',' -> clear L_0C94 to suppress the automatic '?' marker (PRINT-style prompt)
        XOR A
        LD (L_0C94),A
INPUT_PROMPT_1:
        CALL CHRGET
        JR INPUT_PROMPT_3
INPUT_PROMPT_2:
        CALL SYNCHR
        DEFB    ';'                      ; inline char arg consumed by the preceding CALL
INPUT_PROMPT_3:
        PUSH HL
        ; print the prompt string to the console
        CALL STRPRT
        POP HL
        RET
; [RE] INPUT continuation: emits the '? ' prompt via OUTCHR, reads the console line (INLIN), and on empty/abort branches to STMT_END; falls through to the value-parse loop $394D.
INPUT_EMIT_PROMPT:
        PUSH HL
        LD A,(L_0C94)
        OR A
        JR Z,INPUT_PROMPT_5
        LD A,$3F
        CALL OUTCHR
        LD A,$20
        CALL OUTCHR
; ----------------------------------------------------------------------
; INPUT_PROMPT_5 -- read the console reply line and prime the field-parse loop (tail of INPUT_EMIT_PROMPT).
;   In:        Entered after the optional '? ' marker was emitted; the stack carries the variable-list (program) text pointer pushed at INPUT_EMIT_PROMPT entry.
;   Out:       INLIN leaves the typed line in BUF NUL-terminated and HL = L_0A0D (the fixed ',' just before BUF); the seed comma is (re)written; the program text pointer is restored and the reply seed ptr is staged on the stack; control falls into INPUT_PARSE_VALUES. A carry from INLIN (Ctrl-C/abort) diverts to STMT_END_2+1.
;   Clobbers:  AF, BC, DE, HL; BUF / the seed cell L_0A0D.
;   Algorithm: INLIN reads one edited line into BUF and returns HL = L_0A0D (BUF-1, the fixed leading-comma seed). POP the queued program text pointer; carry => aborted -> JP STMT_END_2+1. Store ',' at L_0A0D (priming the scanner so the first reply field reads as if a separator preceded it -- this is a LEADING seed, not a trailing terminator). Juggle HL/DE so HL -> program (variable-list) text and DE = the reply seed ptr, push the reply seed twice, DEC HL, and fall into INPUT_PARSE_VALUES.
; ----------------------------------------------------------------------
INPUT_PROMPT_5:
        ; read one edited console line into BUF; INLIN returns HL = L_0A0D (the fixed ',' seed just before BUF)
        CALL INLIN
        POP BC
        ; INLIN carry = input aborted (Ctrl-C) -> end the statement with the break flag set
        JP C,STMT_END_2+1
        PUSH BC
        ; (re)write the LEADING ',' seed at L_0A0D so the first reply field parses as if a separator preceded it (not a trailing terminator)
        LD (HL),$2C
        EX DE,HL
        POP HL
        PUSH HL
        PUSH DE
        PUSH DE
        DEC HL
; [RE] INPUT value-parse loop: for each variable, read a field from the typed line (honouring quotes and ',' separators), convert and assign via STMT_LET_2; on mismatch jumps to the '?Redo from start' re-prompt (STMT_LINE_1/2).
INPUT_PARSE_VALUES:
        LD A,$80
        LD (PTRGET_SUBSCRIPT_FLAG),A
        CALL CHRGET
        CALL PTRGET_1+1
        LD A,(HL)
        DEC HL
        CP $28
        JR NZ,INPUT_PROMPT_9
        INC HL
        LD B,$00
INPUT_PROMPT_7:
        INC B
INPUT_PROMPT_8:
        CALL CHRGET
        JP Z,RAISE_SYNTAX_ERROR
        CP $22
        JP Z,STMT_LINE_1
        CP $28
        JR Z,INPUT_PROMPT_7
        CP $29
        JR NZ,INPUT_PROMPT_8
        DJNZ INPUT_PROMPT_8
; ----------------------------------------------------------------------
; INPUT_PROMPT_9 -- require the variable-list separator after a resolved INPUT target, then scan the next reply field (scan-only validation pass).
;   In:        HL -> program text after the just-resolved variable (array subscript already skipped via INPUT_PROMPT_7/_8). Stack: parked program-text ptr and reply-buffer ptr.
;   Out:       Requires a ',' (or end-of-statement) in the PROGRAM text separating variables; switches to the reply buffer, requires a ',' separator before the field there (else '?Redo from start'), then scans/converts the field via STMT_READ_4+1 in scan-only mode and re-checks the validation sentinel; on success falls into INPUT_PROMPT_11.
;   Clobbers:  AF, BC, DE, HL; L_0CB7.
;   Algorithm: CHRGET the next PROGRAM char; end-of-statement (Z) or a ',' is required (else Syntax error). EX (SP),HL to switch to the reply buffer: if the reply char is not ',' there are too few values -> STMT_LINE_2 ('?Redo from start'). Set L_0CB7=1 (validation sentinel), CALL STMT_READ_4+1 to scan/convert the field with no store (the +1 entry runs the cover byte as XOR A, clearing L_0C69), then re-read L_0CB7: if it is no longer 1 the field failed to parse -> STMT_LINE_2. On success fall into INPUT_PROMPT_11.
; ----------------------------------------------------------------------
INPUT_PROMPT_9:
        CALL CHRGET
        JR Z,INPUT_PROMPT_10
        CP $2C
        ; variables in the INPUT list must be separated by ',' (or end the statement)
        JP NZ,RAISE_SYNTAX_ERROR
INPUT_PROMPT_10:
        EX (SP),HL
        LD A,(HL)
        CP $2C
        ; sentinel no longer 1 => the typed field did not parse -> '?Redo from start'
        ; reply has no ',' here -> fewer values than variables -> '?Redo from start'
        JP NZ,STMT_LINE_2
        ; arm the validation sentinel (L_0CB7=1); [RE] for a numeric field FIN's epilogue snapshots L_0CB6 into L_0CB7, so a malformed number leaves it != 1
        LD A,$01
        LD (L_0CB7),A
        ; scan+convert this reply field WITHOUT assigning (the +1 entry runs the cover byte as XOR A, clearing the store flag L_0C69)
        CALL STMT_READ_4+1
        LD A,(L_0CB7)
        DEC A
        JP NZ,STMT_LINE_2
        PUSH HL
; ----------------------------------------------------------------------
; INPUT_PROMPT_11 -- commit the parsed INPUT field, then either bind the next variable, finish, or warn on surplus input.
;   In:        Stack: parked program-text ptr and reply-buffer ptr. The field value is staged (FAC + VALTYP) from the scan pass.
;   Out:       If the value is a string its temporary descriptor is resolved (FRESTR); if the PROGRAM text holds another ',' (another variable in the list) loops to INPUT_PARSE_VALUES to bind it; otherwise, if the REPLY still has data, more values were typed than variables -> STMT_LINE_4 ('?Redo from start'); if both are exhausted, falls into INPUT_PROMPT_12 to finish.
;   Clobbers:  AF, BC, DE, HL.
;   Algorithm: FRMEVL_TEST_TYPE; if the staged value is a string (Z) CALL FRESTR to resolve its descriptor. Advance the reply pointer past the field, then EX (SP),HL to bring the PROGRAM (variable-list) pointer into HL and test (HL) for ',': a comma means another variable follows -> JR INPUT_PARSE_VALUES (which will demand its reply field). If the variable list ended, switch back to the REPLY pointer and CHRGET it: if the reply char is nonzero (leftover typed values) -> JP STMT_LINE_4 ('?Redo from start', too many values); else fall into INPUT_PROMPT_12 with HL = the reply seed ptr.
; ----------------------------------------------------------------------
INPUT_PROMPT_11:
        CALL FRMEVL_TEST_TYPE
        ; string field: resolve/free its temporary descriptor before reusing the buffer
        CALL Z,FRESTR
        POP HL
        DEC HL
        CALL CHRGET
        EX (SP),HL
        LD A,(HL)
        CP $2C
        ; the PROGRAM (variable list) has another ',' -> another variable follows; loop to read its reply field
        JR Z,INPUT_PARSE_VALUES
        POP HL
        DEC HL
        CALL CHRGET
        OR A
        POP HL
        ; reply still has data but the variable list ended -> more values typed than variables -> '?Redo from start'
        JP NZ,STMT_LINE_4
; ----------------------------------------------------------------------
; INPUT_PROMPT_12 -- shared restore/seed tail: write a ',' at (HL) and re-enter the variable walk at STMT_READ_1+1 in console-INPUT mode.
;   In:        HL -> the seed comma cell L_0A0D (INPUT# path, set by STMT_LINE_5) or, on the INPUT epilogue fall-through, the reply seed pointer left by INPUT_PROMPT_11.
;   Out:       ',' stored at (HL); control enters STMT_READ_1+1 with the source flag cleared (console/INPUT semantics).
;   Clobbers:  HL (plus whatever STMT_READ_1+1 onward touches).
;   Algorithm: LD (HL),',' primes a separator, then JR STMT_READ_1+1 -- entering one byte past the STMT_READ_1 label so the F6 cover byte runs as XOR A, clearing L_0B53 to mark the source as console INPUT (vs program DATA) before the shared variable-binding walk.
; ----------------------------------------------------------------------
INPUT_PROMPT_12:
        LD (HL),$2C
        ; +1 entry runs the cover byte as XOR A so L_0B53 is cleared -> the shared walk runs in console-INPUT mode, not READ mode
        JR STMT_READ_1+1
; ----------------------------------------------------------------------
; STMT_READ -- READ statement handler (token READ, $87): bind the next program DATA item(s) to the named variable(s).
;   In:        HL -> program text after the READ token; DATA_READ_PTR = DATPTR, the saved cursor into the program DATA stream (set by RESTORE / advanced by prior READs).
;   Out:       Each listed variable is assigned its next DATA value; DATPTR (DATA_READ_PTR) advanced past the consumed items; HL advanced past the READ statement. 'Out of DATA' raised if the stream is exhausted.
;   Clobbers:  AF, BC, DE, HL; L_0B53, DATA_READ_PTR, the assigned variables.
;   Algorithm: PUSH the READ statement's text pointer and load HL=DATPTR (DATA_READ_PTR, the DATA cursor). Fall into STMT_READ_1 at the label (cover byte = OR $AF) which forces L_0B53 nonzero -> 'source = program DATA'. The two text pointers (variable list vs DATA cursor) are then alternately swapped on the stack as the body consumes a variable name from the READ list and a value field from the DATA stream.
; ----------------------------------------------------------------------
STMT_READ:
        PUSH HL
        ; load DATPTR: the running cursor into the program DATA stream
        LD HL,(DATA_READ_PTR)
; ----------------------------------------------------------------------
; STMT_READ_1 -- dual-entry source-flag setter shared by READ and console INPUT.
;   In:        Entered at the label (READ) or at STMT_READ_1+1 (INPUT, from INPUT_PROMPT_12). Stack top = the alternate text pointer to swap in.
;   Out:       L_0B53 set: READ entry leaves it nonzero ('program DATA' source); INPUT entry (+1) leaves it 0 ('console' source). The DATA-cursor and variable-list pointers are exchanged (EX (SP),HL) and control jumps to STMT_READ_3 to resolve the first variable.
;   Clobbers:  AF, HL; L_0B53.
;   Algorithm: The F6 cover byte is 'OR $AF' at the label (A becomes nonzero) and 'XOR A' at +1 (A=0). LD (L_0B53),A records the source. EX (SP),HL brings the variable-list pointer into HL while parking the DATA/reply cursor on the stack, then JR STMT_READ_3 (skipping STMT_READ_2's inter-variable ',' check for the first item).
; ----------------------------------------------------------------------
STMT_READ_1:
        ; label entry: force A nonzero so L_0B53 marks 'source = program DATA'; the +1 entry runs this same F6 byte as XOR A (console INPUT)
        OR $AF
        LD (L_0B53),A
        ; swap to the variable-list pointer, parking the DATA/reply cursor on the stack
        EX (SP),HL
        JR STMT_READ_3
STMT_READ_2:
        CALL SYNCHR
        DEFB    ','                      ; inline char arg consumed by the preceding CALL
STMT_READ_3:
        CALL PTRGET_1+1
        EX (SP),HL
        PUSH DE
        LD A,(HL)
        CP $2C
        JR Z,STMT_READ_4
        LD A,(L_0B53)
        OR A
        JP NZ,STMT_READ_11
; ----------------------------------------------------------------------
; STMT_READ_4 -- bind one field to the resolved target variable: choose numeric vs string scan, optionally store, dispatching to file/console/DATA source.
;   In:        Label entry: store the value (cover byte sets L_0C69 nonzero). STMT_READ_4+1 entry (from INPUT_PROMPT_9): scan only, do not store (cover byte runs as XOR A, clearing L_0C69). DE = target variable address; HL -> the source field text; the stack carries the value type and a finisher. PTRFIL selects file vs console/DATA.
;   Out:       The field is scanned (and, on the label/store entry, converted and assigned via STMT_LET_2). For file input control diverts to INPUT_FILE_SCAN. String-field terminators depend on source: console INPUT ends on ',' or NUL; program DATA additionally ends on ':'; a leading '"' makes it a '"'-quoted field.
;   Clobbers:  AF, BC, DE, HL; L_0C69; the target variable (store path).
;   Algorithm: Cover byte sets L_0C69 = store-flag (OR $AF at label = store; XOR A at +1 = scan-only). If PTRFIL is nonzero -> JP INPUT_FILE_SCAN (file source). Else FRMEVL_TEST_TYPE on the target's VALTYP: a numeric target (NZ) -> STMT_READ_8 (FIN parses a number); a string target reads the field with SCAN_STR_BODY, setting the terminators in B (primary) and D (secondary): if the first char is '"' then B=D='"' (quoted field); otherwise B=',' and D is taken from L_0B53 -- for program DATA (L_0B53 nonzero) D is overwritten with ':' so a colon also ends a DATA item, while for console INPUT (L_0B53=0) D stays 0 (only ',' and NUL terminate). The scanned descriptor flows to the STMT_READ_7 finisher.
; ----------------------------------------------------------------------
STMT_READ_4:
        ; label entry: set the store flag (L_0C69 nonzero) so the field is assigned; the +1 entry runs this F6 byte as XOR A to scan WITHOUT storing (INPUT validation pre-pass)
        OR $AF
        LD (L_0C69),A
        EX DE,HL
        LD HL,(PTRFIL)
        LD A,H
        OR L
        EX DE,HL
        ; a file is selected (PTRFIL!=0): read the field from the file instead
        JP NZ,INPUT_FILE_SCAN
        CALL FRMEVL_TEST_TYPE
        PUSH AF
        ; numeric target: parse the field as a number via FIN
        JR NZ,STMT_READ_8
        CALL CHRGET
        LD D,A
        LD B,A
        CP $22
        JR Z,STMT_READ_6
        LD A,(L_0B53)
        OR A
        LD D,A
        JR Z,STMT_READ_5
        ; string field from program DATA (L_0B53!=0): a ':' is set as a second terminator so a colon also ends the DATA item (for console INPUT D was left 0)
        LD D,$3A
STMT_READ_5:
        LD B,$2C
        DEC HL
STMT_READ_6:
        CALL SCAN_STR_BODY
STMT_READ_7:
        POP AF
        ADD A,$03
        LD C,A
        LD A,(L_0C69)
        OR A
        RET Z
        LD A,C
        EX DE,HL
        LD HL,STMT_READ_9
        EX (SP),HL
        PUSH DE
        JP STMT_LET_2
; ----------------------------------------------------------------------
; STMT_READ_8 -- numeric-field path: convert the source text to a number in FAC via the float scanner.
;   In:        HL -> first char of the numeric field; stack top = the saved FRMEVL_TEST_TYPE result (A=VALTYP-3 plus its flags, pushed at STMT_READ_4). Its carry distinguishes the target type (carry set = NOT double; carry clear = double).
;   Out:       FAC = the parsed numeric value; control returns through STMT_READ_7 which (if L_0C69 set) assigns it. [RE] L_0CB6/L_0CB7 reflect FIN's parse-success snapshot (consumed by the INPUT '?Redo' validation).
;   Clobbers:  AF, BC, DE, HL; FAC, VALTYP, L_0CB6.
;   Algorithm: CHRGET the first field char, recover the saved type/flags (POP AF/PUSH AF), push STMT_READ_7 as the finisher, then dispatch into FIN by the saved carry: carry set (target not double) -> FIN_1+1 (pre-seeds FAC as an integer); carry clear (double target) -> FIN (fresh double-precision accumulation). FIN parses digits/sign/exponent into FAC and its epilogue snapshots L_0CB6 into L_0CB7.
; ----------------------------------------------------------------------
STMT_READ_8:
        CALL CHRGET
        POP AF
        PUSH AF
        ; after the number is parsed, return to the common finisher that (if storing) assigns it
        LD BC,STMT_READ_7
        PUSH BC
        JP C,FIN_1+1
        ; double target (carry clear): scan the field with FIN; FIN_1+1 (carry set) is the non-double entry that pre-seeds FAC as an integer
        JP FIN
STMT_READ_9:
        DEC HL
        CALL CHRGET
        JR Z,STMT_READ_10
        CP $2C
        JP NZ,STMT_LINE_3
STMT_READ_10:
        EX (SP),HL
        DEC HL
        CALL CHRGET
        JP NZ,STMT_READ_2
        POP DE
        LD A,(L_0B53)
        OR A
        EX DE,HL
        JP NZ,STMT_RESTORE_2
        PUSH DE
        POP HL
        JP PRINT_RESET_STATE
; ----------------------------------------------------------------------
; STMT_READ_11 -- DATA-stream advance: scan forward to the next DATA item, crossing statement and line boundaries, raising 'Out of DATA' at the end.
;   In:        HL -> current position in the program DATA stream (just past a consumed value).
;   Out:       HL positioned to re-enter STMT_READ_12 at the next statement; DATA_LINE_TXTPTR updated for the new DATA line (so a parse error can blame the right line). 'Out of DATA' (ERR_OUT_OF_DATA=4) raised when the program text runs out.
;   Clobbers:  AF, DE, HL; DATA_LINE_TXTPTR.
;   Algorithm: STMT_DATA scans to the next ':' or end-of-line; a nonzero return (it stopped on ':' -- another statement on the line) -> STMT_READ_12. Otherwise (end-of-line) step over the line's link word: INC HL, OR the two link bytes; if 0000 the program text ended -> raise 'Out of DATA'. Read the next line's header word into DATA_LINE_TXTPTR (recording the new DATA line for error reporting), then fall into STMT_READ_12 which CHRGETs and requires the DATA token ($84) before re-entering STMT_READ_4.
; ----------------------------------------------------------------------
STMT_READ_11:
        ; scan to the next ':' or end-of-line, skipping quoted strings; nonzero return = stopped at a ':' (another statement follows on this line)
        CALL STMT_DATA
        OR A
        JR NZ,STMT_READ_12
        INC HL
        LD A,(HL)
        INC HL
        OR (HL)
        LD E,ERR_OUT_OF_DATA
        ; the line link is 0000: program text ended before another DATA value -> 'Out of DATA'
        JP Z,RAISE_ERROR
        INC HL
        LD E,(HL)
        INC HL
        LD D,(HL)
        EX DE,HL
        ; record the DATA line now being read so a bad value reports against it
        LD (DATA_LINE_TXTPTR),HL
        EX DE,HL
; ----------------------------------------------------------------------
; STMT_READ_12 -- require the DATA token at the start of the next statement, then resume field reading.
;   In:        HL -> the start of a (possibly DATA) statement reached by STMT_READ_11's line/statement walk.
;   Out:       If the statement is DATA ($84), re-enters STMT_READ_4 to read its first value; otherwise loops back to STMT_READ_11 to keep scanning for a DATA statement.
;   Clobbers:  AF, HL.
;   Algorithm: CHRGET the next significant token. If it is not the DATA token ($84) this statement is not DATA -> JR STMT_READ_11 to advance further. If it is DATA, JP STMT_READ_4 to scan its first item into the current target variable.
; ----------------------------------------------------------------------
STMT_READ_12:
        CALL CHRGET
        CP $84
        ; not a DATA statement -> keep scanning for the next DATA line
        JR NZ,STMT_READ_11
        ; found a DATA statement: read its first value into the current variable
        JP STMT_READ_4
; [RE] Evaluate-expression wrapper: SYNCHR the current char (advance past a required token), RET if at end-of-statement (P flag), else JP into FRMEVL to evaluate the following expression into FAC.
EVAL_EXPR_AFTER_SYNCHR:
        CALL SYNCHR
        DEFB    TOK_EQ                   ; inline keyword-token arg consumed by the preceding CALL
        JP FRMEVL_NOPAREN

; ======================================================================
; EXPRESSION EVALUATOR (FRMEVL) + operator-precedence loop
; ======================================================================
; ----------------------------------------------------------------------
; FRMEVL -- evaluate a parenthesized expression: require '(', evaluate to FAC.
;   In:        HL -> text pointer, positioned just before a '(' token.
;   Out:       FAC ($0CB1) = expression value; VALTYP ($0B14) = its type; HL past the expression.
;   Clobbers:  A, BC, DE, HL, FAC; consumes one stack frame via the operator loop.
;   Algorithm: SYNCHR-assert the next non-blank token is '(' (the inline DEFB '(' is the char
;              argument the preceding CALL SYNCHR consumes; raises Syntax error if absent), then
;              fall through to FRMEVL_NOPAREN to evaluate the sub-expression. SYNCHR-context entry
;              used where a leading parenthesis is mandatory.
; ----------------------------------------------------------------------
FRMEVL:
        CALL SYNCHR
        DEFB    '('                      ; inline char arg consumed by the preceding CALL
; ----------------------------------------------------------------------
; FRMEVL_NOPAREN -- bare expression-evaluator entry (no leading '(' required).
;   In:        HL -> text pointer at the first operand token.
;   Out:       FAC = expression value; VALTYP set; HL advanced past the expression.
;   Clobbers:  A, BC, DE, HL, FAC.
;   Algorithm: DEC HL so the CHRGET inside FRMEVL_EVAL_OPERAND re-reads the current token (the
;              caller has typically already advanced past it), then fall into FRMEVL_LOWPREC. This
;              is the general 'evaluate the expression at (HL) into FAC' entry used by ~60 callers.
; ----------------------------------------------------------------------
FRMEVL_NOPAREN:
        DEC HL
; ----------------------------------------------------------------------
; FRMEVL_LOWPREC -- start an expression at the lowest operator precedence.
;   In:        HL -> one before the first operand token.
;   Out:       falls into the precedence loop with the pending-operator precedence D = 0.
;   Clobbers:  D (set to 0).
;   Algorithm: Seed the pending-operator precedence D = $00 (lower than every entry in
;              FRMEVL_PREC_TBL) so the first binary operator encountered always binds, then enter
;              FRMEVL_OPLOOP. Recursive entries instead arrive with D = the precedence of the
;              operator currently being applied (set in the OPLOOP_9/_10/ARITHOP apply arms).
; ----------------------------------------------------------------------
FRMEVL_LOWPREC:
        LD D,$00
; ----------------------------------------------------------------------
; FRMEVL_OPLOOP -- operator-precedence loop: parse one operand, then bind operators.
;   In:        D = pending-operator precedence (0 at top level, the operator's prec on recursion);
;              HL -> one before the next operand token.
;   Out:       FAC = value of the sub-expression bound at precedence > D; HL past it. Returns to
;              caller when the next operator's precedence <= D (or the token is not an operator).
;   Clobbers:  A, BC, DE, HL, FAC; L_0CB6.
;   Algorithm: PUSH DE to save the pending precedence D, verify stack headroom (CHECK_STACK_ROOM
;              with C=1 = two bytes of headroom), then evaluate one operand (factor) into the FAC
;              via FRMEVL_EVAL_OPERAND and clear the floating-point sign flag L_0CB6. Then loop:
;              read the next token; if below the relational band ('>'=$EF) return; if a relational
;              token dispatch to FRMEVL_RELOP to gather a comparison mask, else map
;              +/-/*//^/AND/OR/XOR/EQV/IMP/MOD/\ to its precedence in FRMEVL_PREC_TBL. While that
;              precedence > D, push the left operand and recurse to evaluate the right operand at
;              the operator's precedence, then apply the operator.
; ----------------------------------------------------------------------
FRMEVL_OPLOOP:
        PUSH DE
        ; request two bytes of Z-80 stack headroom (CHECK_STACK_ROOM reserves 2*C) before recursing
        LD C,$01
        CALL CHECK_STACK_ROOM
        ; evaluate the next operand/factor into the FAC
        CALL FRMEVL_EVAL_OPERAND
        ; [RE] clear the FP sign flag L_0CB6 (set later by the '^'/numeric-input paths) before scanning operators
        XOR A
        LD (L_0CB6),A
; ----------------------------------------------------------------------
; FRMEVL_OPLOOP_1 -- record the current text position as the operator scan point.
;   In:        HL -> the just-evaluated operand's trailing token (the candidate operator).
;   Out:       FOUT_DP_POSITION ($0B69) = HL; falls into FRMEVL_OPLOOP_2.
;   Clobbers:  (FOUT_DP_POSITION).
;   Algorithm: Stash HL so the loop can reload it after a recursive operand evaluation has moved
;              HL on. Re-entered here after the relational-mask collector / recursion returns.
; ----------------------------------------------------------------------
FRMEVL_OPLOOP_1:
        LD (FOUT_DP_POSITION),HL
; ----------------------------------------------------------------------
; FRMEVL_OPLOOP_2 -- classify the next token as terminator / relational / binary operator.
;   In:        FOUT_DP_POSITION = saved text pointer; top of stack = the pushed pending-precedence
;              frame (DE), popped into BC so B = pending precedence.
;   Out:       returns to caller if the token ends the (sub)expression; else dispatches to the
;              relational collector, the string-concat path, or the precedence test (OPLOOP_3).
;   Clobbers:  A, BC, DE, HL, (PRUSING_FORMAT_FLAGS).
;   Algorithm: Reload HL from FOUT_DP_POSITION; POP BC so B = pending precedence. Read the
;              operator token A and store its address in PRUSING_FORMAT_FLAGS. If A < '>' ($EF) it is not an
;              operator -> RET. If A < '+' ($F2) it is a relational ('>','=','<') -> FRMEVL_RELOP.
;              Otherwise E = A-'+' is the binary-operator index (0='+',1='-',2='*',3='/',4='^',
;              5=AND,6=OR,7=XOR,8=EQV,9=IMP,10=MOD,11='\'). Special-case '+' (E=0): if the current
;              FAC value is a string (VALTYP=$03) divert to STR_CONCAT instead of numeric add.
; ----------------------------------------------------------------------
FRMEVL_OPLOOP_2:
        LD HL,(FOUT_DP_POSITION)
        ; recover the pushed pending-precedence frame; B = pending-operator precedence for the test below
        POP BC
        LD A,(HL)
        ; remember the address of this operator token (reloaded by FRMEVL_OPLOOP_6 when applying)
        LD (PRUSING_FORMAT_FLAGS),HL
        ; token below the relational band ($EF) is not a binary operator -> end of (sub)expression
        CP TOK_GT
        RET C
        CP TOK_PLUS
        ; '>','=','<' (tokens $EF-$F1) -> gather the relational comparison mask
        JP C,FRMEVL_RELOP
        ; E = binary-operator index (0='+',1='-',2='*',3='/',4='^',5=AND,...,10=MOD,11='\')
        SUB TOK_PLUS
        LD E,A
        JR NZ,FRMEVL_OPLOOP_3
        LD A,(VALTYP)
        CP VT_STR
        LD A,E
        ; '+' (index 0) applied to a string operand is concatenation, not numeric add
        JP Z,STR_CONCAT
; ----------------------------------------------------------------------
; FRMEVL_OPLOOP_3 -- precedence test and recursion setup for a non-relational binary operator.
;   In:        E = operator index (token-'+', 0..11); A still = that index; B = pending precedence;
;              HL = (reloaded) operator address via PRUSING_FORMAT_FLAGS in the apply arms.
;   Out:       if the operator binds, recurses into FRMEVL_OPLOOP for the right operand; else RET.
;              D = new operator precedence; the chosen apply arm is queued on the stack.
;   Clobbers:  A, BC, DE, HL.
;   Algorithm: Reject indices >= 12 ('CP $0C / RET NC') -> not a valid binary operator. Index
;              FRMEVL_PREC_TBL ($79,$79,$7C,$7C,$7F,$50,$46,$3C,$32,$28,$7A,$7B) by E to fetch this
;              operator's precedence into D. If pending precedence B >= D ('CP D / RET NC') the
;              operator does not bind here (left-associative cutoff) -> RET to apply it at an outer
;              level. Otherwise push the pending-precedence frame, push the return address
;              FRMEVL_OPLOOP_2 (so control resumes scanning the next operator), and select the apply
;              arm by precedence value: $7F selects '^' -> power arm FRMEVL_OPLOOP_9; < $51 are the
;              logical ops AND($50)/OR($46)/XOR($3C)/EQV($32)/IMP($28) -> integer-coerce arm
;              FRMEVL_OPLOOP_10; $7A/$7B fold to $7A under AND $FE (MOD=$7A, '\'=$7B) -> the same
;              integer-coerce arm; the rest ($79 '+'/'-', $7C '*'/'/') fall to the float arm OPLOOP_4.
; ----------------------------------------------------------------------
FRMEVL_OPLOOP_3:
        ; operator index >= 12 is not a binary operator -> done
        CP $0C
        RET NC
        LD HL,FRMEVL_PREC_TBL
        LD D,$00
        ADD HL,DE
        LD A,B
        ; D = this operator's precedence from FRMEVL_PREC_TBL
        LD D,(HL)
        ; if pending precedence >= new precedence the operator binds outward -> RET to apply it later
        CP D
        RET NC
        PUSH BC
        ; after the right operand is evaluated, resume scanning operators here
        LD BC,FRMEVL_OPLOOP_2
        PUSH BC
        LD A,D
        ; precedence $7F selects '^' (exponentiation) -> power arm
        CP $7F
        JP Z,FRMEVL_OPLOOP_9
        CP $51
        ; precedence < $51 are the logical ops (AND/OR/XOR/EQV/IMP) -> integer-coerce arm
        JP C,FRMEVL_OPLOOP_10
        ; fold $7A (MOD) and $7B ('\') to $7A so both route to the integer-coerce arm
        AND $FE
        CP $7A
        JP Z,FRMEVL_OPLOOP_10
FRMEVL_OPLOOP_4:
        LD HL,FAC
        LD A,(VALTYP)
        SUB VT_STR
        JP Z,RAISE_TYPE_MISMATCH
        OR A
        LD C,(HL)
        INC HL
        LD B,(HL)
        PUSH BC
        JP M,FRMEVL_OPLOOP_5
        INC HL
        LD C,(HL)
        INC HL
        LD B,(HL)
        PUSH BC
        JP PO,FRMEVL_OPLOOP_5
        INC HL
        LD HL,FAC_DBL
        LD C,(HL)
        INC HL
        LD B,(HL)
        INC HL
        PUSH BC
        LD C,(HL)
        INC HL
        LD B,(HL)
        PUSH BC
FRMEVL_OPLOOP_5:
        ADD A,$03
        LD C,E
        LD B,A
        PUSH BC
        LD BC,FRMEVL_OPCOMBINE
FRMEVL_OPLOOP_6:
        PUSH BC
        LD HL,(PRUSING_FORMAT_FLAGS)
        JP FRMEVL_OPLOOP
; ----------------------------------------------------------------------
; FRMEVL_RELOP -- begin gathering a relational comparison from one or more of '>','=','<'.
;   In:        A = first relational token ('>','=','<'); HL -> that token; B = pending precedence.
;   Out:       D = accumulated 3-bit relation mask; falls into the per-token collector loop.
;   Clobbers:  D.
;   Algorithm: Initialize the relation mask D = 0, then fall into FRMEVL_OPLOOP_8 which folds each
;              consecutive relational token into the mask. BASIC allows the three relational tokens
;              combined ('<=','=<','><','<>', etc.); the mask encodes which of greater/equal/less
;              were requested so the comparison kernel can test the right combination.
; ----------------------------------------------------------------------
FRMEVL_RELOP:
        LD D,$00
; ----------------------------------------------------------------------
; FRMEVL_OPLOOP_8 -- fold consecutive relational tokens into a 3-bit comparison mask.
;   In:        A = current token; D = mask so far; HL -> current token.
;   Out:       on a non-relational token, falls to FRMEVL_ARITHOP carrying D = the relation mask;
;              HL advanced past the run.
;   Clobbers:  A, D, HL, (PRUSING_FORMAT_FLAGS); calls CHRGET.
;   Algorithm: Compute A = token-'>' giving 0='>',1='=',2='<'; carry (token < '>') or A >= 3 ends
;              the run (-> FRMEVL_ARITHOP). Convert to a single bit (CP $01 / RLA: '>'->1,'='->2,
;              '<'->4) and XOR it into mask D. XOR-ing a bit already set (e.g. '>>') clears it, so
;              the new mask < old D; CP D then sets carry -> RAISE_SYNTAX_ERROR. Save the pointer
;              in PRUSING_FORMAT_FLAGS, CHRGET past the token, and loop. Completed mask uses the MS BASIC code
;              1='>', 2='=', 4='<', combined for '>=','<=','<>','='.
; ----------------------------------------------------------------------
FRMEVL_OPLOOP_8:
        ; A = 0/1/2 for '>'/'='/'<'; out of range (or below '>') ends the relational run
        SUB TOK_GT
        JP C,FRMEVL_ARITHOP
        CP $03
        JP NC,FRMEVL_ARITHOP
        CP $01
        ; turn the token into its single relation bit (1='>',2='=',4='<')
        RLA
        ; merge the bit into the accumulated comparison mask
        XOR D
        CP D
        LD D,A
        ; the same relational symbol appeared twice (e.g. '>>') -> syntax error
        JP C,RAISE_SYNTAX_ERROR
        LD (PRUSING_FORMAT_FLAGS),HL
        ; consume this relational token and look at the next one
        CALL CHRGET
        JR FRMEVL_OPLOOP_8
; ----------------------------------------------------------------------
; FRMEVL_OPLOOP_9 -- power-operator ('^') apply arm: set up x^y.
;   In:        FAC = left operand x; the OPLOOP_2 return address and pending-precedence frame are
;              already pushed by FRMEVL_OPLOOP_3.
;   Out:       queues the power kernel POWER_OP_APPLY as the apply routine and recurses (via OPLOOP_6)
;              to evaluate the exponent y at precedence $7F.
;   Clobbers:  A, BC, DE, HL, FAC; pushes the coerced left operand.
;   Algorithm: Coerce the base to single precision (FN_CSNG) and push it (FAC_PUSH) so the kernel
;              can recover it after y is evaluated. Set BC = POWER_OP_APPLY (the single-precision power
;              kernel; it begins with FN_CSNG, sets the L_0CB6 sign flag, and [RE] computes x^y
;              via exp(y*log x)) and D = $7F as the recursion precedence, then join FRMEVL_OPLOOP_6
;              to push the apply routine and recurse for the exponent.
; ----------------------------------------------------------------------
FRMEVL_OPLOOP_9:
        ; force the base to single precision ('^' is computed in single precision)
        CALL FN_CSNG
        ; save the base so the power kernel can recover it after the exponent is evaluated
        CALL FAC_PUSH
        ; [RE] POWER_OP_APPLY is the x^y power kernel, applied once the exponent is in the FAC
        LD BC,POWER_OP_APPLY
        LD D,$7F
        JR FRMEVL_OPLOOP_6
; ----------------------------------------------------------------------
; FRMEVL_OPLOOP_10 -- integer-operator apply arm ('\','MOD', and the logical ops).
;   In:        FAC = left operand; the OPLOOP_2 return / pending-precedence frame already pushed.
;   Out:       queues FRMEVL_INT_OP_HANDLER as the apply routine and recurses (via OPLOOP_6) for
;              the right operand.
;   Clobbers:  A, BC, DE, HL, FAC; pushes the coerced left operand (HL).
;   Algorithm: Coerce the left operand to a 16-bit integer (FN_CINT, with DE saved/restored across
;              the call) and push it (PUSH HL) so the handler can recover it. Set BC =
;              FRMEVL_INT_OP_HANDLER (which re-coerces the right operand to integer, pops both, and
;              dispatches by precedence code: $7A=MOD, $7B='\', else AND/OR/XOR/etc. via the
;              integer operator band), then join FRMEVL_OPLOOP_6 to recurse for the right operand.
;              '\', MOD and the bitwise/logical operators all require integer operands, hence the
;              coercion here.
; ----------------------------------------------------------------------
FRMEVL_OPLOOP_10:
        PUSH DE
        ; force the left operand to a 16-bit integer (integer/logical operators require integers)
        CALL FN_CINT
        POP DE
        PUSH HL
        ; queue the integer apply handler that dispatches MOD/'\'/AND/OR/XOR by precedence code
        LD BC,FRMEVL_INT_OP_HANDLER
        JR FRMEVL_OPLOOP_6
; ----------------------------------------------------------------------
; FRMEVL_ARITHOP -- relational binary-operator apply guard and frame setup.
;   In:        D = relation mask (from FRMEVL_RELOP/_OPLOOP_8); B = pending precedence;
;              FAC = left operand; HL -> the token after the relational run.
;   Out:       if the relational operator binds, pushes the operand frame and recurses for the
;              right operand at precedence $64 with the relational-result handler queued; else RET.
;   Clobbers:  A, BC, DE, HL; pushes operand/return frames.
;   Algorithm: Relational operators have pseudo-precedence $64 (100); if pending precedence B >=
;              $64 the relational does not bind here -> RET to apply it outward. Otherwise push B
;              and the relation mask D, set DE = $6404 (D=$64 = recursion precedence for the right
;              operand; E=$04 = the operator code that, doubled, selects the compare slot in each
;              type's operator band: DCOMP_REL/FCOMP/INT16_COMP). Queue FRMEVL_RELOP_RESULT ([RE]
;              the relational-result finalizer: it combines the compare result with the relation
;              mask to yield -1/0 into the FAC) as the post-recursion return, then test the left
;              operand's type via FRMEVL_TEST_TYPE. If numeric (NZ), take the compare path through
;              FRMEVL_OPLOOP_4; if string (Z), push the string descriptor (LD HL,(FAC)) and queue
;              the string-compare handler ([RE] NEXT_LOOP_BODY_7, a mislabel) before joining
;              FRMEVL_OPLOOP_6 to recurse for the right side.
; ----------------------------------------------------------------------
FRMEVL_ARITHOP:
        LD A,B
        ; relational pseudo-precedence is $64; if a higher op is pending the comparison binds outward
        CP $64
        RET NC
        PUSH BC
        PUSH DE
        ; D=$64 = recursion precedence for the right operand; E=$04 = compare-slot index within the operator band
        LD DE,$6404
        LD HL,FRMEVL_RELOP_RESULT
        PUSH HL
        ; classify the left operand: numeric (NZ) -> compare path, string (Z) -> string compare
        CALL FRMEVL_TEST_TYPE
        ; numeric left operand: take the numeric comparison path
        JP NZ,FRMEVL_OPLOOP_4
        ; string left operand: load/push its descriptor for the string-comparison handler
        LD HL,(FAC)
        PUSH HL
        LD BC,NEXT_LOOP_BODY_7
        JR FRMEVL_OPLOOP_6
; ----------------------------------------------------------------------
; FRMEVL_OPCOMBINE -- combine a binary operator with its two evaluated operands
;   In:        Right operand in the FAC, its type in VALTYP ($0B14: 2=int,4=single,8=double,3=string).
;              Stack (top first): a frame BC where C = operator routine index and B = the LEFT operand's VALTYP,
;              pushed earlier by FRMEVL_OPLOOP_4/5; below it the LEFT operand's mantissa bytes (2/4/8 by its type).
;              [RE] C = (operator token - TOK_PLUS): 0=add,1=sub,2=mul,3=div; the compare slot (band entry 5) is
;              supplied via the relational path, and power '^' is handled earlier and never reaches here.
;   Out:       Tail-jumps (JP (HL) or PUSH/RET) to the selected OPERATOR_ROUTINE_TBL handler. The handler leaves
;              the result in the FAC with VALTYP set; control does not return here.
;   Clobbers:  A,B,C,D,E,H,L,F, the FAC and its extension cells, CRUNCH_LITERAL_MODE, the operand stack frame.
;   Algorithm: Pop the frame: save C (operator index) into CRUNCH_LITERAL_MODE (reused as the operator scratch),
;              leaving B = left operand type. Compare the right type (VALTYP) with the left type B. If equal,
;              branch to the matching dispatch band (int/single/double). If they differ, fall into FRMEVL_OPC_
;              PROMOTE to widen the narrower operand (int<single<double; string is a TYPE MISMATCH). Once both
;              share a type, index that band of OPERATOR_ROUTINE_TBL by 2*operator-index and dispatch.
; ----------------------------------------------------------------------
FRMEVL_OPCOMBINE:
        POP BC
        LD A,C
        ; Stash the operator routine index (C) in the scratch byte; the band-dispatch tail reads it back to pick the add/sub/mul/div/compare handler within the chosen type band.
        LD (CRUNCH_LITERAL_MODE),A
        LD A,(VALTYP)
        ; Compare the right operand's type (VALTYP) against the left operand's type B.
        CP B
        ; Types differ: go promote the narrower operand to the wider common type.
        JR NZ,FRMEVL_OPC_PROMOTE
        CP VT_INT
        ; Both integer: dispatch through the integer operator band.
        JR Z,FRMEVL_OPC_DISPATCH_INT
        CP VT_SNG
        ; Both single: pop the single-precision left operand and dispatch the single band.
        JP Z,FRMEVL_OPC_DISPATCH_SNG
        ; Both double ($08): stage the double operands and dispatch the double band.
        JR NC,FRMEVL_OPC_DBL_SETUP
; ----------------------------------------------------------------------
; FRMEVL_OPC_PROMOTE -- coerce two differently-typed operands to a common numeric type
;   In:        A = right operand type (VALTYP), B = left operand type; operands as for FRMEVL_OPCOMBINE.
;   Out:       Branches to the path that widens the narrower operand to the wider of the two types, then into
;              that type's dispatch band.
;   Clobbers:  A,D,F (D = right operand type held for the comparisons).
;   Algorithm: Decide the common type by descending width. If the LEFT is double ($08) widen the right/FAC
;              operand to double (FRMEVL_OPC_WIDEN_RIGHT_DBL); if the RIGHT is double widen the left (FRMEVL_OPC_
;              WIDEN_LEFT_DBL). Else if the LEFT is single ($04) widen the right/FAC operand to single (FRMEVL_
;              OPC_WIDEN_RIGHT_SNG). A string right operand ($03) is rejected as TYPE MISMATCH. Otherwise (right
;              single, left integer) widen the left integer to single (FRMEVL_OPC_WIDEN_LEFT_SNG).
; ----------------------------------------------------------------------
FRMEVL_OPC_PROMOTE:
        ; Keep the right operand's type in D; A is reused to test the left type B.
        LD D,A
        LD A,B
        CP $08
        ; Left operand is double: widen the right/FAC operand to double.
        JR Z,FRMEVL_OPC_WIDEN_RIGHT_DBL
        LD A,D
        CP $08
        ; Right operand is double: widen the left operand to double.
        JR Z,FRMEVL_OPC_WIDEN_LEFT_DBL
        LD A,B
        CP $04
        ; Left operand is single: widen the right/FAC operand to single.
        JR Z,FRMEVL_OPC_WIDEN_RIGHT_SNG
        LD A,D
        CP $03
        ; Right operand is a string: arithmetic on a string is a Type mismatch error.
        JP Z,RAISE_TYPE_MISMATCH
        ; Right is single and left is integer: widen the left integer operand to single.
        JR NC,FRMEVL_OPC_WIDEN_LEFT_SNG
; ----------------------------------------------------------------------
; FRMEVL_OPC_DISPATCH_INT -- dispatch a two-integer operation through the integer band
;   In:        Both operands integer. C holds the operator routine index from the popped frame; B is zeroed here.
;              The left integer operand is on the stack; the right integer operand is in the FAC.
;   Out:       PUSH/RET tail-jumps to the integer operator handler (IADD/INT_SIGNEXT_SUB/IMUL/IDIV/INT16_COMP)
;              with DE = left operand (popped) and HL = right operand (from FAC).
;   Clobbers:  A,B,C,D,E,H,L,F.
;   Algorithm: Form HL = OPERATOR_ROUTINE_TBL+OP_BAND_INT ($0517) + 2*index by zeroing B and adding BC twice,
;              load the 16-bit handler address from that DEFW slot into BC, pop the left operand into DE and load
;              the right operand from the FAC into HL, then PUSH handler / RET. (The integer band has its OWN
;              PUSH/RET dispatcher here, distinct from the single/double band dispatcher.)
; ----------------------------------------------------------------------
FRMEVL_OPC_DISPATCH_INT:
        ; Index the integer operator band ($0517: IADD,INT_SIGNEXT_SUB,IMUL,IDIV,INT16_COMP) by 2*operator-index (ADD HL,BC twice with B zeroed).
        LD HL,OPERATOR_ROUTINE_TBL+OP_BAND_INT
        LD B,$00
        ADD HL,BC
        ADD HL,BC
        LD C,(HL)
        INC HL
        LD B,(HL)
        ; Recover the left integer operand into DE; the right integer operand is read from the FAC into HL.
        POP DE
        LD HL,(FAC)
        ; PUSH handler address / RET = computed jump into the integer operator routine.
        PUSH BC
        RET
; ----------------------------------------------------------------------
; FRMEVL_OPC_WIDEN_RIGHT_DBL -- widen the right operand to double, then take the double path
;   In:        Right operand in the FAC (narrower numeric type); the left operand is already double on the stack.
;   Out:       Falls into FRMEVL_OPC_DBL_SETUP with the FAC holding a double-precision right operand.
;   Clobbers:  A,B,C,D,E,H,L,F, the FAC.
;   Algorithm: CALL FN_CDBL converts the FAC in place to double precision, then falls through into the
;              double-operand setup.
; ----------------------------------------------------------------------
FRMEVL_OPC_WIDEN_RIGHT_DBL:
        ; Promote the right operand (in the FAC) up to double precision.
        CALL FN_CDBL
; ----------------------------------------------------------------------
; FRMEVL_OPC_DBL_SETUP -- stage the right double operand and the left operand's low words
;   In:        Right operand is double in the FAC; the left double operand's mantissa bytes are on the stack
;              (low extension words on top). Operator index already saved in CRUNCH_LITERAL_MODE.
;   Out:       Falls into FRMEVL_OPC_DBL_LOADFAC with the right operand moved to the secondary FP temp ($0CBA)
;              and the FAC's two low double extension words ($0CAF/$0CB0 then $0CAD/$0CAE) loaded from the LEFT
;              operand's low words.
;   Clobbers:  A,B,C,D,E,H,L,F, the FAC, the secondary FP temp ($0CBA), $0CAD-$0CB0.
;   Algorithm: FP_ARG_TO_TEMP2 copies the right (FAC) double into the secondary operand temp. Then pop the LEFT
;              operand's two low extension words off the stack into the FAC extension cells $0CAF and $0CAD (the
;              low 4 bytes of the 8-byte double FAC), and fall through to load the left operand's high
;              mantissa/sign and dispatch the double band.
; ----------------------------------------------------------------------
FRMEVL_OPC_DBL_SETUP:
        ; Move the right double operand from the FAC into the secondary FP operand temp ($0CBA).
        CALL FP_ARG_TO_TEMP2
        POP HL
        ; Pop the left double operand's two low extension words into the FAC's low double bytes ($0CAF/$0CB0 then $0CAD/$0CAE).
        LD (L_0CAF),HL
        POP HL
        LD (FAC_DBL),HL
; ----------------------------------------------------------------------
; FRMEVL_OPC_DBL_LOADFAC -- load the left double operand's high mantissa into the FAC
;   In:        Stack holds the left double operand's remaining high mantissa bytes; the FAC low extension words
;              were already loaded by FRMEVL_OPC_DBL_SETUP (or this is entered from the left-was-single path).
;   Out:       Falls into FRMEVL_OPC_DISPATCH_DBL with the full left operand assembled in the FAC.
;   Clobbers:  B,C,D,E,H,L,F, the FAC.
;   Algorithm: POP BC / POP DE recover the left operand's high mantissa/sign bytes and FP_STORE_FAC writes DE
;              into the FAC mantissa-low ($0CB1) and BC into FACHI ($0CB3), completing the LEFT double operand
;              in the FAC.
; ----------------------------------------------------------------------
FRMEVL_OPC_DBL_LOADFAC:
        ; Recover the left operand's high mantissa/sign bytes (BC,DE) from the stack.
        POP BC
        POP DE
        ; Write DE->FAC mantissa-low and BC->FACHI, completing the left operand in the FAC.
        CALL FP_STORE_FAC
; ----------------------------------------------------------------------
; FRMEVL_OPC_DISPATCH_DBL -- dispatch a two-double operation through the double band
;   In:        Left double operand in the FAC, right double operand in the secondary FP temp ($0CBA); the
;              operator index lives in CRUNCH_LITERAL_MODE.
;   Out:       JP (HL) to the double operator handler (DADD/DP_NEGATE_SIGN/DMUL/DDIV/DCOMP_REL).
;   Clobbers:  A,H,L,F (then the handler).
;   Algorithm: CALL FN_CDBL guarantees the FAC is double, then load HL = OPERATOR_ROUTINE_TBL+OP_BAND_DBL ($0503)
;              and fall into the shared band dispatcher FRMEVL_OPC_BAND_DISPATCH.
; ----------------------------------------------------------------------
FRMEVL_OPC_DISPATCH_DBL:
        ; Ensure the FAC (left operand) is double precision before the double handler runs.
        CALL FN_CDBL
        ; Select the double operator band ($0503: DADD,DP_NEGATE_SIGN,DMUL,DDIV,DCOMP_REL).
        LD HL,OPERATOR_ROUTINE_TBL+OP_BAND_DBL
; ----------------------------------------------------------------------
; FRMEVL_OPC_BAND_DISPATCH -- index a band of OPERATOR_ROUTINE_TBL and jump to the handler
;   In:        HL = the chosen band base (OP_BAND_SNG/DBL entry of OPERATOR_ROUTINE_TBL); CRUNCH_LITERAL_MODE =
;              operator routine index. Operands already staged in the FAC and the secondary temp.
;   Out:       JP (HL) into the selected DEFW handler; never returns here.
;   Clobbers:  A,H,L,F.
;   Algorithm: Reload the operator index, RLCA to get 2*index, add it to HL (8-bit add into L with carry
;              propagated into H via the ADD A,L / LD L,A / ADC A,H / SUB L / LD H,A idiom), then load the
;              16-bit handler address from that DEFW slot into HL and JP (HL). Shared by the single and double
;              bands (the integer band uses its own PUSH/RET dispatcher in FRMEVL_OPC_DISPATCH_INT).
; ----------------------------------------------------------------------
FRMEVL_OPC_BAND_DISPATCH:
        ; Reload the operator routine index (saved by FRMEVL_OPCOMBINE).
        LD A,(CRUNCH_LITERAL_MODE)
        ; Double it to a byte offset into the band (each entry is a 2-byte DEFW).
        RLCA
        ; Add the offset to the band base HL; the ADC A,H / SUB L sequence propagates the carry into H.
        ADD A,L
        LD L,A
        ADC A,H
        SUB L
        LD H,A
        ; Load the 16-bit handler address from the DEFW slot, then JP (HL).
        LD A,(HL)
        INC HL
        LD H,(HL)
        LD L,A
        JP (HL)
; ----------------------------------------------------------------------
; FRMEVL_OPC_WIDEN_LEFT_DBL -- widen the left operand to double when only the right is double
;   In:        Right operand is double in the FAC; left operand (narrower: int or single) is on the stack with
;              its type byte. B = left VALTYP, C = operator index on entry (but see below).
;   Out:       Joins the double dispatch path: if the left was single, into FRMEVL_OPC_DBL_LOADFAC (reusing the
;              staged right operand); otherwise loads the left integer into the FAC and falls into FRMEVL_OPC_
;              DISPATCH_DBL (whose FN_CDBL widens it to double).
;   Clobbers:  A,B,C,D,E,H,L,F, the FAC, VALTYP, the secondary FP temp.
;   Algorithm: Stash the right double operand into the secondary temp (FP_ARG_TO_TEMP2). PUSH BC / POP AF
;              recovers the LEFT operand's type byte (old B) into A and sets VALTYP from it (the operator index
;              in old C is dropped into F here -- it survives only because OPCOMBINE already saved it in CRUNCH_
;              LITERAL_MODE). If the left was already single ($04) the staged operand suffices, so branch to the
;              high-mantissa load; otherwise the left is a 16-bit integer -- load it into the FAC and fall through,
;              where FN_CDBL widens it to double.
; ----------------------------------------------------------------------
FRMEVL_OPC_WIDEN_LEFT_DBL:
        PUSH BC
        ; Stash the right double operand into the secondary FP temp before rebuilding the left operand in the FAC.
        CALL FP_ARG_TO_TEMP2
        ; Recover the left operand's type byte (pushed as B) into A and set it as the current VALTYP; the operator index (old C) is discarded here, having already been saved in CRUNCH_LITERAL_MODE.
        POP AF
        LD (VALTYP),A
        CP VT_SNG
        ; Left was already single: its mantissa words are still staged, so join the high-mantissa load.
        JR Z,FRMEVL_OPC_DBL_LOADFAC
        POP HL
        ; Left was a 16-bit integer: load it into the FAC and fall into the double dispatch (FN_CDBL widens it).
        LD (FAC),HL
        JR FRMEVL_OPC_DISPATCH_DBL
; ----------------------------------------------------------------------
; FRMEVL_OPC_WIDEN_RIGHT_SNG -- widen the right operand to single, then dispatch single
;   In:        Right operand in the FAC (narrower than single: integer); the left single operand is on the stack.
;              Reached from the promotion tree when the LEFT operand is single ($04).
;   Out:       Falls into FRMEVL_OPC_DISPATCH_SNG (pops the left single operand and dispatches the single band).
;   Clobbers:  A,B,C,D,E,H,L,F, the FAC.
;   Algorithm: CALL FN_CSNG promotes the FAC (right operand) up to single precision, then falls through to the
;              single-precision dispatch tail.
;   Note:      The prior label/comment ('coerce to INT', CALL FN_CINT) was WRONG -- the bytes at $3BC9 are
;              CD EE 4F = CALL FN_CSNG ($4FEE), the single-precision conversion. This is the single-widen path.
; ----------------------------------------------------------------------
FRMEVL_OPC_WIDEN_RIGHT_SNG:
        ; Promote the right operand (in the FAC) up to single precision to match the single left operand.
        CALL FN_CSNG
; ----------------------------------------------------------------------
; FRMEVL_OPC_DISPATCH_SNG -- recover the left single operand and dispatch the single band
;   In:        Left single operand pushed on the stack as two register pairs; right single operand in the FAC.
;              Entered directly from FRMEVL_OPCOMBINE when BOTH operands are single, or by fall-through after the
;              right operand was widened to single.
;   Out:       Falls into FRMEVL_OPC_SNG_BAND, which selects the single band and dispatches.
;   Clobbers:  B,C,D,E.
;   Algorithm: POP BC / POP DE recover the left single operand into BC,DE (the FP register operand the single
;              handlers expect alongside the FAC), then fall through to load the single band base.
; ----------------------------------------------------------------------
FRMEVL_OPC_DISPATCH_SNG:
        ; Recover the left single operand into BC/DE (the register operand the single-precision handlers take alongside the FAC).
        POP BC
        POP DE
; ----------------------------------------------------------------------
; FRMEVL_OPC_SNG_BAND -- select the single-precision operator band and dispatch
;   In:        Both operands staged for a single-precision op (left in BC/DE, right in the FAC); operator index
;              in CRUNCH_LITERAL_MODE.
;   Out:       Branches into FRMEVL_OPC_BAND_DISPATCH, which JP (HL)s to FADD_ALIGN/FSUB/FMUL/FDIV/FCOMP.
;   Clobbers:  H,L.
;   Algorithm: Load HL = OPERATOR_ROUTINE_TBL+OP_BAND_SNG ($050D, the single-precision band) and jump to the
;              shared band dispatcher.
;   Note:      Prior comment ('relational/string handler vector $050D') was WRONG. $050D = OP_BAND_SNG, the
;              single-precision arithmetic band (FADD_ALIGN,FSUB,FMUL,FDIV,FCOMP); the relational op is just the
;              compare slot (FCOMP) within it, not a separate string vector.
; ----------------------------------------------------------------------
FRMEVL_OPC_SNG_BAND:
        ; Select the single-precision operator band ($050D: FADD_ALIGN,FSUB,FMUL,FDIV,FCOMP).
        LD HL,OPERATOR_ROUTINE_TBL+OP_BAND_SNG
        JR FRMEVL_OPC_BAND_DISPATCH
; ----------------------------------------------------------------------
; FRMEVL_OPC_WIDEN_LEFT_SNG -- widen the integer left operand to single, dispatch single
;   In:        Right operand is single in the FAC; left operand is a 16-bit integer pushed on the stack. Reached
;              when the right is single and the left is integer.
;   Out:       Branches to FRMEVL_OPC_SNG_BAND for single-precision dispatch, with the widened LEFT operand in
;              registers (E,D,C,B from FP_LOAD_FAC) and the original RIGHT operand restored in the FAC.
;   Clobbers:  A,B,C,D,E,H,L,F, the FAC, FACHI.
;   Algorithm: POP the integer left operand into HL, FAC_PUSH saves the current single FAC (the RIGHT operand)
;              on the stack, INT_TO_SINGLE_HL converts the integer to single in the FAC, FP_LOAD_FAC loads that
;              widened LEFT single into the E,D,C,B registers, then POP/POP restore the saved RIGHT operand back
;              into FACHI ($0CB3) and FAC ($0CB1), and JR to the single-band dispatch.
;   Note:      Mislabeled '..._INT': this is an integer->SINGLE widen of the LEFT operand, not an integer coerce.
; ----------------------------------------------------------------------
FRMEVL_OPC_WIDEN_LEFT_SNG:
        ; Recover the integer left operand from the stack.
        POP HL
        ; Save the single right operand (currently in the FAC) on the stack while the left integer is converted.
        CALL FAC_PUSH
        ; Convert the 16-bit integer left operand in HL to single precision in the FAC.
        CALL INT_TO_SINGLE_HL
        CALL FP_LOAD_FAC
        POP HL
        ; Restore the saved single right operand back into the FAC (FACHI then FAC); the widened left operand stays in the E,D,C,B registers loaded by FP_LOAD_FAC.
        LD (FACHI),HL
        POP HL
        LD (FAC),HL
        JR FRMEVL_OPC_SNG_BAND
; ----------------------------------------------------------------------
; IDIV -- integer-band slot for '/' division: promote both integer operands to single and divide as floats
;   In:        DE = left integer operand, HL = right integer operand, as set by the integer dispatcher FRMEVL_
;              OPC_DISPATCH_INT (POP DE = left, LD HL,(FAC) = right). Reached only as the integer band's divide
;              slot ($051D).
;   Out:       Tail-jumps to FDIV_POP_ARGS (the FDIV pop-and-divide entry); the result is a single-precision
;              float in the FAC. VALTYP is set to single by the conversion path.
;   Clobbers:  A,B,C,D,E,H,L,F, the FAC.
;   Algorithm: '/' in MS BASIC always yields a float even on two integers. PUSH HL saves the right operand;
;              EX DE,HL moves the LEFT operand into HL and INT_TO_SINGLE_HL converts the LEFT operand to single
;              in the FAC; FAC_PUSH then pushes that LEFT single (the dividend). POP HL restores the RIGHT
;              operand and a second INT_TO_SINGLE_HL converts the RIGHT operand to single in the FAC (the
;              divisor). JP FDIV_POP_ARGS pops the pushed dividend into BC/DE and FDIV computes popped/FAC =
;              left/right -> single-precision quotient.
;   Note:      The two INT_TO_SINGLE_HL calls convert the LEFT operand first (then the RIGHT), opposite to a
;              prior gloss; after EX DE,HL the first call operates on the LEFT operand.
; ----------------------------------------------------------------------
IDIV:
        PUSH HL
        EX DE,HL
        ; Convert the LEFT integer operand (moved into HL by EX DE,HL) to single precision in the FAC -- this is the dividend.
        CALL INT_TO_SINGLE_HL
        POP HL
        ; Push the LEFT single (dividend) aside; HL is then restored to the RIGHT operand for conversion to the divisor.
        CALL FAC_PUSH
        CALL INT_TO_SINGLE_HL
        ; FAC now holds the RIGHT single (divisor); the FDIV pop entry recovers the pushed dividend and computes left/right -> single quotient.
        JP FDIV_POP_ARGS
; ----------------------------------------------------------------------
; EVAL fetch one operand. [FIX] $FF=extended-function-token escape -> FUNC_DISPATCH_TBL, NOT radix; ampersand $26=radix path.
; ----------------------------------------------------------------------
FRMEVL_EVAL_OPERAND:
        CALL CHRGET
        JP Z,RAISE_MISSING_OPERAND
        JP C,FIN_1+1
        CALL IS_LETTER_A
        JP NC,FRMEVL_PAREN_3
        CP $20
        JP C,CHRGOT_CONST_VALUE
        INC A
        JP Z,FRMEVL_FUNC_TOKEN
        DEC A
        CP TOK_PLUS
        JR Z,FRMEVL_EVAL_OPERAND
        CP TOK_MINUS
        JP Z,FRMEVL_PAREN_1
        CP $22
        JP Z,SCAN_STR_QUOTE
        CP TOK_NOT
        JP Z,FRMEVL_NOT
        CP $26
        JP Z,SCAN_AMP_RADIX_CONST
        CP $E6
        JR NZ,FRMEVL_EVAL_OPERAND_1
        CALL CHRGET
        LD A,(ERRFLG)
        PUSH HL
        CALL FP_LOAD_INT_TO_FAC
        POP HL
        RET
; ----------------------------------------------------------------------
; ERL floats ERR_SAVTXT($0B60). [FIX/UNKNOWN] $0B60 is a saved TEXT POINTER, NOT the line number (that is ERRLIN $0B62).
; ----------------------------------------------------------------------
FRMEVL_EVAL_OPERAND_1:
        CP $E5
        JR NZ,FRMEVL_EVAL_OPERAND_2
        CALL CHRGET
        PUSH HL
        LD HL,(ERR_SAVTXT)
        CALL INT_TO_SNG
        POP HL
        RET
; ----------------------------------------------------------------------
; VARPTR head: SYNCHR '('; '#'($23)->#n via FCB_BUFFER_PTR then _4; else var->_3 (PTRGET).
; ----------------------------------------------------------------------
FRMEVL_EVAL_OPERAND_2:
        CP $EB
        JR NZ,FRMEVL_EVAL_OPERAND_5
        CALL CHRGET
        CALL SYNCHR
        DEFB    '('                      ; inline char arg consumed by the preceding CALL
        CP $23
        JR NZ,FRMEVL_EVAL_OPERAND_3
        CALL GETBYT_CHRGET
        PUSH HL
        CALL FCB_BUFFER_PTR
        POP HL
        JP FRMEVL_EVAL_OPERAND_4
; ----------------------------------------------------------------------
; VARPTR(var): PTRGET (PTRGET_1+1, XOR A=scalar-ref/non-DIM, not no-create) returns the data addr in DE.
; ----------------------------------------------------------------------
FRMEVL_EVAL_OPERAND_3:
        CALL PTRGET_1+1
; ----------------------------------------------------------------------
; VARPTR tail: SYNCHR ')'; 0 addr->ERROR_FC; else FP_STORE_FAC_INT stores the address as an integer FAC.
; ----------------------------------------------------------------------
FRMEVL_EVAL_OPERAND_4:
        CALL SYNCHR
        DEFB    ')'                      ; inline char arg consumed by the preceding CALL
        PUSH HL
        EX DE,HL
        LD A,H
        OR L
        JP Z,ERROR_FC
        CALL FP_STORE_FAC_INT
        POP HL
        RET
; ----------------------------------------------------------------------
; fn tokens: USR INSTR COLOR$CD(plot-color not SCRN) HCOLOR SCRN HSCRN INKEY$ STRING$ INPUT$ FN; none->FRMEVL_PAREN.
; ----------------------------------------------------------------------
FRMEVL_EVAL_OPERAND_5:
        CP $E1
        JP Z,FP_LOAD_INT_TO_FAC_2
        CP $E9
        JP Z,FN_INSTR
        CP $CD
        JP Z,FN_COLOR_READ
        CP $D3
    IFDEF GBASIC
        JP Z,GFX_FN_HCOLOR               ; (GBASIC: HCOLOR() fn handler)
    ELSE
        JP Z,RAISE_GRAPHICS_STATEMENT_NOT_IMPLEMENTED  ; $3C85->$280F  HCOLOR() fn -> not-impl (MBASIC)
    ENDIF
        CP $EC
        JP Z,FN_SCRN
        CP $ED
    IFDEF GBASIC
        JP Z,GFX_FN_HSCRN                ; (GBASIC: HSCRN() fn handler)
    ELSE
        JP Z,RAISE_GRAPHICS_STATEMENT_NOT_IMPLEMENTED  ; $3C8F->$280F  HSCRN() fn -> not-impl (MBASIC)
    ENDIF
        CP $EE
        JP Z,INKEY_SCAN_1
        CP $E7
        JP Z,FN_STRING_STR
        CP TOK_INPUT
        JP Z,FN_INPUT_DOLLAR
        CP TOK_FN
        JP Z,CALL_FN
; ----------------------------------------------------------------------
; paren subexpr: FRMEVL + SYNCHR ')'. Pre-existing 'ADD HL,HL FAC->integer' source comment is WRONG.
; ----------------------------------------------------------------------
FRMEVL_PAREN:
        CALL FRMEVL
        CALL SYNCHR
        DEFB    ')'                      ; inline char arg consumed by the preceding CALL
        RET
; ----------------------------------------------------------------------
; unary minus: D=$7D, FRMEVL_OPLOOP, reload FOUT_DP_POSITION($0B69), FP_NEGATE_CHECKED; exit via _2.
; ----------------------------------------------------------------------
FRMEVL_PAREN_1:
        LD D,$7D
        CALL FRMEVL_OPLOOP
        LD HL,(FOUT_DP_POSITION)
        PUSH HL
        CALL FP_NEGATE_CHECKED
; ----------------------------------------------------------------------
; common exit: POP HL; RET. Shared by _1 and the extended-function dispatch path.
; ----------------------------------------------------------------------
FRMEVL_PAREN_2:
        POP HL
        RET
; ----------------------------------------------------------------------
; variable-ref: PTRGET (PTRGET_1+1, XOR A) returns the data addr in DE and writes VALTYP; falls into _4.
; ----------------------------------------------------------------------
FRMEVL_PAREN_3:
        CALL PTRGET_1+1
; ----------------------------------------------------------------------
; load var into FAC: store addr into FAC($0CB1); FRMEVL_TEST_TYPE Z=string keeps the ptr, NZ=FP_ARG_SETUP1 copies the value.
; ----------------------------------------------------------------------
FRMEVL_PAREN_4:
        PUSH HL
        EX DE,HL
        LD (FAC),HL
        CALL FRMEVL_TEST_TYPE
        CALL NZ,FP_ARG_SETUP1
        POP HL
        RET
; ----------------------------------------------------------------------
; CHRGET_UPCASE -- read the current tokenizer char and fold it to upper case
;   In:        HL -> current character in the BASIC text/console line buffer
;   Out:       A = (HL) with ASCII lowercase a-z folded to uppercase; all other bytes unchanged. HL is NOT advanced (peek, not consume). [RE] Carry is left in a defined state by TOUPPER_A's compares (set if A < 'a', else clear) but is an INCIDENTAL side effect -- no caller consumes it; every caller either uses A or recomputes flags (e.g. via IS_LETTER_A / its own CP).
;   Clobbers:  A, F. HL preserved.
;   Algorithm: Load A from (HL) -- the CURRENT char, with NO INC HL, so it differs from the true CHRGET ($33C9, first byte INC HL) which advances first (and which also skips spaces / expands constant tokens; CHRGET_UPCASE does neither). Fall straight into TOUPPER_A to upcase a-z. [RE] Used by CRUNCH's case-insensitive keyword/identifier scan so 'print' and 'PRINT' tokenize identically.
; ----------------------------------------------------------------------
CHRGET_UPCASE:
        ; Peek the CURRENT char (no INC HL -- unlike the real CHRGET, this does not advance the text pointer), then fall into TOUPPER_A to fold it.
        LD A,(HL)
; ----------------------------------------------------------------------
; TOUPPER_A -- fold the ASCII letter already in A to upper case
;   In:        A = candidate character (entry used when the caller already holds the char, skipping CHRGET_UPCASE's LD A,(HL))
;   Out:       A = uppercase if input was 'a'-'z' ($61-$7A), otherwise A unchanged. [RE] Carry is defined but incidental (set when A < 'a' via the early RET C; clear on the A >= '{' passthrough and on the folded a-z path since AND $5F resets carry) -- no caller relies on it.
;   Clobbers:  A, F
;   Algorithm: Range-guard then mask. CP $61/RET C passes through anything below 'a'. CP $7B/RET NC passes through anything at or above '{' ($7B), i.e. above 'z'. The remaining a-z range is folded with AND $5F, which clears bit 5 ($20) to map lowercase to uppercase. Digits, punctuation, control codes, and already-uppercase letters are returned untouched. [RE] Direct callers (non-exhaustive): the &H/&O radix-literal scanner (SCAN_AMP_RADIX_CONST and SCAN_AMP_RADIX_CONST_1), the '&' marker chooser (CRUNCH_AMP_HEX_OCT), and the EDIT-mode keystroke handler (STMT_EDIT).
; ----------------------------------------------------------------------
TOUPPER_A:
        ; Below 'a' ($61): not lowercase, return char unchanged.
        CP $61
        RET C
        ; At or above '{' ($7B), i.e. past 'z': not lowercase, return char unchanged.
        CP $7B
        RET NC
        ; In a-z: clear bit 5 ($20) to fold lowercase to uppercase.
        AND $5F
        RET
; ----------------------------------------------------------------------
; LINGET_OR_AMP -- dispatch on '&': scan a radix literal, else parse a decimal line number
;   In:        A = current source character (already fetched by the caller); HL -> that char in the BASIC text
;   Out:       Falls through to SCAN_AMP_RADIX_CONST when A=='&' ($26); otherwise tail-jumps to LINGET (decimal line-number parser). Result delivered by whichever path runs.
;   Clobbers:  F (the CP); otherwise per the path taken.
;   Algorithm: One-byte guard. If the lookahead char is '&' ($26) drop into the &H/&O radix-constant scanner; any other char means the operand is a plain decimal line number, so JP LINGET. Lets line-number contexts (GOTO/GOSUB target lists) also accept an &H/&O constant.
; ----------------------------------------------------------------------
LINGET_OR_AMP:
        ; '&' introduces an &H/&O radix literal; anything else is a decimal line number.
        CP $26
        JP NZ,LINGET
; ----------------------------------------------------------------------
; SCAN_AMP_RADIX_CONST -- parse an &H<hex> or &O<octal> integer literal into the FAC
;   In:        HL -> the '&' in the source text (CHRGET advances past it). Reached from FRMEVL_EVAL_OPERAND ($3C24) on token $26 and by fall-through from LINGET_OR_AMP.
;   Out:       16-bit value stored in the FAC as a VT_INT integer (via FP_STORE_FAC_INT); HL advanced past the literal. RET to caller.
;   Clobbers:  A, BC, DE, HL, F. The running accumulator lives in DE BETWEEN digit iterations and is swapped into HL (EX DE,HL) for each shift-and-add.
;   Algorithm: CHRGET the radix letter and upcase it. 'O' selects the octal path (SCAN_AMP_RADIX_CONST_5); 'H' selects the hex path (digit-count guard B=5, loop _1.._3). Any other letter defaults to octal with the radix char un-consumed (DEC HL at _4, so it is re-read as the first digit). Hex accumulates value = value*16 + nibble (ADD HL,HL x4) up to 4 hex digits; octal accumulates value*8 + digit (ADD HL,HL x3). Overflow past the field width raises Overflow; an octal digit >= '8' raises Syntax error. The value is converted to a FAC integer at _6.
; ----------------------------------------------------------------------
SCAN_AMP_RADIX_CONST:
        ; DE = running accumulator (zero); the value lives in DE between digits and is swapped into HL for each shift-and-add.
        LD DE,$0000
        CALL CHRGET
        CALL TOUPPER_A
        ; 'O' -> octal scanner.
        CP $4F
        JR Z,SCAN_AMP_RADIX_CONST_5
        ; 'H' -> hex scanner; any other letter defaults to octal with the char pushed back (DEC HL at _4).
        CP $48
        JR NZ,SCAN_AMP_RADIX_CONST_4
        ; Hex digit-count guard: at most 4 nibbles fit in 16 bits, so a 5th decrements B to zero -> Overflow.
        LD B,$05
SCAN_AMP_RADIX_CONST_1:
        INC HL
        LD A,(HL)
        CALL TOUPPER_A
        CALL IS_LETTER_A
        EX DE,HL
        JR NC,SCAN_AMP_RADIX_CONST_2
        CP $3A
        JR NC,SCAN_AMP_RADIX_CONST_6
        SUB $30
        JR C,SCAN_AMP_RADIX_CONST_6
        JR SCAN_AMP_RADIX_CONST_3
SCAN_AMP_RADIX_CONST_2:
        CP $47
        JR NC,SCAN_AMP_RADIX_CONST_6
        SUB $37
SCAN_AMP_RADIX_CONST_3:
        ADD HL,HL
        ADD HL,HL
        ADD HL,HL
        ADD HL,HL
        OR L
        LD L,A
        DEC B
        JP Z,RAISE_OVERFLOW
        EX DE,HL
        JR SCAN_AMP_RADIX_CONST_1
SCAN_AMP_RADIX_CONST_4:
        DEC HL
; ----------------------------------------------------------------------
; SCAN_AMP_RADIX_CONST_5 -- octal-literal accumulation loop (value = value*8 + digit)
;   In:        DE = running 16-bit accumulator; HL -> next source char (radix char already positioned).
;   Out:       On a non-digit char: leaves the assembled value in HL (via EX DE,HL) and branches to _6 to store it. Otherwise loops.
;   Clobbers:  A, BC, DE, HL, F.
;   Algorithm: CHRGET the next char; EX DE,HL (value into HL); CHRGET returned carry-clear iff the char is not an ASCII digit, which ends the literal (JR NC to _6). A digit >= '8' is illegal octal -> Syntax error. Otherwise shift the value in HL left by 3 (ADD HL,HL x3) with carry-out checked after each shift (RET C -> the pushed RAISE_OVERFLOW), then add digit-'0' (in C) and EX DE,HL back before looping.
; ----------------------------------------------------------------------
SCAN_AMP_RADIX_CONST_5:
        CALL CHRGET
        EX DE,HL
        JR NC,SCAN_AMP_RADIX_CONST_6
        ; Digit '8' or '9' is not a valid octal digit -> Syntax error.
        CP $38
        JP NC,RAISE_SYNTAX_ERROR
        ; Arm RAISE_OVERFLOW as the return target so the three RET C shift-overflow checks raise Overflow with no explicit branch each.
        LD BC,RAISE_OVERFLOW
        PUSH BC
        ADD HL,HL
        RET C
        ADD HL,HL
        RET C
        ADD HL,HL
        RET C
        POP BC
        LD B,$00
        SUB $30
        LD C,A
        ADD HL,BC
        EX DE,HL
        JR SCAN_AMP_RADIX_CONST_5
; ----------------------------------------------------------------------
; SCAN_AMP_RADIX_CONST_6 -- store the scanned radix value into the FAC and return
;   In:        HL = the assembled 16-bit value (every path EX DE,HL's the accumulator into HL before branching here); DE = the saved source text pointer (first char past the literal).
;   Out:       FAC holds the value as a VT_INT integer; HL = source pointer past the literal (restored from DE). RET.
;   Clobbers:  A, DE, HL, F.
;   Algorithm: CALL FP_STORE_FAC_INT first -- it does LD (FAC),HL, so HL must already hold the value -- then EX DE,HL swaps the saved text pointer (in DE) back into HL for the caller, and RET. NOTE: the EX DE,HL is AFTER the store (to recover the text pointer), not before it; the value is never in DE here.
; ----------------------------------------------------------------------
SCAN_AMP_RADIX_CONST_6:
        CALL FP_STORE_FAC_INT
        EX DE,HL
        RET
; ----------------------------------------------------------------------
; FRMEVL_FUNC_TOKEN -- FRMEVL handler for an extended function token (the $FF escape); NOT part of the &H/&O scanner
;   In:        Entered from FRMEVL_EVAL_OPERAND at $3C0A when the current source char is $FF (the function-escape token): the code does INC A (A=$FF -> $00), JP Z,_7. So on entry A=$00 (the INC A result, immediately overwritten); HL -> the $FF byte.
;   Out:       Tail-dispatches to the function's handler via the FUNC_DISPATCH_TBL vector (jumps, does not return here). For RND with no '(' it diverts to the RND-no-argument entry ($5D89).
;   Clobbers:  A, BC, HL, F (and FAC/stack via the argument evaluation in the sub-paths).
;   Algorithm: Step past the $FF escape (INC HL; LD A,(HL)) to read the function sub-token and form index = sub-token - $81. Special-case index 7 (= FUNC_DISPATCH_TBL slot 7 = RND): peek the next char via CHRGET; if it is not '(' this is RND with no argument so JP to the RND-no-arg path; if '(' force A=index 7 and continue. Fall into FRMEVL_FUNC_TOKEN_1 to dispatch.
;   [RE] The $FF-then-byte scheme is the MS BASIC-80 extended-function token path. UNKNOWN: the full sub-token -> table-slot mapping is fixed by the tokenizer; only the RND index (7) is special-cased in code here.
; ----------------------------------------------------------------------
FRMEVL_FUNC_TOKEN:
        ; Step past the $FF function-escape byte to the function sub-token.
        INC HL
        LD A,(HL)
        ; Function sub-tokens start at $81; subtract to get the 0-based FUNC_DISPATCH_TBL index.
        SUB $81
        ; Index 7 is RND, the only function allowing the no-argument form RND with no parens.
        CP $07
        JR NZ,FRMEVL_FUNC_TOKEN_1
        PUSH HL
        CALL CHRGET
        CP $28
        POP HL
        ; [RE] RND with no '(': divert to the RND-no-argument entry ($5D89), which CHRGETs, loads a default arg, and calls FN_RND -- POLY_EVAL_2 is a mislabel of that entry.
        JP NZ,POLY_EVAL_2
        LD A,$07
; ----------------------------------------------------------------------
; FRMEVL_FUNC_TOKEN_1 -- build the dispatch index and evaluate the function argument list
;   In:        A = function table index (0-based; 7 forced for RND-with-parens); HL -> the function token.
;   Out:       For the multi-argument string functions (raw indices 0,1,2) both arguments are evaluated and staged on the stack, then JR to the dispatch tail (_11) with HL=doubled index; otherwise control passes to FRMEVL_FUNC_ARG_PAREN for the single-(arg) form.
;   Clobbers:  A, BC, DE, HL, F, FAC, stack.
;   Algorithm: Double the index into a byte offset (RLCA) and save it (PUSH BC, B=0). CHRGET past the function token. If the doubled index (in C) < $05 (raw index 0,1,2) evaluate the first argument with FRMEVL, require ',' via SYNCHR, integer-check it (REQUIRE_STRING), juggle it onto the stack, GETBYT the second argument, recover the doubled index into HL via EX (SP),HL, and JR to _11. Doubled index >= $05 (raw index >= 3) takes the single-(arg) path at FRMEVL_FUNC_ARG_PAREN.
; ----------------------------------------------------------------------
FRMEVL_FUNC_TOKEN_1:
        LD B,$00
        ; Double the index to a 2-byte (DEFW) offset into FUNC_DISPATCH_TBL.
        RLCA
        LD C,A
        PUSH BC
        CALL CHRGET
        LD A,C
        ; Doubled index < 5 (raw 0,1,2) = multi-argument string functions (STR_SUBSTR/LEFT$/RIGHT$); otherwise a single parenthesised argument.
        CP $05
        JP NC,FRMEVL_FUNC_ARG_PAREN
        CALL FRMEVL
        CALL SYNCHR
        DEFB    ','                      ; inline char arg consumed by the preceding CALL
        CALL REQUIRE_STRING
        EX DE,HL
        LD HL,(FAC)
        EX (SP),HL
        PUSH HL
        EX DE,HL
        CALL GETBYT
        EX DE,HL
        EX (SP),HL
        JR FRMEVL_FUNC_DISPATCH
; ----------------------------------------------------------------------
; FRMEVL_FUNC_ARG_PAREN -- evaluate a single parenthesised function argument
;   In:        Doubled dispatch index on the stack; HL -> '(' of the argument; entered when the doubled index >= $05.
;   Out:       Argument value left in the FAC (promoted to single precision when the index falls in the math band); falls into FRMEVL_FUNC_ARG_PROMOTE then the dispatch tail.
;   Clobbers:  A, DE, HL, F, FAC, stack.
;   Algorithm: FRMEVL_PAREN evaluates the (expr) and consumes the ')'. Recover the doubled index (EX (SP),HL) and inspect L (= index*2): if L < $0C skip coercion; if $0C <= L < $1B call FN_CSNG to coerce the argument to single precision. [RE] That $0C..$1B band is doubled raw indices 6-13 = SQR/RND/SIN/LOG/EXP/COS/TAN/ATN -- the transcendental functions whose handlers want a single-precision float argument (enumerated from FUNC_DISPATCH_TBL).
; ----------------------------------------------------------------------
FRMEVL_FUNC_ARG_PAREN:
        ; Evaluate the parenthesised argument expression and consume the closing ')'.
        CALL FRMEVL_PAREN
        EX (SP),HL
        LD A,L
        CP $0C
        JR C,FRMEVL_FUNC_ARG_PROMOTE
        CP $1B
        PUSH HL
        ; [RE] Coerce the argument to single precision for the transcendental functions (raw indices 6-13: SQR/RND/SIN/LOG/EXP/COS/TAN/ATN).
        CALL C,FN_CSNG
        POP HL
; ----------------------------------------------------------------------
; FRMEVL_FUNC_ARG_PROMOTE -- arm the function return and mark function-eval in progress
;   In:        Doubled dispatch index on the stack (with the saved text pointer below it); argument staged in the FAC.
;   Out:       FRMEVL_PAREN_2 (POP HL; RET) pushed as the handler's return; L_0CB6 set to 1; falls into FRMEVL_FUNC_DISPATCH.
;   Clobbers:  A, DE, F.
;   Algorithm: Push FRMEVL_PAREN_2 so the function handler, when it RETs, pops the saved text pointer and returns through it. Set L_0CB6 = 1. [RE] L_0CB6 here is the FRMEVL function-evaluation-in-progress flag (cleared to 0 by XOR A; LD (L_0CB6),A at FRMEVL_OPLOOP $3A82). DUAL-USE CAVEAT: CLEAR_EVAL_FLAG_0CB6 ($4539) treats the same cell $0CB6 as a screen reverse/INVERSE flag; the two uses are NOT reconciled, so the label is left unrenamed.
; ----------------------------------------------------------------------
FRMEVL_FUNC_ARG_PROMOTE:
        ; Arm FRMEVL_PAREN_2 (POP HL; RET) as the function handler's return path; its POP HL recovers the saved text pointer.
        LD DE,FRMEVL_PAREN_2
        PUSH DE
        LD A,$01
        ; [RE] Flag that a function argument is being evaluated (cleared at FRMEVL_OPLOOP $3A82). NOTE $0CB6 is also used as a screen-INVERSE flag elsewhere -- dual-use, unreconciled.
        LD (L_0CB6),A
; ----------------------------------------------------------------------
; FRMEVL_FUNC_DISPATCH -- jump to the selected function handler via FUNC_DISPATCH_TBL
;   In:        HL = the 2-byte (DEFW) index offset for the function (= raw index * 2, recovered from the stack by the argument paths); arguments staged in the FAC/stack.
;   Out:       Tail-jumps to the function's handler (via DISPATCH_VECTOR_HLBC). Does not return here.
;   Clobbers:  BC, HL (then per the target handler).
;   Algorithm: Load BC = FUNC_DISPATCH_TBL base and fall into DISPATCH_VECTOR_HLBC, which forms base + (index*2), loads the 16-bit handler address from that DEFW slot, and JP (HL). Because the index is already doubled, DISPATCH_VECTOR_HLBC's ADD HL,BC here just adds the pre-doubled offset to the base.
; ----------------------------------------------------------------------
FRMEVL_FUNC_DISPATCH:
        ; BC = function vector-table base; the doubled index offset is already in HL.
        LD BC,FUNC_DISPATCH_TBL
; ----------------------------------------------------------------------
; DISPATCH_VECTOR_HLBC -- indexed vector dispatch: jump through a DEFW table slot
;   In:        HL and BC such that HL+BC = the address of a 2-byte DEFW vector slot.
;   Out:       Jumps to the 16-bit address stored at (HL+BC). Never returns here (control leaves via JP (HL)); a caller wanting a return either pushes one first or CALLs this routine.
;   Clobbers:  HL, C (C reused to hold the target's low byte).
;   Algorithm: ADD HL,BC to address the slot, read the little-endian target word (C=low byte, then H=high byte), set L=C so HL=target, JP (HL). Two callers split base/offset differently: FRMEVL_FUNC_DISPATCH passes BC=FUNC_DISPATCH_TBL base and HL=index*2 (pre-doubled); FRMEVL_APPLY_OP ($3FFF) passes HL=OPERATOR_ROUTINE_TBL+rawindex and BC=rawindex, so its ADD HL,BC adds rawindex a second time, effectively doubling the raw index. Either way HL+BC must equal the slot address.
; ----------------------------------------------------------------------
DISPATCH_VECTOR_HLBC:
        ; Form the address of the DEFW vector slot (HL+BC).
        ADD HL,BC
        LD C,(HL)
        INC HL
        LD H,(HL)
        LD L,C
        ; Jump to the handler address read from the slot.
        JP (HL)
; ----------------------------------------------------------------------
; FIN_EXP_SIGN_SCAN -- consume an optional leading sign while scanning a number's exponent
;   In:        A = current char (the char after the 'E'/'D' exponent marker in a numeric literal); D = exponent-sign accumulator (FIN_7 pre-loads it); HL -> that char.
;   Out:       RET with D toggled per the sign: '-' (raw $2D or token TOK_MINUS $F3) leaves D decremented (sign flipped); '+' (raw $2B or token TOK_PLUS $F2) leaves D unchanged (the DEC/INC cancel). Neither sign -> DEC HL backs the pointer up so the caller re-reads the char as the first exponent digit, then RET. Z is set when a sign matched (incidental: the caller FIN_8 re-reads via CHRGET and does not consume this Z).
;   Clobbers:  D, HL, F.
;   Algorithm: Pre-decrement D, then test the two minus encodings (TOK_MINUS $F3, ASCII '-' $2D) -- a match RETs with the toggle applied. For plus, INC D undoes the pre-decrement before testing '+' ($2B) and TOK_PLUS ($F2). No match -> DEC HL (push the char back) and RET. [RE] Sole caller is the FIN number scanner's exponent handler (FIN_7 $551A, reached on 'D'/'d'/'E'); FIN_8 ($552A) does INC D / JR NZ then negates the exponent E when D wrapped to 0 -- so D's value here is the exponent sign. This is an exponent-sign scan, NOT a general unary-operator factor prescan.
; ----------------------------------------------------------------------
FIN_EXP_SIGN_SCAN:
        ; Tentatively flip the exponent-sign accumulator; undone below for the '+' / no-sign cases.
        DEC D
        CP TOK_MINUS
        RET Z
        CP $2D
        RET Z
        ; Cancel the tentative flip for the '+' / no-sign cases.
        INC D
        CP $2B
        RET Z
        CP TOK_PLUS
        RET Z
        ; No sign present: back up so the caller re-reads this char as the first exponent digit.
        DEC HL
        RET
; ----------------------------------------------------------------------
; FRMEVL_RELOP_RESULT -- turn a comparison's flags + relation mask into a BASIC truth value
;   In:        A = ordering result of the just-applied numeric comparison (sign of left-right, one of $FF/$00/$01); the requested relation mask is on the stack (it was accumulated in D by FRMEVL_RELOP and pushed via PUSH DE in FRMEVL_ARITHOP, so POP BC recovers it into B).
;   Out:       FAC = 0 (false) or -1 (true) as a VT_INT integer (via INT16_TO_FP); continues into FRMEVL_OPLOOP_2 via the shared tail _3.
;   Clobbers:  A, BC, HL, F, FAC.
;   Algorithm: This routine is pushed as a RETURN ADDRESS by FRMEVL_ARITHOP ($3B3F LD HL,this; PUSH HL) so the comparison kernel RETs into it. INC A then ADC A,A maps the ordering code into a small index; POP BC recovers the relation mask into B; AND B tests whether the requested relation holds; ADD $FF then SBC A,A folds non-zero -> $FF (true,-1) and zero -> $00 (false), which INT16_TO_FP stores as a 16-bit integer in the FAC. [RE] The exact bit assignment of the INC A;ADC A,A index is the canonical MS BASIC relational fold; the precise {LT,EQ,GT} bit positions were not pinned and are not load-bearing here.
; ----------------------------------------------------------------------
FRMEVL_RELOP_RESULT:
        INC A
        ADC A,A
        ; Recover the requested relation mask into B (accumulated in D by FRMEVL_RELOP, pushed via PUSH DE).
        POP BC
        ; Keep only the bit matching the actual ordering: non-zero iff the requested relation holds.
        AND B
        ADD A,$FF
        ; Fold to BASIC truth: -1 (true) when the relation held, 0 (false) otherwise.
        SBC A,A
        CALL INT16_TO_FP
        JR FRMEVL_RESULT_DONE
; ----------------------------------------------------------------------
; FRMEVL_NOT -- evaluate the NOT operator (bitwise one's-complement of an integer)
;   In:        HL -> source just past the NOT token; entered from FRMEVL_EVAL_OPERAND ($3C1F) on token TOK_NOT ($E4).
;   Out:       FAC = NOT(operand) as a VT_INT integer; continues into the operator loop via the shared tail _3 (JP FRMEVL_OPLOOP_2).
;   Clobbers:  A, BC, D, HL, F, FAC.
;   Algorithm: Set D = $5A (the binding precedence passed to FRMEVL_OPLOOP) and CALL FRMEVL_OPLOOP to evaluate the operand at that precedence. FN_CINT coerces it to a 16-bit integer in HL, both bytes are CPL'd (one's complement), the result is stored to the FAC (LD (FAC),HL; type stays integer from FN_CINT), POP BC discards the saved precedence frame, then fall into _3 -> JP FRMEVL_OPLOOP_2 to resume operator scanning. [RE] $5A read as NOT's operator precedence (the D byte FRMEVL_OPLOOP saves as 'pending-operator precedence').
; ----------------------------------------------------------------------
FRMEVL_NOT:
        ; [RE] D = NOT's binding precedence; FRMEVL_OPLOOP evaluates the operand bound at this level.
        LD D,$5A
        CALL FRMEVL_OPLOOP
        ; NOT operates on integers: coerce the operand to a 16-bit int before complementing.
        CALL FN_CINT
        LD A,L
        CPL
        LD L,A
        LD A,H
        CPL
        LD H,A
        LD (FAC),HL
        POP BC
; ----------------------------------------------------------------------
; FRMEVL_RESULT_DONE -- shared tail that resumes the operator loop after a NOT or relational result
;   In:        Result already in the FAC; pending-operator frame restored.
;   Out:       Jumps to FRMEVL_OPLOOP_2 to continue evaluating any following binary operators.
;   Clobbers:  (none of its own).
;   Algorithm: Single JP FRMEVL_OPLOOP_2 -- shared continuation reached BOTH from FRMEVL_NOT (fall-through) AND from FRMEVL_RELOP_RESULT (JR _3).
; ----------------------------------------------------------------------
FRMEVL_RESULT_DONE:
        JP FRMEVL_OPLOOP_2
; ----------------------------------------------------------------------
; FRMEVL_TEST_TYPE -- classify the current value's type from VALTYP and return it in the flags
;   In:        VALTYP ($0B14) = storage width of the FAC value (VT_INT=2, VT_STR=3, VT_SNG=4, VT_DBL=8).
;   Out:       Flags encode the type (verified byte-for-byte): Z set <=> string (VALTYP==3); carry set <=> VALTYP < 8 (i.e. NOT double, because the >=8 path's OR A clears carry and there is no SCF there); sign M set <=> integer (VALTYP==2, since 2-3=$FF). A = VALTYP-3.
;   Clobbers:  A, F.
;   Algorithm: Load VALTYP and CP $08 to split double (>= 8) from the rest. On the < 8 path: SUB $03 (int->$FF/M, string->$00/Z, single->$01/P), OR A to set S/Z, then SCF (carry SET unconditionally). On the >= 8 (double) path: the same SUB $03; OR A, but NO SCF, so OR A leaves carry CLEAR. Callers (FN_CSNG/FN_CDBL/FN_CINT, CRUNCH type split, PRINT type split) branch on Z for string and on carry for double-vs-rest.
; ----------------------------------------------------------------------
FRMEVL_TEST_TYPE:
        LD A,(VALTYP)
        ; Split double precision (VALTYP>=8) from int/string/single.
        CP $08
        JR NC,FRMEVL_TEST_TYPE_1
        SUB $03
        OR A
        SCF
        RET
; ----------------------------------------------------------------------
; FRMEVL_TEST_TYPE_1 -- double-precision tail of the VALTYP type test (carry left clear)
;   In:        A = VALTYP, reached (via JR NC) with VALTYP >= 8 (double).
;   Out:       A = VALTYP-3 (=5 for VT_DBL); Z clear, sign positive, carry CLEAR -- the cleared carry signals 'this value is double precision'. RET.
;   Clobbers:  A, F.
;   Algorithm: SUB $03; OR A; RET. Identical arithmetic to the main path but WITHOUT the SCF, so OR A leaves carry clear and the double case is distinguished purely by carry-clear. Not an independent entry point (only the internal JR NC reaches it).
; ----------------------------------------------------------------------
FRMEVL_TEST_TYPE_1:
        SUB $03
        OR A
        RET
; ----------------------------------------------------------------------
; FRMEVL_INT_OP_HANDLER -- integer binary-op kernel. In: B=dispatch; FAC=right operand; LEFT on stack. PUSH BC; FN_CINT->HL; POP AF->dispatch; POP DE->LEFT.
; ----------------------------------------------------------------------
FRMEVL_INT_OP_HANDLER:
        PUSH BC
        CALL FN_CINT
        POP AF
        ; DE = left operand (pushed before recursing on the right operand)
        POP DE
        CP $7A
        JP Z,INT_DIV_ROUND
        CP $7B
        JP Z,INT_DIV_KERNEL
        LD BC,FP_LOAD_INT_TO_FAC_1
        PUSH BC
        CP $46
        JR NZ,INT_OP_AND
        LD A,E
        OR L
        LD L,A
        LD A,H
        OR D
        RET
; ----------------------------------------------------------------------
; INT_OP_AND -- AND arm (50): L=E&L,A=H&D. MIS-NAMED.
; ----------------------------------------------------------------------
INT_OP_AND:
        CP $50
        JR NZ,INT_OP_XOR
        LD A,E
        AND L
        LD L,A
        LD A,H
        AND D
        RET
; ----------------------------------------------------------------------
; INT_OP_XOR -- XOR arm (3C): L=E^L,A=H^D. MIS-NAMED.
; ----------------------------------------------------------------------
INT_OP_XOR:
        CP $3C
        JR NZ,INT_OP_EQV
        LD A,E
        XOR L
        LD L,A
        LD A,H
        XOR D
        RET
; ----------------------------------------------------------------------
; INT_OP_EQV -- EQV arm (32): NOT(a XOR b). MIS-NAMED.
; ----------------------------------------------------------------------
INT_OP_EQV:
        CP $32
        JR NZ,INT_OP_IMP
        LD A,E
        XOR L
        CPL
        LD L,A
        LD A,H
        XOR D
        CPL
        RET
; ----------------------------------------------------------------------
; INT_OP_IMP -- IMP arm (28): (NOT a) OR b. MIS-NAMED.
; ----------------------------------------------------------------------
INT_OP_IMP:
        LD A,L
        CPL
        AND E
        CPL
        LD L,A
        LD A,H
        CPL
        AND D
        CPL
        RET
; ----------------------------------------------------------------------
; FP_INT_SUB_TO_FAC -- subtract HL-DE then INT_TO_SNG. STANDALONE; caller FN_FRE (line 13375).
; ----------------------------------------------------------------------
FP_INT_SUB_TO_FAC:
        LD A,L
        SUB E
        LD L,A
        LD A,H
        SBC A,D
        LD H,A
        JP INT_TO_SNG
; ----------------------------------------------------------------------
; FN_LPOS -- BASIC function LPOS(x): report the line-printer's current print column (1-based).
;   In:        OUTPUT_COLUMN ($0837) = internal 0-based column of the next char on the LIST/printer device (tracked by OUTCHR). The (x) argument is parsed and evaluated by the function-call setup but its value is discarded here. [RE] x is a dummy printer/device number.
;   Out:       FAC ($0CB1) = OUTPUT_COLUMN + 1 stored as a VT_INT integer (high byte 0); VALTYP ($0B14) = VT_INT (=2). Set by the shared FN_POS_1 / FP_STORE_FAC_INT tail.
;   Clobbers:  A, H, L, F; memory FAC and VALTYP (written by the shared tail).
;   Algorithm: Load the printer column byte into A, then JR into the shared FN_POS_1 tail (bypassing the console-column load). FN_POS_1 does INC A and stores A zero-extended as an integer in the FAC. Because it joins FN_POS_1 it gets the SAME +1 as POS, so LPOS returns column+1, not the raw cell. [RE] internal column is 0-based (the PRINT-zone code treats cell==0 as line-start); +1 makes it the 1-based value BASIC reports.
; ----------------------------------------------------------------------
FN_LPOS:
        LD A,(OUTPUT_COLUMN)
        ; join the shared +1-and-store tail, skipping the console-column load (LPOS gets the same +1 as POS)
        JR FN_POS_1
; ----------------------------------------------------------------------
; FN_POS -- BASIC function POS(x): report the console's current cursor (output) column (1-based).
;   In:        CURSOR_POS ($0B11) = internal 0-based column of the next char on the console/CRT. The (x) argument is parsed/evaluated by the call setup but its value is discarded. [RE] x is a dummy.
;   Out:       FAC ($0CB1) = CURSOR_POS + 1 stored as a VT_INT integer; VALTYP ($0B14) = VT_INT (=2). Set by the shared tail.
;   Clobbers:  A, H, L, F; memory FAC and VALTYP (written by the shared tail).
;   Algorithm: Load the console cursor column into A and fall straight into FN_POS_1, which does INC A and stores the byte zero-extended as an integer in the FAC. Differs from FN_LPOS only in which column cell it reads. [RE] internal column is 0-based; +1 yields the 1-based reported value.
; ----------------------------------------------------------------------
FN_POS:
        ; read the console cursor column, then fall into the shared +1-and-store tail
        LD A,(CURSOR_POS)
; ----------------------------------------------------------------------
; FN_POS_1 -- shared tail for LPOS/POS: convert the 0-based column in A to the 1-based result and store it in the FAC as an integer.
;   In:        A = internal 0-based column byte (from OUTPUT_COLUMN via FN_LPOS's JR, or CURSOR_POS via FN_POS's fall-through).
;   Out:       FAC ($0CB1) = (A+1) zero-extended to 16 bits as a VT_INT integer; VALTYP ($0B14) = VT_INT (=2). Returns via the FP_STORE_FAC_INT RET to the function-return path.
;   Clobbers:  A, H, L, F; memory FAC and VALTYP.
;   Algorithm: INC A turns the internal 0-based column into the 1-based column BASIC reports, then falls into FP_LOAD_INT_TO_FAC (LD L,A ; XOR A ; LD H,A => HL = A with high byte 0) and tail-jumps to FP_STORE_FAC_INT, which writes HL to the FAC and sets VALTYP=VT_INT. [RE] column values are < 256 so the zeroed high byte is always correct.
; ----------------------------------------------------------------------
FN_POS_1:
        ; convert the internal 0-based column to the 1-based column BASIC reports, then fall into FP_LOAD_INT_TO_FAC to store it as an integer
        INC A
; [RE] Store the 8-bit value in A (zero-extended to HL) as an integer into the FAC via FP_STORE_FAC_INT.
FP_LOAD_INT_TO_FAC:
        LD L,A
        XOR A
FP_LOAD_INT_TO_FAC_1:
        LD H,A
        JP FP_STORE_FAC_INT
FP_LOAD_INT_TO_FAC_2:
        CALL USRVEC_ADDR
        PUSH DE
        CALL FRMEVL_PAREN
        EX (SP),HL
        LD C,(HL)
        INC HL
        LD B,(HL)
        LD HL,FMUL_7
        PUSH HL
        PUSH BC
        LD A,(VALTYP)
        PUSH AF
        CP $03
        CALL Z,FRESTR
        POP AF
        EX DE,HL
        LD HL,FAC
        RET
; [RE] Compute the address of a USR(n) dispatch vector: base $081F + (digit index*2 from $0B1B if a numeric suffix follows the USR token), returned in DE. Used by DEF USR / USR-call setup.
USRVEC_ADDR:
        CALL CHRGET
        LD BC,$0000
        CP $1B
        JR NC,USRVEC_ADDR_1
        CP $11
        JR C,USRVEC_ADDR_1
        CALL CHRGET
        LD A,(CONST_VALUE)
        OR A
        RLA
        LD C,A
USRVEC_ADDR_1:
        EX DE,HL
        LD HL,L_081F
        ADD HL,BC
        EX DE,HL
        RET
USRVEC_ADDR_2:
        CALL USRVEC_ADDR
        PUSH DE
        CALL SYNCHR
        DEFB    TOK_EQ                   ; inline keyword-token arg consumed by the preceding CALL
        CALL GETINT
        EX (SP),HL
        LD (HL),E
        INC HL
        LD (HL),D
        POP HL
        RET
; ----------------------------------------------------------------------
; STMT_DEF -- DEF statement handler (keyword token $96): route DEF USR vs DEF FN and record the definition.
;   In:        A = the token immediately after DEF (already CHRGOT by the statement dispatcher); HL -> that token in the program text.
;   Out:       For DEF USR (A == $E1): tail-jumps to USRVEC_ADDR_2, which parses '=addr' (GETINT) and stores the address word into the USR(n) vector slot (L_081F + n*2). For DEF FN: the function name's variable slot is made to hold the text pointer just past 'FN name', so a later FN call can find and execute the definition. The formal-parameter list inside '(...)' is then consumed by the fall-through into STMT_DEF_1, ending at STMT_DATA (skip to end of statement). HL advanced.
;   Clobbers:  A, BC, DE, HL, flags, the FAC (via GETVAR_NAME->PTRGET).
;   Algorithm: If A == $E1 (USR token) divert to USRVEC_ADDR_2 (DEF USRn = addr). Otherwise this is DEF FN: GETVAR_NAME parses 'FN name' and resolves the function variable's storage to DE; DEF_FN_REQUIRE_PROGRAM rejects DEF issued in direct mode. The two-byte text pointer (current HL, just past the name) is written into that variable's value cell (EX DE,HL / store E,D) so the slot records WHERE the definition's parameter list begins. If the next char is not '(' there is no parameter list to scan, so jump to STMT_DATA. Otherwise CHRGET past '(' and fall into STMT_DEF_1 to walk the formal parameters.
; ----------------------------------------------------------------------
STMT_DEF:
        CP $E1
        ; DEF USR token ($E1): hand off to the USR(n)-vector '=addr' parser
        JR Z,USRVEC_ADDR_2
        CALL GETVAR_NAME
        ; DEF FN is illegal in direct mode -- must be inside a stored program
        CALL DEF_FN_REQUIRE_PROGRAM
        EX DE,HL
        ; record the text pointer (just past 'FN name') into the function variable's slot so a later FN call can locate this definition
        LD (HL),E
        INC HL
        LD (HL),D
        EX DE,HL
        LD A,(HL)
        ; a '(' begins the formal-parameter list; without one there is nothing more to scan
        CP $28
        ; no parameter list: skip the rest of the statement like a DATA line
        JP NZ,STMT_DATA
        CALL CHRGET
; ----------------------------------------------------------------------
; STMT_DEF_1 -- DEF FN definition: consume the comma-separated formal-parameter name list inside the parentheses.
;   In:        HL -> first char of a formal parameter (or ')'); the DEF statement is recording, not evaluating.
;   Out:       On ')' jumps to STMT_DATA to skip to the end of the DEF statement (the body text is left in place for later FN calls). HL advanced past the parameter list.
;   Clobbers:  A, BC, DE, HL, flags, the FAC (via PTRGET).
;   Algorithm: Loop: PTRGET_1+1 parses and skips one formal-parameter variable name (allocating/locating its slot is harmless here -- the DEF only needs to advance the cursor). If the next char is ')', the list is complete -> STMT_DATA. Otherwise SYNCHR requires a ',' separator and the loop repeats for the next parameter name.
; ----------------------------------------------------------------------
STMT_DEF_1:
        ; skip one formal-parameter name (advance the text cursor past it)
        CALL PTRGET_1+1
        LD A,(HL)
        CP $29
        ; ')' closes the parameter list: ignore the body text and skip to end of statement
        JP Z,STMT_DATA
        CALL SYNCHR
        ; a ',' must separate successive formal parameters
        DEFB    ','                      ; inline char arg consumed by the preceding CALL
        JR STMT_DEF_1
; ----------------------------------------------------------------------
; CALL_FN -- evaluate an FN function-call reference in an expression (NOT part of the DEF statement). MIS-NAMED as CALL_FN.
;   In:        Reached only from FRMEVL's 'CP TOK_FN / JP Z' arm (verified at BASIC.asm:4742): HL -> the 'FN' reference in an expression.
;   Out:       The function result is left in the FAC (VALTYP set); HL advanced past the call. May raise 'Undefined user function' if the function was never DEF'd.
;   Clobbers:  A, BC, DE, HL, SP frame, flags, the FAC.
;   Algorithm: GETVAR_NAME resolves 'FN name' to the function variable slot (DE). Save the caller's VALTYP (PUSH AF). Load the stored definition pointer from the slot (the text pointer STMT_DEF wrote, pointing at the DEF's parameter list); if it is $0000 the function was never defined -> RAISE_UNDEFINED_USER_FUNCTION. If the definition's first char is not '(' (a no-arg / bare reference) divert to CALL_FN_BIND+1 (the bare-PUSH-DE cover entry). Otherwise CHRGET past the definition's '(', save the call-site cursor in PRUSING_FORMAT_FLAGS and reload the definition cursor from FOUT_DP_POSITION, SYNCHR the call's '(', push a zero arg-count seed, and fall into the per-argument loop CALL_FN_ARG.
;   UNKNOWN:   [RE] the reuse of PRUSING_FORMAT_FLAGS / FOUT_DP_POSITION as call-site-vs-definition cursor scratch is inferred from the store/reload pattern, not separately audited.
; ----------------------------------------------------------------------
CALL_FN:
        ; resolve 'FN name' to the function variable's slot (DE)
        CALL GETVAR_NAME
        LD A,(VALTYP)
        OR A
        PUSH AF
        LD (FOUT_DP_POSITION),HL
        EX DE,HL
        LD A,(HL)
        INC HL
        LD H,(HL)
        LD L,A
        OR H
        ; the slot holds $0000 -> this FN was never DEF'd
        JP Z,RAISE_UNDEFINED_USER_FUNCTION
        LD A,(HL)
        CP $28
        ; definition has no '(' (no-arg form): jump into the bare PUSH DE cover at CALL_FN_BIND+1
        JP NZ,CALL_FN_BIND+1
        CALL CHRGET
        LD (PRUSING_FORMAT_FLAGS),HL
        EX DE,HL
        LD HL,(FOUT_DP_POSITION)
        CALL SYNCHR
        ; match the '(' of the call's argument list
        DEFB    '('                      ; inline char arg consumed by the preceding CALL
        XOR A
        PUSH AF
        PUSH HL
        EX DE,HL
; ----------------------------------------------------------------------
; CALL_FN_ARG -- per-argument loop of an FN call: evaluate one actual argument, coerce it to the formal parameter's type, and stage it on the stack. MIS-NAMED as CALL_FN_ARG.
;   In:        Iterating over an FN call's actual-argument list; FOUT_DP_POSITION / PRUSING_FORMAT_FLAGS hold the definition and call-site text cursors; top-of-stack carries the running arg-count seed.
;   Out:       One argument value coerced and pushed as an 8-byte FP-arg frame slot; loops via CALL_FN_ARG for the next ','-separated argument, or falls through to STMT_DEF_5 on ')'.
;   Clobbers:  A, BC, DE, HL, SP frame, flags, the FAC.
;   Algorithm: Force scalar context (PTRGET_SUBSCRIPT_FLAG=$80) and PTRGET the next FORMAL parameter to learn its required VALTYP. Evaluate the matching ACTUAL argument expression (FRMEVL_NOPAREN), save the cursors, then FRMEVL_APPLY_OP coerces the FAC to the formal's type (dispatch via OPERATOR_ROUTINE_TBL[VALTYP&7]). Reserve 8 bytes of stack (LD C,$04 / CHECK_STACK_ROOM then SP += $FFF8 = SP-8) and FP_ARG_SETUP2 stores the coerced value there. If the next definition char is ')', the list ends -> STMT_DEF_5; otherwise SYNCHR a ',' on both the definition and call cursors and loop back via CALL_FN_ARG to evaluate the next argument.
; ----------------------------------------------------------------------
CALL_FN_ARG:
        ; force scalar (non-array) context for resolving the formal parameter
        LD A,$80
        LD (PTRGET_SUBSCRIPT_FLAG),A
        CALL PTRGET_1+1
        EX DE,HL
        EX (SP),HL
        LD A,(VALTYP)
        PUSH AF
        PUSH DE
        ; evaluate the actual-argument expression into the FAC
        CALL FRMEVL_NOPAREN
        LD (FOUT_DP_POSITION),HL
        POP HL
        LD (PRUSING_FORMAT_FLAGS),HL
        POP AF
        ; coerce the argument value to the formal parameter's declared type
        CALL FRMEVL_APPLY_OP
        LD C,$04
        CALL CHECK_STACK_ROOM
        ; reserve 8 bytes on the stack for this argument's FP slot (SP -= 8)
        LD HL,$FFF8
        ADD HL,SP
        LD SP,HL
        CALL FP_ARG_SETUP2
        LD A,(VALTYP)
        PUSH AF
        LD HL,(FOUT_DP_POSITION)
        LD A,(HL)
        CP $29
        ; ')' ends the argument list -> finish binding
        JR Z,STMT_DEF_5
        CALL SYNCHR
        DEFB    ','                      ; inline char arg consumed by the preceding CALL
        PUSH HL
        LD HL,(PRUSING_FORMAT_FLAGS)
        CALL SYNCHR
        DEFB    ','                      ; inline char arg consumed by the preceding CALL
        ; more arguments: consume the ',' and evaluate the next one
        JR CALL_FN_ARG
STMT_DEF_4:
        POP AF
        LD (L_0BFB),A
STMT_DEF_5:
        POP AF
        OR A
        JR Z,CALL_FN_BODY_PREP
        LD (VALTYP),A
        LD HL,$0000
        ADD HL,SP
        CALL FP_ARG_SETUP1
        LD HL,$0008
        ADD HL,SP
        LD SP,HL
        POP DE
        LD L,$03
; ----------------------------------------------------------------------
; CALL_FN_PARAM_SIZE -- back-scan a packed formal-parameter name to recover its length, range-check the running argument-save block, save the formal's current slot, and store the staged actual into it. MIS-NAMED as CALL_FN_PARAM_SIZE.
;   In:        DE -> just past a formal parameter's packed name in the definition; L = $03 running-length seed; VALTYP = this parameter's type; L_0BFB = accumulated arg-block length so far.
;   Out:       The formal's current slot contents are saved into the per-call argument block (L_0BFD + running offset); raises ERROR_FC if the accumulated block length reaches $64 (>= 100 bytes). Continues into STMT_LET_3 (assign the staged actual value into the formal's slot) with STMT_DEF_4 pushed twice as the return continuation.
;   Clobbers:  A, BC, DE, HL, flags.
;   Algorithm: Walk DE backward over the name's high-bit-set continuation bytes (INC L per byte, JP M loops while the sign bit is set), then DEC DE three more times (no L update) to skip a fixed name/type prefix. [RE] the precise packed-name field layout is inferred from the INC/DEC counts. ADD VALTYP to L -> this parameter's cell size in B; load the running accumulator L_0BFB into C, ADD A,B and if the total reaches $64 (NC) raise 'Illegal function call'. Compute the destination inside the per-call arg block (L_0BFD + running offset BC) and BLOCK_COPY_DE_HL the formal's current slot contents there (so they can be restored after the call). PUSH STMT_DEF_4 twice and JP STMT_LET_3 to store the staged actual value into the formal variable's slot.
;   UNKNOWN:   [RE] the exact field offsets within the packed SIMPLEVAR name layout being back-scanned are inferred from the INC/DEC counts, not separately verified.
; ----------------------------------------------------------------------
CALL_FN_PARAM_SIZE:
        INC L
        DEC DE
        LD A,(DE)
        OR A
        ; walk back over the name's high-bit-set continuation bytes, counting length in L
        JP M,CALL_FN_PARAM_SIZE
        DEC DE
        DEC DE
        DEC DE
        LD A,(VALTYP)
        ADD A,L
        LD B,A
        LD A,(L_0BFB)
        LD C,A
        ADD A,B
        ; accumulated argument-block size >= 100 bytes -> too many/large FN parameters (FC error)
        CP $64
        JP NC,ERROR_FC
        PUSH AF
        LD A,L
        LD B,$00
        LD HL,L_0BFD
        ADD HL,BC
        LD C,A
        ; save the formal variable's current contents into the per-call argument block (restored after the call)
        CALL BLOCK_COPY_DE_HL
        ; push STMT_DEF_4 as the STMT_LET_3 return continuation (back into the next-argument step)
        LD BC,STMT_DEF_4
        PUSH BC
        PUSH BC
        ; assign the staged actual value into the formal parameter's variable slot
        JP STMT_LET_3
; ----------------------------------------------------------------------
; CALL_FN_BODY_PREP -- FN call: parenthesised argument list finished; advance both cursors past the call's ')' and fall into the frame-build tail. MIS-NAMED as CALL_FN_BODY_PREP.
;   In:        Reached when the argument loop sees ')'; FOUT_DP_POSITION = definition cursor, PRUSING_FORMAT_FLAGS = call-site cursor.
;   Out:       Both cursors advanced; falls through the PUSH-skip cover (LD A,$D5 in CALL_FN_BIND) into the frame-build/body-evaluation tail. HL = definition cursor pushed for the body eval.
;   Clobbers:  A, HL, flags.
;   Algorithm: Reload the definition cursor (FOUT_DP_POSITION), CHRGET past the parameter-list terminator, push it; reload the call-site cursor (PRUSING_FORMAT_FLAGS) and SYNCHR the call's closing ')'. Then fall into the 3E D5 cover at CALL_FN_BIND: the D5 byte is absorbed as the operand of LD A,$D5 here, so the PUSH DE that the no-arg entry (CALL_FN_BIND+1) would execute is skipped on this parenthesised path. Both paths converge at the store into PRUSING_FORMAT_FLAGS in CALL_FN_BIND.
; ----------------------------------------------------------------------
CALL_FN_BODY_PREP:
        LD HL,(FOUT_DP_POSITION)
        ; advance the definition cursor past the parameter-list terminator
        CALL CHRGET
        PUSH HL
        LD HL,(PRUSING_FORMAT_FLAGS)
        CALL SYNCHR
        ; match the closing ')' of the call's argument list
        DEFB    ')'                      ; inline char arg consumed by the preceding CALL
; ----------------------------------------------------------------------
; CALL_FN_BIND -- build the FN activation frame on the stack, bind the dummy parameters, evaluate the function body, then fall into CALL_FN_RETURN to unwind. MIS-NAMED as CALL_FN_BIND.
;   In:        Entered at CALL_FN_BIND+1 (the bare PUSH DE) from a no-arg FN reference, or by fall-through from CALL_FN_BODY_PREP (the PUSH is skipped). HL/cursors hold the body text position; coerced argument values are staged on the stack; DEFFN_* runtime cells hold the prior FN nesting state.
;   Out:       The function body is evaluated, leaving its result in the FAC; nested DEF FN depth is incremented around the body. Raises 'Syntax error' if the body does not end at a statement terminator.
;   Clobbers:  A, BC, DE, HL, SP frame, flags, the FAC. DEFFN_FRAME_PTR/SIZE, DEFFN_DEPTH, DEFFN_ACTIVE_FLAG, L_0BFB updated.
;   Algorithm: Save the body text cursor into PRUSING_FORMAT_FLAGS. Take DEFFN_FRAME_SIZE+4 as the frame byte count (RRCA halves it only to give CHECK_STACK_ROOM a word count); carve that many bytes off SP (negate via CPL/INC, ADD HL,SP, LD SP,HL). BLOCK_COPY the previous DEFFN_FRAME_PTR header into the new frame (chain the old activation) and republish DEFFN_FRAME_PTR/SIZE. Copy the staged argument block (FN_ARG_BLOCK <- L_0BFD), clear the running arg cell L_0BFB, INC DEFFN_DEPTH and set its boolean shadow DEFFN_ACTIVE_FLAG. Reload the body cursor and EVAL_EXPR_AFTER_SYNCHR evaluates the DEF body expression; the body must end at a statement terminator (DEC HL / CHRGET == 0) else RAISE_SYNTAX_ERROR. If the result is a string whose descriptor points at/above DSCTMP, copy it to a fresh temp (STR_BUILD_FROM_DESC / PUT_STR_TEMP) so it survives the frame teardown, then fall into CALL_FN_RETURN.
;   UNKNOWN:   [RE] the +4 / RRCA frame-size handling and the activation-chain word layout are inferred from the copy pattern; not bit-for-bit audited.
; ----------------------------------------------------------------------
CALL_FN_BIND:
        ; [RE] 3E D5 cover: on the with-args path the D5 is the LD A operand; the no-arg entry (CALL_FN_BIND+1) executes it as PUSH DE to save the text cursor
        LD A,$D5
        LD (PRUSING_FORMAT_FLAGS),HL
        LD A,(DEFFN_FRAME_SIZE)
        ADD A,$04
        PUSH AF
        RRCA
        LD C,A
        ; ensure the stack has room for the new FN activation frame
        CALL CHECK_STACK_ROOM
        POP AF
        LD C,A
        CPL
        INC A
        LD L,A
        LD H,$FF
        ADD HL,SP
        LD SP,HL
        PUSH HL
        LD DE,DEFFN_FRAME_PTR
        ; chain the enclosing activation's frame header into the new frame
        CALL BLOCK_COPY_DE_HL
        POP HL
        LD (DEFFN_FRAME_PTR),HL
        LD HL,(L_0BFB)
        LD (DEFFN_FRAME_SIZE),HL
        LD B,H
        LD C,L
        LD HL,FN_ARG_BLOCK
        LD DE,L_0BFD
        CALL BLOCK_COPY_DE_HL
        LD H,A
        LD L,A
        LD (L_0BFB),HL
        ; enter one FN nesting level deeper
        LD HL,(DEFFN_DEPTH)
        INC HL
        LD (DEFFN_DEPTH),HL
        LD A,H
        OR L
        LD (DEFFN_ACTIVE_FLAG),A
        LD HL,(PRUSING_FORMAT_FLAGS)
        ; evaluate the function's defining expression (the body) into the FAC
        CALL EVAL_EXPR_AFTER_SYNCHR
        DEC HL
        CALL CHRGET
        ; the body must end exactly at the statement terminator
        JP NZ,RAISE_SYNTAX_ERROR
        CALL FRMEVL_TEST_TYPE
        JR NZ,CALL_FN_RETURN
        LD DE,DSCTMP
        LD HL,(FAC)
        CALL CMP_HL_DE
        JR C,CALL_FN_RETURN
        ; string result descriptor points at/above DSCTMP: copy it to a temp so it outlives the frame teardown
        CALL STR_BUILD_FROM_DESC
        CALL PUT_STR_TEMP_1+1
; ----------------------------------------------------------------------
; CALL_FN_RETURN -- tear down the FN activation frame and return to the caller with the result in the FAC. MIS-NAMED as CALL_FN_RETURN.
;   In:        DEFFN_FRAME_PTR -> the current FN activation frame on the stack; the result is in the FAC; DEFFN_DEPTH counts the active nesting.
;   Out:       SP restored to discard the frame; DEFFN_FRAME_PTR/SIZE restored from the saved chain; DEFFN_DEPTH decremented and DEFFN_ACTIVE_FLAG refreshed; the caller's saved HL (text cursor) and AF (saved VALTYP) popped. Falls through into FRMEVL_APPLY_OP / the shared return path.
;   Clobbers:  A, BC, DE, HL, SP, flags.
;   Algorithm: Load DEFFN_FRAME_PTR (D,E = frame base), read the saved-frame length word at frame+2,+3 into BC and INC BC four times (add the header). Restore the enclosing frame header (BLOCK_COPY from frame base into DEFFN_FRAME_PTR), then EX DE,HL / LD SP,HL sets SP to the end of the copied region to pop the activation. DEC DEFFN_DEPTH and update its boolean shadow DEFFN_ACTIVE_FLAG. POP the caller's saved HL (text cursor) and AF (the VALTYP saved at FN entry), then fall through to FRMEVL_APPLY_OP.
;   UNKNOWN:   [RE] the activation-header layout (length word at +2) is inferred from the INC HL counts.
; ----------------------------------------------------------------------
CALL_FN_RETURN:
        LD HL,(DEFFN_FRAME_PTR)
        LD D,H
        LD E,L
        INC HL
        INC HL
        ; read the saved-frame length word (low byte) from the activation header at frame+2
        LD C,(HL)
        INC HL
        LD B,(HL)
        INC BC
        INC BC
        INC BC
        INC BC
        LD HL,DEFFN_FRAME_PTR
        ; restore the enclosing activation's frame header from the saved chain
        CALL BLOCK_COPY_DE_HL
        EX DE,HL
        ; discard the FN activation frame (SP = end of restored region)
        LD SP,HL
        ; leave this FN nesting level
        LD HL,(DEFFN_DEPTH)
        DEC HL
        LD (DEFFN_DEPTH),HL
        LD A,H
        OR L
        LD (DEFFN_ACTIVE_FLAG),A
        POP HL
        POP AF
; ----------------------------------------------------------------------
; FRMEVL_APPLY_OP -- coerce FAC via OPERATOR_ROUTINE_TBL[A&7]; HL preserved.
; ----------------------------------------------------------------------
FRMEVL_APPLY_OP:
        PUSH HL
        AND $07
        LD HL,OPERATOR_ROUTINE_TBL
        LD C,A
        LD B,$00
        ADD HL,BC
        CALL DISPATCH_VECTOR_HLBC
        POP HL
        RET
; ----------------------------------------------------------------------
; BLOCK_COPY_DE_HL_1 -- loop body of BLOCK_COPY_DE_HL. MIS-NAMED.
; ----------------------------------------------------------------------
BLOCK_COPY_DE_HL_1:
        ; copy one source byte to the destination, then advance both pointers
        LD A,(DE)
        LD (HL),A
        INC HL
        INC DE
        DEC BC
; ----------------------------------------------------------------------
; BLOCK_COPY_DE_HL -- ascending block copy of BC bytes from (DE) to (HL).
;   In:        DE = source pointer, HL = destination pointer, BC = byte count.
;   Out:       DE = source+count, HL = dest+count, BC = 0, Z set.
;   Clobbers:  A, BC, DE, HL, flags.
;   Algorithm: Count-test entry point: if BC == 0 return at once; otherwise run a byte-at-a-time
;              ascending copy (LD A,(DE)/LD (HL),A/INC HL/INC DE/DEC BC) looping while BC != 0. A
;              hand loop rather than LDIR so that the surviving DE/HL act as end pointers for the
;              caller. [RE] Callers are the DEF FN handler (STMT_DEF_*), which uses it to save and
;              restore the function-argument frame at $0B91/$0B95/$0BFD.
; ----------------------------------------------------------------------
BLOCK_COPY_DE_HL:
        ; loop guard: stop as soon as the remaining count BC reaches zero
        LD A,B
        OR C
        JR NZ,BLOCK_COPY_DE_HL_1
        RET
; ----------------------------------------------------------------------
; DEF_FN_REQUIRE_PROGRAM -- reject DEF FN / DEF USR issued in direct (immediate) mode.
;   In:        SAVTXT ($0844) = saved program text pointer; equals $FFFF while a direct-mode line runs.
;   Out:       Returns (HL unchanged) when executing a stored program (SAVTXT != $FFFF).
;              When SAVTXT == $FFFF, does not return: jumps to RAISE_ERROR with E = ERR_ILLEGAL_DIRECT (12).
;   Clobbers:  A, flags (HL is pushed and popped, so preserved).
;   Algorithm: Read SAVTXT, INC it and OR H|L to test SAVTXT == $FFFF -- the sentinel BASIC writes
;              while running a direct-mode (keyboard) line. If set, the statement is being typed at
;              the prompt rather than run from a program, which DEF FN/DEF USR forbid, so raise
;              'Illegal direct'. Otherwise return and let STMT_DEF store the function/USR pointer.
;              [RE] This matches the classic MS BASIC-80 'DEF illegal in direct mode' guard; sole caller is STMT_DEF.
; ----------------------------------------------------------------------
DEF_FN_REQUIRE_PROGRAM:
        PUSH HL
        ; [RE] SAVTXT == $FFFF means a direct-mode (keyboard) line is running, not a stored program; INC then OR H|L tests for that sentinel
        LD HL,(SAVTXT)
        INC HL
        LD A,H
        OR L
        POP HL
        ; running inside a program: DEF is allowed, return to STMT_DEF
        RET NZ
        ; direct mode: DEF FN/DEF USR not permitted here, raise 'Illegal direct'
        LD E,ERR_ILLEGAL_DIRECT
        JP RAISE_ERROR
; [RE] Fetch and validate a variable-name token after SYNCHR: requires an alphabetic first char (JP PO on letter test), records the name in $0B52, then resolves it via PTRGET (PTRGET_2).
GETVAR_NAME:
        CALL SYNCHR
        DEFB    TOK_FN                   ; inline keyword-token arg consumed by the preceding CALL
        LD A,$80
        LD (PTRGET_SUBSCRIPT_FLAG),A
        OR (HL)
        LD C,A
        JP PTRGET_2
GETVAR_NAME_1:
        CP $7E
        JP NZ,RAISE_SYNTAX_ERROR
        INC HL
        LD A,(HL)
        CP $83
        JP NZ,RAISE_SYNTAX_ERROR
        INC HL
        JP STMT_MID_ASSIGN
        JP RAISE_SYNTAX_ERROR
; ----------------------------------------------------------------------
; STMT_WIDTH -- WIDTH statement handler (keyword token $9D): set the output line width, distinguishing 'WIDTH LPRINT n' from the console/file forms.
;   In:        A = the token after WIDTH (CHRGOT by the dispatcher); HL -> that token. A == $9B is the LPRINT keyword token (the 'WIDTH LPRINT' form).
;   Out:       For 'WIDTH LPRINT n': stores the printer line width n into LPRINT_WIDTH ($083A) and the clamped comma-zone column into LPRINT_ZONE_WIDTH ($0839), then RET. For other forms: falls into STMT_WIDTH_1. HL advanced past the parsed operand.
;   Clobbers:  A, BC, DE, HL, flags, the FAC.
;   Algorithm: If A == $9B (LPRINT token) this is 'WIDTH LPRINT n': CHRGET past LPRINT, GETBYT evaluates the width byte, store it raw as the printer width (LPRINT_WIDTH), then WIDTH_CLAMP_COLUMN folds it into the printer comma-zone column stored at LPRINT_ZONE_WIDTH, and return. Otherwise dispatch the console/optional-trailing-field forms via STMT_WIDTH_1.
;   NOTE [RE]: LPRINT_WIDTH ($083A, default $84=132) and LPRINT_ZONE_WIDTH ($0839, default $70=112) are the printer-output line width and comma-zone width read by the PRINT line-overflow / comma-tab logic when PRTFLG is set (verified at STMT_PRINT_3 line 3559 and STMT_PRINT_7 line 3601, both gated on PRTFLG nonzero).
; ----------------------------------------------------------------------
STMT_WIDTH:
        ; $9B is the LPRINT token: select 'WIDTH LPRINT n' (printer width) vs the console form
        CP $9B
        JR NZ,STMT_WIDTH_1
        CALL CHRGET
        CALL GETBYT
        LD (PRINTER_WIDTH),A
        LD E,A
        CALL WIDTH_CLAMP_COLUMN
        ; store the clamped printer comma-zone column
        LD (LPRINT_ZONE_WIDTH),A
        RET
; ----------------------------------------------------------------------
; STMT_WIDTH_1 -- WIDTH continuation (non-LPRINT form): set the console width and an optional trailing page-length field.
;   In:        A = the token after WIDTH (not the LPRINT token); HL -> it.
;   Out:       Falls into WIDTH_SET_CONSOLE (stores PRINT_WIDTH and the clamped console comma-zone width WIDTH_FILE, then on a trailing ',' stores PAGE_LENGTH), or jumps to WIDTH_SET_CONSOLE_1 when the form starts with ',' (set only the page-length field). HL advanced.
;   Clobbers:  A, BC, DE, HL, flags, the FAC.
;   Algorithm: If the next char is ',' the width field is omitted -> WIDTH_SET_CONSOLE_1 sets only the page-length. Otherwise GETBYT evaluates the console width and falls into WIDTH_SET_CONSOLE to store PRINT_WIDTH + the clamped comma-zone width; a trailing ',' then sets PAGE_LENGTH.
;   CORRECTION [RE]: this handler does NOT decode a '#file' number -- there is no '#' parse in the code path (contradicting the pre-existing line-5585 source comment's 'WIDTH #file,width' wording). The immediate path sets the console width and an optional trailing PAGE_LENGTH; per-file output width lives in the FCB (read at STMT_PRINT_7 when PTRFIL is nonzero), not here. The existing WIDTH_FILE label name is itself misleading: $083D holds the CONSOLE comma-zone width read at STMT_PRINT_8 ($3609) when PTRFIL=0 and PRTFLG clear.
; ----------------------------------------------------------------------
STMT_WIDTH_1:
        CP $2C
        ; leading ',': width omitted, set only the trailing page-length field
        JR Z,WIDTH_SET_CONSOLE_1
        CALL GETBYT
; [RE] WIDTH continuation: parse 'WIDTH #file,width' branch - stores file-width to $083B/$083D, then handles optional ',pos' second field.
WIDTH_SET_CONSOLE:
        LD (PRINT_WIDTH),A
        LD E,A
        CALL WIDTH_CLAMP_COLUMN
        LD (WIDTH_FILE),A
        LD A,(HL)
        CP $2C
        RET NZ
WIDTH_SET_CONSOLE_1:
        CALL CHRGET
        CALL GETBYT
        LD (PAGE_LENGTH),A
        RET
; [RE] WIDTH helper: fold the requested column count into the valid 1..n range by repeated SUB $0E, then bias by E (original value); returns the clamped width byte.
WIDTH_CLAMP_COLUMN:
        SUB $0E
        JR NC,WIDTH_CLAMP_COLUMN
        ADD A,$1C
        CPL
        INC A
        ADD A,E
        RET
; ----------------------------------------------------------------------
; GETINT_CHRGET -- skip one text char, then evaluate the next expression as a signed 16-bit integer.
;   In:        HL -> a leading character in the program text that is to be discarded (a separator the
;              caller already matched, e.g. '(' or ','); the CHRGET/text cursor follows HL.
;   Out:       DE = signed 16-bit value of the expression; A = high byte (= D); Z set when the value fits in
;              one unsigned byte (high byte 0); HL advanced past the expression. (Falls into GETINT.)
;   Clobbers:  A, BC, DE, HL, flags, the FAC (whole floating-point evaluator state).
;   Algorithm: The GETINT entry used when one text character must be eaten first. CHRGET advances the text
;              pointer one position and fetches the following token, then control falls into GETINT to
;              evaluate the operand. Used by statement parsers that have just consumed a delimiter.
; ----------------------------------------------------------------------
GETINT_CHRGET:
        ; eat the leading separator char, then drop into GETINT to evaluate the operand
        CALL CHRGET
; ----------------------------------------------------------------------
; GETINT -- evaluate the expression at the text pointer and return it as a signed 16-bit integer.
;   In:        HL -> first character/token of a numeric expression in the program text.
;   Out:       DE = signed 16-bit value (-32768..32767); A = high byte (= D); Z set when the value fits in
;              a single unsigned byte (high byte 0); HL advanced past the expression.
;   Clobbers:  A, BC, DE, HL, flags, the FAC.
;   Algorithm: Run the full expression evaluator (FRMEVL_NOPAREN backs HL up one and parses at lowest
;              precedence) to leave the result in the FAC, then fall into FRC_INT_DE, which narrows the FAC
;              to a signed 16-bit integer in DE. The general signed-integer operand reader behind POKE/PEEK
;              addresses, array bounds, coordinate parsers, etc.
; ----------------------------------------------------------------------
GETINT:
        ; evaluate the numeric expression into the FAC, then narrow it in FRC_INT_DE
        CALL FRMEVL_NOPAREN
; ----------------------------------------------------------------------
; FRC_INT_DE -- coerce the current FAC value to a signed 16-bit integer in DE; flag byte-fit.
;   In:        FAC holds an evaluated numeric value (any type); VALTYP ($0B14) describes it.
;   Out:       DE = signed 16-bit integer form of the value; A = D (high byte); flags from OR A, so Z is set
;              iff the high byte is 0 (the value fits in an unsigned byte). HL is preserved.
;   Clobbers:  A, BC, DE, flags. HL saved and restored. The FAC is overwritten by the conversion.
;   Algorithm: Save HL, call FN_CINT (the FAC -> signed-16-bit converter: rounds singles/doubles by adding
;              0.5, range-checks the exponent at $0CB4, and raises Type mismatch on a string / Overflow when
;              magnitude >= 2^16). FN_CINT returns the integer in HL, so EX DE,HL moves it to DE; restore HL,
;              then test the high byte (LD A,D / OR A) to report byte-fit in Z. This is the shared narrowing
;              tail for GETINT and the byte reader GETBYT/CONINT.
;   NOTE [RE]: the stale single-line comment above this label names the converter 'FN_LPOS' -- that is wrong.
;              FN_LPOS ($3E29) is the LPOS(x) printer-column function handler; the routine the CODE actually
;              CALLs here is FN_CINT ($4F76). (The code is correct; only the comment text is stale.)
; ----------------------------------------------------------------------
FRC_INT_DE:
        PUSH HL
        ; FAC -> signed 16-bit integer in HL (rounds and range-checks; raises Type mismatch / Overflow)
        CALL FN_CINT
        EX DE,HL
        POP HL
        ; test the high byte: Z on return means the value fits in a single unsigned byte
        LD A,D
        OR A
        RET
; ----------------------------------------------------------------------
; GETBYT_CHRGET -- skip one text char, then evaluate the next expression as a 0..255 byte.
;   In:        HL -> a leading character to discard (a delimiter the caller already matched); the CHRGET
;              text cursor follows HL.
;   Out:       A = E = the byte value (0..255); D = 0; HL re-positioned on the operand-terminating char.
;              Raises 'Illegal function call' (ERROR_FC) if the value does not fit in a byte.
;   Clobbers:  A, BC, DE, HL, flags, the FAC.
;   Algorithm: The GETBYT entry that must eat one text character first: CHRGET advances past the delimiter,
;              then falls into GETBYT. Used by parsers that have just consumed a separator before a byte arg.
; ----------------------------------------------------------------------
GETBYT_CHRGET:
        CALL CHRGET
; ----------------------------------------------------------------------
; GETBYT -- evaluate the expression at the text pointer and return it as a 0..255 byte.
;   In:        HL -> first character/token of a numeric expression in the program text.
;   Out:       A = E = byte value (0..255); D = 0; HL re-positioned on the operand-terminating char. Range
;              error raises 'Illegal function call' (ERROR_FC).
;   Clobbers:  A, BC, DE, HL, flags, the FAC.
;   Algorithm: Run the expression evaluator (FRMEVL_NOPAREN) to leave the value in the FAC, then fall into
;              CONINT, which narrows to an integer (FRC_INT_DE) and enforces the 0..255 range. The general
;              byte-operand reader used by POKE data, WIDTH, color/coordinate bytes, port masks, etc.
; ----------------------------------------------------------------------
GETBYT:
        CALL FRMEVL_NOPAREN
; ----------------------------------------------------------------------
; CONINT -- narrow the current FAC value to a single byte (0..255), raising FC on overflow.
;   In:        FAC holds an evaluated numeric value; the text cursor is just past the expression.
;   Out:       A = E = byte value (0..255); D = 0 (FRC_INT_DE confirmed the high byte is 0). HL has been
;              stepped back one and re-CHRGOT'd (net HL unchanged), so it sits on the operand-terminating
;              char with CHRGOT's classification flags refreshed. The final LD A,E sets A = the byte value
;              (the token transiently loaded by the CHRGET re-read is overwritten).
;   Clobbers:  A, BC, DE, HL, flags, the FAC.
;   Algorithm: Call FRC_INT_DE to coerce the FAC to a 16-bit integer in DE and set Z iff it fits in a byte;
;              if NZ (high byte nonzero, i.e. value < 0 or > 255) jump to ERROR_FC ('Illegal function call').
;              Otherwise DEC HL then CHRGET (= INC HL + CHRGOT) re-reads the current char so CHRGOT state is
;              valid for the caller, then return the byte in A (= E).
;   NOTE [RE]: the stale comment above this label routes the FC branch via 'GETINT_POSITIVE_1'; the actual
;              target of the JP NZ in the code is ERROR_FC (an equivalent FC raise, but a different label).
; ----------------------------------------------------------------------
CONINT:
        CALL FRC_INT_DE
        ; value does not fit in a byte (high byte nonzero) -> Illegal function call
        JP NZ,ERROR_FC
        ; back up one then CHRGET to re-read the current char (refresh CHRGOT state; net HL unchanged)
        DEC HL
        CALL CHRGET
        LD A,E
        RET
; ----------------------------------------------------------------------
; STMT_LLIST -- LLIST statement handler (keyword token $9C): list program to the printer.
;   In:        HL -> program text just past the LLIST token (an optional line range may follow). Top of stack = the statement dispatcher's return address.
;   Out:       Falls straight into STMT_LIST; never returns here.
;   Clobbers:  A, PRTFLG.
;   Algorithm: Sets PRTFLG=1 so OUTCHR routes every emitted character to the printer device, then drops into the shared LIST engine (STMT_LIST). LLIST and LIST are the same code; only the output-channel flag differs.
; ----------------------------------------------------------------------
STMT_LLIST:
        ; select printer output: OUTCHR sends listing characters to the printer when PRTFLG is nonzero
        LD A,$01
        LD (PRTFLG),A
; ----------------------------------------------------------------------
; STMT_LIST -- LIST statement handler (keyword token $93): detokenize and print program lines.
;   In:        HL -> text after the LIST token; an optional 'start[-end]' line range may follow. Top of stack = statement-dispatcher return address. PRTFLG/PTRFIL select the output channel (console / printer / open file).
;   Out:       Does not return to the caller: when the listed range is exhausted it jumps to the READY prompt (NEWSTT_READY / READY_POP_FRAME).
;   Clobbers:  AF, BC, DE, HL, SAVTXT, ERRLIN; stack rebalanced.
;   Algorithm: Discards the dispatcher's return address (LIST ends at the prompt, not back at NEWSTT), parses the optional line range with SCAN_LINE_RANGE -- which leaves BC pointing at the first BASLINE node at/after the start line (via FNDLIN) and pushes the end-bound line number. Re-pushes that node pointer, then rejects listing a protected program (ILLEGAL_DIRECT_CHECK raises ERROR_FC when the load-protect flag is set). Also reached by SAVE ",A" (ASCII save) via JP STMT_LIST with file #0 open in PTRFIL, so the same engine writes the detokenized program as text to the file.
; ----------------------------------------------------------------------
STMT_LIST:
        ; discard the dispatcher's return address: LIST (and ASCII SAVE) exit at the READY prompt, never back to the dispatcher (BC is reloaded by SCAN_LINE_RANGE below)
        POP BC
        ; parse optional 'start[-end]'; returns BC -> first BASLINE node at/after 'start' and pushes the 'end' line number
        CALL SCAN_LINE_RANGE
        PUSH BC
        ; refuse to list a load-protected program: ILLEGAL_DIRECT_CHECK raises ERROR_FC ('Illegal function call') when the protect flag (LOAD_PROTECT_FLAG) is nonzero
        CALL ILLEGAL_DIRECT_CHECK
; ----------------------------------------------------------------------
; STMT_LIST_NEXT_NODE -- LIST main loop head: fetch the next program line node and test for end-of-program.
;   In:        On the stack (top..): current BASLINE node pointer, then the end-bound line number. (First arrival: pushed by STMT_LIST; later arrivals: re-looped from STMT_LIST_BODY with the next-node pointer on top.)
;   Out:       HL -> the node's BASLINE.LINENUM field (node+2), DE = end-bound line number, BC = this node's BASLINE.LINK (pointer to the next node). Falls into STMT_LIST_EMIT_LINE. On a $0000 link (past the last line) jumps to NEWSTT_READY.
;   Clobbers:  AF, BC, DE, HL, SAVTXT.
;   Algorithm: Stores SAVTXT=$FFFF (the direct-mode sentinel; [RE] this is the standard MS BASIC-80 marker so a CONT after a LIST is rejected), pops the saved node pointer and end-bound, then reads the node's forward link (BASLINE.LINK). A null link ends the program -> return to the READY prompt. Otherwise tests PTRFIL to set Z (Z set when PTRFIL==0, i.e. console / no file open) so STMT_LIST_EMIT_LINE polls the console for a Ctrl-C/Ctrl-S break only when output is the console.
; ----------------------------------------------------------------------
STMT_LIST_NEXT_NODE:
        ; [RE] mark direct mode: SAVTXT=$FFFF, the MS BASIC sentinel so a CONT after a LIST is refused (the routine only writes the cell here; the CONT effect is downstream)
        LD HL,$FFFF
        LD (SAVTXT),HL
        POP HL
        POP DE
        ; read this node's BASLINE.LINK (pointer to the next line); HL then advances to the BASLINE.LINENUM field
        LD C,(HL)
        INC HL
        LD B,(HL)
        INC HL
        LD A,B
        OR C
        ; null forward link = end of program: listing complete, return to the READY prompt
        JP Z,NEWSTT_READY
        PUSH HL
        ; console vs file: Z set here (PTRFIL==0) gates the break-poll below, so ASCII SAVE-to-file (PTRFIL!=0) skips it
        LD HL,(PTRFIL)
        LD A,H
        OR L
        POP HL
; ----------------------------------------------------------------------
; STMT_LIST_EMIT_LINE -- emit one program line: range-test, print the line number, then prepare to detokenize.
;   In:        HL -> the current node's BASLINE.LINENUM field (node+2), BC = next-node link, DE = end-bound line number, Z = console-output flag (from the PTRFIL test in STMT_LIST_NEXT_NODE).
;   Out:       Falls into STMT_LIST_BODY with HL -> the line's token bytes. When the line number exceeds the end bound, jumps to READY_POP_FRAME (listing done).
;   Clobbers:  AF, BC, DE, HL, ERRLIN; stack used for scratch.
;   Algorithm: When listing to the console it first polls for a pending Ctrl-S pause / Ctrl-C break (RPC_CONST_POLL). It reads the node's BASLINE.LINENUM and compares it against the end bound (CMP_HL_DE computes end - linenum; carry => linenum past the end); once past the end, listing stops. Otherwise it records the line number in ERRLIN (so a break is reported against this line), prints it with FOUT, then peeks the first body byte: a leading TAB character ($09) suppresses the usual separating space, otherwise a space is emitted between the number and the line body.
; ----------------------------------------------------------------------
STMT_LIST_EMIT_LINE:
        ; console only: poll the console for a Ctrl-C break / Ctrl-S pause between lines (skipped when output is a file)
        CALL Z,RPC_CONST_POLL
        PUSH BC
        LD C,(HL)
        INC HL
        LD B,(HL)
        INC HL
        PUSH BC
        EX (SP),HL
        EX DE,HL
        ; compare this line's number (DE) against the end bound (HL); carry set when the line number is past the end
        CALL CMP_HL_DE
        POP BC
        ; line number is beyond the requested end: listing finished, return to READY
        JP C,READY_POP_FRAME
        EX (SP),HL
        PUSH HL
        PUSH BC
        EX DE,HL
        ; remember the line being listed so a Ctrl-C break reports the correct line number
        LD (ERRLIN),HL
        ; print the line number (FOUT stores HL into the FAC as an integer, then formats it to ASCII on the output channel)
        CALL FOUT
        POP HL
        LD A,(HL)
        ; if the line body starts with a literal TAB character ($09), skip the separating space so column alignment is preserved
        CP $09
        JR Z,STMT_LIST_BODY
        LD A,$20
        CALL OUTCHR
; ----------------------------------------------------------------------
; STMT_LIST_BODY -- detokenize the current line into BUF, print it, and advance to the next line.
;   In:        HL -> the current line's crunched token bytes; output channel selected by PRTFLG/PTRFIL. Stack holds (top..) the next-node pointer then the end-bound line number.
;   Out:       Loops back to STMT_LIST_NEXT_NODE for the next line (the next-node pointer and end-bound were preserved on the stack).
;   Clobbers:  AF, BC, DE, HL, BUF.
;   Algorithm: Calls DETOKENIZE_LINE to expand the crunched tokens back into ASCII in the line buffer BUF ($0A0E), writes that $00-terminated text with PRINT_ZSTRING, emits a CRLF, then re-enters the loop to list the following line.
; ----------------------------------------------------------------------
STMT_LIST_BODY:
        ; expand the crunched tokens of this line into ASCII text in BUF
        CALL DETOKENIZE_LINE
        LD HL,BUF
        ; write the detokenized line (the $00-terminated text in BUF) to the output channel
        CALL PRINT_ZSTRING
        CALL CRLF
        ; advance to the next program line (its pointer is still on the stack)
        JR STMT_LIST_NEXT_NODE
; ----------------------------------------------------------------------
; PRINT_ZSTRING -- write a $00-terminated string to the selected output channel.
;   In:        HL -> a NUL-terminated byte string (e.g. the detokenized line in BUF). PRTFLG/PTRFIL select console / printer / file.
;   Out:       HL -> the terminating $00; the string has been emitted. (Empty string returns immediately.)
;   Clobbers:  AF, HL; OUTCHR may also clobber BC/DE on the file/printer output path.
;   Algorithm: Loops over the bytes at HL, sending each through OUTCHR_LF_EXPAND (which routes to the active channel and turns a bare LF into CR+LF), stopping at the $00 terminator. General string writer shared by LIST/LLIST/ASCII-SAVE line output and by the line editor (EDIT redisplay, Ctrl-R retype).
; ----------------------------------------------------------------------
PRINT_ZSTRING:
        LD A,(HL)
        OR A
        ; stop at the $00 terminator (also returns immediately on an empty string)
        RET Z
        ; emit one character on the active channel, expanding a lone LF to CR+LF
        CALL OUTCHR_LF_EXPAND
        INC HL
        JR PRINT_ZSTRING

; ======================================================================
; LIST / DETOKENIZER (uncrunch token -> ASCII)
; ======================================================================
; ----------------------------------------------------------------------
; DETOKENIZE_LINE -- expand one crunched BASIC line back to ASCII text in BUF (the LIST de-tokenizer).
;   In:        HL -> the crunched line body (the bytes after the line's LINK+line-number header). The stream is: printable literal bytes ($20-$7F), control literals ($01-$0A), embedded-constant tokens ($0B-$1F = token byte followed by an inline binary value in the stream), reserved-word tokens ($80-$FF, high bit set), and a $00 line terminator.
;   Out:       BUF ($0A0E) holds the NUL-terminated ASCII spelling of the line; HL advanced to the line's $00 terminator. Returns when the $00 byte is reached or the output-length guard (D) is exhausted.
;   Clobbers:  A,BC,D,E,HL; output cursor BC walks across BUF; the inter-token spacing state cell L_0C93 is reset to 0.
;   Algorithm: Set the output cursor BC=BUF, the remaining-length guard D=$FF, clear the spacing-state flag L_0C93, then run ILLEGAL_DIRECT_CHECK. [RE] That guard raises 'Illegal function call' (ERROR_FC) when LOAD_PROTECT_FLAG (LOAD_PROTECT_FLAG, set to $FE when a $FE-protected program was LOADed) is NONZERO -- i.e. it refuses to LIST a protection-loaded program. ILLEGAL_DIRECT_CHECK is a benign subroutine call here (it preserves AF/HL/BC/DE and returns), not the warm-start fall-through that shares its area. Then fall into the per-byte main loop at DETOKENIZE_LINE_2.
; ----------------------------------------------------------------------
DETOKENIZE_LINE:
        ; BC = output cursor into the LIST text buffer (BUF $0A0E)
        LD BC,BUF
        ; D = remaining-length guard; DEC D / RET Z later stops a runaway expansion
        LD D,$FF
        XOR A
        ; clear the inter-token spacing state (no pending word boundary)
        LD (L_0C93),A
        ; [RE] refuse to LIST a protection-loaded program (LOAD_PROTECT_FLAG nonzero -> ERROR_FC)
        CALL ILLEGAL_DIRECT_CHECK
        JR DETOKENIZE_LINE_2
; ----------------------------------------------------------------------
; DETOKENIZE_LINE_1 -- advance to the next source byte after emitting one output byte, then re-enter the main loop.
;   In:        BC = output cursor (just-written byte), HL -> source byte just consumed, D = remaining-length guard.
;   Out:       BC and HL each incremented; D decremented; on D reaching zero RET (output guard exhausted); otherwise falls into DETOKENIZE_LINE_2 for the next source byte.
;   Clobbers:  BC,HL,D,flags.
;   Algorithm: Per-iteration step: bump the output cursor and source pointer, decrement the length guard, and abort the whole expansion if the guard reached zero.
; ----------------------------------------------------------------------
DETOKENIZE_LINE_1:
        INC BC
        INC HL
        DEC D
        ; abort if the output-length guard is exhausted
        RET Z
; ----------------------------------------------------------------------
; DETOKENIZE_LINE_2 -- main-loop head: fetch the next crunched byte and classify it as line-end, control literal, embedded constant, or reserved-word/printable.
;   In:        HL -> next crunched byte, BC = output cursor, D = length guard, L_0C93 = spacing state.
;   Out:       Dispatches by value: $00 stores the NUL terminator and RETs (line done); $01-$0A control literals go to DETOKENIZE_LINE_3; $0B-$1F embedded-constant tokens (saved in E) go to DETOKENIZE_LINE_4; $20-$FF fall through to DETOKENIZE_LINE_3 (which splits high-bit reserved-word tokens from printable literals).
;   Clobbers:  A,E,flags; provisionally writes (BC).
;   Algorithm: Read (HL) and OR A to test for $00, then store it to (BC) BEFORE the RET Z so the $00 terminator lands in BUF for free. CP $0B routes $01-$0A to _3; CP $20 (with E preloaded = byte) routes $0B-$1F to _4; $20-$FF falls into _3.
; ----------------------------------------------------------------------
DETOKENIZE_LINE_2:
        LD A,(HL)
        OR A
        ; stage the byte into BUF before the terminator test (drops the $00 terminator for free)
        LD (BC),A
        ; $00 ends the crunched line -> BUF is now NUL-terminated, done
        RET Z
        CP $0B
        ; control literals $01-$0A -> classify/emit via _3
        JR C,DETOKENIZE_LINE_3
        CP $20
        LD E,A
        ; embedded-constant tokens $0B-$1F (E=token) -> space-aware constant path
        JR C,DETOKENIZE_LINE_4
; ----------------------------------------------------------------------
; DETOKENIZE_LINE_3 -- classify a control literal ($01-$0A) or a >= $20 byte into reserved-word token, identifier/'.'/number-start, or plain punctuation.
;   In:        A = current byte ($01-$0A control, or $20-$FF), HL -> that byte, BC/D/L_0C93 as in the loop.
;   Out:       High-bit bytes ($80-$FF, reserved-word tokens) jump to DETOKENIZE_LINE_8 (keyword expander). '.' ($2E) and alphanumeric characters take the spacing-aware path DETOKENIZE_LINE_4 with E=byte. All other bytes set A=0 and fall to DETOKENIZE_LINE_6, which commits spacing-state 0 (no separating space) before emitting.
;   Clobbers:  A,E,flags.
;   Algorithm: OR A then JP M routes high-bit reserved-word tokens to the table-driven expander. For the rest, reload E=byte and treat '.' and any letter/digit (IS_ALNUM_CHAR returns NC) as a word-forming character that wants inter-token spacing; everything else (operators, separators, quotes, control chars) is non-spacing (A=0) and emitted directly.
; ----------------------------------------------------------------------
DETOKENIZE_LINE_3:
        OR A
        ; high bit set: reserved-word token -> expand its spelling from the keyword table (_8)
        JP M,DETOKENIZE_LINE_8
        LD E,A
        ; [RE] '.' can begin a numeric literal -> treat as a spacing-relevant word char
        CP $2E
        JR Z,DETOKENIZE_LINE_4
        ; letters/digits return NC (word-forming) -> spacing path; other bytes return C
        CALL IS_ALNUM_CHAR
        JP NC,DETOKENIZE_LINE_4
        ; non-word byte: spacing state := 0 (no word boundary), emit via _6
        XOR A
        JR DETOKENIZE_LINE_6
; ----------------------------------------------------------------------
; DETOKENIZE_LINE_4 -- emit the optional separating space before a word-forming item (identifier char, '.', digit, or embedded constant).
;   In:        E = the byte/token to emit next, L_0C93 = spacing state (0 = none pending, $01 = previous emission was a literal word/number, $FF = previous emission was a reserved word), BC/D = output cursor and guard.
;   Out:       If the previous emission was a reserved word (state $FF), a single space is written to BUF first (and the guard decremented, RET on exhaustion). Then falls into DETOKENIZE_LINE_5, which sets the state to $01 (this emission is a literal word) and proceeds to store the byte.
;   Clobbers:  A,BC,D,flags; may write one space to (BC).
;   Algorithm: Inter-token spacing state machine, literal side. A separating space is inserted only at a keyword->word boundary. State 0 (fresh / after punctuation) and state $01 (after another literal word) need no space; INC A turns ONLY the $FF case to zero, so only 'just emitted a reserved word' inserts a space (so 'GOTO100' lists as 'GOTO 100', 'PRINTX' as 'PRINT X').
; ----------------------------------------------------------------------
DETOKENIZE_LINE_4:
        LD A,(L_0C93)
        OR A
        ; spacing state 0: nothing pending, no space needed
        JR Z,DETOKENIZE_LINE_5
        ; INC A makes only state $FF (after a keyword) become zero -> select the space case
        INC A
        ; state $01 (after a literal word): adjacent words, no space
        JR NZ,DETOKENIZE_LINE_5
        ; keyword->word boundary: insert one separating space
        LD A,$20
        LD (BC),A
        INC BC
        DEC D
        ; stop if emitting the space exhausted the output guard
        RET Z
; ----------------------------------------------------------------------
; DETOKENIZE_LINE_5 -- mark the spacing state as 'just emitted a literal word/number' ahead of storing this byte.
;   In:        (entered after the leading-space decision) E = byte to emit.
;   Out:       A = $01; falls into DETOKENIZE_LINE_6, which commits the state and dispatches the byte for output.
;   Clobbers:  A.
;   Algorithm: Set the spacing-state value to $01 (literal-word side) so that, if the NEXT item is a reserved word, the keyword path will insert a separating space.
; ----------------------------------------------------------------------
DETOKENIZE_LINE_5:
        LD A,$01
; ----------------------------------------------------------------------
; DETOKENIZE_LINE_6 -- commit the new spacing state, then route the byte in E to a literal store or to the embedded-constant formatter.
;   In:        A = new spacing-state value (0 from the non-word path in _3, $01 from _5), E = byte/token to emit.
;   Out:       L_0C93 updated. Control bytes $01-$0A and printable $20-$FF are stored as-is via DETOKENIZE_LINE_7. Embedded-constant tokens $0B-$1F hand off to CONST_FMT_BEGIN, the numeric/line-number constant formatter, which renders the inline binary value back to ASCII (and advances HL past it).
;   Clobbers:  A,flags.
;   Algorithm: Write the pending spacing state, reload the byte from E, and split on value: a control ($01-$0A) or printable ($20-$FF) literal is emitted verbatim via _7; a $0B-$1F constant token is not a literal char but a marker for an inline binary numeric value, so it is dispatched to the constant formatter.
; ----------------------------------------------------------------------
DETOKENIZE_LINE_6:
        ; commit the inter-token spacing state for the next iteration
        LD (L_0C93),A
        LD A,E
        CP $0B
        ; $01-$0A control byte: store as a literal
        JR C,DETOKENIZE_LINE_7
        CP $20
        ; $0B-$1F: embedded numeric/line-number constant -> reformat its inline binary value to ASCII
        JP C,CONST_FMT_BEGIN
; ----------------------------------------------------------------------
; DETOKENIZE_LINE_7 -- store one literal byte to BUF and loop.
;   In:        A = literal byte to emit (a $20-$FF printable, or a $01-$0A control), BC = output cursor.
;   Out:       The byte is written at (BC); control returns to DETOKENIZE_LINE_1 to advance both pointers and continue.
;   Clobbers:  writes (BC); the pointer/guard advance happens in DETOKENIZE_LINE_1.
;   Algorithm: Plain copy of a non-token source byte into the output buffer.
; ----------------------------------------------------------------------
DETOKENIZE_LINE_7:
        ; copy the literal byte into BUF
        LD (BC),A
        JR DETOKENIZE_LINE_1
; ----------------------------------------------------------------------
; DETOKENIZE_LINE_8 -- normalize a high-bit reserved-word/function token to its 1-byte code
;   In:        A = the program byte just fetched, with bit 7 set (a token); reached via the caller's `JP M,DETOKENIZE_LINE_8` for ANY token byte (not specifically $FF). HL -> that token byte in the crunched line. BC = output cursor, D = remaining output length.
;   Out:       A = the resolved 1-byte token code. For a one-byte keyword token A is just the byte itself. For the two-byte function form ($FF escape + code) A = (next byte) AND $7F, i.e. the small function-token code (e.g. SIN=$09, CHR$=$15). HL advanced one byte past the $FF prefix only when the prefix was consumed.
;   Clobbers:  A, HL.
;   Algorithm: `INC A` sets Z iff A was $FF, the single escape prefix MS BASIC uses for the small function tokens (those are stored as $FF followed by (code | $80)). Then reload A from (HL). If A was not the prefix (NZ), A now holds the one-byte token; continue. If it was the prefix (Z), step HL to the second byte, read it, and mask with $7F to recover the true (small) function-token code. There is NO $FE prefix. Falls through to _9.
; ----------------------------------------------------------------------
DETOKENIZE_LINE_8:
        ; is this the $FF two-byte-function escape prefix? (sets Z iff A==$FF)
        INC A
        LD A,(HL)
        ; one-byte keyword token: A=(HL) already holds it, no escape prefix
        JR NZ,DETOKENIZE_LINE_9
        ; $FF prefix: the real (small) function-token code is in the next byte
        INC HL
        LD A,(HL)
        ; strip the high bit to recover the true function-token code (e.g. $09=SIN)
        AND $7F
; ----------------------------------------------------------------------
; DETOKENIZE_LINE_9 -- advance past the token byte and undo the cruncher's ':'+REM wrapper for the apostrophe comment
;   In:        A = resolved token code (from _8); HL -> the token byte in the crunched line; BC = output cursor; D = remaining output length.
;   Out:       HL advanced one byte past the token. For the apostrophe-comment token ($EA = TOK_REM_QUOTE): BC moved back 4 and D incremented 4 (overwriting the ':REM' already emitted). For all other tokens BC/D unchanged. A preserved.
;   Algorithm: Step HL past the consumed token. The cruncher stores a `'` source comment as three crunched bytes ':' + $8F (the REM token, TOK_REM) + $EA, followed by the comment text (verified in CRUNCH_STORE_FLAG_AND_EMIT). De-tokenizing the leading ':' and $8F has already written the 4 ASCII chars ':REM' to the output; to LIST a bare `'` instead, rewind the output cursor by 4 (DEC BC x4) and return 4 units of remaining length (INC D x4), then let the keyword lookup that follows emit the $EA spelling (a single `'`). Falls through to _10.
; ----------------------------------------------------------------------
DETOKENIZE_LINE_9:
        INC HL
        ; apostrophe-comment token? (cruncher emitted it as ':' + REM-token $8F + $EA)
        CP $EA
        JR NZ,DETOKENIZE_LINE_10
        ; back up over the 4 chars ':REM' already written, so the comment LISTs as a bare apostrophe
        DEC BC
        DEC BC
        DEC BC
        DEC BC
        ; give back those 4 units of remaining output length
        INC D
        INC D
        INC D
        INC D
; ----------------------------------------------------------------------
; DETOKENIZE_LINE_10 -- suppress ELSE's stored leading ':', then set up the reserved-word name-table walk
;   In:        A = resolved token code; HL -> next crunched byte; BC = output cursor; D = remaining output length.
;   Out:       HL/BC/DE pushed (restored in _14). HL = RESWORD_INDEX+51 (last byte of the 52-byte index, so _12's first INC HL lands on KWGRP_A's first spelling byte). B = target token to find. C = $40 (per-group letter accumulator, bumped to $41='A' by _11 before the first group).
;   Clobbers:  A (via the conditional CALL only), B, C, HL; pushes HL/BC/DE.
;   Algorithm: ELSE is stored crunched as ':' + $9E; the ':' has already been emitted as a literal, so on the ELSE token CALL DEC_BC backs the output cursor over that ':' so ELSE LISTs without its leading colon. Then save the live state and prime the walk: RESWORD_INDEX is a 26-entry (52-byte) word array of per-letter group pointers, so RESWORD_INDEX+51 is its final byte and the walk's first INC HL (_12) steps onto KWGRP_A's first byte. C=$40 is the implied-leading-letter accumulator that _11 bumps once per group ($41='A' ... $5A='Z', then $5B for the operator group RESWORD_OPS that follows KWGRP_Z). Falls through to _11.
; ----------------------------------------------------------------------
DETOKENIZE_LINE_10:
        CP TOK_ELSE
        ; ELSE: back the output cursor over the stored leading ':' so ELSE lists without it
        CALL Z,DEC_BC
        ; save program ptr / output cursor / length across the table walk (restored in _14)
        PUSH HL
        PUSH BC
        PUSH DE
        ; last byte of the 26-word index: _12's first INC HL lands on KWGRP_A
        LD HL,RESWORD_INDEX+51
        LD B,A
        ; implied-leading-letter accumulator: _11 bumps it to 'A'=$41 then once per group
        LD C,$40
; ----------------------------------------------------------------------
; DETOKENIZE_LINE_11 -- advance to the next keyword group (bump the implied-leading-letter accumulator)
;   In:        C = current group-letter accumulator; reached from _10 setup (C=$40) or from _13 when a $00 group terminator was hit.
;   Out:       C incremented = ASCII letter of the next group ('A'=$41 ... 'Z'=$5A, then $5B for the operator group RESWORD_OPS after KWGRP_Z).
;   Clobbers:  C.
;   Algorithm: Each KWGRP_* block ends with a $00 byte (KWGRP_Y/KWGRP_Z are bare $00). Crossing one means the following entries belong to the next letter group, so increment C. After KWGRP_Z's $00 the walk continues into RESWORD_OPS with C=$5B (the operator group has no implied leading letter). Falls through to _12.
; ----------------------------------------------------------------------
DETOKENIZE_LINE_11:
        ; crossed a $00 group terminator: advance the implied leading letter (A,B,C,... then $5B=operators)
        INC C
; ----------------------------------------------------------------------
; DETOKENIZE_LINE_12 -- position at the start of the next keyword entry and snapshot it
;   In:        HL -> the byte just before this entry's first spelling char (the previous $00 terminator on group entry, or the token byte of the previous non-matching entry).
;   Out:       HL -> first spelling char of the current entry; DE = a copy of HL (saved entry-start, used by _13's EX DE,HL after the token byte is read).
;   Clobbers:  HL, D, E.
;   Algorithm: INC HL onto this entry's first spelling char, then snapshot the pointer into DE (LD D,H / LD E,L) so _13 can EX back to the entry start once the trailing token byte is compared. Falls through to _13.
; ----------------------------------------------------------------------
DETOKENIZE_LINE_12:
        INC HL
        ; remember this entry's spelling start so _13 can return to it after reading its token byte
        LD D,H
        LD E,L
; ----------------------------------------------------------------------
; DETOKENIZE_LINE_13 -- scan one keyword entry's tail spelling and test its token against the target
;   In:        HL -> current spelling byte; DE = start of this entry (from _12); B = target token; C = group-letter accumulator.
;   Out:       On match: HL = entry's spelling start (after EX DE,HL); A = matched token; Z flag set iff the matched token is USR ($E1, via JR Z) or FN ($E2, via the trailing CP TOK_FN), else Z clear -- this discriminator survives to _14. Falls into _14. On a $00 group end -> _11 (next group). On a non-matching entry -> _12 (next entry).
;   Clobbers:  A, HL.
;   Algorithm: Read the spelling byte; $00 = group ended with no match -> _11. Otherwise INC HL and, while the byte has bit 7 clear (JP P), keep consuming spelling chars; the high-bit-set byte is the last spelling char and the very next byte is the entry's token code. Compare it to B (the resolved target): mismatch -> _12. On match, EX DE,HL restores HL to the saved entry start (for the _15.._19 emit), then CP $E1 / CP TOK_FN classifies the matched token specifically as USR or FN (the only two single-byte tokens that need the no-trailing-space treatment), leaving the Z discriminator for _14. Note SIN/CHR$/etc. carry small function codes, not $E1/$E2, so they are treated as ordinary keywords.
; ----------------------------------------------------------------------
DETOKENIZE_LINE_13:
        LD A,(HL)
        OR A
        ; $00: this letter group ended with no match -> advance to the next group
        JR Z,DETOKENIZE_LINE_11
        INC HL
        ; bit 7 clear -> ordinary spelling char; scan on to the high-bit-set final char
        JP P,DETOKENIZE_LINE_13
        LD A,(HL)
        ; the byte after the last spelling char is this entry's token: is it the target?
        CP B
        ; wrong keyword: try the next entry
        JR NZ,DETOKENIZE_LINE_12
        ; matched: point HL back at this entry's spelling for the emit stage
        EX DE,HL
        ; classify USR ($E1) / FN ($E2): only these set the no-trailing-space flag in _14
        CP $E1
        JR Z,DETOKENIZE_LINE_14
        CP TOK_FN
; ----------------------------------------------------------------------
; DETOKENIZE_LINE_14 -- finish the match: recover the implied leading letter, set the next-token spacing flag, pick the emit path
;   In:        C = group-letter accumulator (ASCII leading letter of the matched group, or $5B for operators); HL = matched entry's spelling start; Z flag = USR/FN discriminator from _13. Saved BC(out cursor)/DE(length) on the stack from _10.
;   Out:       DE/BC restored to the output cursor and remaining length; E = the implied leading letter (= C). USR/FN path (Z set in _13): stores L_0C93 = $00 (so the FOLLOWING token, e.g. '(' or the FN name, gets no preceding space) and continues at _17. Ordinary-keyword path (NZ): continues at _15, which for non-operator groups stores L_0C93 = $FF (so the NEXT token is preceded by a space). In BOTH paths the leading-space decision for THIS token is made at _17 from the OLD L_0C93 value.
;   Clobbers:  A, E; restores DE, BC; updates L_0C93.
;   Algorithm: Move the group letter into A and E (E carries the first character the table omits, since group membership encodes it). Restore the saved output cursor/length. JR NZ,_15 routes ordinary keywords to the _15/_16 logic. For USR/FN (fall-through), `LD A,(L_0C93) / OR A` reads the OLD spacing flag and sets Z (this Z is NOT discarded -- LD A,$00 / LD (L_0C93),A / JR _17 leave flags untouched, so _17's `JR Z,_18` uses it to decide the leading space). Then store L_0C93 = $00 as the new flag (no space before the next token) and jump to _17. So USR/FN suppress the space AFTER themselves, not before.
; ----------------------------------------------------------------------
DETOKENIZE_LINE_14:
        ; the implied leading letter (the table stores only the tail) -> goes into E for the emit stage
        LD A,C
        POP DE
        POP BC
        LD E,A
        ; ordinary keyword -> _15/_16; fall through only for USR/FN
        JR NZ,DETOKENIZE_LINE_15
        ; read the OLD spacing flag: its Z survives to _17 to decide this token's leading space
        LD A,(L_0C93)
        OR A
        ; USR/FN: new flag $00 so the FOLLOWING token (e.g. '(' or FN name) abuts with no space
        LD A,$00
        LD (L_0C93),A
        JR DETOKENIZE_LINE_17
; ----------------------------------------------------------------------
; DETOKENIZE_LINE_15 -- keyword emit: pick leading-space behaviour for a non-USR/non-FN token
;   In:        A = E = the group/sequence code C of the matched reserved word. C = $41..$5A is the keyword's implied first letter 'A'..'Z'; C = $5B means the entry lives in the post-Z operator group RESWORD_OPS (i.e. '+ - * / ^ \ '' > = <'). HL -> first stored char of the matched word in the name table. BC -> next free BUF byte. D = remaining BUF length. L_0C93 = current inter-token spacing state.
;   Out:        For operator entries (C=$5B): L_0C93 := $00 and control jumps to DETOKENIZE_LINE_19 to copy the operator's own char from the table (no implied leading letter, no separating space before OR after). Otherwise falls through to DETOKENIZE_LINE_16 for ordinary keywords.
;   Clobbers:  A, L_0C93.
;   Algorithm: Reached only when the token was NOT USR/FN (JR NZ from DETOKENIZE_LINE_14). Compare the sequence code C to $5B: the operator sub-table RESWORD_OPS sits one $00-separator past the (empty) KWGRP_Z group, so the group counter reaches $5B for every operator entry, uniquely flagging 'this is an operator, not a lettered keyword'. Operators store their full character in the table and need no implied leading letter or separating space, so reset the spacing state to $00 and branch straight into the character-copy loop. Any other C is a real A..Z keyword group and continues to the general leading-space logic.
; ----------------------------------------------------------------------
DETOKENIZE_LINE_15:
        ; operator group? (C=$5B is the single sequence code shared by all RESWORD_OPS entries, one $00 past the empty Z group)
        CP $5B
        JR NZ,DETOKENIZE_LINE_16
        ; operator: clear the inter-token spacing state (no surrounding space, no implied leading letter) and copy the operator char verbatim
        XOR A
        LD (L_0C93),A
        JR DETOKENIZE_LINE_19
; ----------------------------------------------------------------------
; DETOKENIZE_LINE_16 -- keyword emit: latch 'keyword just emitted' spacing state for an ordinary A..Z keyword
;   In:        L_0C93 = inter-token spacing state from the previously emitted item ($00 = none pending, $01 = last item was an alphanumeric literal, $FF = last item was a keyword). E = group letter / sequence code C, BC -> BUF, D = remaining length.
;   Out:        Z flag set iff the OLD spacing state was $00 (consumed by DETOKENIZE_LINE_17 to decide whether to prepend a space). L_0C93 := $FF (record that a keyword is now the trailing item).
;   Clobbers:  A, L_0C93, flags.
;   Algorithm: Capture the previous spacing state into the Z flag (OR A), then unconditionally set the new state to $FF meaning 'a keyword was just emitted, so the next token/identifier must be space-separated'. Falls into DETOKENIZE_LINE_17, which prepends a space when the old state was non-zero.
; ----------------------------------------------------------------------
DETOKENIZE_LINE_16:
        ; remember whether a space is pending (Z := old spacing state was $00) before overwriting it
        LD A,(L_0C93)
        OR A
        ; mark the trailing item as a keyword so the NEXT emitted token gets a separating space
        LD A,$FF
        LD (L_0C93),A
; ----------------------------------------------------------------------
; DETOKENIZE_LINE_17 -- keyword emit: conditionally prepend one separating space before the keyword spelling
;   In:        Z flag = 'no leading space needed' (set when the prior spacing state was $00). Reached from DETOKENIZE_LINE_16 (ordinary keyword) and from the USR/FN tail of DETOKENIZE_LINE_14 (which set L_0C93 := $00 and jumped here); the operator path does NOT pass through here (it goes DETOKENIZE_LINE_15 -> DETOKENIZE_LINE_19). BC -> next free BUF byte, D = remaining BUF length.
;   Out:        If a space is emitted, BUF gets ' ', BC advances, D decrements; on D underflow to 0 the whole detokenize aborts via GETSPA_2 (shared POP AF / RET exit that also discards the saved source pointer still on the stack). Falls into DETOKENIZE_LINE_18 to emit the keyword's implied leading letter.
;   Clobbers:  A, BC, D, BUF, flags.
;   Algorithm: If the incoming Z flag says no separator is pending, skip directly to copying the keyword. Otherwise write a single ASCII space into the output buffer, advance the write pointer, and decrement the remaining-length counter; if that hits zero the buffer is full and the routine bails out through GETSPA_2 (full abort of DETOKENIZE_LINE).
; ----------------------------------------------------------------------
DETOKENIZE_LINE_17:
        ; no space pending: go straight to emitting the keyword's spelling
        JR Z,DETOKENIZE_LINE_18
        LD A,$20
        LD (BC),A
        INC BC
        ; buffer-full check: on underflow abort the whole detokenize via GETSPA_2 (its POP AF discards the saved source pointer and returns)
        DEC D
        JP Z,GETSPA_2
; ----------------------------------------------------------------------
; DETOKENIZE_LINE_18 -- keyword emit: output the keyword's implied first letter (the group letter)
;   In:        E = the group sequence code C ($41..$5A = the ASCII first letter 'A'..'Z' of the keyword's group). HL -> first stored tail char of the matched keyword in the name table.
;   Out:        A = E (the leading letter); control falls into DETOKENIZE_LINE_20, which masks/stores it and then (since bit7 of E is clear for $41..$5A) loops to DETOKENIZE_LINE_19 to append the stored tail.
;   Clobbers:  A.
;   Algorithm: The reserved-word name table stores only the characters AFTER the group letter (e.g. 'AND' is stored as 'ND'+terminator+token under group 'A'). The matcher reconstructed that first letter as the sequence code C (init $40, INC per $00 group boundary) while walking the $00-separated groups; emit it here as the first output character. Every keyword in the table has at least one stored tail char, so DETOKENIZE_LINE_19/20 always run afterwards to append it (the shortest entries are 2-letter: FN/IF/ON/GR, one tail char each).
; ----------------------------------------------------------------------
DETOKENIZE_LINE_18:
        ; emit the keyword's implied first letter (group code C = 'A'..'Z'); the name table holds only the tail characters
        LD A,E
        JR DETOKENIZE_LINE_20
; ----------------------------------------------------------------------
; DETOKENIZE_LINE_19 -- keyword emit: fetch the next stored tail character of the keyword spelling
;   In:        HL -> next character of the reserved-word name in the table (high bit set on the FINAL character as the terminator). For operator entries, HL -> the (single) stored operator char.
;   Out:        A = E = the raw table byte (still carrying its bit7 terminator flag); HL advanced past it. Falls into DETOKENIZE_LINE_20 to mask, store and test for end.
;   Clobbers:  A, E, HL.
;   Algorithm: Read one spelling character from the name table and advance HL. Keep the UNMASKED byte in E so DETOKENIZE_LINE_20 can re-test bit7 after masking to detect the last character of the keyword. This is the per-character loop body; control returns here from DETOKENIZE_LINE_20 until the high-bit-terminated final char is reached.
; ----------------------------------------------------------------------
DETOKENIZE_LINE_19:
        ; read the next keyword spelling char from the name table (bit7 set marks the final char)
        LD A,(HL)
        INC HL
        ; stash the UNMASKED byte in E so the loop can re-detect the bit7 terminator after masking
        LD E,A
; ----------------------------------------------------------------------
; DETOKENIZE_LINE_20 -- keyword emit: store one spelling char, then loop or finish the keyword
;   In:        A = char to emit (bit7 = terminator flag still present for table chars; for the leading group letter from DETOKENIZE_LINE_18 bit7 is clear). E = the unmasked source byte (its bit7 = 'this was the last char'; for the leading-letter entry E = C = $41..$5A, bit7 clear). BC -> next free BUF byte. D = remaining BUF length.
;   Out:        Masked char written to BUF, BC advanced, D decremented. If more chars remain (bit7 of E clear) loops to DETOKENIZE_LINE_19. On the last char, falls through to the SPC(/TAB( trailing-space-suppression check and DETOKENIZE_LINE_21. On D underflow, aborts via GETSPA_2.
;   Clobbers:  A, BC, D, BUF, flags.
;   Algorithm: Mask off bit7 (AND $7F) so the high-bit terminator never reaches the output, store the printable char, advance the write pointer and decrement the remaining length (buffer-full -> GETSPA_2 full abort). Then OR the stored char with E: since the stored char has bit7 cleared, the sign of the result is bit7 of E, i.e. 'was this the terminating char'. If not (JP P), loop back to fetch the next char; if it was the last char, fall into the post-keyword handling (DETOKENIZE_LINE_21).
;   Note:      For the terminating char, (masked char) OR E == E exactly, so the CP $A8 below tests whether the keyword's final UNMASKED char was $A8. $A8 = '('+$80 is the stored terminator of the function-call keywords SPC( and TAB( (table entries 'P','C','('+$80 and 'A','B','('+$80). [RE] Matching it resets the spacing state to $00 so no space is inserted before the argument that follows '('. The byte value $A8 also coincides with TOK_RENUM=$A8, but here $A8 is the '(' terminator CHARACTER, not the RENUM token.
; ----------------------------------------------------------------------
DETOKENIZE_LINE_20:
        ; strip the bit7 keyword terminator before writing the printable character to BUF
        AND $7F
        LD (BC),A
        INC BC
        ; buffer-full check: abort the whole detokenize via GETSPA_2 on underflow
        DEC D
        JP Z,GETSPA_2
        ; test bit7 of the original byte (in E): clear => more spelling chars, set => this was the keyword's last char
        OR E
        JP P,DETOKENIZE_LINE_19
        ; [RE] keyword ended in '(' ($A8 = '('+$80, i.e. SPC( or TAB()? if so, suppress the trailing space so the argument follows immediately
        CP $A8
        JR NZ,DETOKENIZE_LINE_21
        XOR A
        LD (L_0C93),A
; ----------------------------------------------------------------------
; DETOKENIZE_LINE_21 -- keyword emit: re-enter the main detokenize loop after a reserved word
;   In:        Top of stack = the source pointer HL pushed at DETOKENIZE_LINE_10 before the keyword lookup; HL was already advanced past the (1- or 2-byte) token at DETOKENIZE_LINE_8/_9 before that PUSH, so the saved copy is the correct resume position. (For SPC(/TAB( the preceding step already reset the spacing state to $00.)
;   Out:        HL restored to the next source byte; control returns to DETOKENIZE_LINE_2 to process it.
;   Clobbers:  HL.
;   Algorithm: Pop the saved source pointer (already past the token that was just spelled out) and jump back to the top of the main copy/detokenize loop for the next program byte. This is the normal return path of the reserved-word branch of DETOKENIZE_LINE.
; ----------------------------------------------------------------------
DETOKENIZE_LINE_21:
        ; restore the source pointer saved before the keyword lookup (already advanced past the token) and resume the main loop
        POP HL
        JP DETOKENIZE_LINE_2
; ----------------------------------------------------------------------
; IS_ALNUM_CHAR -- test whether a character is alphanumeric (letter A-Z or ASCII digit 0-9)
;   In:        A = the character to test.
;   Out:       Carry CLEAR (NC) if A is a letter A-Z ($41-$5A) OR an ASCII digit '0'-'9' ($30-$39); carry SET (C) for every other byte. A preserved.
;   Clobbers:  flags only.
;   Algorithm: CALL IS_LETTER_A returns NC for A-Z (RETs immediately). Otherwise CP $30/RET C returns C for anything below '0'; CP $3A then CCF maps '0'-'9' (which are < $3A) to NC and ':'+ to C. Net: NC iff A is a letter OR a decimal digit. Callers read NC as 'this char continues an identifier/number' and C as 'word/identifier boundary'. CORRECTION: the peer header claimed 'carry SET if A is a digit' and that the routine distinguishes letters from digits -- both letters and digits return NC; this is an is-alphanumeric test. Used by BOTH the CRUNCH tokenizer ($30BA, to refuse tokenizing a reserved word when the next source char is still alphanumeric so ANDY stays a variable not AND+Y) and the LIST detokenizer ($4131).
; ----------------------------------------------------------------------
IS_ALNUM_CHAR:
        ; letters A-Z return NC here -> alphanumeric
        CALL IS_LETTER_A
        RET NC
        ; below '0': not a digit either, return carry set (non-alphanumeric)
        CP $30
        RET C
        CP $3A
        ; map '0'-'9' to NC (alphanumeric); ':' and above to C
        CCF
        RET
; ----------------------------------------------------------------------
; CONST_FMT_BEGIN -- format an embedded numeric-constant token ($0B/$0C/$0E/$0F/$11-$1A/$1C/$1D/$1F) back to ASCII for LIST
;   In:        HL -> the constant token byte in the crunched line (detokenizer has not advanced HL yet); E = the token byte; BC -> write position in the detokenize output buffer BUF; D = bytes remaining in BUF.
;   Out:       Via the pushed return CONST_FMT_PREFIX, falls into the prefix/suffix/digit-copy path. The value is rendered NUL-terminated into the renderer scratch buffer (FOUT->$0CC3, HEX_OCT_OUT->$0CC2) with HL left pointing at it; the CONST_* cells are re-staged; BC/DE saved at entry are restored by CONST_FMT_PREFIX.
;   Clobbers:  A, HL, BC, DE (saved/restored in CONST_FMT_PREFIX), the CONST_* staging cells, the FAC, the $0CC2/$0CC3 scratch buffer.
;   Algorithm: DEC HL then CALL CHRGET (= INC HL + CHRGOT) re-positions HL onto the token and re-runs CHRGOT's constant decode, re-staging CONST_TOKEN/CONST_VALUE/CONST_VALTYP/CONST_TEXT_RESUME and returning the token byte in A. Save DE,BC,AF; CALL CHRGOT_CONST_VALUE materializes the staged value into the FAC; POP AF recovers the token. Push CONST_FMT_PREFIX as the renderer's return address, then dispatch on the token: $0B -> HEX_OCT_OUT (octal, base flag B=0), $0C -> HEX_OCT_OUT_1+1 (hex, base flag B=1), anything else -> FOUT_2 (decimal/exponential). Both renderers read the value from the FAC (HEX_OCT_OUT via CALL GETADR, FOUT via LD HL,(FAC)).
; ----------------------------------------------------------------------
CONST_FMT_BEGIN:
        ; reposition so the following CHRGET (INC HL + CHRGOT) re-reads and decodes the constant token at HL
        DEC HL
        CALL CHRGET
        PUSH DE
        PUSH BC
        PUSH AF
        ; materialize the staged constant into the FAC (the value source the renderer reads)
        CALL CHRGOT_CONST_VALUE
        POP AF
        ; push the renderer's return address: it comes back to emit the '&H'/'&O' prefix and copy the digits
        LD BC,CONST_FMT_PREFIX
        PUSH BC
        ; token $0B (&O octal): render via HEX_OCT_OUT with the octal base flag (B=0)
        CP $0B
        JP Z,HEX_OCT_OUT
        ; token $0C (&H hex): enter HEX_OCT_OUT at +1 to load the hex base flag (B=1)
        CP $0C
        JP Z,HEX_OCT_OUT_1+1
        ; [RE] loads HL from CONST_VALUE, but FOUT_2's first act (FOUT_SET_FORMAT) does LD HL,$0CC3 overwriting HL, and FOUT renders from the FAC -- this load has no observed effect; purpose UNKNOWN (likely vestigial)
        LD HL,(CONST_VALUE)
        ; non-&H/&O constant: render the FAC as decimal/exponential ASCII
        JP FOUT_2
; ----------------------------------------------------------------------
; CONST_FMT_PREFIX -- restore the BUF cursor and emit the '&O'/'&H' base prefix for octal/hex constants
;   In:        Stack holds the BC (BUF write ptr) and DE (D = BUF bytes left) saved by CONST_FMT_BEGIN; CONST_TOKEN = the constant token; HL -> the rendered ASCII text.
;   Out:       For $0B/$0C the two-char prefix '&O'/'&H' is written into BUF (BC advanced, D decremented), RET Z early if BUF fills, then falls into CONST_FMT_TYPE_SUFFIX (_4). For every other token it skips the prefix and falls into _4. HL preserved.
;   Clobbers:  A, E, BC, D, flags; writes up to 2 bytes to BUF.
;   Algorithm: POP BC, POP DE restore the BUF cursor. Load CONST_TOKEN. Preload E='O' ($4F); if token==$0B branch to CONST_FMT_EMIT_PREFIX. Else load E='H' ($48); if token!=$0C skip the prefix (JR NZ to CONST_FMT_TYPE_SUFFIX). Otherwise fall into CONST_FMT_EMIT_PREFIX, which writes '&' then E.
; ----------------------------------------------------------------------
CONST_FMT_PREFIX:
        ; restore the BUF write pointer and remaining-length saved before the value was rendered
        POP BC
        POP DE
        ; select the base prefix from the constant token ($0B=&O, $0C=&H, anything else = no prefix)
        LD A,(CONST_TOKEN)
        ; default base letter 'O' (octal) in E
        LD E,$4F
        CP $0B
        JR Z,CONST_FMT_EMIT_PREFIX
        CP $0C
        ; hex case: base letter 'H'
        LD E,$48
        ; not &H/&O: no base prefix, go straight to the type-suffix selection
        JR NZ,CONST_FMT_TYPE_SUFFIX
; ----------------------------------------------------------------------
; CONST_FMT_EMIT_PREFIX -- write the literal '&' and the selected base letter ('O' or 'H') into BUF
;   In:        E = base letter ('O'=$4F or 'H'=$48); BC -> BUF write position; D = bytes remaining in BUF.
;   Out:       '&' then E stored into BUF; BC advanced by 2, D decremented by 2. RET (Z) early if BUF fills after either store. Falls into CONST_FMT_TYPE_SUFFIX.
;   Clobbers:  A, BC, D, flags; writes up to 2 bytes to BUF.
;   Algorithm: Store '&' ($26) to (BC), INC BC, DEC D, RET Z if buffer full. Store E (the base letter), INC BC, DEC D, RET Z if full. Then fall through to choose the numeric type suffix.
; ----------------------------------------------------------------------
CONST_FMT_EMIT_PREFIX:
        ; emit the radix sigil '&' that precedes 'O'/'H'
        LD A,$26
        LD (BC),A
        INC BC
        DEC D
        RET Z
        ; emit the base letter ('O' for octal, 'H' for hex)
        LD A,E
        LD (BC),A
        INC BC
        DEC D
        RET Z
; ----------------------------------------------------------------------
; CONST_FMT_TYPE_SUFFIX -- choose the trailing numeric type-suffix character from the constant's value type
;   In:        CONST_VALTYP = the constant's value width/type (VT_INT=2, VT_SNG=4, VT_DBL=8); HL -> the rendered ASCII text.
;   Out:       E = the suffix byte: $00 (none) for VT_INT (and anything < 4), '!' ($21) for VT_SNG, '#' ($23) for VT_DBL (anything > 4). Falls into CONST_FMT_SKIP_SPACE (_5).
;   Clobbers:  A, E, flags.
;   Algorithm: Load CONST_VALTYP and CP $04. If C (< 4, integer) set E=$00 (no suffix). If Z (== 4, single) set E='!' ($21). Else (> 4, double) set E='#' ($23). E is carried through the digit-copy loop and emitted at the end unless suppressed because the printed form already shows a '.'/'D'/'E'.
; ----------------------------------------------------------------------
CONST_FMT_TYPE_SUFFIX:
        ; pick the BASIC type-suffix from the constant's value type
        LD A,(CONST_VALTYP)
        CP $04
        ; integer constant (VALTYP<4): no type-suffix character
        LD E,$00
        JR C,CONST_FMT_SKIP_SPACE
        ; single-precision (VALTYP=4): suffix '!'
        LD E,$21
        JR Z,CONST_FMT_SKIP_SPACE
        ; double-precision (VALTYP>4): suffix '#'
        LD E,$23
; ----------------------------------------------------------------------
; CONST_FMT_SKIP_SPACE -- skip FOUT's leading sign-placeholder space in the rendered text
;   In:        HL -> first byte of the rendered numeric ASCII (FOUT emits a leading ' ' placeholder for a non-negative value); E = pending type-suffix.
;   Out:       If the first char is a space ($20), HL is advanced past it; otherwise HL unchanged. Falls into the digit-copy loop CONST_FMT_COPY (_6).
;   Clobbers:  A, HL (conditionally), flags.
;   Algorithm: LD A,(HL); CP $20; CALL Z,FP_LOAD_DONE (FP_LOAD_DONE = INC HL; RET) to step over FOUT's leading sign space so the copy starts at the first digit. HEX/OCT output has no leading space, so this is a no-op on that path.
; ----------------------------------------------------------------------
CONST_FMT_SKIP_SPACE:
        LD A,(HL)
        ; FOUT prefixes a non-negative number with a leading space placeholder; drop it before copying
        CP $20
        ; FP_LOAD_DONE = INC HL/RET: advance past the leading space
        CALL Z,FP_LOAD_DONE
; ----------------------------------------------------------------------
; CONST_FMT_COPY -- copy the rendered numeric ASCII into BUF, suppressing the type-suffix when the printed form already shows a '.'/'D'/'E'
;   In:        HL -> next char of the rendered text (NUL-terminated); BC -> BUF write position; D = bytes left in BUF; E = pending type-suffix ($00/'!'/'#'); CONST_VALTYP = value type.
;   Out:       Loops until the NUL terminator, copying each char to BUF (BC++/D--), RET Z if BUF fills; on the terminator jumps to CONST_FMT_EMIT_SUFFIX (_9). E is zeroed (via CONST_FMT_CLEAR_SUFFIX, _8) for single/double values once the appropriate '.'/'D'/'E' has been copied.
;   Clobbers:  A, BC, D, E (via _8), HL, flags; writes to BUF.
;   Algorithm: LD A,(HL); INC HL; if $00 go to CONST_FMT_EMIT_SUFFIX. Store it to BUF, INC BC, DEC D, RET Z on overflow. LD A,(CONST_VALTYP); CP $04: if C (integer, < 4) loop straight back (no suffix logic). CORRECTION: the following JR NZ keys on THIS CP $04 result (single vs double), NOT on the LD A,(BC) -- a Z80 load sets no flags. The re-read DEC BC/LD A,(BC)/INC BC only restores A (clobbered by LD A,(CONST_VALTYP)) to the char just stored so the CP $2E/$44/$45 tests work. JR NZ,CONST_FMT_SUFFIX_TEST takes the DOUBLE path (VALTYP>4): test only 'D'/'E'. The Z (single, VALTYP=4) fall-through tests CP $2E ('.') first -> if '.' clear the suffix, else fall into CONST_FMT_SUFFIX_TEST. Net: single suppresses the suffix on '.', 'D', or 'E'; double suppresses only on 'D' or 'E'.
; ----------------------------------------------------------------------
CONST_FMT_COPY:
        LD A,(HL)
        INC HL
        OR A
        ; NUL terminator: digits done, go append the type-suffix
        JR Z,CONST_FMT_EMIT_SUFFIX
        LD (BC),A
        INC BC
        DEC D
        RET Z
        ; integer values carry no suffix (CP $04/JR C below skips the test); also splits single (Z) vs double (NZ) for the test that follows
        LD A,(CONST_VALTYP)
        CP $04
        JR C,CONST_FMT_COPY
        DEC BC
        ; re-read the just-stored char to RESTORE A (clobbered by LD A,(CONST_VALTYP)) for the CP $2E/$44/$45 tests; this load does NOT set the flags used by the next JR NZ
        LD A,(BC)
        INC BC
        JR NZ,CONST_FMT_SUFFIX_TEST
        CP $2E
        JR Z,CONST_FMT_CLEAR_SUFFIX
; ----------------------------------------------------------------------
; CONST_FMT_SUFFIX_TEST -- test a copied char for an exponent marker ('D'/'E') and drop the type-suffix if found
;   In:        A = the character just copied into BUF; E = pending type-suffix. Reached on the double-precision path (JR NZ from CONST_FMT_COPY) or as the single-precision fall-through after the '.' test missed.
;   Out:       If A is 'D' ($44) or 'E' ($45), fall/branch to CONST_FMT_CLEAR_SUFFIX to zero E; otherwise (JR NZ) loop back to CONST_FMT_COPY for the next char.
;   Clobbers:  flags.
;   Algorithm: CP $44 ('D', double-precision exponent letter) -> if equal go clear the suffix. CP $45 ('E', single-precision exponent letter) -> if not equal continue the copy loop; if equal fall into CONST_FMT_CLEAR_SUFFIX. A number shown in exponential form already implies its type, so the '!'/'#' suffix is suppressed.
; ----------------------------------------------------------------------
CONST_FMT_SUFFIX_TEST:
        ; 'D' = double-precision exponent marker -> type already shown, drop the suffix
        CP $44
        JR Z,CONST_FMT_CLEAR_SUFFIX
        ; 'E' = single-precision exponent marker -> drop the suffix; any other char keeps copying
        CP $45
        JR NZ,CONST_FMT_COPY
; ----------------------------------------------------------------------
; CONST_FMT_CLEAR_SUFFIX -- suppress the trailing type-suffix because the printed text already shows a decimal point/exponent
;   In:        Reached when a '.', 'D', or 'E' was just copied (single), or a 'D'/'E' (double).
;   Out:       E = $00 (no suffix). Re-enters the copy loop CONST_FMT_COPY to finish the remaining characters.
;   Clobbers:  E, flags.
;   Algorithm: LD E,$00 to cancel the pending '!'/'#'; JR back to CONST_FMT_COPY. A number rendered with a fractional point or an E/D exponent is unambiguously typed, so the redundant suffix is omitted.
; ----------------------------------------------------------------------
CONST_FMT_CLEAR_SUFFIX:
        ; cancel the pending type-suffix: the printed form already shows the type
        LD E,$00
        JR CONST_FMT_COPY
; ----------------------------------------------------------------------
; CONST_FMT_EMIT_SUFFIX -- append the surviving type-suffix character to BUF, if any
;   In:        E = the type-suffix ($00=none, '!'=$21 single, '#'=$23 double) after suppression; BC -> BUF write position; D = bytes left.
;   Out:       If E != 0, the suffix is written into BUF (BC++/D--), RET Z if BUF fills. Falls into CONST_FMT_RESUME (_10).
;   Clobbers:  A, BC, D, flags; writes up to 1 byte to BUF.
;   Algorithm: LD A,E; OR A; if zero (no suffix or suppressed) skip to CONST_FMT_RESUME. Otherwise store E into BUF, INC BC, DEC D, RET Z on overflow, then fall into CONST_FMT_RESUME.
; ----------------------------------------------------------------------
CONST_FMT_EMIT_SUFFIX:
        ; append the type-suffix '!'/'#' if it survived the decimal/exponent suppression
        LD A,E
        OR A
        ; no suffix to emit (integer, or already suppressed)
        JR Z,CONST_FMT_RESUME
        LD (BC),A
        INC BC
        DEC D
        RET Z
; ----------------------------------------------------------------------
; CONST_FMT_RESUME -- restore the source pointer past the consumed constant and resume detokenizing
;   In:        CONST_TEXT_RESUME = the crunched-line pointer just past the embedded constant (saved when the constant was decoded).
;   Out:       HL reloaded from CONST_TEXT_RESUME; control jumps to DETOKENIZE_LINE_2 to continue expanding the rest of the line.
;   Clobbers:  HL.
;   Algorithm: LD HL,(CONST_TEXT_RESUME) to skip over the whole multi-byte embedded constant in one step, then JP DETOKENIZE_LINE_2 to process the next byte of the crunched line.
; ----------------------------------------------------------------------
CONST_FMT_RESUME:
        ; advance source past the whole embedded constant (token + value bytes) in one step
        LD HL,(CONST_TEXT_RESUME)
        ; rejoin the detokenize loop for the next byte of the line
        JP DETOKENIZE_LINE_2
; ----------------------------------------------------------------------
; STMT_DELETE -- DELETE statement handler (keyword token $A6): remove a range of program lines.
;   In:        HL -> the line-range arguments after DELETE; the program is the singly-linked BASLINE list from TXTTAB.
;   Out:       On a valid non-empty range, 'Ok' is printed and the routine falls into BLOCK_MOVE_TO_VARTAB to excise the lines (text above the range moved down over them, VARTAB re-anchored), with SUB_0EB7_4 arranged as the post-delete relink/reset continuation. Raises 'Illegal function call' (via STMT_DELETE_1) if the range is empty or malformed.
;   Clobbers:  A, BC, DE, HL, SP frame, flags.
;   Algorithm: SCAN_LINE_RANGE parses 'start[-end]', leaving the start link/insert point in BC and the end line number on the stack. RENUM_FIXUP_IF_PENDING applies any deferred RENUM line-reference patch first. FNDLIN locates the END line: if not found (NC) drop into STMT_DELETE_1's FC check; otherwise verify the found end line is at/after the start (CMP_HL_DE) and join STMT_DELETE_1.
;   UNKNOWN:   [RE] the exact stack choreography handing the start/end pointers between SCAN_LINE_RANGE, FNDLIN and BLOCK_MOVE_TO_VARTAB is inferred from the PUSH/POP/EX (SP) pattern, not single-stepped.
; ----------------------------------------------------------------------
STMT_DELETE:
        ; parse the 'start[-end]' line-number range to delete
        CALL SCAN_LINE_RANGE
        PUSH BC
        ; apply any deferred RENUM line-reference fixups before editing the program
        CALL RENUM_FIXUP_IF_PENDING
        POP BC
        POP DE
        PUSH BC
        PUSH BC
        ; locate the end line of the range in the program
        CALL FNDLIN
        JR NC,STMT_DELETE_1
        LD D,H
        LD E,L
        EX (SP),HL
        PUSH HL
        ; verify the end line is at or after the start (non-empty range)
        CALL CMP_HL_DE
; ----------------------------------------------------------------------
; STMT_DELETE_1 -- DELETE validity gate and program-compaction setup (continuation of STMT_DELETE).
;   In:        Carry reflects the range validity check (NC = invalid/empty range); BC/stack hold the start insert point; the end-of-range pointer is staged.
;   Out:       On an invalid range raises 'Illegal function call'. On a valid range prints 'Ok', arranges SUB_0EB7_4 as the post-delete continuation, and falls into BLOCK_MOVE_TO_VARTAB to delete the lines by compacting the program text.
;   Clobbers:  A, BC, DE, HL, SP frame, flags.
;   Algorithm: JP NC,ERROR_FC rejects an empty/invalid range. Print MSG_OK ('Ok'). POP the start pointer into BC (destination of the compaction copy), load SUB_0EB7_4 and EX (SP),HL so it becomes the routine BLOCK_MOVE_TO_VARTAB returns to (re-link program and reset run state). Fall into BLOCK_MOVE_TO_VARTAB to move the surviving text down and re-anchor VARTAB.
; ----------------------------------------------------------------------
STMT_DELETE_1:
        ; empty or malformed line range -> Illegal function call
        JP NC,ERROR_FC
        LD HL,MSG_OK
        CALL STROUT
        POP BC
        ; arrange the post-delete relink/reset to run after the program is compacted
        LD HL,SUB_0EB7_4
        EX (SP),HL
; ----------------------------------------------------------------------
; BLOCK_MOVE_TO_VARTAB -- copy a byte run from (HL) to (BC) until the source reaches VARTAB, then republish VARTAB.
;   In:        HL = source start, BC = destination start. VARTAB = exclusive source-end sentinel.
;   Out:       (BC..) holds the copied bytes; VARTAB := the ending destination pointer (BC after the copy).
;   Clobbers:  A, BC, DE, HL, flags.
;   Algorithm: EX DE,HL moves the source pointer into DE, then HL is loaded with VARTAB to serve as the
;              stop sentinel. Copy bytes (DE)->(BC) ascending, advancing both, until the source pointer DE
;              equals VARTAB (CMP_HL_DE returns Z). Finally store the ending destination pointer (B,C) back
;              into VARTAB. [RE] Used by the DELETE / line-edit and CHAIN paths to relocate the program/text
;              run and re-anchor the variable-table base behind it. NOTE: source is supplied in HL on entry
;              (the routine's own EX DE,HL moves it into DE); BC is the destination.
; ----------------------------------------------------------------------
BLOCK_MOVE_TO_VARTAB:
        EX DE,HL
        ; use the variable-table base as the exclusive end-of-source sentinel
        LD HL,(VARTAB)
BLOCK_MOVE_TO_VARTAB_1:
        ; copy one byte from the source run into the destination
        LD A,(DE)
        LD (BC),A
        INC BC
        INC DE
        CALL CMP_HL_DE
        JR NZ,BLOCK_MOVE_TO_VARTAB_1
        ; publish the ending destination pointer (B,C) as the new VARTAB
        LD H,B
        LD L,C
        LD (VARTAB),HL
        RET
; ----------------------------------------------------------------------
; FN_PEEK -- PEEK(addr) function handler (function token $16, TOK_PEEK): return the byte stored at a machine address.
;   In:        FAC holds the parenthesised numeric argument, already evaluated by the function-call
;              dispatcher (FRMEVL_FUNC_* path) before this handler is entered; the argument is NOT
;              pre-coerced (PEEK's dispatch index is above the single-precision-coercion band, so GETADR
;              does the typing). HL = program-text cursor positioned just past the closing ')'. SAVTXT
;              ($0844) = current statement pointer (== $FFFF in direct mode). LOAD_PROTECT_FLAG ($0C99)
;              nonzero iff a load-protected program (LOADed from a $FE-prefixed file) is resident.
;   Out:       FAC := the unsigned byte read from memory (0..255), stored as a 16-bit integer (high byte 0,
;              VALTYP = VT_INT). May raise 'Illegal function call' (ERR_FC) via the direct-mode guard, or
;              Type mismatch / Overflow via GETADR's FN_CINT continuation.
;   Clobbers:  A, BC, DE, HL, flags, the FAC.
;   Algorithm: GETADR coerces the FAC argument to an unsigned 16-bit address (0..65535) returned in HL.
;              DIRECT_MODE_GUARD applies the PEEK/POKE protection check: it returns immediately while a
;              program is running (SAVTXT != $FFFF), but in direct mode (SAVTXT == $FFFF) it falls into
;              ILLEGAL_DIRECT_CHECK, which raises ERR_FC only when LOAD_PROTECT_FLAG is nonzero -- i.e. PEEK
;              from the keyboard is refused when a load-protected program is resident. [RE] the intent is
;              to stop dumping a protected program's bytes via direct-mode PEEK. The byte at the address
;              is then fetched (LD A,(HL)) and tail-jumped into FP_LOAD_INT_TO_FAC, which zero-extends A
;              into HL (H=0) and stores it as a VT_INT in the FAC.
; ----------------------------------------------------------------------
FN_PEEK:
        ; coerce the parenthesised argument (already in the FAC) to an unsigned 16-bit address in HL
        CALL GETADR
        ; PEEK/POKE protection check: a no-op while a program runs; in direct mode it FC-errors only if a load-protected program is resident
        CALL DIRECT_MODE_GUARD
        ; read the byte at the target address
        LD A,(HL)
        ; return the byte (zero-extended, high byte 0) as a VT_INT in the FAC
        JP FP_LOAD_INT_TO_FAC
; ----------------------------------------------------------------------
; STMT_POKE -- POKE statement handler (keyword token $97): store a byte to an arbitrary memory address.
;   In:        HL -> the 'addr , value' arguments after POKE.
;   Out:       The byte 'value' (0..255) is written to memory at the unsigned 16-bit 'addr'. HL advanced past the second operand. May raise Type mismatch / Overflow (via GETADR) or 'Illegal function call' (value not a byte, or via DIRECT_MODE_GUARD).
;   Clobbers:  A, BC, DE, HL, flags, the FAC.
;   Algorithm: FRMEVL_NOPAREN evaluates the address expression into the FAC; PUSH HL saves the text cursor; GETADR coerces the FAC to an unsigned 16-bit address (returned in HL); EX (SP),HL stashes that address and restores the text cursor. DIRECT_MODE_GUARD blocks the store in a protected/direct context. SYNCHR consumes the ',' , GETBYT evaluates the value as a byte in A, POP DE recovers the address, and LD (DE),A performs the store.
;   UNKNOWN:   [RE] the precise condition DIRECT_MODE_GUARD enforces here (protected vs direct mode) is shared with FN_PEEK; not separately audited in this routine.
; ----------------------------------------------------------------------
STMT_POKE:
        ; evaluate the destination address expression into the FAC
        CALL FRMEVL_NOPAREN
        PUSH HL
        ; coerce the address to an unsigned 16-bit value (returned in HL)
        CALL GETADR
        EX (SP),HL
        ; guard the store (shared PEEK/POKE protected/direct check)
        CALL DIRECT_MODE_GUARD
        CALL SYNCHR
        ; require the ',' between address and value
        DEFB    ','                      ; inline char arg consumed by the preceding CALL
        ; evaluate the value to store as a single byte (0..255)
        CALL GETBYT
        POP DE
        ; write the byte to the target address
        LD (DE),A
        RET
; ----------------------------------------------------------------------
; GETADR -- coerce the already-evaluated FAC value to an UNSIGNED 16-bit machine address (0..65535).
;   In:        FAC holds a numeric value already evaluated by the CALLER (callers do FRMEVL_NOPAREN before
;              CALL GETADR; function handlers like FN_PEEK arrive with the parenthesised arg already in the
;              FAC). VALTYP describes the value; HL is the text cursor past the expression.
;   Out:       HL = unsigned 16-bit address (0..65535). NOTE the result is in HL, not DE: GETADR pre-pushes
;              FN_CINT, whose tail (FP_STORE_FAC_INT) leaves the 16-bit integer in HL, and every caller
;              (FN_PEEK / STMT_POKE / STMT_CLEAR / STMT_CHAIN / HEX$/OCT$) reads HL. Type mismatch / Overflow
;              may be raised by the pushed FN_CINT continuation.
;   Clobbers:  A, BC, DE, HL, flags, the FAC.
;   Algorithm: GETADR does NOT itself evaluate an expression -- it only re-types the value already in the
;              FAC. Pre-push FN_CINT as a continuation so any early RET routes into the normal FAC->int16
;              extractor. FRMEVL_TEST_TYPE classifies the FAC's VALTYP (it does NOT evaluate text): RET M
;              when the value is already integer (VALTYP==2) -> straight into FN_CINT. Otherwise, only when
;              the FP exponent byte ($0CB4) is exactly $90 -- magnitude in [2^15,2^16), the positive range
;              signed FN_CINT would Overflow on -- and the value is positive (FACHI sign bit clear, RET M
;              else), load -65536.0 as ARG (BC=$9180: B=$91 exponent, C=$80 = sign-bit-set + 1.0 mantissa
;              MSB; DE=0) and JP FADD_ALIGN to add it. Adding -2^16 maps the value into [-32768,0), whose
;              signed-int16 two's-complement bit pattern equals the desired unsigned address; the pushed
;              FN_CINT then extracts those 16 bits. Values < 2^15 fall through the early RETs into FN_CINT
;              unchanged. The $9180 immediate is the single-precision FP encoding of -65536.0 (C bit7 = sign
;              in this MBF format), NOT a memory address.
;   UNKNOWN:   the exact FADD_ALIGN/FN_CINT bit interplay that recovers the unsigned result is inferred from
;              the -2^16 (two's-complement-wrap) idiom, not traced bit-for-bit here.
; ----------------------------------------------------------------------
GETADR:
        ; pre-push the FAC->int16 extractor as the return continuation for every early RET below
        LD BC,FN_CINT
        PUSH BC
        ; classify the FAC's type from VALTYP (does NOT evaluate); RET M when already integer -> FN_CINT
        CALL FRMEVL_TEST_TYPE
        RET M
        LD A,(FAC_EXP)
        CP $90
        RET NZ
        ; reject negative values: only a positive magnitude reaches the unsigned-extract path (RET M otherwise)
        LD A,(FACHI)
        OR A
        RET M
        ; load -65536.0 as ARG and add it: maps [2^15,2^16) to [-32768,0) so FN_CINT's bits = the unsigned address
        LD BC,$9180
        LD DE,$0000
        JP FADD_ALIGN
; ----------------------------------------------------------------------
; STMT_RENUM -- RENUM statement handler (token $A8): renumber the program's lines and fix all line-number references.
;   In:        HL -> crunched text just past the RENUM token; Z set if no operands. Optional
;              syntax: RENUM [newstart][,[oldstart][,increment]]. Defaults newstart=10, increment=10.
;   Out:       Program lines renumbered in place; every GOTO/GOSUB/THEN/etc. line reference
;              retargeted (RENUM_PATCH_LINEREFS). Returns to the READY prompt via the pushed
;              READY_POP_FRAME frame. Raises FC (Illegal function call) on overlap/overflow,
;              Syntax error on a bad increment, 'Undefined line' for references with no target.
;   Clobbers:  AF, BC, DE, HL; rewrites BASLINE.LINENUM fields and embedded line-ref tokens.
;   Algorithm: Parse up to three operands. BC := new starting line number (LINGET_DOT, default 10),
;              pushed for later reuse; DE := old starting line number (the first line to touch,
;              default 0 = top of program); when an explicit increment is given it replaces the
;              pushed BC and is validated non-zero (else FC). FNDLIN locates the old-start line and a
;              guard checks the new range does not collide with lines that stay (CMP_HL_DE, FC on
;              overlap). A first walk (STMT_RENUM_3/_4) advances the running counter by the increment
;              once per line from old-start to end-of-program, range-checking against 16-bit overflow
;              and the max-line-number ceiling $FFF9 (FC on either) WITHOUT yet writing the lines.
;              STMT_RENUM_5 then arms the line-ref flag (RENUM_PENDING_FLAG via STMT_RENUM_8+1) and
;              STMT_RENUM_6 writes the running counter into each node's BASLINE.LINENUM. Finally
;              RENUM_PATCH_LINEREFS rewrites every encoded line-number reference to its new value.
;   [RE] The split into a validating walk (RENUM_3/_4) and a storing walk (RENUM_6) is inferred from
;              the byte flow: RENUM_3/_4 only ADD HL,BC and range-check; the LD (HL),E/LD (HL),D store
;              is exclusively in RENUM_6.
; ----------------------------------------------------------------------
STMT_RENUM:
        ; default new-starting-line-number and increment are both 10 (BC, pushed and reused as the step)
        LD BC,$000A
        PUSH BC
        LD D,B
        LD E,B
        ; no operands at all: use all defaults (new start 10, old start = top of program, step 10)
        JR Z,STMT_RENUM_2
        CP $2C
        JR Z,STMT_RENUM_1
        PUSH DE
        ; parse the new starting line number (BC); '.' means the current line
        CALL LINGET_DOT
        LD B,D
        LD C,E
        POP DE
        JR Z,STMT_RENUM_2
; ----------------------------------------------------------------------
; STMT_RENUM_1 -- RENUM operand parser, second/third operand entry (',' already seen).
;   In:        HL -> the comma separating RENUM operands; stack holds the new-start number (BC).
;   Out:       DE := old-start line number; on the three-operand path BC := the increment and the
;              pushed new-start is replaced; falls into the FNDLIN range-check at STMT_RENUM_2.
;   Clobbers:  AF, BC, DE, HL.
;   Algorithm: Consume the ',' (SYNCHR), LINGET_DOT the old-start line into DE (Z = omitted ->
;              default 0). If a further ',' follows, pop the saved new-start, consume the comma,
;              and LINGET the increment (Syntax error if absent, FC if zero); shuffle the increment
;              into the pushed slot via EX (SP),HL so the later store walk still finds the new-start.
; ----------------------------------------------------------------------
STMT_RENUM_1:
        CALL SYNCHR
        DEFB    ','                      ; inline char arg consumed by the preceding CALL
        ; parse the old-start line number (first line to renumber) into DE; omitted -> 0 = top of program
        CALL LINGET_DOT
        JR Z,STMT_RENUM_2
        ; discard the placeholder; the third operand (increment) is about to be parsed and re-pushed
        POP AF
        CALL SYNCHR
        DEFB    ','                      ; inline char arg consumed by the preceding CALL
        PUSH DE
        ; parse the explicit increment into DE; it must be present and non-zero here
        CALL LINGET
        JP NZ,RAISE_SYNTAX_ERROR
        LD A,D
        OR E
        ; a zero increment is illegal (lines must stay distinct)
        JP Z,ERROR_FC
        EX DE,HL
        EX (SP),HL
        EX DE,HL
STMT_RENUM_2:
        PUSH BC
        CALL FNDLIN
        POP DE
        PUSH DE
        PUSH BC
        ; locate the old-start line; the following CMP_HL_DE guards that the new numbers won't collide with lines that keep their old numbers (FC on overlap)
        CALL FNDLIN
        LD H,B
        LD L,C
        POP DE
        CALL CMP_HL_DE
        EX DE,HL
        JP C,ERROR_FC
        POP DE
        POP BC
        POP AF
        PUSH HL
        PUSH DE
        ; begin the validating walk: advance/range-check the running counter once per line (the actual LINENUM store happens later in STMT_RENUM_6)
        JR STMT_RENUM_4
; ----------------------------------------------------------------------
; STMT_RENUM_3 / STMT_RENUM_4 -- RENUM validating walk: range-check the new line numbers without storing.
;   In:        HL -> current BASLINE node; BC = increment; DE/stack carry the running new line
;              number; entered at STMT_RENUM_4 for the first line.
;   Out:       The running counter is advanced once per line over the renumber range; on success the
;              walk falls into STMT_RENUM_5 (which arms the line-ref flag and starts the store walk).
;              No BASLINE field is written here.
;   Clobbers:  AF, BC, DE, HL.
;   Algorithm: STMT_RENUM_3 advances the running counter by the increment (FC if it carries past 16
;              bits) and guards it stays at/below the max-line-number ceiling $FFF9 (FC otherwise).
;              STMT_RENUM_4 reads the current node's BASLINE.LINK; a $0000 link ends the walk
;              (STMT_RENUM_5). The actual store of the counter into BASLINE.LINENUM happens later in
;              the STMT_RENUM_6 loop; this walk only sequences the line list and validates the range.
; ----------------------------------------------------------------------
STMT_RENUM_3:
        ; advance the running new line number by the increment
        ADD HL,BC
        JP C,ERROR_FC
        EX DE,HL
        PUSH HL
        ; ceiling check: the running line number must not exceed $FFF9 (65529), MS BASIC's maximum line number ([RE] the values above it are reserved for the direct-mode sentinel)
        LD HL,$FFF9
        CALL CMP_HL_DE
        POP HL
        JP C,ERROR_FC
STMT_RENUM_4:
        PUSH DE
        LD E,(HL)
        LD A,E
        INC HL
        LD D,(HL)
        OR D
        EX DE,HL
        POP DE
        ; BASLINE.LINK == 0: reached the end of the program text, validating walk done
        JR Z,STMT_RENUM_5
        LD A,(HL)
        INC HL
        OR (HL)
        DEC HL
        EX DE,HL
        JR NZ,STMT_RENUM_3
; ----------------------------------------------------------------------
; STMT_RENUM_5 / STMT_RENUM_6 -- RENUM store walk: write the new BASLINE.LINENUM into each line.
;   In:        Stack/registers carry the running new line number, the increment (BC), and HL ->
;              first line to renumber (recovered from the stack).
;   Out:       Every line from the start node onward has BASLINE.LINENUM := running number; running
;              number += increment per line. Ends when BASLINE.LINK == 0; falls into STMT_RENUM_7.
;   Clobbers:  AF, BC, DE, HL.
;   Algorithm: STMT_RENUM_5 first arms the line-reference patch flag (CALL STMT_RENUM_8+1, whose +1
;              entry decodes as OR $AF; LD (RENUM_PENDING_FLAG),A and so sets it nonzero), then
;              restores the new-number/increment/start-node off the stack. STMT_RENUM_6 walks the
;              line list: at each node read BASLINE.LINK (stop on $0000), write the running new number
;              into the node's BASLINE.LINENUM (the two bytes after the link), add the increment, and
;              follow the link.
;   [RE] STMT_RENUM_8+1 is a coded-overlap dual entry: the byte pair $F6 $AF at STMT_RENUM_8/+0..+1
;              reads as CP $F6 on the clear (fall-through) path; entering at +1 runs $F6 $AF as
;              OR $AF, setting RENUM_PENDING_FLAG nonzero.
; ----------------------------------------------------------------------
STMT_RENUM_5:
        PUSH BC
        ; arm the pending-line-reference flag (RENUM_PENDING_FLAG := nonzero) so the patch pass will run after relinking
        CALL STMT_RENUM_8+1
        POP BC
        POP DE
        POP HL
STMT_RENUM_6:
        PUSH DE
        LD E,(HL)
        LD A,E
        INC HL
        LD D,(HL)
        OR D
        ; BASLINE.LINK == 0: all lines renumbered, proceed to the reference-patch pass
        JR Z,STMT_RENUM_7
        EX DE,HL
        EX (SP),HL
        EX DE,HL
        INC HL
        ; store the new line number into this node's BASLINE.LINENUM (low byte then high)
        LD (HL),E
        INC HL
        LD (HL),D
        EX DE,HL
        ; advance the running new line number by the increment for the next line
        ADD HL,BC
        EX DE,HL
        POP HL
        JR STMT_RENUM_6
; ----------------------------------------------------------------------
; STMT_RENUM_7 -- RENUM tail: arm the return-to-READY frame, then fall into the line-reference patch.
;   In:        Line renumbering complete; the program's BASLINE.LINENUM fields are updated.
;   Out:       Pushes READY_POP_FRAME so RENUM_PATCH_LINEREFS returns to the Ok/READY prompt; falls
;              into STMT_RENUM_8 / RENUM_PATCH_LINEREFS.
;   Clobbers:  BC (the pushed return address).
;   Algorithm: Push READY_POP_FRAME as the eventual return target, then fall into the coded-overlap
;              dual entry STMT_RENUM_8 (the $F6 operand byte of CP $F6 is absorbed on this path, then
;              RENUM_PATCH_LINEREFS clears RENUM_PENDING_FLAG and rewrites every encoded line-number
;              reference to its renumbered target).
; ----------------------------------------------------------------------
STMT_RENUM_7:
        ; after the reference patch completes, fall back to the Ok/READY prompt
        LD BC,READY_POP_FRAME
        PUSH BC
; [RE] Flag-skip into RENUM line-ref pass setup. FE F6 = CP $F6: fall-through (from PUSH BC at $436F) absorbs F6 and runs XOR A; LD ($0B56),A = clear the pending-refs flag. CALL STMT_RENUM_8+1 ($4351) re-decodes F6 AF as OR $AF; LD ($0B56),A = set the flag nonzero. $0B56 read at $438A / gated at $440B drives RENUM_PATCH_LINEREFS. Independently verified; MBASIC twin confirms.
STMT_RENUM_8:
        CP $F6
; [RE] RENUM pass 2: walk every program line, find line-number references after GOTO/GOSUB/THEN tokens ($A4/$0E markers), translate each old line number to its new value (LINGET_TOKLINE lookup) and rewrite the 3-byte encoded line-number token in place; reports 'Undefined line' for missing targets.
RENUM_PATCH_LINEREFS:
        XOR A
        LD (RENUM_PENDING_FLAG),A
        LD HL,(TXTTAB)
        DEC HL
RENUM_PATCH_LINEREFS_1:
        INC HL
        LD A,(HL)
        INC HL
        OR (HL)
        RET Z
        INC HL
        LD E,(HL)
        INC HL
        LD D,(HL)
RENUM_PATCH_LINEREFS_2:
        CALL CHRGET
RENUM_PATCH_LINEREFS_3:
        OR A
        JR Z,RENUM_PATCH_LINEREFS_1
        LD C,A
        LD A,(RENUM_PENDING_FLAG)
        OR A
        LD A,C
        JR Z,RENUM_PATCH_LINEREFS_8
        CP $A4
        JR NZ,RENUM_PATCH_LINEREFS_4
        CALL CHRGET
        CP TOK_GOTO
        JR NZ,RENUM_PATCH_LINEREFS_3
        CALL CHRGET
        CP $0E
        JR NZ,RENUM_PATCH_LINEREFS_3
        PUSH DE
        CALL LINGET_TOKLINE
        LD A,D
        OR E
        JR NZ,RENUM_PATCH_LINEREFS_5
        JR RENUM_PATCH_LINEREFS_7
RENUM_PATCH_LINEREFS_4:
        CP $0E
        JR NZ,RENUM_PATCH_LINEREFS_2
        PUSH DE
        CALL LINGET_TOKLINE
RENUM_PATCH_LINEREFS_5:
        PUSH HL
        CALL FNDLIN
        DEC BC
        LD A,$0D
        JR C,RENUM_PATCH_LINEREFS_9
        CALL PRINT_CRLF_IF_COL
        LD HL,MSG_UNDEFINED_LINE
        PUSH DE
        CALL STROUT
        POP HL
        CALL FOUT
        POP BC
        POP HL
        PUSH HL
        PUSH BC
        CALL PRINT_IN_LINENO
RENUM_PATCH_LINEREFS_6:
        POP HL
RENUM_PATCH_LINEREFS_7:
        POP DE
        DEC HL
        JR RENUM_PATCH_LINEREFS_2
; Data string 'Undefined line ' (+NUL) printed by the RENUM/line-reference checker (loaded at $43C1, emitted via STROUT) before the offending line number
MSG_UNDEFINED_LINE:
        DEFB    "Undefined line "        ; string
        DEFB    $00                      ; terminator
RENUM_PATCH_LINEREFS_8:
        CP $0D
        JP NZ,RENUM_PATCH_LINEREFS_2
        PUSH DE
        CALL LINGET_TOKLINE
        PUSH HL
        EX DE,HL
        INC HL
        INC HL
        INC HL
        LD C,(HL)
        INC HL
        LD B,(HL)
        LD A,$0E
RENUM_PATCH_LINEREFS_9:
        LD HL,RENUM_PATCH_LINEREFS_6
        PUSH HL
        LD HL,(CONST_TEXT_RESUME)
; [RE] Write the 3-byte encoded line-number token (marker A, line# in BC) backward into the program text just before the pointer in $0B17.
RENUM_STORE_LINEREF:
        PUSH HL
        DEC HL
        LD (HL),B
        DEC HL
        LD (HL),C
        DEC HL
        LD (HL),A
        POP HL
        RET
; [RE] If the renumber-pending flag $0B56 is set, run the line-reference fix-up pass (RENUM_PATCH_LINEREFS); otherwise return. Called after DELETE edits the program.
RENUM_FIXUP_IF_PENDING:
        LD A,(RENUM_PENDING_FLAG)
        OR A
        RET Z
        JP RENUM_PATCH_LINEREFS
; ----------------------------------------------------------------------
; STMT_OPTION -- OPTION statement handler (token $B5): set the array lower bound, OPTION BASE 0|1.
;   In:        HL -> text just past the OPTION token (expects the letters BASE then a 0/1 digit).
;   Out:       OPTION_BASE_VALUE := 0 or 1; OPTION_BASE_SET_FLAG := value+1 (now nonzero = 'BASE
;              has been set'). HL advanced past the digit. RET.
;   Clobbers:  AF, DE, HL.
;   Algorithm: Match the literal keyword 'BASE' (four SYNCHR character checks). Reject a second
;              OPTION BASE: 'Duplicate Definition' if OPTION_BASE_SET_FLAG is already set, OR if any
;              array has been dimensioned (ARYTAB != STREND, i.e. array space is non-empty -- BASE
;              must come before any array use). Read the bound digit, require '0' or '1' (Syntax
;              error otherwise), store it as OPTION_BASE_VALUE, and mark it set (value+1).
; ----------------------------------------------------------------------
STMT_OPTION:
        CALL SYNCHR
        DEFB    'B'                      ; inline char arg consumed by the preceding CALL
        CALL SYNCHR
        DEFB    'A'                      ; inline char arg consumed by the preceding CALL
        CALL SYNCHR
        DEFB    'S'                      ; inline char arg consumed by the preceding CALL
        CALL SYNCHR
        DEFB    'E'                      ; inline char arg consumed by the preceding CALL
        ; OPTION BASE may be set only once: reject a repeat
        LD A,(OPTION_BASE_SET_FLAG)
        OR A
        JP NZ,RAISE_DUPLICATE_DEFINITION
        PUSH HL
        ; and only before any array exists: ARYTAB != STREND means array space is non-empty -> too late, Duplicate Definition
        LD HL,(ARYTAB)
        EX DE,HL
        LD HL,(STREND)
        CALL CMP_HL_DE
        JP NZ,RAISE_DUPLICATE_DEFINITION
        POP HL
        LD A,(HL)
        ; convert the ASCII digit to 0/1; reject anything outside [0,1] as a Syntax error
        SUB $30
        JP C,RAISE_SYNTAX_ERROR
        CP $02
        JP NC,RAISE_SYNTAX_ERROR
        ; record the lower bound (0 or 1) and mark BASE as set (store value+1 into the set-flag)
        LD (OPTION_BASE_VALUE),A
        INC A
        LD (OPTION_BASE_SET_FLAG),A
        CALL CHRGET
        RET
; ----------------------------------------------------------------------
; STROUT_NOFLAGS -- print a $00-terminated string at (HL) to the console, character by character.
;   In:        HL -> first byte of a NUL-terminated string.
;   Out:       The whole string emitted through STROUT_PUTC -> OUTDO_WIDTH_1 (console engine); HL left at the
;              terminating $00.
;   Clobbers:  A, HL, flags (BC/DE preserved by the OUTDO_WIDTH_1/OUTDO_DEVICE2 path).
;   Algorithm: Walk the string: fetch (HL); a $00 byte ends the loop with an immediate return; otherwise emit
;              the character via STROUT_PUTC, advance HL, and repeat. A raw-channel string printer that leans on
;              the OUTDO_WIDTH_1 console core (it makes no PRTFLG/file routing decision of its own).
; ----------------------------------------------------------------------
STROUT_NOFLAGS:
        LD A,(HL)
        ; stop at the NUL terminator
        OR A
        RET Z
        CALL STROUT_PUTC
        INC HL
        JP STROUT_NOFLAGS
; ----------------------------------------------------------------------
; STROUT_PUTC -- emit one character to the console output engine, preserving the character on the stack.
;   In:        A = character to print.
;   Out:       Character emitted via the console engine OUTDO_WIDTH_1; the pushed AF is recovered by that
;              engine (its POP AF, which runs AFTER the Ctrl-O suppress test, or by GETSPA_2's POP AF on the
;              suppress path).
;   Clobbers:  Per OUTDO_WIDTH_1 (BC/DE saved/restored by it / OUTDO_DEVICE2).
;   Algorithm: Pushes AF so the char survives, then tail-jumps into OUTDO_WIDTH_1; that engine first tests
;              Ctrl-O suppression and only then pops AF as its working character. The single-character feeder
;              used by STROUT_NOFLAGS. NOTE: OUTDO_WIDTH_1 does NOT begin with POP AF -- the pop is its 4th
;              instruction (after LD A,(CTRL_O_SUPPRESS)/OR A/JP NZ,GETSPA_2).
; ----------------------------------------------------------------------
STROUT_PUTC:
        ; stash the char; OUTDO_WIDTH_1 recovers it with its POP AF (after the Ctrl-O test), or GETSPA_2 pops it if suppressed
        PUSH AF
        JP OUTDO_WIDTH_1
; ----------------------------------------------------------------------
; STMT_RANDOMIZE -- RANDOMIZE statement handler (token $B6): reseed the RND generator.
;   In:        HL -> text just past the RANDOMIZE token; Z set if no seed expression follows.
;   Out:       The user seed is injected into the RND state's mantissa bytes (via STMT_RANDOMIZE_3)
;              and the generator is advanced/reseeded (RND_SEED_RESET). HL restored. RET.
;   Clobbers:  AF, BC, DE, HL, FAC; updates the RND seed state.
;   Algorithm: If an argument is present, FRMEVL_NOPAREN it and FN_CINT it to a signed 16-bit integer
;              in HL. If absent, prompt interactively (STMT_RANDOMIZE_1/_2). Either way join at
;              STMT_RANDOMIZE_3 which stores HL into RNDX_SEED_WORD (overwriting two of the RND
;              state's upper mantissa bytes) and calls RND_SEED_RESET to fold the generator forward.
; ----------------------------------------------------------------------
STMT_RANDOMIZE:
        ; no seed given: drop into the interactive 'Random number seed' prompt
        JR Z,STMT_RANDOMIZE_1
        ; evaluate the supplied seed expression
        CALL FRMEVL_NOPAREN
        PUSH HL
        ; coerce the seed to a signed 16-bit integer (HL)
        CALL FN_CINT
        JR STMT_RANDOMIZE_3
; ----------------------------------------------------------------------
; STMT_RANDOMIZE_1 / STMT_RANDOMIZE_2 -- interactive RANDOMIZE seed prompt loop.
;   In:        HL preserved (pushed); reached when RANDOMIZE was typed with no argument.
;   Out:       HL = the entered seed as a signed 16-bit integer; falls into STMT_RANDOMIZE_3 to
;              store it. If the input line was aborted (QINLIN carry), branches to STMT_END_2+1
;              to break to direct mode.
;   Clobbers:  AF, BC, DE, HL, FAC.
;   Algorithm: Print MSG_RANDOMIZE_PROMPT ('Random number seed (-32768 to 32767)') via STROUT and
;              read a console line with QINLIN. On Ctrl-C/abort (carry) jump to the break path.
;              Parse the typed text as a numeric constant into the FAC (FIN_1+1); if any non-numeric
;              trailing character remains, re-prompt. Otherwise FN_CINT the value to a 16-bit integer
;              in HL and continue.
; ----------------------------------------------------------------------
STMT_RANDOMIZE_1:
        PUSH HL
STMT_RANDOMIZE_2:
        ; show the 'Random number seed (-32768 to 32767)' prompt and read a console line
        LD HL,MSG_RANDOMIZE_PROMPT
        CALL STROUT
        CALL QINLIN
        POP DE
        ; input aborted (Ctrl-C): break to direct mode (the +1 entry runs OR $FF, flagging A=$FF break)
        JP C,STMT_END_2+1
        PUSH DE
        INC HL
        LD A,(HL)
        ; parse the typed text into the FAC as a numeric constant (the +1 entry pre-seeds FAC=0 as an integer)
        CALL FIN_1+1
        LD A,(HL)
        OR A
        ; trailing non-numeric junk after the number: reject and re-prompt
        JR NZ,STMT_RANDOMIZE_2
        CALL FN_CINT
; ----------------------------------------------------------------------
; STMT_RANDOMIZE_3 -- store the new RND seed and reseed the generator.
;   In:        HL = the 16-bit seed value (from the expression or the prompt); a caller HL was
;              pushed earlier.
;   Out:       RNDX_SEED_WORD := HL (2 bytes); RND state advanced/reseeded via RND_SEED_RESET;
;              caller HL restored. RET.
;   Clobbers:  AF, BC, DE, FAC; HL restored from the stack.
;   Algorithm: Write the 16-bit HL into RNDX_SEED_WORD ([RE] this cell is the start of the RND
;              state's upper mantissa bytes at $5E25, so the store overwrites two of those bytes and
;              perturbs the running seed), call RND_SEED_RESET (which loads the constant 1.0 and folds
;              it through FN_RND to advance/reseed the generator), then pop the saved text-pointer HL
;              and return.
; ----------------------------------------------------------------------
STMT_RANDOMIZE_3:
        ; inject the user seed (2 bytes) into the upper mantissa bytes of the RND state
        LD (RNDX_SEED_WORD),HL
        ; fold the constant 1.0 through FN_RND to advance/reseed the generator with the new seed in place
        CALL RND_SEED_RESET
        POP HL
        RET
; Data string 'Random number seed (-32768- to 32767)' (with a $08 backspace splice) -- the interactive RANDOMIZE prompt emitted by STMT_RANDOMIZE via STROUT/QINLIN
MSG_RANDOMIZE_PROMPT:
        DEFB    "Random number seed (-32768-"  ; string
        DEFB    $08
        DEFB    " to 32767)"             ; string
        DEFB    $00                      ; terminator
; ----------------------------------------------------------------------
; BLOCK_SCAN_WHILE -- enter the structured-block scanner configured for WHILE/WEND.
;   In:        HL -> crunched program text just after the WHILE token (the loop condition);
;              SAVTXT holds the current source-line pointer.
;   Out:       Same contract as BLOCK_SCAN_FORNEXT: returns with HL at the matching WEND ($B0)
;              at nesting depth 0 and L_0C71 = the start of that line, or raises WHILE without
;              WEND (err 29) at the end of the program.
;   Clobbers:  AF, BC, DE, HL (see BLOCK_SCAN_FORNEXT).
;   Algorithm: Set the mode/error byte C = $1D (= ERR_WHILE_WITHOUT_WEND, 29) and fall into the
;              shared scanner, which uses C both to select the WHILE=$AF / WEND=$B0 token pair
;              to balance and to name the error if the program text runs out first.
; ----------------------------------------------------------------------
BLOCK_SCAN_WHILE:
        LD C,$1D
        JR BLOCK_SCAN_INIT
; ----------------------------------------------------------------------
; BLOCK_SCAN_FORNEXT -- forward-scan crunched program text for the block-closing keyword that
; matches an opening FOR/WHILE, balancing nested blocks; entered here for FOR/NEXT.
;   In:        HL -> crunched program text just after the opening keyword (the part already
;              parsed by STMT_FOR / STMT_WHILE). SAVTXT = pointer to the current source line
;              (read once at entry into L_0C71).
;   Out:       On success: returns with HL pointing at the matching close keyword (NEXT $83 /
;              WEND $B0) found at nesting depth 0, and L_0C71 = the start (link field) of the
;              line that holds it, so the caller can adopt L_0C71 as SAVTXT. On failure
;              (program text exhausted before a match): LD E,C / JP Z,RAISE_ERROR raises the
;              missing-terminator error and does not return.
;   Clobbers:  AF, BC, DE, HL; updates L_0C71; temporarily repoints SAVTXT during the
;              NEXT-variable PTRGET sub-scan (restored before each iteration).
;   Mode byte: The entry point you CALL selects C, which is BOTH the open/close token pair to
;              balance AND the error code raised on run-off: BLOCK_SCAN_FORNEXT sets C=$1A
;              (FOR $82 / NEXT $83; err 26 FOR without NEXT); BLOCK_SCAN_WHILE sets C=$1D
;              (WHILE $AF / WEND $B0; err 29 WHILE without WEND). C is thus an internal input to
;              the shared body (BLOCK_SCAN_INIT), not a caller-supplied register.
;   Algorithm: B = nesting depth. Walk statement by statement: CHRGET to the next statement
;              separator (end-of-line $00, ELSE $9E, or THEN $DE); on end-of-line, follow the
;              2-byte line LINK to the next line (a 0000 link raises the run-off error) and
;              record the new line start in L_0C71. At each statement head inspect the leading
;              token: an opening keyword (FOR/WHILE) increments depth; a closing keyword
;              (NEXT/WEND) decrements it and returns once depth reaches 0. A NEXT that closes an
;              inner FOR may carry a variable list, so when depth is still nonzero the routine
;              PTRGETs the loop variable(s) (temporarily using L_0C71 as SAVTXT) and, on a
;              comma, loops to consume the next variable before resuming the scan.
; ----------------------------------------------------------------------
BLOCK_SCAN_FORNEXT:
        ; FOR/NEXT mode: C=$1A both selects the FOR $82 / NEXT $83 token pair and doubles as ERR_FOR_WITHOUT_NEXT (26) if the program text runs out.
        LD C,$1A
BLOCK_SCAN_INIT:
        LD B,$00
        EX DE,HL
        ; Snapshot the current source-line start into L_0C71; it is re-updated each time the scan follows a line link.
        LD HL,(SAVTXT)
        LD (L_0C71),HL
        EX DE,HL
BLOCK_SCAN_PUSH_DEPTH:
        ; Entering a nested block of the same kind (FOR/WHILE): deepen the nesting count.
        INC B
BLOCK_SCAN_NEXT_CHAR:
        DEC HL
BLOCK_SCAN_TO_SEP:
        CALL CHRGET
        JR Z,BLOCK_SCAN_AT_SEP
        ; Statement separators inside a line: ELSE and THEN start a new sub-statement to inspect, like end-of-line.
        CP TOK_ELSE
        JR Z,BLOCK_SCAN_AT_STMT_HEAD
        CP TOK_THEN
        JR NZ,BLOCK_SCAN_TO_SEP
BLOCK_SCAN_AT_SEP:
        OR A
        JR NZ,BLOCK_SCAN_AT_STMT_HEAD
        ; End of line reached: follow the 2-byte line LINK; a 0000 link means the program ended with no match -> raise the (FOR/WHILE)-without-(NEXT/WEND) error.
        INC HL
        LD A,(HL)
        INC HL
        OR (HL)
        ; Run off the end of the program: E = C = the mode's missing-terminator error code, then RAISE_ERROR.
        LD E,C
        JP Z,RAISE_ERROR
        INC HL
        ; Adopt the linked line as the new scan position; its start is recorded in L_0C71 just below.
        LD E,(HL)
        INC HL
        LD D,(HL)
        EX DE,HL
        LD (L_0C71),HL
        EX DE,HL
BLOCK_SCAN_AT_STMT_HEAD:
        CALL CHRGET
        ; Branch on mode: C=$1A takes the FOR/NEXT ($82/$83) token tests, otherwise the WHILE/WEND ($AF/$B0) tests.
        LD A,C
        CP $1A
        LD A,(HL)
        JR Z,BLOCK_SCAN_FORNEXT_TOKEN
        CP $AF
        JR Z,BLOCK_SCAN_PUSH_DEPTH
        CP $B0
        JR NZ,BLOCK_SCAN_NEXT_CHAR
        ; WEND seen: DEC B drops one nesting level; if depth is now 0 this is the matching WEND -> fall through to RET, else keep scanning.
        DJNZ BLOCK_SCAN_NEXT_CHAR
        RET
BLOCK_SCAN_FORNEXT_TOKEN:
        ; FOR opens a nested loop -> deepen; NEXT ($83) closes one -> fall into the close-depth handler.
        CP $82
        JR Z,BLOCK_SCAN_PUSH_DEPTH
        CP $83
        JR NZ,BLOCK_SCAN_NEXT_CHAR
BLOCK_SCAN_CLOSE_DEPTH:
        ; NEXT closes a level: if it balances to 0 this is our matching NEXT -> RET; otherwise it closes an inner FOR and may list variables.
        DEC B
        RET Z
        CALL CHRGET
        JR Z,BLOCK_SCAN_AT_SEP
        EX DE,HL
        LD HL,(SAVTXT)
        PUSH HL
        LD HL,(L_0C71)
        LD (SAVTXT),HL
        EX DE,HL
        PUSH BC
        ; Resolve the inner NEXT's loop variable (SAVTXT temporarily points at this line) so a variable list is skipped over correctly.
        CALL PTRGET_1+1
        POP BC
        DEC HL
        CALL CHRGET
BLOCK_SCAN_NEXTVAR_TAIL:
        LD DE,BLOCK_SCAN_AT_SEP
        JR Z,BLOCK_SCAN_NEXTVAR_RESUME
        ; After a NEXT variable, a non-end char must be ',': SYNCHR ',' validates it, then the routine loops to read the next variable.
        CALL SYNCHR
        DEFB    ','                      ; inline char arg consumed by the preceding CALL
        DEC HL
        LD DE,BLOCK_SCAN_CLOSE_DEPTH
BLOCK_SCAN_NEXTVAR_RESUME:
        ; Restore SAVTXT and tail-jump (via the pushed DE continuation) back into the main scan.
        EX (SP),HL
        LD (SAVTXT),HL
        POP HL
        PUSH DE
        RET
FIN_EPILOGUE_SNAPSHOT_EVAL_FLAG:
        PUSH AF
        LD A,(L_0CB6)
        LD (L_0CB7),A
        POP AF

; ======================================================================
; GRAPHICS + TEXT-SCREEN STATEMENTS and the 6502 RPC PATH (SoftCard superset)  ---  Apple soft-switches reached as $E0xx (Z-80 $E000-$EFFF == Apple $C000-$CFFF); Apple monitor-ROM calls reached by the 6502 RPC (A$VEC=$F3D0, Z$CPU=$F3DE, SLTTYP+2=$F3BB).  Handlers $45xx-$4Bxx; dispatch table $0194-$01B0.
; ======================================================================
; ----------------------------------------------------------------------
; CLEAR_EVAL_FLAG_0CB6 -- zero the $0CB6 floating-point / numeric-eval state flag.
;   In:        (none)
;   Out:       byte at $0CB6 = 0; A and flags preserved (PUSH AF / POP AF bracket the write)
;   Clobbers:  nothing visible to the caller
;   Algorithm: Zero the cell at $0CB6. [RE] This is NOT a graphics/screen routine despite its
;              physical location among the GFX statements and its prior name. Every observed use
;              of $0CB6 is floating-point / numeric-eval STATE: FIN (the number parser) sets it
;              to 1 then tests 0/1/2; the '^'/power path (FN_SQR) pushes THIS routine as its
;              return and sets $0CB6=1; the FRMEVL operator scan clears it (the file's own
;              comments there call it 'the FP sign flag' / 'function-evaluation-in-progress
;              flag'); and RESET_RUN_STATE calls this to clear it on RUN/error unwind. No code
;              path ties $0CB6 to a console reverse/INVERSE attribute -- the 'screen reverse'
;              reading is UNKNOWN/unsupported. So this is a generic 'clear the eval state flag'
;              helper, called from the run-state reset and used as a tail-return by the FP
;              power routine.
; ----------------------------------------------------------------------
CLEAR_EVAL_FLAG_0CB6:
        PUSH AF
        XOR A
        LD (L_0CB6),A
        POP AF
        RET
; ----------------------------------------------------------------------
; GFX_STMT_VTAB -- VTAB statement handler (token $C8, dispatch slot $0196): set the text cursor ROW and reposition.
;   In:        HL -> BASIC text just past the VTAB token; the row expression follows
;   Out:       CURSOR_ROW ($0B12) = (row-1) mod PAGE_LENGTH; cursor repositioned on the console
;              via SCREEN_POS_FROM_TABLE; HL restored to post-expression text; A,DE clobbered
;   Clobbers:  A, DE, HL (saved/restored), the row cell $0B12
;   Algorithm: Evaluate the 1-based row operand (GFX_GET_BYTE_ARG returns row-1, 0-based).
;              Reduce it modulo PAGE_LENGTH ($083C, lines-per-page, default 24) with the classic
;              repeated-subtract-then-add-back idiom, store the wrapped row in CURSOR_ROW, then
;              call SCREEN_POS_FROM_TABLE to emit the new cursor position to the terminal.
; ----------------------------------------------------------------------
GFX_STMT_VTAB:
        CALL GFX_GET_BYTE_ARG
        PUSH HL
        ; reduce the 0-based row modulo the page length (lines-per-screen) so it wraps into range
        LD HL,PAGE_LENGTH
GFX_STMT_VTAB_1:
        SUB (HL)
        JP P,GFX_STMT_VTAB_1
        ADD A,(HL)
        ; store the wrapped row in the cursor-row cell
        LD (CURSOR_ROW),A
GFX_STMT_VTAB_2:
        ; emit the Address-Cursor sequence so the terminal moves to the new row/column
        CALL SCREEN_POS_FROM_TABLE
        POP HL
        RET
; ----------------------------------------------------------------------
; SCREEN_POS_FROM_TABLE -- emit the SoftCard 'Address Cursor' sequence to move the terminal cursor to (col,row).
;   In:        $0B11 = cursor column (CURSOR_COL), $0B12 = cursor row (CURSOR_ROW) -- the two bytes
;              form the LD HL,($0B11) word (L=col, H=row); SXYOFF ($F396) = cursor-XY coordinate
;              offset, low 7 bits = origin bias, bit7 = transmit order; screen-function table
;              entry fn7 at $F39E reached via SCREEN_POS_EMIT
;   Out:       fn7 (Address Cursor, optional lead-in) then the two offset-biased coordinate bytes
;              sent to the console via OUTDO_DEVICE2 (char in A); A,HL,DE clobbered
;   Clobbers:  A, HL, DE
;   Algorithm: First emit screen-function #7 (Address Cursor) via SCREEN_POS_EMIT (E=7). Load
;              (col,row) into HL (L=col, H=row), read SXYOFF: if bit7=0 send Y(row) first then
;              X(col); if bit7=1 swap H<->L so X(col) is sent first then Y(row). Bias each
;              coordinate by the low-7-bit offset and emit the two adjusted bytes in that order
;              via OUTDO_DEVICE2. Implements the GOTOXY/cursor-addressing protocol of the I/O
;              Configuration Block [DOC software-and-hardware-details 2-14].
; ----------------------------------------------------------------------
SCREEN_POS_FROM_TABLE:
        ; screen function 7 = Address Cursor: emit its lead-in/code before the coordinates
        LD E,$07
        CALL SCREEN_POS_EMIT
        ; load the cursor position: L = column ($0B11), H = row ($0B12)
        LD HL,(CURSOR_POS)
        LD A,(SXYOFF)
        OR A
        ; SXYOFF bit7: clear => send Y(row) then X(col); set => swap to send X(col) then Y(row)
        JP P,SCREEN_POS_FROM_TABLE_1
        AND $7F
        ; bit7 set: swap H<->L so the column is the first coordinate transmitted
        LD E,L
        LD L,H
        LD H,E
SCREEN_POS_FROM_TABLE_1:
        LD E,A
        ; bias each coordinate by the terminal's XY offset before sending
        ADD A,L
        LD L,A
        LD A,E
        ADD A,H
        PUSH HL
        ; send the first coordinate byte (in A) to the console
        CALL OUTDO_DEVICE2
        POP HL
        LD A,L
        ; tail-emit the second coordinate byte (in A) through the same console-output vector
        JR SCREEN_POS_EMIT_1
; ----------------------------------------------------------------------
; SCREEN_POS_EMIT -- emit one SoftCard screen-control function (number in E) to the console.
;   In:        E = screen-function number 1..9 (1=Clear Screen, 4=Set Normal, 5=Set Inverse,
;              7=Address Cursor, ... per the Software Screen Function Table); the function byte
;              is at SSFTAB-1+E = SFLDIN($F397)+E; SFLDIN holds the table's lead-in char
;   Out:       the function's terminal sequence (optional lead-in + 7-bit function byte) sent via
;              OUTDO_DEVICE2; returns with NO output if the table byte is 0
;   Clobbers:  A, D, HL (E preserved; PUSH AF/POP AF brackets the lead-in; tail-jumps to OUTDO_DEVICE2)
;   Algorithm: Index the screen-function table by E (D=0, ADD HL,DE) to fetch the terminal byte
;              for that function. A zero byte means 'function not implemented' -> RET without
;              emitting. If the byte's high bit is set the function needs a lead-in: send SFLDIN
;              first, then tail-jump to OUTDO_DEVICE2 with the function byte masked to 7 bits.
;              Otherwise tail-jump straight to OUTDO_DEVICE2 [DOC software-and-hardware-details 2-14..2-15].
; ----------------------------------------------------------------------
SCREEN_POS_EMIT:
        LD D,$00
        ; index the software screen-function table (SSFTAB-1 = SFLDIN) by the function number in DE
        LD HL,SFLDIN
        ADD HL,DE
        LD A,(HL)
        OR A
        ; a zero table entry means this screen function is not implemented on this terminal -- do nothing
        RET Z
        ; high bit set => a lead-in char is required before the function byte
        JP P,SCREEN_POS_EMIT_1
        AND $7F
        PUSH AF
        ; emit the lead-in character first
        LD A,(SFLDIN)
        CALL OUTDO_DEVICE2
        POP AF
SCREEN_POS_EMIT_1:
        ; send the function byte (in A) to the console (tail call)
        JP OUTDO_DEVICE2
; ----------------------------------------------------------------------
; GFX_GET_BYTE_ARG -- evaluate the next expression as a 1-based byte and return it 0-based.
;   In:        HL -> BASIC text at the operand expression
;   Out:       A = (value - 1); HL advanced past the expression (via GETBYT/CONINT). Raises
;              'Illegal function call' (ERROR_FC, $34D0) if the value is 0
;   Clobbers:  A, plus whatever GETBYT/FRMEVL clobbers (BC, DE, HL, FAC); HL ends past the operand
;   Algorithm: Call GETBYT to evaluate the expression and range-check it to 0..255. Reject 0
;              with the FC error, then decrement so a 1-based BASIC coordinate (VTAB/HTAB use
;              1-based rows/columns) becomes the 0-based internal coordinate. Shared operand
;              fetch for the VTAB and HTAB cursor statements.
; ----------------------------------------------------------------------
GFX_GET_BYTE_ARG:
        CALL GETBYT
        OR A
        ; VTAB/HTAB are 1-based: position 0 is out of range -> Illegal function call
        JP Z,ERROR_FC
        ; convert the 1-based coordinate to the 0-based internal value
        DEC A
        RET
; ----------------------------------------------------------------------
; GFX_STMT_HTAB -- HTAB statement handler (token $C9, dispatch slot $0198): set the text cursor COLUMN and reposition.
;   In:        HL -> BASIC text just past the HTAB token; the column expression follows
;   Out:       CURSOR_COL ($0B11) = (col-1) mod PRINT_WIDTH; cursor repositioned on the console;
;              HL restored past the expression; A,DE clobbered
;   Clobbers:  A, DE, HL (saved/restored), the column cell $0B11
;   Algorithm: Evaluate the 1-based column (GFX_GET_BYTE_ARG -> col-1), reduce it modulo
;              PRINT_WIDTH ($083B, default 80) with the repeated-subtract/add-back idiom, store
;              the wrapped column in CURSOR_COL, then FALL THROUGH (no return) into the
;              CURSOR_REPOSITION thunk at the next address ('JR GFX_STMT_VTAB_2'), which CALLs
;              SCREEN_POS_FROM_TABLE and then POP HL / RET -- balancing this routine's own
;              PUSH HL. So HTAB does physically move the terminal cursor.
; ----------------------------------------------------------------------
GFX_STMT_HTAB:
        CALL GFX_GET_BYTE_ARG
        PUSH HL
        ; reduce the 0-based column modulo the output line width so it wraps into range
        LD HL,PRINT_WIDTH
GFX_STMT_HTAB_1:
        SUB (HL)
        JP P,GFX_STMT_HTAB_1
        ADD A,(HL)
        ; store the wrapped column in the cursor-column cell, then fall into CURSOR_REPOSITION to move the terminal cursor
        LD (CURSOR_POS),A
; ----------------------------------------------------------------------
; CURSOR_REPOSITION -- shared 'reposition the terminal cursor' tail: JR into GFX_STMT_VTAB_2.
;   In:        $0B11/$0B12 (CURSOR_COL/CURSOR_ROW) already set to the desired (col,row); the caller
;              has a matching PUSH HL outstanding (HTAB's PUSH HL, or the TEXT handler's PUSH HL)
;   Out:       jumps to GFX_STMT_VTAB_2 (CALL SCREEN_POS_FROM_TABLE; POP HL; RET): emits the
;              Address-Cursor sequence then returns to the statement handler's caller
;   Clobbers:  A, DE, HL (via SCREEN_POS_FROM_TABLE)
;   Algorithm: A 2-byte 'JR GFX_STMT_VTAB_2' thunk. It is NOT the HOME statement dispatch target
;              (that is GFX_STMT_HOME at the next address, $45A8). It is reached two ways: (1) by
;              FALL-THROUGH from GFX_STMT_HTAB after HTAB stores the column -- this is HTAB's
;              normal completion, so HTAB DOES reposition; and (2) by an explicit 'JR CURSOR_REPOSITION'
;              from the tail of the TEXT statement handler after it resets the cursor cells and
;              exits graphics mode. Either way it re-emits the cursor position once.
; ----------------------------------------------------------------------
CURSOR_REPOSITION:
        JR GFX_STMT_VTAB_2
; ----------------------------------------------------------------------
; GFX_STMT_HOME -- HOME statement handler (token $C7, dispatch slot $0194 -> $45A8): clear screen and home cursor.
;   In:        HL -> BASIC text (no operand); also called internally (e.g. the sign-on path at
;              $83D2 before printing the banner) as a plain 'clear and home' subroutine
;   Out:       $0B11/$0B12 (CURSOR_COL,CURSOR_ROW) = 0,0; screen-function #1 (Clear Screen) emitted
;              to the terminal; HL preserved
;   Clobbers:  A, BC, DE, E (E=1 selects fn1); HL saved/restored
;   Algorithm: Zero the 16-bit cursor word ($0B11=col, $0B12=row) so the BASIC notion of the
;              cursor is home, set E=1, then fall through STMT_INVERSE/_2 (whose LD BC,$051E /
;              LD BC,$041E cover bytes clobber BC but leave E=1 on this path) into the shared
;              tail PUSH HL / CALL SCREEN_POS_EMIT / POP HL / RET, which sends the terminal's
;              Clear-Screen sequence. Net effect: clear the text screen and home the cursor.
; ----------------------------------------------------------------------
GFX_STMT_HOME:
        PUSH HL
        LD HL,$0000
        ; reset the BASIC cursor position (column low $0B11, row high $0B12) to home (0,0)
        LD (CURSOR_POS),HL
        POP HL
        ; select screen function 1 = Clear Screen for the shared SCREEN_POS_EMIT tail
        LD E,$01
; ----------------------------------------------------------------------
; STMT_INVERSE -- (entered at +1) INVERSE statement handler (token $CA, dispatch slot $019A).
;   In:        HL -> BASIC text (no operand); reached via DEFW STMT_INVERSE+1 = $019A -> $45B3
;   Out:       screen-function #5 (Set Inverse / high-light text mode) emitted to the terminal;
;              HL preserved
;   Clobbers:  A, D, E (=5); HL saved/restored
;   Algorithm: Classic LD-BC-cover overlap idiom. The assembled bytes 01 1E 05 read as
;              'LD BC,$051E' on fall-through from the HOME path (which keeps E=1), but the
;              dispatch slot $019A enters one byte in, at '1E 05' = 'LD E,$05', selecting screen
;              function 5 (Set Inverse text mode). It then shares the common tail (PUSH HL; CALL
;              SCREEN_POS_EMIT; POP HL; RET) that emits the function. Verified against the MBASIC twin.
; ----------------------------------------------------------------------
STMT_INVERSE:
        LD BC,$051E
; ----------------------------------------------------------------------
; STMT_NORMAL -- (entered at +1) NORMAL statement handler (token $CB, dispatch slot $019C).
;   In:        HL -> BASIC text (no operand); reached via DEFW STMT_NORMAL+1 = $019C -> $45B6
;   Out:       screen-function #4 (Set Normal / low-light text mode) emitted to the terminal;
;              HL preserved
;   Clobbers:  A, D, E (=4); HL saved/restored
;   Algorithm: Same overlap idiom as STMT_INVERSE: bytes 01 1E 04 are 'LD BC,$041E' on
;              fall-through, but dispatch slot $019C enters at '1E 04' = 'LD E,$04', selecting
;              screen function 4 (Set Normal text mode). Falls into the shared tail (PUSH HL;
;              CALL SCREEN_POS_EMIT; POP HL; RET) that emits the Set-Normal sequence. Verified
;              against the MBASIC twin.
; ----------------------------------------------------------------------
STMT_NORMAL:
        LD BC,$041E
        PUSH HL
        ; emit the selected screen-function sequence (Clear/Normal/Inverse) to the terminal
        CALL SCREEN_POS_EMIT
        POP HL
        RET
; ----------------------------------------------------------------------
; STMT_TEXT -- TEXT statement (token $C6): leave Apple graphics and return the console to the text screen.
;   In:        HL = BASIC text pointer (past the TEXT token). GFX_MODE_ACTIVE_FLAG nonzero iff a graphics
;              mode is currently active. PAGE_LENGTH = current text screen height in rows (default $18=24).
;   Out:       Returns to the caller (via the CURSOR_REPOSITION -> GFX_STMT_VTAB_2 tail, which ends in RET) with HL
;              preserved. On the way the Apple is switched to text/page-1, the BASIC cursor is homed to the
;              bottom-left, and -- if graphics had been active -- the screen is cleared via the Apple HOME ROM.
;   Clobbers:  A,F, CURSOR_POS, GFX_MODE_ACTIVE_FLAG; HL preserved across the body via PUSH/POP.
;   Algorithm: RPC to the Apple TEXT ROM entry to set text mode + full-screen window, then set the BASIC
;              cursor cell CURSOR_POS to row=(PAGE_LENGTH-1), col=0 (bottom-left). Read the TXTSET and
;              TXTPAGE1 soft switches (the read toggles the switch) to force text display on page 1. If a
;              graphics mode was active (flag != 0) also RPC the Apple HOME ROM to clear the text window.
;              Clear the graphics-active flag and fall into CURSOR_REPOSITION, whose RET tail returns to the caller.
;              [RE] Reused by STMT_SYSTEM (CALL STMT_TEXT) to restore the text screen before warm-booting CP/M,
;              which depends on this routine returning normally.
; ----------------------------------------------------------------------
STMT_TEXT:
        PUSH HL
        ; RPC the Apple TEXT monitor entry: set text mode and a full-screen text window
        LD HL,TEXT_ROM
        CALL RPC_CALL
        ; home the BASIC cursor to the bottom-left of the text screen: row = PAGE_LENGTH-1, col = 0
        LD A,(PAGE_LENGTH)
        DEC A
        LD H,A
        LD L,$00
        LD (CURSOR_POS),HL
        ; read the soft switches to force the text display on page 1 (the read itself flips each switch)
        LD A,(TXTSET)
        LD A,(TXTPAGE1)
        ; if a graphics mode was active, also clear the text window via the Apple HOME ROM
        LD A,(GFX_MODE_ACTIVE_FLAG)
        OR A
        JR Z,STMT_TEXT_DONE
        LD HL,HOME_ROM
        CALL RPC_CALL
STMT_TEXT_DONE:
        ; back in text mode: clear the graphics-active flag and fall into CURSOR_REPOSITION (whose RET returns to the caller)
        XOR A
        LD (GFX_MODE_ACTIVE_FLAG),A
        JR CURSOR_REPOSITION

; ======================================================================
; GRAPHICS SUBSYSTEM (GFX_) + 6502 RPC bridge
; ======================================================================
; ----------------------------------------------------------------------
; RPC_CALL -- Z80->6502 remote-procedure-call bridge: run an Apple monitor-ROM routine on the 6502.
;   In:        HL = the Apple ROM (6502) target address to execute (e.g. TEXT_ROM, HOME_ROM, HLINE).
;              Caller has already staged any 6502 register arguments in RPC_ACC/RPC_XREG/RPC_YREG.
;   Out:       The 6502 routine has run and returned; no Z80 register result (results, if any, are read
;              back from the shared RPC register cells by the caller).
;   Clobbers:  A_VEC (set to HL); the trigger store writes A (caller's A). Z80 registers otherwise preserved.
;   Algorithm: Store the target address into A_VEC ($F3D0), the SoftCard 6502-call-vector cell, then fall
;              into RPC_TRIGGER_STORE, whose store-address operand was self-modified at cold start. Executing
;              that store hands the bus to the 6502, which runs the routine at A_VEC and returns control to
;              the Z80. This is the single bridge all graphics/screen statements use to reach the Apple ROM.
; ----------------------------------------------------------------------
RPC_CALL:
        ; publish the 6502 target address in the SoftCard call-vector cell, then fall into the trigger store
        LD (A_VEC),HL
; ----------------------------------------------------------------------
; RPC_TRIGGER_STORE -- the self-modified store that triggers the SoftCard 6502 hand-off.
;   In:        A_VEC already holds the 6502 target address (set by RPC_CALL).
;   Out:       The 6502 runs and returns; control resumes at the RET.
;   Clobbers:  the destination cell of the store (the byte written is the caller's A; its value is
;              irrelevant -- it is the WRITE to the SoftCard trigger that matters, not the value).
;   Algorithm: Assembled as LD ($0000),A (a placeholder operand). At cold start the init at $8243 does
;              LD HL,(Z_CPU) / LD (RPC_TRIGGER_STORE+1),HL, patching this instruction's operand word so the
;              live store writes to the SoftCard CPU-switch trigger; that write switches CPUs, the 6502 runs
;              the queued routine, and on return this routine RETs to RPC_CALL's caller.
;   Note:      [RE] LD HL,(Z_CPU) reads the WORD stored AT $F3DE, not the literal $F3DE, so the exact patched
;              destination is the contents of that cell at cold start; the file convention treats it as $F3DE
;              (a self-pointing trigger cell), giving the live instruction LD (Z_CPU),A. UNKNOWN whether the
;              cell ever holds anything other than $F3DE.
; ----------------------------------------------------------------------
RPC_TRIGGER_STORE:
        LD ($0000),A
        RET
; ----------------------------------------------------------------------
; GFX_STMT_GR -- GR statement (token $CC): enter low-res graphics mode and clear the graphics field.
;   In:        HL = BASIC text pointer at the (optional) argument. On entry the Z flag reflects the
;              statement-entry CHRGOT classification of the first char (Z = end-of-statement / bare GR,
;              NZ = an argument character follows). Optional syntax: GR [mode][,color], mode in {0,1}.
;   Out:       Apple is in low-res graphics on page 1: mode 0 = mixed (split graphics + 4 bottom text lines,
;              40 graphics rows); mode 1 = full-screen graphics (48 rows). The graphics field is cleared/filled
;              by drawing a full-width HLIN on every row using the current COLOR. GFX_MODE_ACTIVE_FLAG := $FF.
;              HL advanced past the consumed argument(s). Returns to the statement executor.
;   Clobbers:  A,B,C,D,E,H,L,F; COLOR, WNDTOP, CURSOR_POS, H2, RPC_ACC, RPC_YREG, the TXTCLR/MIXSET/MIXCLR/
;              LORES soft switches.
;   Algorithm: Default COLOR=0 (black). If an argument follows (entry NZ), GETBYT the MODE into A; reject
;              mode >= 2 (ERROR_FC). Set the text-window top to row $14 (20) and CURSOR_POS so the cursor sits
;              at row 23, col 0; position it via SCREEN_POS_FROM_TABLE. Read the LORES soft switch (select
;              low-res, clear hi-res). Call GFX_SET_DISPLAY_MODE which uses bit 0 of the mode to pick MIXSET
;              (mode 0, mixed, D=$28=40 rows) vs MIXCLR (mode 1, full screen, D=$30=48 rows) and returns Z iff
;              the next BASIC char is ',' (a second argument, the lo-res color, follows). If a comma follows,
;              skip it (INC HL), GETBYT the color into E, and apply it via GFX_SET_LORES_COLOR. Then clear the
;              field: H2 := $27 (right-edge col 39), B := D (row count, 40 or 48); for each row B-1 down to 0
;              stage RPC_YREG=0 (left col) and RPC_ACC=row, calling GFX_LORES_HLIN_RPC to draw a full-width
;              horizontal line. Finally set GFX_MODE_ACTIVE_FLAG=$FF.
;   Note:      [RE] The mode->display mapping (0=mixed/1=full-screen, row count 40/48) is read directly from
;              GFX_SET_DISPLAY_MODE's MIXSET/MIXCLR + D=$28/$30 logic, not inferred. The mode>=2 reject limits
;              GR to the two hardware display modes.
; ----------------------------------------------------------------------
GFX_STMT_GR:
        ; default the lo-res plotting color to 0 (black) before reading any argument
        LD A,$00
        LD (COLOR),A
        ; if an argument follows the GR token, fetch the display mode (0=mixed, 1=full-screen) into A
        CALL NZ,GETBYT
        CP $02
        ; reject GR display modes >= 2 as illegal (shared ERROR_FC tail)
        JR NC,GFX_PARSE_LINE_COORDS_1
        PUSH HL
        PUSH AF
        ; set the text-window top to row 20, reserving the bottom text lines for the mixed-graphics screen
        LD A,$14
        LD (WNDTOP),A
        LD HL,$1700
        LD (CURSOR_POS),HL
        CALL SCREEN_POS_FROM_TABLE
        ; read the LORES soft switch to select low-res graphics and clear hi-res
        LD A,(LORES)
        POP AF
        POP HL
        LD (LORES),A
        ; commit MIXSET vs MIXCLR from the mode and set D = row count (40 or 48); Z means a ',color' arg follows
        CALL GFX_SET_DISPLAY_MODE
        JR NZ,GFX_STMT_GR_FILL
        INC HL
        PUSH DE
        CALL GETBYT
GFX_STMT_GR_SETCOLOR:
        CALL GFX_SET_LORES_COLOR
        POP DE
GFX_STMT_GR_FILL:
        PUSH HL
        ; set the HLIN right-edge column to 39 so each fill line spans the full 40-column field
        LD A,$27
        LD (H2),A
        LD B,D
GFX_STMT_GR_FILL_ROW:
        ; stage the 6502 call: Y = left column 0, A = current row, then RPC one full-width HLIN
        XOR A
        LD (RPC_YREG),A
        LD A,B
        DEC A
        LD (RPC_ACC),A
        CALL GFX_LORES_HLIN_RPC
        ; repeat for every row (B = 40 or 48 down to 0), clearing the field one horizontal line at a time
        DJNZ GFX_STMT_GR_FILL_ROW
        ; mark graphics mode active so a later TEXT statement knows to clear the screen
        LD A,$FF
        LD (GFX_MODE_ACTIVE_FLAG),A
        POP HL
        RET
; ----------------------------------------------------------------------
; GFX_LORES_HLIN_RPC -- draw one low-res horizontal line on the 6502 side via the RPC bridge.
;   In:        RPC_ACC = row (Apple $45, passed to 6502 A), RPC_YREG = left column (Apple $47, 6502 Y),
;              H2 ($F02C, Apple $2C) = right-edge column, COLOR ($F030, Apple $30) = lo-res color. All staged
;              by the caller.
;   Out:       The 6502 HLINE ($F819) routine has drawn the segment; returns to the caller of RPC_CALL.
;   Clobbers:  A_VEC; per RPC_CALL.
;   Algorithm: Load HL with the Apple HLINE ROM entry ($F819) and tail-jump into RPC_CALL, which queues
;              the address and triggers the 6502 to run the lo-res horizontal-line draw. Used by the GR
;              screen-clear fill and by the HLIN statement.
; ----------------------------------------------------------------------
GFX_LORES_HLIN_RPC:
        LD HL,HLINE
        JP RPC_CALL
; ----------------------------------------------------------------------
; GFX_STMT_COLOR -- COLOR= statement (token $CD): set the current low-res plotting color.
;   In:        HL = BASIC text pointer positioned at the '=' token after COLOR.
;   Out:       Falls into GFX_SET_LORES_COLOR with E = the parsed color byte; on return COLOR ($F030)
;              holds the 4-bit color replicated into both nibbles. HL advanced past the expression.
;   Clobbers:  A,E,F,H,L (via SYNCHR/GETBYT).
;   Algorithm: Require the '=' token via SYNCHR (the inline DEFB TOK_EQ is the expected-token argument that
;              SYNCHR reads from the byte after the call), evaluate the following expression to a byte with
;              GETBYT (result in A and E), then fall into GFX_SET_LORES_COLOR to validate and pack it.
; ----------------------------------------------------------------------
GFX_STMT_COLOR:
        ; require the '=' that follows the COLOR keyword (the expected token is the inline DEFB below)
        CALL SYNCHR
        DEFB    TOK_EQ                   ; inline keyword-token arg consumed by the preceding CALL
        ; evaluate the color expression to a 0..255 byte (in A and E), then validate and pack it
        CALL GETBYT
; ----------------------------------------------------------------------
; GFX_SET_LORES_COLOR -- validate a lo-res color and store it packed into both nibbles at COLOR.
;   In:        E = requested low-res color (0..15).
;   Out:       COLOR ($F030) = (E<<4) | E, i.e. the color in both the high and low nibble. Returns to
;              caller. On E >= 16, jumps to ERROR_FC (Illegal function call) instead.
;   Clobbers:  A,F. (E preserved.)
;   Algorithm: Reject colors >= 16. Otherwise replicate the 4-bit color into both nibbles by four ADD A,A
;              (shift left 4) then OR E, and store the packed byte to the Apple lo-res COLOR cell, so that
;              a lo-res plot of one screen cell paints both stacked half-blocks the same color.
; ----------------------------------------------------------------------
GFX_SET_LORES_COLOR:
        LD A,E
        ; low-res colors are 0..15; anything larger is an illegal function call
        CP $10
        JR NC,GFX_PARSE_LINE_COORDS_1
        ; replicate the 4-bit color into both nibbles: shift it into the high nibble (4x), then OR in the low
        ADD A,A
        ADD A,A
        ADD A,A
        ADD A,A
        OR E
        ; store the packed color so each lo-res cell paints both half-blocks the same
        LD (COLOR),A
        RET
; ----------------------------------------------------------------------
; GFX_PARSE_LINE_COORDS -- parse a low-res line's "start,end AT cross" coordinate triple for HLIN/VLIN
;   In:        HL -> text after the HLIN/VLIN token; B = exclusive upper bound for the end coordinate, C = exclusive upper bound for the cross-axis coordinate (HLIN passes BC=$2830 => end<$28=40 columns, cross<$30=48 rows; VLIN passes BC=$3028 => end<$30=48 rows, cross<$28=40 columns)
;   Out:       A = cross-axis coordinate (the "AT" value); E = start coordinate; D = end coordinate; HL advanced past the parsed text
;   Clobbers:  A, D, E, flags (BC is pushed/popped, restored to the caller's bound; the saved start/end is recovered into DE at the final POP)
;   Algorithm: Reads "start,end" via GFX_PARSE_TWO_BYTES (leaves A=end, E=start), then range-checks: end must be < B and end >= start (else Illegal-function-call). Saves start/end, requires the literal "AT", reads the cross-axis byte with GETBYT, range-checks it < C, and returns it in A with start/end restored in E/D. The two bounds are swapped between HLIN and VLIN so the same parser enforces the correct column-vs-row limits for each axis.
; ----------------------------------------------------------------------
GFX_PARSE_LINE_COORDS:
        PUSH BC
        ; read the "start,end" pair: A=end coordinate, E=start coordinate
        CALL GFX_PARSE_TWO_BYTES
        POP BC
        ; reject end coordinate >= its axis limit (B)
        CP B
GFX_PARSE_LINE_COORDS_1:
        JP NC,ERROR_FC
        ; reject end < start (segment would run backwards)
        CP E
        JP C,ERROR_FC
        LD D,A
        PUSH DE
        PUSH BC
        CALL SYNCHR
        ; require the literal "AT" separating the segment from its cross-axis coordinate
        DEFB    'A'                      ; inline char arg consumed by the preceding CALL
        CALL SYNCHR
        DEFB    'T'                      ; inline char arg consumed by the preceding CALL
        ; read the cross-axis ("AT") coordinate into A
        CALL GETBYT
        POP BC
        ; reject cross-axis coordinate >= its axis limit (C)
        CP C
        JR NC,GFX_PARSE_LINE_COORDS_1
        POP DE
        RET
; ----------------------------------------------------------------------
; GFX_STMT_HLIN -- HLIN statement (token $CE): draw a horizontal low-res line via the 6502 ROM
;   In:        HL -> text after the HLIN token, expecting "x1,x2 AT y"
;   Out:       Horizontal segment drawn by the Apple HLINE ROM ($F819); HL advanced past the statement; returns to the statement dispatcher
;   Clobbers:  A, D, E, BC, HL (restored), the Apple-side cells RPC_ACC/RPC_YREG/H2
;   Algorithm: Sets bounds BC=$2830 (x-column 0..39, y-row 0..47) and parses "x1,x2 AT y" with GFX_PARSE_LINE_COORDS, yielding A=y(row), E=x1(left col), D=x2(right col). Stages them where the Apple HLINE primitive expects: RPC_ACC=row (6502 A), RPC_YREG=left col (6502 Y), H2=right col, then RPC-calls HLINE on the 6502 to render the run.
; ----------------------------------------------------------------------
GFX_STMT_HLIN:
        ; axis limits for HLIN: end column < $28 (40), row < $30 (48)
        LD BC,$2830
        CALL GFX_PARSE_LINE_COORDS
        ; HLINE wants A=row, Y=left col, H2=right col -> stage the row in the 6502 A cell
        LD (RPC_ACC),A
        LD A,E
        LD (RPC_YREG),A
        ; right-edge column -> HLINE right-end cell H2
        LD A,D
        LD (H2),A
        PUSH HL
        ; run the Apple HLINE ROM on the 6502 to draw the row segment
        CALL GFX_LORES_HLIN_RPC
        POP HL
        RET
; ----------------------------------------------------------------------
; GFX_STMT_VLIN -- VLIN statement (token $CF): draw a vertical low-res line via the 6502 ROM
;   In:        HL -> text after the VLIN token, expecting "y1,y2 AT x"
;   Out:       Vertical segment drawn by the Apple VLINE ROM ($F828); HL advanced; returns to the dispatcher (via the shared GFX_STMT_PLOT_1 tail)
;   Clobbers:  A, D, E, BC, HL (restored by the shared tail), cells RPC_ACC/RPC_YREG/V2
;   Algorithm: Mirror of GFX_STMT_HLIN with axis limits swapped: BC=$3028 (y-row 0..47, x-column 0..39). Parses "y1,y2 AT x" giving A=x(col), E=y1(top row), D=y2(bottom row). Stages RPC_YREG=col (6502 Y), RPC_ACC=top row (6502 A), V2=bottom row, loads HL=VLINE ($F828), and falls into GFX_STMT_PLOT_1 to RPC-call the 6502 VLINE primitive.
; ----------------------------------------------------------------------
GFX_STMT_VLIN:
        ; axis limits for VLIN: end row < $30 (48), column < $28 (40)
        LD BC,$3028
        CALL GFX_PARSE_LINE_COORDS
        ; VLINE wants A=top row, Y=column, V2=bottom row -> stage the column in the 6502 Y cell
        LD (RPC_YREG),A
        LD A,E
        LD (RPC_ACC),A
        ; bottom row -> VLINE bottom-end cell V2
        LD A,D
        LD (V2),A
        PUSH HL
        ; target the Apple VLINE ROM and join the shared RPC-call/return tail
        LD HL,VLINE
        JR GFX_STMT_PLOT_1
; ----------------------------------------------------------------------
; GFX_PARSE_TWO_BYTES -- evaluate two comma-separated byte expressions "a,b"
;   In:        HL -> text positioned at the first expression
;   Out:       A = second byte value; E = first byte value; D = high byte of the first value (0, since CONINT forces it; unused by callers); HL advanced past "a,b"
;   Clobbers:  A, D, E, flags (DE saved across the comma so the first value survives the second GETBYT)
;   Algorithm: GETBYT evaluates the first byte (into A/E), pushes DE to preserve it, requires a literal comma, GETBYT evaluates the second byte (into A), then POPs DE to recover the first byte in E. Returns first in E, second in A. Shared low-res coordinate-pair reader used by PLOT, SCRN(), HLIN/VLIN (indirectly) and BEEP.
; ----------------------------------------------------------------------
GFX_PARSE_TWO_BYTES:
        ; evaluate the first byte; save it across the comma and second evaluation
        CALL GETBYT
        PUSH DE
        CALL SYNCHR
        ; require the comma between the two values
        DEFB    ','                      ; inline char arg consumed by the preceding CALL
        ; evaluate the second byte into A; restore the first into E
        CALL GETBYT
        POP DE
        RET
; ----------------------------------------------------------------------
; GFX_PARSE_PLOT_COORD -- parse and range-check a low-res "x,y" point and stage it for the 6502
;   In:        HL -> text at the X (first) expression of an "x,y" pair
;   Out:       RPC_YREG = X column (0..39, the 6502 Y reg); RPC_ACC = Y row (0..47, the 6502 A reg); HL advanced past "x,y"; on out-of-range value, jumps to Illegal-function-call (never returns)
;   Clobbers:  A, E, flags, cells RPC_ACC/RPC_YREG
;   Algorithm: Reads the pair via GFX_PARSE_TWO_BYTES (A=second operand=Y row, E=first operand=X column). Validates the row Y < $30 (48 rows) and the column X < $28 (40 columns), erroring otherwise, then stores the row into RPC_ACC (6502 A) and the column into RPC_YREG (6502 Y) so the Apple PLOT/SCRN primitives find the point in (A=row, Y=column) form. Shared by PLOT and SCRN(). [RE] orientation taken from the ROM convention (HLINE/PLOT use A=row, Y=column) and the matching < 48 / < 40 bounds; the BASIC operand order is X(column) then Y(row).
; ----------------------------------------------------------------------
GFX_PARSE_PLOT_COORD:
        CALL GFX_PARSE_TWO_BYTES
        ; reject the Y row >= 48 (this is the second operand, staged into the 6502 A cell)
        CP $30
        JR NC,GFX_PARSE_LINE_COORDS_1
        ; stage the row in the 6502 A cell (PLOT/SCRN expect the row in A)
        LD (RPC_ACC),A
        LD A,E
        ; reject the X column >= 40 (first operand, staged into the 6502 Y cell)
        CP $28
        JR NC,GFX_PARSE_LINE_COORDS_1
        ; stage the column in the 6502 Y cell
        LD (RPC_YREG),A
        RET
; ----------------------------------------------------------------------
; GFX_STMT_PLOT -- PLOT statement (token $CD-family): light one low-res cell via the 6502 ROM
;   In:        HL -> text after the PLOT token, expecting "x,y" (x=column, y=row)
;   Out:       The cell at (x,y) plotted in the current COLOR by the Apple PLOT ROM ($F800); HL advanced; returns to the dispatcher
;   Clobbers:  A, E, HL (restored), cells RPC_ACC/RPC_YREG
;   Algorithm: Parses and validates the coordinate with GFX_PARSE_PLOT_COORD (which stages row->RPC_ACC and column->RPC_YREG into the 6502 register cells), loads HL=$F800 (the Apple PLOT entry), and falls into GFX_STMT_PLOT_1 to perform the RPC and restore HL.
; ----------------------------------------------------------------------
GFX_STMT_PLOT:
        CALL GFX_PARSE_PLOT_COORD
        PUSH HL
        ; target the Apple PLOT ROM entry, then join the shared RPC-call tail
        LD HL,$F800
; ----------------------------------------------------------------------
; GFX_STMT_PLOT_1 -- shared RPC-call-and-restore tail for the low-res draw statements
;   In:        HL = Apple ROM target address to call on the 6502; one saved HL (the BASIC text pointer) on the stack
;   Out:       The 6502 routine executed; HL restored to the BASIC text pointer; returns to the dispatcher
;   Clobbers:  whatever RPC_CALL touches; HL reloaded from the stack
;   Algorithm: Calls RPC_CALL to run the staged 6502 graphics primitive, then POPs the text pointer back into HL. Tail-shared by PLOT (fall-through), VLIN (JR), and BEEP (JP).
; ----------------------------------------------------------------------
GFX_STMT_PLOT_1:
        CALL RPC_CALL
        POP HL
        RET
; ----------------------------------------------------------------------
; GFX_FN_PDL -- PDL(n) function (token $35): read pushbutton/switch n as a BASIC integer
;   In:        HL -> text at the argument expression; the argument already parenthesized by the function dispatcher
;   Out:       FAC = -1 if button n is pressed, 0 if not (returned as a 16-bit integer); HL advanced; on n > 2, Illegal-function-call
;   Clobbers:  A, D, E, HL (restored), FAC
;   Algorithm: CONINT evaluates the argument to a 0..255 byte (E=value, A=E; CONINT itself raises FC if it does not fit in a byte, leaving D=0). Requires n in 0..2 (CP $03 / JR NC -> FC). The following LD A,D / OR A / JR NZ is a redundant high-byte guard -- CONINT has already forced D to 0, so it can never fire. Then indexes the Apple pushbutton soft-switches at BUTN0 ($E061=Apple $C061) by n and reads the switch; bit 7 = pressed. RLA rotates that bit into carry and SBC A,A turns it into $FF (pressed) or $00 (released), then falls into GFX_STORE_SIGNED_BYTE_FAC to return it as a 16-bit integer. NOTE [RE]: despite the Applesoft name PDL(), this reads the BUTNn PUSHBUTTON soft-switches (a boolean -1/0), not the analog paddle position; the analog read (PREAD $FB1E) is in the adjacent routine currently labeled FN_PDL.
; ----------------------------------------------------------------------
GFX_FN_PDL:
        ; evaluate the button number into a 0..255 byte (E=value, A=E; D forced to 0)
        CALL CONINT
        LD A,E
        ; only buttons 0..2 are valid
        CP $03
        JR NC,FN_RANGE_ERR
        LD A,D
        OR A
        JR NZ,FN_RANGE_ERR
        PUSH HL
        ; index the pushbutton soft-switch for button n and read its state (bit 7 = pressed)
        LD HL,BUTN0
        ADD HL,DE
        LD A,(HL)
        POP HL
        ; move the pressed bit (bit 7) into carry, then SBC A,A expands it to $FF (pressed) / $00 (released)
        RLA
        SBC A,A
; ----------------------------------------------------------------------
; GFX_STORE_SIGNED_BYTE_FAC -- return a sign-extended 8-bit value as a 16-bit BASIC integer
;   In:        A = byte value whose sign has already been broadcast across all 8 bits ($00 or $FF, as left by RLA/SBC A,A in the PDL path)
;   Out:       FAC holds the signed 16-bit integer (VALTYP=VT_INT); returns via FP_STORE_FAC_INT to the function-return path
;   Clobbers:  H, L, FAC
;   Algorithm: Copies A into both H and L (so $FFFF = -1 or $0000 = 0), then tail-calls FP_STORE_FAC_INT to load HL into the floating accumulator as an integer. Result tail for PDL().
; ----------------------------------------------------------------------
GFX_STORE_SIGNED_BYTE_FAC:
        ; replicate the already-sign-extended byte into both halves of HL (0000 or FFFF)
        LD L,A
        LD H,A
        JP FP_STORE_FAC_INT
; ----------------------------------------------------------------------
; FN_VPOS -- VPOS() function (function token $34): return the current vertical text
; row counter (1-based) as an integer in the FAC.  MISLABELED: this is VPOS, not MKD$.
; FUNC_DISPATCH_TBL is based at $01B2, slot address = base + 2*(token-1), so this slot
; $0218 = token $34 = VPOS (msbasic_tokens.inc); the real MKD$ is FN_MKD_STR at slot
; $0216 = token $33.  Vertical analogue of FN_POS, which reads the horizontal column
; cell CURSOR_POS.
;   In:        CURSOR_ROW = current screen row / printed-line counter (set by GFX_STMT_VTAB,
;              advanced by LINE_COUNT_INC / OUTDO_WIDTH).  HL -> BASIC text pointer.
;   Out:       FAC = (CURSOR_ROW)+1 as a zero-extended 16-bit integer (VALTYP := VT_INT, set by
;              FP_STORE_FAC_INT); HL preserved.
;   Clobbers:  A, L, H, flags.
;   Algorithm: A := (row counter)+1, then fall into the shared 'push text ptr / load byte
;              into FAC as integer / restore text ptr' tail (FAC_LOAD_BYTE_PUSH_TXT, which
;              zero-extends the byte via FP_LOAD_INT_TO_FAC).
; ----------------------------------------------------------------------
FN_VPOS:
        ; read the vertical cursor row / lines-printed counter (1-based after the INC)
        LD A,(CURSOR_ROW)
        INC A
FAC_LOAD_BYTE_PUSH_TXT:
        PUSH HL
FAC_LOAD_BYTE_POP_TXT:
        CALL FP_LOAD_INT_TO_FAC
        POP HL
        RET
; ----------------------------------------------------------------------
; GFX_STMT_BEEP -- BEEP statement (token $D4): sound a tone whose pitch and length come from "a,b"
;   In:        HL -> text after the BEEP token, expecting "pitch,duration" (first operand=pitch, second=duration)
;   Out:       A tone played by the embedded 6502 routine; HL advanced; returns to the dispatcher (via GFX_STMT_PLOT_1)
;   Clobbers:  A, E, HL (restored by the tail), cells RPC_ACC/RPC_XREG
;   Algorithm: Parses two bytes with GFX_PARSE_TWO_BYTES (E=first operand, A=second operand). Increments each (so a 0 argument still yields a minimal count rather than the 256-iteration wraparound the 6502 loop would otherwise take), stages the SECOND operand in RPC_ACC (6502 zp $45) and the FIRST in RPC_XREG (6502 zp $46), points HL at the embedded 6502 tone loop at its 6502-view address (BEEP_6502_PAYLOAD+$1000 = $5709), and JPs to GFX_STMT_PLOT_1 to RPC-run it. [RE] in the 6502 loop zp $45 is the duration (outer toggle count) and zp $46 sets the half-period (pitch); so the second operand is duration and the first is pitch.
; ----------------------------------------------------------------------
GFX_STMT_BEEP:
        ; read the "pitch,duration" pair: E=first operand (pitch), A=second operand (duration)
        CALL GFX_PARSE_TWO_BYTES
        ; +1 so a 0 argument gives a minimal (not wrapped 256) count; stage the duration in 6502 zp $45
        INC A
        LD (RPC_ACC),A
        LD A,E
        ; +1 the pitch likewise; stage it in 6502 zp $46
        INC A
        LD (RPC_XREG),A
        PUSH HL
        ; target the embedded 6502 tone loop at its 6502-view address ($5709) and RPC-run it
        LD HL,BEEP_6502_PAYLOAD+$1000
        JP GFX_STMT_PLOT_1
; ----------------------------------------------------------------------
; BEEP_6502_PAYLOAD -- embedded 6502 machine code that GFX_STMT_BEEP RPC-executes to play a tone
;   In:        (read by the 6502) zp $45 = duration count (from RPC_ACC), zp $46 = pitch/half-period count (from RPC_XREG)
;   Out:       Speaker toggled to produce a tone; control returns to the RPC bridge via RTS
;   Clobbers:  6502 A, X, Y, zp $45 (counted down to 0); from the Z80 view this block is opaque data
;   Algorithm: Nested-loop square-wave generator. The speaker is toggled by LDA $C030 at the top; an inner loop then DEYs (Y down from 0 = up to 256 passes) with a JSR $FF57 (Monitor WAIT) delay each pass, gated by X which is reloaded from zp $46 (so $46 sets the inner pass count = half-period = pitch). When Y wraps to 0 it DECs the duration in zp $45 and exits (RTS) when that reaches 0; otherwise it reloads X from $46 and branches back to toggle the speaker again. Verified 6502 listing at $5709: LDY #$00 / LDA $C030 / DEY / BNE $5715 / DEC $45 / BEQ $5721 / JSR $FF57 / DEX / BNE $570E / LDX $46 / BNE $570B / BEQ $570B / RTS. The +$1000 on the load address in GFX_STMT_BEEP is the SoftCard CPU-view offset (a Z80 ADDRESS X maps to 6502 ADDRESS X+$1000), not a relocation artifact.
; ----------------------------------------------------------------------
BEEP_6502_PAYLOAD:
        DEFB    $A0,$00,$AD,$30,$C0,$88,$D0,$04,$C6,$45,$F0,$0C,$20,$57,$FF,$CA
        DEFB    $D0,$F3,$A6,$46,$D0,$EC,$F0,$EA,$60
; ----------------------------------------------------------------------
; STMT_WAIT -- WAIT statement (token $D5): busy-poll an I/O port until masked bits match (SoftCard superset)
;   In:        HL -> text after the WAIT token, expecting "port, andmask [, xormask]"
;   Out:       Returns once ((portbyte XOR xormask) AND andmask) is non-zero; HL advanced; loops forever if the condition is never met
;   Clobbers:  A, D, E, HL (text pointer saved/restored via the stack), flags
;   Algorithm: GETINT evaluates the 16-bit port address (saved on the stack as the poll target), GETBYT reads the AND mask, and an optional third byte is the XOR mask (default 0 when the comma is absent, detected by the GETBYT Z flag -- Z set means the statement ended with no third argument). With D=AND mask and E=XOR mask, it swaps the saved port address into HL and spins: read (HL), XOR with E, AND with D, repeat while zero. This blocks BASIC until the selected hardware-port bits reach the wanted state -- the classic MS-BASIC/Apple WAIT, present here as a SoftCard extension and physically interleaved with the graphics statements.
; ----------------------------------------------------------------------
STMT_WAIT:
        ; evaluate the 16-bit I/O port address; keep it on the stack as the poll target
        CALL GETINT
        PUSH DE
        CALL SYNCHR
        DEFB    ','                      ; inline char arg consumed by the preceding CALL
        CALL GETBYT
        PUSH AF
        ; default the XOR mask to 0; the GETBYT Z flag (pushed) is set when the statement ended with no third argument
        LD E,$00
        JR Z,STMT_WAIT_HAVE_MASKS
        CALL SYNCHR
        ; optional third argument present -> read the XOR mask into E
        DEFB    ','                      ; inline char arg consumed by the preceding CALL
        CALL GETBYT
STMT_WAIT_HAVE_MASKS:
        POP AF
        LD D,A
        ; swap the saved port address into HL so (HL) reads the port; the BASIC text pointer parks on the stack
        EX (SP),HL
STMT_WAIT_POLL_LOOP:
        ; poll: read the port, apply XOR/AND masks, loop until any selected bit is set
        LD A,(HL)
        XOR E
        AND D
        JR Z,STMT_WAIT_POLL_LOOP
        POP HL
        RET
; ----------------------------------------------------------------------
; FN_PDL -- PDL() function (function token $35): read an Apple game paddle / analog input
; via the 6502 monitor PREAD routine over the Z80->6502 RPC bridge.  MISLABELED as VPOS:
; FUNC_DISPATCH_TBL slot $021A = base $01B2 + 2*($35-1) = token $35 = PDL, and the body
; RPC-calls PREAD, not a cursor read.
;   In:        Paddle-number expression in source; CONINT yields it in E (and A), 0..255.
;              RPC bridge: A_VEC ($F3D0) / Z_CPU ($F3DE) RPC dispatch cells; RPC_XREG passes
;              the paddle index to the 6502, RPC_YREG returns the result.
;   Out:       FAC = paddle value 0..255 as a zero-extended integer (VALTYP := VT_INT).
;   Clobbers:  A,E,HL, the 6502 RPC cells; HL (text ptr) saved/restored across the RPC.
;   Algorithm: Range-check the paddle index < 4 (else 'Illegal function call' via ERROR_FC).
;              Stage it in RPC_XREG, RPC-call the Apple ROM PREAD ($FB1E) which returns the
;              paddle/timer count in 6502 Y = RPC_YREG, then load that byte into the FAC as
;              an integer.
;
; NOTE: the labels FN_SCRN..\_9 below are NOT part of PDL -- they are independent
; function/statement bodies that merely share the _N numbering: _1 = shared range-error
; tail; _2 = SCRN() fn; _3 = COLOR-read fn; _4..\_9 = the argument list + 6502-invoke tail
; of STMT_CALL (entered via JP Z,STMT_CALL_INVOKE_6502 at asm line 14704).  See their renames.
; ----------------------------------------------------------------------
FN_PDL:
        CALL CONINT
        LD A,E
        CP $04
FN_RANGE_ERR:
        JP NC,ERROR_FC
        ; pass the paddle number to the 6502 in X
        LD (RPC_XREG),A
        PUSH HL
        ; call the Apple monitor paddle-read routine over the 6502 RPC bridge
        LD HL,PREAD
        CALL RPC_CALL
        POP HL
        ; PREAD returns the paddle/timer count in 6502 Y
        LD A,(RPC_YREG)
        JP FP_LOAD_INT_TO_FAC
; ----------------------------------------------------------------------
; FN_SCRN -- SCRN(x,y) function (token $EC): read the colour of one LOW-RES screen cell
;   In:        HL -> program text positioned at the SCRN token; the '(x,y)' argument list follows.
;   Out:       FAC = the lo-res colour 0..15 at cell (x,y), as a zero-extended 16-bit integer (VALTYP := VT_INT); HL advanced past the ')'.
;   Clobbers:  A, E, flags, the 6502 RPC cells RPC_ACC/RPC_YREG. HL is advanced past ')' (its value is saved across the RPC and the FAC load, then restored to that position by the tail).
;   Algorithm: CHRGET past the token, require '(', then GFX_PARSE_PLOT_COORD parses+range-checks the
;              coordinate pair (x<40 columns -> RPC_YREG/6502 Y, y<48 rows -> RPC_ACC/6502 A); require ')'.
;              RPC-call the Apple ROM SCRN routine (SCRN_ROM=$F871, reads lo-res pixel (Y,A)->A) over the
;              Z80->6502 bridge. Read the result colour byte from RPC_ACC (the 6502 A-result is returned
;              through that register cell per the RPC contract [RE/DOC]) and load it into the FAC as an
;              integer via the shared FAC_LOAD_BYTE_POP_TXT tail (which POPs the HL pushed here).
; ----------------------------------------------------------------------
FN_SCRN:
        ; skip the SCRN token and fetch the first argument character
        CALL CHRGET
        CALL SYNCHR
        DEFB    '('                      ; inline char arg consumed by the preceding CALL
        ; parse and range-check (x,y); stages row->RPC_ACC (6502 A), column->RPC_YREG (6502 Y)
        CALL GFX_PARSE_PLOT_COORD
        CALL SYNCHR
        DEFB    ')'                      ; inline char arg consumed by the preceding CALL
        PUSH HL
        ; read the cell colour on the 6502: RPC-call the Apple lo-res SCRN ROM (reads pixel (Y,A)->A)
        LD HL,SCRN_ROM
        CALL RPC_CALL
        ; [RE] read the result colour 0..15 back from RPC_ACC (SCRN returns it in 6502 A, passed through this cell)
        LD A,(RPC_ACC)
        ; return the colour as a 16-bit integer in the FAC and restore the text pointer (POPs the HL pushed above)
        JP FAC_LOAD_BYTE_POP_TXT
; ----------------------------------------------------------------------
; FN_COLOR_READ -- COLOR used as a function (token $CD in operand position): return the current LOW-RES draw colour
;   In:        HL -> program text at the COLOR token; (COLOR) = the current lo-res colour cell ($F030, the 0..15 colour replicated in both nibbles by GFX_SET_LORES_COLOR).
;   Out:       FAC = current draw colour 0..15, as a zero-extended 16-bit integer (VALTYP := VT_INT); HL advanced one character (by CHRGET).
;   Clobbers:  A, flags. HL advanced one char; the text-pointer value is saved/restored by the tail (FP_LOAD_INT_TO_FAC uses H,L internally but the tail's PUSH/POP restores them).
;   Algorithm: CHRGET past the token, read the COLOR cell, mask off the high nibble (AND $0F) to
;              recover the single 0..15 colour value (the cell stores it in both nibbles for the lo-res
;              plot primitives), and load it into the FAC as an integer via FAC_LOAD_BYTE_PUSH_TXT
;              (which pushes HL, zero-extends the byte via FP_LOAD_INT_TO_FAC, then restores HL).
; ----------------------------------------------------------------------
FN_COLOR_READ:
        ; skip the COLOR token (no argument list: this is COLOR read as a value)
        CALL CHRGET
        ; read the current lo-res colour cell (the 0..15 colour is replicated in both nibbles)
        LD A,(COLOR)
        ; keep one nibble -> the colour value 0..15
        AND $0F
        ; return the colour as a 16-bit integer in the FAC (tail saves/restores the text pointer)
        JP FAC_LOAD_BYTE_PUSH_TXT
; ----------------------------------------------------------------------
; STMT_CALL_INVOKE_6502 -- SoftCard CALL %addr(a,x,y): stage the 6502 A/X/Y registers from the argument list.
;   In:        L_0C93 = the resolved 6502 target address (set by STMT_CALL). The text pointer is on the stack (POPped here -> HL). Optional argument list "(a[,x[,y]])".
;   Out:       The three SoftCard register cells RPC_ACC/RPC_XREG/RPC_YREG ($F045..$F047 = Apple zp $45/$46/$47) initialized to 0 then loaded from the supplied byte arguments; falls into STMT_CALL_INVOKE which performs the 6502 call.
;   Clobbers:  AF,BC,DE,HL; RPC_ACC,RPC_XREG,RPC_YREG.
;   Algorithm: Zero the three consecutive register cells (LD HL,RPC_ACC; XOR A; store 3 bytes). POP the text pointer. If no '(' follows (CHRGOT Z) go straight to STMT_CALL_INVOKE (call with A=X=Y=0). Otherwise SYNCHR '(' and run STMT_CALL_ARG_LOOP over up to 3 comma-separated byte values, storing them into RPC_ACC,RPC_XREG,RPC_YREG in store order.
; ----------------------------------------------------------------------
STMT_CALL_INVOKE_6502:
        ; default the 6502 A/X/Y register cells ($F045..$F047) to zero before reading any arguments
        LD HL,RPC_ACC
        XOR A
        LD (HL),A
        INC HL
        LD (HL),A
        INC HL
        LD (HL),A
        POP HL
        CALL CHRGOT
        ; no argument list: call the 6502 routine with A=X=Y=0
        JR Z,STMT_CALL_INVOKE
        CALL SYNCHR
        DEFB    '('                      ; inline char arg consumed by the preceding CALL
        LD DE,RPC_ACC
        LD B,$03
; ----------------------------------------------------------------------
; STMT_CALL_ARG_LOOP -- parse up to three byte arguments into the 6502 register cells (A, X, Y).
;   In:        HL -> text inside the argument list; DE -> RPC_ACC (first register cell); B = 3 (max arguments); '(' already consumed.
;   Out:       Each supplied byte expression evaluated and stored into the next register cell (DE auto-increments RPC_ACC->RPC_XREG->RPC_YREG); ')' ends the list (-> STMT_CALL_ARG_END requiring ')'). HL advanced past the arguments.
;   Clobbers:  AF,BC,DE,HL.
;   Algorithm: Inspect the current char: ')' ($29) -> done; ',' ($2C) -> an empty slot, CHRGET past the comma and DJNZ without storing. Otherwise STMT_CALL_ARG_STORE evaluates a byte (GETBYT), stores it at (DE), INC DE, and skips a following comma. DJNZ repeats up to 3 times, then STMT_CALL_ARG_END requires the closing ')'.
;   Note:      OBSERVED: an explicitly omitted argument (consecutive commas) decrements B but leaves DE unchanged, so the empty slot does NOT reserve a register cell -- the next value lands in the cell the empty slot would have used (arguments map by store-order, not comma-position). [RE]/UNKNOWN whether MS intended positional skipping.
; ----------------------------------------------------------------------
STMT_CALL_ARG_LOOP:
        LD A,(HL)
        ; ')' ends the argument list
        CP $29
        JR Z,STMT_CALL_ARG_END
        CP $2C
        JR NZ,STMT_CALL_ARG_STORE
        CALL CHRGET
        JR STMT_CALL_ARG_NEXT
STMT_CALL_ARG_STORE:
        PUSH BC
        PUSH DE
        ; evaluate the next argument as a 0..255 byte for the 6502 register
        CALL GETBYT
        POP DE
        POP BC
        ; store it into the next 6502 register cell (A then X then Y, in store order)
        LD (DE),A
        INC DE
        LD A,(HL)
        CP $2C
        CALL Z,CHRGET
STMT_CALL_ARG_NEXT:
        DJNZ STMT_CALL_ARG_LOOP
STMT_CALL_ARG_END:
        CALL SYNCHR
        DEFB    ')'                      ; inline char arg consumed by the preceding CALL
; ----------------------------------------------------------------------
; STMT_CALL_INVOKE -- perform the SoftCard 6502 subroutine call with the staged A/X/Y registers.
;   In:        L_0C93 = the 6502 target address; RPC_ACC/RPC_XREG/RPC_YREG already staged; HL -> text after the argument list.
;   Out:       The 6502 routine at the target address executes (with the staged registers) and returns; HL restored to the BASIC text pointer; control returns to the statement executor. Any 6502 results are read back from the register cells by the caller, not here.
;   Clobbers:  whatever the shared RPC tail (GFX_STMT_PLOT_1 -> RPC_CALL) touches; HL reloaded.
;   Algorithm: PUSH the text pointer, load HL = the target address from L_0C93, and JP GFX_STMT_PLOT_1 -- the shared 'RPC_CALL then POP HL' tail used by the low-res graphics statements -- so RPC_CALL runs the 6502 code at the target via the SoftCard CPU switch, then HL is restored on return.
; ----------------------------------------------------------------------
STMT_CALL_INVOKE:
        PUSH HL
        ; load the 6502 target address resolved by STMT_CALL
        LD HL,(L_0C93)
        ; reuse the shared RPC-call-and-restore tail to bridge to the 6502 and pop HL back
        JP GFX_STMT_PLOT_1
; ----------------------------------------------------------------------
; GFX_SET_DISPLAY_MODE -- switch the Apple video into the requested graphics mode and
; report the resulting lo-res screen height.
;   In:        A = mode byte (the LORES/HIRES soft-switch value); bit 0 selects the screen
;              split.  HL -> BASIC text pointer (preserved; used for the trailing peek).
;   Out:       Display soft switches set; D = lo-res screen height ($30 = 48 rows full-screen,
;              $28 = 40 rows mixed); Z/flags from comparing the next source char to ','.
;              A = next source char; HL preserved.
;   Clobbers:  A, D, HL (restored), flags.
;   Algorithm: Touch TXTCLR ($C050) to turn graphics on.  RRA rotates mode bit 0 into carry:
;              carry clear (bit0=0, EVEN) keeps MIXSET ($C053, mixed graphics + 4 text lines,
;              D:=$28); carry set (bit0=1, ODD) does DEC L to MIXCLR ($C052, full screen,
;              D:=$30).  Touch the chosen switch, then peek whether the next source char is
;              ',' so the caller can read an optional sub-argument.  [RE] D is consumed by
;              the GR statement as a row count (GFX_STMT_GR does LD B,D then a DJNZ fill loop).
; ----------------------------------------------------------------------
GFX_SET_DISPLAY_MODE:
        PUSH HL
        ; turn graphics on (clear the text screen) -- Apple $C050
        LD (TXTCLR),A
        LD HL,MIXSET
        ; rotate mode bit 0 into carry: even keeps MIXSET (mixed + 4 text lines), odd selects MIXCLR (full-screen)
        RRA
        LD D,$28
        JR NC,GFX_DISPLAY_MODE_WRITE
        ; odd/full-screen path: step the switch pointer from MIXSET ($C053) down to MIXCLR ($C052)
        DEC L
        LD D,$30
GFX_DISPLAY_MODE_WRITE:
        LD (HL),L
        POP HL
        LD A,(HL)
        ; report to the caller whether a ',' sub-argument follows
        CP $2C
        RET
    IFDEF GBASIC
; ====================================================================== GRAPHICS (GBASIC only)
; [RE] Current hi-res plot color/mode index. Set by COLOR=/HCOLOR= (GFX_SET_COLOR_INDEX $4847); read by GFX_SELECT_COLOR_MASK ($4A91) and the SCRN color read to pick the bit-pattern mask.
GFX_COLOR_INDEX:
        DEFB    "\0"
; [RE] Two-byte hi-res pixel bit pattern for the current color (stored by GFX_SET_COLOR_INDEX_4 $4871); loaded into DE by GFX_LOAD_STEP_STATE ($49EF) for the plot/line writer.
GFX_COLOR_PATTERN:
        DEFB    "\0\0"
; [RE] Hi-res screen byte address of the current plot point (init $8081). Computed by GFX_XY_TO_HIRES_ADDR; loaded into BC by GFX_LOAD_STEP_STATE; saved/restored around a SCRN(x,y) read.
GFX_HIRES_BYTE_ADDR:
        DEFB    $81,$80
; [RE] Hi-res row base screen address of the current point (init $1000). Built by GFX_XY_TO_HIRES_ADDR and advanced a row/column at a time by the Bresenham step routines.
GFX_HIRES_ROW_BASE:
        DEFB    $00,$10
; [RE] Intra-byte bit/column index of the current hi-res point (set $49D1; read $49A6/$49DB to index the column mask). The COLOR/SCRN state save reads it as a word spanning into GFX_X_FRACTION.
GFX_HIRES_BIT_INDEX:
        DEFB    "\0"
; [RE] X sub-byte offset added to the row base in GFX_LOAD_STEP_STATE ($49F3) to reach the plot byte; set by GFX_XY_TO_HIRES_ADDR_2 and recomputed at HPLOT line end.
GFX_X_FRACTION:
        DEFB    "\0"
; [RE] Current hi-res X coordinate (0-279), stored by GFX_XY_TO_HIRES_ADDR ($4978); reloaded by GFX_DRAW_LINE and at HPLOT line end to seed the next segment's delta.
GFX_X_COORD:
        DEFB    "\0\0"
; [RE] Current hi-res Y/row coordinate, stored by GFX_XY_TO_HIRES_ADDR ($497D); read/updated by GFX_DRAW_LINE to compute the vertical delta for Bresenham stepping.
GFX_Y_COORD:
        DEFB    "\0"
; ----------------------------------------------------------------------
; GFX_FN_HCOLOR -- HCOLOR() function (function token $D3): return the current hi-res plot
; colour/mode index.  GBASIC-only; MBASIC routes token $D3 to the not-implemented stub
; (RAISE_GRAPHICS_STATEMENT_NOT_IMPLEMENTED).  Reached from FRMEVL_EVAL_OPERAND_5 via CP
; $D3 / JP Z at $3C85.
;   In:        GFX_COLOR_INDEX = colour index set by the HCOLOR= statement (GFX_SET_COLOR_INDEX).
;              HL -> the function token, the current char.
;   Out:       FAC = colour index as a zero-extended integer (VALTYP := VT_INT); HL preserved.
;   Clobbers:  A, HL (saved/restored by the shared tail), flags.
;   Algorithm: Advance past the function token (CHRGET), read GFX_COLOR_INDEX, and load it
;              into the FAC as an integer via the shared FAC_LOAD_BYTE_PUSH_TXT tail.
; ----------------------------------------------------------------------
GFX_FN_HCOLOR:
        CALL CHRGET
        ; read the current hi-res colour index set by HCOLOR=
        LD A,(GFX_COLOR_INDEX)
        JP FAC_LOAD_BYTE_PUSH_TXT
; ----------------------------------------------------------------------
; GFX_FN_HSCRN -- HSCRN() function (function token $ED): read a hi-res screen point and
; return its on/off state.  Reached from FRMEVL_EVAL_OPERAND_5 via CP $ED / JP Z at $3C8F;
; GBASIC-only (MBASIC stubs token $ED to the not-implemented raise).
;   In:        '(x,y)' coordinate pair in source (row 0-23, column 0-191 via
;              GFX_READ_COORD_PAIR).  HL -> BASIC text pointer.
;   Out:       FAC = -1 if the point is set, 0 if clear (signed integer); the three live
;              hi-res plot-state cells are restored to their pre-call values; HL preserved.
;   Clobbers:  A,BC,DE,HL and the alternate register set; FAC.
;   Algorithm: Parse and range-check (x,y).  Save the BASIC text ptr, then save the THREE
;              live plot-state cells (GFX_HIRES_BYTE_ADDR / _ROW_BASE / _BIT_INDEX) on the
;              stack so the read does not disturb a HPLOT in progress.  Push HSCRN_READ_PIXEL
;              TWICE (so GFX_XY_TO_HIRES_ADDR_4's POP HL/RET lands on it), self-modify that
;              routine's mask-table pointer (GFX_XY_TO_HIRES_ADDR_4+1) to colour-mask table B,
;              then JP GFX_XY_TO_HIRES_ADDR_1 to compute the byte address (which on this path
;              leaves the two table-B mask bytes in GFX_HIRES_BYTE_ADDR).  HSCRN_READ_PIXEL
;              tests them and returns -1/0, then restores the saved cells and text ptr.
; ----------------------------------------------------------------------
GFX_FN_HSCRN:
        CALL CHRGET
        CALL SYNCHR
        DEFB    '('                      ; inline char arg consumed by the preceding CALL
        CALL GFX_READ_COORD_PAIR
        CALL SYNCHR
        DEFB    ')'                      ; inline char arg consumed by the preceding CALL
        PUSH HL
        ; save the live hi-res plot-state cells so the point read does not corrupt an in-progress HPLOT
        LD HL,(GFX_HIRES_BYTE_ADDR)
        PUSH HL
        LD HL,(GFX_HIRES_ROW_BASE)
        PUSH HL
        LD HL,(GFX_HIRES_BIT_INDEX)
        PUSH HL
        LD HL,HSCRN_READ_PIXEL
        PUSH HL
        PUSH HL
        LD HL,GFX_HIRES_COLOR_MASK_TABLE_B
        ; self-modify the address builder to use colour-mask table B for this read
        LD (GFX_XY_TO_HIRES_ADDR_4+1),HL
        LD A,C
        ; compute the screen byte/bit address for (x,y); returns into HSCRN_READ_PIXEL (pushed above)
        JP GFX_XY_TO_HIRES_ADDR_1
; ----------------------------------------------------------------------
; HSCRN_READ_PIXEL -- HSCRN() read body: test the hi-res byte at the computed address
; against the colour masks and store -1 (point set) or 0 (clear) into the FAC, then restore
; the saved plot-state cells and the BASIC text pointer.
;   In:        Entered (via the pushed return address) after GFX_XY_TO_HIRES_ADDR_1 ran with
;              mask-table B selected, so GFX_HIRES_BYTE_ADDR holds the two table-B mask bytes.
;              GFX_LOAD_STEP_STATE then (after EXX) gives BC = those two masks (C=first,
;              B=second), DE = colour pattern, HL = row base + X offset = the actual screen
;              byte address.  Stack holds the three saved plot-state words then the text ptr.
;   Out:       FAC = -1 if the addressed pixel (either mask bit) is set, else 0; the
;              GFX_HIRES_BIT_INDEX / _ROW_BASE / _BYTE_ADDR cells and HL (text ptr) restored.
;   Clobbers:  A,BC,DE,HL, alternate registers; FAC.
;   Algorithm: AND the screen byte with mask C; ADD A,A discards the high palette bit ($80)
;              so JR NZ fires only on a real pixel bit.  If clear, INC HL and AND the NEXT
;              byte with mask B (again ADD A,A then JR Z).  If either pixel bit survives load
;              A=$FF (-1) else A=$00, and store it into the FAC via GFX_STORE_SIGNED_BYTE_FAC.
;              Finally pop the three saved words back into the plot-state cells and pop HL.
;              UNKNOWN: the precise palette reason both adjacent bytes are consulted (inferred
;              from the two-byte mask layout, not round-trip-confirmed).
; ----------------------------------------------------------------------
HSCRN_READ_PIXEL:
        ; load the screen byte address and the two colour-mask bytes for the target point
        CALL GFX_LOAD_STEP_STATE
        EXX
        LD A,(HL)
        ; mask this byte with the first colour-mask byte
        AND C
        ADD A,A
        JR NZ,HSCRN_PIXEL_ON
        INC HL
        LD A,(HL)
        ; if the first byte showed no pixel, test the adjacent byte against the second mask
        AND B
        ADD A,A
        JR Z,HSCRN_PIXEL_DONE
HSCRN_PIXEL_ON:
        ; pixel set -> return TRUE (-1)
        LD A,$FF
HSCRN_PIXEL_DONE:
        ; store the -1/0 result into the FAC
        CALL GFX_STORE_SIGNED_BYTE_FAC
        ; restore the saved hi-res plot-state cells (bit index, row base, byte addr)
        POP HL
        LD (GFX_HIRES_BIT_INDEX),HL
        POP HL
        LD (GFX_HIRES_ROW_BASE),HL
        POP HL
        LD (GFX_HIRES_BYTE_ADDR),HL
        POP HL
        RET
; ----------------------------------------------------------------------
; GFX_STMT_HCOLOR -- HCOLOR= statement handler (token $D3): set the current hi-res plotting color/mode.
;   In:        HL -> BASIC text after the HCOLOR token (expects '=' then a numeric expression)
;   Out:       falls through into GFX_SET_COLOR_INDEX with A = the evaluated color index (0..12); on return the global plot color/mask state is armed
;   Clobbers:  A, BC, DE, HL (via SYNCHR/GETBYT and the fall-through)
;   Algorithm: Require the literal '=' token (SYNCHR with the inline DEFB TOK_EQ argument it consumes), then GETBYT evaluates the following expression and range-checks it to an 8-bit value in A (and E). Control drops straight into GFX_SET_COLOR_INDEX, which validates and installs the color.
; ----------------------------------------------------------------------
GFX_STMT_HCOLOR:
        ; require the '=' after HCOLOR (the inline DEFB TOK_EQ is the token SYNCHR matches and skips past)
        CALL SYNCHR
        DEFB    TOK_EQ                   ; inline keyword-token arg consumed by the preceding CALL
        ; evaluate the color expression to a 0..255 byte in A, then fall into the shared color-select code
        CALL GETBYT
; ----------------------------------------------------------------------
; GFX_SET_COLOR_INDEX -- validate a hi-res color index and arm the global plot color/mask state.
;   In:        A = color/mode index (0..12); HL -> BASIC text (saved/restored across the body)
;   Out:       GFX_COLOR_INDEX = A; GFX_COLOR_PATTERN = the 2-byte pixel pattern for this color; GFX_PLOT_BYTE_1+1 self-modified to select the color vs erase plot body; the active color-mask table pointer is set via GFX_SELECT_COLOR_MASK and the current point's mask/address state is recomputed (tail JP GFX_XY_TO_HIRES_ADDR_3). HL restored.
;   Clobbers:  A, DE, HL (HL saved/restored around the body)
;   Algorithm: Reject index >= 13 (CP $0D -> ERROR_FC) and store it at GFX_COLOR_INDEX. For index 0..7, read a 2-byte pixel pattern from GFX_HIRES_COLOR_WORDS[2*index] into HL. For 8..11 synthesise a solid pattern: RRA puts the index's low bit into carry, SBC A,A makes A all-0s (even index) or all-1s (odd index); 8/9 then AND $7F (clear bit7), 10/11 then SET 7,A (force bit7); LD H,A/LD L,A duplicate the byte into both halves. Index 12 is the dedicated erase color (no pattern needed). Store the pattern at GFX_COLOR_PATTERN, then self-modify the plotter's JP slot: GFX_PLOT_BYTE_2 for the color (XOR/AND merge) variant, GFX_PLOT_BYTE_7 for the AND $7F erase variant (index 12). Finally select the matching color-mask table and recompute the current pixel's mask/address.
; ----------------------------------------------------------------------
GFX_SET_COLOR_INDEX:
        ; reject indices >= 13 (above 12) with an Illegal Function Call error
        CP $0D
        JP NC,ERROR_FC
        ; record the current plot color/mode index for the mask selector and SCRN reads
        LD (GFX_COLOR_INDEX),A
        PUSH HL
        ; indices 0..7 take a 2-byte pattern from the color-word table; 8..12 are computed/special
        CP $08
        JR NC,GFX_SET_COLOR_INDEX_1
        ; index the pixel-pattern table at base + 2*color and load that word into HL
        LD HL,GFX_HIRES_COLOR_WORDS
        ADD A,A
        LD E,A
        LD D,$00
        ADD HL,DE
        LD E,(HL)
        INC HL
        LD D,(HL)
        EX DE,HL
        JR GFX_SET_COLOR_INDEX_4
GFX_SET_COLOR_INDEX_1:
        ; index 12 is the erase color: route to the AND $7F erase-body selection
        CP $0C
        JR Z,GFX_SET_COLOR_INDEX_6
        CP $0A
        JR NC,GFX_SET_COLOR_INDEX_2
        ; [RE] index low bit -> carry, then SBC A,A makes A a solid all-0 (even) or all-1 (odd) byte
        RRA
        SBC A,A
        ; indices 8/9: clear bit7 of the solid byte
        AND $7F
        JR GFX_SET_COLOR_INDEX_3
GFX_SET_COLOR_INDEX_2:
        RRA
        SBC A,A
        ; indices 10/11: set bit7 of the solid byte
        SET 7,A
GFX_SET_COLOR_INDEX_3:
        ; replicate the solid byte into both halves of the 2-byte pattern
        LD H,A
        LD L,A
GFX_SET_COLOR_INDEX_4:
        ; publish the chosen 2-byte pixel pattern for the plot/line writer
        LD (GFX_COLOR_PATTERN),HL
        ; self-modify the plotter dispatch JP to the color (XOR/AND merge) body
        LD HL,GFX_PLOT_BYTE_2
        LD (GFX_PLOT_BYTE_1+1),HL
GFX_SET_COLOR_INDEX_5:
        ; pick the color-mask table for this index, then recompute the current pixel's mask/address
        CALL GFX_SELECT_COLOR_MASK
        JP GFX_XY_TO_HIRES_ADDR_3
GFX_SET_COLOR_INDEX_6:
        ; erase color: self-modify the plotter dispatch JP to the AND $7F erase body
        LD HL,GFX_PLOT_BYTE_7
        LD (GFX_PLOT_BYTE_1+1),HL
        JR GFX_SET_COLOR_INDEX_5
; ----------------------------------------------------------------------
; GFX_PLOT_BYTE -- write the current pixel's color/mask into the hi-res screen byte(s).
;   In:        the alternate register set holds the plot state (set up by GFX_LOAD_STEP_STATE / GFX_LOAD_COLUMN_MASK before the call): HL' = screen byte address (row base + intra-row X offset), BC' = the two per-column mask bytes (B,C), DE' = the 2-byte color pixel pattern (D,E). [RE] the masks come from the GFX_HIRES_BYTE_ADDR workspace cell, whose name is misleading: GFX_XY_TO_HIRES_ADDR stores two mask-table bytes there, not a screen address. GFX_PLOT_BYTE_1+1 has been self-modified to the active body.
;   Out:       one or two hi-res page bytes updated in place to show the pixel in the current color/mode; registers restored (EXX back) before RET.
;   Clobbers:  A, L (transiently via INC/DEC L); uses the alternate register bank for the screen pointer/masks/pattern.
;   Algorithm: EXX into the bank holding the screen pointer, masks and pattern. BIT 0,L tests the low bit of the screen address (even/odd byte), which selects which mask/pattern half is written first. The self-modified JP at GFX_PLOT_BYTE_1 then enters GFX_PLOT_BYTE_2 (color body: scr = ((scr XOR pattern) AND mask) XOR scr, i.e. set the masked bits to the pattern) or GFX_PLOT_BYTE_7 (erase body: clear/toggle the masked low-7 bits). Each body conditionally writes the neighbour byte too when that half's mask byte has bit7 set (LD A,mask / ADD A,A tests bit7), stepping L across the byte pair.
; ----------------------------------------------------------------------
GFX_PLOT_BYTE:
        ; switch to the alternate bank holding the screen pointer, the two mask bytes and the color pattern
        EXX
        ; [RE] low bit of the screen address (even/odd byte) selects which mask/pattern half is written first
        BIT 0,L
; ----------------------------------------------------------------------
; GFX_PLOT_BYTE_1 -- self-modifying dispatch slot inside GFX_PLOT_BYTE.
;   In:        the 2-byte operand at GFX_PLOT_BYTE_1+1 has been written by GFX_SET_COLOR_INDEX.
;   Out:       jumps to the selected plot body.
;   Clobbers:  none (a single JP).
;   Algorithm: A bare JP whose 2-byte target operand is patched at runtime: GFX_SET_COLOR_INDEX_4 ($4877) stores GFX_PLOT_BYTE_2 (color XOR/AND variant) and GFX_SET_COLOR_INDEX_6 ($4883, index 12) stores GFX_PLOT_BYTE_7 (AND $7F erase variant). The bytes after the C3 JP opcode are this operand, not separate code.
; ----------------------------------------------------------------------
GFX_PLOT_BYTE_1:
        JP GFX_PLOT_BYTE_2
; ----------------------------------------------------------------------
; GFX_PLOT_BYTE_2 -- color plot body: set the addressed hi-res pixel bits to the current color pattern.
;   In:        HL = screen byte address; B,C = the two per-column mask bytes; D,E = the two color-pattern halves; Z flag from BIT 0,L (even vs odd address).
;   Out:       up to two hi-res bytes updated so the masked pixel bits carry the color pattern; registers restored via EXX before RET.
;   Clobbers:  A, L (transiently via INC/DEC L), flags.
;   Algorithm: Branch on the even/odd address (NZ -> GFX_PLOT_BYTE_4, which writes the B/D half first instead of the C/E half). For each half whose mask byte has bit7 set (tested by LD A,mask / ADD A,A): A = screen byte; XOR the matching pattern half (E or D); AND the column mask (C or B) to keep only the addressed bits changing; XOR back with the original screen byte; store. INC/DEC L crosses to the neighbour byte for the second half. A mask byte with bit7 clear skips its half (JP Z to the tail). GFX_PLOT_BYTE_3 / GFX_PLOT_BYTE_5 are the second-byte tails; GFX_PLOT_BYTE_6 is the common EXX/RET exit.
; ----------------------------------------------------------------------
GFX_PLOT_BYTE_2:
        ; [RE] odd address: write the B/D half first instead of the C/E half
        JP NZ,GFX_PLOT_BYTE_4
        ; load this column's mask; the following ADD A,A / JP Z skips this byte when its bit7 is clear
        LD A,C
        ADD A,A
        JP Z,GFX_PLOT_BYTE_3
        LD A,(HL)
        ; merge color: ((scr XOR pattern) AND mask) XOR scr sets only the masked bits to the pattern
        XOR E
        AND C
        XOR (HL)
        LD (HL),A
        LD A,B
        ADD A,A
        JP Z,GFX_PLOT_BYTE_6
GFX_PLOT_BYTE_3:
        ; step to the neighbour screen byte for the second mask/pattern half
        INC L
        LD A,(HL)
        XOR D
        AND B
        XOR (HL)
        LD (HL),A
        DEC L
        EXX
        RET
GFX_PLOT_BYTE_4:
        LD A,B
        ADD A,A
        JP Z,GFX_PLOT_BYTE_5
        LD A,(HL)
        XOR D
        AND B
        XOR (HL)
        LD (HL),A
        LD A,C
        ADD A,A
        JP Z,GFX_PLOT_BYTE_6
GFX_PLOT_BYTE_5:
        INC L
        LD A,(HL)
        XOR E
        AND C
        XOR (HL)
        LD (HL),A
        DEC L
GFX_PLOT_BYTE_6:
        EXX
        RET
; ----------------------------------------------------------------------
; GFX_PLOT_BYTE_7 -- erase plot body (color index 12): clear/toggle the addressed pixel bits, leaving bit7 untouched.
;   In:        HL = screen byte address; B,C = the two per-column mask bytes; Z flag from BIT 0,L (even vs odd address). The color pattern D/E is unused on this path.
;   Out:       up to two hi-res bytes have their addressed low-7 pixel bits XOR'd by the (masked) mask byte, leaving bit7 (the palette/phase bit) untouched on the first-byte writes; registers restored via EXX before RET.
;   Clobbers:  A, L (transiently), flags.
;   Algorithm: Branch on even/odd address like the color body. For the FIRST byte of a half, take the mask (C in the even path, B in the odd path), AND $7F, XOR it into the screen byte and store. For the SECOND (neighbour) byte the tails GFX_PLOT_BYTE_8 / GFX_PLOT_BYTE_10 do NOT freshly reload the mask: they reuse the A left by the preceding LD A,mask / ADD A,A, i.e. a SHIFTED mask byte, then AND $7F. OBSERVED anomaly: GFX_PLOT_BYTE_8 finishes with XOR (HL) (XOR against the screen byte) but GFX_PLOT_BYTE_10 finishes with XOR B (XOR against mask B, NOT the screen byte) before storing. Both the shifted-A reuse and the GFX_PLOT_BYTE_10 XOR B divergence are what the shipped bytes do; the intent of those two second-byte paths is UNKNOWN (not asserting a bug or invented rationale).
; ----------------------------------------------------------------------
GFX_PLOT_BYTE_7:
        ; [RE] odd address: take the B-mask erase path first
        JP NZ,GFX_PLOT_BYTE_9
        LD A,C
        ADD A,A
        JP Z,GFX_PLOT_BYTE_8
        LD A,C
        ; confine the erase mask to the 7 visible pixel bits, preserving the palette/phase bit7
        AND $7F
        ; XOR the masked bits into the screen byte (clear/toggle the addressed pixels)
        XOR (HL)
        LD (HL),A
        LD A,B
        ADD A,A
        JP Z,GFX_PLOT_BYTE_6
GFX_PLOT_BYTE_8:
        INC L
        AND $7F
        XOR (HL)
        LD (HL),A
        DEC L
        EXX
        RET
GFX_PLOT_BYTE_9:
        LD A,B
        ADD A,A
        JP Z,GFX_PLOT_BYTE_10
        LD A,B
        AND $7F
        XOR (HL)
        LD (HL),A
        LD A,C
        ADD A,A
        JP Z,GFX_PLOT_BYTE_6
GFX_PLOT_BYTE_10:
        INC L
        LD A,C
        AND $7F
        XOR B
        LD (HL),A
        DEC L
        EXX
        RET
; ----------------------------------------------------------------------
; GFX_DRAW_LINE -- draw a hi-res line from the current point to a new (X,Y) endpoint (Bresenham).
;   In:        DE = X column (0-279) of the new endpoint, C = Y row (0-191) of the new endpoint;
;              current point in GFX_X_COORD (word) / GFX_Y_COORD (byte); color already selected.
;   Out:       line plotted; GFX_X_COORD/GFX_Y_COORD updated to the new endpoint. On return the
;              alternate register set holds the last pixel's working state: BC = the two column
;              bit-mask bytes (the value of GFX_HIRES_BYTE_ADDR), DE = the color pixel-pattern word
;              (GFX_COLOR_PATTERN), HL = the live screen pointer; the HPLOT caller reads these back.
;              Returns when the major-axis step counter (BC) reaches zero.
;   Clobbers:  A,BC,DE,HL, AF'/BC'/DE'/HL', and the three SMC operand cells GFX_DRAW_LINE_7+1 /
;              _9+1 / _10+1 (the major/minor step-routine CALL targets and the [RE] major-count
;              value used in the error-reset add).
;   Algorithm: Compute |dy| = |Ycur - Ynew| and |dx| = |Xnew - Xcur|, selecting the Y/row stepper
;              (GFX_LOAD_STEP_STATE_1 for up, GFX_STEP_ROW for down) for the vertical move and the
;              X/column stepper (GFX_STEP_BIT for +X, GFX_STEP_ROW_6 for -X) for the horizontal move.
;              Pick the larger delta as the MAJOR axis (its step routine is self-modified into the
;              always-taken CALL at _7 and its count drives the loop) and the smaller as the MINOR
;              axis (its step routine into the conditional CALL at _9, its count into DE). _10+1 is
;              self-modified to the MAJOR count. Seed the error term HL to majorcount/2; each loop
;              iteration subtracts the minor count from HL and, when it underflows, takes one minor
;              step and adds the major count back (_10), then always takes one major step and calls
;              GFX_PLOT_BYTE.
; ----------------------------------------------------------------------
GFX_DRAW_LINE:
        CALL GFX_SELECT_COLOR_MASK
        ; vertical delta: |dy| = |Ycur - Ynew|; choose the Y/row stepper for the direction (up vs down)
        LD A,(GFX_Y_COORD)
        LD HL,GFX_LOAD_STEP_STATE_1
        SUB C
        JR NC,GFX_DRAW_LINE_1
        CPL
        INC A
        LD HL,GFX_STEP_ROW
GFX_DRAW_LINE_1:
        PUSH HL
        PUSH AF
        LD A,C
        LD (GFX_Y_COORD),A
        ; horizontal delta: store the new X as current, dx = Xnew - Xcur (abs value), and pick the +X (GFX_STEP_BIT) or -X (GFX_STEP_ROW_6) column stepper
        LD HL,(GFX_X_COORD)
        EX DE,HL
        LD (GFX_X_COORD),HL
        OR A
        ; Bresenham error update: subtract the MINOR delta; on underflow take a minor-axis step and add the major count back
        SBC HL,DE
        JR NC,GFX_DRAW_LINE_2
        ADD HL,DE
        EX DE,HL
        OR A
        SBC HL,DE
        LD DE,GFX_STEP_ROW_6
        JR GFX_DRAW_LINE_3
GFX_DRAW_LINE_2:
        LD DE,GFX_STEP_BIT
GFX_DRAW_LINE_3:
        POP BC
        ; choose the major axis: X is major when |dx| > |dy| (else Y is major); the larger delta drives the loop count
        LD A,H
        OR A
        LD A,B
        JR NZ,GFX_DRAW_LINE_4
        CP L
        JR C,GFX_DRAW_LINE_4
        EX (SP),HL
        ; Y-major branch: self-modify the always-taken CALL _7 to the major (Y/row) stepper and the conditional CALL _9 to the minor (X/column) stepper
        LD (GFX_DRAW_LINE_7+1),HL
        EX DE,HL
        LD (GFX_DRAW_LINE_9+1),HL
        LD L,A
        LD H,$00
        POP DE
        PUSH HL
        JR GFX_DRAW_LINE_5
GFX_DRAW_LINE_4:
        EX (SP),HL
        ; X-major branch (swapped vs Y-major): conditional CALL _9 = minor (Y/row) stepper, always-taken CALL _7 = major (X/column) stepper
        LD (GFX_DRAW_LINE_9+1),HL
        EX DE,HL
        LD (GFX_DRAW_LINE_7+1),HL
        LD E,A
        LD D,$00
GFX_DRAW_LINE_5:
        POP HL
        LD (GFX_DRAW_LINE_10+1),HL
        LD B,H
        LD C,L
        INC BC
        OR A
        ; seed the Bresenham error term to majorcount/2
        RR H
        RR L
        JR GFX_DRAW_LINE_8
GFX_DRAW_LINE_6:
        EXX
; ----------------------------------------------------------------------
; GFX_DRAW_LINE_7 -- per-step MAJOR-axis CALL site (self-modified operand).
;   In:        operand byte at GFX_DRAW_LINE_7+1 patched by GFX_DRAW_LINE to whichever step routine
;              drives the major axis (Y/row: GFX_LOAD_STEP_STATE_1 or GFX_STEP_ROW; X/column:
;              GFX_STEP_BIT or GFX_STEP_ROW_6), per the major-axis branch.
;   Out:       advances the working screen state one pixel along the major axis (alternate reg set).
;   Clobbers:  per the selected step routine.
;   Algorithm: This label exists only because GFX_DRAW_LINE_7+1 is a self-modifying-code operand; the
;              CALL opcode here is executed every Bresenham iteration with the patched target.
; ----------------------------------------------------------------------
GFX_DRAW_LINE_7:
        CALL GFX_STEP_ROW
        EXX
        ; write the pixel at the current screen byte for this step
        CALL GFX_PLOT_BYTE
GFX_DRAW_LINE_8:
        DEC BC
        LD A,B
        OR C
        RET Z
        AND A
        SBC HL,DE
        JR NC,GFX_DRAW_LINE_6
        EXX
; ----------------------------------------------------------------------
; GFX_DRAW_LINE_9 -- per-step MINOR-axis CALL site (self-modified operand), paired with GFX_DRAW_LINE_7.
;   In:        operand byte at GFX_DRAW_LINE_9+1 patched by GFX_DRAW_LINE to the OTHER step routine
;              from _7 (the minor axis).
;   Out:       advances the working screen state one pixel along the minor axis when the error term
;              underflows (alternate reg set).
;   Clobbers:  per the selected step routine.
;   Algorithm: Reached only on a minor-axis step; the CALL operand is SMC, patched once per line by
;              GFX_DRAW_LINE.
; ----------------------------------------------------------------------
GFX_DRAW_LINE_9:
        CALL GFX_STEP_BIT
        EXX
        PUSH DE
; ----------------------------------------------------------------------
; GFX_DRAW_LINE_10 -- Bresenham error-reset add (self-modified LD DE immediate = the major-axis count).
;   In:        the 16-bit immediate at GFX_DRAW_LINE_10+1 self-modified by GFX_DRAW_LINE to the MAJOR
;              count (|dx| when X-major, |dy| when Y-major); HL (main reg set) = the running Bresenham
;              error accumulator.
;   Out:       HL += the major count (the standard error-term reset after a minor-axis step), executed
;              with the alternate set already switched back to main (the screen pointer in the
;              alternate HL is NOT touched here).
;   Clobbers:  HL; DE preserved (pushed/popped around the add).
;   Algorithm: Run only on the minor-step branch: after CALL _9 steps the minor axis, switch back to
;              the main registers and add the patched major count back into the error accumulator HL,
;              then loop to GFX_DRAW_LINE_6 for the always-taken major step. This is the Bresenham
;              error reset, NOT a screen-address increment.
; ----------------------------------------------------------------------
GFX_DRAW_LINE_10:
        LD DE,$0000
        ADD HL,DE
        POP DE
        JP GFX_DRAW_LINE_6
; ----------------------------------------------------------------------
; GFX_XY_TO_HIRES_ADDR -- convert (X,Y) to an Apple hi-res screen address, bit index, and color mask pair.
;   In:        DE = X column (0-279), C = Y row (0-191).
;   Out:       GFX_X_COORD = X, GFX_Y_COORD = Y; GFX_HIRES_ROW_BASE = interleaved scan-line base
;              address (this build's hi-res buffer is based at $1000, so the high byte lands in
;              $10-$2F); GFX_HIRES_BIT_INDEX = X mod 14 (intra-cell bit position, set via GFX_XY_HELPER);
;              GFX_X_FRACTION = byte offset within the row; GFX_HIRES_BYTE_ADDR = the 2 column
;              bit-mask bytes for this point (E = mask at the bit column, D = mask at column+7).
;              HL preserved (pushed/popped).
;   Clobbers:  A,BC,DE.
;   Algorithm: Select the color mask table, then build the Apple interleaved hi-res row address from
;              Y (AND $C0 + rotates to spread the three address bit-groups, AND $1F, + $10 base into
;              H). Split X into byte+bit via GFX_XY_HELPER, store the byte offset, then index the active
;              color-mask table twice (at the bit column and at column+7, the second wrapped down by
;              $0E when it crosses into the next 14-pixel cell) to fetch the low/high mask bytes for
;              GFX_PLOT_BYTE.
; ----------------------------------------------------------------------
GFX_XY_TO_HIRES_ADDR:
        PUSH HL
        CALL GFX_SELECT_COLOR_MASK
        EX DE,HL
        LD (GFX_X_COORD),HL
        EX DE,HL
        LD A,C
        LD (GFX_Y_COORD),A
GFX_XY_TO_HIRES_ADDR_1:
        ; build the Apple interleaved hi-res scan-line address from Y: spread Y's bit groups across H (high byte $10-$2F, the $1F group plus the $10 buffer base) and L (byte-in-line)
        AND $C0
        LD L,A
        RRA
        RRA
        OR L
        LD L,A
        LD A,C
        ADD A,A
        ADD A,A
        LD H,A
        ADD A,A
        RLA
        RLA
        RR L
        OR H
        AND $1F
        ADD A,$10
        LD H,A
        LD (GFX_HIRES_ROW_BASE),HL
        EX DE,HL
        ; split the X column into a byte index (B) and an intra-cell bit index (GFX_HIRES_BIT_INDEX = X mod 14)
        CALL GFX_XY_HELPER
        SUB $07
        JR C,GFX_XY_TO_HIRES_ADDR_2
        INC B
GFX_XY_TO_HIRES_ADDR_2:
        LD A,B
        LD (GFX_X_FRACTION),A
GFX_XY_TO_HIRES_ADDR_3:
        ; index the active color-mask table to fetch the two mask bytes (E at this bit column, D at column+7 wrapped) for GFX_PLOT_BYTE
        LD A,(GFX_HIRES_BIT_INDEX)
        LD C,A
; [RE] SMC: LD HL immediate = the active hi-res color-mask table base. $4812 stores GFX_HIRES_COLOR_MASK_TABLE_B ($4AC5); GFX_SELECT_COLOR_MASK $4AB3 stores table A ($4AB7) or B ($4AC5) per color index. $49AB is the operand, not code.
GFX_XY_TO_HIRES_ADDR_4:
        LD HL,$0000
        PUSH HL
        LD B,$00
        ADD HL,BC
        LD E,(HL)
        LD A,C
        POP HL
        ADD A,$07
        LD C,A
        SUB $0E
        JR C,GFX_XY_TO_HIRES_ADDR_5
        LD C,A
GFX_XY_TO_HIRES_ADDR_5:
        ADD HL,BC
        LD D,(HL)
        EX DE,HL
        ; store the 2 column bit-mask bytes (E:D, here in HL) for the current point
        LD (GFX_HIRES_BYTE_ADDR),HL
        POP HL
        RET
; ----------------------------------------------------------------------
; GFX_XY_HELPER -- normalize an X column into a 14-pixel-cell byte index and intra-cell bit position.
;   In:        HL = X coordinate (0-279).
;   Out:       B = 2 * (X div 14) (the screen byte-pair index, doubled because each 14-pixel color
;              cell spans two screen bytes); GFX_HIRES_BIT_INDEX = X mod 14 (the bit position within
;              the 14-pixel cell).
;   Clobbers:  A,B,DE,HL.
;   Algorithm: Repeatedly add -14 ($FFF2) to HL, counting in A, until HL goes negative; A then holds
;              X div 14. Double A into B. The final iteration over-subtracts by 14, so the leftover
;              low byte + $0E (14) recovers exactly X mod 14, which is stored as the bit index.
; ----------------------------------------------------------------------
GFX_XY_HELPER:
        LD DE,$FFF2
        LD A,D
GFX_XY_HELPER_1:
        ; count how many whole 14-pixel cells fit in X: repeatedly subtract 14 until the value goes negative
        INC A
        ADD HL,DE
        JR C,GFX_XY_HELPER_1
        ; two screen bytes per 14-pixel color cell, so the byte-pair index is 2 * (X div 14)
        ADD A,A
        LD B,A
        LD A,L
        ; add back the 14 the loop over-subtracted on its last pass, recovering exactly X mod 14 as the bit index
        ADD A,$0E
        LD (GFX_HIRES_BIT_INDEX),A
        RET
; ----------------------------------------------------------------------
; GFX_LOAD_COLUMN_MASK -- fetch the per-column hi-res bit mask for the current point into A'.
;   In:        GFX_HIRES_BIT_INDEX = intra-cell bit position (0-13) of the current point.
;   Out:       A' (alternate accumulator) = the column's bit-mask byte ANDed with $7F (high bit
;              cleared); alternate register set selected (EXX) on exit. Falls through into
;              GFX_LOAD_STEP_STATE.
;   Clobbers:  A,DE,HL (in the alternate set after the EXX); AF'.
;   Algorithm: Switch to the alternate registers, fold the bit index into the 7-bit screen byte
;              (subtract 7 if >= 7, the two bytes of a 14-pixel cell share one 7-bit pattern), index
;              GFX_HIRES_COLOR_MASK_TABLE_B, mask off the high bit, and stash the result in A' for the
;              plot writer; then fall into GFX_LOAD_STEP_STATE.
; ----------------------------------------------------------------------
GFX_LOAD_COLUMN_MASK:
        EXX
        LD HL,GFX_HIRES_COLOR_MASK_TABLE_B
        LD D,$00
        LD A,(GFX_HIRES_BIT_INDEX)
        ; fold the bit index into the 7-pixel screen byte (a 14-pixel cell spans two bytes that share one 7-bit pattern)
        SUB $07
        JR NC,GFX_LOAD_COLUMN_MASK_1
        ADD A,$07
GFX_LOAD_COLUMN_MASK_1:
        LD E,A
        ADD HL,DE
        LD A,(HL)
        ; clear the high (color-phase) bit; the mask is a 7-pixel pattern
        AND $7F
        ; hand the column mask to A' for GFX_PLOT_BYTE, then fall into the step-state loader
        EX AF,AF'
; ----------------------------------------------------------------------
; GFX_LOAD_STEP_STATE -- load the plot/line working point from save cells into the alternate registers.
;   In:        GFX_HIRES_BYTE_ADDR, GFX_COLOR_PATTERN, GFX_X_FRACTION, GFX_HIRES_ROW_BASE (the saved
;              current-point state).
;   Out:       alternate set: BC = the two column bit-mask bytes (the value of GFX_HIRES_BYTE_ADDR),
;              DE = the color pixel-pattern word, HL = row-base address + X byte offset (the live
;              screen pointer). Main register set restored on exit (EXX); RET.
;   Clobbers:  A; alternate BC/DE/HL.
;   Algorithm: Pull the current point's mask bytes, color pattern, and row base from the workspace
;              cells into the alternate registers and add the X sub-byte fraction to the row-base low
;              byte to form the live screen pointer, so the Bresenham steppers and GFX_PLOT_BYTE can
;              run entirely in the alternate set.
; ----------------------------------------------------------------------
GFX_LOAD_STEP_STATE:
        ; BC = the two column bit-mask bytes for the current point (used as masks by GFX_PLOT_BYTE)
        LD HL,(GFX_HIRES_BYTE_ADDR)
        LD C,L
        LD B,H
        ; DE = the two-byte color pixel pattern for the selected HCOLOR
        LD HL,(GFX_COLOR_PATTERN)
        EX DE,HL
        LD A,(GFX_X_FRACTION)
        LD HL,(GFX_HIRES_ROW_BASE)
        ; HL = row base + X byte offset = the live hi-res screen pointer for plotting
        ADD A,L
        LD L,A
        EXX
        RET
; ----------------------------------------------------------------------
; GFX_LOAD_STEP_STATE_1 -- Y/row step (up): move the working screen pointer one scan line toward smaller Y.
;   In:        L = low byte of the current screen pointer; GFX_HIRES_ROW_BASE = current row base.
;   Out:       GFX_HIRES_ROW_BASE advanced one display row (handling the Apple hi-res interleave and
;              page-group wrap); the pointer's offset within the row re-applied via the shared tail.
;              Joins the GFX_STEP_ROW tail at GFX_STEP_ROW_3 / GFX_STEP_ROW_5.
;   Clobbers:  A,HL (and the stack via PUSH AF / POP AF in the shared tail).
;   Algorithm: Save the pointer's offset past its row base, then adjust the high byte by -$14 to move
;              to the adjacent interleaved scan group; on wrap re-base H to $2F and shift L by $28
;              [RE] -- this is the decreasing-Y direction, mirroring GFX_STEP_ROW's increasing-Y case.
;              GFX_DRAW_LINE selects this routine (vs GFX_STEP_ROW) by the sign of the Y delta; it
;              then serves as the major or minor stepper depending on which axis Y is.
; ----------------------------------------------------------------------
GFX_LOAD_STEP_STATE_1:
        LD A,L
        LD HL,(GFX_HIRES_ROW_BASE)
        ; remember how far the live pointer sits past its row base, to re-apply after re-basing the row
        SUB L
        PUSH AF
        LD A,H
        ; step to the adjacent scan line by adjusting the interleaved hi-res row group in H
        SUB $14
        JR NC,GFX_STEP_ROW_3
        RL L
        RLA
        DEC A
        BIT 3,A
        JR NZ,GFX_STEP_ROW_1
        ; [RE] wrapped the page group: re-base H to $2F and shift L by one byte-line ($28)
        LD H,$2F
        SCF
        LD A,L
        RRA
        SUB $28
        LD L,A
        JP GFX_STEP_ROW_5
; ----------------------------------------------------------------------
; GFX_STEP_ROW -- hi-res row stepper: move the current plot point DOWN one scan line (Y+1).
;   In:        Alternate register set active (the line drawer EXX's before calling). HL = current screen pointer (current row-base low byte plus the X sub-byte offset in L, page in H). GFX_HIRES_ROW_BASE = the 16-bit screen address of the current row's left edge.
;   Out:       GFX_HIRES_ROW_BASE advanced to the next scan line down; HL reformed as the new row base plus the preserved X sub-byte offset (so the screen pointer follows the same column on the new row).
;   Clobbers:  A, HL, flags; pushes/pops AF internally to preserve the X sub-byte offset across the row-base update.
;   Algorithm: Apple hi-res scan lines within a 64-line group are $0400 apart and the three groups interleave. Recover the X sub-byte offset (A = old L minus row-base low). Then advance the page/row: compute A = H - $0C and test BIT 5. [RE] When BIT 5 is CLEAR the next line stays in the current 8-line page band, so just ADD $10 to H. When BIT 5 is SET the step crosses a band/group boundary, so re-derive the low byte (the wrap path uses RL L/RLA/INC A then BIT 3 to pick between the $28 row-spacing add with H reset to $10, or the XOR $60 group toggle) and reset H accordingly. Store the new row base, then re-add the saved X offset to L. This is the step-DOWN routine; GFX_LOAD_STEP_STATE_1 is the step-UP twin (the line drawer selects one as the Y-axis stepper). [RE] The exact interleave arithmetic of the wrap branches (BIT 3 / XOR $60 / $28) is inferred from the Apple hi-res row layout, not fully traced. NOTE: the prior in-file [RE] gloss calling this an 'X step that advances the bit mask' is WRONG -- it advances the row (Y), not the column.
; ----------------------------------------------------------------------
GFX_STEP_ROW:
        LD A,L
        LD HL,(GFX_HIRES_ROW_BASE)
        ; recover the saved X sub-byte offset within the row (A = current L minus row-base low byte)
        SUB L
        ; stash the X offset so it can be re-added after the row base advances
        PUSH AF
        LD A,H
        SUB $0C
        ; [RE] bit 5 of (H-$0C) clear: next line stays in this page band; set: cross a band/group boundary
        BIT 5,A
        JR Z,GFX_STEP_ROW_3
        RL L
        RLA
        INC A
        BIT 3,A
        JR Z,GFX_STEP_ROW_2
        ; [RE] crossed an interleave group: reset the page base to $10 on the wrap branch
        LD H,$10
        LD A,L
        RRA
        ; [RE] advance the row-base low byte by the $28 group row-spacing on the wrap branch
        ADD A,$28
        LD L,A
        JP GFX_STEP_ROW_5
GFX_STEP_ROW_1:
        AND $3F
GFX_STEP_ROW_2:
        XOR $60
        RRA
        RR L
        JP GFX_STEP_ROW_4
GFX_STEP_ROW_3:
        ; still in the page band: bump the page byte by $10 to the next scan line
        ADD A,$10
GFX_STEP_ROW_4:
        LD H,A
GFX_STEP_ROW_5:
        ; commit the new scan-line row base
        LD (GFX_HIRES_ROW_BASE),HL
        POP AF
        ; re-apply the saved X sub-byte offset so the pointer tracks the same column on the new row
        ADD A,L
        LD L,A
        RET
; ----------------------------------------------------------------------
; GFX_STEP_ROW_6 -- hi-res column stepper: move the current plot point LEFT one pixel (X-1).
;   In:        Alternate register set active. A' (reached via EX AF,AF') = the single-bit intra-byte phase flag; L = screen pointer low byte; B/C = the two adjacent-byte single-column write masks consumed by GFX_PLOT_BYTE (C for the current byte, B for the neighbor byte). [RE] which neighbor (left vs right) B represents is inferred, not proven.
;   Out:       B/C rotated right by one bit position (active column shifted one pixel left); L decremented when the pixel crosses to the previous screen byte; A' phase flag updated.
;   Clobbers:  A' (alternate A), B, C, L, flags.
;   Algorithm: The X-decreasing (leftward) column stepper, twin of GFX_STEP_BIT (rightward). Rotate the phase flag in A' right (RRCA); on carry-out the pixel left the byte, so DEC L (step to the previous screen byte) and rotate A' again. Then SCF + RR the masks (RR B, RR C) so a 1 enters the high bit, conditionally RES the wrap bit (RES 7,C when B did not carry, RES 6,B when C did not carry) so exactly one column stays selected across the byte boundary. The drawer self-modifies this routine into GFX_DRAW_LINE's CALL operand as the X stepper (major axis for an X-major leftward line, minor axis for a Y-major line). [RE] The exact wrap-bit bookkeeping is inferred from the mask shape, not fully traced.
; ----------------------------------------------------------------------
GFX_STEP_ROW_6:
        EX AF,AF'
        ; rotate the intra-byte phase flag right; carry out means the pixel left the low end of the byte
        RRCA
        JP NC,GFX_STEP_ROW_7
        ; pixel crossed a byte boundary: step the screen pointer to the previous byte
        DEC L
        RRCA
GFX_STEP_ROW_7:
        EX AF,AF'
        SCF
        ; shift the neighbor-byte column mask right (a 1 is fed in via the preceding SCF)
        RR B
        JP C,GFX_STEP_ROW_8
        ; [RE] clear the wrap bit so only the active column stays masked when the neighbor did not carry
        RES 7,C
GFX_STEP_ROW_8:
        SCF
        ; shift the current-byte column mask right one pixel position
        RR C
        RET C
        ; [RE] clear the spill bit in the neighbor mask after the cross
        RES 6,B
        RET
; ----------------------------------------------------------------------
; GFX_STEP_BIT -- hi-res column stepper: move the current plot point RIGHT one pixel (X+1).
;   In:        Alternate register set active. A' = the single-bit intra-byte phase flag; L = screen pointer low byte; B/C = the two adjacent-byte single-column write masks consumed by GFX_PLOT_BYTE. [RE] B vs C neighbor assignment inferred.
;   Out:       B/C rotated left one bit position (active column shifted one pixel right); L incremented when the pixel crosses into the next screen byte; A' phase flag updated.
;   Clobbers:  A' (alternate A), B, C, L, flags.
;   Algorithm: The X-increasing (rightward) column stepper, twin of GFX_STEP_ROW_6 (leftward). Shift the phase flag left (ADD A,A); when it goes negative (JP P not taken) the pixel left the high end of the byte, so INC L to the next screen byte and re-seed the flag (RLCA). Then SCF and manage the carry across the masks: BIT 6,B and the conditional OR A select whether the carry feeds the neighbor byte, RL C / RL B shift the masks left, SET 7,C (conditional) / SET 7,B (unconditional) re-seed the wrap bit so one column stays selected across the byte boundary. The drawer self-modifies this into the CALL operand as the X stepper. [RE] The exact carry/SET-bit bookkeeping is inferred from the mask shape, not fully traced.
; ----------------------------------------------------------------------
GFX_STEP_BIT:
        EX AF,AF'
        ; shift the intra-byte phase flag left; a negative result means the pixel left the high end of the byte
        ADD A,A
        JP P,GFX_STEP_BIT_1
        ; pixel crossed a byte boundary: step the screen pointer to the next byte
        INC L
        RLCA
GFX_STEP_BIT_1:
        EX AF,AF'
        SCF
        ; [RE] test bit 6 of the neighbor mask to decide whether the carry feeds the neighbor byte
        BIT 6,B
        JP NZ,GFX_STEP_BIT_2
        OR A
GFX_STEP_BIT_2:
        ; shift the current-byte column mask left one pixel position
        RL C
        JP M,GFX_STEP_BIT_3
        OR A
        ; [RE] re-seed the high column bit so one column stays selected after the shift
        SET 7,C
GFX_STEP_BIT_3:
        ; shift the neighbor-byte column mask left in step
        RL B
        ; [RE] re-seed the neighbor mask's high bit for the cross-byte case
        SET 7,B
        RET
; ----------------------------------------------------------------------
; GFX_HIRES_COLOR_WORDS -- hi-res color -> two-byte pixel-pattern lookup table (8 entries x 2 bytes).
;   In:        Indexed by GFX_SET_COLOR_INDEX as base + 2*colorIndex, for color indices 0-7 only (indices 8-11 compute their pattern arithmetically instead and do not read this table).
;   Out:       The selected 16-bit word (read little-endian into DE, then EX DE,HL) is stored at GFX_COLOR_PATTERN; GFX_LOAD_COLUMN_MASK / GFX_PLOT_BYTE later load it as the D/E pixel pattern.
;   Clobbers:  (data table, no code).
;   Algorithm: Eight color words, read little-endian: 0=$0000 black, 1=$552A, 2=$2A55, 3=$7F7F white, then high-bit (palette-shift) variants 4=$8080, 5=$D5AA, 6=$AAD5, 7=$FFFF. [RE] Entries 1/2 and 5/6 are the two halftone phases of a color (the byte pair swaps $2A/$55 or $AA/$D5) so adjacent screen bytes get complementary patterns; bit 7 ($80) selects the Apple palette-shift group. Specific color names (violet/green/blue/orange) are the conventional Apple hi-res assignments and are [RE] inference.
; ----------------------------------------------------------------------
GFX_HIRES_COLOR_WORDS:
        DEFB    $00,$00,$2A,$55,$55,$2A,$7F,$7F,$80,$80,$AA,$D5,$D5,$AA,$FF,$FF
; ----------------------------------------------------------------------
; GFX_SELECT_COLOR_MASK -- choose hi-res column-mask table A or B for the current color and patch it into the address-builder's self-modified pointer.
;   In:        GFX_COLOR_INDEX = current color/mode index (0-12). DE = a 16-bit value (the X coordinate on the GFX_XY_TO_HIRES_ADDR / GFX_DRAW_LINE call paths) used by the index>=8 / odd-phase branch.
;   Out:       The chosen table base (GFX_HIRES_COLOR_MASK_TABLE_A or _B) is written into GFX_XY_TO_HIRES_ADDR_4+1, the self-modified LD HL immediate that the address builder uses to fetch the per-column mask byte.
;   Clobbers:  A, HL, flags; DE may be decremented (DEC DE) on one branch.
;   Algorithm: Default to table B. Index 12 keeps B. For index < 8: take (colorIndex AND 3); phases 0 and 3 keep B, phases 1 and 2 fall to the table-A path. For index >= 8 also take the table-A path. On the table-A path it first does LD HL,$FEE9 / AND A / ADC HL,DE: $FEE9 = -$0117 = -279, so HL = DE - 279; if DE == 279 (Z set) it does DEC DE before loading table A. [RE] $0117 = 279 is the maximum hi-res X column index, so this looks like a right-edge clamp nudging the X coordinate in DE left by one when it sits at the extreme right; the downstream consumer of the modified DE is not fully traced, so treat the DE side effect as [RE]/UNKNOWN. The selected table base is the firmly verified output.
; ----------------------------------------------------------------------
GFX_SELECT_COLOR_MASK:
        LD A,(GFX_COLOR_INDEX)
        ; default to mask table B
        LD HL,GFX_HIRES_COLOR_MASK_TABLE_B
        ; index 12 (full-screen erase mode) keeps table B unchanged
        CP $0C
        JR Z,GFX_SELECT_COLOR_MASK_3
        ; indices >= 8 take the table-A path
        CP $08
        JR NC,GFX_SELECT_COLOR_MASK_1
        ; isolate the halftone phase of indices < 8; phases 0 and 3 keep table B
        AND $03
        JR Z,GFX_SELECT_COLOR_MASK_3
        CP $03
        JR Z,GFX_SELECT_COLOR_MASK_3
GFX_SELECT_COLOR_MASK_1:
        ; [RE] $FEE9 = -279; HL = DE - 279 to test the X coordinate against the rightmost hi-res column
        LD HL,$FEE9
        AND A
        ADC HL,DE
        JR NZ,GFX_SELECT_COLOR_MASK_2
        ; [RE] nudge the X coordinate left by one when it sits at the extreme right edge (DE == 279)
        DEC DE
GFX_SELECT_COLOR_MASK_2:
        ; select mask table A
        LD HL,GFX_HIRES_COLOR_MASK_TABLE_A
GFX_SELECT_COLOR_MASK_3:
        ; self-modify the address builder's mask-table pointer to the chosen table
        LD (GFX_XY_TO_HIRES_ADDR_4+1),HL
        RET
; ----------------------------------------------------------------------
; GFX_HIRES_COLOR_MASK_TABLE_A -- hi-res per-column bit masks, palette/phase A.
;   In:        Indexed by intra-byte column via GFX_XY_TO_HIRES_ADDR_4's self-modified pointer; also referenced by GFX_LOAD_COLUMN_MASK.
;   Out:       Each byte is a single-column write mask used by GFX_PLOT_BYTE / the address builder to select one pixel column of a hi-res byte; bit 7 is the palette-shift flag.
;   Clobbers:  (data table, no code).
;   Algorithm: 14 bytes $83,$86,$8C,$98,$B0,$E0,$C0 then $80 x6,$81. [RE] The first 7 entries walk a column mask across the 7 pixels of a hi-res byte for this palette phase; the trailing $80 run plus the $81 wrap entry cover the adjacent-byte carry positions used when a step crosses a byte boundary. The violet-green palette assignment is [RE] inference.
; ----------------------------------------------------------------------
GFX_HIRES_COLOR_MASK_TABLE_A:
        DEFB    $83,$86,$8C,$98,$B0,$E0,$C0,$80,$80,$80,$80,$80,$80,$81
; ----------------------------------------------------------------------
; GFX_HIRES_COLOR_MASK_TABLE_B -- hi-res per-column bit masks, palette/phase B; the default table.
;   In:        Indexed by intra-byte column via the address builder's self-modified pointer; loaded as the default by GFX_SELECT_COLOR_MASK and GFX_LOAD_COLUMN_MASK.
;   Out:       Each byte is a single-column write mask for this palette phase (bit 7 = palette flag).
;   Clobbers:  (data table, no code).
;   Algorithm: 7 active bytes $81,$82,$84,$88,$90,$A0,$C0 -- a single bit walking left across the 7 pixel columns of a hi-res byte -- followed by an 8-byte $80 fill covering the cross-byte carry positions. The blue-orange palette assignment is [RE] inference.
; ----------------------------------------------------------------------
GFX_HIRES_COLOR_MASK_TABLE_B:
        DEFB    $81,$82,$84,$88,$90,$A0,$C0
        DEFS    8, $80                   ; fill
; ----------------------------------------------------------------------
; GFX_STMT_HGR -- HGR statement (token $D1): enter hi-res graphics mode, optionally set color, and clear the screen.
;   In:        HL = BASIC text pointer; the dispatcher's Z flag indicates whether a mode-argument byte follows (NZ => evaluate it via GETBYT).
;   Out:       HIRES mode cell set; display soft switches programmed (GFX_SET_DISPLAY_MODE); plot color set (GFX_SET_COLOR_INDEX); hi-res page optionally filled/cleared. HL advanced past consumed arguments.
;   Clobbers:  A, BC, DE, HL, flags; writes the HIRES cell and the screen page buffer.
;   Algorithm: Read the mode byte (default 0, or GETBYT if an arg follows), range-check < 4 (else ERROR_FC) and store it to HIRES. GFX_SET_DISPLAY_MODE programs the actual display soft switches. Read the optional color/fill argument and set the plot color (GFX_SET_COLOR_INDEX). If bit 1 of the mode byte is set, return without clearing. Otherwise clear the page: for color index $0C complement (XOR $7F) every byte of the page, else broadcast the 2-byte GFX_COLOR_PATTERN across the page with LDIR. NOTE: the page buffer here is at RELOCATE_AND_RUN ($1000); in this self-relocated GBASIC layout that region aliases the working hi-res page memory. [RE] the $1000 aliasing is inference from the layout.
; ----------------------------------------------------------------------
GFX_STMT_HGR:
        LD A,$00
        ; an argument follows: evaluate the hi-res mode byte (else it defaults to 0)
        CALL NZ,GETBYT
        ; valid hi-res modes are 0-3
        CP $04
GFX_STMT_HGR_1:
        JP NC,ERROR_FC
        ; record the requested mode (GFX_SET_DISPLAY_MODE below programs the soft switches)
        LD (HIRES),A
        PUSH AF
        CALL GFX_SET_DISPLAY_MODE
        LD A,$00
        JR NZ,GFX_STMT_HGR_2
        INC HL
        CALL GETBYT
GFX_STMT_HGR_2:
        PUSH AF
        ; set the current plot color from the optional second argument
        CALL GFX_SET_COLOR_INDEX
        POP BC
        POP AF
        ; mode bit 1 set means 'enter graphics but do not clear the screen'
        AND $02
        RET NZ
        LD A,B
        CP $0C
        JR Z,GFX_STMT_HGR_ERASE_PAGE
        PUSH HL
        LD HL,RELOCATE_AND_RUN
        LD HL,(GFX_COLOR_PATTERN)
        LD (RELOCATE_AND_RUN),HL
        LD HL,RELOCATE_AND_RUN
        LD DE,$1002
        LD BC,$1FFE
        ; clear the page by broadcasting the 2-byte color pattern across it
        LDIR
        POP HL
        RET
GFX_STMT_HGR_ERASE_PAGE:
        LD DE,RELOCATE_AND_RUN
GFX_STMT_HGR_ERASE_PAGE_1:
        LD A,(DE)
        ; color index 12: erase the page by complementing each byte instead of pattern-filling
        XOR $7F
        LD (DE),A
        INC DE
        LD A,D
        CP $30
        JR NZ,GFX_STMT_HGR_ERASE_PAGE_1
        RET
; ----------------------------------------------------------------------
; GFX_READ_COORD_PAIR -- parse and range-check a two-number coordinate pair "<n>,<m>" from BASIC text.
;   In:        HL = BASIC text pointer positioned at the first coordinate expression.
;   Out:       DE = first value (range-checked 0..23, this value is stored as GFX_X_COORD by GFX_XY_TO_HIRES_ADDR); C = second value (range-checked 0..191, stored as GFX_Y_COORD); HL advanced past both numbers and the comma. On either out-of-range it jumps to the shared ERROR_FC site (labeled GFX_STMT_HGR_1) and does not return.
;   Clobbers:  A, C, DE, HL, flags; consumes the inline ',' separator.
;   Algorithm: GETINT evaluates the first value into DE and the CP $18 / SBC A,$01 pair range-checks it against 0..23 (else ERROR_FC). SYNCHR consumes the required ','. GETBYT evaluates the second value and CP $C0 checks it < 192 (else ERROR_FC); it is returned in C. NOTE: the first value (0-23) is stored as GFX_X_COORD and the second (0-191) as GFX_Y_COORD by the caller. [RE]/UNKNOWN: the row-vs-column semantic meaning is unverified -- the 0-23 bound on the X-coord slot does not map cleanly to a 280-wide hi-res X, so do not assert which is row vs column. This is the generic coordinate reader for the hi-res statements.
; ----------------------------------------------------------------------
GFX_READ_COORD_PAIR:
        CALL GETINT
        LD A,E
        ; first value must be 0-23 (reject 24+ or negative)
        CP $18
        LD A,D
        SBC A,$01
        JR NC,GFX_STMT_HGR_1
        PUSH DE
        ; require the comma separator between the two values
        CALL SYNCHR
        DEFB    ','                      ; inline char arg consumed by the preceding CALL
        CALL GETBYT
        ; second value must be 0-191
        CP $C0
        JR NC,GFX_STMT_HGR_1
        ; return the second value in C (the first is already in DE)
        LD C,A
        POP DE
        RET
; ----------------------------------------------------------------------
; GFX_STMT_HPLOT -- HPLOT statement (token $D2): plot a hi-res point and/or draw connected lines via TO.
;   In:        A = current (lookahead) token from the dispatcher; HL = BASIC text pointer. A = TOK_TO distinguishes 'HPLOT TO ...' (continue from the current point) from 'HPLOT x,y ...'.
;   Out:       The point(s) plotted to the hi-res page; the current-point state (GFX_HIRES_BYTE_ADDR, GFX_HIRES_ROW_BASE, GFX_X_FRACTION, GFX_X_COORD/GFX_Y_COORD) left at the final endpoint. HL advanced past the statement.
;   Clobbers:  A, BC, DE, HL and the alternate register set; flags.
;   Algorithm: If the token is TO, skip the initial coordinate and just load the column mask, continuing the line from the existing current point. Otherwise read a coordinate pair, convert to a screen address (GFX_XY_TO_HIRES_ADDR), load the column mask, and plot the single point (GFX_PLOT_BYTE); if no more text (CHRGOT Z), return. Then for each 'TO <n>,<m>': read the endpoint and draw a Bresenham line to it (GFX_DRAW_LINE), looping while another TO follows. At line end, EXX into the alternate working values and reconstruct the canonical current-point state: derive GFX_X_FRACTION from the final screen pointer vs row base, store the final byte address (GFX_HIRES_BYTE_ADDR), and recompute the intra-byte bit (GFX_XY_HELPER) so a later HPLOT TO continues correctly.
; ----------------------------------------------------------------------
GFX_STMT_HPLOT:
        ; 'HPLOT TO ...' continues a line from the current point with no leading coordinate
        CP TOK_TO
        JR NZ,GFX_STMT_HPLOT_1
        CALL GFX_LOAD_COLUMN_MASK
        JR GFX_STMT_HPLOT_2
GFX_STMT_HPLOT_1:
        CALL GFX_READ_COORD_PAIR
        CALL GFX_XY_TO_HIRES_ADDR
        CALL GFX_LOAD_COLUMN_MASK
        ; plot the single starting point
        CALL GFX_PLOT_BYTE
        CALL CHRGOT
        ; no TO clause follows: a lone point was requested, done
        RET Z
GFX_STMT_HPLOT_2:
        CALL CHRGET
        CALL GFX_READ_COORD_PAIR
        PUSH HL
        ; draw a Bresenham line from the current point to this endpoint
        CALL GFX_DRAW_LINE
        POP HL
        LD A,(HL)
        CP TOK_TO
        ; another TO follows: chain the next connected segment
        JR Z,GFX_STMT_HPLOT_2
        EXX
        LD A,(GFX_HIRES_ROW_BASE)
        SUB L
        CPL
        INC A
        ; rebuild the final point's X sub-byte offset from screen pointer minus row base
        LD (GFX_X_FRACTION),A
        LD L,C
        LD H,B
        LD (GFX_HIRES_BYTE_ADDR),HL
        LD HL,(GFX_X_COORD)
        ; recompute the intra-byte bit index so a later HPLOT TO resumes from this point
        CALL GFX_XY_HELPER
        EXX
        RET
    ENDIF
; ----------------------------------------------------------------------
; DISK_RAISE_RESET_ERROR -- raise BASIC error 31 "Reset error" (head of the disk-error raise vector chain).
;   In:        (none)
;   Out:       falls into the shared tail with E = ERR_RESET_ERROR; never returns (jumps to RAISE_ERROR).
;   Clobbers:  E (then DISK_RESELECT_AND_RAISE clobbers A,C,DE and issues a BDOS call).
;   Algorithm: Set E to the disk-reset error code, then fall through the overlap-skip chain (the trailing
;              DEFB $01 = LD BC opcode swallows the next routine's LD E,n) into DISK_RESELECT_AND_RAISE.
;              These vectors are also stored in the cold-start vector table so the disk/RWTS error path can
;              jump to one directly.
; ----------------------------------------------------------------------
DISK_RAISE_RESET_ERROR:
        LD E,ERR_RESET_ERROR             ; raise error 31
        DEFB    $01                      ; LD BC opcode = skip the next LD E
; ----------------------------------------------------------------------
; DISK_RAISE_DISK_I_O_ERROR -- raise BASIC error 57 "Disk I/O error".
;   In:        (none)
;   Out:       falls into the shared tail with E = ERR_DISK_I_O_ERROR; never returns.
;   Clobbers:  E (and the shared tail's clobbers).
;   Algorithm: Set E to the disk-I/O error code; the trailing DEFB $01 swallows the next LD E so control
;              reaches DISK_RESELECT_AND_RAISE, which reselects the default drive and raises the error.
; ----------------------------------------------------------------------
DISK_RAISE_DISK_I_O_ERROR:
        LD E,ERR_DISK_I_O_ERROR          ; raise error 57
        DEFB    $01                      ; LD BC opcode = skip the next LD E
; ----------------------------------------------------------------------
; DISK_RAISE_DISK_READ_ONLY -- raise BASIC error 68 "Disk Read Only".
;   In:        (none)
;   Out:       falls into the shared tail with E = ERR_DISK_READ_ONLY; never returns.
;   Clobbers:  E (and the shared tail's clobbers).
;   Algorithm: Load the read-only-disk error code into E and fall through (DEFB $01 skip-idiom) to
;              DISK_RESELECT_AND_RAISE.
; ----------------------------------------------------------------------
DISK_RAISE_DISK_READ_ONLY:
        LD E,ERR_DISK_READ_ONLY          ; raise error 68
        DEFB    $01                      ; LD BC opcode = skip the next LD E
; ----------------------------------------------------------------------
; DISK_RAISE_DRIVE_SELECT_ERROR -- raise BASIC error 69 "Drive select error".
;   In:        (none)
;   Out:       falls into the shared tail with E = ERR_DRIVE_SELECT_ERROR; never returns.
;   Clobbers:  E (and the shared tail's clobbers).
;   Algorithm: Load the drive-select error code into E and fall through (DEFB $01 skip-idiom) to
;              DISK_RESELECT_AND_RAISE.
; ----------------------------------------------------------------------
DISK_RAISE_DRIVE_SELECT_ERROR:
        LD E,ERR_DRIVE_SELECT_ERROR      ; raise error 69
        DEFB    $01                      ; LD BC opcode = skip the next LD E
; ----------------------------------------------------------------------
; DISK_RAISE_FILE_READ_ONLY -- raise BASIC error 70 "File Read Only" (last vector before the shared tail).
;   In:        (none)
;   Out:       falls straight into the shared tail with E = ERR_FILE_READ_ONLY; never returns.
;   Clobbers:  E (and the shared tail's clobbers).
;   Algorithm: Load the file-read-only error code into E; with no skip idiom it simply falls into
;              DISK_RESELECT_AND_RAISE.
; ----------------------------------------------------------------------
DISK_RAISE_FILE_READ_ONLY:
        LD E,ERR_FILE_READ_ONLY          ; raise error 70
; ----------------------------------------------------------------------
; DISK_RESELECT_AND_RAISE -- shared tail of the disk-error vectors: reselect the recorded default drive, then raise.
;   In:        E = BASIC error code (set by one of the DISK_RAISE_* vectors above).
;   Out:       never returns; jumps to RAISE_ERROR with E = the error code.
;   Clobbers:  A, C, DE around the BDOS call; E is preserved across it (saved/restored via the stack).
;   Algorithm: After a disk fault the BDOS may have left a non-default drive selected; save the error code,
;              issue BDOS Select-Disk (C=DRV_SET) with E = the CP/M current-drive byte at $0004 to re-log
;              the recorded default drive, restore the code, then JP RAISE_ERROR. In the GBASIC build it
;              falls straight to the JP; in MBASIC an IFNDEF island injects the hi-res "Graphics statement
;              not implemented" raise (error 32) sharing this same JP RAISE_ERROR exit.
; ----------------------------------------------------------------------
DISK_RESELECT_AND_RAISE:
        PUSH DE
        ; reselect the recorded default drive (E = CP/M current-drive byte at $0004) to undo any drive the failed BDOS op left logged
        LD C,DRV_SET
        LD A,($0004)
        LD E,A
        CALL BDOS
        POP DE
    IFNDEF GBASIC
        DEFB    $01                      ;        LD BC opcode = skip the LD E on the reselect fall-through
RAISE_GRAPHICS_STATEMENT_NOT_IMPLEMENTED:
        LD E,ERR_GRAPHICS_STATEMENT_NOT_IMPLEMENTED  ; HGR/HPLOT/HCOLOR raise (MBASIC has no hi-res)
    ENDIF
        JP RAISE_ERROR
; ----------------------------------------------------------------------
; GFX_MODE_ACTIVE_FLAG -- one-byte graphics-mode/text-screen state flag (NOT executable code; disassembles incidentally as NOP $00).
;   In:        Written by the GR statement (set to $FF at $4637) and read/cleared in a TEXT/HOME screen-restore path (read at $45D5, cleared to 0 at $45E2). It is a flag, not an HPLOT entry point.
;   Out:       Holds a graphics-active flag that the text/HOME path tests to decide whether to issue the 6502 HOME RPC before returning to text.
;   Clobbers:  (data cell).
;   Algorithm: A 1-byte work cell sitting just past the IFDEF graphics block; the $00 here is its initial value. OBSERVED writers/readers: set $FF at $4637 (GR), read at $45D5, cleared at $45E2. [RE] Its precise role is a graphics-entered flag gating a text-screen HOME; not part of the HPLOT plotter -- its placement here is a layout artifact.
; ----------------------------------------------------------------------
GFX_MODE_ACTIVE_FLAG:
        NOP
; ----------------------------------------------------------------------
; GFX_STMT_HPLOT_9 -- one-byte terminal line-width work cell (NOT executable code; disassembles incidentally as LD D,B $50).
;   In:        Written during cold start (set to $28 = 40 for a 40-column console, else $50 = 80) and read back by the output/LIST width logic.
;   Out:       Holds the current terminal text width used by the console output paths.
;   Clobbers:  (data cell).
;   Algorithm: A 1-byte state variable, not code at this address. OBSERVED: stored at $8289 (cold start, A = $28 or $50), loaded at $66F7 and compared in the output-width logic. Its placement just past the conditional graphics region is a layout artifact, not an HPLOT flow target.
; ----------------------------------------------------------------------
GFX_STMT_HPLOT_9:
        LD D,B
; ----------------------------------------------------------------------
; FADD_LOAD_CONST -- FADD the fixed in-image constant 0.5 to the FAC.
;   In:        FAC ($0CB1 mantissa-low / $0CB3 FACHI sign+high / $0CB4 exponent) holds the running value.
;   Out:       FAC = FAC + 0.5 (single precision), normalized and rounded.
;   Clobbers:  A,B,C,D,E,H,L, FAC cells, $0CB5 (working sign byte used by the add path).
;   Algorithm: Point HL at the 4-byte MBF constant FP_CONST_HALF_SNG (bytes 00 00 00 80 = +0.5),
;              then fall into FADD_FROM_MEM so the generic memory-operand add does the work. Used to add
;              the 0.5 round-to-nearest bias before truncation in the single-precision FOUT/FIX paths.
; ----------------------------------------------------------------------
FADD_LOAD_CONST:
        LD HL,FP_CONST_HALF_SNG
; ----------------------------------------------------------------------
; FADD_FROM_MEM -- FADD the single-precision MBF number at (HL) to the FAC.
;   In:        HL -> 4-byte MBF operand [LSB, mid, MSB|sign, exponent]; FAC holds the accumulator.
;   Out:       FAC = FAC + (HL). (Addition is commutative, so operand order does not matter here.)
;   Clobbers:  A,B,C,D,E,H,L, FAC cells, $0CB5.
;   Algorithm: Load the operand from memory into the argument registers via FP_LOAD_MEM (E=LSB, D=mid,
;              C=MSB|sign, B=exponent), then JR to FADD_ALIGN to align exponents and add. Standard
;              'add value at (HL)' entry.
; ----------------------------------------------------------------------
FADD_FROM_MEM:
        ; load the 4-byte MBF addend at (HL) into E,D,C,B (E=LSB ... B=exponent)
        CALL FP_LOAD_MEM
        JR FADD_ALIGN
; ----------------------------------------------------------------------
; FADD_FROM_MEM_1 -- subtract the FAC FROM the single-precision MBF number at (HL): FAC = (HL) - FAC.
;   In:        HL -> 4-byte MBF operand (the MINUEND); FAC holds the value to subtract (the subtrahend).
;   Out:       FAC = (HL) - FAC.   [RE/OBSERVED] direction confirmed by the FN_ATN caller, which pushes
;              FADD_FROM_MEM_1 with HL -> PI/2 to compute PI/2 - ATN(1/x).
;   Clobbers:  A,B,C,D,E,H,L, FAC cells, $0CB3 (FP_NEG), $0CB5.
;   Algorithm: Load the operand at (HL) into the argument registers (FP_LOAD_MEM) so it becomes ARG, then
;              fall into FSUB, which negates the FAC and adds: ARG + (-FAC) = (HL) - FAC. The memory-operand
;              twin of FADD_FROM_MEM.
; ----------------------------------------------------------------------
FADD_FROM_MEM_1:
        ; load the 4-byte MBF minuend at (HL) into E,D,C,B; FSUB then computes (HL) - FAC
        CALL FP_LOAD_MEM
; ----------------------------------------------------------------------
; FSUB -- single-precision subtract: FAC = ARG - FAC (the register operand minus the FAC).
;   In:        ARG in registers (B=exponent, C=MSB|sign, D=mid, E=LSB); FAC holds the value subtracted.
;   Out:       FAC = ARG - FAC, normalized and rounded.
;              [OBSERVED] In the single-precision operator band (FRMEVL_OPC_DISPATCH_SNG) the LEFT operand
;              is loaded into the registers (BC/DE) and the RIGHT into the FAC, so for the '-' operator this
;              slot yields LEFT - RIGHT = ARG - FAC, the correct result.
;   Clobbers:  A,B,C,D,E,H,L, FAC cells, $0CB3 (FP_NEG flips the FACHI sign bit), $0CB5.
;   Algorithm: FP_NEG flips bit7 of the FAC sign byte FACHI ($0CB3), then control falls into FADD_ALIGN to
;              add ARG to the now-negated FAC: ARG + (-FAC) = ARG - FAC.
; ----------------------------------------------------------------------
FSUB:
        ; negate the FAC (flip FACHI bit7) so the following add yields ARG - FAC
        CALL FP_NEG
; ----------------------------------------------------------------------
; FADD_ALIGN -- exponent alignment front-end of single-precision add (the FADDT core).
;   In:        ARG in B(exp),C(MSB|sign),D(mid),E(LSB); FAC at $0CB1/$0CB3, exponent at $0CB4.
;   Out:       Either an early store/return (one operand zero), or both mantissas aligned and the path
;              continued into the add (MANT_ADD) or subtract-borrow (FADD_SUB_BORROW -> FADD_COMBINE/FADD).
;   Clobbers:  A,B,C,D,E,H,L, FAC cells, $0CB5, the alignment stack frame.
;   Algorithm: 1) If ARG exponent (B)=0, ARG is zero -> return (FAC unchanged). 2) If FAC exponent
;              ($0CB4)=0, FAC is zero -> store ARG into FAC and return. 3) Compute exp diff (FACexp-ARGexp);
;              if FAC has the SMALLER exponent, swap so the larger-exponent operand sits in FAC (FAC_PUSH /
;              FP_STORE_FAC of ARG, take |diff|). 4) If |diff| >= $19 (25) the smaller operand is negligible
;              -> return the larger unchanged. 5) FP_UNPACK_MSB restores the FAC hidden MSB and returns the
;              SIGN-AGREEMENT bit (bit7 set when signs match); right-shift the smaller mantissa by the diff
;              (MANT_SHIFT_BYTES) to align, then ADD (same sign) or SUBTRACT-BORROW (different sign).
; ----------------------------------------------------------------------
FADD_ALIGN:
        LD A,B
        OR A
        ; ARG exponent 0 means ARG is zero: FAC is already the sum, return
        RET Z
        LD A,(FAC_EXP)
        OR A
        ; FAC exponent 0 means FAC is zero: result is just ARG, store ARG into FAC and return
        JP Z,FP_STORE_FAC
        ; exponent difference = FAC_exp - ARG_exp (no borrow => FAC is the larger operand)
        SUB B
        ; FAC has the larger (or equal) exponent: keep it as the accumulator and align ARG down to it
        JR NC,FADD_ALIGN_GO
        ; FAC was the smaller operand: form |diff| and swap ARG<->FAC so the larger sits in FAC
        CPL
        INC A
        EX DE,HL
        CALL FAC_PUSH
        EX DE,HL
        CALL FP_STORE_FAC
        POP BC
        POP DE
FADD_ALIGN_GO:
        ; if the smaller operand is >=25 bits down it cannot affect the result: return the larger unchanged
        CP $19
        RET NC
        PUSH AF
        ; restore the FAC's hidden mantissa MSB and return the sign-agreement bit (bit7 set = signs match)
        CALL FP_UNPACK_MSB
        LD H,A
        POP AF
        ; right-shift the smaller mantissa by the exponent difference to align the binary points
        CALL MANT_SHIFT_BYTES
        LD A,H
        OR A
        LD HL,FAC
        ; returned byte positive (bit7 clear) => operands have OPPOSITE signs: take the subtract/borrow path
        JP P,FADD_SUB_BORROW
        ; signs agree: add the two aligned 3-byte mantissas
        CALL MANT_ADD
        JP NC,FP_PACK_ROUND
        INC HL
        ; mantissa add carried out: bump the exponent ($0CB4) and shift the mantissa right one bit to renormalize
        INC (HL)
        ; exponent wrapped to 0 => magnitude overflow: jump to the shared FP error-finalize path
        JP Z,OVERR_SIGN_FROM_FPFLAG_CPL
        LD L,$01
        CALL MANT_SHIFT_BITS
        JR FP_PACK_ROUND
FADD_SUB_BORROW:
        XOR A
        SUB B
        LD B,A
        LD A,(HL)
        SBC A,E
        LD E,A
        INC HL
        LD A,(HL)
        SBC A,D
        LD D,A
        INC HL
        LD A,(HL)
        SBC A,C
        LD C,A
; ----------------------------------------------------------------------
; FADD_COMBINE -- opposite-sign mantissa combine entry: conditionally two's-complement, then normalize.
;   In:        Working mantissa difference in C(high),D,E,B from FADD_SUB_BORROW's SBC chain, with CARRY set
;              when the subtraction underflowed (result magnitude is negative); FAC exponent $0CB4, sign $0CB5.
;   Out:       Falls into FADD to byte-left-justify, then FP_SET_ZERO to bit-normalize, adjust the exponent,
;              round, and store the result.
;   Clobbers:  A,B,C,D,E,H,L, FAC cells, $0CB5.
;   Algorithm: If the subtract produced a negative magnitude (CARRY set), FCOMPL two's-complements the
;              working mantissa and flips the sign byte $0CB5; otherwise the magnitude is already positive.
;              Then drop into FADD to renormalize. Also entered directly by FLOAT_A to normalize a freshly
;              built integer-as-float.
; ----------------------------------------------------------------------
FADD_COMBINE:
        ; subtract underflowed (negative magnitude): two's-complement the mantissa and flip the sign byte $0CB5
        CALL C,FCOMPL
; ----------------------------------------------------------------------
; FADD -- post-add byte-granular left-justify of the summed/subtracted mantissa before bit normalization.
;   In:        Working mantissa spread across C(high),D,E,B after the combine; entered with A=0 (shift count).
;   Out:       Mantissa shifted left by whole bytes until the high byte is non-zero, with the running
;              (negative) shift count in A in multiples of 8; falls into FP_SET_ZERO for bit-normalize/round/
;              store. On full cancellation it falls through to FP_SET_ZERO's exact-zero store.
;   Clobbers:  A,B,C,D,E,H,L.
;   Algorithm: Each iteration: if the high byte (C) is non-zero, stop (JR NZ,FP_NORM_TEST_MSB). Otherwise slide
;              the mantissa one whole byte toward the high end (C<-D<-H<-L, new low=0), subtract 8 from the
;              shift count, and repeat until a non-zero high byte appears or the count reaches $E0 (-32, all
;              four bytes cancelled, value exactly 0).
; ----------------------------------------------------------------------
FADD:
        LD L,B
        LD H,E
        XOR A
FADD_LJUST_BYTE:
        LD B,A
        LD A,C
        OR A
        ; high mantissa byte non-zero: stop byte-shifting and go to bit-granular normalization
        JR NZ,FP_NORM_TEST_MSB
        LD C,D
        LD D,H
        LD H,L
        LD L,A
        LD A,B
        ; shifted one whole byte left: subtract 8 from the running normalize shift count
        SUB $08
        CP $E0
        ; keep sliding bytes left until a non-zero high byte or full ($E0 = all 4 bytes) cancellation
        JR NZ,FADD_LJUST_BYTE
; ----------------------------------------------------------------------
; FP_SET_ZERO -- two roles: (a) the exact-zero store (FP_SET_ZERO/_1) and (b) the MBF bit-normalize / exponent-fixup / round / pack tail (entered at FP_NORM_BITLOOP/_5/_7).
;   In:        (a) entered to write a zero result. (b) entered with the byte-justified mantissa in H,L,D,C and
;              B = running bit-shift count from FADD; FAC exponent $0CB4; sign in $0CB5.
;   Out:       (a) FP_SET_ZERO writes exponent 0 and returns (result 0.0). (b) the normalized result is rounded,
;              the sign folded in, and stored via FP_STORE_FAC; underflow/zero also exits through the exponent
;              clear. Returns through FP_STORE_FAC.
;   Clobbers:  A,B,C,D,E,H,L, FAC cells.
;   Algorithm: FP_SET_ZERO/_1 just store A (=0) into the exponent $0CB4 and RET (the exact-zero path). The
;              normalize tail bit-shifts the mantissa left until its top bit is set (FP_NORM_BITLOOP/_4 loop, with
;              the _3 fast path when only the low byte holds bits), then adds the accumulated shift count to the
;              exponent at $0CB4 (a no-carry or zero result = underflow -> store 0). Finally it rounds on the
;              round bit (CALL M,FADD_ROUND_CARRY), folds the sign held in $0CB5 into the mantissa MSB (C), and
;              JP FP_STORE_FAC.
; ----------------------------------------------------------------------
FP_SET_ZERO:
        XOR A
FP_SET_ZERO_EXP:
        ; write the exponent byte (A=0 here stores an exact zero result)
        LD (FAC_EXP),A
        RET
FP_NORM_BITLOOP:
        LD A,H
        OR L
        OR D
        ; upper mantissa bytes still hold bits: take the full multi-byte left-shift path
        JR NZ,FP_NORM_SHIFT_LEFT
        LD A,C
FP_NORM_LOWBYTE:
        DEC B
        RLA
        ; keep rotating the low byte left until its top bit is set (counting the shift in B)
        JR NC,FP_NORM_LOWBYTE
        INC B
        RRA
        LD C,A
        JR FP_NORM_ADJ_EXP
FP_NORM_SHIFT_LEFT:
        DEC B
        ADD HL,HL
        LD A,D
        RLA
        LD D,A
        LD A,C
        ADC A,A
        LD C,A
FP_NORM_TEST_MSB:
        ; top mantissa bit still clear: shift left another bit to normalize
        JP P,FP_NORM_BITLOOP
FP_NORM_ADJ_EXP:
        LD A,B
        LD E,H
        LD B,L
        OR A
        ; no exponent change needed: go straight to round-and-pack
        JR Z,FP_PACK_ROUND
        LD HL,FAC_EXP
        ; adjust the exponent by the accumulated normalize shift count
        ADD A,(HL)
        LD (HL),A
        ; exponent underflowed below the minimum: result rounds to 0
        JR NC,FP_SET_ZERO
        ; exponent reached 0: result is 0.0
        JP Z,FP_SET_ZERO
FP_PACK_ROUND:
        LD A,B
FP_PACK_STORE:
        LD HL,FAC_EXP
        OR A
        ; round bit set: propagate the round-up carry through the mantissa and exponent
        CALL M,FADD_ROUND_CARRY
        LD B,(HL)
        INC HL
        LD A,(HL)
        ; extract bit7 of the working sign byte $0CB5 (the result's sign) ...
        AND $80
        ; ... and fold it into the packed mantissa high byte (C) before storing
        XOR C
        LD C,A
        JP FP_STORE_FAC
; ----------------------------------------------------------------------
; FADD_ROUND_CARRY -- propagate a round-up (+1 ULP) carry through the mantissa and exponent.
;   In:        Mantissa bytes in E(low),D(mid),C(high); HL -> exponent cell $0CB4.
;   Out:       Mantissa incremented by one ULP with the carry rippled; on a full mantissa carry the exponent
;              is bumped and the mantissa MSB reseeded to $80. Exponent overflow exits via OVERR_POP1.
;   Clobbers:  E,D,C and (HL); flags. (A is NOT touched.)
;   Algorithm: INC E; if it wrapped, INC D; if that wrapped, INC C; if that wrapped too the whole mantissa
;              rolled over, so set C=$80 (the new normalized MSB) and INC the exponent (HL). If the exponent
;              then wraps to 0 the magnitude overflowed -> JP OVERR_POP1 (the shared FP error-finalize path,
;              which reports Overflow here).
; ----------------------------------------------------------------------
FADD_ROUND_CARRY:
        ; add one ULP to the low mantissa byte; ripple the carry upward only as needed
        INC E
        RET NZ
        INC D
        RET NZ
        INC C
        RET NZ
        ; mantissa fully carried out: reseed the MSB to $80 and bump the exponent
        LD C,$80
        INC (HL)
        RET NZ
        ; exponent wrapped past max: overflow -> shared FP error-finalize (reports Overflow)
        JP OVERR_POP1
; ----------------------------------------------------------------------
; MANT_ADD -- add an aligned 3-byte mantissa from (HL) into the working mantissa registers.
;   In:        HL -> 3 consecutive mantissa bytes (low..high); working mantissa in E(low),D(mid),C(high).
;   Out:       E,D,C = (HL bytes) + E,D,C with carry out in CY; HL ends pointing at the high (third) byte.
;   Clobbers:  A,E,D,C,H,L, flags.
;   Algorithm: Byte-serial add with carry: E += (HL); D += (HL+1) + CY; C += (HL+2) + CY. The final carry
;              signals a mantissa overflow (the caller renormalizes by shifting right and bumping the exponent).
; ----------------------------------------------------------------------
MANT_ADD:
        LD A,(HL)
        ADD A,E
        LD E,A
        INC HL
        LD A,(HL)
        ADC A,D
        LD D,A
        INC HL
        LD A,(HL)
        ADC A,C
        LD C,A
        RET
; ----------------------------------------------------------------------
; FCOMPL -- two's-complement negate the working mantissa and flip the result sign byte.
;   In:        Working mantissa in B(low/guard),E,D,C(high); sign byte at $0CB5.
;   Out:       B,E,D,C = -(B,E,D,C) (32-bit two's complement); $0CB5 = ~$0CB5 (sign flipped).
;   Clobbers:  A,B,C,D,E,H,L, $0CB5, flags.
;   Algorithm: CPL the sign byte at $0CB5, then negate the 4 mantissa bytes as 0 - mantissa via a borrow
;              chain (A=0, L=0 carrier): B=0-B; E=0-E-borrow; D=0-D-borrow; C=0-C-borrow. Used by the
;              opposite-sign add path (FADD_COMBINE) when the subtraction produced a negative magnitude.
; ----------------------------------------------------------------------
FCOMPL:
        LD HL,FP_SIGN_FLAG
        LD A,(HL)
        ; flip the working sign byte ($0CB5) to match the negated magnitude
        CPL
        LD (HL),A
        XOR A
        LD L,A
        ; negate the 4-byte mantissa as 0 - mantissa, rippling the borrow through B,E,D,C
        SUB B
        LD B,A
        LD A,L
        SBC A,E
        LD E,A
        LD A,L
        SBC A,D
        LD D,A
        LD A,L
        SBC A,C
        LD C,A
        RET
; ----------------------------------------------------------------------
; MANT_SHIFT_BYTES -- right-shift the 4-byte working mantissa by a bit count, whole bytes first.
;   In:        A = right-shift amount in bits (the aligned exponent difference); mantissa in C(high),D,E with
;              B used as the shifted-out guard byte (initialized to 0). H is preserved across this call (it
;              carries the caller's sign-agreement bit).
;   Out:       Mantissa shifted right by A bits; the residual (sub-8) bit shift is finished by the inline
;              MANT_SHIFT_BITS / MANT_SHIFT_BIT_STEP loop.
;   Clobbers:  A,B,C,D,E,L, flags. (H preserved.)
;   Algorithm: While >= 8 bits remain, slide each mantissa byte down one position (C->D->E->B, new C=0),
;              subtracting 8 per whole byte. The leftover bit count (carried negative) is biased by +$09 to
;              form L = a 1-based bit-loop counter, then the residual 0..7-bit shift is finished by the bit
;              loop below. [RE] A fast path handles the case where the upper bytes are already zero, shifting
;              only C (see MANT_SHIFT_C_ONLY); the precise low/high role of C in that branch is inferred from
;              the opcode sequence.
; ----------------------------------------------------------------------
MANT_SHIFT_BYTES:
        LD B,$00
MANT_SHIFT_BYTE_LOOP:
        SUB $08
        ; fewer than 8 bits left: stop the whole-byte cascade and handle the residual bits
        JR C,MANT_SHIFT_RESIDUAL
        LD B,E
        LD E,D
        LD D,C
        ; slide the mantissa down one whole byte (B<-E<-D<-C, new high byte = 0)
        LD C,$00
        JR MANT_SHIFT_BYTE_LOOP
MANT_SHIFT_RESIDUAL:
        ; bias the leftover (negative) bit count by +9 to form a 1-based loop counter in L
        ADD A,$09
        LD L,A
        LD A,D
        OR E
        OR B
        ; other mantissa bytes still hold bits: take the full per-bit shift; else use the C-only fast path
        JR NZ,MANT_SHIFT_BIT_STEP
        LD A,C
MANT_SHIFT_C_ONLY:
        DEC L
        ; residual bit counter exhausted: alignment shift complete
        RET Z
        RRA
        LD C,A
        JR NC,MANT_SHIFT_C_ONLY
        JR MANT_SHIFT_BITS_LOW3
MANT_SHIFT_BIT_STEP:
        XOR A
        DEC L
        RET Z
        LD A,C
; ----------------------------------------------------------------------
; MANT_SHIFT_BITS -- right-shift the 4-byte mantissa by one bit (the residual bit-shift step).
;   In:        Mantissa in C(high),D,E,B(low/guard); A holds C with the carry = the bit shifted in at the top.
;   Out:       Mantissa rotated right one bit (C->D->E->B), then re-enters MANT_SHIFT_BIT_STEP to repeat.
;   Clobbers:  A,B,C,D,E, flags.
;   Algorithm: RRA the high byte C (already in A), store it, then propagate the shifted-out bit down through
;              D, E, and the guard byte B via RRA on each (the carry chains the boundary bit). Loops back to
;              MANT_SHIFT_BIT_STEP to decrement the bit counter L until the requested residual shift is done.
; ----------------------------------------------------------------------
MANT_SHIFT_BITS:
        ; rotate the mantissa right one bit, chaining the boundary bit from C down through D,E,B
        RRA
        LD C,A
MANT_SHIFT_BITS_LOW3:
        LD A,D
        RRA
        LD D,A
        LD A,E
        RRA
        LD E,A
        LD A,B
        RRA
        LD B,A
        JR MANT_SHIFT_BIT_STEP
L_4CA6:
        DEFB    $00,$00,$00,$81
; [RE] LOG() numerator coefficient pool: MBF (4-byte single) polynomial, layout { count byte; N x 4-byte MBF coefficient } with count=$04 -> 4 coefficients ($4CAB-$4CBA). Evaluated by POLY_EVAL (Horner) from the LOG mantissa-reduction routine at $4CDF ($4CEC/$4CEF). Paired with FP_POLY_LOG_DEN; the two are FDIV'd ($4D03) to form the rational approximation of ln over the reduced interval.
FP_POLY_LOG_NUM:
        DEFB    $04,$9A,$F7,$19,$83,$24,$63,$43,$83,$75,$CD,$8D,$84,$A9,$7F,$83
        DEFB    $82
; [RE] LOG() denominator coefficient pool: MBF polynomial { count byte; N x 4-byte MBF } with count=$04 -> 4 coefficients ($4CBC-$4CCB). Evaluated by POLY_EVAL from $4CFB/$4CFE; the result divides the FP_POLY_LOG_NUM result (FDIV at $4D03) to yield ln of the range-reduced mantissa.
FP_POLY_LOG_DEN:
        DEFB    $04,$00,$00,$00,$81,$E2,$B0,$4D,$83,$0A,$72,$11,$83,$F4,$04,$35
        DEFB    $7F
; ----------------------------------------------------------------------
; FN_LOG -- LOG(x) natural-logarithm function handler (BASIC token $0A)
;   In:        FAC holds x (MBF single); FAC_EXP = FAC exponent, FACHI = high mantissa byte + sign
;   Out:       FAC = ln(x); returns through FMUL
;   Clobbers:  FAC, all FP scratch, A/BC/DE/HL
;   Algorithm: Reject x<=0: FP_SIGN returns $FF/$00/$01, then OR A + JP PE,ERROR_FC traps the
;              even-parity values $FF (negative) and $00 (zero) -> Illegal function call. Call
;              LOG_MANTISSA_POLY (formerly LOG_MANTISSA_POLY) to split x = m*2^e and return a rational
;              approximation r = ln(reduced mantissa) + e in the FAC. Finally multiply by the
;              constant ln(2) (operand B=$80 exp, C/D/E = $31,$72,$18 = MBF 0.6931472) so the
;              e-in-units-of-2 result becomes a true natural log: ln(x) = r * ln(2).
; ----------------------------------------------------------------------
FN_LOG:
        CALL FP_SIGN
        OR A
        ; reject x <= 0: FP_SIGN returns $FF for negative / $00 for zero, both even-parity (PE) -> Illegal function call
        JP PE,ERROR_FC
        ; split x = m*2^e and form ln(m)+e via the LOG rational polynomial (NUM/DEN), result in the FAC
        CALL LOG_MANTISSA_POLY
        ; scale by ln(2) = 0.6931472 (MBF exp=$80, mantissa $31,$72,$18): converts the base-2 reduction result into a natural log
        LD BC,$8031
        LD DE,$7218
        JP FMUL
; ----------------------------------------------------------------------
; LOG_MANTISSA_POLY -- LOG range reduction + rational approximation of ln (LOG helper, was LOG_MANTISSA_POLY)
;   In:        FAC holds x>0 (already sign-checked by FN_LOG)
;   Out:       FAC = ln(reduced mantissa) + e, where e is the binary exponent (caller FN_LOG scales by ln 2)
;   Clobbers:  FAC, FP work stack, A/BC/DE/HL, FAC_EXP
;   Algorithm: Read the FAC mantissa (FP_LOAD_FAC), force the exponent cell FAC_EXP to $80 so the
;              value is reduced to a pure mantissa m in [0.5,1), and stash the original exponent
;              relationship in A via XOR B (saved on the stack). Evaluate two polynomials in m:
;              FP_POLY_LOG_NUM and FP_POLY_LOG_DEN (each Horner via POLY_EVAL), then FDIV them to
;              get the rational approximation NUM(m)/DEN(m) ~= ln(m). Float the saved binary
;              exponent e (FLOAT_A) and FADD it so FAC = ln(m) + e (e in units of powers of two).
; ----------------------------------------------------------------------
LOG_MANTISSA_POLY:
        CALL FP_LOAD_FAC
        ; force exponent = $80: reduce x to its pure mantissa m in [0.5,1) so the polynomial sees a small in-range argument
        LD A,$80
        LD (FAC_EXP),A
        ; stash the original binary exponent (relative to the forced $80) so it can be added back after taking ln of the mantissa
        XOR B
        PUSH AF
        CALL FAC_PUSH
        ; evaluate numerator polynomial NUM(m) of the rational approximation of ln(m)
        LD HL,FP_POLY_LOG_NUM
        CALL POLY_EVAL
        POP BC
        POP HL
        CALL FAC_PUSH
        EX DE,HL
        CALL FP_STORE_FAC
        ; evaluate denominator polynomial DEN(m); NUM/DEN ~= ln(m)
        LD HL,FP_POLY_LOG_DEN
        CALL POLY_EVAL
        POP BC
        POP DE
        ; rational approximation: ln(reduced mantissa) = NUM(m) / DEN(m)
        CALL FDIV
        POP AF
        CALL FAC_PUSH
        ; float the saved binary exponent e
        CALL FLOAT_A
        POP BC
        POP DE
        ; FAC = ln(m) + e (e in powers of two); FN_LOG then scales the whole thing by ln 2
        JP FADD_ALIGN

; ======================================================================
; FLOATING-POINT MATH PACKAGE (MBF) -- FAC at $0CB1/$0CB4
; ======================================================================
; ----------------------------------------------------------------------
; FMUL -- single-precision MBF multiply: FAC = operand * FAC (the '*' single-precision operator handler).
;   In:        Operand factor in registers B=biased exponent, C=mantissa high (bit7=sign), D=mantissa mid,
;              E=mantissa low.  FAC ($0CB1/$0CB2 mantissa, $0CB3 sign+high, $0CB4 exponent) holds the other
;              factor.  Reached from the single-precision operator band (DEFW FMUL, line 432).
;   Out:       FAC = operand * FAC, normalized and rounded by the FADD continuation.  Returns early with the
;              FAC unchanged (still zero) when the FAC factor is zero (RET Z after FP_SIGN).  [RE] when the
;              OPERAND factor is zero EXP_ADD's B=0 test takes the zero/clear path instead.
;   Clobbers:  A,B,C,D,E,H,L,F, the FAC, and the self-modified cells FMUL_3+1 / FMUL_4+1.
;   Algorithm: If the FAC factor is zero the product is zero -> return.  EXP_ADD (L=$00) adds the two biased
;              exponents (with over/underflow routing) and combines the signs.  The operand mantissa high byte
;              (C) is patched into the inner ADC operand and its low word (DE) into the inner ADD operand, then
;              the FAC mantissa is scanned low-to-high (FMUL_1): for each set bit the operand is shift-and-added
;              into the running product (BC:HL), shifting right one place per step.  FADD (pushed as the
;              continuation) normalizes and rounds the accumulated product back into the FAC.  Multiply is
;              commutative, so which factor is 'scanned' vs 'added' is an implementation choice, not semantics.
; ----------------------------------------------------------------------
FMUL:
        ; If the FAC factor is zero the product is zero -- return immediately (FP_SIGN sets Z when the FAC exponent is 0).
        CALL FP_SIGN
        RET Z
        ; L=$00 tells EXP_ADD to ADD the FAC exponent (multiply); EXP_ADD also combines the result sign and routes over/underflow.
        LD L,$00
        CALL EXP_ADD
        LD A,C
        ; Self-modify the inner loop: patch the operand mantissa high byte (C) into the ADC operand cell and (next two instrs) its low word (DE) into the ADD operand cell.
        LD (FMUL_4+1),A
        EX DE,HL
        LD (FMUL_3+1),HL
        LD BC,$0000
        LD D,B
        LD E,B
        ; Push FADD as the return continuation so the shift-and-add loop falls into normalize/round when it finishes.
        LD HL,FADD
        PUSH HL
        LD HL,FMUL_1
        PUSH HL
        PUSH HL
        ; Scan the FAC mantissa bytes low-to-high; each set bit drives one shift-and-add of the patched operand into the partial product.
        LD HL,FAC
FMUL_1:
        LD A,(HL)
        INC HL
        OR A
        ; [RE] A zero FAC mantissa byte contributes nothing -- skip its 8-bit inner loop (FMUL_8 shifts the partial product down one byte and returns).
        JR Z,FMUL_8
        PUSH HL
        EX DE,HL
        LD E,$08
FMUL_2:
        RRA
        LD D,A
        LD A,C
        ; Add the operand into the running product only when this mantissa bit is set; otherwise just shift.
        JR NC,FMUL_5
        PUSH DE
; [RE] SMC operand cell: LD DE,nnnn at $4D43 is patched by FMUL setup ($4D20 LD (FMUL_3+1),HL) to the multiplicand mantissa low word; the shift-and-add loop then accumulates it via ADD HL,DE ($4D46). FMUL_3+1 is the immediate field, not a code entry.
FMUL_3:
        LD DE,$0000
        ; Accumulate the patched operand low word into the product low half (the high byte is folded in by the following ADC).
        ADD HL,DE
        POP DE
; [RE] SMC operand cell: the immediate of ADC A,nn at $4D48 is patched by FMUL prologue ($4D1C LD (FMUL_4+1),A) to the multiplicand high byte; folded into the running product high byte each loop pass. FMUL_4+1 is the immediate, not a code entry.
FMUL_4:
        ADC A,$00
FMUL_5:
        RRA
        LD C,A
        LD A,H
        RRA
        LD H,A
        LD A,L
        RRA
        LD L,A
        LD A,B
        RRA
        LD B,A
        AND $10
        JP Z,FMUL_6
        LD A,B
        OR $20
        LD B,A
FMUL_6:
        DEC E
        LD A,D
        JR NZ,FMUL_2
        EX DE,HL
FMUL_7:
        POP HL
        RET
FMUL_8:
        LD B,E
        LD E,D
        LD D,C
        LD C,A
        RET
; ----------------------------------------------------------------------
; FDIV_BY_TEN -- divide the FAC by ten (single precision): FAC = FAC / 10.0.
;   In:        FAC holds the dividend (mantissa $0CB1/$0CB2, sign+high $0CB3, exponent $0CB4).
;   Out:       FAC = FAC / 10, normalized.
;   Clobbers:  A,B,C,D,E,H,L,F, the FAC, FDIV's self-modified cells, and the stack (one FP value pushed/popped).
;   Algorithm: Push the dividend (FAC_PUSH), point HL at the constant +10.0 (DP_CONST_2) and load it into the
;              FAC as the divisor (FP_STORE_REGS_LD), then enter FDIV at FDIV_POP_ARGS, which pops the saved
;              dividend into B/C/D/E and computes dividend/divisor = old_FAC/10.  FDIV_POP_ARGS is the generic
;              'pop the stacked dividend and divide by the current FAC' entry, also reused by IDIV (line 4631).
; ----------------------------------------------------------------------
FDIV_BY_TEN:
        ; Stack the dividend (current FAC); the FAC is about to be overwritten with the divisor.
        CALL FAC_PUSH
        ; Point at the divisor constant +10.0 (MBF $00 $00 $20 $84); the following FP_STORE_REGS_LD loads it into the FAC.
        LD HL,DP_CONST_2
        CALL FP_STORE_REGS_LD
FDIV_POP_ARGS:
        ; FDIV_POP_ARGS: recover the stacked dividend into B(exp)/C(high)/D(mid)/E(low), then fall into FDIV to compute dividend/FAC.
        POP BC
        POP DE
; ----------------------------------------------------------------------
; FDIV -- single-precision MBF divide: FAC = operand / FAC (the '/' single-precision operator handler).
;   In:        Dividend in B=biased exponent, C=mantissa high (bit7=sign), D=mantissa mid, E=mantissa low.
;              FAC holds the divisor.  Reached from the operator band (DEFW FDIV, line 433) and from
;              FDIV_POP_ARGS / IDIV.
;   Out:       FAC = dividend / divisor, normalized.  On a zero DIVISOR (FAC=0) jumps to DIV0_SIGN_FROM_C, which
;              reaches DIV0_SET_MSG -> the Division-by-zero error (confirmed: DIV0_SET_MSG loads
;              ERRMSG_DIVISION_BY_ZERO).  A zero dividend underflows to a zero result via FP_SET_ZERO.
;   Clobbers:  A,B,C,D,E,H,L,F, the FAC, the FDIV subtract trio (FDIV_2/3/4 +1) and the quotient scratch
;              FDIV_5+1.
;   Algorithm: FP_SIGN(FAC) detects a zero divisor (-> error).  EXP_ADD with L=$FF forms the quotient exponent
;              by SUBTRACTING the divisor exponent (one's-complement add); the two INC (HL) afterward correct
;              the divide bias, and EXP_ADD combines the sign.  The divisor mantissa bytes are patched into the
;              SUB/SBC trio, then a restoring long division shifts the remainder left and conditionally
;              subtracts the divisor each iteration (FDIV_1 loop), assembling the quotient in the FDIV_5 scratch
;              byte and B:HL; the result is normalized, falling to FP_SET_ZERO* / FP_SET_ZERO on exponent
;              underflow.
; ----------------------------------------------------------------------
FDIV:
        CALL FP_SIGN
        ; A zero divisor (FAC=0, FP_SIGN returns Z) raises Division by zero (DIV0_SIGN_FROM_C -> DIV0_SET_MSG loads ERRMSG_DIVISION_BY_ZERO).
        JP Z,DIV0_SIGN_FROM_C
        ; L=$FF makes EXP_ADD SUBTRACT the divisor exponent (it one's-complements it before adding); the next two INC (HL) restore the divide bias.
        LD L,$FF
        CALL EXP_ADD
        INC (HL)
        INC (HL)
        DEC HL
        LD A,(HL)
        ; Self-modify the restoring-divide inner loop: patch the divisor's three mantissa bytes into the SUB/SBC operand cells.
        LD (FDIV_4+1),A
        DEC HL
        LD A,(HL)
        LD (FDIV_3+1),A
        DEC HL
        LD A,(HL)
        LD (FDIV_2+1),A
        LD B,C
        EX DE,HL
        XOR A
        LD C,A
        LD D,A
        LD E,A
        LD (FDIV_5+1),A
FDIV_1:
        ; FDIV_1: each iteration trial-subtracts the divisor from the remainder; PUSH preserves the remainder so a failed (non-fitting) subtract can be undone.
        PUSH HL
        PUSH BC
        LD A,L
; [RE] SMC operand cell: the SUB nn immediate at $4D9D is patched by FDIV setup ($4D8E LD (FDIV_2+1),A) to divisor mantissa byte 0; the restoring-division loop subtracts it from the remainder low byte. FDIV_2+1 is the immediate, not a code entry.
FDIV_2:
        SUB $00
        LD L,A
        LD A,H
; [RE] SMC operand cell: the SBC A,nn immediate at $4DA1 is patched by FDIV setup ($4D89 LD (FDIV_3+1),A) to divisor mantissa byte 1; subtracted-with-borrow from the remainder middle byte. FDIV_3+1 is the immediate, not a code entry.
FDIV_3:
        SBC A,$00
        LD H,A
        LD A,B
; [RE] SMC operand cell: the SBC A,nn immediate at $4DA5 is patched by FDIV setup ($4D84 LD (FDIV_4+1),A) to divisor mantissa byte 2; subtracted-with-borrow from the remainder high byte. FDIV_4+1 is the immediate, not a code entry.
FDIV_4:
        SBC A,$00
        LD B,A
; [RE] SMC scratch cell: the LD A,nn immediate at $4DA8 is the running quotient/borrow byte. Init 0 at $4D97; rewritten $4DAF/$4DE6; read back LD A,(FDIV_5+1) at $4DC0/$4DE2 to assemble the result. The byte is both the executed immediate and a self-modified scratch; FDIV_5+1 is not a code entry.
FDIV_5:
        LD A,$00
        SBC A,$00
        CCF
        ; [RE] Quotient-bit decision: if the divisor did not fit, restore the saved remainder; else commit the subtraction and record the quotient bit (FDIV_6+1 is the flag-skip POP-pair tail).
        JR NC,FDIV_6+1
        LD (FDIV_5+1),A
        POP AF
        POP AF
        SCF
; [RE] Flag-skip dual tail: $4DB5 JP NC,$E1C1 -- on the success branch JR NC,FDIV_7+1 ($4DAD) lands at $4DB6 and runs the operand bytes C1 E1 as POP BC; POP HL to discard the FDIV_1 loop saves. On fall-through SCF ($4DB4) leaves carry set so the JP NC is not taken (the POPs were already done as POP AF/POP AF). Both paths converge at $4DB8.
FDIV_6:
        JP NC,$E1C1
        LD A,C
        INC A
        DEC A
        RRA
        JP P,FDIV_8
        RLA
        LD A,(FDIV_5+1)
        RRA
        AND $C0
        PUSH AF
        LD A,B
        OR H
        OR L
        JP Z,FDIV_7
        LD A,$20
FDIV_7:
        POP HL
        OR H
        JP FP_PACK_STORE
FDIV_8:
        ; FDIV_8: shift the remainder and accumulating quotient left one place for the next division step.
        RLA
        LD A,E
        RLA
        LD E,A
        LD A,D
        RLA
        LD D,A
        LD A,C
        RLA
        LD C,A
        ADD HL,HL
        LD A,B
        RLA
        LD B,A
        LD A,(FDIV_5+1)
        RLA
        LD (FDIV_5+1),A
        LD A,C
        OR D
        OR E
        JR NZ,FDIV_1
        PUSH HL
        LD HL,FAC_EXP
        ; Decrement the FAC exponent once per normalizing left-shift; reaching zero yields a zero result (JP FP_SET_ZERO).
        DEC (HL)
        POP HL
        JR NZ,FDIV_1
        JP FP_SET_ZERO
; ----------------------------------------------------------------------
; MULDIV_SIGN -- combine the two operand SIGNS for a double-precision multiply/divide, then fall into EXP_ADD.
;   In:        $0CC0 and $0CC1 hold the two operands' sign/high bytes (bit7 = sign).  Entry at MULDIV_SIGN
;              (A=$FF, used by DDIV via CALL MULDIV_SIGN at line 10368) complements the XOR; entry at
;              MULDIV_SIGN_1+1 (the $AF immediate of LD L,$AF runs as XOR A => A=0, used by DMUL via
;              CALL MULDIV_SIGN_1+1 at line 10234) gives a straight sign XOR.
;   Out:       B = combined result sign/high byte (sign in bit7); C = the first operand's sign byte ($0CC0,
;              loaded in passing); L=$00; falls into EXP_ADD which combines the exponents.
;   Clobbers:  A,B,C,H,L,F.
;   Algorithm: Load the two saved operand sign bytes from $0CC0/$0CC1 and XOR them so the product/quotient is
;              negative iff exactly one operand was negative; the DDIV entry pre-loads A=$FF so the XOR is
;              complemented for its sign convention.  Set L:=$00, then drop into EXP_ADD.  [RE] This base is the
;              double-precision DMUL/DDIV sign+exponent setup; FMUL/FDIV reach EXP_ADD directly with their own
;              L selector, not through here.
; ----------------------------------------------------------------------
MULDIV_SIGN:
        LD A,$FF
; [RE] Flag-skip sign-combine: $4DFB LD L,$AF is a dead load whose $AF immediate doubles as XOR A. DDIV enters via MULDIV_SIGN ($4DF9, A=$FF preserved) so the sign-byte XOR is complemented; DMUL enters at +1 ($4DFC) running XOR A (A=0) for a straight sign XOR. Both fall into LD HL,$0CC0 and XOR the $0CC0/$0CC1 operand signs.
MULDIV_SIGN_1:
        LD L,$AF
        ; Read both operands' saved sign bytes ($0CC0, $0CC1) and XOR them: result is negative iff exactly one operand was negative.
        LD HL,L_0CC0
        LD C,(HL)
        INC HL
        XOR (HL)
        LD B,A
        ; L=$00 selects the add-exponents path in EXP_ADD (this sign-combine entry is the DMUL/DDIV setup).
        LD L,$00
; ----------------------------------------------------------------------
; EXP_ADD -- combine biased exponents for MUL/DIV with over/underflow detection (shared by FMUL/FDIV and the
;              MULDIV_SIGN fall-through).
;   In:        B = operand biased exponent; L = direction selector ($00 = add the FAC exponent for multiply,
;              $FF = one's-complement = subtract the FAC exponent for divide).  FAC exponent at $0CB4, sign/high
;              at $0CB3.
;   Out:       On success: HL -> FAC exponent $0CB4 (so FDIV's following two INC (HL) increment the exponent),
;              the new biased exponent stored at $0CB4, and FP_UNPACK_MSB has set the hidden mantissa MSB and
;              written the result sign/extension bytes; returns via the DEC_HL_RET fall-through.  On operand
;              exponent 0 -> DEC_HL_RET_3 (zero/clear path).  On exponent over/underflow -> the DEC_HL_RET_2
;              fork or FMUL_7.
;   Clobbers:  A,B,H,L,F, $0CB3, $0CB4, $0CB5 (via FP_UNPACK_MSB).
;   Algorithm: If B=0 the operand is zero -> bail to the zero path.  Compute A = (L XOR FAC_exp) + B: with L=$00
;              this is FAC_exp + op_exp (multiply); with L=$FF the FAC_exp is one's-complemented first (~x =
;              -x-1), so A = op_exp - FAC_exp - 1 (divide, later corrected by FDIV's two INC (HL)).  An RRA-then-
;              XOR test detects whether the add overflowed the biased-exponent range; a non-wrapping result is
;              routed to the over/underflow fork (DEC_HL_RET_2), otherwise the exponent is re-biased by +$80 and
;              stored, and on a non-zero exponent FP_UNPACK_MSB restores the hidden MSB and applies the combined
;              sign before the multiply/divide loop runs.
; ----------------------------------------------------------------------
EXP_ADD:
        LD A,B
        OR A
        ; A zero operand exponent means the operand is zero -> route to the zero-result path.
        JR Z,DEC_HL_RET_3
        LD A,L
        LD HL,FAC_EXP
        ; Bring in the FAC exponent: with L=$00 it passes through unchanged; with L=$FF it is one's-complemented (the following ADD A,B then yields op_exp-FAC_exp-1 for divide).
        XOR (HL)
        ADD A,B
        LD B,A
        RRA
        ; [RE] Over/underflow test: compares the sum's sign before vs after the carry to detect an exponent-range wrap.
        XOR B
        LD A,B
        ; A non-wrapping result hands the over/underflow decision to the DEC_HL_RET_2 fork (zero-result vs Overflow error).
        JP P,DEC_HL_RET_2
        ; Re-apply the exponent bias and store at $0CB4; a zero result here underflows -> abandon via FMUL_7 (pop and return).
        ADD A,$80
        LD (HL),A
        JP Z,FMUL_7
        ; [RE] Restore the hidden mantissa MSB and apply the combined sign (FP_UNPACK_MSB also writes the $0CB5 extension byte); leaves HL at $0CB5 so the trailing LD (HL),A writes there before DEC_HL_RET backs HL to the exponent.
        CALL FP_UNPACK_MSB
        LD (HL),A
; ----------------------------------------------------------------------
; DEC_HL_RET -- generic 'DEC HL; RET' pointer back-up helper (also EXP_ADD's success-path tail).
;   In:        HL.  When reached as EXP_ADD's fall-through, HL = $0CB5 (left there by FP_UNPACK_MSB + the
;              preceding LD (HL),A).
;   Out:       HL decremented by 1; returns.  (From EXP_ADD this leaves HL = $0CB4, the FAC exponent cell, which
;              is exactly what FDIV's two INC (HL) then increment.)
;   Clobbers:  HL, F.
;   Algorithm: One-instruction back-up of HL, then RET.  Reused as a standalone CALLed subroutine by the FOUT
;              number formatter (lines 11134, 11344) to step a digit pointer back one byte.
; ----------------------------------------------------------------------
DEC_HL_RET:
        DEC HL
        RET
; ----------------------------------------------------------------------
; EXP_OVUN_TEST -- [RE] over/underflow handler region for the MUL/DIV exponent combine.
;   In:        UNKNOWN as a label entry: no JP/CALL targets EXP_OVUN_TEST ($4E23) anywhere in this build, and it
;              is not a fall-through (the instruction above it is DEC_HL_RET's RET), so its CALL FP_SIGN / CPL /
;              POP HL prefix is UNREACHED here.  The over/underflow region is actually entered ONLY at the two
;              interior labels reached from EXP_ADD: DEC_HL_RET_2 (from JP P, with one stacked frame to discard)
;              and DEC_HL_RET_3 (from JR Z when the operand exponent is 0).
;   Out:       After discarding the saved frame: a positive sign test -> JP FP_SET_ZERO (FAC := 0, underflow);
;              otherwise JP OVERR_SIGN_FROM_ARGS ([RE] the Overflow error path).
;   Clobbers:  A,H,L,F, the discarded stack frame.
;   Algorithm: At DEC_HL_RET_2/DEC_HL_RET_3, pop the saved return/exponent frame and, on a positive sign, clear
;              the FAC to zero (underflow), else fall into OVERR_SIGN_FROM_ARGS.  [RE] The unreached EXP_OVUN_TEST prefix
;              (FP_SIGN; CPL; POP HL) looks like a legacy 're-test and complement the sign' entry inherited from
;              the MS BASIC-80 overflow handler; its role in this image is UNKNOWN because nothing reaches it.
; ----------------------------------------------------------------------
EXP_OVUN_TEST:
        CALL FP_SIGN
        ; [RE] Part of the UNREACHED EXP_OVUN_TEST prefix (no caller in this build); would complement the re-fetched FAC sign ahead of the underflow/overflow fork.
        CPL
        POP HL
DEC_HL_RET_2:
        OR A
DEC_HL_RET_3:
        POP HL
        ; [RE] Underflow branch of the over/underflow fork: a positive sign here clears the FAC to zero.
        JP P,FP_SET_ZERO
        ; [RE] Otherwise fall into OVERR_SIGN_FROM_ARGS (the over/underflow error path).
        JP OVERR_SIGN_FROM_ARGS
; ----------------------------------------------------------------------
; FP_SCALE2 -- multiply the FAC by ten (single precision): FAC = FAC * 10.
;   In:        FAC holds the value (mantissa $0CB1/$0CB2, sign+high $0CB3, exponent $0CB4).
;   Out:       FAC = FAC * 10, normalized.  RET unchanged if FAC=0.  On exponent overflow -> OVERR_SIGN_FROM_FAC
;              ([RE] the Overflow error path).
;   Clobbers:  A,B,C,D,E,H,L,F, the FAC.
;   Algorithm: Load the value into the operand registers (FP_LOAD_FAC: B=exp, C/D/E=mantissa).  Add 2 to the
;              operand exponent (the copy *= 4); a carry there is an exponent overflow.  FADD_ALIGN adds that
;              value*4 to the still-intact FAC (value), giving value*5; then INC the FAC exponent doubles it to
;              value*10.  Used as the single-precision x10 decimal-scale step by the FIN number parser
;              (FIN_MUL10 at line 10585 and the FIN digit path at line 10655).
; ----------------------------------------------------------------------
FP_SCALE2:
        CALL FP_LOAD_FAC
        LD A,B
        OR A
        RET Z
        ; Bump the operand-copy exponent by 2 (multiply the copy by 4); a carry here is an exponent overflow -> Overflow error.
        ADD A,$02
        JP C,OVERR_SIGN_FROM_FAC
        LD B,A
        ; Add value*4 (the operand copy) to the original FAC (value) -> value*5 in the FAC.
        CALL FADD_ALIGN
        LD HL,FAC_EXP
        ; Increment the FAC exponent: doubles value*5 to value*10 (a zero result -> Overflow error).
        INC (HL)
        RET NZ
        JP OVERR_SIGN_FROM_FAC
; ----------------------------------------------------------------------
; FP_SIGN -- return the sign of the FAC as A = -1 / 0 / +1, with flags to match.
;   In:        FAC exponent at $0CB4, sign byte (high mantissa) at $0CB3 (FACHI), bit7 = sign.
;   Out:       A = $00 (and Z) if the FAC is zero (exponent 0); otherwise A = $01 (positive) or $FF (negative),
;              with S/Z reflecting A.
;   Clobbers:  A,F.
;   Algorithm: If the exponent is zero the value is zero -> A=0, return.  Otherwise load the sign byte and run
;              the shared RLA/SBC A,A tail (FP_SIGN_2/_3): RLA shifts the sign bit (bit7) into carry, SBC A,A
;              spreads carry to $00/$FF, and INC A on the positive branch yields +1.  The leading CP $2F is a
;              flag-skip cover whose operand byte ($2F) is executed as CPL when the routine is entered one byte
;              in at FP_SIGN_1+1; FCOMP/DCOMP/INT16_COMP reuse the tail via FP_SIGN_1+1 / FP_SIGN_2 / FP_SIGN_3,
;              entering with a precomputed compare result instead of the raw sign byte.
; ----------------------------------------------------------------------
FP_SIGN:
        LD A,(FAC_EXP)
        OR A
        ; Exponent zero means the FAC value is exactly zero -> return A=0.
        RET Z
        LD A,(FACHI)
; [RE] Flag-skip shared sign tail: $4E4F CP $2F is the FP_SIGN body; FCOMP/DCOMP reuse the tail by entering at FP_SIGN_1+1 ($4E50) where the $2F operand byte runs as CPL, then the shared RLA/SBC A,A ($4E51-$4E55) collapses A to -1/0/+1. The full entry tests the sign byte; the +1 entry complements a precomputed difference.
FP_SIGN_1:
        CP $2F
FP_SIGN_2:
        RLA
FP_SIGN_3:
        ; With the sign bit now in carry (from the preceding RLA), SBC A,A yields $FF (negative) or $00; INC A on the positive branch then makes +1.
        SBC A,A
        RET NZ
        INC A
        RET
; ----------------------------------------------------------------------
; FLOAT_A -- float a signed 8-bit integer in A into the FAC (single precision).
;   In:        A = signed byte to convert.
;   Out:       FAC ($0CB1..$0CB4) holds A as a normalized single-precision float (via FADD_COMBINE).
;   Clobbers:  A, B, C, D, E, H, L, flags, FAC cells, FP sign cell $0CB5.
;   Algorithm: Preset binary exponent B=$88 (left-justifies an 8-bit integer under the $80 bias) and clear the low mantissa word (DE=0), then fall into FLOAT_A_1 which packs the byte and renormalizes. The companion entry FLOAT_FROM_INT enters FLOAT_A_1 with B=$98 to float a signed 16-bit value (INT_TO_SINGLE uses $90).
; ----------------------------------------------------------------------
FLOAT_A:
        ; binary exponent for an 8-bit-wide integer (bias $80 + 8 bits)
        LD B,$88
        ; clear the low 16 bits of the mantissa; the source byte enters via C
        LD DE,$0000
; ----------------------------------------------------------------------
; FLOAT_A_1 -- shared float-pack-and-normalize tail (used by FLOAT_A, FLOAT_FROM_INT, INT_TO_SINGLE).
;   In:        A = signed source value (its sign bit selects the result sign); B = biased binary exponent ($88 for a byte, $98 for a 16-bit int, $90 from INT_TO_SINGLE); DE = low 16 mantissa bits to seed.
;   Out:       Falls into FADD_COMBINE which folds in the sign and normalizes/stores the signed single-precision result in the FAC.
;   Clobbers:  A, B, C, H, L, flags, exponent cell $0CB4, FP sign cell $0CB5.
;   Algorithm: Write the exponent B to $0CB4, stash the source value in C, write $0CB5 (the FP result-sign working cell) = $80 (provisional positive sign), zero B, then RLA to shift the source's sign bit into carry. JP FADD_COMBINE: when carry indicates negative it CALLs FCOMPL (which two's-complements the mantissa and flips $0CB5) before normalizing. [RE] the precise mantissa register packing into FADD is not fully traced.
; ----------------------------------------------------------------------
FLOAT_A_1:
        LD HL,FAC_EXP
        LD C,A
        LD (HL),B
        LD B,$00
        INC HL
        ; seed $0CB5, the FP result-sign cell, with a provisional positive sign
        LD (HL),$80
        ; shift the source sign bit into carry so FADD_COMBINE applies the sign (CALL C,FCOMPL)
        RLA
        JP FADD_COMBINE
; ----------------------------------------------------------------------
; FN_ABS -- ABS() intrinsic (dispatch index 5 = function token $06 ABS): return the absolute value of the FAC.
;   In:        FAC = numeric operand; VALTYP ($0B14) = its type (int / single / double).
;   Out:       FAC = |operand|, same type. A string operand raises Type-mismatch (inside FP_TEST_SIGN).
;   Clobbers:  A, H, L, flags; on the negate path also whatever INT_NEGATE_FAC / FP_NEG touch.
;   Algorithm: FP_TEST_SIGN both type-checks the value (string -> Type mismatch) and returns its sign in A (0 / +1 ($01) / -1 ($FF)) with the FAC left intact. RET P returns when the sign is zero-or-positive (the value already equals its own magnitude). On a negative sign, control falls into FP_NEGATE_CHECKED, which negates by type (integer path via INT_NEGATE_FAC, handling the -32768->single promotion; single/double path via FP_NEG toggling the sign bit), yielding |operand|.
;   [RE] MISLABEL: the file label FN_ABS and the existing '[RE] INT() handler (function token $05): floor to integer' comment are WRONG. The function-dispatch slot address = FUNC_DISPATCH_TBL($01B2) + 2*(token-1) (see the FN_VPOS header note and msbasic_tokens.inc). INT (TOK_INT=$05) -> slot $01BA = FN_INT_FLOOR, which IS the real floor-to-minus-infinity handler. This routine sits at slot $01BC = TOK_ABS=$06, and its code (test sign, keep if >=0, negate if <0) is textbook ABS. It does NOT floor or truncate. Renamed FN_ABS.
; ----------------------------------------------------------------------
FN_ABS:
        ; type-check (string -> Type mismatch) and get the operand's sign in A (0/+1/-1), leaving the FAC unchanged
        CALL FP_TEST_SIGN
        ; sign zero-or-positive: |x| == x, return it unchanged (negative falls into FP_NEGATE_CHECKED to negate)
        RET P
; ----------------------------------------------------------------------
; FP_NEGATE_CHECKED -- unary-minus handler: negate the numeric value in the FAC, dispatching by type.
;   In:        FAC = operand; VALTYP = its type.
;   Out:       FAC = -operand. Integer operands go to INT_NEGATE_FAC (which also handles the $8000 overflow-to-single case); single/double operands have their sign bit flipped by FP_NEG. String operands raise Type-mismatch.
;   Clobbers:  A, H, L, flags (and whatever INT_NEGATE_FAC touches on the integer path).
;   Algorithm: FRMEVL_TEST_TYPE sets flags by VALTYP: sign M => integer (JP INT_NEGATE_FAC), Z => string (JP RAISE_TYPE_MISMATCH); otherwise (single or double) fall into FP_NEG to flip the floating-point sign bit.
; ----------------------------------------------------------------------
FP_NEGATE_CHECKED:
        CALL FRMEVL_TEST_TYPE
        ; integer operand: negate via the integer path (handles the -32768 promotion)
        JP M,INT_NEGATE_FAC
        JP Z,RAISE_TYPE_MISMATCH
; ----------------------------------------------------------------------
; FP_NEG -- negate a floating-point FAC value in place (toggle its sign).
;   In:        FACHI ($0CB3) = the high mantissa byte whose bit 7 is the sign.
;   Out:       FACHI bit 7 inverted, i.e. FAC negated. A = the new $0CB3 byte.
;   Clobbers:  A, H, L, flags.
;   Algorithm: Read $0CB3, XOR $80 to flip the sign bit, store it back. Does not touch the exponent or low mantissa, so a true zero (exponent 0) is unaffected in magnitude.
; ----------------------------------------------------------------------
FP_NEG:
        LD HL,FACHI
        LD A,(HL)
        ; flip the sign bit (bit 7) of the high mantissa byte
        XOR $80
        LD (HL),A
        RET
; [RE] MID$() handler (function token $03): substring extraction.
FN_MID_STR:
        CALL FP_TEST_SIGN
; ----------------------------------------------------------------------
; INT16_TO_FP -- store a signed 8-bit value (in A) into the FAC as a 16-bit BASIC integer.
;   In:        A = signed byte.
;   Out:       FAC = A sign-extended to 16 bits; VALTYP = VT_INT (set by FP_STORE_FAC_INT). Tail-calls FP_STORE_FAC_INT.
;   Clobbers:  A, H, L, flags.
;   Algorithm: Put A into L, then RLA/SBC A,A produces the sign-extension byte ($00 if A>=0, $FF if A<0) into H, forming the signed 16-bit value in HL. JP FP_STORE_FAC_INT writes HL to the FAC and marks it integer. [RE] the relational and EOF handlers (callers at 5064, 17532) use this to deliver boolean results (0 / -1) as integers.
; ----------------------------------------------------------------------
INT16_TO_FP:
        LD L,A
        RLA
        ; form the sign-extension byte (00 or FF) from the carry left by RLA
        SBC A,A
        LD H,A
        JP FP_STORE_FAC_INT
; ----------------------------------------------------------------------
; FP_TEST_SIGN -- type-check the FAC for an INT-class operation and return its sign.
;   In:        FAC = value; VALTYP = its type.
;   Out:       String operand => JP RAISE_TYPE_MISMATCH (no return). Single/double => tail-call FP_SIGN returning A = 0 (zero), $01 (positive) or $FF (negative). Integer => load FAC into HL and fall into FP_MANT_SIGN to test the integer mantissa.
;   Clobbers:  A, H, L, flags.
;   Algorithm: FRMEVL_TEST_TYPE: Z => string error; sign P (single OR double, since both yield a positive A=VALTYP-3) => FP_SIGN on the float; otherwise (M, integer) load the 16-bit mantissa from FAC ($0CB1) and continue into FP_MANT_SIGN.
; ----------------------------------------------------------------------
FP_TEST_SIGN:
        CALL FRMEVL_TEST_TYPE
        JP Z,RAISE_TYPE_MISMATCH
        ; single or double value: return its sign via the shared SIGN tail
        JP P,FP_SIGN
        LD HL,(FAC)
; ----------------------------------------------------------------------
; FP_MANT_SIGN -- sign of the 16-bit integer mantissa already loaded in HL.
;   In:        HL = the FAC integer value (loaded by the FP_TEST_SIGN integer path).
;   Out:       A = 0 with Z set if the value is zero; otherwise A = $01/$FF (positive/negative) via the shared FP_SIGN tail (entered at FP_SIGN_2).
;   Clobbers:  A, flags.
;   Algorithm: OR H with L to test for zero and RET Z. Otherwise load the high byte (its bit 7 is the sign) into A and JR FP_SIGN_2, where RLA/SBC A,A collapse A to the signed -1/0/+1 result.
; ----------------------------------------------------------------------
FP_MANT_SIGN:
        LD A,H
        ; zero integer => sign 0; return immediately
        OR L
        RET Z
        LD A,H
        ; reuse the SIGN tail to collapse the high byte to -1/+1
        JR FP_SIGN_2
; ----------------------------------------------------------------------
; FAC_PUSH -- PUSHF: save the FAC's working bytes onto the stack, preserving the caller's return address.
;   In:        FAC ($0CB1 mantissa low word) and FACHI ($0CB3 sign/high byte) hold the value; the return address is on top of the stack.
;   Out:       The two FAC words are pushed below the (still top-of-stack) return address; HL/DE restored to their entry values. RET to caller.
;   Clobbers:  flags; stack grows by 4 bytes (HL and DE net unchanged).
;   Algorithm: EX DE,HL saves the caller's HL in DE. Load FAC into HL, EX (SP),HL swaps it with the return address (return address now in HL), PUSH HL puts the return address back on top with the FAC word beneath it; repeat for FACHI. EX DE,HL restores HL. Net: the two FAC words are interleaved beneath the return address so a later POP can recover them.
; ----------------------------------------------------------------------
FAC_PUSH:
        EX DE,HL
        LD HL,(FAC)
        ; swap the FAC word under the return address so RET still works
        EX (SP),HL
        PUSH HL
        LD HL,(FACHI)
        EX (SP),HL
        PUSH HL
        EX DE,HL
        RET
; ----------------------------------------------------------------------
; FP_STORE_REGS_LD -- load a 4-byte FP operand from (HL) into registers, then store it into the FAC.
;   In:        HL = address of a 4-byte FP value.
;   Out:       FAC ($0CB1..$0CB4) = the value; HL advanced past the source.
;   Clobbers:  B,C,D,E,H,L, flags, FAC cells.
;   Algorithm: CALL FP_LOAD_MEM reads (HL..HL+3) into E,D,C,B (advancing HL), then fall into FP_STORE_FAC which writes DE -> $0CB1 and B,C -> $0CB3/$0CB4. A combined memory->FAC move; e.g. FDIV_BY_TEN ($9087) uses it to load the constant DP_CONST_2.
; ----------------------------------------------------------------------
FP_STORE_REGS_LD:
        CALL FP_LOAD_MEM
; ----------------------------------------------------------------------
; FP_STORE_FAC -- MOVFR [RE]: store a 4-byte FP value from registers into the FAC.
;   In:        DE = mantissa low word; B = high mantissa/sign byte; C = exponent byte.
;   Out:       FAC ($0CB1) = DE; $0CB3 = B (sign/high byte); $0CB4 = C (exponent); HL restored to the caller's entry HL; DE = (B in D, C in E) after the final EX.
;   Clobbers:  H, L, flags; DE altered.
;   Algorithm: EX DE,HL puts the mantissa low word in HL and stores it to $0CB1; build HL=B:C and store that word to $0CB3/$0CB4 (so $0CB3=B sign/high, $0CB4=C exponent). The final EX DE,HL restores the caller's HL (now leaving B:C in DE). The standard MS BASIC-80 register-to-FAC move.
; ----------------------------------------------------------------------
FP_STORE_FAC:
        EX DE,HL
        ; store the mantissa low word into FAC ($0CB1)
        LD (FAC),HL
        LD H,B
        LD L,C
        ; store sign/high byte (B) at $0CB3 and exponent byte (C) at $0CB4
        LD (FACHI),HL
        EX DE,HL
        RET
; ----------------------------------------------------------------------
; FP_LOAD_FAC -- MOVRF [RE]: load the FAC's 4-byte FP value into registers E,D,C,B.
;   In:        FAC ($0CB1).
;   Out:       E,D,C,B = the four FP bytes ($0CB1,$0CB2,$0CB3,$0CB4); HL = FAC+4 ($0CB5).
;   Clobbers:  B,C,D,E,H,L.
;   Algorithm: Point HL at FAC and fall into FP_LOAD_MEM, the generic (HL)->E,D,C,B reader.
; ----------------------------------------------------------------------
FP_LOAD_FAC:
        LD HL,FAC
; ----------------------------------------------------------------------
; FP_LOAD_MEM -- read a 4-byte FP value from (HL) into registers E,D,C,B, advancing HL.
;   In:        HL = source address.
;   Out:       E=(HL),D=(HL+1),C=(HL+2),B=(HL+3); HL = source+4.
;   Clobbers:  B,C,D,E,H,L.
;   Algorithm: Read the first byte into E, then fall into FP_LOAD_MEM3 to read the remaining three into D,C,B. The shared FP_LOAD_DONE tail does the final INC HL and RET.
; ----------------------------------------------------------------------
FP_LOAD_MEM:
        LD E,(HL)
        INC HL
; ----------------------------------------------------------------------
; FP_LOAD_MEM3 -- read 3 FP bytes from (HL) into D,C,B (continuation entry past the first byte).
;   In:        HL = address of the second of four FP bytes.
;   Out:       D=(HL),C=(HL+1),B=(HL+2); HL = address+3 (via the FP_LOAD_DONE tail).
;   Clobbers:  B,C,D,H,L.
;   Algorithm: Sequential reads of D,C,B with INC HL between, then fall into FP_LOAD_DONE for the final INC HL and RET. Entered directly when the first byte was already loaded by the caller.
; ----------------------------------------------------------------------
FP_LOAD_MEM3:
        LD D,(HL)
        INC HL
        LD C,(HL)
        INC HL
        LD B,(HL)
; ----------------------------------------------------------------------
; FP_LOAD_DONE -- shared tail of the (HL)->register FP loaders: final pointer bump and return.
;   In:        HL = pointer at the last byte just read.
;   Out:       HL = past the 4-byte field; RET.
;   Clobbers:  H, L.
;   Algorithm: INC HL then RET, so every loader leaves HL one past the value it read.
; ----------------------------------------------------------------------
FP_LOAD_DONE:
        INC HL
        RET
; ----------------------------------------------------------------------
; FP_MOVE_TO_FAC -- MOVE [RE]: copy a 4-byte FP value from (DE) into the FAC.
;   In:        DE = source address of a 4-byte FP value.
;   Out:       FAC ($0CB1..$0CB4) = the copied bytes; DE = source+4, HL = FAC+4.
;   Clobbers:  A, B, D, E, H, L, flags.
;   Algorithm: Set HL = FAC (the destination) and fall into FP_MOVE4, the fixed 4-byte (DE)->(HL) block copy.
; ----------------------------------------------------------------------
FP_MOVE_TO_FAC:
        LD DE,FAC
; ----------------------------------------------------------------------
; FP_MOVE4 -- copy a fixed 4 bytes from (DE) to (HL); the single-precision FP block move.
;   In:        DE = source, HL = destination.
;   Out:       4 bytes copied; DE and HL advanced by 4; B = 0.
;   Clobbers:  A, B, D, E, H, L, flags.
;   Algorithm: Load count B=4 and JR into FP_MOVE_LOOP. The separate entry FP_MOVE4_1 (below) first does EX DE,HL then falls into the VALTYP-sized move FP_MOVE_TYPED instead.
; ----------------------------------------------------------------------
FP_MOVE4:
        LD B,$04
        JR FP_MOVE_LOOP
; ----------------------------------------------------------------------
; FP_MOVE4_1 -- typed-operand move entry: swap DE<->HL then copy VALTYP bytes (DE)->(HL).
;   In:        HL = source, DE = destination (the FP_ARG_SETUP1 convention).
;   Out:       After the EX, DE = source and HL = destination; VALTYP bytes copied; B = 0.
;   Clobbers:  A, B, D, E, H, L, flags.
;   Algorithm: EX DE,HL converts the (HL=src, DE=dst) caller convention into the (DE=src, HL=dst) convention the copy loop expects, then falls into FP_MOVE_TYPED to move exactly VALTYP bytes. This is the continuation FP_ARG_SETUP1 queues for the double-operand case.
; ----------------------------------------------------------------------
FP_MOVE4_1:
        ; swap to the (DE=source, HL=dest) convention the copy loop expects
        EX DE,HL
; ----------------------------------------------------------------------
; FP_MOVE_TYPED -- copy VALTYP bytes from (DE) to (HL); the type-width FP/value block move.
;   In:        DE = source, HL = destination; VALTYP ($0B14) = the value's storage width in bytes (2=int, 3=string descriptor, 4=single, 8=double).
;   Out:       VALTYP bytes copied; DE,HL advanced by VALTYP; B = 0.
;   Clobbers:  A, B, D, E, H, L, flags.
;   Algorithm: Load B = VALTYP and fall into FP_MOVE_LOOP, a DJNZ byte copier. Because the loop count is exactly VALTYP, this site is direct evidence that VALTYP encodes the value's byte width.
; ----------------------------------------------------------------------
FP_MOVE_TYPED:
        ; copy length = VALTYP, the value's storage width in bytes
        LD A,(VALTYP)
        LD B,A
; ----------------------------------------------------------------------
; FP_MOVE_LOOP -- DJNZ byte-copy loop body shared by the FP block moves.
;   In:        DE = source, HL = destination, B = byte count.
;   Out:       B bytes copied; DE,HL advanced by B; B = 0; RET.
;   Clobbers:  A, B, D, E, H, L, flags.
;   Algorithm: LD A,(DE) / LD (HL),A / INC DE / INC HL / DJNZ. A plain forward memory copy.
; ----------------------------------------------------------------------
FP_MOVE_LOOP:
        LD A,(DE)
        LD (HL),A
        INC DE
        INC HL
        DJNZ FP_MOVE_LOOP
        RET
; ----------------------------------------------------------------------
; FP_UNPACK_MSB -- restore the hidden mantissa MSBs and combine the operand signs for a multiply/divide/add-align.
;   In:        FACHI ($0CB3) = the FAC's packed sign/high mantissa byte; C = the operand's packed sign/high mantissa byte.
;   Out:       $0CB3 bit 7 forced to 1 (FAC hidden MSB restored); $0CB5 (FP_SIGN_FLAG) = a sign-derived byte; C bit 7 forced to 1 (operand hidden MSB restored); A = the combined sign bit (FAC sign XOR operand sign). Callers: FADD_ALIGN ($8763, saves A in H across MANT_SHIFT_BYTES) and EXP_ADD/FMUL+FDIV ($9222, stores A back to $0CB5).
;   Clobbers:  A, C, H, L, flags, $0CB3, $0CB5.
;   Algorithm: For the FAC byte: RLCA rotates bit 7 (sign) into carry, SCF+RRA forces bit 7 = 1 (the implicit leading mantissa bit) and writes it back at $0CB3; CCF+RRA forms a sign-derived byte written to $0CB5. For C (the operand): RLCA/SCF/RRA likewise forces C bit 7 = 1; a trailing RRA/XOR (HL=$0CB5) combines the two signs into A. [RE] the exact rounding-vs-sign meaning of the returned A bit is inferred from the two call sites and the standard MBF multiply prologue, not traced bit-by-bit.
; ----------------------------------------------------------------------
FP_UNPACK_MSB:
        LD HL,FACHI
        LD A,(HL)
        ; rotate the FAC sign bit out of bit 7 into carry
        RLCA
        ; force the hidden mantissa MSB (bit 7 = 1) back into the FAC high byte
        SCF
        RRA
        ; [RE] write the sign-derived byte into the FP sign cell ($0CB5)
        LD (HL),A
        CCF
        RRA
        INC HL
        INC HL
        LD (HL),A
        ; now restore the operand's hidden MSB and combine its sign with the FAC sign
        LD A,C
        RLCA
        SCF
        RRA
        LD C,A
        RRA
        XOR (HL)
        RET
; ----------------------------------------------------------------------
; FP_ARG_TO_TEMP1 -- operand-setup wrapper that targets the secondary temp at $0CBA (swap-move variant).
;   In:        FAC = current value; VALTYP = its type.
;   Out:       Sets HL = ARG2_TEMP ($0CBA) as the move destination anchor, then falls into FP_ARG_SETUP1 to stage the typed move (FP_MOVE4_1 continuation).
;   Clobbers:  A, D, E, H, L, flags (and the move performed on return).
;   Algorithm: Load HL with the $0CBA temp pointer and continue into FP_ARG_SETUP1, which queues the FP_MOVE4_1 continuation and selects the source by VALTYP.
; ----------------------------------------------------------------------
FP_ARG_TO_TEMP1:
        LD HL,ARG2_TEMP
; ----------------------------------------------------------------------
; FP_ARG_SETUP1 -- prepare a typed FP operand move, selecting the swap-form copy (FP_MOVE4_1).
;   In:        HL = the operand's destination anchor (e.g. ARG2_TEMP); FAC/VALTYP = the value being staged.
;   Out:       Returns with FP_MOVE4_1 queued as the continuation and DE = source: FAC ($0CB1) for int/string/single (carry-set early return), or the double-FAC base $0CAD (FAC_DBL) for a double operand (VALTYP>=8).
;   Clobbers:  A, D, E, flags; pushes one continuation address.
;   Algorithm: Load DE = FP_MOVE4_1 (the swap-then-copy move) and JR into the shared FP_ARG_SETUP2_1 body, which pushes that continuation, runs FRMEVL_TEST_TYPE, returns DE=FAC on carry (VALTYP<8), else points DE at the double-FAC base $0CAD.
; ----------------------------------------------------------------------
FP_ARG_SETUP1:
        LD DE,FP_MOVE4_1
        JR FP_ARG_SETUP2_1
; ----------------------------------------------------------------------
; FP_ARG_TO_TEMP2 -- operand-setup wrapper that targets the secondary temp at $0CBA (typed-move variant).
;   In:        FAC = current value; VALTYP = its type.
;   Out:       Sets HL = ARG2_TEMP ($0CBA) and falls into FP_ARG_SETUP2, which queues the VALTYP-sized move (FP_MOVE_TYPED).
;   Clobbers:  A, D, E, H, L, flags (and the staged move).
;   Algorithm: Load HL with the $0CBA temp pointer and continue into FP_ARG_SETUP2 (the FP_MOVE_TYPED-selecting variant).
; ----------------------------------------------------------------------
FP_ARG_TO_TEMP2:
        LD HL,ARG2_TEMP
; ----------------------------------------------------------------------
; FP_ARG_SETUP2 -- prepare a typed FP operand move, selecting the VALTYP-sized copy (FP_MOVE_TYPED).
;   In:        HL = the operand's destination anchor; FAC/VALTYP = the value being staged.
;   Out:       Returns with FP_MOVE_TYPED queued as the continuation and DE = source: FAC ($0CB1) for int/string/single (carry-set return), or FAC_DBL ($0CAD) for a double operand.
;   Clobbers:  A, D, E, flags; pushes one continuation address.
;   Algorithm: Load DE = FP_MOVE_TYPED (the width-driven copy) and fall into FP_ARG_SETUP2_1: PUSH the move continuation, set DE = FAC, run FRMEVL_TEST_TYPE (RET C when VALTYP<8), else point DE at the double-FAC base $0CAD before returning into the queued move.
; ----------------------------------------------------------------------
FP_ARG_SETUP2:
        LD DE,FP_MOVE_TYPED
; ----------------------------------------------------------------------
; FP_ARG_SETUP2_1 -- shared body of the FP operand-setup helpers: push the move, classify by VALTYP, pick the source.
;   In:        DE = the move routine to run on return (FP_MOVE4_1 or FP_MOVE_TYPED); HL = operand destination anchor; VALTYP = type.
;   Out:       The move routine is PUSHed (so the final RET enters it); DE = source pointer = FAC ($0CB1) for int/string/single (carry set, early RET) or FAC_DBL ($0CAD) for a double (VALTYP>=8).
;   Clobbers:  A, D, E, flags; pushes one address.
;   Algorithm: PUSH DE (queue the move). Set DE = FAC as the default source. CALL FRMEVL_TEST_TYPE: it sets carry for VALTYP<8 (int/string/single) -> RET C leaving DE=FAC. Only when carry is clear (VALTYP>=8, double) does it set DE = FAC_DBL ($0CAD), the double-FAC base, and RET into the queued move. NOTE: the discriminator is double-vs-not-double (carry), NOT string-vs-non-string.
; ----------------------------------------------------------------------
FP_ARG_SETUP2_1:
        ; queue the selected move routine; the final RET dispatches into it
        PUSH DE
        LD DE,FAC
        CALL FRMEVL_TEST_TYPE
        RET C
        ; double operand (VALTYP>=8, carry clear): source the double-FAC base ($0CAD)
        LD DE,FAC_DBL
        RET
; ----------------------------------------------------------------------
; FCOMP -- single-precision floating-point compare: FAC against the register operand in B/C/D/E.
;   In:        FAC = first operand (FAC=$0CB1 mantissa-low, FACHI=$0CB3 mantissa-MSB+sign in bit7, FAC_EXP=$0CB4 biased exponent). B = second operand's exponent; C = its packed sign/MSB byte (bit7=sign); D,E = its low mantissa bytes (a 4-byte single laid out in registers).
;   Out:       A = ordering of (FAC vs operand). On the normal mantissa-compare path A is the clean relational code $00 (equal) / $01 (FAC>operand) / $FF (FAC<operand) produced via the FP_SIGN tail and the FCOMP_1 fold. [RE] BUT the signs-differ early-out (RET M) returns the RAW operand sign byte C, not a normalized $FF/$01 -- only its bit7 (sign) is meaningful; the relational finalizer (FRMEVL_RELOP_RESULT) consumes that bit. So 'clean -1/0/+1' holds only on the equal-sign path.
;   Clobbers:  A, HL, F (B,C,D,E preserved as the operand).
;   Algorithm: If the operand exponent B==0 the operand is zero, so the answer is SGN(FAC) (JP FP_SIGN). Otherwise arm the FP_SIGN tail (PUSH FP_SIGN_1+1) and call FP_SIGN; if FAC==0 (Z) return A=C (the operand's sign byte). If the two signs differ (FACHI XOR C has bit7 set) return A=C raw (RET M) -- the sign byte alone decides the order. With equal signs, compare the four mantissa bytes high-to-low (FP_MANT_EQ); on a difference FCOMP_1 folds the borrow bit (RRA) with the sign (XOR C) into the final code. [RE] FP_SIGN_2/_3 collapse a sign byte to $FF(neg)/$01(pos); the exact direction of the signs-differ result was not hand-verified beyond 'bit7 of C decides'.
; ----------------------------------------------------------------------
FCOMP:
        LD A,B
        OR A
        ; operand exponent 0 => operand is zero; result is just SGN(FAC)
        JP Z,FP_SIGN
        ; arm the FP_SIGN tail (entered at +1) to fold the pending result into the -1/0/+1 code
        LD HL,FP_SIGN_1+1
        PUSH HL
        CALL FP_SIGN
        LD A,C
        ; FAC is zero => return A=C, the operand's sign byte (its bit7 gives the ordering)
        RET Z
        LD HL,FACHI
        ; test bit7 of C XOR FACHI: do FAC and the operand have different signs?
        XOR (HL)
        LD A,C
        ; opposite signs: return the raw operand sign byte C; its sign bit decides the order
        RET M
        ; same sign: compare the 4 mantissa bytes high-to-low
        CALL FP_MANT_EQ
FCOMP_1:
        RRA
        XOR C
        RET
; ----------------------------------------------------------------------
; FP_MANT_EQ -- compare the register operand's 4 mantissa bytes against a memory FP value, with a two-level-return early-out on full equality.
;   In:        B,C,D,E = the register operand's mantissa bytes (B = MSB ... E = LSB). On entry HL points one byte BELOW the memory operand's mantissa MSB (FACHI-1 when called from FCOMP, since FACHI was loaded just before); the first INC HL steps onto the MSB.
;   Out:       If all four bytes are equal: pops TWO return addresses and RETs, so control returns two levels up (past FCOMP's own caller) with A==0 / Z set -- the 'operands equal' fast path. If any byte differs: RETs to the caller (FCOMP) with NZ; on the first three bytes A/flags hold a CP result, on the LSB A holds the SUB (borrow) result for FCOMP_1 to fold.
;   Clobbers:  A, HL, F.
;   Algorithm: Walk MSB-first: INC HL then CP B; DEC HL/CP C; DEC HL/CP D; DEC HL/SUB E on the LSB. Note the pointer steps UP once to the MSB then DECREMENTS down through the bytes. The first non-equal byte RETs immediately (NZ). Only if every byte matched does it reach the double POP HL, unwinding two stack levels to signal exact equality.
;   [RE]:      The MSB byte uses CP (compare only); the LSB uses SUB so A carries the borrow out to FCOMP_1. Whether the memory operand really is FACHI/FAC at the byte level depends on HL on entry; verified for the FCOMP call (HL=FACHI just loaded).
; ----------------------------------------------------------------------
FP_MANT_EQ:
        ; step up to the mantissa MSB, then the compares walk back down byte by byte
        INC HL
        LD A,B
        CP (HL)
        RET NZ
        DEC HL
        LD A,C
        CP (HL)
        RET NZ
        DEC HL
        LD A,D
        CP (HL)
        RET NZ
        DEC HL
        LD A,E
        ; lowest byte uses SUB (not CP) so A/borrow flow out to FCOMP_1 on a mismatch
        SUB (HL)
        RET NZ
        ; all bytes equal: discard two return levels so the caller's caller sees 'equal'
        POP HL
        POP HL
        RET
; ----------------------------------------------------------------------
; INT16_COMP -- signed 16-bit integer relational compare via the FP_SIGN tail, producing the standard -1/0/+1 ordering code.
;   In:        D:E and H:L = the two signed 16-bit operands. Per the integer dispatch (FRMEVL_OPC_DISPATCH_INT) DE = left operand (popped from stack) and HL = right operand (from the FAC).
;   Out:       A = $FF / $00 / $01 ordering code (via FP_SIGN_2/_3), consumed by FRMEVL_RELOP_RESULT as 'sign of (left - right)'. Exact equality returns directly (the SUB E leaves A=0, Z set).
;   Clobbers:  A, F (D,E,H,L preserved).
;   Algorithm: XOR the two high bytes (D^H) to test whether the signs differ; if they differ (M) the sign of one high byte alone decides the order via FP_SIGN_2 (A was reloaded with H). With matching signs, compare high bytes (CP D); on a difference FP_SIGN_3's SBC A,A turns the borrow into the ordering code. If highs are equal, compare low bytes (SUB E) the same way. Exact equality falls through to RET with A==0.
;   [RE]:      FP_SIGN_2 maps bit7-set->$FF and bit7-clear->$01. The signs-differ branch feeds it A=H (the second/right operand's high byte); a hand-trace did not cleanly reconcile the resulting direction with 'sign of (left-right)', so the precise sign of THAT branch is left [RE]/unconfirmed (the relational mask bit assignment in FRMEVL_RELOP_RESULT was likewise not pinned). The high/low-byte compare branches do compute sign of (D:E - H:L).
; ----------------------------------------------------------------------
INT16_COMP:
        LD A,D
        ; do the two integers have different signs? (tests bit7 of D^H)
        XOR H
        LD A,H
        ; signs differ => one high byte's sign alone gives the ordering (A was reloaded with H)
        JP M,FP_SIGN_2
        ; same sign: compare high bytes; a difference yields the ordering via the borrow
        CP D
        JP NZ,FP_SIGN_3
        LD A,L
        ; high bytes equal: compare low bytes for the final ordering
        SUB E
        JP NZ,FP_SIGN_3
        RET
; ----------------------------------------------------------------------
; DCOMP -- comparison entry that first marshals the second operand into the temp at ARG2_TEMP, then falls into DCOMP_BODY.
;   In:        FAC = first operand. VALTYP ($0B14) = the second operand's type (its storage width in bytes); the second operand sits where FP_MOVE_TYPED's source DE points (set up by the caller).
;   Out:       Falls into DCOMP_BODY, which returns the ordering of FAC vs the temp operand.
;   Clobbers:  A, B, C, D, E, H, L, F.
;   Algorithm: Copy the second operand into the comparison temp at ARG2_TEMP using FP_MOVE_TYPED -- a DJNZ copy of VALTYP bytes (the direct proof that VALTYP is the byte width). Then drop into DCOMP_BODY. NOTE: FP_MOVE_TYPED's source/destination are whatever DE/HL hold on entry; DCOMP only sets HL=ARG2_TEMP, so the source operand must have been positioned by the caller. [RE] Whether DCOMP is reached as a live entry (vs DCOMP_BODY directly) was not pinned from the dispatch tables here.
; ----------------------------------------------------------------------
DCOMP:
        ; destination = the 8-byte comparison temp (ARG); FP_MOVE_TYPED copies VALTYP bytes into it
        LD HL,ARG2_TEMP
        CALL FP_MOVE_TYPED
; ----------------------------------------------------------------------
; DCOMP_BODY -- core compare of FAC against the temp operand staged at ARG2_TEMP: returns the ordering of (FAC vs temp).
;   In:        FAC = first operand (FACHI sign in bit7, FAC_EXP exponent). Temp operand pre-staged at ARG2_TEMP: its exponent at L_0CC1, packed sign/MSB at L_0CC0, the rest descending below.
;   Out:       A = ordering code on the clean path ($00 equal, $01/$FF otherwise via the FP_SIGN tail). On a mantissa-byte difference it jumps to FCOMP_1 (shared with the single comparator) to fold the borrow+sign. [RE] As in FCOMP, the signs-differ early-out (RET M) returns the raw temp sign byte C, not a normalized code.
;   Clobbers:  A, B, C, D, E, H, L, F.
;   Algorithm: Same shape as FCOMP but operands are in MEMORY and the loop walks 8 bytes. If the temp exponent (L_0CC1) is 0 the temp is zero => answer SGN(FAC). Otherwise arm the FP_SIGN tail and call FP_SIGN; load C = temp sign byte (L_0CC0). If FAC==0 (Z) return A=C. If signs differ (FACHI XOR C, bit7 set) return A=C raw (RET M). With equal signs, set B=8 and compare descending from the high cells: HL starts at FACHI+1 ($0CB4) and DE at L_0CC1, BOTH decrementing each iteration (LD A,(DE) / SUB (HL) / DEC DE / DEC HL). The first differing byte jumps to FCOMP_1. A full 8-byte match drops the armed FP_SIGN return (POP BC) and RETs equal (A==0).
;   [RE]:      The prior spec said the loop walks 'HL from FACHI upward / DE from L_0CC0 downward' -- that is WRONG. The code does INC HL/INC DE once (to FACHI+1 / L_0CC1) and then BOTH pointers DECREMENT; the compare runs high cell (the exponent byte) down through the mantissa.
; ----------------------------------------------------------------------
DCOMP_BODY:
        LD DE,L_0CC1
        LD A,(DE)
        OR A
        ; temp exponent 0 => temp operand is zero; result is SGN(FAC)
        JP Z,FP_SIGN
        ; arm the FP_SIGN tail (entered at +1) for the final relational fold
        LD HL,FP_SIGN_1+1
        PUSH HL
        CALL FP_SIGN
        DEC DE
        LD A,(DE)
        LD C,A
        ; FAC is zero => return A=C, the temp operand's sign byte
        RET Z
        LD HL,FACHI
        ; test bit7 of C XOR FACHI: signs differ?
        XOR (HL)
        LD A,C
        RET M
        INC DE
        INC HL
        ; same sign: compare 8 bytes, walking both pointers DOWN from the high (exponent) cell
        LD B,$08
DCOMP_BODY_1:
        LD A,(DE)
        SUB (HL)
        ; first differing byte: fold borrow+sign into the result (shared tail with FCOMP)
        JP NZ,FCOMP_1
        DEC DE
        DEC HL
        DEC B
        JR NZ,DCOMP_BODY_1
        ; all 8 bytes equal: drop the armed FP_SIGN return and exit equal
        POP BC
        RET
; ----------------------------------------------------------------------
; DCOMP_REL -- double-precision relational comparator (operator-table double-compare slot, $050B): run DCOMP_BODY and normalize the result to the relational code.
;   In:        FAC = first operand; the second operand pre-staged in the temp at ARG2_TEMP by the caller. Reached from the double-operand operator dispatch.
;   Out:       A = $00 if equal (returns immediately), else the normalized ordering from the FP_SIGN tail (FP_SIGN_1+1). Consumed by FRMEVL_RELOP_RESULT.
;   Clobbers:  A, B, C, D, E, H, L, F.
;   Algorithm: CALL DCOMP_BODY; if it returned zero (Z, operands equal) RET with A=0. Otherwise JP FP_SIGN_1+1 to normalize the raw result into the canonical ordering code. This is the double-precision analog of how FCOMP_1 finalizes FCOMP.
; ----------------------------------------------------------------------
DCOMP_REL:
        CALL DCOMP_BODY
        ; nonzero difference => normalize to the relational ordering code via the FP_SIGN tail
        JP NZ,FP_SIGN_1+1
        RET
; ----------------------------------------------------------------------
; FN_CINT -- CINT(x): round x to the nearest signed 16-bit integer and store it in the FAC as an integer; also the universal FAC->int16 coercion entry (MS BASIC FRCINT) reused by GETINT/GETBYT/GETADR.
;   In:        FAC holds the value; VALTYP ($0B14) gives its type. The integer form lands at FAC=$0CB1.
;   Out:       FAC = the rounded 16-bit integer ($0CB1); VALTYP set to VT_INT (=2). Raises 'Overflow' if the exponent is >= $90 (magnitude >= 2^16); 'Type mismatch' on a string.
;   Clobbers:  A, B, C, D, E, H, L, F.
;   Algorithm: Type-check via FRMEVL_TEST_TYPE (loads HL=(FAC) regardless). If already integer (M) RET unchanged. If string (Z) raise Type mismatch. If single (PO) round at FN_CINT_1 by adding the single 0.5 constant (FADD_LOAD_CONST). If double (fall-through), stage the operand to temp (FP_ARG_TO_TEMP2), DADD the double 0.5 constant, then FIX_TO_INT (narrow double->single). FN_CINT_2 then takes |FAC|: save the FACHI sign (OR A; PUSH AF), clear bit7, range-check the exponent (CP $90; JP NC,RAISE_OVERFLOW), shift the mantissa down to a raw 16-bit magnitude (FP_SHIFT_MANTISSA), and if the original value was negative two's-complement the 16-bit result (CPL H, CPL L) before storing via FP_STORE_FAC_INT.
;   [RE]:      The double path's FIX_TO_INT narrows double->SINGLE (not 'to int'); the actual int extraction is FN_CINT_2's magnitude shift. CINT accepts the full unsigned 16-bit magnitude range (< 2^16) and lets the result wrap when negative, so the $90 guard is 'exponent >= 2^16', not a strict signed-range check.
; ----------------------------------------------------------------------
FN_CINT:
        CALL FRMEVL_TEST_TYPE
        LD HL,(FAC)
        ; already an integer: nothing to convert
        RET M
        ; string value: not coercible to a number
        JP Z,RAISE_TYPE_MISMATCH
        ; single precision: round by adding the single 0.5 constant
        JP PO,FN_CINT_1
        CALL FP_ARG_TO_TEMP2
        ; double precision: point at the double 0.5 constant to add before narrowing
        LD HL,FP_CONST_HALF_DBL
        CALL FP_ARG_SETUP1
        CALL DADD
        CALL FIX_TO_INT
        JP FN_CINT_2
FN_CINT_1:
        ; single path: add 0.5 so the following shift rounds to nearest
        CALL FADD_LOAD_CONST
FN_CINT_2:
        LD A,(FACHI)
        OR A
        ; remember the sign of the value before taking its magnitude
        PUSH AF
        ; clear FACHI bit7: work on |x| from here on
        AND $7F
        LD (FACHI),A
        LD A,(FAC_EXP)
        CP $90
        ; exponent >= $90 (magnitude >= 2^16): cannot fit a 16-bit integer
        JP NC,RAISE_OVERFLOW
        ; shift the aligned mantissa down to a raw 16-bit integer magnitude
        CALL FP_SHIFT_MANTISSA
        LD A,(FAC_EXP)
        OR A
        JP NZ,FN_CINT_3
        POP AF
        EX DE,HL
        JP FN_CINT_4
FN_CINT_3:
        POP AF
        EX DE,HL
        JP P,FN_CINT_5
FN_CINT_4:
        ; value was negative: two's-complement the 16-bit magnitude back to a signed result
        LD A,H
        CPL
        LD H,A
        LD A,L
        CPL
        LD L,A
FN_CINT_5:
        JP FP_STORE_FAC_INT
FN_CINT_6:
        LD HL,RAISE_OVERFLOW
        PUSH HL
; ----------------------------------------------------------------------
; FP_TO_INT -- convert the (positive-magnitude) FAC float to a 16-bit integer in HL, with an overflow guard, then store and tag it integer.
;   In:        FAC = a positive/pre-magnituded float; exponent at FAC_EXP.
;   Out:       16-bit integer stored into the FAC (via FP_TO_INT_1 -> FP_STORE_FAC_INT) with VALTYP=VT_INT. If the exponent is >= $90 control diverts to FP_TO_INT_RANGE for the boundary/overflow check.
;   Clobbers:  A, B, C, D, E, H, L, F.
;   Algorithm: If exponent >= $90 the integer needs 16+ bits, so JR to FP_TO_INT_RANGE. Otherwise FP_SHIFT_MANTISSA shifts the mantissa down into a raw 16-bit magnitude, EX DE,HL moves it to HL, and FP_TO_INT_1 pops the saved hook (POP DE) and stores via FP_STORE_FAC_INT.
;   Note:      FN_CINT_6 (the byte just before FP_TO_INT) does LD HL,RAISE_OVERFLOW / PUSH HL before falling in, so when FP_TO_INT_RANGE returns NZ (out of range) the popped/return path lands on the overflow handler.
; ----------------------------------------------------------------------
FP_TO_INT:
        LD A,(FAC_EXP)
        CP $90
        ; exponent >= $90: handle the 16-bit boundary / overflow separately
        JR NC,FP_TO_INT_RANGE
        ; in range: shift the mantissa down to a 16-bit integer magnitude
        CALL FP_SHIFT_MANTISSA
        EX DE,HL
FP_TO_INT_1:
        POP DE
; ----------------------------------------------------------------------
; FP_STORE_FAC_INT -- store a 16-bit integer into the FAC and mark the FAC integer-typed (MS BASIC MOVFR, integer case).
;   In:        HL = the signed 16-bit integer to install.
;   Out:       FAC ($0CB1) = HL; VALTYP ($0B14) = VT_INT (=2). RET.
;   Clobbers:  A, F.
;   Algorithm: LD (FAC),HL, then fall into SET_TYPE_INTEGER to tag the value. The integer-result store used throughout the evaluator whenever a routine produces a 16-bit integer in HL.
; ----------------------------------------------------------------------
FP_STORE_FAC_INT:
        LD (FAC),HL
; ----------------------------------------------------------------------
; SET_TYPE_INTEGER -- mark the current FAC value as integer-typed.
;   In:        (none; sets a fixed type code).
;   Out:       VALTYP ($0B14) = VT_INT (=2). RET.
;   Clobbers:  A, F.
;   Algorithm: LD A,$02 then fall into SET_TYPE_INTEGER_1, the shared 'LD (VALTYP),A; RET' tail reached by all the type-setters. Entered as a fall-through from FP_STORE_FAC_INT and directly by integer-producing operations.
; ----------------------------------------------------------------------
SET_TYPE_INTEGER:
        LD A,$02
SET_TYPE_INTEGER_1:
        LD (VALTYP),A
        RET
; ----------------------------------------------------------------------
; FP_TO_INT_RANGE -- boundary check for FP->int16 when the exponent is >= $90: succeed only for exactly the magnitude 32768 (yielding -32768).
;   In:        FAC = the positive magnitude with exponent >= $90 (reached from FP_TO_INT).
;   Out:       If FAC equals exactly 32768 produce the bit pattern $8000 and store it (via FP_TO_INT_1) as the integer -32768. Otherwise RET NZ, which (with the caller's pushed RAISE_OVERFLOW hook) drives the overflow error.
;   Clobbers:  A, B, C, D, E, H, L, F.
;   Algorithm: Build the constant 32768 in registers (LD BC,$9080 -> B=$90 exponent, C=$80 sign/MSB; LD DE,$0000 zero low mantissa) and FCOMP it against the FAC. A nonzero compare (RET NZ) means the magnitude differs from the boundary => overflow. On exact equality, form HL=$8000 (LD H,C=$80, LD L,D=$00) and JR FP_TO_INT_1 to store -32768.
;   Note:      In Z80 'LD BC,$9080' puts $90 in B and $80 in C; exponent $90 with a leading-1 mantissa represents 2^15 = 32768, the only in-range magnitude at this exponent.
; ----------------------------------------------------------------------
FP_TO_INT_RANGE:
        LD BC,$9080
        LD DE,$0000
        ; compare |FAC| against 32768, the only representable magnitude at exponent >= $90
        CALL FCOMP
        ; magnitude differs from 32768 => not representable; return so the overflow hook fires
        RET NZ
        ; exactly 32768: form HL=$8000 (= -32768) and store it
        LD H,C
        LD L,D
        JR FP_TO_INT_1
; ----------------------------------------------------------------------
; FN_CSNG -- CSNG(x): coerce x to single precision in the FAC.
;   In:        FAC = value; VALTYP gives its type.
;   Out:       FAC holds x in single-precision form; VALTYP = VT_SNG (=4). Raises 'Type mismatch' on a string.
;   Clobbers:  A, B, C, D, E, H, L, F.
;   Algorithm: Type-check via FRMEVL_TEST_TYPE. If already single (PO) RET unchanged. If integer (M) widen via INT_TO_SINGLE. If string (Z) error. Otherwise (double, fall-through) drop into FIX_TO_INT -- the double->single round/normalize path -- which leaves VALTYP=single.
; ----------------------------------------------------------------------
FN_CSNG:
        CALL FRMEVL_TEST_TYPE
        ; already single precision: nothing to do
        RET PO
        ; integer: widen to single
        JP M,INT_TO_SINGLE
        ; string: not a number
        JP Z,RAISE_TYPE_MISMATCH
; ----------------------------------------------------------------------
; FIX_TO_INT -- narrow a double to single precision: round the double mantissa and re-normalize as a single (the double->single step shared by CSNG's double case and CINT's double path).
;   In:        FAC = a double-precision value (exponent FAC_EXP, mantissa bytes from L_0CB0 up through FACHI).
;   Out:       FAC re-normalized as single precision; VALTYP set to VT_SNG (=4) via the SET_TYPE_DOUBLE_1+1 sub-entry.
;   Clobbers:  A, B, C, D, E, H, L, F.
;   Algorithm: Load the FAC mantissa into registers (FP_LOAD_FAC) and set VALTYP=single (CALL SET_TYPE_DOUBLE_1+1: the +1 entry runs 'LD A,$04'). If the loaded high byte B is zero the value is already in range -> RET. Otherwise unpack the hidden MSB and sign (FP_UNPACK_MSB), fetch the extension/round byte from L_0CB0 into B, and JP FP_PACK_ROUND to apply rounding and re-store the normalized single.
;   [RE]:      The inline label 'CINT body' on this routine is a MISNOMER -- it is the double->single round/normalize helper, not part of CINT's integer extraction. UNKNOWN: the exact rounding policy of the FP_PACK_ROUND tail (round-to-nearest vs truncate) is not re-derived here.
; ----------------------------------------------------------------------
FIX_TO_INT:
        CALL FP_LOAD_FAC
        ; tag the result single precision (the +1 entry runs LD A,$04 => VT_SNG)
        CALL SET_TYPE_DOUBLE_1+1
        LD A,B
        OR A
        ; high mantissa byte zero => already fits single, no rounding needed
        RET Z
        CALL FP_UNPACK_MSB
        ; fetch the low extension/round byte to round the narrowed mantissa
        LD HL,L_0CB0
        LD B,(HL)
        JP FP_PACK_ROUND
; ----------------------------------------------------------------------
; INT_TO_SINGLE -- widen the signed 16-bit integer in the FAC to a single-precision float.
;   In:        FAC integer cell ($0CB1) = the signed 16-bit value.
;   Out:       FAC = the equivalent single-precision float; VALTYP = VT_SNG (=4).
;   Clobbers:  A, B, C, D, E, H, L, F.
;   Algorithm: Load the integer from (FAC) into HL, then fall into INT_TO_SINGLE_HL which sets the single type, seeds the trial exponent $90 and normalizes via FLOAT_A_1.
; ----------------------------------------------------------------------
INT_TO_SINGLE:
        ; load the 16-bit integer from the FAC, then float it
        LD HL,(FAC)
; ----------------------------------------------------------------------
; INT_TO_SINGLE_HL -- float a signed 16-bit integer already in HL into single precision in the FAC (entry shared by INT_TO_SINGLE and callers holding the integer in HL, e.g. IADD's overflow promotion).
;   In:        HL = signed 16-bit integer.
;   Out:       FAC = single-precision float of HL; VALTYP = VT_SNG (=4).
;   Clobbers:  A, B, C, D, E, H, L, F.
;   Algorithm: Set VALTYP=single (SET_TYPE_DOUBLE_1+1 = LD A,$04). Put the integer high byte in A and low byte in D, clear E, set the trial exponent B=$90 (treating the 16-bit integer as an unnormalized mantissa scaled by 2^16), then JP FLOAT_A_1 which packs the sign and normalizes into a proper single.
;   [RE]:      Exponent $90 = bias for 2^16, so a 16-bit integer placed as the top mantissa bytes evaluates to its integer value; FLOAT_A_1 then left-justifies and adjusts the exponent down.
; ----------------------------------------------------------------------
INT_TO_SINGLE_HL:
        CALL SET_TYPE_DOUBLE_1+1
        LD A,H
        LD D,L
        LD E,$00
        ; trial exponent for a 16-bit integer mantissa; FLOAT_A_1 normalizes it down
        LD B,$90
        JP FLOAT_A_1
; ----------------------------------------------------------------------
; FN_CDBL -- CDBL(x): coerce x to double precision in the FAC.
;   In:        FAC = value; VALTYP gives its type.
;   Out:       FAC holds x in double-precision form; VALTYP = VT_DBL (=8). Raises 'Type mismatch' on a string.
;   Clobbers:  A, B, C, D, E, H, L, F.
;   Algorithm: Type-check via FRMEVL_TEST_TYPE. If already double (carry clear, RET NC) leave it. If string (Z) error. If integer (M) first widen to single (CALL M,INT_TO_SINGLE). Then fall into FP_CLEAR_EXT, which zeroes the double-precision extension mantissa bytes, and SET_TYPE_DOUBLE marks it double -- promoting the single's mantissa to the double layout by appending zero low bytes.
;   [RE]:      Clobbers includes B,C,D,E because the integer branch runs INT_TO_SINGLE (the prior spec under-listed clobbers as A,H,L,F).
; ----------------------------------------------------------------------
FN_CDBL:
        CALL FRMEVL_TEST_TYPE
        ; already double precision: done
        RET NC
        ; string: not a number
        JP Z,RAISE_TYPE_MISMATCH
        ; integer: widen to single first, then to double
        CALL M,INT_TO_SINGLE
; ----------------------------------------------------------------------
; FP_CLEAR_EXT -- zero the double-precision low/extension mantissa cells, then mark the FAC double-typed.
;   In:        FAC = a single-precision value occupying the high mantissa bytes.
;   Out:       Extension cells at FAC_DBL ($0CAD..$0CAE) and L_0CAF ($0CAF) cleared to zero; falls into SET_TYPE_DOUBLE so VALTYP = VT_DBL (=8).
;   Clobbers:  A, H, L, F.
;   Algorithm: LD HL,$0000 then store it to (FAC_DBL) and (L_0CAF) -- zeroing the low mantissa bytes used only by double precision (giving the widened value a zero fractional extension) -- then fall through to SET_TYPE_DOUBLE.
; ----------------------------------------------------------------------
FP_CLEAR_EXT:
        LD HL,$0000
        ; zero the double-precision extension mantissa bytes the single form did not use
        LD (FAC_DBL),HL
        LD (L_0CAF),HL
; ----------------------------------------------------------------------
; SET_TYPE_DOUBLE -- mark the current value double-typed (entry) / single-typed (the +1 sub-entry), via a flag-skip overlap with SET_TYPE_DOUBLE_1.
;   In:        Entered at SET_TYPE_DOUBLE for double; entered at SET_TYPE_DOUBLE_1+1 ($5030) for single.
;   Out:       VALTYP ($0B14) = VT_DBL (=8) via the double entry, or VT_SNG (=4) via the +1 entry. RET (after JP SET_TYPE_INTEGER_1).
;   Clobbers:  A, F (and BC when the cover instruction at SET_TYPE_DOUBLE_1 actually executes).
;   Algorithm: LD A,$08, then the following 'LD BC,$043E' (opcode 01 3E 04) swallows the 3E 04 bytes as its immediate, so the double entry keeps A=$08 and reaches JP SET_TYPE_INTEGER_1 to store 8. Callers needing single enter at SET_TYPE_DOUBLE_1+1, where those same 3E 04 bytes execute as 'LD A,$04', so the stored type is 4. Both paths converge on the shared LD (VALTYP),A. (VALTYP = storage width in bytes: int=2, string=3, single=4, double=8.)
; ----------------------------------------------------------------------
SET_TYPE_DOUBLE:
        ; double entry: VALTYP=8 (the LD BC below hides the LD A,$04 that the single sub-entry uses)
        LD A,$08
; ----------------------------------------------------------------------
; SET_TYPE_DOUBLE_1 -- the LD BC cover whose +1 sub-entry ($5030) is the single-precision type-setter (see SET_TYPE_DOUBLE).
;   In:        Reached as a fall-through from SET_TYPE_DOUBLE (then BC is scratch), OR entered at +1 as 'LD A,$04' to select single.
;   Out:       JP SET_TYPE_INTEGER_1 with A = the type code in flight ($08 via fall-through, $04 via the +1 entry); stores VALTYP.
;   Clobbers:  BC (fall-through) or A (the +1 entry), F.
;   Algorithm: The bytes 01 3E 04 are 'LD BC,$043E' at the label (consuming 3E 04 harmlessly) but 'LD A,$04' when entered at +1. Either way control reaches JP SET_TYPE_INTEGER_1 (the shared 'LD (VALTYP),A; RET').
; ----------------------------------------------------------------------
SET_TYPE_DOUBLE_1:
        LD BC,$043E
        JP SET_TYPE_INTEGER_1
; ----------------------------------------------------------------------
; REQUIRE_STRING -- assert that the current FAC value is a STRING; raise 'Type mismatch' for any numeric type. (CONFIRMED at both call sites: LINE INPUT into a string var, and the first arg of LEFT$/RIGHT$/MID$.)
;   In:        FAC value with VALTYP ($0B14) set.
;   Out:       RET (with Z set) when the value is a string (VALTYP==3). Raises 'Type mismatch' (JP RAISE_TYPE_MISMATCH) for every numeric type (int/single/double).
;   Clobbers:  A, F.
;   Algorithm: CALL FRMEVL_TEST_TYPE (which sets Z iff VALTYP==3, i.e. string, since A=VALTYP-3); RET Z. Any non-string falls through to JP RAISE_TYPE_MISMATCH. This is a 'string required here' guard.
;   [RE]:      The routine NAME 'REQUIRE_STRING' and the prior inline comment ('Type-check requiring a numeric value') are BOTH wrong/inverted -- the routine demands a STRING and rejects numbers. A rename to REQUIRE_STRING (or ASSERT_STRING_OPERAND) would reflect the verified behavior.
; ----------------------------------------------------------------------
REQUIRE_STRING:
        CALL FRMEVL_TEST_TYPE
        ; string value (VALTYP=3 => Z): accepted, return
        RET Z
        ; any numeric type: reject with Type mismatch
        JP RAISE_TYPE_MISMATCH
; ----------------------------------------------------------------------
; FP_SHIFT_MANTISSA -- load the FAC mantissa and shift it right by a bit count derived from A, producing a right-aligned magnitude with rounding (used to extract the integer part for FP->int and to align an addend in FADD).
;   In:        A = the shift seed (also copied into B,C and then D,E). FAC = the value whose mantissa is shifted (exponent at FAC_EXP). HL = a caller pointer (saved/restored).
;   Out:       The mantissa right-shifted with rounding applied; on a negative value the result is two's-complemented (FCOMPL). The shifted magnitude is left in the working registers (the FP->int callers then EX DE,HL to get HL). HL restored on exit.
;   Clobbers:  A, B, C, D, E, H, L, F.
;   Algorithm: Seed B=C=A (entry) then D=E=A; if A==0 there is nothing to shift -> RET. Save HL, load the FAC mantissa (FP_LOAD_FAC) and unpack the hidden MSB + sign (FP_UNPACK_MSB, returning the sign-fold in A); XOR (HL) to fold in the sign and stash it in H. If negative (M) adjust the counter with DEC_DE_WITH_BORROW. Compute the shift distance ($98 - B) and shift the mantissa right that many places (MANT_SHIFT_BYTES). RLA tests the bit shifted out: on carry round up (FADD_ROUND_CARRY); set B=0; then if a final carry remains two's-complement the result (FCOMPL). Restore HL and RET.
;   [RE]:      UNKNOWN: the exact register pairing of the shifted output as consumed per caller (FN_CINT/FP_TO_INT vs FADD) was not re-derived; only the FP->int 'EX DE,HL then store' usage was followed here.
; ----------------------------------------------------------------------
FP_SHIFT_MANTISSA:
        LD B,A
        LD C,A
FP_SHIFT_MANTISSA_1:
        LD D,A
        LD E,A
        OR A
        ; zero shift amount: mantissa already aligned, nothing to do
        RET Z
        PUSH HL
        ; pull the FAC mantissa into registers to shift it
        CALL FP_LOAD_FAC
        CALL FP_UNPACK_MSB
        XOR (HL)
        LD H,A
        ; negative value: adjust the shift counter with borrow for the two's-complement form
        CALL M,DEC_DE_WITH_BORROW
        LD A,$98
        SUB B
        ; shift the mantissa right by ($98 - count) places to align it
        CALL MANT_SHIFT_BYTES
        LD A,H
        RLA
        ; bit shifted out was set: round the result up
        CALL C,FADD_ROUND_CARRY
        LD B,$00
        ; restore the negative sign by two's-complementing the shifted magnitude
        CALL C,FCOMPL
        POP HL
        RET
; ----------------------------------------------------------------------
; DEC_DE_WITH_BORROW -- decrement DE and, on the borrow boundary, fall THROUGH into DEC_BC (multi-byte counter decrement for the shift loop).
;   In:        DE (and BC) = the shift/round counter.
;   Out:       DE decremented. If DE did NOT wrap (D AND E != $FF) RET NZ. If DE just became $FFFF (D AND E == $FF, so INC A wraps to 0 / Z) it falls through into DEC_BC, also decrementing BC, then RETs.
;   Clobbers:  A, D, E, F (and BC on the borrow path).
;   Algorithm: DEC DE; LD A,D; AND E; INC A; RET NZ. The 'RET NZ' returns for the common case; only when both D and E are $FF (the borrow boundary) does control fall into DEC_BC. The prior spec's claim that it merely 'reports' the boundary understated this -- it ACTS on the borrow by falling into DEC_BC.
;   [RE]:      The borrow detection (D AND E == $FF) only catches DE==$FFFF, i.e. DE wrapping from $0000; this is the post-DEC test.
; ----------------------------------------------------------------------
DEC_DE_WITH_BORROW:
        DEC DE
        LD A,D
        AND E
        INC A
        RET NZ
; ----------------------------------------------------------------------
; DEC_BC -- decrement BC and return (the high half of the shift/round counter; also the fall-through target of DEC_DE_WITH_BORROW's borrow path, and reached directly elsewhere, e.g. LIST's ELSE colon back-up).
;   In:        BC = counter.
;   Out:       BC decremented. RET.
;   Clobbers:  BC.
;   Algorithm: DEC BC; RET.
; ----------------------------------------------------------------------
DEC_BC:
        DEC BC
        RET
; ----------------------------------------------------------------------
; FN_FIX -- FIX(x) library function (function token $1E): truncate the FAC toward zero to an integer-valued float.
;   In:        FAC holds the argument; VALTYP ($0B14) gives its type. Reached via FUNC_DISPATCH_TBL slot $01EC (= base $01B2 + 2*(TOK_FIX-1), TOK_FIX=$1E).
;   Out:       FAC = trunc(x), same numeric type as the input (int returned unchanged; single/double floored toward zero).
;   Clobbers:  A, HL, DE, BC, F (through the floor worker FN_INT_FLOOR, FP_SIGN, FP_NEG and FP_NEGATE_CHECKED).
;   Algorithm: If VALTYP=VT_INT, return unchanged (RET M). Otherwise FIX(x)=sign(x)*floor(|x|): take FP_SIGN; for x>=0 call the floor worker FN_INT_FLOOR directly (for non-negative values floor == truncate-toward-zero); for x<0 negate the FAC (FP_NEG), floor |x| via FN_INT_FLOOR, then re-apply the sign through FP_NEGATE_CHECKED. This differs from INT() which floors toward minus infinity for all signs.
; ----------------------------------------------------------------------
FN_FIX:
        CALL FRMEVL_TEST_TYPE
        ; VALTYP=VT_INT: FIX of an integer is itself, return unchanged
        RET M
        ; branch on the sign of x: FIX(x)=sign(x)*floor(|x|), so handle x>=0 and x<0 separately
        CALL FP_SIGN
        ; x>=0: floor directly (for non-negative values floor == truncate toward zero)
        JP P,FN_INT_FLOOR
        ; x<0: work on |x| -- floor the magnitude, then restore the negative sign below
        CALL FP_NEG
        CALL FN_INT_FLOOR
        ; re-apply the negative sign to floor(|x|), yielding trunc(x)
        JP FP_NEGATE_CHECKED
; ----------------------------------------------------------------------
; FN_INT_FLOOR (file label FN_INT_FLOOR -- MISLABELED; this is the BASIC INT() handler) -- floor the FAC toward minus infinity, yielding an integer-valued float.
;   In:        FAC holds a numeric value; VALTYP selects the path. Reached via FUNC_DISPATCH_TBL slot $01BA for the INT token, and called twice by FN_FIX as its magnitude-floor worker.
;   Out:       FAC = floor(value) as a float of the same type. VALTYP=VT_INT returns unchanged; single/double have their fractional bits dropped and are re-normalized.
;   Clobbers:  A, HL, DE, BC, F.
;   Algorithm: Type-dispatch on FRMEVL_TEST_TYPE. Integer (sign set) -> RET unchanged. Double (carry clear) -> FIX_SCALE_1 (the double-precision floor path). String (Z) -> Type mismatch. Single (the remaining case) -> CALL FP_TO_INT to align the mantissa, then continue into FIX_SCALE which drops the fraction (exponent forced to $98) and re-rounds via FADD_COMBINE. [RE] Whether the single case always reaches FIX_SCALE is uncertain: FP_TO_INT contains a POP DE (FP_TO_INT_1) that can consume the CALL's return address on the exponent<$90 sub-path, so 'CALL FP_TO_INT then fall into FIX_SCALE' is not fully confirmed for every single-precision input.
; ----------------------------------------------------------------------
FN_INT_FLOOR:
        CALL FRMEVL_TEST_TYPE
        ; VALTYP=VT_INT: an integer is already integral, return unchanged
        RET M
        ; double precision (carry clear from FRMEVL_TEST_TYPE): take the double-precision floor path
        JR NC,FIX_SCALE_1
        ; string argument is not numeric: Type mismatch
        JP Z,RAISE_TYPE_MISMATCH
        ; single: align the mantissa to the integer field before the fraction-dropping scale below
        CALL FP_TO_INT
; ----------------------------------------------------------------------
; FIX_SCALE -- denormalize a single-precision FAC to the integer position and re-round; the floor mantissa-scaler.
;   In:        FAC = single-precision value; $0CB4 = its binary exponent.
;   Out:       FAC = value floored to integral, exponent forced to $98; A = FAC low byte ($0CB1). If the exponent is already >= $98 the value has no fraction and it returns unchanged.
;   Clobbers:  A, HL, DE, BC, F.
;   Algorithm: If exponent >= $98 the value has no fractional bits -> return (A loaded from FAC low). Otherwise shift the mantissa right by the exponent via FP_SHIFT_MANTISSA so the fraction falls off, force the exponent to $98, then fold the shifted-out rounding bit back (LD A,C / RLA / FADD_COMBINE) to renormalize. Also reached directly by the transcendental functions (EXP at $5D01, the SIN/COS path at $5E4C, and the SQR-area helper at $5CC4) to extract the integer part of a scaled argument.
; ----------------------------------------------------------------------
FIX_SCALE:
        LD HL,FAC_EXP
        LD A,(HL)
        ; exponent >= $98 means no fractional bits remain: already an integral float
        CP $98
        LD A,(FAC)
        RET NC
        LD A,(HL)
        ; shift the mantissa down by the exponent so the fractional bits are discarded
        CALL FP_SHIFT_MANTISSA
        ; pin the exponent to the integer-aligned scale after the shift
        LD (HL),$98
        LD A,E
        PUSH AF
        LD A,C
        RLA
        ; fold the rounding/carry bit back in and renormalize the floored result
        CALL FADD_COMBINE
        POP AF
        RET
FIX_SCALE_1:
        LD HL,FAC_EXP
        LD A,(HL)
        CP $90
        JR NZ,FIX_SCALE_4
        LD C,A
        DEC HL
        LD A,(HL)
        XOR $80
        LD B,$06
FIX_SCALE_2:
        DEC HL
        OR (HL)
        DEC B
        JR NZ,FIX_SCALE_2
        OR A
        LD HL,$8000
        JP NZ,FIX_SCALE_3
        CALL FP_STORE_FAC_INT
        JP FN_CDBL
FIX_SCALE_3:
        LD A,C
FIX_SCALE_4:
        OR A
        RET Z
        CP $B8
        RET NC
; ----------------------------------------------------------------------
; FIX_DENORM -- denormalize a DOUBLE-precision FAC to the integer position; the double-precision floor/round helper used by FOUT.
;   In:        FAC = double value (8-byte mantissa $0CAC..$0CB3, exponent $0CB4); A on entry = a borrow/round flag (saved by PUSH AF) controlling the trailing DADD_NORMALIZE fixup.
;   Out:       FAC = value aligned so the integer part sits at exponent $B8; guard cell $0CAC cleared. Returns via RET NC, or JP DADD_NORMALIZE to finish renormalizing when a carry/borrow is pending.
;   Clobbers:  A, HL, BC, DE, F.
;   Algorithm: Load the FAC mantissa, set the hidden MSB and capture the sign (FP_UNPACK_MSB), force the working exponent to $B8, and if the value is negative pre-borrow the low extension bytes (DBL_EXT_DEC). Compute the shift count $B8 - exponent and right-align the 8-byte mantissa with DP_SHIFT_RIGHT_N, applying DP_ROUND_CARRY when the saved sign demands rounding. Clear the low guard byte $0CAC; on a pending carry tail-call DADD_NORMALIZE to renormalize. Called by FOUT ($5B0F) when formatting a double for printing (after adding 0.5 for round-to-nearest).
; ----------------------------------------------------------------------
FIX_DENORM:
        PUSH AF
        CALL FP_LOAD_FAC
        CALL FP_UNPACK_MSB
        XOR (HL)
        DEC HL
        ; target the double integer-aligned scale (exponent $B8)
        LD (HL),$B8
        PUSH AF
        DEC HL
        LD (HL),C
        ; negative value: pre-borrow the low extension bytes before the down-shift so two's-complement rounding is correct
        CALL M,DBL_EXT_DEC
        LD A,(FACHI)
        LD C,A
        LD HL,FACHI
        LD A,$B8
        SUB B
        ; right-align the 8-byte mantissa by ($B8 - exponent) so the fraction is shifted out
        CALL DP_SHIFT_RIGHT_N
        POP AF
        ; apply round-half (the saved sign/round flag) into the now-aligned mantissa
        CALL M,DP_ROUND_CARRY
        XOR A
        ; clear the low guard byte after the shift
        LD (L_0CAC),A
        POP AF
        RET NC
        JP DADD_NORMALIZE
; ----------------------------------------------------------------------
; DBL_EXT_DEC -- propagate a two's-complement borrow downward through the FAC double-precision extension bytes.
;   In:        The FAC low extension bytes starting at $0CAD (the bytes below the visible mantissa).
;   Out:       The extension decremented with borrow rippled up until a non-$00 byte absorbs it.
;   Clobbers:  A, HL, F.
;   Algorithm: Starting at $0CAD, decrement each byte; while a byte was $00 (so it wrapped to $FF and the borrow continues) advance to the next higher byte and repeat. Stop at the first byte that was non-zero. This is the low-end borrow of negating/rounding the double mantissa, used by FIX_DENORM for negative values.
; ----------------------------------------------------------------------
DBL_EXT_DEC:
        LD HL,FAC_DBL
DBL_EXT_DEC_1:
        LD A,(HL)
        DEC (HL)
        OR A
        INC HL
        ; the byte was $00 (wrapped to $FF): borrow continues into the next higher extension byte
        JR Z,DBL_EXT_DEC_1
        RET
; ----------------------------------------------------------------------
; ARRAY_INDEX_MUL16 -- unsigned 16x16->16 multiply for array subscript/offset math, with overflow trapped as 'Subscript out of range'.
;   In:        DE = multiplier (the running index accumulator carried across dimensions); BC = multiplicand (the current dimension size). HL is NOT an operand -- it is saved and restored (callers in PTRGET hold a table pointer in HL across the call).
;   Out:       DE = (DE * BC) mod 2^16. HL preserved. On any 16-bit overflow it does NOT return: JP PTRGET_SEARCH_27 to raise 'Subscript out of range' (error 9).
;   Clobbers:  DE, A, F (HL saved/restored; BC unchanged).
;   Algorithm: Save HL, zero the product in HL, then for 16 iterations shift the product left (ADD HL,HL), shift the multiplier DE left to test its top bit, and when that bit is set add the multiplicand BC into the product. Every shift and add is overflow-checked (JP C,PTRGET_SEARCH_27) because array offsets must fit in 16 bits. Short-circuits to product 0 if BC is zero. On exit EX DE,HL moves the product into DE and HL is restored. Used by PTRGET array code ($61BB/$61FD) to size and index multi-dimensional arrays.
; ----------------------------------------------------------------------
ARRAY_INDEX_MUL16:
        PUSH HL
        LD HL,$0000
        LD A,B
        OR C
        ; multiplicand BC is zero: the product is zero, skip the multiply loop
        JR Z,ARRAY_INDEX_MUL16_3
        LD A,$10
ARRAY_INDEX_MUL16_1:
        ADD HL,HL
        JP C,PTRGET_SEARCH_27
        EX DE,HL
        ADD HL,HL
        EX DE,HL
        JR NC,ARRAY_INDEX_MUL16_2
        ; current multiplier bit set: add the multiplicand BC into the running product
        ADD HL,BC
        ; overflow past 16 bits: the subscript/offset is out of range (error 9)
        JP C,PTRGET_SEARCH_27
ARRAY_INDEX_MUL16_2:
        DEC A
        JR NZ,ARRAY_INDEX_MUL16_1
ARRAY_INDEX_MUL16_3:
        EX DE,HL
        POP HL
        RET
; ----------------------------------------------------------------------
; INT_SIGNEXT_SUB -- 16-bit signed integer SUBTRACT operator (DE - HL); the '-' arm of the integer arithmetic dispatch band.
;   In:        DE = left operand, HL = right operand (both already coerced to int16 by FRMEVL_INT_OP_HANDLER).
;   Out:       FAC = DE - HL as a signed integer (VALTYP=VT_INT), or promoted to single precision on overflow. Joins IADD's combine/overflow logic at IADD_1.
;   Clobbers:  A, HL, BC, DE, F.
;   Algorithm: Compute DE - HL == DE + (-HL) reusing the integer adder. Sign-extend HL into B (LD A,H/RLA/SBC A,A), negate HL via INT_NEG_STORE (leaves -HL in HL and stores it, and sets C=0), then form A = C - B with borrow (the sign extension of the negated right operand) and JR into IADD_1, which adds DE with full signed-overflow detection and float fallback.
; ----------------------------------------------------------------------
INT_SIGNEXT_SUB:
        LD A,H
        RLA
        SBC A,A
        LD B,A
        ; negate the right operand so the subtract becomes DE + (-HL) and can reuse the integer adder
        CALL INT_NEG_STORE
        LD A,C
        SBC A,B
        ; enter the shared add/overflow combine, passing the negated right operand's sign extension in B
        JR IADD_1
; ----------------------------------------------------------------------
; IADD -- 16-bit signed integer ADD operator (HL + DE); the '+' arm of the integer arithmetic dispatch band.
;   In:        HL = one operand, DE = the other (both int16). For the subtract entry IADD_1, A already holds the right operand's sign extension (loaded into B).
;   Out:       FAC = HL + DE as a signed integer (VALTYP=VT_INT) when it fits; on signed overflow both operands are promoted to single precision and the add finishes in floating point (via FIN_FLOAT_RETURN), leaving a single-precision FAC.
;   Clobbers:  A, HL, DE, BC, F.
;   Algorithm: Sign-extend both operands into a 17th bit (LD A,H/RLA/SBC A,A gives 0 or $FF), add the low 16 bits (ADD HL,DE) and the sign bits (ADC A,B). Detect signed overflow by comparing the carry-out sign with the result's top bit (RRCA / XOR H): if they agree (JP P) the 16-bit result is valid -> store via FP_TO_INT_1. If they disagree, overflow occurred: float the right operand (EX DE,HL / INT_TO_SINGLE_HL), recover and float the left operand (FLOAT_FROM_INT), and continue through the floating-point add at FIN_FLOAT_RETURN.
; ----------------------------------------------------------------------
IADD:
        LD A,H
        RLA
        SBC A,A
IADD_1:
        LD B,A
        PUSH HL
        LD A,D
        RLA
        SBC A,A
        ; add the two 16-bit operands; the following ADC folds in the sign-extension bits
        ADD HL,DE
        ADC A,B
        RRCA
        XOR H
        ; no signed overflow (carry-out sign matches result sign): store the 16-bit integer result
        JP P,FP_TO_INT_1
        PUSH BC
        EX DE,HL
        CALL INT_TO_SINGLE_HL
        POP AF
        POP HL
        CALL FAC_PUSH
        EX DE,HL
        ; overflow: float the left operand; both operands are now single precision and the add finishes in floating point
        CALL FLOAT_FROM_INT
        JP FIN_FLOAT_RETURN
; ----------------------------------------------------------------------
; IMUL -- 16-bit signed integer MULTIPLY operator; the '*' arm of the integer arithmetic dispatch band.
;   In:        HL and DE = the two int16 factors. INT_SETSIGN_NEG captures the combined result sign and makes the factors non-negative.
;   Out:       FAC = HL * DE as a signed integer (VALTYP=VT_INT) when it fits in 16 bits; on overflow both factors are promoted to single precision and the multiply is finished by the FP multiplier (FMUL).
;   Clobbers:  A, HL, DE, BC, F.
;   Algorithm: If HL is zero, the product is the integer 0 (JP FP_STORE_FAC_INT with HL=0). Otherwise sign-normalize via INT_SETSIGN_NEG (B = combined sign, operands made non-negative), move the multiplicand into BC, and run a 16-iteration shift-and-add accumulating the product into HL. Any carry out of the 16-bit product during the shift/add is an overflow and diverts to IMUL_5+1 (the float-promotion path, the +1 being a flag-skip cover-byte idiom). When the loop completes, IMULDIV_FINISH applies the sign and either stores the integer or promotes to single precision.
; ----------------------------------------------------------------------
IMUL:
        LD A,H
        OR L
        ; HL factor is zero: product is integer 0 (HL already holds 0)
        JP Z,FP_STORE_FAC_INT
        PUSH HL
        PUSH DE
        ; record the result sign and make both factors non-negative for an unsigned shift-add
        CALL INT_SETSIGN_NEG
        PUSH BC
        LD B,H
        LD C,L
        LD HL,$0000
        LD A,$10
IMUL_1:
        ADD HL,HL
        ; product overflowed 16 bits: bail to the float-promotion path
        JR C,IMUL_5+1
        EX DE,HL
        ADD HL,HL
        EX DE,HL
        JR NC,IMUL_2
        ; current multiplier bit set: add the multiplicand into the running product
        ADD HL,BC
        JP C,IMUL_5+1
IMUL_2:
        DEC A
        JR NZ,IMUL_1
        POP BC
        POP DE
; ----------------------------------------------------------------------
; IMULDIV_FINISH -- shared tail of integer multiply and divide: apply the sign and store the result, promoting to single precision on overflow.
;   In:        HL = the unsigned 16-bit result of the integer multiply or divide; B = the desired result sign (high bit); the partner value (DE for multiply, the remainder/quotient for divide) is on the stack.
;   Out:       FAC = the signed integer result (VALTYP=VT_INT) when it fits, else the operands are floated and re-dispatched to FMUL / the FP store path.
;   Clobbers:  A, HL, DE, BC, F.
;   Algorithm: If the result high bit is clear (positive, fits as a non-negative int16) pop the partner value, take the sign in B and store via INT_ABS_STORE_1 (negating if the sign says so). If the high bit is set, test the magnitude: $8000 with a clear low byte is the exact INT_MIN boundary, handled by IMULDIV_FLOAT_FALLBACK; anything larger overflowed int16 and is promoted to single precision (IMUL_5/IMUL_6 -> FMUL).
; ----------------------------------------------------------------------
IMULDIV_FINISH:
        LD A,H
        OR A
        ; top bit set: result may not fit a signed 16-bit int, test for the $8000 boundary vs true overflow
        JP M,IMUL_4
        POP DE
        LD A,B
        ; fits: store the magnitude in HL applying the recorded sign (B)
        JP INT_ABS_STORE_1
IMUL_4:
        XOR $80
        OR L
        JR Z,IMULDIV_FLOAT_FALLBACK
        EX DE,HL
; [RE] Flag-skip stack cleanup: $5176 LD BC,$E1C1 -- the C1 E1 operand bytes double as POP BC; POP HL. On integer-mul overflow, JR/JP C,IMUL_5+1 ($5156/$515E) enters $5177 to pop the pre-loop saves (PUSH BC $514D, PUSH HL $5148); the IMUL_4 fall-through reaches $5176 with the stack already balanced and skips them via the junk LD BC. Both converge at $5179.
IMUL_5:
        LD BC,$E1C1
        CALL INT_TO_SINGLE_HL
        POP HL
        CALL FAC_PUSH
        CALL INT_TO_SINGLE_HL
IMUL_6:
        POP BC
        POP DE
        JP FMUL
; ----------------------------------------------------------------------
; IMULDIV_FLOAT_FALLBACK -- handle the boundary case for signed integer mul/div whose magnitude is exactly $8000.
;   In:        HL = $8000 (the magnitude landed on the int16 boundary); B = result sign; DE = partner operand; stack carries the saved registers from the operator.
;   Out:       If the sign is negative, $8000 IS the valid representation of INT_MIN (-32768) -> store as integer (FP_STORE_FAC_INT). If positive, +32768 does not fit int16, so float HL (INT_TO_SINGLE_HL) and continue via FP_NEG.
;   Clobbers:  A, HL, DE, BC, F.
;   Algorithm: Inspect the sign byte B. Negative -> the two's-complement $8000 already encodes -32768 exactly, store it as the integer result. Positive -> +32768 overflows the signed range, so promote to single precision and finish in floating point.
; ----------------------------------------------------------------------
IMULDIV_FLOAT_FALLBACK:
        LD A,B
        OR A
        POP BC
        ; negative sign: $8000 is exactly INT_MIN (-32768), store as an integer
        JP M,FP_STORE_FAC_INT
        PUSH DE
        ; positive: +32768 won't fit int16, promote to single precision
        CALL INT_TO_SINGLE_HL
        POP DE
        JP FP_NEG
; ----------------------------------------------------------------------
; INT_DIV_KERNEL -- signed 16-bit divide/remainder kernel (restoring shift-subtract); the MOD operator entry (opcode $7B) and the quotient source for INT_DIV_ROUND.
;   In:        DE = dividend, HL = divisor (both int16, from FRMEVL_INT_OP_HANDLER).
;   Out:       Produces both quotient and remainder; the sign-corrected result is stored to the FAC as an integer via IMULDIV_FINISH. [RE] The D:E pair at exit carries the value used by INT_DIV_ROUND to recover the quotient; the exact quotient-vs-remainder register assignment is inferred from the restoring-division structure, not independently confirmed by emulation.
;   Clobbers:  A, HL, DE, BC, F.
;   Algorithm: Trap a zero divisor (RAISE_DIVISION_BY_ZERO). Sign-normalize through INT_SETSIGN_NEG (B = combined sign; operands made non-negative), form -divisor in BC, and run a 17-iteration restoring division: each step trial-adds -divisor to the running remainder in HL, shifts the dividend/quotient pair (D:E) and remainder (H:L) left by one, and records the success bit as the next quotient bit. On exit (EX DE,HL) the sign is reapplied and the result stored (IMULDIV_FINISH).
; ----------------------------------------------------------------------
INT_DIV_KERNEL:
        LD A,H
        OR L
        ; divisor (HL) is zero: Division by zero error
        JP Z,RAISE_DIVISION_BY_ZERO
        ; record the result sign and make both operands non-negative for the unsigned division loop
        CALL INT_SETSIGN_NEG
        PUSH BC
        EX DE,HL
        ; form -divisor in HL (then BC) so the inner loop subtracts by adding (ADD HL,BC)
        CALL INT_NEG_STORE
        LD B,H
        LD C,L
        LD HL,$0000
        ; 17 iterations: 16 quotient bits plus the initial alignment step of the restoring divide
        LD A,$11
        PUSH AF
        OR A
        JR INT_DIV_KERNEL_3
INT_DIV_KERNEL_1:
        PUSH AF
        PUSH HL
        ; trial-subtract the divisor from the running remainder (BC holds -divisor)
        ADD HL,BC
        JR NC,INT_DIV_KERNEL_2+1
        POP AF
        SCF
; [RE] Flag-skip stack balance: $51B5 LD A,$E1 -- the $E1 immediate doubles as POP HL. After ADD HL,BC: no-carry takes JR NC,INT_DIV_KERNEL_2+1 ($51B1) to $51B6 = POP HL (restore the pre-add HL); the carry path consumed that saved HL via POP AF/SCF ($51B3-$51B4) and must skip the POP, so the junk LD A,$E1 swallows the E1. Each path pops the single $51AF push; both fall into $51B7 LD A,E.
INT_DIV_KERNEL_2:
        LD A,$E1
INT_DIV_KERNEL_3:
        LD A,E
        RLA
        LD E,A
        LD A,D
        RLA
        LD D,A
        LD A,L
        RLA
        LD L,A
        LD A,H
        RLA
        LD H,A
        POP AF
        DEC A
        JR NZ,INT_DIV_KERNEL_1
        EX DE,HL
        POP BC
        PUSH DE
        ; reapply the sign and store the integer result (shared with the multiply tail)
        JP IMULDIV_FINISH
; ----------------------------------------------------------------------
; INT_SETSIGN_NEG -- sign prologue for signed integer multiply/divide: capture the combined result sign and make HL non-negative.
;   In:        HL and DE = the two signed operands.
;   Out:       B = combined sign byte (high bit = XOR of the two operand signs); HL = |original HL| stored to the FAC; then EX DE,HL leaves the partner operand (original DE) in HL for the caller.
;   Clobbers:  A, B, HL, DE, F.
;   Algorithm: B = H XOR D captures whether the product/quotient is negative (top bit). Take |HL| via INT_ABS_STORE (stores the magnitude, negating if HL<0), then EX DE,HL so the partner operand is now in HL ready for its own abs/setup. The magnitude operands let the mul/div loops run unsigned; B reapplies the sign at the end.
; ----------------------------------------------------------------------
INT_SETSIGN_NEG:
        LD A,H
        ; combined result sign = sign(HL) XOR sign(DE); top bit of B carries it
        XOR D
        LD B,A
        ; replace HL with its magnitude so the arithmetic loop is unsigned
        CALL INT_ABS_STORE
        EX DE,HL
; ----------------------------------------------------------------------
; INT_ABS_STORE -- store |HL| into the integer FAC: pass through if HL>=0, else negate first.
;   In:        HL = signed 16-bit value. INT_ABS_STORE_1 is the entry when the sign test is already in A (mul/div pass the sign byte B in A there).
;   Out:       FAC = signed integer result; VALTYP=VT_INT. For a non-negative value HL is stored as-is; for a negative one the two's-complement negation is stored.
;   Clobbers:  A, HL, C, F.
;   Algorithm: Test the high byte's sign (OR A). If non-negative, JP FP_STORE_FAC_INT to store HL unchanged. If negative, fall into INT_NEG_STORE to negate then store. Used both standalone (absolute store) and as the sign-reapply step of integer multiply/divide via the INT_ABS_STORE_1 entry.
; ----------------------------------------------------------------------
INT_ABS_STORE:
        LD A,H
INT_ABS_STORE_1:
        OR A
        ; non-negative: store the value directly as a signed integer
        JP P,FP_STORE_FAC_INT
; ----------------------------------------------------------------------
; INT_NEG_STORE -- two's-complement negate the 16-bit integer in HL, then store it to the integer FAC.
;   In:        HL = signed 16-bit value to negate.
;   Out:       HL = -HL (two's complement); C = 0; FAC = that value as an integer (VALTYP=VT_INT) via FP_STORE_FAC_INT.
;   Clobbers:  A, HL, C, F.
;   Algorithm: C := 0, then 0 - L into L and 0 - H with borrow into H (16-bit negate), and tail-store through FP_STORE_FAC_INT. Note $8000 negates to itself (the unrepresentable INT_MIN); callers (INT_NEGATE_FAC) check for that sentinel separately.
; ----------------------------------------------------------------------
INT_NEG_STORE:
        XOR A
        LD C,A
        ; 16-bit two's-complement negate: 0-L low, then 0-H with borrow
        SUB L
        LD L,A
        LD A,C
        SBC A,H
        LD H,A
        JP FP_STORE_FAC_INT
; ----------------------------------------------------------------------
; INT_NEGATE_FAC -- unary negate of the integer FAC, promoting to single precision only at the INT_MIN boundary.
;   In:        FAC ($0CB1) holds a 16-bit signed integer (VALTYP=VT_INT). Reached from FP_NEGATE_CHECKED for the integer case of unary minus.
;   Out:       FAC = -value as an integer when representable (returns NZ). If value == $8000 (-32768), -(-32768) is not an int16, so it falls into INT_TO_SNG to return +32768 as a single.
;   Clobbers:  A, HL, C, F.
;   Algorithm: Load HL from the FAC, negate-and-store (INT_NEG_STORE). Detect the unrepresentable result: XOR $80 / OR L tests whether the negated high byte is $80 and low byte $00 (i.e. result == $8000). If not, return (RET NZ). If it is the boundary, drop into INT_TO_SNG to promote +32768 to single precision.
; ----------------------------------------------------------------------
INT_NEGATE_FAC:
        LD HL,(FAC)
        CALL INT_NEG_STORE
        LD A,H
        ; test for the $8000 (INT_MIN) result: negating -32768 overflows int16
        XOR $80
        OR L
        ; ordinary case: the negated integer is representable, done
        RET NZ
; ----------------------------------------------------------------------
; INT_TO_SNG -- promote the 16-bit signed integer currently in HL to a single-precision float in the FAC.
;   In:        HL = signed 16-bit integer.
;   Out:       FAC = HL as a single-precision MBF float; VALTYP set to VT_SNG ($04). Falls into FLOAT_FROM_INT.
;   Clobbers:  A, B, DE, HL, F.
;   Algorithm: Move HL into DE (the mantissa source for the float builder), set VALTYP=VT_SNG via SET_TYPE_DOUBLE_1+1 (the +1 entry runs the cover byte as LD A,$04, selecting single not double), clear A, and fall into FLOAT_FROM_INT to build the float with the integer-aligned exponent. Reached when an integer overflows its type (INT_NEGATE_FAC boundary, line-number-to-float, FN_FRE difference) and must become a float.
; ----------------------------------------------------------------------
INT_TO_SNG:
        EX DE,HL
        ; set VALTYP=VT_SNG (the +1 entry runs the LD A,$04 cover byte, selecting single not double)
        CALL SET_TYPE_DOUBLE_1+1
        XOR A
; ----------------------------------------------------------------------
; FLOAT_FROM_INT -- build a single-precision MBF float in the FAC from a signed integer, with the integer-aligned exponent.
;   In:        DE = the integer mantissa source; A = the additional low/rounding byte (0 from INT_TO_SNG); the magnitude already placed for normalization.
;   Out:       FAC = the value as a single-precision float (normalized and packed by the FP path at FLOAT_A_1).
;   Clobbers:  A, B, C, HL, DE, F.
;   Algorithm: Load the binary exponent $98 (the integer-aligned scale) into B and jump into the shared float normalize/pack core FLOAT_A_1, which writes the exponent, sets the hidden mantissa bit, applies the sign, and renormalizes via FADD_COMBINE. This is the integer->single conversion's final stage; INT_TO_SNG sets the type and falls in here, and IADD's overflow path calls it directly.
; ----------------------------------------------------------------------
FLOAT_FROM_INT:
        ; exponent $98 = the integer-aligned scale; the normalizer shifts down to the true magnitude
        LD B,$98
        JP FLOAT_A_1
; ----------------------------------------------------------------------
; INT_DIV_ROUND -- 16-bit signed integer DIVIDE operator ('\', opcode $7A): compute the quotient and store it as an integer.
;   In:        DE = dividend, HL = divisor (int16, from FRMEVL_INT_OP_HANDLER).
;   Out:       FAC = the signed integer quotient DE \ HL (VALTYP=VT_INT), with the correct sign applied.
;   Clobbers:  A, HL, DE, BC, F.
;   Algorithm: PUSH DE, run the shared divide kernel (INT_DIV_KERNEL) which performs the restoring division. [RE] On return the accumulated quotient is in the D:E pair; recover it by shifting D:E right one bit (XOR A/ADD A,D/RRA -> H; LD A,E/RRA -> L) to undo the kernel's trailing shift, mark the type integer (SET_TYPE_INTEGER), and store with sign through INT_ABS_STORE_1. The companion MOD operator enters INT_DIV_KERNEL directly to keep the remainder instead. The one-bit right-shift accounting is inferred from the kernel's 17-iteration restoring-division structure, not independently verified by emulation.
; ----------------------------------------------------------------------
INT_DIV_ROUND:
        PUSH DE
        ; run the restoring division; [RE] the quotient accumulates in the D:E pair
        CALL INT_DIV_KERNEL
        XOR A
        ; recover the quotient: shift D:E right one bit (RRA chain) to undo the kernel's trailing shift
        ADD A,D
        RRA
        LD H,A
        LD A,E
        RRA
        LD L,A
        ; the '\' result is always an integer
        CALL SET_TYPE_INTEGER
        POP AF
        ; store the quotient applying the sign recorded during division
        JR INT_ABS_STORE_1
; ----------------------------------------------------------------------
; DP_NEGATE_SIGN -- double-precision SUBTRACT entry: negate ARG, then fall into DADD.
;   In:        ARG (8-byte MBF double) at $0CBA..$0CC1: mantissa $0CBA..$0CC0 (LSB-first), MSB/sign byte $0CC0 (sign in bit7), exponent $0CC1. FAC double at $0CAC..$0CB4.
;   Out:       Falls into DADD => FAC = FAC - ARG.
;   Clobbers:  A, HL, plus everything DADD clobbers; ARG sign byte $0CC0 toggled.
;   Algorithm: XOR $80 the ARG mantissa MSB at $0CC0 to flip its sign bit, then fall straight into DADD. Because MBF stores the sign in bit7 of the high mantissa byte, toggling it turns the pending add into FAC + (-ARG) = FAC - ARG.
; ----------------------------------------------------------------------
DP_NEGATE_SIGN:
        LD HL,L_0CC0
        LD A,(HL)
        ; flip the sign bit (bit7 of the ARG mantissa MSB) so DADD computes FAC - ARG
        XOR $80
        LD (HL),A
; ----------------------------------------------------------------------
; DADD -- double-precision ADD/SUBTRACT core (MBF 8-byte mantissa).
;   In:        FAC double at $0CAC..$0CB4 (guard $0CAC, 7-byte mantissa $0CAD..$0CB3 LSB-first, MSB/sign $0CB3=FACHI, exponent $0CB4). ARG double at $0CBA..$0CC1 (7-byte mantissa $0CBA..$0CC0, MSB/sign $0CC0, exponent $0CC1).
;   Out:       FAC = FAC + ARG, normalized and rounded; result sign folded into FACHI bit7.
;   Clobbers:  A,B,C,D,E,H,L; FAC mantissa/exponent, $0CB5/$0CB9 scratch, guard $0CAC.
;   Algorithm: (1) If ARG exponent=0 return FAC unchanged; if FAC exponent=0 copy ARG into FAC (FP_ARG_TO_TEMP1) and return. (2) diff = FACexp - ARGexp; if FAC is the smaller (carry) negate the difference and swap the two 8-byte operands so the larger magnitude sits in FAC. (3) If the alignment shift >= $39 (57) the smaller operand is negligible -> return the larger unchanged. (4) FP_UNPACK_MSB restores the hidden mantissa MSBs and returns in B the XOR of the two sign bits (bit7=0 => like signs, bit7=1 => unlike signs). Right-shift (denormalize) the ARG mantissa by the exponent difference (DP_SHIFT_RIGHT_N) to align radix points. (5) LIKE signs (B positive, DADD_LIKE_SIGNS): straight magnitude add of the aligned mantissas (DP_ADD_BLOCK_INIT with $9E); if the high byte came out negative, two's-complement it (DP_NEG_MANTISSA). UNLIKE signs (B negative, fall-through): subtract by adding (DP_ADD_CONST_8E with $8E); on carry-out renormalize right and bump the exponent. (6) Left-normalize: byte-at-a-time while FACHI=0 (DADD_NORMALIZE_BYTE_LOOP/DADD_SHIFT_UP_BYTE shifting up 8 bits per step), then bit-at-a-time (DADD_NORMALIZE_BIT_LOOP/DADD_NORMALIZE_CHECK_MSB via DP_SHIFT_LEFT_8) until FACHI bit7 is set or the result underflows to zero (FP_SET_ZERO). (7) Round on the guard byte (DP_ROUND_CARRY) and merge the final sign into FACHI.
; ----------------------------------------------------------------------
DADD:
        LD HL,L_0CC1
        LD A,(HL)
        OR A
        ; ARG exponent 0 => ARG is zero => FAC + 0 = FAC
        RET Z
        LD B,A
        DEC HL
        LD C,(HL)
        LD DE,FAC_EXP
        LD A,(DE)
        OR A
        ; FAC exponent 0 => FAC is zero => result is just ARG; copy ARG into FAC and return
        JP Z,FP_ARG_TO_TEMP1
        ; diff = FACexp - ARGexp; if it borrows (carry, FAC smaller) negate diff and swap operands below
        SUB B
        JR NC,DADD_ALIGNED
        CPL
        INC A
        PUSH AF
        LD C,$08
        INC HL
        PUSH HL
DADD_SWAP_OPERANDS:
        LD A,(DE)
        LD B,(HL)
        LD (HL),A
        LD A,B
        LD (DE),A
        DEC DE
        DEC HL
        DEC C
        JR NZ,DADD_SWAP_OPERANDS
        POP HL
        LD B,(HL)
        DEC HL
        LD C,(HL)
        POP AF
DADD_ALIGNED:
        ; [RE] if the alignment shift >= $39 (57) the smaller operand falls off the 7-byte mantissa+guard; return the larger unchanged
        CP $39
        RET NC
        PUSH AF
        CALL FP_UNPACK_MSB
        LD HL,L_0CB9
        LD B,A
        LD A,$00
        LD (HL),A
        LD (L_0CAC),A
        POP AF
        LD HL,L_0CC0
        ; denormalize the (smaller) ARG mantissa right by the exponent difference to align radix points
        CALL DP_SHIFT_RIGHT_N
        LD A,(L_0CB9)
        LD (L_0CAC),A
        LD A,B
        OR A
        ; B = XOR of the two sign bits: positive => like signs (add, DADD_LIKE_SIGNS); negative => unlike signs (subtract, fall through)
        JP P,DADD_LIKE_SIGNS
        ; unlike signs: subtract by adding the aligned mantissa ($8E); on carry-out renormalize right and bump the exponent
        CALL DP_ADD_CONST_8E
        JP NC,DADD_ROUND_AND_SIGN
        EX DE,HL
        INC (HL)
        JP Z,OVERR_SIGN_FROM_FPFLAG_CPL
        CALL DP_SHIFT_RIGHT_FROM_CB3
        JP DADD_ROUND_AND_SIGN
DADD_LIKE_SIGNS:
        LD A,$9E
        CALL DP_ADD_BLOCK_INIT
        LD HL,FP_SIGN_FLAG
        ; like-signs add left a negative high byte: two's-complement the mantissa and record the sign
        CALL C,DP_NEG_MANTISSA
DADD_NORMALIZE:
        XOR A
DADD_NORMALIZE_BYTE_LOOP:
        LD B,A
        LD A,(FACHI)
        OR A
        JR NZ,DADD_NORMALIZE_CHECK_MSB
        LD HL,L_0CAC
        LD C,$08
DADD_SHIFT_UP_BYTE:
        LD D,(HL)
        LD (HL),A
        LD A,D
        INC HL
        DEC C
        JR NZ,DADD_SHIFT_UP_BYTE
        LD A,B
        SUB $08
        CP $C0
        JR NZ,DADD_NORMALIZE_BYTE_LOOP
        ; mantissa shifted entirely away during normalize => true zero
        JP FP_SET_ZERO
DADD_NORMALIZE_BIT_LOOP:
        DEC B
        LD HL,L_0CAC
        CALL DP_SHIFT_LEFT_8
        OR A
DADD_NORMALIZE_CHECK_MSB:
        JP P,DADD_NORMALIZE_BIT_LOOP
        LD A,B
        OR A
        JR Z,DADD_ROUND_AND_SIGN
        LD HL,FAC_EXP
        ADD A,(HL)
        LD (HL),A
        ; exponent underflowed below the bias => too small to represent => zero
        JP NC,FP_SET_ZERO
        RET Z
DADD_ROUND_AND_SIGN:
        LD A,(L_0CAC)
DADD_ROUND_AND_SIGN_A:
        OR A
        CALL M,DP_ROUND_CARRY
        LD HL,FP_SIGN_FLAG
        LD A,(HL)
        AND $80
        DEC HL
        DEC HL
        XOR (HL)
        LD (HL),A
        RET
; ----------------------------------------------------------------------
; DP_ROUND_CARRY -- round the double mantissa up by 1 with carry propagation.
;   In:        FAC 7-byte mantissa at $0CAD..$0CB3, exponent at $0CB4; called (CALL M,...) when the guard byte $0CAC has bit7 set (round-up needed).
;   Out:       Mantissa incremented; on a full 7-byte carry the MSB is forced to $80 and the exponent is bumped (overflow -> OVERR_SIGN_FROM_FPFLAG_CPL).
;   Clobbers:  A,B,H,L; FAC mantissa and possibly exponent.
;   Algorithm: INC the lowest mantissa byte ($0CAD); while a byte wraps to 0, carry into the next higher byte for up to 7 bytes. If the carry runs off the top, the value rounded up to 1.0: HL now points at the exponent ($0CB4), so INC it (Z => overflow), then set FACHI ($0CB3) MSB to $80 (the renormalized hidden bit).
; ----------------------------------------------------------------------
DP_ROUND_CARRY:
        LD HL,FAC_DBL
        LD B,$07
DP_ROUND_CARRY_PROPAGATE:
        ; add 1 to the current mantissa byte; if it did not wrap (NZ) the round is complete
        INC (HL)
        RET NZ
        INC HL
        DEC B
        JR NZ,DP_ROUND_CARRY_PROPAGATE
        ; carry ran past the whole mantissa: HL is now the exponent, bump it (Z => exponent overflow => error)
        INC (HL)
        JP Z,OVERR_SIGN_FROM_FPFLAG_CPL
        DEC HL
        ; the 1.0 carry renormalizes the mantissa MSB to $80 (hidden leading bit)
        LD (HL),$80
        RET
; ----------------------------------------------------------------------
; DP_SUB_CONST_8E -- divide step: chained ADC of the ARG mantissa ($0CBA) into the divide remainder block ($0CDD), first ADC operand patched from A.
;   In:        A = constant byte supplied by the caller (DDIV passes $9E then $8E); source mantissa at $0CBA; destination = divide remainder block $0CDD.
;   Out:       7-byte chained ADC of [$0CBA] into [$0CDD]; carry out of the high byte in CY.
;   Clobbers:  A,C,D,E,H,L; the $0CDD remainder block.
;   Algorithm: Point the shared multi-byte adder at source=$0CBA / dest=$0CDD and jump into DP_ADD_BLOCK_SETUP, which patches A as the operand of the first ADC and runs the 7-byte chained add-with-carry. NOTE: despite the '_SUB'/'_8E' label this is an ADD primitive whose constant varies; DDIV uses it as the trial-subtract/restore step of restoring division (the [RE] sub vs add semantics of the $9E/$8E markers are not fully pinned -- see UNKNOWN).
; ----------------------------------------------------------------------
DP_SUB_CONST_8E:
        ; destination = divide remainder block $0CDD (not the FAC mantissa)
        LD DE,L_0CDD
        LD HL,ARG2_TEMP
        JP DP_ADD_BLOCK_SETUP
; ----------------------------------------------------------------------
; DP_ADD_CONST_8E -- add the ARG mantissa ($0CBA) into the FAC mantissa, with the first ADC operand preset to $8E.
;   In:        ARG mantissa at $0CBA; FAC mantissa at $0CAD.
;   Out:       7-byte chained ADC of [$0CBA] into [$0CAD]; carry out in CY.
;   Clobbers:  A,C,D,E,H,L; FAC mantissa.
;   Algorithm: Preset A=$8E and fall into DP_ADD_BLOCK_INIT, which sets source=$0CBA / dest=$0CAD and runs the chained 7-byte ADC. ($8E is the byte patched into the first ADC slot; the [RE] meaning of that marker is not pinned.) Called by the DADD unlike-signs subtract path and by the DMUL inner conditional-add.
; ----------------------------------------------------------------------
DP_ADD_CONST_8E:
        LD A,$8E
; ----------------------------------------------------------------------
; DP_ADD_BLOCK_INIT -- set the ARG source ($0CBA) then run the multi-byte add into FAC.
;   In:        A = first-ADC operand byte (constant patched into the loop, e.g. $9E/$8E); ARG mantissa source at $0CBA.
;   Out:       Falls into DP_ADD_BLOCK to ADC the 7-byte ARG mantissa into the FAC mantissa [$0CAD]; carry out in CY.
;   Clobbers:  A,C,D,E,H,L; FAC mantissa.
;   Algorithm: Point HL at the ARG mantissa $0CBA, then fall into DP_ADD_BLOCK (which sets dest=$0CAD and runs the chained ADC). Split from DP_ADD_CONST_8E so DADD_LIKE_SIGNS can enter with its own already-loaded constant ($9E) in A.
; ----------------------------------------------------------------------
DP_ADD_BLOCK_INIT:
        LD HL,ARG2_TEMP
; ----------------------------------------------------------------------
; DP_ADD_BLOCK -- 7-byte chained add-with-carry primitive (mantissa add).
;   In:        HL = source mantissa pointer (LSB-first); A = byte patched into the first ADC; dest fixed at $0CAD (FAC mantissa) on this entry.
;   Out:       [DE..DE+6] += [HL..HL+6], carry chained low->high; final carry-out in CY.
;   Clobbers:  A,C,D,E,H,L.
;   Algorithm: Self-modifying loop: store A into the 'ADC A,(HL)' slot at DP_ADD_BLOCK_PATCHED_ADC (so the first iteration's added operand is the caller-supplied constant), XOR A to clear carry, then for 7 bytes do A=[DE]; A=ADC patched-operand; [DE]=A; advance both pointers. The patched first operand lets callers inject a constant marker byte ahead of the genuine ARG bytes.
; ----------------------------------------------------------------------
DP_ADD_BLOCK:
        LD DE,FAC_DBL
DP_ADD_BLOCK_SETUP:
        LD C,$07
        ; self-modify: patch A as the added operand of the first ADC below
        LD (DP_ADD_BLOCK_PATCHED_ADC),A
        ; clear carry (and A) before the first add of the chain
        XOR A
DP_ADD_BLOCK_LOOP:
        LD A,(DE)
DP_ADD_BLOCK_PATCHED_ADC:
        ADC A,(HL)
        LD (DE),A
        INC DE
        INC HL
        DEC C
        JR NZ,DP_ADD_BLOCK_LOOP
        RET
; ----------------------------------------------------------------------
; DP_NEG_MANTISSA -- two's-complement negate the 8-byte FAC mantissa (guard included).
;   In:        HL = pointer to a sign-carrying scratch byte (CPL'd on entry, e.g. $0CB5); FAC mantissa+guard at $0CAC..$0CB3 (8 bytes).
;   Out:       Mantissa replaced by 0 - mantissa across all 8 bytes; [HL] complemented.
;   Clobbers:  A,B,C,H,L; [HL] and the 8 mantissa bytes.
;   Algorithm: CPL the byte at HL (the saved sign scratch), then chained 0 - byte SBC from the guard $0CAC upward across 8 bytes (C preset to 0), two's-complementing the magnitude. Invoked by DADD's like-signs path when the add produced a negative high byte.
; ----------------------------------------------------------------------
DP_NEG_MANTISSA:
        LD A,(HL)
        ; complement the saved sign scratch at [HL] to match the negated magnitude
        CPL
        LD (HL),A
        LD HL,L_0CAC
        LD B,$08
        XOR A
        LD C,A
DP_NEG_MANTISSA_LOOP:
        LD A,C
        ; 0 - byte with borrow: two's-complement the mantissa byte by byte
        SBC A,(HL)
        LD (HL),A
        INC HL
        DEC B
        JR NZ,DP_NEG_MANTISSA_LOOP
        RET
; ----------------------------------------------------------------------
; DP_SHIFT_RIGHT_N -- denormalize: shift an 8-byte mantissa right by A bit positions.
;   In:        A = shift count (bits); HL = pointer to the MSB of the block to shift (DADD calls it with HL=$0CC0, the ARG mantissa MSB); C = byte written into the MSB slot before shifting (the restored MSB value).
;   Out:       The 8-byte window ending at [HL] (the ARG mantissa $0CC0 down to fill cell $0CB9 in the DADD call) shifted right A bits, vacated high bits zero-filled; bits past the bottom are lost (rounding handled by the caller).
;   Clobbers:  A,C,D,E,H,L.
;   Algorithm: Write C into the MSB slot [HL], then shift in two phases: whole-byte moves while count >= 8 (move the 8 bytes down one position per step), then the leftover (count mod 8) bits as per-bit RRA chains across the 8 bytes. Used to align the smaller operand before DADD. (The single-bit entry DP_SHIFT_RIGHT_FROM_CB3 jumps past the C-store directly into the bit phase.)
; ----------------------------------------------------------------------
DP_SHIFT_RIGHT_N:
        ; write the restored MSB byte (C) into the top slot before shifting
        LD (HL),C
        PUSH HL
DP_SHIFT_RIGHT_COUNT_BYTES:
        ; consume 8 bits per whole-byte shift; once the count goes negative do the leftover bits
        SUB $08
        JR C,DP_SHIFT_RIGHT_BITS_SETUP
        POP HL
; [RE] Inner byte/bit right-shift loop for DP_SHIFT_RIGHT_N: moves whole bytes while the shift count exceeds 8, then performs the leftover bit shifts.
DP_SHIFT_RIGHT_BYTE:
        PUSH HL
        ; D=8 bytes to move, E=0 fill for the byte coming in at the top
        LD DE,$0800
DP_SHIFT_RIGHT_BYTE_INNER:
        LD C,(HL)
        LD (HL),E
        LD E,C
        DEC HL
        DEC D
        JR NZ,DP_SHIFT_RIGHT_BYTE_INNER
        JR DP_SHIFT_RIGHT_COUNT_BYTES
DP_SHIFT_RIGHT_BITS_SETUP:
        ; recover the leftover bit count (+8 to undo the last SUB, +1 for the pre-decrement) after the byte phase overshot
        ADD A,$09
        LD D,A
DP_SHIFT_RIGHT_BIT:
        XOR A
        POP HL
        DEC D
        RET Z
DP_SHIFT_RIGHT_BIT_PASS:
        PUSH HL
        LD E,$08
DP_SHIFT_RIGHT_BIT_INNER:
        LD A,(HL)
        ; rotate one bit down through the block, MSB toward LSB across 8 bytes
        RRA
        LD (HL),A
        DEC HL
        DEC E
        JR NZ,DP_SHIFT_RIGHT_BIT_INNER
        JR DP_SHIFT_RIGHT_BIT
; ----------------------------------------------------------------------
; DP_SHIFT_RIGHT_FROM_CB3 -- shift the FAC mantissa right by exactly 1 bit.
;   In:        FAC mantissa at $0CAC..$0CB3, MSB at FACHI=$0CB3.
;   Out:       Mantissa shifted right 1 bit (single RRA chain from the MSB down).
;   Clobbers:  A,D,E,H,L.
;   Algorithm: Point HL at FACHI, set the bit-pass count D=1, and jump straight into DP_SHIFT_RIGHT's single-bit pass (skipping the C fill-store). Used between partial products in DMUL, and on the carry-out path in DADD, to halve the accumulator one place.
; ----------------------------------------------------------------------
DP_SHIFT_RIGHT_FROM_CB3:
        LD HL,FACHI
        ; exactly one bit-shift pass
        LD D,$01
        JR DP_SHIFT_RIGHT_BIT_PASS
; ----------------------------------------------------------------------
; DP_SHIFT_LEFT_8 -- shift an 8-byte mantissa left by 1 bit (chained RLA).
;   In:        HL = pointer to the mantissa LSB; CY = bit rotated into the LSB.
;   Out:       8 bytes at [HL] shifted left 1 bit, low->high; bit out of the top in CY.
;   Clobbers:  A,C,H,L.
;   Algorithm: For C bytes (8 here), RLA each from the LSB upward so carry chains the shifted-out bit into the next byte. The '_8' is the BYTE count, not the bit count -- this is a 1-bit shift. Used by DADD's left-normalize and (entered at DP_SHIFT_LEFT_LOOP with C preset to 7) by DDIV to shift the remainder and quotient.
; ----------------------------------------------------------------------
DP_SHIFT_LEFT_8:
        LD C,$08
DP_SHIFT_LEFT_LOOP:
        LD A,(HL)
        RLA
        LD (HL),A
        INC HL
        DEC C
        JR NZ,DP_SHIFT_LEFT_LOOP
        RET
; ----------------------------------------------------------------------
; DMUL -- double-precision MULTIPLY (MBF, 8-byte mantissa).
;   In:        FAC double at $0CAC..$0CB4 (multiplier), ARG double at $0CBA..$0CC1 (multiplicand).
;   Out:       FAC = FAC * ARG, normalized/rounded; FAC=0 if either operand is zero.
;   Clobbers:  A,B,C,D,E,H,L; FAC, ARG, the $0CE3 temp.
;   Algorithm: If FAC=0 return; if ARG exponent=0 set FAC=0. Combine the operand signs and add exponents (MULDIV_SIGN_1+1, the +1 entry doing a plain sign XOR). Stash the multiplier mantissa into the $0CE3 temp and zero the FAC mantissa (DP_COPY_TEMP) to form the accumulator. Classic shift-add: for each of the 7 multiplier mantissa bytes (skipping all-zero bytes via DMUL_SKIP_ZERO_BYTE) process 8 bits LSB-first (RRA the bit out); if set, add the multiplicand mantissa into the accumulator (DP_ADD_CONST_8E), then shift the accumulator right 1 (DP_SHIFT_RIGHT_FROM_CB3) so each successive bit's partial product weighs one place lower. Finish through DADD_NORMALIZE (normalize+round).
; ----------------------------------------------------------------------
DMUL:
        CALL FP_SIGN
        ; FAC is zero => product is zero
        RET Z
        LD A,(L_0CC1)
        OR A
        ; ARG (multiplicand) exponent zero => product is zero
        JP Z,FP_SET_ZERO
        ; +1 entry runs XOR A: plain sign XOR (no complement) then add the exponents
        CALL MULDIV_SIGN_1+1
        ; stash the multiplier mantissa to the temp and clear the FAC mantissa to seed the accumulator
        CALL DP_COPY_TEMP
        LD (HL),C
        INC DE
        LD B,$07
DMUL_BYTE_LOOP:
        LD A,(DE)
        INC DE
        OR A
        PUSH DE
        ; whole multiplier byte is zero: skip the 8 conditional adds, just shift one byte
        JR Z,DMUL_SKIP_ZERO_BYTE
        LD C,$08
DMUL_BIT_LOOP:
        PUSH BC
        ; shift out the next multiplier bit (LSB-first); carry set => add the multiplicand
        RRA
        LD B,A
        ; bit set: add the multiplicand mantissa into the running product
        CALL C,DP_ADD_CONST_8E
        ; shift the partial product right one place to weight the next bit
        CALL DP_SHIFT_RIGHT_FROM_CB3
        LD A,B
        POP BC
        DEC C
        JR NZ,DMUL_BIT_LOOP
DMUL_NEXT_BYTE:
        POP DE
        DEC B
        JR NZ,DMUL_BYTE_LOOP
        ; all partial products accumulated: normalize and round via the shared DADD normalize tail
        JP DADD_NORMALIZE
DMUL_SKIP_ZERO_BYTE:
        LD HL,FACHI
        CALL DP_SHIFT_RIGHT_BYTE
        JR DMUL_NEXT_BYTE
; [RE] Double-precision MBF constant (8-byte mantissa $CD CC CC CC CC CC 4C exp $7D ~= 0.1) used as the divide-by-ten reciprocal seed by DDIV/the decimal scaler. [RE] MBF double-precision constant 0.1 (CD CC CC CC CC CC 4C 7D). Loaded by the double-precision code (LD DE,DP_CONST_TENTH at $5390). The repeating $CC is 0.1's mantissa.
DP_CONST_TENTH:
        DEFB    $CD,$CC,$CC,$CC,$CC,$CC,$4C,$7D,$00  ; "MLLLLLL}"
        DEFB    "\0\0\0"
; [RE] Small double-precision MBF constant ($00 $00 $20 $84) following DP_CONST_TENTH, used as a rounding/scaling constant by the double-precision path.
DP_CONST_2:
        DEFB    $00,$00,$20,$84
; ----------------------------------------------------------------------
; FIN_DSCALE_DIV10 -- decimal scaler: divide the FAC double by 10.
;   In:        FAC double at $0CAC..$0CB4; ARG slot $0CBA used as scratch; constant DP_CONST_TENTH (~0.1, small path only).
;   Out:       FAC = FAC / 10, full double precision.
;   Clobbers:  A,B,C,D,E,H,L; FAC, ARG slot, stack.
;   Algorithm: For small magnitudes (exponent < $41) just multiply FAC by the precomputed 0.1 constant (DMUL) and return -- this is x/10 directly. For larger values it computes x/10 by an iterative exponent-shifted self-add series: if FAC is negative, strip the sign and defer a closing FP_NEG (PUSH HL). Seed with a couple of DP_DEC_EXP + DADD steps, then iterate 15 times (LD A,$0F): each pass drops the ARG exponent by 4 (DP_DEC_EXP_BY4 ~ one decimal place), saves the operand across an inner DADD (DP_PUSH_OPERAND/DADD/DP_POP_OPERAND) to add the next correction term, and a final 3x DP_DEC_EXP trims the exponent. [RE] The series structure is observed; the exact convergence method and why exactly 15 passes (and the precise meaning of the seed/trim DP_DEC_EXP steps) is UNKNOWN -- it is some correction/series expansion of 1/10, not proven to be Newton reciprocal iteration.
; ----------------------------------------------------------------------
FIN_DSCALE_DIV10:
        LD A,(FAC_EXP)
        CP $41
        ; exponent >= $41: use the iterative refinement instead of the single 0.1 multiply
        JP NC,FIN_DSCALE_DIV10_REFINE
        LD DE,DP_CONST_TENTH
        LD HL,ARG2_TEMP
        CALL FP_MOVE_TYPED
        ; small magnitude: x/10 == x * 0.1, multiply by the DP_CONST_TENTH constant
        JP DMUL
FIN_DSCALE_DIV10_REFINE:
        LD A,(FACHI)
        OR A
        JP P,FIN_DSCALE_DIV10_SEED
        AND $7F
        LD (FACHI),A
        LD HL,FP_NEG
        ; negative input: defer a closing FP_NEG so the refinement works on the magnitude
        PUSH HL
FIN_DSCALE_DIV10_SEED:
        CALL DP_DEC_EXP
        LD DE,FAC_DBL
        LD HL,ARG2_TEMP
        CALL FP_MOVE_TYPED
        CALL DP_DEC_EXP
        CALL DADD
        LD DE,FAC_DBL
        LD HL,ARG2_TEMP
        CALL FP_MOVE_TYPED
        ; 15 correction passes
        LD A,$0F
FIN_DSCALE_DIV10_ITER:
        PUSH AF
        CALL DP_DEC_EXP_BY4
        ; preserve the operand across the inner DADD that adds this pass's correction term
        CALL DP_PUSH_OPERAND
        CALL DADD
        LD HL,L_0CC0
        CALL DP_POP_OPERAND
        POP AF
        DEC A
        ; loop until all 15 passes are done
        JP NZ,FIN_DSCALE_DIV10_ITER
        CALL DP_DEC_EXP
        CALL DP_DEC_EXP
        CALL DP_DEC_EXP
        RET
; ----------------------------------------------------------------------
; DP_DEC_EXP -- decrement the FAC double exponent by 1.
;   In:        FAC exponent at $0CB4.
;   Out:       Exponent--; if it underflows to 0 the value is zero -> JP FP_SET_ZERO; otherwise returns NZ.
;   Clobbers:  flags,H,L; $0CB4.
;   Algorithm: DEC the exponent byte; a zero result means the magnitude scaled below representable range, so set the whole FAC to zero. Used by the /10 scaler to track the exponent across its shifts.
; ----------------------------------------------------------------------
DP_DEC_EXP:
        LD HL,FAC_EXP
        DEC (HL)
        RET NZ
        ; exponent underflowed to 0 => result is zero
        JP FP_SET_ZERO
; ----------------------------------------------------------------------
; DP_DEC_EXP_BY4 -- decrement the ARG exponent ($0CC1) by up to 4, stopping at 0.
;   In:        ARG exponent at $0CC1.
;   Out:       Exponent reduced by 4 (or fewer if it would pass 0); returns immediately when it reaches 0.
;   Clobbers:  A,H,L; $0CC1.
;   Algorithm: Up to four times, DEC the exponent and RET (Z) the moment it reaches 0; otherwise count A down and loop. The /10 refinement loop calls this each pass to drop the correction-term weight by 4 binary exponent steps (~one decimal place, since 2^4 ~ 10) [RE].
; ----------------------------------------------------------------------
DP_DEC_EXP_BY4:
        LD HL,L_0CC1
        LD A,$04
DP_DEC_EXP_BY4_LOOP:
        ; drop the ARG exponent one step; stop early if it reaches zero
        DEC (HL)
        RET Z
        DEC A
        JP NZ,DP_DEC_EXP_BY4_LOOP
        RET
; ----------------------------------------------------------------------
; DP_PUSH_OPERAND -- save the 8-byte ARG operand ($0CBA..$0CC1) onto the stack across an inner DADD.
;   In:        ARG block at $0CBA (4 consecutive words); return address on top of stack.
;   Out:       The 4 words pushed below the preserved return address; ARG unchanged in memory.
;   Clobbers:  A,B,C,H,L (DE holds the return address).
;   Algorithm: Pop the return address into DE, push the 4 words of the operand block low->high ($0CBA upward), then push DE back and RET. Paired with DP_POP_OPERAND so the /10 refinement can reuse the shared DADD on a correction term without clobbering its working operand.
; ----------------------------------------------------------------------
DP_PUSH_OPERAND:
        ; lift the return address off so the pushed operand sits below it
        POP DE
        LD A,$04
        LD HL,ARG2_TEMP
DP_PUSH_OPERAND_LOOP:
        LD C,(HL)
        INC HL
        LD B,(HL)
        INC HL
        PUSH BC
        DEC A
        JP NZ,DP_PUSH_OPERAND_LOOP
        ; restore the return address on top before RET
        PUSH DE
        RET
; ----------------------------------------------------------------------
; DP_POP_OPERAND -- restore the 8-byte operand from the stack into $0CC1..$0CBA.
;   In:        4 operand words on the stack (as pushed by DP_PUSH_OPERAND); return address above them.
;   Out:       Operand block reloaded high->low ($0CC1 down to $0CBA); ARG restored.
;   Clobbers:  A,B,C,H,L (DE holds the return address).
;   Algorithm: Pop the return address into DE, pop the 4 words back into the block writing high->low (B->[HL], C->[HL-1], walking down from $0CC1), then push DE and RET. Exact inverse of DP_PUSH_OPERAND. (Callers may LD HL,... before the call, but the routine overwrites HL with $0CC1 immediately.)
; ----------------------------------------------------------------------
DP_POP_OPERAND:
        POP DE
        LD A,$04
        LD HL,L_0CC1
DP_POP_OPERAND_LOOP:
        ; pull each saved word and store high-byte then low-byte, walking down from $0CC1
        POP BC
        LD (HL),B
        DEC HL
        LD (HL),C
        DEC HL
        DEC A
        JP NZ,DP_POP_OPERAND_LOOP
        PUSH DE
        RET
; ----------------------------------------------------------------------
; DDIV -- double-precision DIVIDE (MBF, restoring division).
;   In:        FAC double at $0CAC..$0CB4 (dividend), ARG double at $0CBA..$0CC1 (divisor).
;   Out:       FAC = FAC / ARG, normalized/rounded; FAC=0 on dividend zero; divide-by-zero -> DIV0_SIGN_DOUBLE, overflow -> OVERR_SIGN_FROM_FPFLAG_CPL.
;   Clobbers:  A,B,C,D,E,H,L; FAC, the $0CDD remainder block and $0CE3/$0CE4 temps.
;   Algorithm: If the divisor exponent ($0CC1) is 0, jump to the divide-by-zero handler (DIV0_SIGN_DOUBLE). If the dividend exponent ($0CB4) is 0, the quotient is 0. Combine signs and form the quotient exponent (MULDIV_SIGN, A=$FF complement path), then INC the exponent twice to set the quotient scale (Z => overflow -> OVERR_SIGN_FROM_FPFLAG_CPL). Seed the remainder block $0CDD..$0CE3 with the dividend mantissa (DP_COPY_TEMP); the quotient builds in the FAC mantissa $0CAD (cleared to 0). Restoring division: each step trial-subtracts the divisor (DP_SUB_CONST_8E with $9E; SBC/CCF turns the borrow into a fit/no-fit test), and on no-fit adds it back ($8E); a 1/0 quotient bit is recorded, then the QUOTIENT ($0CAD, 7 bytes via DP_SHIFT_LEFT_LOOP) and the REMAINDER ($0CDD, 8 bytes via DP_SHIFT_LEFT_8) are shifted left, looping over the bit counter B and the exponent at $0CB4 until the quotient is filled; exponent underflow yields zero.
; ----------------------------------------------------------------------
DDIV:
        LD A,(L_0CC1)
        OR A
        ; divisor exponent 0 => division by zero
        JP Z,DIV0_SIGN_DOUBLE
        LD A,(FAC_EXP)
        OR A
        ; dividend exponent 0 => quotient is zero
        JP Z,FP_SET_ZERO
        ; combine signs (A=$FF complement => divide) and form the quotient exponent
        CALL MULDIV_SIGN
        INC (HL)
        INC (HL)
        JP Z,OVERR_SIGN_FROM_FPFLAG_CPL
        ; seed the remainder block ($0CDD..$0CE3) with the dividend mantissa
        CALL DP_COPY_TEMP
        LD HL,L_0CE4
        LD (HL),C
        LD B,C
DDIV_DIGIT_LOOP:
        LD A,$9E
        ; trial-subtract the divisor from the remainder ($9E); SBC+CCF makes the borrow a fit/no-fit test
        CALL DP_SUB_CONST_8E
        LD A,(DE)
        SBC A,C
        CCF
        JR C,DDIV_RECORD_DIGIT+1
        LD A,$8E
        ; divisor did not fit: add it back ($8E) to restore the remainder; quotient bit stays 0
        CALL DP_SUB_CONST_8E
        XOR A
; [RE] DDIV digit-loop overlap (VERIFIED). DA 12 04 = JP C,$0412 only on the carry-CLEAR fall-through ($544B XOR A guarantees carry clear, so the JP is a never-taken 2-byte skip of its own operand). The carry-SET branch (JR C,DDIV_RECORD_DIGIT+1 at $5444) enters at +1 and runs 12 04 = LD (DE),A / INC B: store the reduced remainder, count one decimal digit. Both paths land at $544F. MBASIC DDIV_3 byte-identical.
DDIV_RECORD_DIGIT:
        JP C,$0412
        LD A,(FACHI)
        INC A
        DEC A
        RRA
        JP M,DADD_ROUND_AND_SIGN_A
        RLA
        LD HL,FAC_DBL
        LD C,$07
        ; shift the QUOTIENT mantissa ($0CAD, 7 bytes) left one bit to make room for the next digit
        CALL DP_SHIFT_LEFT_LOOP
        LD HL,L_0CDD
        ; shift the REMAINDER ($0CDD, 8 bytes) left one bit for the next division step
        CALL DP_SHIFT_LEFT_8
        LD A,B
        OR A
        ; more bits remain in this quotient byte (bit counter B not yet zero)
        JR NZ,DDIV_DIGIT_LOOP
        LD HL,FAC_EXP
        DEC (HL)
        ; exponent still positive: keep producing quotient digits
        JR NZ,DDIV_DIGIT_LOOP
        ; exponent underflowed => quotient rounds to zero
        JP FP_SET_ZERO
; ----------------------------------------------------------------------
; DP_COPY_TEMP -- move the 7-byte FAC mantissa into the $0CE3 temp and zero the source.
;   In:        HL = pointer just above the FAC mantissa MSB ($0CB4); C = leading byte to stash (the saved sign/MSB byte); FAC mantissa just below HL.
;   Out:       7 mantissa bytes copied high->low into $0CE3..$0CDD; source FAC mantissa zeroed; leading byte saved to $0CC0.
;   Clobbers:  A,B,C,D,E,H,L; $0CE3..$0CDD temp, FAC mantissa (cleared), $0CC0.
;   Algorithm: Save the leading byte C into $0CC0, DEC HL to the mantissa MSB, then copy 7 bytes from the FAC mantissa down into the $0CE3 temp while writing 0 back into each source byte (BC=$0700 sets B=7 count and C=0 as the clear value). Used by DMUL (stash multiplier, clear accumulator) and DDIV (seed remainder, clear quotient).
; ----------------------------------------------------------------------
DP_COPY_TEMP:
        LD A,C
        ; stash the leading mantissa byte (C) before the source is cleared
        LD (L_0CC0),A
        DEC HL
        LD DE,L_0CE3
        LD BC,$0700
DP_COPY_TEMP_LOOP:
        LD A,(HL)
        LD (DE),A
        ; clear each source byte (C=0) as it is copied out, leaving the accumulator at zero
        LD (HL),C
        DEC DE
        DEC HL
        DEC B
        JR NZ,DP_COPY_TEMP_LOOP
        RET
; ----------------------------------------------------------------------
; DP_MUL10 -- multiply the FAC double by ten (decimal input/output scaler).
;   In:        FAC double at $0CAC..$0CB4.
;   Out:       FAC = FAC * 10, full double precision; exponent overflow -> OVERR_SIGN_FROM_FPFLAG_CPL; FAC unchanged if its exponent was 0.
;   Clobbers:  A,D,E,H,L; FAC, ARG temp ($0CBA).
;   Algorithm: Copy FAC into the ARG temp (FP_ARG_TO_TEMP2 -> FP_MOVE_TYPED copies $0CAD..$0CB4 to $0CBA..$0CC1, leaving HL at the FAC exponent $0CB4). x*10 = (x*4 + x)*2: ADD A,$02 bumps the FAC exponent by 2 (FAC = x*4; carry => overflow), DADD adds the saved original (ARG = x) giving x*4 + x = x*5, then INC the FAC exponent ($0CB4) once to double it to x*10. Returns FAC unchanged if its exponent was 0.
; ----------------------------------------------------------------------
DP_MUL10:
        CALL FP_ARG_TO_TEMP2
        EX DE,HL
        DEC HL
        LD A,(HL)
        OR A
        ; FAC exponent 0 => 0*10 = 0, return unchanged
        RET Z
        ; bump the FAC exponent by 2 binary steps (FAC = x*4); carry => overflow
        ADD A,$02
        JP C,OVERR_SIGN_FROM_FPFLAG_CPL
        LD (HL),A
        PUSH HL
        ; FAC(x*4) + ARG(original x) = x*5
        CALL DADD
        POP HL
        ; final FAC-exponent bump doubles the sum: (x*5)*2 = x*10
        INC (HL)
        RET NZ
        JP OVERR_SIGN_FROM_FPFLAG_CPL
; ----------------------------------------------------------------------
; FIN -- parse an ASCII numeric literal into the FAC (string-to-number).
;   In:        HL -> first character of the numeric text (TXTPTR-style scan cursor).
;              A on entry distinguishes the two entry styles: the FIN top entry leaves A such
;              that FIN_1's 'OR $AF' can never be zero (Z stays clear -> parse a fresh value
;              from FAC=0); the five +1 entrants enter one byte later so the F6 AF cover byte
;              executes as 'XOR A' (Z set), pre-seeding an integer value into the FAC. [RE]
;   Out:       FAC = the parsed number with VALTYP set to the literal's type (int/sng/dbl);
;              HL advanced past the consumed literal. Returns to the caller via the tail FIN_1
;              pushes (FIN_RETURN_COPY_FLAG), with the parsed value already in the FAC.
;   Clobbers:  A,B,C,D,E,H,L,F; FAC; VALTYP; the eval-state flag at $0CB6/$0CB7.
;   Algorithm: Clear the FAC to exact zero (FP_SET_ZERO) and default the working type to
;              double (SET_TYPE_DOUBLE) so digit accumulation has full precision, then fall
;              into FIN_1 which sets up the return tail, optional FAC pre-seed, sign skip,
;              and the main digit/decimal/exponent scan.
; ----------------------------------------------------------------------
FIN:
        ; start with FAC = exact zero (clears exponent so digit accumulation builds up from 0)
        CALL FP_SET_ZERO
        ; accumulate at double precision (VALTYP=8); a trailing type suffix (%/!/#) narrows it later
        CALL SET_TYPE_DOUBLE
; ----------------------------------------------------------------------
; FIN_1 -- FIN setup: install the return tail, optionally pre-seed the FAC, skip a leading
;          sign, and dispatch on the first significant character.
;   In:        HL -> first character; FAC = 0, VALTYP = double (from FIN). A's Z flag selects
;              whether to pre-seed an integer into the FAC (see FIN entry note).
;   Out:       Eval-state flag $0CB6 = 1 (the return tail later snapshots it to $0CB7). On '&'
;              radix prefix, jumps to SCAN_AMP_RADIX_CONST. A leading '-' or '+' is consumed
;              (the entry flags are PUSHed via PUSH AF before the comparisons, carrying the
;              '-'/'+' decision down to FIN_10's CALL Z,FP_NEGATE_CHECKED). Control falls into
;              the FIN_2 scan loop.
;   Clobbers:  A,B,C,D,E,H,L,F; $0CB6.
;   Algorithm: Push FIN_RETURN_COPY_FLAG as the eventual RET target. Set $0CB6=1 while
;              preserving the entry Z flag across PUSH AF/POP AF. Load BC=$00FF (B=0, C=$FF)
;              and zero HL (the running-integer accumulator and the B/C digit-bookkeeping
;              seeds; C=$FF makes integer-part digits add 0 to the fractional counter B),
;              and when entered with Z set call FP_STORE_FAC_INT to seed FAC=0 as an integer.
;              Read the first char: '&' (=$26) -> radix constant; '-' (=$2D) -> remember sign
;              via PUSH AF then FIN_2; '+' (=$2B) -> FIN_2 with no negate; otherwise back up HL
;              one char so FIN_2's CHRGET re-reads it as the first digit.
; ----------------------------------------------------------------------
FIN_1:
        ; [RE] dual-entry cover byte (F6 AF): at the FIN top entry this is 'OR $AF' which can never be zero (Z stays clear -> skip the FAC pre-seed); the +1 entrants enter one byte later so AF executes as 'XOR A' (Z set) and the FAC is pre-seeded as an integer below
        OR $AF
        LD BC,FIN_EPILOGUE_SNAPSHOT_EVAL_FLAG
        PUSH BC
        PUSH AF
        ; mark numeric-parse / eval in progress in $0CB6 (flag preserved across the PUSH AF/POP AF that bracket the entry Z)
        LD A,$01
        LD (L_0CB6),A
        POP AF
        EX DE,HL
        ; seed the digit bookkeeping: B=0 (fractional-digit count), C=$FF (decimal-point-not-seen sentinel; with C=$FF integer-part digits add 0 to B); HL=0 is the running-integer accumulator
        LD BC,$00FF
        LD H,B
        LD L,B
        ; +1 entrants only (Z set): pre-seed FAC = 0 as an integer before scanning
        CALL Z,FP_STORE_FAC_INT
        EX DE,HL
        LD A,(HL)
        ; '&' radix prefix (&H hex / &O octal): hand off to the radix-constant scanner
        CP $26
        JP Z,SCAN_AMP_RADIX_CONST
        ; leading '-': remember it (PUSH AF leaves Z set) so FIN_10 negates the result
        CP $2D
        PUSH AF
        JP Z,FIN_2
        ; leading '+': consume it, no negate
        CP $2B
        JR Z,FIN_2
        ; no sign char: back up so FIN_2 re-reads this character as the first digit
        DEC HL
; ----------------------------------------------------------------------
; FIN_2 -- main mantissa-scan dispatch: read one character and route it to digit, decimal
;          point, exponent-marker, or type-suffix handling.
;   In:        HL -> next character to classify; B = fractional-digit count; C = decimal-point
;              sentinel; FAC = running value.
;   Out:       Dispatches: carry from CHRGET (a digit) -> FIN_ACCUM_DIGIT; '.' -> FIN_11;
;              'e'/'E' -> FIN_3; anything else -> FIN_6 (type-suffix / terminator / 'd'/'D').
;              FIN_3 is entered with Z set iff the char was 'e' (via the JR Z) or 'E' (via the
;              fall-through CP $45 leaving Z).
;   Clobbers:  A,H,L,F (plus whatever the dispatched target uses).
;   Algorithm: CHRGET advances HL, skips spaces, expands constant tokens, and returns carry
;              set iff the char is an ASCII digit. On a digit, accumulate it. CP '.' ($2E)
;              detects the decimal point. CP 'e' ($65) / 'E' ($45) detect the 'E' exponent
;              marker; the CP $45 sits immediately before FIN_3 so the Z from either compare
;              carries into FIN_3's branch.
; ----------------------------------------------------------------------
FIN_2:
        ; fetch next char (CHRGET advances HL); carry set => it is an ASCII digit '0'..'9'
        CALL CHRGET
        ; digit: fold it into the running integer/float value
        JP C,FIN_ACCUM_DIGIT
        ; '.' decimal point: switch to fractional-digit counting (FIN_11)
        CP $2E
        JP Z,FIN_11
        ; 'e'/'E' candidate exponent marker -> FIN_3 to disambiguate from the ELSE/EQV keywords
        CP $65
        JR Z,FIN_3
        CP $45
; ----------------------------------------------------------------------
; FIN_3 -- decide whether an 'e'/'E' is an exponent marker or the start of a keyword, by
;          peeking the following character.
;   In:        Z set iff the char in A was 'e'/'E'; HL -> the char after it.
;   Out:       If the char was NOT 'e'/'E', NZ -> FIN_6 (re-classify as a suffix/terminator).
;              If it was 'e'/'E', peek the next char: if it is 'l'/'L' ($6C/$4C) or 'q'/'Q'
;              ($71/$51) [RE: the second letters of the keywords ELSE and EQV, both of which
;              begin with 'E'] take the FIN_5 path so the number TERMINATES before the 'E'.
;              Otherwise FIN_4 decides the result type and parses the exponent field.
;   Clobbers:  A,H,L,F.
;   Algorithm: JP NZ,FIN_6 when not an 'E'. Otherwise PUSH HL (save the cursor just past 'E'),
;              CHRGET the next char, and CP it against $6C/$4C ('l'/'L') and $71/$51 ('q'/'Q');
;              a match (Z) enters FIN_4 -> FIN_5. [RE] These four letters are not numeric
;              grammar: they distinguish exponent 'E' from the reserved words ELSE (E+LSE) and
;              EQV (E+QV); the file's reserved-word table stores 'LSE'+TOK_ELSE and 'QV'+TOK_EQV
;              after a leading 'E'. The exact intent of the peek is INFERRED from those keyword
;              spellings and from FIN_5's effect (it ends the number at the 'E').
; ----------------------------------------------------------------------
FIN_3:
        ; not an 'E' after all: re-classify the char as a type suffix / terminator
        JP NZ,FIN_6
        ; save cursor (just past 'E'); peek the next char to tell exponent 'E' from the keywords ELSE/EQV
        PUSH HL
        CALL CHRGET
        ; [RE] 'l'/'L' (or 'q'/'Q' below) after 'E' => the keyword ELSE/EQV, not an exponent: end the number before 'E'
        CP $6C
        JR Z,FIN_4
        CP $4C
        JR Z,FIN_4
        CP $71
        JR Z,FIN_4
        CP $51
; ----------------------------------------------------------------------
; FIN_4 -- exponent vs keyword resolution; on the exponent path choose the result type and
;          set A to the FIN_7 type-fixup selector.
;   In:        Z set iff the peeked char was one of l/L/q/Q (the ELSE/EQV case); HL was saved
;              by FIN_3.
;   Out:       HL restored to the char after the 'E'. If l/L/q/Q matched (Z) -> FIN_5 (the
;              keyword case: end the number). Otherwise this is a real exponent: A is set to
;              the FIN_7 selector -- 0 if VALTYP is not already double (force single), or kept
;              at VT_DBL ($08) if VALTYP==VT_DBL (stay double). Falls into FIN_7.
;   Clobbers:  A,H,L,F.
;   Algorithm: POP HL to undo FIN_3's peek. JR Z,FIN_5 on the keyword case. Else load VALTYP;
;              if it already equals VT_DBL keep double and JR FIN_7; otherwise LD A,$00 selects
;              single and falls to FIN_7.
; ----------------------------------------------------------------------
FIN_4:
        ; restore the cursor (the peeked char was only for the exponent-vs-keyword test)
        POP HL
        JR Z,FIN_5
        ; real 'E' exponent: keep double only if the value is already double, else force single
        LD A,(VALTYP)
        CP VT_DBL
        JR Z,FIN_7
        ; selector 0 => FIN_TYPE_FIXUP coerces the value to single precision
        LD A,$00
        JR FIN_7
; ----------------------------------------------------------------------
; FIN_5 -- keyword case (E followed by l/L/q/Q): re-read the letter and re-dispatch so the
;          number ends before the 'E'.
;   In:        HL -> the letter after 'E' (restored by FIN_4); reached only when l/L/q/Q
;              matched in FIN_3.
;   Out:       A = that letter; falls into FIN_6. In FIN_6 none of the suffix/exponent compares
;              match l/L/q/Q, so FIN_6's JR NZ,FIN_9 fires and the number is finalized with the
;              'E' (and the keyword) left unconsumed for the statement scanner.
;   Clobbers:  A.
;   Algorithm: LD A,(HL) reloads the letter and falls through to the FIN_6 terminator
;              classifier, which treats it as a non-suffix terminator. [RE] This is the
;              ELSE/EQV disambiguation tail, NOT a double-exponent ('d') marker path.
; ----------------------------------------------------------------------
FIN_5:
        ; [RE] reload the letter after 'E' (ELSE/EQV case); FIN_6 will treat it as a terminator and end the number before 'E'
        LD A,(HL)
; ----------------------------------------------------------------------
; FIN_6 -- classify a non-digit terminator: dispatch the type-suffix characters and the
;          'd'/'D' double-exponent marker.
;   In:        A = the candidate character; HL -> just past it.
;   Out:       '%' ($25) -> FIN_12 (integer suffix); '#' ($23) -> FIN_13 (double suffix);
;              '!' ($21) -> FIN_14 (single suffix); 'd'/'D' ($64/$44) -> FIN_7 (double exponent);
;              any other char -> FIN_9 (no suffix: finalize with the accumulated scale).
;   Clobbers:  A,F.
;   Algorithm: A cascade of CP/JP-Z comparisons against the type-suffix punctuation and the
;              two double-exponent letter forms. The 'd'/'D' case shares FIN_7 with the 'e'/'E'
;              exponent path because both introduce a decimal exponent field; for 'd'/'D' the
;              char in A is itself nonzero, so FIN_7's OR A leaves NZ and FIN_TYPE_FIXUP coerces
;              the literal to double.
; ----------------------------------------------------------------------
FIN_6:
        ; '%' integer type suffix
        CP $25
        JP Z,FIN_12
        ; '#' double type suffix
        CP $23
        JP Z,FIN_13
        ; '!' single type suffix
        CP $21
        JP Z,FIN_14
        ; 'd'/'D' double-precision exponent marker: parse it like 'e'/'E' (FIN_7), forcing double
        CP $64
        JR Z,FIN_7
        CP $44
        ; no suffix or exponent: finalize the value with the scale accumulated so far
        JR NZ,FIN_9
; ----------------------------------------------------------------------
; FIN_7 -- exponent-field handler: fix the literal's type, then scan the signed decimal
;          exponent (the digits after e/E/d/D).
;   In:        A = type selector with its Z flag: Z (A=0) => force single, NZ => force/keep
;              double (A is VT_DBL from FIN_4 or the 'd'/'D' char from FIN_6); HL -> first char
;              of the exponent field; D = exponent-sign accumulator.
;   Out:       Value coerced to single or double (FIN_TYPE_FIXUP); the exponent sign consumed
;              (FIN_EXP_SIGN_SCAN decrements D for '-'); falls into FIN_8 to read the exponent
;              digits.
;   Clobbers:  A,B,C,D,E,H,L,F; FAC; VALTYP.
;   Algorithm: OR A sets Z from the selector (Z => single in FIN_TYPE_FIXUP). Coerce the type,
;              CHRGET past the marker, then FIN_EXP_SIGN_SCAN reads an optional '+'/'-' exponent
;              sign (it pre-DECs D and re-INCs it for '+'/none, so D ends decremented only for
;              '-') and backs up HL if no sign so FIN_8 re-reads the char as the first exponent
;              digit.
; ----------------------------------------------------------------------
FIN_7:
        ; set Z from the selector: Z => coerce to single, NZ => coerce to double
        OR A
        CALL FIN_TYPE_FIXUP
        ; step past the e/E/d/D marker to the exponent field
        CALL CHRGET
        ; consume the optional exponent sign (decrements D for '-')
        CALL FIN_EXP_SIGN_SCAN
; ----------------------------------------------------------------------
; FIN_8 -- accumulate the explicit decimal-exponent digits, then apply the exponent's sign.
;   In:        HL -> exponent digits; D = exponent-sign accumulator (decremented to $FF for
;              '-', else $00); E = exponent magnitude built by FIN_EXP_DIGIT.
;   Out:       E = signed explicit exponent (negated if D indicated '-'); HL past the digits.
;              Falls into FIN_9 to combine with the fractional-digit count.
;   Clobbers:  A,D,E,H,L,F.
;   Algorithm: Loop: CHRGET; while carry (a digit) accumulate via FIN_EXP_DIGIT (E=E*10+digit,
;              range-guarded). On the first non-digit, INC D: if D was $FF ('-' seen) it wraps
;              to $00 (Z) and the code falls through to negate E (XOR A; SUB E; LD E,A);
;              otherwise (NZ) jump to FIN_9 with E left positive.
; ----------------------------------------------------------------------
FIN_8:
        ; read next exponent char; carry => another exponent digit
        CALL CHRGET
        ; accumulate the digit into the exponent magnitude E
        JP C,FIN_EXP_DIGIT
        ; end of exponent digits: D was $FF iff a '-' was seen, so wrapping to 0 (Z) marks a negative exponent
        INC D
        JR NZ,FIN_9
        ; negative exponent: E = -E
        XOR A
        SUB E
        LD E,A
; ----------------------------------------------------------------------
; FIN_9 -- compute the net decimal scale and hand off to the power-of-ten scaler.
;   In:        E = explicit decimal exponent (from FIN_8, 0 if none); B = count of fractional
;              digits seen after the decimal point; HL -> next char; FAC = running value.
;   Out:       E = E - B (the net power-of-ten to apply); the scan cursor saved on the stack;
;              falls into FIN_10.
;   Clobbers:  A,E,H,L,F.
;   Algorithm: PUSH HL to preserve the cursor across the scaling loop, then LD A,E; SUB B;
;              LD E,A folds the fractional-digit count into the exponent: each digit after the
;              '.' was accumulated as if integral, so the value must be divided by an extra
;              power of ten per fractional digit; net scale = explicit exponent E minus B.
; ----------------------------------------------------------------------
FIN_9:
        ; preserve the scan cursor across the power-of-ten scaling loop
        PUSH HL
        ; net decimal scale = explicit exponent E minus the fractional-digit count B
        LD A,E
        SUB B
        LD E,A
; ----------------------------------------------------------------------
; FIN_10 -- apply the net power-of-ten scale, then finalize (sign + type) and return the
;           parsed number.
;   In:        E = signed decimal scale; FAC = unscaled magnitude; the saved leading-sign flag
;              is on the stack (Z => the literal had a leading '-'); VALTYP = the literal's type.
;   Out:       FAC = the fully scaled, signed value. For a value that ended up single-precision,
;              a final integer-range/boundary check runs (FP_TO_INT_RANGE, with FMUL_7 pushed as
;              the overflow hook). RET to FIN's caller (via the FIN_RETURN_COPY_FLAG tail).
;   Clobbers:  A,B,C,D,E,H,L,F; FAC; VALTYP.
;   Algorithm: Loop multiplying by ten while E>0 (CALL P,FIN_MUL10) or dividing while E<0
;              (CALL M,FIN_DIV10), each helper stepping E toward 0; JR NZ loops until E==0.
;              Restore HL, recover the leading-sign flag, and CALL Z,FP_NEGATE_CHECKED to apply
;              a '-'. FRMEVL_TEST_TYPE then RET PE -- which returns for int, double, AND string
;              (every type whose VALTYP-3 byte has even parity); only the SINGLE case (parity
;              odd, PO) falls through. [RE] On that single leg, push FMUL_7 (overflow hook) and
;              CALL FP_TO_INT_RANGE, which catches the exact +-32768 boundary (storing -32768 as
;              int16) and otherwise lets the overflow hook fire; the precise reason a value lands
;              here as single rather than already typed is INFERRED (it is the integer-mantissa
;              promotion edge from FIN_ACCUM_DIGIT), not fully traced.
; ----------------------------------------------------------------------
FIN_10:
        ; E>0: multiply the value by ten and decrement E
        CALL P,FIN_MUL10
        ; E<0: divide the value by ten and increment E
        CALL M,FIN_DIV10
        JR NZ,FIN_10
        POP HL
        POP AF
        PUSH HL
        ; apply the remembered leading '-' sign (Z was set when FIN_1 saw the minus)
        CALL Z,FP_NEGATE_CHECKED
        POP HL
        CALL FRMEVL_TEST_TYPE
        ; [RE] return for int/double/string (VALTYP-3 has even parity); only single (PO) falls through
        RET PE
        PUSH HL
        LD HL,FMUL_7
        PUSH HL
        ; [RE] single leg only: +-32768 integer-range/boundary check (FMUL_7 = overflow hook pushed above)
        CALL FP_TO_INT_RANGE
        RET
; ----------------------------------------------------------------------
; FIN_11 -- decimal-point handler: mark the point seen so later digits count as fractional,
;           and promote a still-integer value to single precision so the fraction can be held.
;   In:        HL -> char after the '.'; C = decimal-point sentinel ($FF until the first point);
;              B = fractional-digit count; VALTYP = current type.
;   Out:       A second '.' (C already incremented past $FF) ends the number -> FIN_9. Otherwise
;              the value is coerced to single if it was integer/single-and-not-double
;              (FIN_TYPE_FIXUP via the carry leg), and scanning resumes at FIN_2; subsequent
;              digits now increment B (because C has become $00).
;   Clobbers:  A,C,F (plus the type-fixup clobbers); VALTYP.
;   Algorithm: FRMEVL_TEST_TYPE sets carry iff VALTYP<8 (not double) and is used both to gate
;              the fixup and (its earlier effect) to keep parity flags. INC C advances the
;              decimal-point sentinel: first '.' takes C $FF->$00 (Z, NOT taken by JR NZ),
;              a second '.' takes C $00->$01 (NZ -> JR NZ,FIN_9 ends the number). CALL C,
;              FIN_TYPE_FIXUP (carry => not double) coerces an integer/single accumulator to
;              single, then JP FIN_2 continues the scan with the point now recorded so each
;              following digit bumps B.
; ----------------------------------------------------------------------
FIN_11:
        CALL FRMEVL_TEST_TYPE
        ; advance the decimal-point sentinel: first '.' takes C $FF->$00 (continue); a second '.' (NZ) ends the number. After this, fractional digits increment B in FIN_ACCUM_DIGIT
        INC C
        JR NZ,FIN_9
        ; carry (value not yet double) => coerce an integer/single accumulator to single so the fraction can be held
        CALL C,FIN_TYPE_FIXUP
        ; resume scanning; subsequent digits are now counted as fractional (B)
        JP FIN_2
; ----------------------------------------------------------------------
; FIN_12 -- '%' integer-suffix handler: arrange to coerce the final value to a 16-bit integer.
;   In:        HL -> the '%'; the leading-sign flag is on the stack.
;   Out:       Consumes the suffix; rebuilds the stack so the finalize path runs FN_CINT (force
;              to integer) first and the FMUL_7 overflow hook second, then re-pushes the sign
;              flag and joins FIN_9.
;   Clobbers:  A,H,L,F; stack.
;   Algorithm: CHRGET past the '%'. POP AF recovers the leading-sign flag; build the return
;              chain on the stack: PUSH HL (cursor), PUSH FMUL_7 (overflow hook, runs last),
;              PUSH FN_CINT (force-integer, runs first because pushed last), then re-PUSH AF
;              (sign). JR FIN_9 to scale and finalize; on the way out the stacked FN_CINT
;              narrows the value to int16 and FMUL_7 guards overflow.
; ----------------------------------------------------------------------
FIN_12:
        ; consume the '%' suffix
        CALL CHRGET
        ; recover the leading-sign flag so it can be re-stacked above the coercion chain
        POP AF
        PUSH HL
        LD HL,FMUL_7
        PUSH HL
        ; stack the force-to-integer routine to run first as the literal is finalized
        LD HL,FN_CINT
        PUSH HL
        PUSH AF
        JR FIN_9
; ----------------------------------------------------------------------
; FIN_13 -- '#' double-suffix handler: coerce the literal to double precision.
;   In:        A = the '#' char ($23, nonzero); HL -> the '#'.
;   Out:       OR A clears Z (A nonzero) so the shared FIN_14 tail runs FIN_TYPE_FIXUP's double
;              leg (FN_CDBL); suffix consumed; joins FIN_9 to finalize.
;   Clobbers:  A,F (plus FIN_14/FIN_TYPE_FIXUP clobbers); VALTYP.
;   Algorithm: OR A forces NZ and falls straight into FIN_14, which runs the type fixup (NZ =>
;              double), consumes the suffix char, and rejoins FIN_9.
; ----------------------------------------------------------------------
FIN_13:
        ; force NZ (A='#' is nonzero) so the shared FIN_14 fixup coerces to double precision
        OR A
; ----------------------------------------------------------------------
; FIN_14 -- '!' single-suffix handler (and the shared tail for '#'): coerce the type per the
;           Z flag, consume the suffix, and finalize.
;   In:        Z flag selects the coercion: Z => single (FN_CSNG), NZ => double (FN_CDBL).
;              Reached directly for '!' (Z set, because the FIN_6 'CP $21' that matched leaves
;              Z) or fallen into from FIN_13 (NZ, double). HL -> the suffix char.
;   Out:       Value coerced to single or double; suffix consumed; joins FIN_9 to scale and
;              return.
;   Clobbers:  A,B,C,D,E,H,L,F; VALTYP.
;   Algorithm: CALL FIN_TYPE_FIXUP (Z=>single, NZ=>double), CHRGET past the suffix, JR FIN_9.
; ----------------------------------------------------------------------
FIN_14:
        ; coerce to single (Z, the '!' case) or double (NZ, fallen in from '#')
        CALL FIN_TYPE_FIXUP
        ; consume the type-suffix character
        CALL CHRGET
        JR FIN_9
; ----------------------------------------------------------------------
; FIN_TYPE_FIXUP -- coerce the FAC's numeric type during parsing, preserving all registers.
;   In:        Z flag selects the target type: Z set => single (FN_CSNG); Z clear => double
;              (FN_CDBL). FAC = current value; VALTYP = current type.
;   Out:       FAC re-typed to single or double; VALTYP updated. A,B,C,D,E,H,L all restored to
;              their entry values (the scan state survives the coercion).
;   Clobbers:  Nothing visible (every register saved/restored); FAC and VALTYP change.
;   Algorithm: PUSH HL/DE/BC/AF to protect the scanner's register state, then CALL Z,FN_CSNG
;              (single) or, after re-reading the saved flags (POP AF), CALL NZ,FN_CDBL (double).
;              POP BC/DE/HL restores everything and RET. NOTE: the existing one-line file
;              comment above this label wrongly says 'FN_CINT when Z, else FN_CSNG when NZ' --
;              the code is FN_CSNG (Z) / FN_CDBL (NZ); the comment should be corrected.
; ----------------------------------------------------------------------
FIN_TYPE_FIXUP:
        PUSH HL
        PUSH DE
        PUSH BC
        PUSH AF
        ; Z => coerce the running value to single precision
        CALL Z,FN_CSNG
        POP AF
        ; NZ => coerce the running value to double precision
        CALL NZ,FN_CDBL
        POP BC
        POP DE
        POP HL
        RET
; ----------------------------------------------------------------------
; FIN_MUL10 -- multiply the running FAC value by ten, count permitting (FIN scaling step).
;   In:        A = signed scale count (number of *10 steps still owed, >= 0 here); FAC = partially-parsed
;              number; VALTYP selects single vs double.  Flags reflect A on entry (caller's CALL P, so
;              A >= 0 including A == 0).
;   Out:       FAC *= 10 (one step); A decremented by one (DEC_A_RET tail) so the caller re-tests its sign.
;              RET immediately with A unchanged when A == 0 (Z on entry).
;   Clobbers:  A, B, C, D, E, H, L, F, FAC, ARG temp ($0CBA) on the double path.
;   Algorithm: Guard: if the count reached zero (Z) return without scaling.  Otherwise fall into
;              FIN_MUL10_DO to do exactly one *10 (single- or double-precision per VALTYP parity), then
;              DEC A so the FIN scaling loop converges toward zero.
; ----------------------------------------------------------------------
FIN_MUL10:
        ; no scaling owed: count exhausted, return the value as-is
        RET Z
; ----------------------------------------------------------------------
; FIN_MUL10_DO -- perform exactly one FAC *= 10, dispatched by precision (no count guard).
;   In:        FAC = current value; VALTYP selects the path; A = caller's scale count (preserved across).
;   Out:       FAC = FAC * 10 (single via FP_SCALE2, or double via DP_MUL10); A restored unchanged on
;              return, then the shared DEC_A_RET tail decrements it.  Also reached directly by the FOUT
;              output formatter (CALL FIN_MUL10_DO at $5A7D) to scale a value for printing.
;   Clobbers:  B, C, D, E, H, L, F, FAC, ARG temp ($0CBA) on the double path; A preserved across the multiply.
;   Algorithm: Save A (the count).  Type-test the FAC: FRMEVL_TEST_TYPE returns parity ODD (PO) for
;              single precision and parity EVEN (PE) for double precision (the parity of VALTYP-3).
;              Dispatch CALL PO,FP_SCALE2 for single or CALL PE,DP_MUL10 for double -- both compute
;              value*10 = (value*4 + value)*2 in their own width.  Restore A and fall into DEC_A_RET.
; ----------------------------------------------------------------------
FIN_MUL10_DO:
        PUSH AF
        ; classify the FAC: parity ODD => single precision, parity EVEN => double precision
        CALL FRMEVL_TEST_TYPE
        PUSH AF
        ; single-precision *10 (PO = VALTYP single)
        CALL PO,FP_SCALE2
        POP AF
        ; double-precision *10 (PE = VALTYP double)
        CALL PE,DP_MUL10
        POP AF
; ----------------------------------------------------------------------
; DEC_A_RET -- shared 'decrement the count in A and return' tail.
;   In:        A = a digit/exponent/scale counter.
;   Out:       A = A - 1, with S/Z flags reflecting the result; RET.
;   Clobbers:  A, F.
;   Algorithm: One DEC A then RET.  Used as the tail of FIN_MUL10_DO (each *10 step burns one owed
;              scale count) and called conditionally by the FOUT exponent formatter (CALL NZ,DEC_A_RET
;              at $5986 and $59EB) to step its decimal-exponent counter; the sign of the result drives
;              the caller's mul-vs-div decision.
; ----------------------------------------------------------------------
DEC_A_RET:
        DEC A
        RET
; ----------------------------------------------------------------------
; FIN_DIV10 -- divide the running FAC value by ten, counting one step (FIN fractional/scale-down step).
;   In:        A = signed scale count (negative here, owing /10 steps); FAC = current value; VALTYP
;              selects single vs double.  Reached via the caller's CALL M (count negative).
;   Out:       FAC /= 10 (one step); A incremented by one (toward zero) so the FIN loop converges.
;              Also called by the FOUT formatter (CALL M,FIN_DIV10 at $5990/$59FC and $5A84) to bring
;              an out-of-range magnitude back into the printable window.
;   Clobbers:  A, B, C, D, E, H, L, F, FAC, ARG/temp cells.  DE, HL saved and restored.
;   Algorithm: Save DE/HL/A.  Type-test the FAC: parity ODD (PO) => single, parity EVEN (PE) => double.
;              Dispatch CALL PO,FDIV_BY_TEN (single FAC/10.0) or CALL PE,FIN_DSCALE_DIV10 (double /10
;              via the 0.1 multiply for small magnitudes / iterative refinement for large).  Restore
;              A/HL/DE and INC A to record that one /10 step was performed (decimal-exponent bookkeeping).
; ----------------------------------------------------------------------
FIN_DIV10:
        PUSH DE
        PUSH HL
        PUSH AF
        ; classify the FAC: parity ODD => single precision, parity EVEN => double precision
        CALL FRMEVL_TEST_TYPE
        PUSH AF
        ; single-precision /10 (PO = VALTYP single)
        CALL PO,FDIV_BY_TEN
        POP AF
        ; double-precision /10 (PE = VALTYP double)
        CALL PE,FIN_DSCALE_DIV10
        POP AF
        POP HL
        POP DE
        ; one /10 step done: step the scale count toward zero
        INC A
        RET
; ----------------------------------------------------------------------
; FIN_ACCUM_DIGIT -- accumulate one ASCII decimal digit into the running number (the FIN main digit path).
;   In:        HL -> the current digit char in the source text (its value is '0'..'9'); carry SET (caller
;              reached here via JP C, the CHRGET 'is a digit' flag).  B = digits-since-decimal-point
;              counter, C = fractional-place flag/counter ($FF before a '.', 0 after it), set by FIN_1
;              /FIN_11.  FAC ($0CB1) holds the running integer mantissa while the value still fits 16 bits;
;              VALTYP tracks int/single/double as the value is promoted.
;   Out:       The digit is folded in: while integer, FAC = FAC*10 + digit (16-bit); on 16-bit overflow
;              the value is promoted to single, and if it then reaches 2,000,000 to double, continuing
;              the multiply-accumulate in float.  B is bumped by one per fractional digit (so FIN can
;              later scale by 10^-fracdigits).  Control returns to FIN_2 (via FIN_DIGIT_DONE) for the next char.
;   Clobbers:  A, B, C, D, E, H, L, F, FAC, ARG/temp cells.  DE/BC/HL are pushed and unwound at FIN_DIGIT_DONE.
;   Algorithm: First advance the place counter: B = B + C + carry, where carry is the (always-set here)
;              'is a digit' flag.  Before the decimal point C = $FF so B + $FF + 1 leaves B unchanged;
;              after the point C = 0 so each digit increments B (counting fractional places).  Save BC/HL,
;              fetch the digit and SUB $30 to its 0..9 value, and stash it.  Type-test the FAC: if already
;              floating (sign positive) jump to FIN_FLOAT_ACCUM_DIGIT to accumulate in float.  Otherwise
;              (still integer) load the 16-bit accumulator from FAC; if it is >= 3277 ($0CCD = ceil(32768
;              /10), so *10 would overflow 16 bits) bail to FIN_PROMOTE_TO_SINGLE.  Else compute
;              HL = HL*10 (HL+HL,+HL,+DE=x5,+HL=x10) + digit; if the high bit is now set (>= 32768, signed
;              overflow) promote via FIN_DIGIT_OVF_TO_FLOAT, otherwise store HL back to FAC and loop to FIN_2.
; ----------------------------------------------------------------------
FIN_ACCUM_DIGIT:
        PUSH DE
        ; advance the place counter: B = B + C + carry (carry is always set here, so no-op before the decimal point where C=$FF, +1 per fractional digit after it where C=0)
        LD A,B
        ADC A,C
        LD B,A
        PUSH BC
        PUSH HL
        ; fetch the ASCII digit at the text pointer
        LD A,(HL)
        ; convert ASCII '0'..'9' to its numeric value 0..9
        SUB $30
        PUSH AF
        CALL FRMEVL_TEST_TYPE
        ; value already promoted to float (sign positive) -> accumulate this digit in floating point
        JP P,FIN_FLOAT_ACCUM_DIGIT
        ; still integer: load the 16-bit running accumulator
        LD HL,(FAC)
        ; threshold 3277 = ceil(32768/10): at or above this, *10 would overflow the signed 16-bit accumulator
        LD DE,$0CCD
        CALL CMP_HL_DE
        ; accumulator too large to multiply by 10 in 16 bits (FAC >= 3277) -> promote to single precision
        JR NC,FIN_PROMOTE_TO_SINGLE
        LD D,H
        LD E,L
        ; HL = HL*10: double, double, +original (=x5), double again
        ADD HL,HL
        ADD HL,HL
        ADD HL,DE
        ADD HL,HL
        POP AF
        LD C,A
        ; add the new digit (C = digit) into HL*10
        ADD HL,BC
        LD A,H
        OR A
        ; result went negative (>= 32768): overflowed signed 16-bit range -> promote, re-adding the digit in float
        JP M,FIN_DIGIT_OVF_TO_FLOAT
        ; still fits: store the updated 16-bit integer accumulator
        LD (FAC),HL
; ----------------------------------------------------------------------
; FIN_DIGIT_DONE -- common epilogue of the FIN digit-accumulate: unwind and fetch next char.
;   In:        Stack holds the saved HL (text pointer), BC (place/digit counters) and DE pushed by
;              FIN_ACCUM_DIGIT; FAC holds the updated running value.
;   Out:       HL/BC/DE restored; control transfers to FIN_2 to scan and classify the next source
;              character (another digit, a '.', an exponent marker, a type suffix, or end).
;   Clobbers:  H, L, B, C, D, E (restored from the stack), F.
;   Algorithm: POP HL, POP BC, POP DE to balance the three pushes made at FIN_ACCUM_DIGIT entry, then
;              JP FIN_2.  Reached from the integer-stored path, the overflow-promote path, and both the
;              single- and double-precision float-accumulate paths -- the single shared exit of one digit.
; ----------------------------------------------------------------------
FIN_DIGIT_DONE:
        POP HL
        POP BC
        POP DE
        ; digit folded in: go scan and classify the next source character
        JP FIN_2
; ----------------------------------------------------------------------
; FIN_DIGIT_OVF_TO_FLOAT -- 16-bit integer accumulate overflowed; re-stage the digit and promote.
;   In:        C = the current digit value (0..9); the integer HL*10+digit overflowed signed 16 bits.
;              The original digit push was already consumed (POPped) by the integer-add path.
;   Out:       The digit is re-pushed (so the float path can re-add it), then falls into
;              FIN_PROMOTE_TO_SINGLE to widen the accumulator to single precision.
;   Clobbers:  A, F; pushes the digit on the stack.
;   Algorithm: Recover the digit into A (LD A,C), PUSH AF to re-stage it for the float accumulate (the
;              earlier POP AF that consumed it happened at the ADD HL,BC step), then fall through into
;              FIN_PROMOTE_TO_SINGLE.  This is the path taken when the 16-bit product itself overflows
;              (as opposed to the pre-test catching it via the 3277 threshold).
; ----------------------------------------------------------------------
FIN_DIGIT_OVF_TO_FLOAT:
        ; re-stage the just-added digit so the float path can add it again after promotion
        LD A,C
        PUSH AF
; ----------------------------------------------------------------------
; FIN_PROMOTE_TO_SINGLE -- widen the integer accumulator to single precision, arm the crossover test.
;   In:        FAC ($0CB1) = the 16-bit integer accumulator; the digit (0..9) is on the stack.
;   Out:       FAC = single-precision float of the integer; VALTYP = VT_SNG; carry SET (SCF) to signal
;              the float-accumulate path to run the 2,000,000 single->double crossover check.
;   Clobbers:  A, B, C, D, E, H, L, F, FAC.
;   Algorithm: CALL INT_TO_SINGLE floats the 16-bit FAC into single precision, then SCF sets the flag
;              that FIN_FLOAT_ACCUM_DIGIT reads to mean 'this value just left integer territory -- check
;              whether it must go double'.  Falls straight into FIN_FLOAT_ACCUM_DIGIT.
; ----------------------------------------------------------------------
FIN_PROMOTE_TO_SINGLE:
        ; widen the 16-bit integer accumulator to single precision
        CALL INT_TO_SINGLE
        ; carry := 1 to request the single->double crossover test in the float path
        SCF
; ----------------------------------------------------------------------
; FIN_FLOAT_ACCUM_DIGIT -- floating-point digit-accumulate dispatcher (single vs double).
;   In:        FAC = running value in float form; the digit (0..9) is on the stack; carry distinguishes
;              the source: carry CLEAR means already double (entered from FIN_ACCUM_DIGIT's JP P with a
;              double FAC), carry SET means single (just promoted via SCF, or staying single).
;   Out:       FAC = FAC*10 + digit, computed in single or double precision; control reaches
;              FIN_DIGIT_DONE to unwind and fetch the next char.
;   Clobbers:  A, B, C, D, E, H, L, F, FAC, ARG/temp cells.
;   Algorithm: If carry is clear (already double) jump to FIN_DOUBLE_ACCUM_DIGIT.  Otherwise (single)
;              compare the FAC against the constant 2,000,000 ($9474/$2400 in MBF single = the ~7-digit
;              precision limit) via FCOMP.  FCOMP returns sign POSITIVE when FAC >= operand, so
;              JP P,FIN_WIDEN_TO_DOUBLE is taken when FAC >= 2,000,000: the value has exhausted single's
;              ~7-digit precision, so widen to double and accumulate there.  If FAC < 2,000,000 (fall
;              through) stay single: FP_SCALE2 does FAC*=10, then POP the digit and FIN_FINALIZE pushes
;              value*10, floats the digit and FADD_ALIGNs them (FAC = value*10 + digit), then loop to
;              FIN_DIGIT_DONE.
;   [RE]:      The 2,000,000 threshold encodes MS BASIC-80's single-precision crossover: once the integer
;              part reaches ~7 significant digits, further digits are accumulated in double precision to
;              preserve them.  Constant value verified by MBF decode of $94/$74/$24/$00 = 2000000.0.
;              [CORRECTED] The comparison direction was reversed in the peer spec: widen-to-double is the
;              FAC>=2,000,000 case, stay-single is the FAC<2,000,000 case (FCOMP positive == FAC>=operand,
;              cross-checked against FOUT_SCALE10's ~199999.89 normalization bound).
; ----------------------------------------------------------------------
FIN_FLOAT_ACCUM_DIGIT:
        ; already double (carry clear): skip the crossover test, accumulate in double
        JR NC,FIN_DOUBLE_ACCUM_DIGIT
        ; single->double crossover constant: MBF single 2,000,000 (the ~7-digit single-precision limit)
        LD BC,$9474
        LD DE,$2400
        ; compare the running single FAC against 2,000,000 (FCOMP returns positive when FAC >= operand)
        CALL FCOMP
        ; FAC >= 2,000,000: single's ~7-digit precision is exhausted -> widen to double and accumulate there
        JP P,FIN_WIDEN_TO_DOUBLE
        ; FAC < 2,000,000: still fits single precision, multiply the running value by 10
        CALL FP_SCALE2
        POP AF
        ; add the digit: push value*10, float the digit, FADD_ALIGN them into FAC (reuses FIN_FINALIZE's scale-and-add tail)
        CALL FIN_FINALIZE
        JR FIN_DIGIT_DONE
; ----------------------------------------------------------------------
; FIN_WIDEN_TO_DOUBLE -- promote the single FAC to double precision, then accumulate.
;   In:        FAC = single-precision running value that has reached/exceeded 2,000,000; the digit is on the stack.
;   Out:       FAC widened to double (zero mantissa extension, VALTYP = VT_DBL); falls into
;              FIN_DOUBLE_ACCUM_DIGIT to compute FAC*10 + digit in double precision.
;   Clobbers:  A, H, L, F, FAC, VALTYP.
;   Algorithm: CALL FP_CLEAR_EXT zeroes the double-precision low mantissa cells (the bytes the single
;              form did not use) and marks the value double, then fall through to the double accumulate.
;              Reached when FCOMP found FAC >= 2,000,000 (single precision exhausted).
; ----------------------------------------------------------------------
FIN_WIDEN_TO_DOUBLE:
        ; widen single -> double: zero the extension mantissa bytes and mark VALTYP double
        CALL FP_CLEAR_EXT
; ----------------------------------------------------------------------
; FIN_DOUBLE_ACCUM_DIGIT -- accumulate one digit into the FAC in double precision.
;   In:        FAC = double-precision running value; the digit (0..9) is on the stack.
;   Out:       FAC = FAC*10 + digit (full double precision); JR FIN_DIGIT_DONE to unwind and fetch the
;              next source char.
;   Clobbers:  A, B, C, D, E, H, L, F, FAC, ARG temp ($0CBA).
;   Algorithm: DP_MUL10 computes FAC *= 10 in double.  FP_ARG_TO_TEMP2 copies that value*10 into the ARG
;              temp ($0CBA).  POP the pending digit, FLOAT_A floats it into the FAC (single), FP_CLEAR_EXT
;              widens that digit to double, then DADD adds ARG (value*10) to FAC (the digit) giving FAC =
;              value*10 + digit.  Loop to FIN_DIGIT_DONE.
; ----------------------------------------------------------------------
FIN_DOUBLE_ACCUM_DIGIT:
        ; value *= 10 in double precision
        CALL DP_MUL10
        ; stash value*10 in the ARG temp ($0CBA) so it survives loading the digit into the FAC
        CALL FP_ARG_TO_TEMP2
        POP AF
        ; float the pending digit into the FAC
        CALL FLOAT_A
        ; widen the digit to double precision before the add
        CALL FP_CLEAR_EXT
        ; FAC = ARG(value*10) + FAC(digit): the double-precision accumulate
        CALL DADD
        JR FIN_DIGIT_DONE
; ----------------------------------------------------------------------
; FIN_FINALIZE -- finalize a freshly parsed numeric literal and complete it via the FP add path
;   In:        FAC holds the value built by the FIN ASCII->float scanner. Two register words
;              saved by the FIN digit-accumulate path (FIN_ACCUM_DIGIT) sit on the stack; they
;              are the second addend (ARG) for the floating-point add, NOT an evaluator frame.
;   Out:       FAC re-floated/normalized, then control transfers into FADD_ALIGN (via
;              FIN_FLOAT_RETURN), which adds ARG and RETs to the FIN caller with the result.
;   Clobbers:  A, BC, DE, HL, FAC; pops the two saved register words as the FADD ARG.
;   Algorithm: FAC_PUSH saves the running FAC, FLOAT_A re-floats/normalizes the accumulated
;              value, then fall into FIN_FLOAT_RETURN which loads ARG from the two stacked words
;              and jumps into FADD_ALIGN.
;   [RE] The exact identity of the two stacked words is inferred from the FIN_ACCUM_DIGIT
;        PUSH sequence and FADD_ALIGN's B/C/D/E ARG convention, not directly observed here.
; ----------------------------------------------------------------------
FIN_FINALIZE:
        ; save the in-progress FAC, then re-float/normalize the completed value
        CALL FAC_PUSH
        CALL FLOAT_A
; ----------------------------------------------------------------------
; FIN_FLOAT_RETURN -- load the FADD ARG operand from the stack and finish via the FP add path
;   In:        FAC = the running accumulator. The top two stack words hold the second operand
;              for the add (consumed as ARG: B=exponent, C=MSB|sign, D=mid, E=LSB -- the
;              FADD_ALIGN convention).
;   Out:       Jumps to FADD_ALIGN, which adds ARG into FAC and RETs to the FIN caller; control
;              does not return here.
;   Clobbers:  BC, DE (loaded as the ARG operand), plus whatever FADD_ALIGN touches.
;   Algorithm: POP BC / POP DE load the second addend into the FADD_ALIGN B/C/D/E ARG registers,
;              then JP FADD_ALIGN performs the floating-point add. Shared entry: the integer-add
;              overflow path also jumps here after promoting both operands to single precision,
;              so the add finishes in floating point.
;   [RE] That the two popped words are the FADD ARG (rather than a saved evaluator/precedence
;        frame) is inferred from FADD_ALIGN's documented B/C/D/E input convention; not a return
;        frame unwind.
; ----------------------------------------------------------------------
FIN_FLOAT_RETURN:
        POP BC
        POP DE
        JP FADD_ALIGN
; ----------------------------------------------------------------------
; FIN_EXP_DIGIT -- accumulate one digit of the E/D exponent field of a numeric literal
;   In:        E = exponent accumulated so far; (HL) -> the current ASCII digit '0'-'9'.
;   Out:       E = E*10 + digit on the in-range path. If E was already >= 10 the JR enters
;              FIN_EXP_SATURATE+1, whose LD E,$7F clamps E to $7F (forcing downstream overflow);
;              both paths continue to JP FIN_8 to read the next exponent character.
;   Clobbers:  A, E.
;   Algorithm: Guard E < 10 (CP $0A / JR NC). On the in-range path compute E*10 (LD A,E; RLCA
;              twice = *4; ADD A,E = *5; RLCA = *10), add the ASCII digit, subtract '0', store
;              to E. On the >= 10 path enter the +1 cover at FIN_EXP_SATURATE to saturate E.
; ----------------------------------------------------------------------
FIN_EXP_DIGIT:
        LD A,E
        CP $0A
        ; exponent already >= 10: enter the +1 cover to saturate E to $7F (literal will overflow)
        JR NC,FIN_EXP_SATURATE+1
        ; compute E*10: RLCA twice (=*4), ADD A,E (=*5), RLCA (=*10)
        RLCA
        RLCA
        ADD A,E
        RLCA
        ; fold in the ASCII digit, then SUB '0' to get its numeric value
        ADD A,(HL)
        SUB $30
        LD E,A
; ----------------------------------------------------------------------
; FIN_EXP_SATURATE -- exponent-overflow cover; continue scanning the exponent field
;   In:        Entered aligned ($5623) on the normal accumulate path; entered +1 ($5624) from
;              FIN_EXP_DIGIT's range guard to saturate E.
;   Out:       Falls into JP FIN_8 to read the next exponent character.
;   Clobbers:  none on the aligned path (the JP M is never taken); E=$7F on the +1 path.
;   Algorithm: The 3-byte JP M,$7F1E (FA 1E 7F) is a coded overlap. On the accumulate path the
;              sign is always positive (E*10+digit stays < 100) so the JP M is not taken and the
;              1E 7F operand bytes are skipped to reach JP FIN_8. On the +1 entry those bytes
;              execute as LD E,$7F, clamping the exponent so the literal overflows. Both converge
;              at JP FIN_8.
;   [RE] VERIFIED: the existing inline note documents this flag-skip; MBASIC twin byte-identical.
; ----------------------------------------------------------------------
FIN_EXP_SATURATE:
        JP M,$7F1E
        JP FIN_8
; ----------------------------------------------------------------------
; OVERR_SIGN_POSITIVE -- overflow-finalize entry that forces a POSITIVE saturated result
;   In:        an overflow has been detected by an FP operation.
;   Out:       Enters FP_ERROR_FINALIZE with carry clear (positive sign selected).
;   Clobbers:  flags (carry cleared).
;   Algorithm: OR A clears carry so FP_ERROR_FINALIZE picks +MBF max, then JP FP_ERROR_FINALIZE.
;   [RE] UNREFERENCED in this build (no incoming jump found) -- a vestigial OVERR entry retained
;        from MS BASIC-80. The byte immediately after the JP (a POP AF) is also UNREACHED in this
;        image; in stock MS BASIC the OVERR entries chain by fall-through, but here this entry
;        jumps away, so that POP AF is dead. UNKNOWN whether any +1 cover was intended.
; ----------------------------------------------------------------------
OVERR_SIGN_POSITIVE:
        ; clear carry -> saturated overflow result will be positive (+max)
        OR A
        JP FP_ERROR_FINALIZE
        POP AF
; ----------------------------------------------------------------------
; OVERR_SIGN_FROM_ARGS -- overflow-finalize that signs the result from the two operand signs
;   In:        Reached from the MUL/DIV exponent-combine over/underflow path (JP OVERR_SIGN_FROM_ARGS in
;              the EXP_OVUN_TEST region). FACHI ($0CB3) holds one operand sign; the other sign
;              comes from C (single) or the L_0CC0 cell (double), chosen by VALTYP.
;   Out:       Carry = XOR of the two operand sign bits (the product/quotient sign); enters
;              FP_ERROR_FINALIZE which stores the correspondingly-signed MBF max.
;   Clobbers:  A, HL, flags.
;   Algorithm: PUSH HL; HL=FACHI; FRMEVL_TEST_TYPE sets parity. JP PO (single) -> OVERR_SIGN_FROM_C
;              takes the second sign from C; otherwise (double) LD A,(L_0CC0). Then XOR (HL)
;              merges the two sign bytes, RLA shifts the combined sign bit into carry, POP HL,
;              JP FP_ERROR_FINALIZE.
;   [RE] The PUSH HL at entry is balanced by the POP HL after the XOR. The single-vs-double
;        discriminator is the PARITY of (VALTYP-3) returned by FRMEVL_TEST_TYPE: parity-odd (PO)
;        => single, parity-even (PE, e.g. VT_DBL) => the L_0CC0 path.
; ----------------------------------------------------------------------
OVERR_SIGN_FROM_ARGS:
        PUSH HL
        LD HL,FACHI
        ; [RE] FRMEVL_TEST_TYPE sets parity from VALTYP-3: PO=single (use C), PE=double (use L_0CC0)
        CALL FRMEVL_TEST_TYPE
        JP PO,OVERR_SIGN_FROM_C
        LD A,(L_0CC0)
        JP OVERR_SIGN_COMBINE
; ----------------------------------------------------------------------
; OVERR_SIGN_FROM_C -- single-precision branch: use register C as the second operand's sign byte
;   In:        C = the second operand sign byte (the parity-odd / single-precision case).
;   Out:       A = C; falls into the shared XOR/RLA sign-combine (OVERR_SIGN_COMBINE).
;   Clobbers:  A.
;   Algorithm: LD A,C then fall through into OVERR_SIGN_COMBINE (XOR (HL)/RLA/POP HL tail).
; ----------------------------------------------------------------------
OVERR_SIGN_FROM_C:
        LD A,C
; ----------------------------------------------------------------------
; OVERR_SIGN_COMBINE -- XOR the two operand sign bytes and place the result sign into carry
;   In:        A = one operand sign byte; (HL) = FACHI ($0CB3), the other operand's sign byte.
;   Out:       Carry = combined result sign bit; HL restored; control -> FP_ERROR_FINALIZE.
;   Clobbers:  A, flags (HL popped/restored).
;   Algorithm: XOR (HL) merges the sign bits, RLA shifts bit 7 into carry, POP HL restores the
;              caller's HL, then JP FP_ERROR_FINALIZE.
; ----------------------------------------------------------------------
OVERR_SIGN_COMBINE:
        XOR (HL)
        RLA
        POP HL
        JP FP_ERROR_FINALIZE
; ----------------------------------------------------------------------
; OVERR_SIGN_FROM_FPFLAG -- overflow-finalize entry that takes the sign from FP_SIGN_FLAG
;   In:        FP_SIGN_FLAG ($0CB5) holds the intended result sign in bit 7.
;   Out:       Enters the RLA sign-into-carry tail (FP_ERROR_SIGN_RLA, =FP_ERROR_SIGN_RLA) -> FP_ERROR_FINALIZE.
;   Clobbers:  A, flags.
;   Algorithm: LD A,(FP_SIGN_FLAG); JP FP_ERROR_SIGN_RLA (RLA then finalize).
;   [RE] UNREFERENCED in this build -- vestigial OVERR entry. The byte after the JP (a POP AF) is
;        likewise UNREACHED here; UNKNOWN whether a +1 cover was intended (no caller observed).
; ----------------------------------------------------------------------
OVERR_SIGN_FROM_FPFLAG:
        LD A,(FP_SIGN_FLAG)
        JP FP_ERROR_SIGN_RLA
        POP AF
; ----------------------------------------------------------------------
; OVERR_POP2 -- overflow-finalize that discards two stacked words first (EXP overflow)
;   In:        Reached from FN_EXP_3 (JP OVERR_POP2) on EXP() overflow (FACHI positive). Two
;              words pushed by the EXP evaluation chain sit above the caller frame; FACHI
;              ($0CB3) carries the result sign.
;   Out:       Stack trimmed by two words; falls into OVERR_SIGN_FROM_FAC, which reads the FACHI
;              sign and finalizes.
;   Clobbers:  flags, stack (two words dropped).
;   Algorithm: POP AF twice to abandon the in-flight EXP call chain (mirrors the symmetric POP
;              AF/POP AF underflow branch in FN_EXP), then fall into OVERR_SIGN_FROM_FAC.
;   [RE] The exact identity of the two discarded words is inferred from FN_EXP's matching push/
;        pop pattern, not directly observed here.
; ----------------------------------------------------------------------
OVERR_POP2:
        ; discard two stacked words from the aborted EXP chain before finalizing
        POP AF
        POP AF
; ----------------------------------------------------------------------
; OVERR_SIGN_FROM_FAC -- overflow-finalize that signs the result from the FAC sign byte
;   In:        FACHI ($0CB3) bit 7 = the result sign. Reached from FP_SCALE2 (single-precision
;              *10) exponent overflow, and via OVERR_POP2 (EXP overflow).
;   Out:       Carry = FACHI bit 7; enters FP_ERROR_FINALIZE.
;   Clobbers:  A, flags.
;   Algorithm: LD A,(FACHI); RLA shifts the sign bit into carry; JP FP_ERROR_FINALIZE so the
;              stored MBF max takes the FAC's sign.
; ----------------------------------------------------------------------
OVERR_SIGN_FROM_FAC:
        LD A,(FACHI)
        RLA
        JP FP_ERROR_FINALIZE
; ----------------------------------------------------------------------
; OVERR_POP1 -- overflow-finalize that discards one stacked word, then signs from FP_SIGN_FLAG (CPL)
;   In:        Reached from FADD_ROUND_CARRY (JP OVERR_POP1) when a round-up (+1 ULP) carries
;              out of the mantissa and bumps the exponent past max. One word above the caller
;              frame; FP_SIGN_FLAG ($0CB5) holds the un-complemented sign.
;   Out:       Stack trimmed by one word; result sign = complement of FP_SIGN_FLAG; -> FP_ERROR_FINALIZE.
;   Clobbers:  A, flags, one stack word.
;   Algorithm: POP AF drops the stacked word, then fall into OVERR_SIGN_FROM_FPFLAG_CPL which
;              loads FP_SIGN_FLAG, CPLs it and RLAs the inverted sign bit into carry.
;   [RE] The identity of the discarded word is inferred, not directly observed.
; ----------------------------------------------------------------------
OVERR_POP1:
        ; drop one stacked word from the aborted round-carry path before finalizing
        POP AF
; ----------------------------------------------------------------------
; OVERR_SIGN_FROM_FPFLAG_CPL -- overflow-finalize, sign = complement of FP_SIGN_FLAG
;   In:        FP_SIGN_FLAG ($0CB5) holds the un-complemented sign. Reached from several exponent-
;              overflow sites: the single-precision add front-end (FADD_ALIGN_GO), double add
;              (DADD_ALIGNED), double round-carry (DP_ROUND_CARRY_PROPAGATE), double divide (DDIV)
;              and double *10 (DP_MUL10).
;   Out:       Carry = NOT FP_SIGN_FLAG bit 7; enters FP_ERROR_FINALIZE.
;   Clobbers:  A, flags.
;   Algorithm: LD A,(FP_SIGN_FLAG); CPL inverts it; fall into FP_ERROR_SIGN_RLA (RLA puts the
;              inverted sign bit into carry) then JP FP_ERROR_FINALIZE.
;   [RE] Caller list compiled from the JP OVERR_SIGN_FROM_FPFLAG_CPL sites; it spans BOTH single- and double-
;        precision overflow paths, not double-only.
; ----------------------------------------------------------------------
OVERR_SIGN_FROM_FPFLAG_CPL:
        LD A,(FP_SIGN_FLAG)
        CPL
; ----------------------------------------------------------------------
; FP_ERROR_SIGN_RLA -- shift the computed sign bit (A bit 7) into carry, then finalize
;   In:        A = sign byte (bit 7 is the intended result sign).
;   Out:       Carry = A bit 7; control -> FP_ERROR_FINALIZE.
;   Clobbers:  A, flags.
;   Algorithm: RLA moves bit 7 into carry; JP FP_ERROR_FINALIZE selects +/- MBF max accordingly.
; ----------------------------------------------------------------------
FP_ERROR_SIGN_RLA:
        RLA
        JP FP_ERROR_FINALIZE
; ----------------------------------------------------------------------
; DIV0_SIGN_FROM_C -- division-by-zero finalize, dividend sign in C
;   In:        C = dividend sign byte. Reached from FDIV (JP Z,DIV0_SIGN_FROM_C) when the divisor
;              (FAC) is zero.
;   Out:       A = C (sign); jumps to DIV0_SET_MSG (DIV0_SET_MSG) which RLAs the sign into carry,
;              selects the 'Division by zero' message and enters FP_ERROR_FINALIZE.
;   Clobbers:  A.
;   Algorithm: LD A,C; JP DIV0_SET_MSG (DIV0_SET_MSG).
; ----------------------------------------------------------------------
DIV0_SIGN_FROM_C:
        LD A,C
        JP DIV0_SET_MSG
; ----------------------------------------------------------------------
; DIV0_SIGN_DOUBLE -- division-by-zero finalize for DDIV; stage magnitude, take the dividend sign
;   In:        Reached from DDIV (JP Z,DIV0_SIGN_DOUBLE) when the divisor exponent is 0. FAC_DBL/FAC
;              hold the dividend; VALTYP selects double vs single.
;   Out:       The all-ones constant (MBF_MAX_NEG) is copied over FAC_DBL ($0CAD..$0CB0); A = dividend
;              sign byte; control falls into DIV0_RESTORE_REGS -> DIV0_SET_MSG.
;   Clobbers:  A, DE, HL (PUSHed/POPped), FAC_DBL, L_0CAF.
;   Algorithm: PUSH HL/DE; FP_MOVE4 copies MBF_MAX_NEG ($FF,$FF,$FF,$FF) into FAC_DBL; re-store its
;              first byte to L_0CAF (this write is redundant given the move already filled $0CAF;
;              [RE] its purpose is UNKNOWN). FRMEVL_TEST_TYPE then picks the sign source: FACHI
;              on the parity-even (double) branch, L_0CC0 (DIV0_SIGN_NONDOUBLE) on parity-odd; POP DE/HL;
;              fall into DIV0_SET_MSG.
;   [RE] The FP_MOVE4 stages an all-ones magnitude before the sign decision; exactly why it
;        pre-fills FAC_DBL here (vs. relying on FP_ERROR_FINALIZE's own store) is UNKNOWN.
; ----------------------------------------------------------------------
DIV0_SIGN_DOUBLE:
        PUSH HL
        PUSH DE
        LD HL,FAC_DBL
        LD DE,MBF_MAX_NEG
        ; [RE] stage the all-ones constant (MBF_MAX_NEG) over the double mantissa before the sign decision
        CALL FP_MOVE4
        LD A,(MBF_MAX_NEG)
        LD (L_0CAF),A
        ; [RE] parity from VALTYP-3: PE=double -> dividend sign from FACHI; PO -> from L_0CC0
        CALL FRMEVL_TEST_TYPE
        JP PO,DIV0_SIGN_NONDOUBLE
        LD A,(FACHI)
        JP DIV0_RESTORE_REGS
; ----------------------------------------------------------------------
; DIV0_SIGN_NONDOUBLE -- single-precision branch: dividend sign comes from the L_0CC0 cell
;   In:        L_0CC0 ($0CC0) holds the dividend sign byte (the parity-odd / single case).
;   Out:       A = sign byte; falls into DIV0_RESTORE_REGS (POP DE/POP HL) then DIV0_SET_MSG.
;   Clobbers:  A.
;   Algorithm: LD A,(L_0CC0); fall into the shared register-restore + DIV0_SET_MSG tail.
; ----------------------------------------------------------------------
DIV0_SIGN_NONDOUBLE:
        LD A,(L_0CC0)
; ----------------------------------------------------------------------
; DIV0_RESTORE_REGS -- restore DE/HL saved by DIV0_SIGN_DOUBLE, then fall into DIV0_SET_MSG
;   In:        A = dividend sign byte; saved DE/HL on the stack.
;   Out:       DE, HL restored; control falls into DIV0_SET_MSG.
;   Clobbers:  DE, HL (restored).
;   Algorithm: POP DE / POP HL then drop into DIV0_SET_MSG.
; ----------------------------------------------------------------------
DIV0_RESTORE_REGS:
        POP DE
        POP HL
; ----------------------------------------------------------------------
; DIV0_SET_MSG -- select the 'Division by zero' message, then enter the common error finalize
;   In:        A = sign byte (bit 7 = result sign). Reached by DIV0_SIGN_* and by the power
;              operator (JP Z,DIV0_SET_MSG in POWER_OP_APPLY/FN_SQR) for 0^(negative).
;   Out:       Carry = result sign; the current-error-message pointer L_0848 = ERRMSG_
;              DIVISION_BY_ZERO; falls into FP_ERROR_FINALIZE.
;   Clobbers:  A, HL, flags, L_0848.
;   Algorithm: RLA moves the sign bit into carry; LD HL,ERRMSG_DIVISION_BY_ZERO; store it to the
;              current-error-message cell L_0848; fall into FP_ERROR_FINALIZE.
;   [RE] L_0848 is the live error-message pointer (cold-init = ERRMSG_OVERFLOW, $0577). Overflow
;        entries leave it at that default; the divide entries override it here.
; ----------------------------------------------------------------------
DIV0_SET_MSG:
        RLA
        ; divide-by-zero, not overflow: point the current-message cell L_0848 at 'Division by zero'
        LD HL,ERRMSG_DIVISION_BY_ZERO
        LD (L_0848),HL
; ----------------------------------------------------------------------
; FP_ERROR_FINALIZE -- common overflow / divide-by-zero finalize: store signed max, trap or warn
;   In:        Carry = result sign (clear = +, set = -); L_0848 -> the current error message
;              ('Overflow' by default, 'Division by zero' if set by DIV0_SET_MSG); VALTYP
;              selects single vs double; ON_ERROR_LINE = active ON ERROR handler (0 = none).
;   Out:       FAC = signed MBF max magnitude (MBF_MAX_SINGLE for +, MBF_MAX_NEG for -; FAC_DBL extended for
;              double). If a handler is armed, jumps to RAISE_OVERFLOW / RAISE_DIVISION_BY_ZERO.
;              Otherwise prints the message and RETs with the saturated FAC (MS BASIC overflow
;              is a non-fatal warning).
;   Clobbers:  A, BC, DE, HL, FAC; restores BC/DE/HL it saves; updates L_0CB6.
;   Algorithm: Save regs and the sign (PUSH AF twice). If ON_ERROR_LINE != 0, skip straight to
;              the store step (FP_ERROR_STORE_SAT). Otherwise check the L_0CB6 print guard: print on 0;
;              on 1 bump it to 2 and print; on 2 skip (avoids re-printing on re-entry). After the
;              optional print, recover the sign and FP_MOVE4 the matching MBF max into the FAC
;              (and FAC_DBL if double). Finally, if a handler is armed normalize L_0848 and RAISE
;              the matching error; else reset L_0848 to 'Overflow', restore regs and RET.
;   [RE] L_0CB6 is a dual-use cell (elsewhere the FRMEVL function-eval-in-progress flag, and at
;        $4539 a screen INVERSE flag -- see the unreconciled DUAL-USE CAVEAT in the source). Its
;        use here as a one-shot error-print guard is [RE] inference. L_0848 is the live error-
;        message pointer cell (cold-init ERRMSG_OVERFLOW).
; ----------------------------------------------------------------------
FP_ERROR_FINALIZE:
        PUSH HL
        PUSH BC
        PUSH DE
        ; stash the result sign (carry) across the message-print decision
        PUSH AF
        PUSH AF
        ; is an ON ERROR handler armed? if so, skip the message print and go store+raise (trap)
        LD HL,(ON_ERROR_LINE)
        LD A,H
        OR L
        JP NZ,FP_ERROR_STORE_SAT
        ; [RE] print guard: print on 0 or 1 (bumping 1->2), suppress on 2, to avoid a repeat print on re-entry
        LD A,(L_0CB6)
        OR A
        JP Z,FP_ERROR_PRINT_MSG
        CP $01
        JP NZ,FP_ERROR_STORE_SAT
        LD A,$02
        LD (L_0CB6),A
; ----------------------------------------------------------------------
; FP_ERROR_PRINT_MSG -- print the current FP error message ('Overflow'/'Division by zero') + CRLF
;   In:        L_0848 -> the NUL-terminated message string.
;   Out:       Message written to the console followed by CR/LF; CURSOR_POS updated.
;   Clobbers:  A, HL (and whatever STROUT_NOFLAGS/STROUT_PUTC touch).
;   Algorithm: Load the message pointer from L_0848, STROUT_NOFLAGS it, store the returned column
;              to CURSOR_POS, then emit CR ($0D) and LF ($0A). The non-fatal warning path: print
;              the message and continue with the saturated value.
; ----------------------------------------------------------------------
FP_ERROR_PRINT_MSG:
        LD HL,(L_0848)
        CALL STROUT_NOFLAGS
        LD (CURSOR_POS),A
        ; terminate the warning line with CR then LF
        LD A,$0D
        CALL STROUT_PUTC
        LD A,$0A
        CALL STROUT_PUTC
; ----------------------------------------------------------------------
; FP_ERROR_STORE_SAT -- store the signed MBF max-magnitude constant into the FAC
;   In:        Carry (saved on stack, recovered by POP AF) = result sign: clear -> +max, set ->
;              -max; VALTYP selects single vs double.
;   Out:       FAC = the saturated MBF max (positive or negative); for double, FAC_DBL is also
;              filled with the all-ones constant (continued in FP_ERROR_STORE_SAT_MOVE).
;   Clobbers:  A, DE, HL, FAC.
;   Algorithm: POP AF recovers the sign. LD HL,FAC. Choose DE = MBF_MAX_SINGLE on NC (positive, top
;              mantissa byte $7F) or MBF_MAX_NEG on C (negative, $FF), then fall into FP_ERROR_STORE_
;              SAT_MOVE which FP_MOVE4s the 4-byte constant into the FAC.
;   [RE] The MBF max has all-ones mantissa low bytes and exponent $FF; the top mantissa byte
;        ($7F vs $FF) carries the sign bit, giving +max vs -max.
; ----------------------------------------------------------------------
FP_ERROR_STORE_SAT:
        POP AF
        LD HL,FAC
        LD DE,MBF_MAX_SINGLE
        ; positive (NC) -> +max constant MBF_MAX_SINGLE ($7F top byte); negative -> -max constant MBF_MAX_NEG ($FF top byte)
        JP NC,FP_ERROR_STORE_SAT_MOVE
        LD DE,MBF_MAX_NEG
; ----------------------------------------------------------------------
; FP_ERROR_STORE_SAT_MOVE -- copy the selected MBF max into the FAC (and extend FAC_DBL if double)
;   In:        HL -> FAC; DE -> the chosen MBF max constant (MBF_MAX_SINGLE or MBF_MAX_NEG); VALTYP.
;   Out:       FAC = the saturated max; for double, FAC_DBL also filled with the all-ones
;              constant MBF_MAX_NEG.
;   Clobbers:  A, DE, HL, FAC, FAC_DBL.
;   Algorithm: FP_MOVE4 copies the 4-byte constant into the FAC. FRMEVL_TEST_TYPE; if parity-even
;              (double) FP_MOVE4 MBF_MAX_NEG into FAC_DBL to fill the extra mantissa bytes; then fall
;              into FP_ERROR_DISPATCH.
;   [RE] The double branch is selected by the PARITY of (VALTYP-3) from FRMEVL_TEST_TYPE (PO ->
;        single, skip the extend), not by carry.
; ----------------------------------------------------------------------
FP_ERROR_STORE_SAT_MOVE:
        CALL FP_MOVE4
        CALL FRMEVL_TEST_TYPE
        JP PO,FP_ERROR_DISPATCH
        LD HL,FAC_DBL
        LD DE,MBF_MAX_NEG
        CALL FP_MOVE4
; ----------------------------------------------------------------------
; FP_ERROR_DISPATCH -- route to the ON ERROR trap, or fall through to the warning return
;   In:        ON_ERROR_LINE (0 = no handler); L_0848 -> the current message; FAC = saturated value.
;   Out:       Handler armed -> normalize L_0848 to ERRMSG_OVERFLOW and JP RAISE_OVERFLOW (if the
;              current message was Overflow) or RAISE_DIVISION_BY_ZERO. No handler -> FP_ERROR_RETURN.
;   Clobbers:  A, DE, HL, L_0848.
;   Algorithm: If ON_ERROR_LINE is zero, JP FP_ERROR_RETURN. Otherwise CMP_HL_DE compares the
;              current message pointer (L_0848) against ERRMSG_OVERFLOW, force L_0848 to
;              ERRMSG_OVERFLOW, then JP Z,RAISE_OVERFLOW (was Overflow) else JP RAISE_DIVISION_BY_
;              ZERO, so the trap fires with the correct ERR code.
; ----------------------------------------------------------------------
FP_ERROR_DISPATCH:
        ; handler armed? if not, just return the saturated value (warning already printed)
        LD HL,(ON_ERROR_LINE)
        LD A,H
        OR L
        JP Z,FP_ERROR_RETURN
        LD HL,(L_0848)
        LD DE,ERRMSG_OVERFLOW
        CALL CMP_HL_DE
        LD HL,ERRMSG_OVERFLOW
        LD (L_0848),HL
        ; raise to the ON ERROR trap: Overflow if the message pointer was Overflow, else Division by zero
        JP Z,RAISE_OVERFLOW
        JP RAISE_DIVISION_BY_ZERO
; ----------------------------------------------------------------------
; FP_ERROR_RETURN -- untrapped exit: reset the message cell and return with the saturated FAC
;   In:        FAC = signed MBF max; saved DE/BC/HL on the stack; the saved sign word on top
;              (discarded by POP AF).
;   Out:       L_0848 reset to ERRMSG_OVERFLOW (the default); DE/BC/HL restored; RET to the
;              caller with the saturated value (execution continues after the non-fatal warning).
;   Clobbers:  A, HL, L_0848 (restored regs otherwise).
;   Algorithm: POP AF discards the saved sign, reset L_0848 to ERRMSG_OVERFLOW for the next
;              fault, POP DE/BC/HL, RET.
; ----------------------------------------------------------------------
FP_ERROR_RETURN:
        POP AF
        ; reset the error-message cell L_0848 to its 'Overflow' default for the next fault
        LD HL,ERRMSG_OVERFLOW
        LD (L_0848),HL
        POP DE
        POP BC
        POP HL
        RET
; ----------------------------------------------------------------------
; MBF_MAX_SINGLE -- the largest POSITIVE Microsoft Binary Format value (approx +1.7E38)
;   Bytes: $FF,$FF,$7F,$FF = mantissa low $FF, mid $FF, high $7F (bit 7 clear => positive),
;          exponent $FF (maximum).
;   Use:   FP_ERROR_STORE_SAT_MOVE FP_MOVE4s this into the FAC on a POSITIVE overflow / divide-
;          by-zero so the result saturates to the signed maximum rather than wrapping.
; ----------------------------------------------------------------------
MBF_MAX_SINGLE:
        DEFB    $FF,$FF,$7F,$FF
; ----------------------------------------------------------------------
; MBF_MAX_NEG -- all-ones MBF constant: the NEGATIVE single max, also the double-mantissa fill
;   Bytes: $FF,$FF,$FF,$FF.
;   Use:   FP_ERROR_STORE_SAT copies this into the FAC on a NEGATIVE overflow (high mantissa byte
;          $FF => sign bit set, giving approx -1.7E38). For double-precision results it is also
;          FP_MOVE4'd into FAC_DBL to fill the extra mantissa bytes with $FF, and DIV0_SIGN_DOUBLE
;          pre-stages it as the saturated magnitude over FAC_DBL.
;   [RE] This is a 4-byte all-ones pattern, NOT a distinct 8-byte double-precision constant.
; ----------------------------------------------------------------------
MBF_MAX_NEG:
        DEFB    $FF,$FF,$FF,$FF
; ----------------------------------------------------------------------
; PRINT_IN_LINENO -- print ' in <linenumber>' (MS BASIC INPRT); prints ' in ' then prints HL
;   In:        HL = the line number to print (unsigned 16-bit).
;   Out:       Console shows ' in ' followed by the decimal line number. HL is preserved across
;              the ' in ' print, then consumed by FOUT. Does NOT return here -- it falls into FOUT.
;   Clobbers:  A, BC, DE, HL, and the FOUT scratch buffer at $0CC3.
;   Algorithm: PUSH HL (save the line number); LD HL,L_0CED and STROUT the literal ' in ' text;
;              POP HL to restore the line number; then FALL THROUGH into FOUT (no RET). FOUT
;              converts HL to a decimal ASCII string in the $0CC3 buffer and, via the
;              PUT_STR_TEMP_2 return it pushes, prints it. Used by the STOP/Break and error line
;              reporters and the RENUM 'Undefined line' message.
;   [RE] L_0CED is the ' in ' separator string ($0CED, DEFB " in "), distinct from the FOUT
;        digit buffer at $0CC3.
; ----------------------------------------------------------------------
PRINT_IN_LINENO:
        PUSH HL
        ; print the ' in ' separator; the line number in HL is printed next by the fall-through into FOUT
        LD HL,L_0CED
        CALL STROUT
        POP HL

; ======================================================================
; NUMBER <-> ASCII (FOUT formatter)
; ======================================================================
; ----------------------------------------------------------------------
; FOUT -- integer fast-path number-to-ASCII: format the 16-bit value in HL and chain into the string-printer.
;   In:        HL = signed 16-bit value to format (e.g. the sign-on free-bytes count / integer STR$/PRINT).
;   Out:       HL -> NUL-terminated ASCII decimal string in the $0CC3 output buffer; control then enters the pushed PUT_STR_TEMP_2/STROUT continuation, which prints that string from (HL).
;   Clobbers:  A, BC, DE, HL, flags; FAC ($0CB1), VALTYP ($0B14), output buffer at $0CC3.
;   Algorithm: Pushes PUT_STR_TEMP_2 as the return target (so the formatted string is printed on RET), stores HL into the FAC as a VT_INT integer (FP_STORE_FAC_INT sets VALTYP=$02), and with A=0 (no PRINT USING flags) seeds the buffer head to a space (FOUT_SET_FORMAT, returns HL=$0CC3). It then jumps straight to FOUT_BODY_2, bypassing the FOUT_BODY/FOUT_BODY_1 sign-handling block. [RE] OR (HL) ORs A with the just-written space ($20): this clears carry and sets NZ, so at FOUT_BODY_2 neither the carry (PRINT USING E-field) test nor the zero-value early-out fires and the plain integer digit path is taken. The free-byte caller passes a non-negative count, so no '-'/'+' sign step is needed.
; ----------------------------------------------------------------------
FOUT:
        ; return into the string-print continuation (STROUT) once the number is formatted
        LD BC,PUT_STR_TEMP_2
        PUSH BC
        ; install the caller's 16-bit value into the FAC as an integer (VALTYP := VT_INT)
        CALL FP_STORE_FAC_INT
        XOR A
        ; A=0: no PRINT USING flags; seed the buffer head ($0CC3) with a space, HL -> head
        CALL FOUT_SET_FORMAT
        ; [RE] OR with the head space: clear carry + set NZ so FOUT_BODY_2 takes the plain integer path (no E-field, not the zero early-out)
        OR (HL)
        ; non-negative integer: skip the FOUT_BODY sign-handling block, go straight to digit emission
        JP FOUT_BODY_2
; ----------------------------------------------------------------------
; FOUT_2 -- ordinary FOUT entry: format the FAC value with NO PRINT USING flags.
;   In:        FAC ($0CB1 mantissa) = value; VALTYP ($0B14) = its type (int/single/double).
;   Out:       HL -> NUL-terminated ASCII string in the $0CC3 buffer (set by the FOUT_EXPONENT_4 / FOUT_EXPONENT_3 tail). RET to caller (no continuation is pushed, unlike FOUT).
;   Clobbers:  A, BC, DE, HL, flags, output buffer, scratch FP cells.
;   Algorithm: Loads A=0 (no format byte) and falls into FOUT_BODY, which does sign handling and then type dispatch. This is the plain PRINT/STR$/LIST entry point; the value's type (VALTYP) and the zero/sign of the FAC drive which digit generator runs.
; ----------------------------------------------------------------------
FOUT_2:
        ; no PRINT USING format flags for a plain PRINT/STR$ conversion
        XOR A
; ----------------------------------------------------------------------
; FOUT_BODY -- FOUT with PRINT USING format flags: store the flags, place the sign placeholder, then sign-test and dispatch.
;   In:        A = PRINT USING format byte (bit3=$08 force leading '+'; bit7 selects the PRINT USING exponential-field path; bit2/$04 sign-already-placed, bit4/$10 floating '$', bit5/$20 asterisk-fill consumed later by PRUSING_FIELD). FAC = value; VALTYP = type.
;   Out:       Format byte saved at $0B4A; buffer head seeded; optional '+' written; falls into FOUT_BODY_1 (sign test).
;   Clobbers:  A, HL, flags, $0B4A, buffer head ($0CC3).
;   Algorithm: FOUT_SET_FORMAT stores A at $0B4A and seeds the buffer head with a space (HL -> head). If the 'force +' flag (bit3/$08) is set, overwrite the head with '+'. Then fall into FOUT_BODY_1, which tests the FAC sign. [RE] the bit meanings beyond bit3 are inferred from the masks used here and in FOUT_BODY_2/PRUSING_FIELD.
; ----------------------------------------------------------------------
FOUT_BODY:
        ; store the format byte at $0B4A and seed the buffer head with a space
        CALL FOUT_SET_FORMAT
        ; [RE] PRINT USING 'force leading +' flag (bit3)?
        AND $08
        JR Z,FOUT_BODY_1
        ; yes: place a '+' as the sign placeholder
        LD (HL),$2B
; ----------------------------------------------------------------------
; FOUT_BODY_1 -- sign test: detect a negative FAC, write '-', and negate the FAC to its magnitude.
;   In:        HL -> buffer head (sign slot); FAC = value; VALTYP = type.
;   Out:       If FAC < 0: head := '-' and FAC := |FAC| (FP_NEGATE_CHECKED), and A forced NZ. If FAC >= 0: head unchanged. Either way falls into FOUT_BODY_2.
;   Clobbers:  A, BC, DE, HL, flags, FAC.
;   Algorithm: FP_TEST_SIGN clobbers HL (the integer path does LD HL,(FAC)), so EX DE,HL stashes the buffer pointer in DE across the call and restores it afterward. FP_TEST_SIGN returns A = -1/0/+1 (Z set when the value is zero -- that Z is what FOUT_BODY_2's zero early-out later relies on). On a non-negative result (JP P) jump to FOUT_BODY_2. On negative, store '-', negate the FAC to its magnitude, then OR H (H=$0C) forces A NZ so FOUT_BODY_2 does NOT take the zero early-out.
; ----------------------------------------------------------------------
FOUT_BODY_1:
        EX DE,HL
        ; type-aware sign of the FAC: A = -1/0/+1, Z set iff the value is zero
        CALL FP_TEST_SIGN
        EX DE,HL
        ; non-negative (incl. zero): keep the space/'+' placeholder and continue
        JP P,FOUT_BODY_2
        ; negative: overwrite the placeholder with '-'
        LD (HL),$2D
        PUSH BC
        PUSH HL
        ; fold to the magnitude so the rest of FOUT formats |value|
        CALL FP_NEGATE_CHECKED
        POP HL
        POP BC
        ; H=$0C, so A becomes non-zero: forces NZ so FOUT_BODY_2 skips the zero early-out
        OR H
; ----------------------------------------------------------------------
; FOUT_BODY_2 -- lay down the leading '0', then dispatch on the carried flags and VALTYP to the right digit path.
;   In:        HL -> sign slot; format byte at $0B4A; VALTYP ($0B14) = type; FAC = non-negative magnitude. Carry/Z flags are CARRIED IN from the entry (FOUT: OR(HL) -> NC/NZ; FOUT_BODY_1: FP_TEST_SIGN -> Z iff value==0).
;   Out:       Buffer head+1 := '0' (the always-present leading digit). Branches (does not return here) to one of: PRUSING_NUMFIELD (PRINT USING E-field), FOUT_EXPONENT_3 (value is zero -> just NUL-terminate the bare '0'), FOUT_DOUBLE_FMT (any float, single or double), or FOUT_DIGITS_INT+PRUSING_FIELD (integer).
;   Clobbers:  A, BC, DE, HL, flags.
;   Algorithm: INC HL past the sign and store '0' as the guaranteed first digit. Load the format byte into D, RLA to shift its bit7 into carry, then load A=VALTYP (which does NOT disturb carry/Z). Dispatch: (1) carry set (format bit7) -> PRUSING_NUMFIELD, the PRINT USING exponential-field path; (2) Z set (the value-is-zero flag carried from FP_TEST_SIGN) -> FOUT_EXPONENT_3, which NUL-terminates the lone '0'; (3) CP VT_SNG, JP NC -> VALTYP>=4 (single OR double float) goes to FOUT_DOUBLE_FMT; (4) otherwise (VALTYP<4, i.e. integer) seed BC=0, run FOUT_DIGITS_INT, fall into PRUSING_FIELD.
; ----------------------------------------------------------------------
FOUT_BODY_2:
        INC HL
        ; always emit a leading '0' digit slot (so e.g. .5 prints as 0.5, and a zero value prints as 0)
        LD (HL),$30
        LD A,(PRUSING_FORMAT_FLAGS)
        LD D,A
        ; shift format bit7 into carry: PRINT USING exponential field selected?
        RLA
        LD A,(VALTYP)
        ; format bit7: PRINT USING exponential-field path
        JP C,PRUSING_NUMFIELD
        ; value is zero (Z carried from FP_TEST_SIGN): terminate the lone '0' and return
        JP Z,FOUT_EXPONENT_3
        ; VALTYP < single -> integer path; >= single (single OR double) -> float path
        CP VT_SNG
        ; single or double float: route to the floating-point formatter
        JP NC,FOUT_DOUBLE_FMT
        LD BC,$0000
        ; integer value: emit its decimal digits, then fall into PRUSING_FIELD
        CALL FOUT_DIGITS_INT
; ----------------------------------------------------------------------
; PRUSING_FIELD -- PRINT USING numeric-field finisher: choose the fill character and prepend any '$'/'*'/sign in front of the laid-out digits.
;   In:        Output buffer at $0CC3 holds the formatted digit string (the sign slot at $0CC3, digits after). Format byte at $0B4A (bit2=$04 sign-already-placed, bit4=$10 floating '$', bit5=$20 asterisk-fill).
;   Out:       The fill character (space / '*' / '$') and an optional sign char are spliced in front of the number in the buffer. RET. [RE] B carries the chosen lead/sign char into PRUSING_FIELD_4.
;   Clobbers:  A, B, C, E, HL, flags.
;   Algorithm: Read the current head byte ($0CC3) into B (the sign placeholder set earlier) and default fill C=' '. Copy the format byte into E. If asterisk-fill (bit5) is set, set C='*'; if the head was already a non-space sign char and the sign-placed flag (bit2) is not set, also force the lead char B='*'. Then PRUSING_FIELD_1 writes the fill char and walks the digit string in the buffer via CHRGET to splice the '$'/sign. [RE] the exact PRINT USING bit assignments are inferred from these masks.
; ----------------------------------------------------------------------
PRUSING_FIELD:
        LD HL,L_0CC3
        LD B,(HL)
        ; default field fill character is a space
        LD C,$20
        LD A,(PRUSING_FORMAT_FLAGS)
        LD E,A
        ; [RE] asterisk-fill ('**') field requested (bit5)?
        AND $20
        JR Z,PRUSING_FIELD_1
        LD A,B
        CP C
        ; asterisk-fill: switch the fill character to '*'
        LD C,$2A
        JR NZ,PRUSING_FIELD_1
        LD A,E
        AND $04
        JP NZ,PRUSING_FIELD_1
        LD B,C
; ----------------------------------------------------------------------
; PRUSING_FIELD_1 -- write the fill char, then walk the formatted digit string for '.', 'E', 'D', '0', ','.
;   In:        HL -> current buffer byte; C = fill char; E = format flags.
;   Out:       Fill char stored; at end-of-string / 'E' / 'D' / '.' diverts to PRUSING_FIELD_2 (force a leading '0'); '0' or ',' loops here; any other char falls into PRUSING_FIELD_3.
;   Clobbers:  A, HL, flags.
;   Algorithm: Store C at (HL). CALL CHRGET advances HL through the OUTPUT buffer ($0CC3+) and re-fetches the next char (Z set at the $00 end-of-string terminator). On Z, 'E'/'D' or '.' -> PRUSING_FIELD_2; on '0' or ',' -> loop (still writing fill in the leading region); otherwise -> PRUSING_FIELD_3. NOTE: CHRGET here walks the formatted number in the buffer, not the program's format image.
; ----------------------------------------------------------------------
PRUSING_FIELD_1:
        ; lay down the fill character at this buffer position
        LD (HL),C
        ; advance through the formatted digit string in the buffer; Z at the NUL terminator
        CALL CHRGET
        JR Z,PRUSING_FIELD_2
        ; 'E' exponent marker reached -> force the leading zero
        CP $45
        JR Z,PRUSING_FIELD_2
        CP $44
        JR Z,PRUSING_FIELD_2
        CP $30
        JR Z,PRUSING_FIELD_1
        CP $2C
        JR Z,PRUSING_FIELD_1
        ; '.' decimal point reached -> force the leading zero
        CP $2E
        JR NZ,PRUSING_FIELD_3
; ----------------------------------------------------------------------
; PRUSING_FIELD_2 -- force a leading '0' when the number starts with '.', 'E' or 'D' (or is empty).
;   In:        HL just past the position that triggered it.
;   Out:       The byte before HL set to '0'; falls into PRUSING_FIELD_3.
;   Clobbers:  HL.
;   Algorithm: DEC HL and store '0', guaranteeing a digit precedes a bare decimal point or exponent (so '.##' prints '0.xx').
; ----------------------------------------------------------------------
PRUSING_FIELD_2:
        DEC HL
        ; ensure a '0' sits before a leading '.'/'E'/'D'
        LD (HL),$30
; ----------------------------------------------------------------------
; PRUSING_FIELD_3 -- splice a floating '$' in front of the number when the field requested it.
;   In:        E = format flags (bit4=$10 floating dollar); HL -> head of the digit region.
;   Out:       If bit4 set, '$' written just before the digits (HL backed up one); falls into PRUSING_FIELD_4.
;   Clobbers:  A, HL, flags.
;   Algorithm: Test the floating-dollar flag; if set, DEC HL and store '$' ($24) so the currency sign abuts the first significant digit. [RE] bit4 = floating-'$' inferred from the AND $10 mask.
; ----------------------------------------------------------------------
PRUSING_FIELD_3:
        LD A,E
        ; [RE] floating-dollar ('$$') field (bit4)?
        AND $10
        JR Z,PRUSING_FIELD_4
        DEC HL
        ; splice a '$' immediately before the number
        LD (HL),$24
; ----------------------------------------------------------------------
; PRUSING_FIELD_4 -- splice the saved lead/sign character unless a sign was already placed.
;   In:        E = format flags (bit2=$04 sign already emitted); B = the saved lead/sign char; HL -> front of the field.
;   Out:       If bit2 clear, B stored just before the number (HL backed up); RET either way.
;   Clobbers:  A, HL, flags.
;   Algorithm: If the 'sign already emitted' flag (bit2) is set, RET with nothing to add. Otherwise DEC HL and store B (the lead/sign char chosen in PRUSING_FIELD). [RE] bit2 = sign-already-placed inferred from the AND $04 mask (used here and in PRUSING_FIELD).
; ----------------------------------------------------------------------
PRUSING_FIELD_4:
        LD A,E
        ; [RE] was the sign already written by an earlier step (bit2)?
        AND $04
        ; sign already in place: nothing to splice
        RET NZ
        DEC HL
        ; place the saved lead/sign character in front of the number
        LD (HL),B
        RET
; ----------------------------------------------------------------------
; FOUT_SET_FORMAT -- store the PRINT USING format byte and reset the FOUT output buffer head.
;   In:        A = format flags byte (0 for plain PRINT/STR$).
;   Out:       $0B4A := A; ($0CC3) := ' ' (space, the leading sign slot); HL = $0CC3. RET.
;   Clobbers:  HL.
;   Algorithm: Save A into the format-flags cell ($0B4A), point HL at the output buffer ($0CC3), write a leading space (default sign placeholder), and return with HL at the buffer head for the caller to build the number.
; ----------------------------------------------------------------------
FOUT_SET_FORMAT:
        LD (PRUSING_FORMAT_FLAGS),A
        LD HL,L_0CC3
        ; seed the buffer head with a space (default sign placeholder)
        LD (HL),$20
        RET
; ----------------------------------------------------------------------
; FOUT_DOUBLE_FMT -- floating-point FOUT driver (single AND double): format the FAC float, then pick E vs D notation and the digit count.
;   In:        VALTYP ($0B14) >= VT_SNG (=4): single OR double. FAC ($0CB1) plus the double-extension cells FAC_DBL ($0CAD) and $0CAF hold the value; HL -> output buffer head; format byte at $0B4A.
;   Out:       Output buffer holds the formatted float; the saved FAC/extension cells are restored on the way out (FOUT_SET_FORMAT_5 / PRUSING_ESET_RESTORE tails); RET to FOUT's caller with HL -> string.
;   Clobbers:  A, BC, DE, HL, flags, FAC + extension cells, $0CB8 (force-E flag).
;   Algorithm: Saves the live FAC (FAC_PUSH) and the two double-extension words ($0CAD, $0CAF), clears the force-E flag $0CB8, and calls FOUT_CORE to round/scale and lay down the decimal digit string. FOUT_CORE itself is parameterized by precision (it does CP $05 on VALTYP), so this one path serves both single and double. It then scans the produced string via FOUT_SET_FORMAT_2/_4 -- first for 'E' (B=$45) then for 'D' (B=$44) -- counting significant digits in C to decide whether E/D scientific notation is needed (FOUT_SET_FORMAT_6). [RE-CORRECTION] this is FOUT OUTPUT formatting, NOT the FIN ASCII->float input parser: it calls FOUT_CORE and writes the output buffer; no text input is scanned. The pre-existing [RE] 'FIN core' comment is stale/wrong.
; ----------------------------------------------------------------------
FOUT_DOUBLE_FMT:
        ; save the live FAC value across the float formatting
        CALL FAC_PUSH
        EX DE,HL
        ; preserve the double-precision low-mantissa extension word ($0CAD)
        LD HL,(FAC_DBL)
        PUSH HL
        ; preserve the second double-extension word ($0CAF)
        LD HL,(L_0CAF)
        PUSH HL
        EX DE,HL
        PUSH AF
        XOR A
        ; clear the force-E-notation flag ($0CB8) before formatting
        LD (L_0CB8),A
        POP AF
        PUSH AF
        ; round, scale, and emit the decimal digit string (precision per VALTYP)
        CALL FOUT_CORE
        ; first pass: scan the produced string for an 'E' exponent
        LD B,$45
        LD C,$00
; ----------------------------------------------------------------------
; FOUT_SET_FORMAT_2 -- begin a scan of the formatted string for exponent letter B, with the digit counter reset.
;   In:        HL -> start of the digit string; B = exponent letter to find ('E'=$45 or 'D'=$44); C = digit counter (already 0 here).
;   Out:       Saves HL (string start), loads the first char, falls into FOUT_SET_FORMAT_3.
;   Clobbers:  A, HL, flags.
;   Algorithm: PUSH HL to remember the string start for the possible second pass, load (HL), and enter the per-character loop FOUT_SET_FORMAT_3.
; ----------------------------------------------------------------------
FOUT_SET_FORMAT_2:
        ; remember the string start in case the second ('D') pass is needed
        PUSH HL
        LD A,(HL)
; ----------------------------------------------------------------------
; FOUT_SET_FORMAT_3 -- per-character loop: count digits and stop at the exponent letter.
;   In:        A = current char; HL -> current char; B = exponent letter sought; C = running digit count.
;   Out:       On finding letter B -> FOUT_SET_FORMAT_6 (parse its exponent digits); otherwise falls into FOUT_SET_FORMAT_4 to advance.
;   Clobbers:  A, C, HL, flags.
;   Algorithm: Compare A to B (target 'E'/'D'); equal -> FOUT_SET_FORMAT_6. Otherwise, if the char is an ASCII digit ('0'..'9') bump the digit count C; then fall into FOUT_SET_FORMAT_4.
; ----------------------------------------------------------------------
FOUT_SET_FORMAT_3:
        ; reached the exponent letter being searched for?
        CP B
        JP Z,FOUT_SET_FORMAT_6
        ; char above '9' -> not a digit
        CP $3A
        JP NC,FOUT_SET_FORMAT_4
        ; char below '0' -> not a digit
        CP $30
        JP C,FOUT_SET_FORMAT_4
        ; count this digit
        INC C
; ----------------------------------------------------------------------
; FOUT_SET_FORMAT_4 -- advance to the next char; at end of string, switch the search from 'E' to 'D' once.
;   In:        HL -> current char; B = exponent letter currently sought.
;   Out:       Not NUL: loop to FOUT_SET_FORMAT_3 on the next char. At NUL: if B was 'E' ($45) reset B='D' ($44), C=0, restart from the saved start (FOUT_SET_FORMAT_2); if B was already 'D', fall into FOUT_SET_FORMAT_5 (string had no exponent).
;   Clobbers:  A, B, C, HL, flags.
;   Algorithm: INC HL, load next byte; non-zero continues the loop. At the NUL terminator, compare the just-used letter to 'D' ($44): if it differs (was 'E') swap in 'D', pop back to the saved string start, zero the count, and rescan; if it was already 'D', the string truly has no exponent and control falls through to FOUT_SET_FORMAT_5.
; ----------------------------------------------------------------------
FOUT_SET_FORMAT_4:
        INC HL
        LD A,(HL)
        ; end of the formatted string?
        OR A
        JP NZ,FOUT_SET_FORMAT_3
        ; prepare to retry the scan looking for 'D'
        LD A,$44
        CP B
        LD B,A
        POP HL
        LD C,$00
        ; first pass was 'E': rescan from the saved start looking for 'D'
        JP NZ,FOUT_SET_FORMAT_2
; ----------------------------------------------------------------------
; FOUT_SET_FORMAT_5 -- exit tail: restore the saved double-extension words and registers, then return.
;   In:        Stack holds (top->bottom) the saved AF, then the two double-extension words, then the FAC_PUSH words (FACHI, FAC).
;   Out:       FAC_DBL ($0CAD) and $0CAF restored; BC/DE restored from the FAC_PUSH; RET to FOUT's caller.
;   Clobbers:  A, BC, DE, HL, flags, FAC extension cells.
;   Algorithm: POP AF (discard the pushed AF), POP BC/POP DE to recover the two preserved extension words, EX DE,HL to land each in HL before storing them back to FAC_DBL ($0CAD) and $0CAF, then POP BC/POP DE to consume the FAC_PUSH words, and RET. This is the common landing point for 'no exponent needed' and 'exponent within precision' outcomes.
; ----------------------------------------------------------------------
FOUT_SET_FORMAT_5:
        POP AF
        POP BC
        POP DE
        EX DE,HL
        ; restore the saved double-precision low-extension word ($0CAD)
        LD (FAC_DBL),HL
        LD H,B
        LD L,C
        ; restore the saved second double-extension word ($0CAF)
        LD (L_0CAF),HL
        EX DE,HL
        POP BC
        POP DE
        RET
; ----------------------------------------------------------------------
; FOUT_SET_FORMAT_6 -- parse the signed exponent following the 'E'/'D' letter and decide whether scientific notation is forced.
;   In:        HL -> the matched 'E'/'D' letter; B = the letter; C = the significant-digit count from the scan.
;   Out:       On a leading '+' or on magnitude overflow (>=16) -> PRUSING_FIELD_ABORT (accept as-is, no force-E). On end of the exponent digits, compares digit-count+exponent against the precision window ($09 for 'E', $12 for 'D' via PRUSING_EXP_FITS_CHECK): in-range -> FOUT_SET_FORMAT_5 (accept); out-of-range -> PRUSING_ESET_EXP_OVF, which sets the $0CB8 force-E flag ($80). [RE] no error is raised here -- $0CB8 is a formatting flag, not a RAISE.
;   Clobbers:  A, B, C, H, HL, flags.
;   Algorithm: PUSH BC, zero the accumulator B, INC past the letter, and walk the exponent text (FOUT_SET_FORMAT_7) decimal-accumulating B = B*10 + digit. A leading '+' diverts to PRUSING_FIELD_ABORT; '-' to the FOUT_SET_FORMAT_8 negative branch. At the end the magnitude window (C significant digits + exponent) is checked against $09 ('E') or $12 ('D') to choose plain decimal vs forced E/D notation.
; ----------------------------------------------------------------------
FOUT_SET_FORMAT_6:
        PUSH BC
        ; accumulate the exponent magnitude here
        LD B,$00
        ; step past the 'E'/'D' letter to its exponent digits
        INC HL
        LD A,(HL)
; ----------------------------------------------------------------------
; FOUT_SET_FORMAT_7 -- exponent-digit accumulator: B := B*10 + digit, honoring a leading sign.
;   In:        A = current exponent char; HL -> it; B = running magnitude; C scratch.
;   Out:       On '+' -> PRUSING_FIELD_ABORT (accept, no force-E); on '-' -> FOUT_SET_FORMAT_8 (skip the sign, keep accumulating); a digit updates B; if B reaches $10 (>=16) -> PRUSING_FIELD_ABORT.
;   Clobbers:  A, B, C, flags.
;   Algorithm: Branch on '+' / '-'. For a digit: C = char-'0'; A = B; ADD A,A / ADD A,A / ADD A,B / ADD A,A computes B*10 (i.e. ((B*4)+B)*2), then ADD A,C adds the new digit; store back to B. If B has reached $10 the exponent is too large -> PRUSING_FIELD_ABORT.
; ----------------------------------------------------------------------
FOUT_SET_FORMAT_7:
        ; '+' exponent sign -> accept without forcing E-notation
        CP $2B
        JP Z,PRUSING_FIELD_ABORT
        ; '-' exponent sign -> negative-exponent branch
        CP $2D
        JP Z,FOUT_SET_FORMAT_8
        ; ASCII digit -> its numeric value
        SUB $30
        LD C,A
        LD A,B
        ADD A,A
        ; compute B*10 ( ((B*4)+B)*2 ) before adding the new digit
        ADD A,A
        ADD A,B
        ADD A,A
        ADD A,C
        LD B,A
        ; exponent magnitude overflow (>=16)?
        CP $10
        JP NC,PRUSING_FIELD_ABORT
; ----------------------------------------------------------------------
; FOUT_SET_FORMAT_8 -- continuation after a sign char: advance to the next exponent digit, then finalize the precision check.
;   In:        HL -> char just consumed; B = accumulated magnitude.
;   Out:       If the next char is non-NUL, loops to FOUT_SET_FORMAT_7. At NUL: H := B (the magnitude), and the precision check runs -- 'E' here ($09 window), 'D' via PRUSING_EXP_FITS_CHECK ($12 window) -- choosing accept (FOUT_SET_FORMAT_5) vs force-E (PRUSING_ESET_EXP_OVF).
;   Clobbers:  A, B, C, H, HL, flags.
;   Algorithm: INC HL, load the next char; non-zero loops back to accumulate. At end, move the magnitude into H and restore the letter into B. For 'E' ($45): A = C + H (digit count + exponent), CP $09 -- if >= the limit accept (FOUT_SET_FORMAT_5), else PRUSING_ESET_EXP_OVF sets the $0CB8 force-E flag. For 'D' the check is in PRUSING_EXP_FITS_CHECK against $12.
; ----------------------------------------------------------------------
FOUT_SET_FORMAT_8:
        ; advance to the next exponent character
        INC HL
        LD A,(HL)
        OR A
        JP NZ,FOUT_SET_FORMAT_7
        LD H,B
        POP BC
        LD A,B
        ; 'E' (single-precision exponent) -> use the $09 digit-window limit
        CP $45
        JP NZ,PRUSING_EXP_FITS_CHECK
        LD A,C
        ADD A,H
        ; does digit-count + exponent reach single precision's window limit?
        CP $09
        POP HL
        JP NC,FOUT_SET_FORMAT_5
; ----------------------------------------------------------------------
; PRUSING_ESET_EXP_OVF -- force the PRINT USING numeric field into E (scientific) notation
;   In:        Reached from the '^^^^' / 'E' exponent-format scanner: from FOUT_SET_FORMAT_8 when an 'E' format image was found but its computed width is small (C + H < 9), or jumped from PRUSING_EXP_FITS_CHECK
;   Out:       Sets the E-notation force flag L_0CB8 = $80 (FOUT_CORE later branches on this cell's sign), then JP PRUSING_ESET_RESTORE which restores the saved FAC/format frame and re-enters the digit core
;   Clobbers:  A; writes (L_0CB8)
;   Algorithm: Store $80 into L_0CB8 so the FOUT digit core formats this value in scientific notation, then transfer to PRUSING_ESET_RESTORE.
; ----------------------------------------------------------------------
PRUSING_ESET_EXP_OVF:
        ; set the E-notation force flag (L_0CB8=$80) the FOUT core reads
        LD A,$80
        LD (L_0CB8),A
        JP PRUSING_ESET_RESTORE
; ----------------------------------------------------------------------
; PRUSING_EXP_FITS_CHECK -- non-'E' image: decide fixed vs forced E-notation by total field width
;   In:        Entered (JP NZ) from FOUT_SET_FORMAT_8 when the trailing format char was NOT 'E' ($45). H = accumulated exponent-field digit value parsed by the scanner; C = fraction-digit count
;   Out:       If H + C >= $12 (18) the field is wide -> POP HL and JP FOUT_SET_FORMAT_5 (commit fixed format); otherwise JP PRUSING_ESET_EXP_OVF to force E-notation
;   Clobbers:  A; pops HL
;   Algorithm: A = H + C; CP $12; if no borrow (>=18) restore the buffer pointer and finish via the fixed-format exit, else fall back to the E-notation force path. [RE] H/C exact provenance inferred from the FOUT_SET_FORMAT_8 scanner (H=accumulated field value, C=fraction count).
; ----------------------------------------------------------------------
PRUSING_EXP_FITS_CHECK:
        LD A,H
        ; A = field digit-value (H) + fraction count (C)
        ADD A,C
        CP $12
        POP HL
        ; width >= 18: commit fixed format and restore the saved frame
        JP NC,FOUT_SET_FORMAT_5
        JP PRUSING_ESET_EXP_OVF
; ----------------------------------------------------------------------
; PRUSING_FIELD_ABORT -- abandon the exponent-field parse and revert to fixed format
;   In:        Entered from FOUT_SET_FORMAT_7 on a literal '+' in the exponent image, or from FOUT_SET_FORMAT_7/_8 when the accumulated field value overflows (CP $10, carry clear). Two work words are on the stack from the in-progress scan
;   Out:       Discards the two saved stack words and JP FOUT_SET_FORMAT_5 to format in ordinary fixed notation
;   Clobbers:  BC, HL (both popped and discarded)
;   Algorithm: POP BC / POP HL to unwind the partial scan frame, then jump to the fixed-format exit.
; ----------------------------------------------------------------------
PRUSING_FIELD_ABORT:
        ; discard the in-progress field scan frame and revert to fixed formatting
        POP BC
        POP HL
        JP FOUT_SET_FORMAT_5
; ----------------------------------------------------------------------
; PRUSING_ESET_RESTORE -- restore the saved FAC/format frame and fall into FOUT_CORE
;   In:        Stack holds the frame pushed by FOUT_DOUBLE_FMT before the format scan: the rounding/format byte A, then BC, then DE (the saved FAC_DBL low word and the L_0CAF (B,C) pair), then the FAC working-copy BC/DE. L_0CB8 already $80 (from PRUSING_ESET_EXP_OVF)
;   Out:       Restores FAC_DBL and L_0CAF, reloads the live FAC via FP_STORE_FAC, INC HL, and falls into FOUT_CORE (which now sees L_0CB8=$80 and emits E-notation). A on entry to FOUT_CORE = the popped VALTYP/format byte
;   Clobbers:  A, BC, DE, HL, (FAC_DBL), (L_0CAF), FAC
;   Algorithm: POP the format/rounding byte (A); POP BC/DE and write the low double-FAC word to FAC_DBL and the (B,C) pair to L_0CAF; POP the FAC working copy; CALL FP_STORE_FAC to reload the FAC; INC HL; fall through to FOUT_CORE. This restore path mirrors FOUT_SET_FORMAT_5 byte-for-byte except it continues into the digit core instead of RET.
; ----------------------------------------------------------------------
PRUSING_ESET_RESTORE:
        POP AF
        POP BC
        POP DE
        EX DE,HL
        ; restore the low word of the saved double-precision FAC
        LD (FAC_DBL),HL
        LD H,B
        LD L,C
        ; restore the saved (sign/MSB, exponent-or-fraction) FAC pair
        LD (L_0CAF),HL
        EX DE,HL
        POP BC
        POP DE
        ; reload the live FAC, then fall into the digit core
        CALL FP_STORE_FAC
        INC HL
; ----------------------------------------------------------------------
; FOUT_CORE -- normalize FAC, generate the rounded decimal digit string, trim trailing zeros
;   In:        FAC holds the (sign-stripped, non-negative) value; A = VALTYP (4 = single, 8 = double); HL -> output buffer just past the sign/leading-digit slot; L_0CB8 = E-notation force flag (sign bit set => scientific). Only caller is FOUT_DOUBLE_FMT (also reached via PRUSING_ESET_RESTORE fall-through)
;   Out:       Decimal digit string written at HL; HL backed to the last significant digit; A = residual count whose Z result selects the fixed tail (FOUT_EXPONENT_4) vs the E-notation tail (FOUT_EXPONENT); B = integer-digit count on the fixed path
;   Clobbers:  A, B, C, D, HL, FAC, FP temporaries used by FOUT_SCALE10/FOUT_DIGITS_FRAC
;   Algorithm: Derive the rounding precision D from VALTYP: CP $05 / SBC A,$00 / RLA / LD D,A / INC D gives D = 7 (single) or 17 (double). CALL FOUT_SCALE10 to scale FAC into digit-gen range and return the base-10 exponent in A. Read L_0CB8: if its sign bit is clear take FOUT_CORE_1 (value may print fixed); if set fall to FOUT_CORE_2 (force scientific digit layout). FOUT_CORE_1/_2 set B = integer-digit count, then FOUT_CORE_3 emits the leading '.'/zero run (FOUT_LEADING_FRAC) and the digits (FOUT_DIGITS_FRAC). FOUT_CORE_4 strips trailing '0's and a dangling '.'.
; ----------------------------------------------------------------------
FOUT_CORE:
        CP $05
        PUSH HL
        SBC A,$00
        RLA
        LD D,A
        INC D
        ; scale FAC into digit-generation range; A returns the base-10 exponent
        CALL FOUT_SCALE10
        LD BC,$0300
        PUSH AF
        ; [RE] branch on the E-notation force flag: scientific vs fixed digit layout
        LD A,(L_0CB8)
        OR A
        JP P,FOUT_CORE_1
        POP AF
        ADD A,D
        JP FOUT_CORE_2
; ----------------------------------------------------------------------
; FOUT_CORE_1 -- fixed-notation branch: check the exponent fits the precision
;   In:        A = base-10 exponent (restored by POP AF); D = rounding precision (7 or 17); entered when L_0CB8 is non-negative (value not forced scientific)
;   Out:       Falls into FOUT_CORE_2 (set integer-digit count) when the exponent fits, or jumps to FOUT_CORE_3 (no integer digits / scientific layout) otherwise
;   Clobbers:  A, D, flags
;   Algorithm: A += D (exponent plus precision). If negative (pure fraction) go to FOUT_CORE_3. Otherwise INC D and CP D: if A >= D the magnitude does not fit the precision -> FOUT_CORE_3; else fall through to FOUT_CORE_2.
; ----------------------------------------------------------------------
FOUT_CORE_1:
        POP AF
        ADD A,D
        ; exponent negative: no integer digits, go straight to the fraction/leading-zero path
        JP M,FOUT_CORE_3
        INC D
        CP D
        ; magnitude beyond the precision window: use the scientific digit layout
        JR NC,FOUT_CORE_3
; ----------------------------------------------------------------------
; FOUT_CORE_2 -- record the integer-digit count for fixed-point output
;   In:        A = (exponent + precision) for the fixed case
;   Out:       B = number of digits left of the decimal point (A+1); A reset to $02; falls into FOUT_CORE_3
;   Clobbers:  A, B
;   Algorithm: INC A; LD B,A captures the integer-digit count; LD A,$02 seeds the FOUT_CORE_3 SUB $02 to 0 so the leading-fraction setup is neutral on this path. Fall into FOUT_CORE_3.
; ----------------------------------------------------------------------
FOUT_CORE_2:
        INC A
        ; B = digit count to the left of the decimal point
        LD B,A
        LD A,$02
; ----------------------------------------------------------------------
; FOUT_CORE_3 -- emit the leading '.'/zero prefix, then generate the digit string
;   In:        A from the FOUT_CORE_1/_2 branches; B = integer-digit count (or scientific budget); HL recovered by POP HL -> buffer
;   Out:       Leading decimal point and pure-fraction zero run written via FOUT_LEADING_FRAC; digits generated via FOUT_DIGITS_FRAC; A (saved on the stack) carries the residual count into FOUT_CORE_4
;   Clobbers:  A, HL, FAC temporaries
;   Algorithm: SUB $02 adjusts the count; POP HL restores the buffer pointer; PUSH AF saves the count. CALL FOUT_LEADING_FRAC lays down '.' and leading '0's for |x|<1 (returns Z when it emitted the point). Store a '0' guard; if Z, FP_LOAD_DONE (INC HL) steps past it. CALL FOUT_DIGITS_FRAC emits the significant digits; fall into FOUT_CORE_4.
; ----------------------------------------------------------------------
FOUT_CORE_3:
        SUB $02
        POP HL
        PUSH AF
        ; emit '.' and the leading zeros for a sub-1 magnitude (records the point position)
        CALL FOUT_LEADING_FRAC
        LD (HL),$30
        CALL Z,FP_LOAD_DONE
        ; generate the significant decimal digits into the buffer
        CALL FOUT_DIGITS_FRAC
; ----------------------------------------------------------------------
; FOUT_CORE_4 -- strip trailing zeros (and a dangling '.') from the digit string
;   In:        HL -> one past the last digit; buffer holds the generated digits; A (saved earlier) = residual count selecting the fixed vs E tail
;   Out:       HL backed over trailing '0's and re-advanced past the last real digit; a trailing '.' is dropped; Z result jumps to FOUT_EXPONENT_4 (fixed tail) else falls into FOUT_EXPONENT (append E suffix)
;   Clobbers:  A, HL, flags
;   Algorithm: Loop DEC HL while (HL)=='0'. CP $2E: if the surviving last char is NOT '.', CALL FP_LOAD_DONE (= INC HL) to re-include that last real digit; if it IS '.', leave HL on it so it is dropped. POP AF; on Z take the fixed tail (FOUT_EXPONENT_4), else fall into FOUT_EXPONENT.
; ----------------------------------------------------------------------
FOUT_CORE_4:
        DEC HL
        LD A,(HL)
        ; trim trailing '0' digits the rounding produced
        CP $30
        JR Z,FOUT_CORE_4
        CP $2E
        CALL NZ,FP_LOAD_DONE
        POP AF
        ; fixed notation: NUL-terminate; otherwise fall through to append the E/D exponent
        JR Z,FOUT_EXPONENT_4
; ----------------------------------------------------------------------
; FOUT_EXPONENT -- append the E/D scientific exponent field and NUL-terminate
;   In:        HL -> end of the digit string; A = signed decimal exponent to emit; FAC value type read by FRMEVL_TEST_TYPE (single vs double selects 'E' vs 'D')
;   Out:       Writes '<E|D><sign><tens><ones>' then a $00 terminator; on return DE -> string end and HL -> buffer head L_0CC3
;   Clobbers:  A, B, HL, DE
;   Algorithm: FRMEVL_TEST_TYPE returns carry SET for single, CLEAR for double; LD A,$22 / ADC A,A yields $45 ('E', single) or $44 ('D', double). Write the letter, then '+' or '-' (CPL/INC A negates A for a negative exponent). FOUT_EXPONENT_2 converts |exponent| to two ASCII digits via repeated SUB $0A; FOUT_EXPONENT_3/_4 INC HL, write the $00 terminator, set DE=end, HL=L_0CC3, RET.
; ----------------------------------------------------------------------
FOUT_EXPONENT:
        PUSH AF
        ; value type sets carry: single -> 'E' ($45), double -> 'D' ($44)
        CALL FRMEVL_TEST_TYPE
        LD A,$22
        ADC A,A
        LD (HL),A
        INC HL
        POP AF
        LD (HL),$2B
        JP P,FOUT_EXPONENT_1
        ; negative exponent: write '-' then take its magnitude (CPL/INC A)
        LD (HL),$2D
        CPL
        INC A
; ----------------------------------------------------------------------
; FOUT_EXPONENT_1 -- non-negative-exponent entry (sign already '+')
;   In:        A = exponent magnitude (>= 0); HL -> the '+' byte already written
;   Out:       Seeds B = $2F ('0'-1) for the tens counter and falls into FOUT_EXPONENT_2
;   Clobbers:  B
;   Algorithm: LD B,$2F primes the ASCII tens digit so FOUT_EXPONENT_2's INC B produces '0','1',... per ten subtracted.
; ----------------------------------------------------------------------
FOUT_EXPONENT_1:
        LD B,$2F
; ----------------------------------------------------------------------
; FOUT_EXPONENT_2 -- convert the exponent magnitude to two ASCII decimal digits
;   In:        A = exponent magnitude; B = $2F ('0'-1) tens accumulator; HL -> after the sign byte
;   Out:       Tens digit (B) and ones digit (A+$3A) written; HL advanced past both
;   Clobbers:  A, B, HL
;   Algorithm: Loop SUB $0A / INC B until A goes negative (B='0'+tens). ADD A,$3A converts the negative remainder to the ones ASCII digit. INC HL / store B; INC HL / store the ones digit; fall into FOUT_EXPONENT_3.
; ----------------------------------------------------------------------
FOUT_EXPONENT_2:
        INC B
        ; count tens into B; the underflow remainder becomes the ones digit
        SUB $0A
        JR NC,FOUT_EXPONENT_2
        ; convert the underflow remainder to the ASCII ones digit (B holds the tens digit)
        ADD A,$3A
        INC HL
        LD (HL),B
        INC HL
        LD (HL),A
; ----------------------------------------------------------------------
; FOUT_EXPONENT_3 -- advance past the last digit before terminating
;   In:        HL -> last digit written
;   Out:       HL incremented to the terminator slot; falls into FOUT_EXPONENT_4
;   Clobbers:  HL
;   Algorithm: INC HL, then fall into FOUT_EXPONENT_4. Also reached directly from FOUT_BODY_2 for the zero/empty case.
; ----------------------------------------------------------------------
FOUT_EXPONENT_3:
        INC HL
; ----------------------------------------------------------------------
; FOUT_EXPONENT_4 -- NUL-terminate the formatted string and return the buffer pointer
;   In:        HL -> the terminator slot just past the formatted number
;   Out:       Writes $00; DE := old HL (string end); HL := L_0CC3 (buffer head); RET
;   Clobbers:  HL, DE
;   Algorithm: Store the $00 terminator, EX DE,HL so DE marks the end, LD HL,L_0CC3 and RET. Shared fixed-notation exit (also taken via FOUT_CORE_4's Z path).
; ----------------------------------------------------------------------
FOUT_EXPONENT_4:
        ; NUL-terminate; DE = string end, HL = buffer head on return
        LD (HL),$00
        EX DE,HL
        LD HL,L_0CC3
        RET
; ----------------------------------------------------------------------
; PRUSING_NUMFIELD -- PRINT USING numeric-field formatter dispatch (integer / float / E-image)
;   In:        A = VALTYP; D = PRINT USING format-flag byte (copied from PRUSING_FORMAT_FLAGS in FOUT_BODY_2); HL -> output buffer; FAC holds the value. Reached (JP C) from FOUT_BODY_2 when format-flag bit7 marks an active USING field
;   Out:       Dispatches: FOUT_CHOOSE_NOTATION (float field, VALTYP >= VT_SNG), FOUT_INT_TO_FLOAT_FIELD (integer rendered via the E-image path, format bit0 set), or the inline integer fixed field; ultimately joins PRUSING_OVERLAY
;   Clobbers:  A, B, C, D, E, HL, FAC temporaries
;   Algorithm: INC HL; PUSH BC. CP $04 tests VALTYP (still in A). LD A,D loads the format flags. JP NC,FOUT_CHOOSE_NOTATION when VALTYP >= 4 (single/double). Else RRA the flags: carry (bit0 set) -> FOUT_INT_TO_FLOAT_FIELD (integer via E-image). Else plain integer fixed field: LD BC,$0603 (group/sep seeds), PRUSING_COMMA_FLAG, pad leading zeros for width D-5 (FOUT_EMIT_ZEROS), FOUT_DIGITS_INT, fall into PRUSING_NUMFIELD_TRAIL.
; ----------------------------------------------------------------------
PRUSING_NUMFIELD:
        INC HL
        PUSH BC
        CP $04
        LD A,D
        ; single/double value: take the float fixed-vs-E placement chain
        JP NC,FOUT_CHOOSE_NOTATION
        RRA
        ; integer with an E-format image: widen to single and render via the E path
        JP C,FOUT_INT_TO_FLOAT_FIELD
        LD BC,$0603
        CALL PRUSING_COMMA_FLAG
        POP DE
        LD A,D
        SUB $05
        CALL P,FOUT_EMIT_ZEROS
        ; emit the integer digits into the fixed field
        CALL FOUT_DIGITS_INT
; ----------------------------------------------------------------------
; PRUSING_NUMFIELD_TRAIL -- finish the integer portion of a PRINT USING field
;   In:        E = remaining fractional-position count; A = trailing-zero count; HL -> buffer after the integer digits
;   Out:       Backs HL up one when there is no fraction (E==0), pads the requested trailing zeros, falls into PRUSING_OVERLAY to overlay the image
;   Clobbers:  A, HL
;   Algorithm: LD A,E / OR A: if E==0 CALL Z,DEC_HL_RET to drop the trailing slot. DEC A; CALL P,FOUT_EMIT_ZEROS pads that many '0' digits; fall into PRUSING_OVERLAY.
; ----------------------------------------------------------------------
PRUSING_NUMFIELD_TRAIL:
        LD A,E
        OR A
        ; no fractional digits: drop the unused trailing slot
        CALL Z,DEC_HL_RET
        DEC A
        CALL P,FOUT_EMIT_ZEROS
; ----------------------------------------------------------------------
; PRUSING_OVERLAY -- overlay the digits onto the PRINT USING format image, then rescan trailing chars
;   In:        HL -> end of the generated digit string; B = trailing field character (e.g. trailing sign); the format image is at L_0CC2/L_0CC3
;   Out:       PRUSING_FIELD rewrites fill/sign/'$'/'*' over the buffer; if it signalled a trailing char (NZ), B is stored and HL advanced; control NUL-terminates and continues into the PRUSING_OVERLAY_TERM/_9/_10 image rescan
;   Clobbers:  A, B, HL
;   Algorithm: PUSH HL; CALL PRUSING_FIELD (Z => no trailing char). POP HL; on NZ LD (HL),B / INC HL. Fall into PRUSING_OVERLAY_TERM.
; ----------------------------------------------------------------------
PRUSING_OVERLAY:
        PUSH HL
        ; rewrite the buffer per the format image (fill chars, '$', '*', sign)
        CALL PRUSING_FIELD
        POP HL
        JR Z,PRUSING_OVERLAY_TERM
        LD (HL),B
        INC HL
; ----------------------------------------------------------------------
; PRUSING_OVERLAY_TERM -- terminate the field and start the trailing-image rescan
;   In:        HL -> just past the field text
;   Out:       Writes $00; sets HL = L_0CC2 (image base) and falls into PRUSING_IMAGE_SCAN_NEXT
;   Clobbers:  HL
;   Algorithm: LD (HL),$00; LD HL,L_0CC2; fall into the PRUSING_IMAGE_SCAN_NEXT/_10 scan.
; ----------------------------------------------------------------------
PRUSING_OVERLAY_TERM:
        LD (HL),$00
        LD HL,L_0CC2
; ----------------------------------------------------------------------
; PRUSING_IMAGE_SCAN_NEXT -- advance to the next format-image character
;   In:        HL -> current image position
;   Out:       HL incremented; falls into PRUSING_IMAGE_SCAN
;   Clobbers:  HL
;   Algorithm: INC HL; fall into PRUSING_IMAGE_SCAN. Loop-advance target for skippable image chars (space, '*').
; ----------------------------------------------------------------------
PRUSING_IMAGE_SCAN_NEXT:
        INC HL
; ----------------------------------------------------------------------
; PRUSING_IMAGE_SCAN -- scan trailing format-image chars, skipping space/'*' fill
;   In:        HL -> format-image byte; FOUT_DP_POSITION ($0B69) holds the recorded image-length reference; D = format-flag context
;   Out:       RET when the image is consumed; skips ' ' ($20) and '*' ($2A); on a meaningful char DEC HL, PUSH HL and enter PRUSING_TRAIL_SCAN
;   Clobbers:  A, HL
;   Algorithm: A = (FOUT_DP_POSITION low byte) - L - D; RET Z when zero. LD A,(HL): if ' ' or '*' loop to PRUSING_IMAGE_SCAN_NEXT. Otherwise DEC HL / PUSH HL and enter PRUSING_TRAIL_SCAN. [RE] the SUB L / SUB D form a remaining-length computation against the recorded image reference.
; ----------------------------------------------------------------------
PRUSING_IMAGE_SCAN:
        LD A,(FOUT_DP_POSITION)
        SUB L
        SUB D
        ; trailing image fully consumed: done
        RET Z
        LD A,(HL)
        CP $20
        ; skip a space fill character
        JR Z,PRUSING_IMAGE_SCAN_NEXT
        CP $2A
        ; skip a '*' fill character
        JR Z,PRUSING_IMAGE_SCAN_NEXT
        DEC HL
        PUSH HL
; ----------------------------------------------------------------------
; PRUSING_TRAIL_SCAN -- CHRGET-driven scan over trailing sign/'$' image characters
;   In:        HL -> trailing image position; the digit field is already laid down
;   Out:       Skips runs of '-','+','$' image chars via a CHRGET self-loop; on any other char drops the loop frame and dispatches to PRUSING_FIELD_OVERFLOW (overflow-marker handling), with a side path that strips a leading '0'
;   Clobbers:  A, BC, HL (uses a self-referential return address)
;   Algorithm: PUSH AF; push PRUSING_TRAIL_SCAN as the return address; CALL CHRGET (advances HL, fetches next image char). If '-','+', or '$' RET -> re-enters PRUSING_TRAIL_SCAN (skip-and-continue). Otherwise POP the loop return; if the char is '0' run the leading-zero handling (INC HL / CHRGET / into PRUSING_STRIP_OVERLAP overlap strip-loop), else JP-fall to PRUSING_FIELD_OVERFLOW. [RE] the exact emit of the skipped sign/'$' chars happens via PRUSING_FIELD's earlier overlay, not here; this scan only walks past them.
; ----------------------------------------------------------------------
PRUSING_TRAIL_SCAN:
        PUSH AF
        ; push this label as the return address: CHRGET re-enters here to walk the next trailing char
        LD BC,PRUSING_TRAIL_SCAN
        PUSH BC
        ; advance HL and fetch the next format-image character
        CALL CHRGET
        CP $2D
        RET Z
        CP $2B
        RET Z
        CP $24
        RET Z
        POP BC
        CP $30
        JR NZ,PRUSING_FIELD_OVERFLOW
        INC HL
        CALL CHRGET
        JR NC,PRUSING_FIELD_OVERFLOW
        DEC HL
; ----------------------------------------------------------------------
; PRUSING_STRIP_OVERLAP -- trailing-zero strip step encoded in the LD BC operand (overlap idiom)
;   In:        HL -> buffer position; reached from PRUSING_TRAIL_SCAN's leading-'0' handling; the JR Z self-loop drives the strip
;   Out:       Repeatedly DEC HL / LD (HL),A while Z holds, then POP BC restores the loop frame and JP PRUSING_IMAGE_SCAN to continue the image scan
;   Clobbers:  BC (first pass only), A, HL
;   Algorithm: VERIFIED overlap (bytes 01 2B 77): on first entry they assemble/execute as LD BC,$772B; the JR Z self-loop re-enters at +1, skipping the 01 opcode (BC preserved) and re-running 2B 77 = DEC HL / LD (HL),A as the strip-and-overwrite body. When Z clears, POP BC then JP PRUSING_IMAGE_SCAN.
; ----------------------------------------------------------------------
PRUSING_STRIP_OVERLAP:
        LD BC,$772B
        POP AF
        JR Z,PRUSING_STRIP_OVERLAP+1
        POP BC
        JP PRUSING_IMAGE_SCAN
; ----------------------------------------------------------------------
; PRUSING_FIELD_OVERFLOW -- prepend the '%' field-overflow marker
;   In:        Stack top -> the start of the formatted field (pushed in PRUSING_IMAGE_SCAN); Z flag may drive a brief self-loop
;   Out:       Writes '%' ($25) at the field start to flag that the value overflowed the field width; RET
;   Clobbers:  A, HL
;   Algorithm: POP AF; the JR Z self-loop spins while Z holds; POP HL recovers the field-start pointer; LD (HL),$25 writes the standard BASIC PRINT USING overflow marker; RET.
; ----------------------------------------------------------------------
PRUSING_FIELD_OVERFLOW:
        POP AF
        JR Z,PRUSING_FIELD_OVERFLOW
        POP HL
        ; value too wide: prepend the '%' field-overflow marker
        LD (HL),$25
        RET
; ----------------------------------------------------------------------
; FOUT_CHOOSE_NOTATION -- choose fixed vs E-notation for a float field (the fixed-vs-scientific decision)
;   In:        A = D = format-flag byte; FAC holds the non-negative single/double value; the live single/double discriminator is the Z flag from the earlier CP $04 (VALTYP vs 4) in PRUSING_NUMFIELD (RRA does not touch Z). Reached from PRUSING_NUMFIELD when VALTYP >= VT_SNG
;   Out:       carry (format bit0) -> FOUT_EFIELD_DIGITS_SEL (E-image integer/single path); Z (VALTYP==4, SINGLE) -> FOUT_CHOOSE_NOTATION_SGL; else (VALTYP==8, DOUBLE) compare against FP_CONST_ENOTATION_THRESHOLD via DCOMP, set D=$10 (16-digit double budget) and on M go to FOUT_PLACE_FIXED (fixed), else fall into FOUT_EMIT_SCIENTIFIC (E-notation)
;   Clobbers:  A, D, DE, HL, FP temporaries
;   Algorithm: PUSH HL; RRA the format flags into carry. JP C,FOUT_EFIELD_DIGITS_SEL. JR Z,FOUT_CHOOSE_NOTATION_SGL -- Z is still the CP $04 result, so this is the SINGLE branch (VALTYP==4). The fall-through is the DOUBLE branch: LD DE,FP_CONST_ENOTATION_THRESHOLD / CALL DCOMP (double-precision compare) / LD D,$10; JP M,FOUT_PLACE_FIXED when FAC < threshold (fixed), else continue into FOUT_EMIT_SCIENTIFIC (scientific).
; ----------------------------------------------------------------------
FOUT_CHOOSE_NOTATION:
        PUSH HL
        RRA
        JP C,FOUT_EFIELD_DIGITS_SEL
        ; VALTYP==4 (Z from the CP $04): single-precision magnitude test
        JR Z,FOUT_CHOOSE_NOTATION_SGL
        ; double path: compare magnitude against the fixed-vs-E crossover constant (DCOMP)
        LD DE,FP_CONST_ENOTATION_THRESHOLD
        CALL DCOMP
        LD D,$10
        ; below threshold: format in fixed (positional) notation
        JP M,FOUT_PLACE_FIXED
; ----------------------------------------------------------------------
; FOUT_EMIT_SCIENTIFIC -- format in E-notation and prepend the field marker
;   In:        FAC holds the value; HL/BC restored from the stack hold the buffer/field state
;   Out:       Recursively formats the value via FOUT_2, then DEC HL and writes '%' ($25) before RET
;   Clobbers:  A, BC, HL
;   Algorithm: POP HL / POP BC restore state; CALL FOUT_2 to produce the digit string; DEC HL / LD (HL),$25 prepends the field/overflow marker; RET. Reached when the magnitude exceeds the fixed-notation threshold (both single and double arms join here).
; ----------------------------------------------------------------------
FOUT_EMIT_SCIENTIFIC:
        POP HL
        POP BC
        ; recursively format the value, then prepend the field marker
        CALL FOUT_2
        DEC HL
        LD (HL),$25
        RET
; ----------------------------------------------------------------------
; FOUT_CHOOSE_NOTATION_SGL -- single-precision magnitude test for fixed vs E-notation
;   In:        FAC holds the SINGLE value; entered (JR Z from FOUT_CHOOSE_NOTATION) when VALTYP==4
;   Out:       If FAC >= the single crossover constant ($0EB6,$1BCA) use E-notation (FOUT_EMIT_SCIENTIFIC); else LD D,$06 (6-digit single budget) and fall into FOUT_PLACE_FIXED (fixed)
;   Clobbers:  A, BC, DE, D, FP temporaries
;   Algorithm: LD BC,$B60E / LD DE,$1BCA load the single comparison constant; CALL FCOMP (single-precision register compare). JP P,FOUT_EMIT_SCIENTIFIC when FAC >= constant (scientific). Otherwise LD D,$06 and fall into FOUT_PLACE_FIXED.
; ----------------------------------------------------------------------
FOUT_CHOOSE_NOTATION_SGL:
        LD BC,$B60E
        LD DE,$1BCA
        CALL FCOMP
        ; single magnitude at/above the crossover: use E-notation
        JP P,FOUT_EMIT_SCIENTIFIC
        LD D,$06
; ----------------------------------------------------------------------
; FOUT_PLACE_FIXED -- normalize and place digits/decimal point for fixed-notation output
;   In:        D = digit budget ($06 single / $10 double); FAC holds the value; HL/BC restored hold buffer/field state
;   Out:       Generates the fixed-notation digit string with the decimal point placed; emits leading zeros, integer digits, the point and fractional digits; rejoins PRUSING_NUMFIELD_TRAIL
;   Clobbers:  A, B, C, D, E, HL, FAC temporaries
;   Algorithm: CALL FP_SIGN to test for zero (NZ => nonzero); CALL NZ,FOUT_SCALE10 to renormalize and return the base-10 exponent in A (FP_SIGN itself returns only a -1/0/+1 sign code, NOT the exponent). POP HL/BC. If the exponent is negative (M) -> FOUT_PLACE_FIXED_FRAC (pure fraction). Else E=A; compute the leading-zero pad B-D-E, emit it (FOUT_EMIT_ZEROS), set group counters (PRUSING_DIGIT_COUNT), generate digits (FOUT_DIGITS_FRAC), emit trailing-zero/separator fill, POP DE, JP PRUSING_NUMFIELD_TRAIL.
; ----------------------------------------------------------------------
FOUT_PLACE_FIXED:
        CALL FP_SIGN
        ; nonzero: renormalize FAC to digit-gen range; A returns the base-10 exponent
        CALL NZ,FOUT_SCALE10
        POP HL
        POP BC
        ; negative exponent: value is a pure fraction, handle leading zeros below
        JP M,FOUT_PLACE_FIXED_FRAC
        PUSH BC
        LD E,A
        LD A,B
        SUB D
        SUB E
        CALL P,FOUT_EMIT_ZEROS
        CALL PRUSING_DIGIT_COUNT
        ; emit the significant digits across the decimal point
        CALL FOUT_DIGITS_FRAC
        OR E
        CALL NZ,FOUT_EMIT_ZERO_LOOP
        OR E
        CALL NZ,FOUT_DIGIT_SEP
        POP DE
        JP PRUSING_NUMFIELD_TRAIL
; ----------------------------------------------------------------------
; FOUT_PLACE_FIXED_FRAC -- fixed-notation placement for a pure fraction (|x| < 1)
;   In:        A = (negative) base-10 exponent; C = integer-position count; FAC holds the value
;   Out:       Computes the post-point leading-zero adjustment and the digit budget; falls into FOUT_PLACE_FRAC_SCALE/_20 to scale and emit
;   Clobbers:  A, C, D, E, flags
;   Algorithm: E=A (save exponent); LD A,C / OR A: if C!=0 CALL NZ,DEC_A_RET (adjust for the integer-position digit). ADD A,E. If still negative JP M,FOUT_PLACE_FRAC_SCALE, else XOR A (clamp the leading-zero count to zero) and fall into FOUT_PLACE_FRAC_SCALE's continuation.
; ----------------------------------------------------------------------
FOUT_PLACE_FIXED_FRAC:
        LD E,A
        LD A,C
        OR A
        CALL NZ,DEC_A_RET
        ADD A,E
        ; still negative after adjust: a real leading-zero run is needed
        JP M,FOUT_PLACE_FRAC_SCALE
        XOR A
; ----------------------------------------------------------------------
; FOUT_PLACE_FRAC_SCALE -- scale the fraction up and compute its leading-zero count
;   In:        A = adjusted (negative) exponent; BC/AF saved across the divide loop
;   Out:       FAC scaled by powers of ten (via the FOUT_DIV10_LOOP FIN_DIV10 loop); E = leading-zero count; dispatches to FOUT_PLACE_FRAC_DEEP (deep fraction) or continues fixed placement
;   Clobbers:  A, B, C, D, E, FAC temporaries
;   Algorithm: PUSH BC / PUSH AF, then enter the FOUT_DIV10_LOOP loop. After it, POP BC; E = E - B (digits consumed); POP BC; LD E,A; ADD A,D; LD A,B. If negative (M) -> FOUT_PLACE_FRAC_DEEP (more leading zeros). Else SUB D / SUB E, pad leading zeros (FOUT_EMIT_ZEROS), set group counts (PRUSING_DIGIT_COUNT), JR FOUT_FRAC_DIGITS_TAIL.
; ----------------------------------------------------------------------
FOUT_PLACE_FRAC_SCALE:
        PUSH BC
        PUSH AF
; ----------------------------------------------------------------------
; FOUT_DIV10_LOOP -- divide FAC by 10 while the working exponent is negative
;   In:        A = signed scale counter (negative => keep dividing); FAC holds the value
;   Out:       FAC divided down until A >= 0; control returns to FOUT_PLACE_FRAC_SCALE's continuation
;   Clobbers:  A, FAC temporaries
;   Algorithm: CALL M,FIN_DIV10 (divide FAC by ten, A incremented, only while A negative); JP M loop back until A non-negative.
; ----------------------------------------------------------------------
FOUT_DIV10_LOOP:
        ; scale FAC down by 10 while the working exponent is still negative
        CALL M,FIN_DIV10
        JP M,FOUT_DIV10_LOOP
        POP BC
        LD A,E
        SUB B
        POP BC
        LD E,A
        ADD A,D
        LD A,B
        JP M,FOUT_PLACE_FRAC_DEEP
        SUB D
        SUB E
        CALL P,FOUT_EMIT_ZEROS
        PUSH BC
        CALL PRUSING_DIGIT_COUNT
        JR FOUT_FRAC_DIGITS_TAIL
; ----------------------------------------------------------------------
; FOUT_PLACE_FRAC_DEEP -- emit decimal point and leading zeros for a small fraction
;   In:        C = integer-position count; D/E = computed digit/zero counts; HL -> buffer
;   Out:       Writes leading zeros, the decimal point (FOUT_DECIMAL_POINT) and the post-point zero run, seeds the group counters, falls into FOUT_FRAC_DIGITS_TAIL
;   Clobbers:  A, B, C, D, E, HL
;   Algorithm: CALL FOUT_EMIT_ZEROS (integer-side zeros); LD A,C / FOUT_DECIMAL_POINT writes '.' and records its position; LD C,A. XOR A / SUB D / SUB E gives the post-point zero run; FOUT_EMIT_ZEROS pads it. PUSH BC; LD B,A / LD C,A seed the digit counters; fall into FOUT_FRAC_DIGITS_TAIL.
; ----------------------------------------------------------------------
FOUT_PLACE_FRAC_DEEP:
        CALL FOUT_EMIT_ZEROS
        LD A,C
        ; write the decimal point and record its buffer position
        CALL FOUT_DECIMAL_POINT
        LD C,A
        XOR A
        SUB D
        SUB E
        CALL FOUT_EMIT_ZEROS
        PUSH BC
        LD B,A
        LD C,A
; ----------------------------------------------------------------------
; FOUT_FRAC_DIGITS_TAIL -- generate fractional digits and patch the trailing-zero pointer
;   In:        B/C = digit counters; FAC holds the fraction; HL -> buffer at the first fractional digit
;   Out:       Fractional digits written via FOUT_DIGITS_FRAC; if no significant digits remain HL is reset to the recorded decimal-point position; falls into FOUT_FIXED_TRAIL
;   Clobbers:  A, B, C, HL, FAC temporaries
;   Algorithm: CALL FOUT_DIGITS_FRAC; POP BC; OR C: if zero (no digit budget left) LD HL,(FOUT_DP_POSITION) to back up to the recorded decimal-point spot. Fall into FOUT_FIXED_TRAIL.
; ----------------------------------------------------------------------
FOUT_FRAC_DIGITS_TAIL:
        CALL FOUT_DIGITS_FRAC
        POP BC
        OR C
        JR NZ,FOUT_FIXED_TRAIL
        ; no significant digits left: rewind to the recorded decimal-point position
        LD HL,(FOUT_DP_POSITION)
; ----------------------------------------------------------------------
; FOUT_FIXED_TRAIL -- pad trailing zeros and rejoin the field-finish path
;   In:        A = residual count; E = trailing-zero requirement; B = field digit count
;   Out:       Emits the remaining trailing '0' fill, sets D=B and JP PRUSING_OVERLAY to overlay the image
;   Clobbers:  A, D, HL
;   Algorithm: ADD A,E; DEC A; CALL P,FOUT_EMIT_ZEROS pads that many zeros. LD D,B carries the digit count, then JP PRUSING_OVERLAY.
; ----------------------------------------------------------------------
FOUT_FIXED_TRAIL:
        ADD A,E
        DEC A
        CALL P,FOUT_EMIT_ZEROS
        LD D,B
        JP PRUSING_OVERLAY
; ----------------------------------------------------------------------
; FOUT_INT_TO_FLOAT_FIELD -- widen an integer to single before the E-image path
;   In:        FAC holds a 16-bit integer (VALTYP integer, USING field with an E image); HL/DE saved
;   Out:       Converts the integer to single (INT_TO_SINGLE) and falls into FOUT_EFIELD_DIGITS_SEL with A=0 (Z) so the +1 entry is forced
;   Clobbers:  A, DE, HL, FAC
;   Algorithm: PUSH HL / PUSH DE; CALL INT_TO_SINGLE to widen the integer FAC to single; POP DE; XOR A (sets Z, the +1 budget-select entry); fall into FOUT_EFIELD_DIGITS_SEL.
; ----------------------------------------------------------------------
FOUT_INT_TO_FLOAT_FIELD:
        PUSH HL
        PUSH DE
        ; widen the integer to single so the float E-field path can format it
        CALL INT_TO_SINGLE
        POP DE
        XOR A
; ----------------------------------------------------------------------
; FOUT_EFIELD_DIGITS_SEL -- select the E-field digit budget (overlap-flag idiom)
;   In:        Z flag selects the entry: from FOUT_INT_TO_FLOAT_FIELD (XOR A => Z) or the external NZ entry (JP C from FOUT_CHOOSE_NOTATION); FAC holds the single value
;   Out:       E = E-field digit budget (16 on the NZ path, 6 on the Z/+1 path); both converge at FP_SIGN in FOUT_EFIELD_BUILD
;   Clobbers:  E (BC on the NZ path)
;   Algorithm: VERIFIED flag-skip overlap: the NZ entry runs LD E,$10 then 01 1E 06 = LD BC,$061E (E stays $10); the Z entry (JP Z,FOUT_EFIELD_BUILD+1) enters at +1, skipping the LD BC opcode and running 1E 06 = LD E,$06. Both fall into FP_SIGN at FOUT_EFIELD_BUILD. Note the local FOUT_INT_TO_FLOAT_FIELD XOR A always forces the +1 path; the LD E,$10 cover is exercised only via the external NZ entry.
; ----------------------------------------------------------------------
FOUT_EFIELD_DIGITS_SEL:
        JP Z,FOUT_EFIELD_BUILD+1
        LD E,$10
; ----------------------------------------------------------------------
; FOUT_EFIELD_BUILD -- generate the E-notation mantissa digits and compute the exponent
;   In:        E = digit budget (from FOUT_EFIELD_DIGITS_SEL); FAC holds the single value; D = format flags; HL/BC restored hold buffer/field state
;   Out:       FAC renormalized; mantissa digits laid down (FOUT_DIGITS_FRAC) with a decimal point; the residual exponent carried toward FOUT_EFIELD_EXP_VALUE/_30 which append the E suffix
;   Clobbers:  A, B, C, D, E, HL, FAC temporaries
;   Algorithm: CALL FP_SIGN (zero test only); SCF; CALL NZ,FOUT_SCALE10 to renormalize and return the base-10 exponent in A. POP HL/BC. Compute the integer/fraction split: CALL NZ,DEC_A_RET when C!=0, ADD A,B. Then LD A,D / AND $04 / CP $01 / SBC A,A / LD D,A folds in format-flag bit2 (a sign/leading-digit adjustment, NOT an E-field flag) to 0 or -1; ADD A,C / SUB E. Run the FIN_DIV10 normalization loop (FOUT_EFIELD_DIV10_LOOP). FOUT_EFIELD_COUNT builds B = digit count, C=0, generates digits (FOUT_DIGITS_FRAC), emits zero/point fill (FOUT_EMIT_ZEROS_DP / FOUT_DIGIT_SEP), then proceeds to FOUT_EFIELD_EXP_VALUE/_30.
; ----------------------------------------------------------------------
FOUT_EFIELD_BUILD:
        LD BC,$061E
        CALL FP_SIGN
        SCF
        ; nonzero: renormalize FAC to digit-gen range; A returns the base-10 exponent
        CALL NZ,FOUT_SCALE10
        POP HL
        POP BC
        PUSH AF
        LD A,C
        OR A
        PUSH AF
        CALL NZ,DEC_A_RET
        ADD A,B
        LD C,A
        LD A,D
        ; [RE] fold in format-flag bit2 (a sign/leading-digit adjustment) -> D = 0 or -1
        AND $04
        CP $01
        SBC A,A
        LD D,A
        ADD A,C
        LD C,A
        SUB E
        PUSH AF
        PUSH BC
; ----------------------------------------------------------------------
; FOUT_EFIELD_DIV10_LOOP -- divide-by-ten normalization for the E-field exponent
;   In:        A = signed exponent counter (negative => keep dividing); FAC holds the value; AF/BC saved
;   Out:       FAC scaled until A >= 0; saved counts recovered for the digit-count computation
;   Clobbers:  A, FAC temporaries
;   Algorithm: CALL M,FIN_DIV10 while A negative; JP M loop until non-negative; then POP BC / POP AF to recover the field counts for FOUT_EFIELD_COUNT.
; ----------------------------------------------------------------------
FOUT_EFIELD_DIV10_LOOP:
        ; scale FAC down by 10 until the working exponent is non-negative
        CALL M,FIN_DIV10
        JP M,FOUT_EFIELD_DIV10_LOOP
        POP BC
        POP AF
        PUSH BC
        PUSH AF
        JP M,FOUT_EFIELD_COUNT
        XOR A
; ----------------------------------------------------------------------
; FOUT_EFIELD_COUNT -- finalize the E-field mantissa digit count and emit the digits
;   In:        B = field width; D = format/leading-digit adjustment; A = normalized exponent
;   Out:       B = mantissa digit count (C=0); digits generated (FOUT_DIGITS_FRAC); zero/point fill emitted; A carries the residual exponent toward FOUT_EFIELD_EXP_VALUE
;   Clobbers:  A, B, C, HL, FAC temporaries
;   Algorithm: (PUSH AF/JP M/XOR A above clamp A). CPL / INC A negate; ADD A,B; INC A; ADD A,D combine into B = mantissa digit count; LD C,$00. CALL FOUT_DIGITS_FRAC. POP AF / CALL P,FOUT_EMIT_ZEROS_DP pads zeros with the point; CALL FOUT_DIGIT_SEP. POP BC / POP AF; JP NZ,FOUT_EFIELD_EXP_VALUE; otherwise CALL DEC_HL_RET, and if the last char is NOT '.' CALL NZ,FP_LOAD_DONE (= INC HL) to re-include it (dropping the '.' only when present), record HL at FOUT_DP_POSITION.
; ----------------------------------------------------------------------
FOUT_EFIELD_COUNT:
        CPL
        INC A
        ADD A,B
        INC A
        ADD A,D
        LD B,A
        LD C,$00
        ; emit the E-notation mantissa digits at the computed width
        CALL FOUT_DIGITS_FRAC
        POP AF
        CALL P,FOUT_EMIT_ZEROS_DP
        CALL FOUT_DIGIT_SEP
        POP BC
        POP AF
        JP NZ,FOUT_EFIELD_EXP_VALUE
        CALL DEC_HL_RET
        LD A,(HL)
        CP $2E
        ; last char is not '.': INC HL to re-include the final digit (the '.' is dropped only when present)
        CALL NZ,FP_LOAD_DONE
        LD (FOUT_DP_POSITION),HL
; ----------------------------------------------------------------------
; FOUT_EFIELD_EXP_VALUE -- compute the signed E-exponent value to append
;   In:        carry (popped AF) selects whether to adjust; A = running exponent; E = digit budget; B/D = field/adjustment counts
;   Out:       A = the signed decimal exponent to emit; falls into FOUT_EFIELD_APPEND
;   Clobbers:  A, flags
;   Algorithm: POP AF; JR C skips the adjust. Otherwise A = A + E - B - D to fold the digit-budget and field widths into the final exponent. Fall into FOUT_EFIELD_APPEND.
; ----------------------------------------------------------------------
FOUT_EFIELD_EXP_VALUE:
        POP AF
        JR C,FOUT_EFIELD_APPEND
        ADD A,E
        SUB B
        SUB D
; ----------------------------------------------------------------------
; FOUT_EFIELD_APPEND -- append the E/D suffix and overlay the format image
;   In:        A = signed exponent; HL -> end of the mantissa digits; BC = field state
;   Out:       Exponent suffix written by FOUT_EXPONENT (E/D + sign + two digits + NUL); control joins PRUSING_OVERLAY (PRUSING_OVERLAY)
;   Clobbers:  A, B, DE, HL
;   Algorithm: PUSH BC; CALL FOUT_EXPONENT to write the suffix and terminate; EX DE,HL / POP DE restore the buffer/field pointers; JP PRUSING_OVERLAY to overlay the format image over the assembled E-notation string.
; ----------------------------------------------------------------------
FOUT_EFIELD_APPEND:
        PUSH BC
        ; write the 'E'/'D' exponent suffix and terminator
        CALL FOUT_EXPONENT
        EX DE,HL
        POP DE
        JP PRUSING_OVERLAY
; ----------------------------------------------------------------------
; FOUT_SCALE10 -- normalize |FAC| into the digit-generation range and return the decimal exponent
;   In:        FAC holds the value being formatted (MBF single or double per VALTYP=$0B14).
;   Out:       A = decimal scale exponent (net power-of-ten count) leaving the rescaled FAC in the digit window: [1e15,1e16) for doubles, [1e5,1e6) for singles. FAC rescaled; flags per OR A (Z if zero); original DE restored.
;   Clobbers:  A, BC, DE, HL, FAC and all FP scratch; the running exponent counter rides in A on the stack across the loop.
;   Algorithm: Push a running decimal-exponent counter (init 0 via XOR A). If double, FOUT_SCALE10_1 coarsely multiplies by FP_DBL_1E10 (=1e10), subtracting 10 from the counter per pass, WHILE FAC_EXPONENT < $91 (~2^16): a fast up-scale of tiny doubles. Then FOUT_SCALE10_STEP divides by 10 WHILE FAC >= the upper bound (FP_DBL_1E16 / ~1e6 single). Then FOUT_SCALE10_3 multiplies by 10 (FIN_MUL10_DO, which decrements the counter) WHILE FAC < the lower bound (FP_DBL_1E15 / ~1e5 single), exiting once reached. Pop the final exponent into A.
; ----------------------------------------------------------------------
FOUT_SCALE10:
        PUSH DE
        ; seed the running decimal-exponent counter (kept on the stack across the whole scale)
        XOR A
        PUSH AF
        ; double? (A=VALTYP-3 has even parity PE for VT_DBL) -> run the coarse 1e10 up-scale; single (PO) skips to the fine step
        CALL FRMEVL_TEST_TYPE
        JP PO,FOUT_SCALE10_2
; ----------------------------------------------------------------------
; FOUT_SCALE10_1 -- coarse up-scale loop for tiny doubles (multiply by 1e10 until the binary exponent reaches $91)
;   In:        FAC = double value; top of stack = the running decimal-exponent counter.
;   Out:       loops while FAC_EXPONENT < $91; on reaching $91 branches to FOUT_SCALE10_2; FAC multiplied up, counter decremented by 10 per pass.
;   Clobbers:  A, DE, HL, FAC, FP scratch, stacked counter.
;   Algorithm: Read FAC_EXPONENT; if >= $91 the magnitude is large enough, jump to FOUT_SCALE10_2. Otherwise stage FP_DBL_1E10 (FP_MOVE_TYPED into ARG2_TEMP), DMUL the FAC by it, pop/adjust the counter by -10, push it back, repeat.
; ----------------------------------------------------------------------
FOUT_SCALE10_1:
        LD A,(FAC_EXP)
        CP $91
        JP NC,FOUT_SCALE10_2
        ; coarse multiply the FAC by 1e10 and credit -10 to the exponent counter
        LD DE,FP_DBL_1E10
        LD HL,ARG2_TEMP
        CALL FP_MOVE_TYPED
        CALL DMUL
        POP AF
        ; each *1e10 multiply lowers the decimal exponent by 10
        SUB $0A
        PUSH AF
        JR FOUT_SCALE10_1
; ----------------------------------------------------------------------
; FOUT_SCALE10_2 -- entry to the fine normalize: run the divide-down step, then the multiply-up loop
;   In:        FAC scaled by the coarse loop (or untouched if single / already large); stacked exponent counter live.
;   Out:       calls FOUT_SCALE10_STEP (fine divide-down) then falls into FOUT_SCALE10_3 (fine multiply-up).
;   Clobbers:  per FOUT_SCALE10_STEP.
;   Algorithm: One call to FOUT_SCALE10_STEP (divide by 10 while FAC >= the upper bound), then control proceeds to FOUT_SCALE10_3 to multiply up while FAC < the lower bound, converging into the digit window.
; ----------------------------------------------------------------------
FOUT_SCALE10_2:
        CALL FOUT_SCALE10_STEP
; ----------------------------------------------------------------------
; FOUT_SCALE10_3 -- fine MULTIPLY-UP loop: multiply by 10 while |FAC| is below the lower digit-range bound
;   In:        FAC partially scaled; stacked decimal-exponent counter live.
;   Out:       on FAC reaching/passing the lower bound, exits to FOUT_SCALE10_7 (returns exponent); otherwise loops.
;   Clobbers:  A, BC, DE, HL, FAC, FP scratch, stacked counter.
;   Algorithm: Pick the comparator by precision parity: double uses DCOMP against FP_DBL_1E15 (~1e15); single uses FCOMP against $9143/$4FF9 (= 99999.95 ~1e5). FCOMP/DCOMP return A = ordering ($00 equal, $01 FAC>bound, $FF FAC<bound). JP P (A>=0, FAC at/above the lower bound) -> done (FOUT_SCALE10_7). Otherwise (A=$FF) multiply by 10 (FIN_MUL10_DO decrements the counter) and loop.
; ----------------------------------------------------------------------
FOUT_SCALE10_3:
        ; multiply-up loop: compare |FAC| against the LOWER digit-range bound for this precision
        CALL FRMEVL_TEST_TYPE
        JP PE,FOUT_SCALE10_4
        ; single-precision LOWER bound (~99999.95 ~ 1e5) packed in the immediates: B=$91 exponent, C=$43 sign/MSB
        LD BC,$9143
        ; low mantissa bytes ($4F,$F9) of that single-precision bound for FCOMP
        LD DE,$4FF9
        CALL FCOMP
        JR FOUT_SCALE10_5
; ----------------------------------------------------------------------
; FOUT_SCALE10_4 -- double-precision arm of the multiply-up lower-bound comparison
;   In:        FAC = double value; FP_DBL_1E15 is the 8-byte lower bound.
;   Out:       A = ordering of (FAC vs bound) from DCOMP ($00/$01/$FF); merges with the single arm at FOUT_SCALE10_5.
;   Clobbers:  A, B, C, D, E, H, L, F (DCOMP).
;   Algorithm: Load DE = FP_DBL_1E15 and call DCOMP, which stages the constant into ARG2_TEMP and compares it against the FAC, returning the ordering code in A.
; ----------------------------------------------------------------------
FOUT_SCALE10_4:
        LD DE,FP_DBL_1E15
        CALL DCOMP
; ----------------------------------------------------------------------
; FOUT_SCALE10_5 -- act on the multiply-up comparison: exit if at/above bound, else multiply by 10
;   In:        A = ordering of (FAC vs lower bound) from FCOMP/DCOMP; stacked exponent counter live.
;   Out:       JP P (A>=0, FAC at/above the lower bound) -> FOUT_SCALE10_7 (exit); otherwise multiplies up and loops to FOUT_SCALE10_3.
;   Clobbers:  A, FAC, FP scratch, stacked counter.
;   Algorithm: If the compare is non-negative (FAC reached the bound) exit to FOUT_SCALE10_7. Otherwise pop the counter, multiply the FAC by 10 (FIN_MUL10_DO decrements the counter), push it back and re-enter FOUT_SCALE10_3 to re-test.
; ----------------------------------------------------------------------
FOUT_SCALE10_5:
        ; FAC has reached/passed the lower bound (compare code >= 0) -> done scaling, return the exponent
        JP P,FOUT_SCALE10_7
        POP AF
        ; still below the lower bound: multiply by 10 (decrements the exponent counter) and re-test
        CALL FIN_MUL10_DO
        PUSH AF
        JR FOUT_SCALE10_3
; ----------------------------------------------------------------------
; FOUT_SCALE10_6 -- one fine divide-by-10 then re-run the divide-down step
;   In:        FAC too large; stacked exponent counter live; reached from FOUT_SCALE10_STEP_2 when FAC >= the upper bound.
;   Out:       FAC divided by 10, counter incremented; re-checks via FOUT_SCALE10_STEP, then falls to FOUT_SCALE10_7.
;   Clobbers:  A, FAC, FP scratch, stacked counter.
;   Algorithm: Pop the counter, FIN_DIV10 the FAC (FIN_DIV10 increments A to track the decimal exponent), push the counter back, and call FOUT_SCALE10_STEP again to re-test whether FAC is now below the upper bound before exiting.
; ----------------------------------------------------------------------
FOUT_SCALE10_6:
        POP AF
        CALL FIN_DIV10
        PUSH AF
        CALL FOUT_SCALE10_STEP
; ----------------------------------------------------------------------
; FOUT_SCALE10_7 -- scale-loop exit: return the accumulated decimal exponent
;   In:        top of stack = the running decimal-exponent counter; original DE saved beneath it.
;   Out:       A = final decimal exponent; flags per OR A (Z if zero); DE restored; RET.
;   Clobbers:  A, F, DE.
;   Algorithm: Pop the counter into A, OR A to set Z/sign for the caller (FOUT_CORE combines it via ADD A,D into the digit layout), restore the saved DE, and return.
; ----------------------------------------------------------------------
FOUT_SCALE10_7:
        POP AF
        OR A
        POP DE
        RET
; ----------------------------------------------------------------------
; FOUT_SCALE10_STEP -- fine DIVIDE-DOWN step: divide the FAC by 10 while it is at/above the upper digit-range bound
;   In:        FAC = value being normalized; the caller's pushed return address doubles as the 'in-range' continuation (computed-return idiom).
;   Out:       If FAC is at/above the upper bound, diverts to FOUT_SCALE10_6 to divide by 10 (then re-runs this step); otherwise JP (HL) returns to the caller's pushed address. Bound differs by precision.
;   Clobbers:  A, B, C, D, E, H, L, FP scratch.
;   Algorithm: By precision parity, compare FAC against the UPPER bound: double via DCOMP against FP_DBL_1E16 (=1e16), single via FCOMP against $9474/$23F8 (= 999999.5 ~1e6). FCOMP/DCOMP return A = ordering ($00/$01/$FF). POP HL recovers the caller's return address. JP P (A>=0, FAC at/above the upper bound) -> FOUT_SCALE10_6 (divide by 10, then this step runs again); otherwise JP (HL) returns in range. A divide-while-too-large loop with the comparison shared across precisions.
; ----------------------------------------------------------------------
FOUT_SCALE10_STEP:
        ; select the comparator: double (PE) vs single (PO) upper-bound constant
        CALL FRMEVL_TEST_TYPE
        JP PE,FOUT_SCALE10_STEP_1
        LD BC,$9474
        LD DE,$23F8
        CALL FCOMP
        JR FOUT_SCALE10_STEP_2
; ----------------------------------------------------------------------
; FOUT_SCALE10_STEP_1 -- double-precision arm of the divide-down upper-bound compare
;   In:        FAC = double value; FP_DBL_1E16 = 8-byte upper bound.
;   Out:       A = ordering of (FAC vs bound) from DCOMP; merges at FOUT_SCALE10_STEP_2.
;   Clobbers:  A, B, C, D, E, H, L, FP scratch.
;   Algorithm: Load DE = FP_DBL_1E16 and DCOMP it against the FAC.
; ----------------------------------------------------------------------
FOUT_SCALE10_STEP_1:
        LD DE,FP_DBL_1E16
        CALL DCOMP
; ----------------------------------------------------------------------
; FOUT_SCALE10_STEP_2 -- act on the divide-down comparison via the computed return
;   In:        A = ordering of (FAC vs upper bound); top of stack = caller's return address.
;   Out:       divide-and-recheck (FOUT_SCALE10_6) if FAC at/above the bound, else return to the caller.
;   Clobbers:  A, HL, F.
;   Algorithm: POP HL = caller return address. If A>=0 (JP P, FAC at/above the upper bound) divert to FOUT_SCALE10_6 (divide by 10, then this step runs again); otherwise JP (HL) to the caller's saved continuation.
; ----------------------------------------------------------------------
FOUT_SCALE10_STEP_2:
        ; recover the caller's pushed return address; it becomes the in-range continuation (JP (HL))
        POP HL
        ; FAC still at/above the upper bound (compare code >= 0) -> divide by 10 and re-check
        JP P,FOUT_SCALE10_6
        ; FAC now below the bound: return in range via the caller's pushed address
        JP (HL)
; ----------------------------------------------------------------------
; FOUT_EMIT_ZEROS -- write A ASCII '0' bytes into the output buffer at HL
;   In:        A = count of zeros to emit; HL = output buffer cursor.
;   Out:       A = 0; HL advanced past the emitted zeros.
;   Clobbers:  A, HL, F.
;   Algorithm: OR A to set flags, then fall into the loop: while A != 0, DEC A, store '0' ($30) at (HL), INC HL. Plain zero padding with no decimal-point/comma interleaving.
; ----------------------------------------------------------------------
FOUT_EMIT_ZEROS:
        OR A
; ----------------------------------------------------------------------
; FOUT_EMIT_ZEROS_1 -- zero-fill loop body (count already flag-tested)
;   In:        A = remaining count (flags reflect A); HL = buffer cursor.
;   Out:       on A==0 returns; otherwise stores one '0' and tail-loops.
;   Clobbers:  A, HL, F.
;   Algorithm: RET Z when exhausted; else DEC A, LD (HL),'0', INC HL, JR back. Entry used when the caller has already set flags on the count.
; ----------------------------------------------------------------------
FOUT_EMIT_ZEROS_1:
        RET Z
        DEC A
        LD (HL),$30
        INC HL
        JR FOUT_EMIT_ZEROS_1
; ----------------------------------------------------------------------
; FOUT_EMIT_ZEROS_DP -- emit A '0' digits while interleaving decimal-point/comma separators (PRINT USING fill)
;   In:        A = number of zero digits to emit; Z flag distinguishes entry mode (NZ = one digit pending now); HL = cursor; B = integer digits remaining before the point, C = comma countdown (FOUT_DIGIT_SEP state).
;   Out:       A = 0; HL advanced; separators inserted as digit positions are crossed.
;   Clobbers:  A, BC, HL, ($0B69 decimal-point position), F.
;   Algorithm: Unlike FOUT_EMIT_ZEROS, each zero is preceded by a FOUT_DIGIT_SEP call so the decimal point (when B reaches 0) and thousands commas (every 3 digits when grouping is on) drop in at the right spots. On the NZ entry it stores the first zero immediately (jump into FOUT_EMIT_ZERO_LOOP) before testing for a separator; on the Z entry it returns when exhausted, else calls FOUT_DIGIT_SEP then stores a zero. This is the PRINT USING positional zero fill.
; ----------------------------------------------------------------------
FOUT_EMIT_ZEROS_DP:
        ; a digit is already pending on this entry: store it before testing for a separator
        JR NZ,FOUT_EMIT_ZERO_LOOP
; ----------------------------------------------------------------------
; FOUT_EMIT_ZEROS_DP_1 -- separator-aware zero-fill loop head
;   In:        A = remaining zeros (flags reflect A); HL cursor; B/C separator state.
;   Out:       returns when A==0; otherwise inserts a separator then a zero and loops.
;   Clobbers:  A, BC, HL, ($0B69 decimal-point position), F.
;   Algorithm: RET Z when done; else CALL FOUT_DIGIT_SEP to drop a decimal point/comma if this position warrants one, then fall into FOUT_EMIT_ZERO_LOOP to store the '0'.
; ----------------------------------------------------------------------
FOUT_EMIT_ZEROS_DP_1:
        RET Z
        CALL FOUT_DIGIT_SEP
; ----------------------------------------------------------------------
; FOUT_EMIT_ZERO_LOOP -- store one '0' digit, advance, decrement, continue the separator-aware fill
;   In:        A = remaining count; HL = cursor.
;   Out:       one '0' stored; HL incremented; A decremented; loops to FOUT_EMIT_ZEROS_DP_1.
;   Clobbers:  A, HL, F.
;   Algorithm: LD (HL),'0'; INC HL; DEC A; JR FOUT_EMIT_ZEROS_DP_1. Shared tail used both as the first-digit shortcut and the per-iteration store of the separator-aware fill.
; ----------------------------------------------------------------------
FOUT_EMIT_ZERO_LOOP:
        LD (HL),$30
        INC HL
        DEC A
        JR FOUT_EMIT_ZEROS_DP_1
; ----------------------------------------------------------------------
; PRUSING_DIGIT_COUNT -- compute total digit width B and initial comma countdown C from the integer/fraction digit counts
;   In:        D = integer-part digit count, E = fraction-part digit count (PRINT USING numeric field).
;   Out:       B = E+D+1 (total digit width); C = countdown to the first thousands group; falls into PRUSING_COMMA_FLAG which may zero C.
;   Clobbers:  A, B, C, F.
;   Algorithm: A = E + D + 1 -> B. Then INC A (=E+D+2) and SUB $03 repeatedly until it underflows (carry), leaving A = (E+D+2) mod 3 biased negative; ADD $05 biases it into the FOUT_DIGIT_SEP comma-countdown range and stores it in C so the first comma lands on the correct 3-digit boundary. Falls into PRUSING_COMMA_FLAG, which clears C when grouping is off.
; ----------------------------------------------------------------------
PRUSING_DIGIT_COUNT:
        ; total digit width B = fraction digits (E) + integer digits (D) + 1
        LD A,E
        ADD A,D
        INC A
        LD B,A
        INC A
; ----------------------------------------------------------------------
; PRUSING_DIGIT_COUNT_1 -- mod-3 reduction loop for the comma countdown
;   In:        A = digit-position seed (E+D+2).
;   Out:       A reduced by repeated -3 until it underflows (carry set), ready for the +5 bias.
;   Clobbers:  A, F.
;   Algorithm: SUB $03; JR NC back while still non-negative. Computes (E+D+2) mod 3 by repeated subtraction.
; ----------------------------------------------------------------------
PRUSING_DIGIT_COUNT_1:
        ; reduce the digit position mod 3 to find the offset to the first thousands comma
        SUB $03
        JR NC,PRUSING_DIGIT_COUNT_1
        ; bias the remainder into the FOUT_DIGIT_SEP comma-countdown range
        ADD A,$05
        LD C,A
; ----------------------------------------------------------------------
; PRUSING_COMMA_FLAG -- gate thousands-comma grouping from the PRINT USING format flags
;   In:        $0B4A (PRINT USING format byte) bit 6 = comma-grouping requested; C = the seeded comma countdown from PRUSING_DIGIT_COUNT.
;   Out:       bit 6 set -> returns (NZ) with C unchanged (grouping on); clear -> C := 0 (grouping off) and RET.
;   Clobbers:  A, C, F.
;   Algorithm: Read the format-flag byte ($0B4A), AND $40 to isolate the comma flag; RET NZ leaves the countdown live; otherwise LD C,A (=0) disables comma insertion in FOUT_DIGIT_SEP, then RET. Reachable both as its own entry and as the tail of PRUSING_DIGIT_COUNT.
; ----------------------------------------------------------------------
PRUSING_COMMA_FLAG:
        LD A,(PRUSING_FORMAT_FLAGS)
        ; isolate the comma-grouping request (bit 6 of the PRINT USING format byte)
        AND $40
        RET NZ
        ; grouping off: zero the comma countdown so FOUT_DIGIT_SEP never emits a comma
        LD C,A
        RET
; ----------------------------------------------------------------------
; FOUT_LEADING_FRAC -- lay the '.' and leading fraction zeros for a magnitude < 1
;   In:        B = integer-digit count (the leading-fraction-zero path is taken when B-1 < 0, i.e. B <= 0, meaning no integer digits); HL = buffer cursor.
;   Out:       for a pure fraction: decimal point written and its buffer position recorded at $0B69, then |B| '0' digits written, HL advanced, C := 0; RET. If integer digits remain (B-1 >= 0) it diverts to FOUT_DIGIT_SEP_1 (the normal separator path).
;   Clobbers:  A, B, C, HL, ($0B69 decimal-point position), F.
;   Algorithm: DEC B; if still non-negative (JP P) there are integer digits -> jump to FOUT_DIGIT_SEP_1 (no leading '0.'). Otherwise this is a pure fraction (|x|<1): record HL as the decimal-point position ($0B69), write '.', then FOUT_LEADING_FRAC_1 writes '0' and INC B until B counts up to 0. Finally INC HL past the run and set C := B (=0).
; ----------------------------------------------------------------------
FOUT_LEADING_FRAC:
        ; any integer digits? if B-1 stays non-negative this is not a pure fraction -> normal separator path
        DEC B
        JP P,FOUT_DIGIT_SEP_1
        ; pure fraction (|x|<1): record where the decimal point goes ($0B69) and emit '.'
        LD (FOUT_DP_POSITION),HL
        LD (HL),$2E
; ----------------------------------------------------------------------
; FOUT_LEADING_FRAC_1 -- leading-fraction-zero fill loop
;   In:        B = remaining (negative) leading-zero count; HL = cursor at the '.'.
;   Out:       writes '0's until B counts up to 0; HL advanced; falls out to set C := B.
;   Clobbers:  B, HL, F.
;   Algorithm: INC HL; LD (HL),'0'; INC B; JP NZ back. Emits |B| zeros after the decimal point.
; ----------------------------------------------------------------------
FOUT_LEADING_FRAC_1:
        INC HL
        ; fill one leading fraction zero per missing place until the first significant digit
        LD (HL),$30
        INC B
        JP NZ,FOUT_LEADING_FRAC_1
        INC HL
        LD C,B
        RET
; ----------------------------------------------------------------------
; FOUT_DIGIT_SEP -- per-digit separator hook: drop the decimal point at the integer/fraction boundary, or a comma every 3 digits
;   In:        B = integer digits remaining before the decimal point; C = comma countdown (or 0 if grouping off); HL = buffer cursor.
;   Out:       when B reaches 0 the decimal point is written ($0B69 recorded, comma counter reseeded from B); otherwise when C decrements to 0 a comma is written and C reseeded to 3; HL advanced past any emitted separator.
;   Clobbers:  A, B, C, HL, ($0B69 decimal-point position), F.
;   Algorithm: DEC B (consume one integer-digit position). If B is now zero the decimal point is due -> FOUT_DECIMAL_POINT. Otherwise fall to FOUT_DECIMAL_POINT_1 for the comma-group countdown. Called once per emitted digit by the integer/fraction digit generators and the zero-fill helpers so separators interleave correctly.
; ----------------------------------------------------------------------
FOUT_DIGIT_SEP:
        ; consume one integer-digit position; B hitting 0 means the decimal point is due here
        DEC B
; ----------------------------------------------------------------------
; FOUT_DIGIT_SEP_1 -- separator dispatch on the (already-decremented) digit position
;   In:        B (already decremented) = integer digits left, Z set if at the decimal-point boundary; C = comma countdown; HL = cursor.
;   Out:       decimal point (Z) or comma-group handling (NZ).
;   Clobbers:  A, BC, HL, ($0B69 decimal-point position), F.
;   Algorithm: JR NZ to FOUT_DECIMAL_POINT_1 (comma countdown) when integer digits remain; otherwise fall through to FOUT_DECIMAL_POINT to emit '.'. Reached directly from FOUT_LEADING_FRAC when B was decremented without a fresh entry through FOUT_DIGIT_SEP.
; ----------------------------------------------------------------------
FOUT_DIGIT_SEP_1:
        JR NZ,FOUT_DECIMAL_POINT_1
; ----------------------------------------------------------------------
; FOUT_DECIMAL_POINT -- write the decimal point, record its position, reseed the comma counter
;   In:        HL = output buffer cursor; B = the (now-exhausted) integer-digit counter, reused to reseed C.
;   Out:       '.' stored at (HL); $0B69 := HL (for the later trailing-zero strip); HL incremented; C := B; RET.
;   Clobbers:  HL, C, ($0B69 decimal-point position).
;   Algorithm: LD (HL),'.'; save HL to $0B69; INC HL; C := B. Marks the integer/fraction boundary and tells the trailing-zero trimmer where the point is.
; ----------------------------------------------------------------------
FOUT_DECIMAL_POINT:
        LD (HL),$2E
        ; remember the decimal-point address ($0B69) so trailing fraction zeros can be stripped later
        LD (FOUT_DP_POSITION),HL
        INC HL
        LD C,B
        RET
; ----------------------------------------------------------------------
; FOUT_DECIMAL_POINT_1 -- thousands-comma countdown: emit ',' every third integer digit when grouping is on
;   In:        C = comma countdown; HL = cursor.
;   Out:       if C decrements to non-zero, returns (no separator); if it reaches 0, writes ',', advances HL, and reseeds C := 3.
;   Clobbers:  C, HL, F.
;   Algorithm: DEC C; RET NZ while the group is not yet full. When C hits 0 a three-digit group just completed: LD (HL),',' ; INC HL ; C := 3 to start the next group; RET. With grouping disabled C was seeded 0 by PRUSING_COMMA_FLAG so DEC C makes it $FF (NZ) and no comma is ever emitted.
; ----------------------------------------------------------------------
FOUT_DECIMAL_POINT_1:
        DEC C
        RET NZ
        ; a 3-digit group completed: emit the thousands comma and start a fresh group
        LD (HL),$2C
        INC HL
        LD C,$03
        RET
; ----------------------------------------------------------------------
; FOUT_DIGITS_FRAC -- generate the fractional decimal digits of FAC into the output buffer
;   In:        FAC holds the (already range-scaled) value whose fraction is to be emitted;
;              HL = next free byte in the FOUT scratch buffer; B = digit-position counter,
;              C = comma-group counter (both threaded through FOUT_DIGIT_SEP); VALTYP selects
;              the path (see Algorithm).
;   Out:       fractional ASCII digits ('0'..'9') stored at (HL), HL advanced past them;
;              decimal point and grouping commas inserted by FOUT_DIGIT_SEP; FAC consumed.
;   Clobbers:  A,B,C,D,E,H,L, FAC, FAC_DBL, the FP work cells, flags.
;   Algorithm: Digit extraction is by repeated SUBTRACTION of power-of-ten constants, NOT by
;              multiply-by-10 (the stale pre-label comment that says 'multiply by 10' is wrong).
;              [RE] Path select via FRMEVL_TEST_TYPE then JP PO: FRMEVL_TEST_TYPE computes
;              parity of (VALTYP-3), and PO (single precision, VALTYP=4) goes to
;              FOUT_DIGITS_FRAC_3; the fallthrough (double VALTYP=8, AND integer VALTYP=2, which
;              is parity-even) takes the high-precision path -- so the PO branch is SINGLE only,
;              not 'single/integer'. DOUBLE/fallthrough path: round by ADDing 0.5 (DADD of the
;              8-byte FP_CONST_HALF_DBL) then FIX_DENORM to integer-align the 8-byte mantissa,
;              and run 10 digit passes (A=$0A) over FP_POW10_FRAC_TABLE in FOUT_DIGITS_FRAC_1 --
;              each pass trial-subtracts one scaled-ten constant until borrow, counting the
;              subtractions as the digit. SINGLE path (FOUT_DIGITS_FRAC_3) adds 0.5 and
;              integer-aligns, then both paths converge at FOUT_DIGITS_FRAC_4 / the low-precision
;              3-byte loop.
; ----------------------------------------------------------------------
FOUT_DIGITS_FRAC:
        PUSH DE
        ; [RE] classify VALTYP: the following JP PO branches single precision (VALTYP=4) to the low-precision setup; double AND integer (parity-even) fall through to the high-precision path
        CALL FRMEVL_TEST_TYPE
        JP PO,FOUT_DIGITS_FRAC_3
        PUSH BC
        PUSH HL
        CALL FP_ARG_TO_TEMP2
        ; round-to-nearest: DADD double-precision 0.5 before integer-aligning so the last emitted digit rounds correctly
        LD HL,FP_CONST_HALF_DBL
        CALL FP_ARG_SETUP1
        CALL DADD
        XOR A
        ; right-align the 8-byte mantissa to an integer scale so digits can be peeled off the fraction by subtraction
        CALL FIX_DENORM
        POP HL
        POP BC
        ; point DE at the descending power-of-ten constant table; A=$0A = 10 digit passes
        LD DE,FP_POW10_FRAC_TABLE
        LD A,$0A
; ----------------------------------------------------------------------
; FOUT_DIGITS_FRAC_1 -- double-precision fractional digit loop (one decimal digit per pass)
;   In:        A = remaining digit count (starts at 10 = $0A); DE -> current entry in
;              FP_POW10_FRAC_TABLE; FAC_DBL holds the integer-aligned remaining fraction;
;              HL = buffer write pointer; B/C threaded for FOUT_DIGIT_SEP.
;   Out:       one ASCII digit appended per pass; FAC_DBL reduced by digit*power-of-ten;
;              repeats until A reaches 0, then transfers the reduced double accumulator down
;              into the single-precision FAC and joins FOUT_DIGITS_FRAC_4.
;   Clobbers:  A,B,C,D,E,H,L, FAC, FAC_DBL, flags.
;   Algorithm: Emit any pending '.'/',' via FOUT_DIGIT_SEP, save state, seed B='0'-1, then call
;              FOUT_DIGITS_FRAC_2 which trial-subtracts the current power-of-ten constant
;              repeatedly (counting in B = ASCII digit) until it underflows, adds the last
;              over-subtraction back, writes the digit byte, advances the buffer, and DEC A loops.
;              When all 10 digits are done, FP_STORE_REGS_LD COPIES FAC_DBL's low 4 bytes into
;              the single-precision FAC (it loads from FAC_DBL and stores to FAC), then control
;              falls to FOUT_DIGITS_FRAC_4 for the low-precision tail.
; ----------------------------------------------------------------------
FOUT_DIGITS_FRAC_1:
        ; emit the decimal point or a grouping comma if this digit position calls for one
        CALL FOUT_DIGIT_SEP
        PUSH BC
        PUSH AF
        PUSH HL
        PUSH DE
        ; seed the digit accumulator at '0'-1 ($2F); each successful subtraction below INCs it toward the ASCII digit
        LD B,$2F
; ----------------------------------------------------------------------
; FOUT_DIGITS_FRAC_2 -- inner trial-subtract loop: count how many times one power-of-ten fits
;   In:        B = ASCII digit accumulator (preset '0'-1); top of stack = pointer to the current
;              FP_POW10_FRAC_TABLE constant (7-byte double); FAC_DBL = the running fraction.
;   Out:       B incremented once per successful subtraction (= the decimal digit); the constant
;              is subtracted from FAC_DBL that many times, then added back once to undo the
;              over-subtraction that broke the loop; DE left pointing past the constant.
;   Clobbers:  A,B,D,E,H,L, FAC_DBL, flags.
;   Algorithm: Each pass re-loads HL from the saved constant pointer (POP HL/PUSH HL) and calls
;              DP_ADD_BLOCK with A=$9E -- DP_ADD_BLOCK SELF-MODIFIES its 'ADC A,(HL)' opcode to
;              the operand byte in A, so $9E patches it to SBC A,(HL): a borrowing subtract of the
;              7-byte double constant from FAC_DBL; while no borrow (NC) INC B and repeat. On
;              borrow, call DP_ADD_BLOCK once with A=$8E (restores 'ADC A,(HL)') to add the
;              constant back, restoring the non-negative remainder before the next, smaller
;              power-of-ten. EX DE,HL then leaves DE past the consumed constant.
; ----------------------------------------------------------------------
FOUT_DIGITS_FRAC_2:
        INC B
        POP HL
        PUSH HL
        ; A=$9E self-modifies DP_ADD_BLOCK's ADC A,(HL) into SBC A,(HL): trial-subtract this power-of-ten from FAC_DBL
        LD A,$9E
        CALL DP_ADD_BLOCK
        ; no borrow means the constant still fit: count this digit (INC B) and subtract again
        JR NC,FOUT_DIGITS_FRAC_2
        POP HL
        ; A=$8E restores DP_ADD_BLOCK to ADC A,(HL): add the constant once to undo the final over-subtraction
        LD A,$8E
        CALL DP_ADD_BLOCK
        EX DE,HL
        POP HL
        LD (HL),B
        INC HL
        POP AF
        POP BC
        DEC A
        JR NZ,FOUT_DIGITS_FRAC_1
        PUSH BC
        PUSH HL
        LD HL,FAC_DBL
        CALL FP_STORE_REGS_LD
        JR FOUT_DIGITS_FRAC_4
; ----------------------------------------------------------------------
; FOUT_DIGITS_FRAC_3 -- single-precision fraction setup (the PO / VALTYP=4 path)
;   In:        FAC = single-precision value (entered when FRMEVL_TEST_TYPE yields PO, VALTYP=4);
;              B/C/HL threaded as in FOUT_DIGITS_FRAC.
;   Out:       FAC = (FAC + 0.5) integer-aligned and re-stored, ready for the shared low-precision
;              subtraction loop; falls into FOUT_DIGITS_FRAC_4.
;   Clobbers:  A,B,C,D,E,H,L, FAC, flags.
;   Algorithm: FADD_LOAD_CONST ADDS single-precision 0.5 to the FAC (it is an FADD of the in-image
;              constant FP_CONST_HALF_SNG, not merely a load) as the round-to-nearest bias. Then
;              FP_SHIFT_MANTISSA with A=$01 integer-aligns the single-precision mantissa (the
;              single-precision analog of the double path's FIX_DENORM; the count byte and its
;              internal round-on-carry are handled inside FP_SHIFT_MANTISSA), and FP_STORE_FAC
;              commits the aligned value before joining the shared fraction tail.
; ----------------------------------------------------------------------
FOUT_DIGITS_FRAC_3:
        PUSH BC
        PUSH HL
        ; add single-precision 0.5 to the FAC (FADD of FP_CONST_HALF_SNG) as the round-to-nearest bias for the single path
        CALL FADD_LOAD_CONST
        LD A,$01
        ; integer-align the single-precision mantissa (A=$01 selects the alignment count; the single-precision analog of FIX_DENORM), then commit to the FAC
        CALL FP_SHIFT_MANTISSA
        CALL FP_STORE_FAC
; ----------------------------------------------------------------------
; FOUT_DIGITS_FRAC_4 -- common entry to the low-precision (3-byte) fraction loop
;   In:        FAC holds the integer-aligned fraction (single FAC, set by either path); the saved
;              buffer pointer (HL) and counters (BC) are on the stack.
;   Out:       falls into FOUT_DIGITS_FRAC_5 with A=0 (the CCF/carry seed) and
;              DE -> FP_POW10_FRAC_TABLE2.
;   Clobbers:  A,D,E; restores B,C,HL from stack.
;   Algorithm: Pop the saved buffer pointer (HL) and counters (BC), clear A (this also clears
;              carry, the seed for the CCF toggle in _5), and point DE at the compact 3-byte
;              power-of-ten table used by the low-precision loop.
; ----------------------------------------------------------------------
FOUT_DIGITS_FRAC_4:
        POP HL
        POP BC
        XOR A
        ; select the compact 3-byte power-of-ten table for the low-precision fraction loop
        LD DE,FP_POW10_FRAC_TABLE2
; ----------------------------------------------------------------------
; FOUT_DIGITS_FRAC_5 -- low-precision fractional digit loop (2 digits, 3-byte mantissa)
;   In:        DE -> current FP_POW10_FRAC_TABLE2 constant (3-byte little-endian); FAC = the
;              remaining fraction; HL = buffer pointer; B/C threaded for FOUT_DIGIT_SEP; carry
;              seeded clear, toggled each pass by CCF.
;   Out:       one ASCII digit appended per pass; FAC reduced; runs EXACTLY 2 passes (one per
;              FP_POW10_FRAC_TABLE2 entry), driven by the CCF toggle: CCF sets carry on pass 1
;              (JR C loops back) and clears it on pass 2 (JR NC exits). On exit it advances DE
;              (INC DE/INC DE) and jumps to FOUT_DIGITS_INT_1 with A=$04.
;   Clobbers:  A,B,C,D,E,H,L, FAC, flags.
;   Algorithm: Emit pending '.'/',' (FOUT_DIGIT_SEP -- it preserves carry), reload the FAC's low
;              3 mantissa bytes into E,D,C via FP_LOAD_FAC, and call FOUT_DIGITS_FRAC_6 to
;              trial-subtract the 3-byte constant until borrow (digit counted in B), which adds
;              it back once (MANT_ADD) and re-stores the FAC, then store the digit. The PUSH
;              AF/POP AF carries the CCF-toggled flag across the loop body so JR C alternates;
;              it therefore produces exactly 2 fraction digits before handing off to the
;              integer-digit body (A=$04 = 4 more positions, from POW10_INT_TABLE).
; ----------------------------------------------------------------------
FOUT_DIGITS_FRAC_5:
        ; toggle the carry (seeded clear): set on the first pass so JR C loops back, cleared on the second so JR NC exits -- this loop runs exactly 2 passes
        CCF
        CALL FOUT_DIGIT_SEP
        PUSH BC
        PUSH AF
        PUSH HL
        PUSH DE
        ; reload the working fraction's low 3 mantissa bytes into E,D,C for the subtraction
        CALL FP_LOAD_FAC
        POP HL
        LD B,$2F
; ----------------------------------------------------------------------
; FOUT_DIGITS_FRAC_6 -- inner 3-byte trial-subtract loop for the low-precision fraction path
;   In:        E,D,C = working fraction (low,mid,high) from FP_LOAD_FAC; HL -> the 3-byte
;              little-endian power-of-ten constant in FP_POW10_FRAC_TABLE2; B = ASCII digit
;              accumulator (preset '0'-1).
;   Out:       B = decimal digit (count of successful subtractions); E,D,C reduced by
;              digit*constant; on the final borrow, the constant is added back once (MANT_ADD) so
;              the remainder is non-negative; the result is re-stored to the FAC (FP_STORE_FAC).
;   Clobbers:  A,B,C,D,E,H,L, flags.
;   Algorithm: Borrowing 24-bit subtract of (HL),(HL+1),(HL+2) from E,D,C, with HL rewound by
;              DEC HL/DEC HL after each trial so it re-aims at the constant's low byte; INC B and
;              repeat while no borrow. On borrow, MANT_ADD reads the 3 constant bytes back into
;              E,D,C (advancing HL past them), INC HL, and FP_STORE_FAC commits the reduced
;              fraction.
; ----------------------------------------------------------------------
FOUT_DIGITS_FRAC_6:
        INC B
        ; 24-bit borrowing subtract of the power-of-ten constant from the working fraction (E/D/C)
        LD A,E
        SUB (HL)
        LD E,A
        INC HL
        LD A,D
        SBC A,(HL)
        LD D,A
        INC HL
        LD A,C
        SBC A,(HL)
        LD C,A
        DEC HL
        DEC HL
        ; no borrow: the constant fit, so count the digit (INC B) and subtract again
        JR NC,FOUT_DIGITS_FRAC_6
        ; add the constant back once to undo the over-subtraction that produced the borrow
        CALL MANT_ADD
        INC HL
        ; write the reduced fraction back to the FAC for the next (smaller) power-of-ten
        CALL FP_STORE_FAC
        EX DE,HL
        POP HL
        LD (HL),B
        INC HL
        POP AF
        POP BC
        JR C,FOUT_DIGITS_FRAC_5
        INC DE
        INC DE
        LD A,$04
        JR FOUT_DIGITS_INT_1
; ----------------------------------------------------------------------
; FOUT_DIGITS_INT -- generate the integer decimal digits of FAC into the output buffer
;   In:        FAC ($0CB1) = the 16-bit unsigned integer part to print; HL = buffer write
;              pointer; B/C threaded for FOUT_DIGIT_SEP (digit position / comma group).
;   Out:       5 ASCII digits (10000s..1s, leading positions handled by the caller's
;              zero-suppression) appended at (HL); HL advanced; a final NUL written; (FAC)
;              reduced (0 for a whole integer); DE restored, RET.
;   Clobbers:  A,B,C,D,E,H,L, FAC, flags.
;   Algorithm: Classic divide-by-repeated-subtraction. DE -> POW10_INT_TABLE (10000,1000,100,
;              10,1 little-endian), A=$05 digit passes. Each pass (FOUT_DIGITS_INT_1) trial-
;              subtracts the current power of ten from (FAC) until borrow, counting the quotient
;              digit in B, adds the power back once, stores the digit, and moves to the next
;              entry. After 5 digits it emits a final separator and NUL-terminates.
; ----------------------------------------------------------------------
FOUT_DIGITS_INT:
        PUSH DE
        ; point DE at the 10000/1000/100/10/1 little-endian table; A=$05 = 5 integer digit positions
        LD DE,POW10_INT_TABLE
        LD A,$05
; ----------------------------------------------------------------------
; FOUT_DIGITS_INT_1 -- one integer-digit pass (also the join target from the fraction loop)
;   In:        A = remaining digit count; DE -> current 16-bit power-of-ten in POW10_INT_TABLE;
;              (FAC) = remaining integer; HL = buffer pointer; B/C threaded for FOUT_DIGIT_SEP.
;              (Entered from FOUT_DIGITS_FRAC_5 with A=$04 and DE one entry into the table.)
;   Out:       one ASCII digit appended; (FAC) reduced by digit*power-of-ten; DE advanced to the
;              next table entry; loops (JR NZ) until A=0, then writes the trailing NUL and RETs.
;   Clobbers:  A,B,C,D,E,H,L, FAC, flags.
;   Algorithm: Emit pending '.'/',' (FOUT_DIGIT_SEP), fetch the current 16-bit power-of-ten into
;              the subtrahend (DE via the EX (SP),HL juggle), run FOUT_DIGITS_INT_2 to count
;              subtractions into B (the digit), add the power back once (ADD HL,DE) to restore
;              the non-negative remainder, store it to (FAC), write the digit byte, advance, and
;              DEC A loop.
; ----------------------------------------------------------------------
FOUT_DIGITS_INT_1:
        ; emit the decimal point or grouping comma when this digit position requires it
        CALL FOUT_DIGIT_SEP
        PUSH BC
        PUSH AF
        PUSH HL
        EX DE,HL
        LD C,(HL)
        INC HL
        LD B,(HL)
        PUSH BC
        INC HL
        EX (SP),HL
        EX DE,HL
        ; load the 16-bit remaining integer from the FAC for this digit's subtraction loop
        LD HL,(FAC)
        LD B,$2F
; ----------------------------------------------------------------------
; FOUT_DIGITS_INT_2 -- inner 16-bit trial-subtract loop counting one integer digit
;   In:        HL = remaining integer; DE = current 16-bit power-of-ten subtrahend; B = ASCII
;              digit accumulator (preset '0'-1).
;   Out:       B = decimal digit (subtraction count); HL = remainder after the borrowing
;              subtraction that broke the loop (over-subtracted by one power, restored by the
;              caller's ADD HL,DE).
;   Clobbers:  A,B,H,L, flags.
;   Algorithm: 16-bit subtract HL = HL - DE (LD A,L/SUB E/LD L,A; LD A,H/SBC A,D/LD H,A); while
;              no borrow (NC) INC B and repeat. The single over-subtraction at exit is undone by
;              the caller adding DE back.
; ----------------------------------------------------------------------
FOUT_DIGITS_INT_2:
        INC B
        ; 16-bit subtract of the power-of-ten from the remaining integer
        LD A,L
        SUB E
        LD L,A
        LD A,H
        SBC A,D
        LD H,A
        ; still non-negative: count this digit (INC B) and subtract the same power again
        JR NC,FOUT_DIGITS_INT_2
        ADD HL,DE
        LD (FAC),HL
        POP DE
        POP HL
        LD (HL),B
        INC HL
        POP AF
        POP BC
        DEC A
        JR NZ,FOUT_DIGITS_INT_1
        CALL FOUT_DIGIT_SEP
        LD (HL),A
        POP DE
        RET
; ----------------------------------------------------------------------
; FP_DBL_1E10 -- [RE] MBF double-precision power-of-ten scaling constant (DATA, not code)
;              8-byte little-endian MBF double, bytes 00 00 00 00 F9 02 15 A2 (high byte $A2).
;   In:        n/a (data). Loaded as a DE operand pointer at FOUT_SCALE10 ($5A4D), copied via
;              FP_MOVE_TYPED into ARG2_TEMP, then multiplied into the FAC by DMUL.
;   Out:       n/a.
;   Clobbers:  n/a.
;   Algorithm: [RE] Large power-of-ten multiplier used by FOUT_SCALE10 to pull a very small value
;              up into the [1,10) digit-generation range; the caller subtracts $0A from the
;              tracked decimal exponent per multiply (so this is on the order of 1e10). Exact
;              decimal magnitude UNKNOWN from these bytes alone. The current NOP/LD SP,HL/AND D
;              disassembly is a data-as-code artifact: the 8 bytes are an FP constant consumed
;              only as a DMUL operand.
; ----------------------------------------------------------------------
FP_DBL_1E10:
        NOP
        NOP
        NOP
        NOP
        LD SP,HL
        LD (BC),A
        DEC D
        AND D
; ----------------------------------------------------------------------
; FP_DBL_1E15 -- [RE] MBF double-precision comparison-bound constant (DATA, not code)
;              8-byte little-endian MBF double, bytes E1 FF 9F 31 A9 5F 63 B2 (high byte $B2).
;   In:        n/a (data). Loaded as a DE operand pointer at FOUT_SCALE10_4 ($5A73) and compared
;              against the FAC by DCOMP (which copies 8 bytes via FP_MOVE_TYPED for a double).
;   Out:       n/a.
;   Clobbers:  n/a.
;   Algorithm: [RE] An upper bound in the FOUT range-scaling logic (DCOMP decides whether the
;              value still needs another multiply/divide-by-ten step). Exact decimal magnitude
;              UNKNOWN. Disassembled as code here only as a data-as-code artifact; the bytes are
;              a DCOMP FP operand.
; ----------------------------------------------------------------------
FP_DBL_1E15:
        POP HL
        RST $38
        SBC A,A
        LD SP,$5FA9
        LD H,E
        OR D
; ----------------------------------------------------------------------
; FP_DBL_1E16 -- [RE] MBF double-precision comparison-bound constant (DATA, not code)
;              8-byte little-endian MBF double, bytes FE FF 03 BF C9 1B 0E B6 (high byte $B6).
;   In:        n/a (data). Loaded as a DE operand pointer at FOUT_SCALE10_STEP_1 ($5AA0) and
;              compared against the FAC by DCOMP.
;   Out:       n/a.
;   Clobbers:  n/a.
;   Algorithm: [RE] The bound used by FOUT_SCALE10_STEP when normalizing the FAC into the
;              digit-generation window. Exact decimal magnitude UNKNOWN. Disassembled as code
;              only as a data-as-code artifact; the bytes are a DCOMP FP operand. NOTE the last
;              two bytes ($0E,$B6) abut FP_CONST_HALF_DBL and are part of THIS constant, not the
;              next label.
; ----------------------------------------------------------------------
FP_DBL_1E16:
        CP $FF
        INC BC
        CP A
        RET
        DEC DE
        LD C,$B6
; ----------------------------------------------------------------------
; FP_CONST_HALF_DBL -- MBF double-precision constant 0.5 (rounding bias)
;              8-byte MBF double 0.5 = 00 00 00 00 00 00 00 80. NOTE the label as laid out covers
;              only the first 4 bytes ($5BD8..$5BDB = 00 00 00 00); the trailing 4 bytes overlap
;              FP_CONST_HALF_SNG ($5BDC = 00 00 00 80), which is itself the high half / single
;              0.5. The 8-byte double read starting here is therefore the concatenation of both.
;   In:        n/a (data). HL points here at FN_LPOS ($4F86) and in FOUT_DIGITS_FRAC ($5B05).
;   Out:       n/a.
;   Clobbers:  n/a.
;   Algorithm: DADD'd to a value before FIX_DENORM/integer-alignment so the truncation that
;              follows performs round-to-nearest on the last printed (or fixed) digit. The
;              overlap with FP_CONST_HALF_SNG is a deliberate space optimization: single 0.5 is
;              the top 4 bytes of double 0.5.
; ----------------------------------------------------------------------
FP_CONST_HALF_DBL:
        NOP
        NOP
        NOP
        NOP
; ----------------------------------------------------------------------
; FP_CONST_HALF_SNG -- MBF single-precision constant 0.5 (rounding bias)
;              4-byte MBF single 00 00 00 80, value +0.5. Also forms the high 4 bytes of the
;              overlapping FP_CONST_HALF_DBL (see that label).
;   In:        n/a (data). Loaded by FADD_LOAD_CONST/FADDT ($4B98) -- which ADDs it to the FAC --
;              and at FN_SQR ($5C90, as the 0.5 exponent for SQR = x^0.5) and in the
;              single-precision FOUT round path.
;   Out:       n/a.
;   Clobbers:  n/a.
;   Algorithm: FADD'd to the FAC for round-before-truncate in single-precision FOUT/FIX, and
;              reused as the literal exponent 0.5 by the square-root handler.
; ----------------------------------------------------------------------
FP_CONST_HALF_SNG:
        NOP
        NOP
        NOP
        ADD A,B
; ----------------------------------------------------------------------
; FP_CONST_ENOTATION_THRESHOLD -- [RE] MBF double FP magnitude threshold for switching to E notation
;              8-byte MBF double, bytes 00 00 04 BF C9 1B 0E B6 (high byte $B6).
;   In:        n/a (data). Loaded as the DE comparison operand at FOUT_CHOOSE_NOTATION ($593C) and
;              compared against the FAC by DCOMP.
;   Out:       n/a.
;   Clobbers:  n/a.
;   Algorithm: [RE] The magnitude at which numeric output switches between fixed and E
;              (scientific) notation in the FOUT exponent path (the JP M after DCOMP selects the
;              branch). Exact decimal value UNKNOWN from these bytes alone; the role is confirmed
;              by the DCOMP at the exponent-decision site.
; ----------------------------------------------------------------------
FP_CONST_ENOTATION_THRESHOLD:
        NOP
        NOP
        INC B
        CP A
        RET
        DEFB    $1B,$0E,$B6
; ----------------------------------------------------------------------
; FP_POW10_FRAC_TABLE -- MBF double-precision power-of-ten constant table (DATA)
;              10 descending entries of 7-byte double constants (the high-precision scaled tens),
;              70 bytes spanning $5BE8..$5C2D (10 = the A=$0A pass count in FOUT_DIGITS_FRAC_1;
;              70/7 = 10 entries).
;   In:        n/a (data). DE points here at FOUT_DIGITS_FRAC ($5B14); each entry consumed by
;              FOUT_DIGITS_FRAC_2 via DP_ADD_BLOCK (7-byte block).
;   Out:       n/a.
;   Clobbers:  n/a.
;   Algorithm: One fractional decimal digit is produced per entry by repeated borrowing
;              subtraction of that scaled-ten constant from the integer-aligned FAC_DBL fraction
;              (count of subtractions = the digit). Entries descend so successive digits are less
;              significant.
; ----------------------------------------------------------------------
FP_POW10_FRAC_TABLE:
        DEFB    $00,$80,$C6,$A4,$7E,$8D,$03,$00,$40,$7A,$10,$F3,$5A,$00,$00,$A0
        DEFB    $72,$4E,$18,$09,$00,$00,$10,$A5,$D4,$E8,$00,$00,$00,$E8,$76,$48
        DEFB    $17,$00,$00,$00,$E4,$0B,$54,$02,$00,$00,$00,$CA,$9A,$3B,$00,$00
        DEFB    $00,$00,$E1,$F5,$05,$00,$00,$00,$80,$96,$98,$00,$00,$00,$00,$40
        DEFB    $42,$0F,$00,$00,$00,$00
; ----------------------------------------------------------------------
; FP_POW10_FRAC_TABLE2 -- compact 3-byte power-of-ten constants for the low-precision fraction loop
;              6 bytes: A0 86 01 / 10 27 00 = the little-endian 24-bit values 100000 and 10000
;              (2 entries, matching the 2-pass FOUT_DIGITS_FRAC_5 loop).
;   In:        n/a (data). DE points here at FOUT_DIGITS_FRAC_4 ($5B55); each 3-byte constant is
;              consumed by the 24-bit subtract in FOUT_DIGITS_FRAC_6.
;   Out:       n/a.
;   Clobbers:  n/a.
;   Algorithm: Companion to FP_POW10_FRAC_TABLE for the single-precision (low-precision) path:
;              the 2-pass loop peels 2 fraction digits by subtracting these 24-bit scaled tens
;              from the FAC's low 3 mantissa bytes, then the code continues into the integer-digit
;              body for 4 more positions from POW10_INT_TABLE.
; ----------------------------------------------------------------------
FP_POW10_FRAC_TABLE2:
        DEFB    $A0,$86,$01,$10,$27,$00
; ----------------------------------------------------------------------
; POW10_INT_TABLE -- little-endian 16-bit power-of-ten table for integer-digit generation (DATA)
;              10 bytes: 10 27 / E8 03 / 64 00 / 0A 00 / 01 00 = 10000, 1000, 100, 10, 1.
;   In:        n/a (data). DE points here at FOUT_DIGITS_INT ($5B8C, 5 entries from the start);
;              also entered one element in (DE=$5C36) from the fraction tail for 4 entries.
;              Each 16-bit entry is the subtrahend for one integer digit in FOUT_DIGITS_INT_2.
;   Out:       n/a.
;   Clobbers:  n/a.
;   Algorithm: Drives the 5-digit divide-by-repeated-subtraction that converts a 16-bit integer
;              part to ASCII (and is reused for the trailing 4 digits of the single-precision
;              fraction).
; ----------------------------------------------------------------------
POW10_INT_TABLE:
        DEFB    $10,$27,$E8,$03,$64,$00,$0A,$00,$01,$00
; ----------------------------------------------------------------------
; HEX_OCT_OUT -- HEX$()/OCT$() and LIST &H/&O integer-to-ASCII converter
;   In:        FAC holds the value to render (GETADR fetches the 16-bit integer into HL). Entry
;              at HEX_OCT_OUT selects octal (base flag B=0); callers enter at HEX_OCT_OUT_1+1
;              ($5C41) to select hex (B=1) -- see HEX_OCT_OUT_1.
;   Out:       NUL-terminated ASCII string at L_0CC2 ($0CC2), with no leading zeros; HL left
;              pointing at the string start (the pushed buffer pointer popped at HEX_OCT_OUT_8)
;              on RET.
;   Clobbers:  A,B,C,D,E,H,L, the $0CC2 scratch buffer, flags.
;   Algorithm: XOR A / LD B,A zero B (octal), then fall into HEX_OCT_OUT_1. GETADR materializes
;              the 16-bit value; DE = the $0CC2 buffer (pushed for the final POP HL); C is set to
;              the group count (6 octal groups / 4 hex nibbles) by the DEC B/INC B base test.
;              Then shift groups of bits (3 octal / 4 hex) out of HL into A, convert each to an
;              ASCII digit, suppressing leading zeros, NUL-terminating at the end.
; ----------------------------------------------------------------------
HEX_OCT_OUT:
        ; octal entry: clear A and B=0 so the base-selector test below picks the octal width
        XOR A
        LD B,A
; ----------------------------------------------------------------------
; HEX_OCT_OUT_1 -- base-selector flag-skip plus the buffer/width setup shared by hex and octal
;   In:        B = 0 on octal entry (from HEX_OCT_OUT); hex callers JP/CALL HEX_OCT_OUT_1+1 so
;              the LD B,$01 (06 01) embedded in this JP's operand runs instead, setting B=1.
;              FAC holds the value.
;   Out:       HL = 16-bit value (GETADR); DE = $0CC2 buffer (also pushed as the eventual return
;              HL); C = group/nibble count; first buffer byte zeroed; control to
;              HEX_OCT_OUT_4 (octal's short first group) or falls into HEX_OCT_OUT_2 (hex).
;   Clobbers:  A,B,C,D,E,H,L, flags.
;   Algorithm: The 3-byte JP NZ,$0106 is a self-overlapping flag trick: octal (Z set on entry,
;              B=0) does not take the jump and skips its operand harmlessly; hex re-enters
;              mid-instruction at +1 so the operand bytes 06 01 execute as LD B,$01. GETADR
;              fetches the integer; the buffer pointer is staged in DE and pushed; DEC B/INC B
;              sets Z iff B=0 (octal) to pick C=6 groups (then JR Z to _4 for the short top group)
;              vs C=4 nibbles.
; ----------------------------------------------------------------------
HEX_OCT_OUT_1:
        JP NZ,$0106
        PUSH BC
        ; evaluate the FAC into a 16-bit unsigned integer in HL (the value to render)
        CALL GETADR
        POP BC
        ; DE = output scratch buffer $0CC2; pushed so the final POP HL returns the string start
        LD DE,L_0CC2
        PUSH DE
        XOR A
        LD (DE),A
        ; test the base flag: Z (B==0) selects octal (C=6 three-bit groups); NZ selects hex (C=4 nibbles)
        DEC B
        INC B
        LD C,$06
        JR Z,HEX_OCT_OUT_4
        LD C,$04
; ----------------------------------------------------------------------
; HEX_OCT_OUT_2 -- start of a hex nibble group: shift the first bit of a 4-bit digit out of HL
;   In:        HL = value being rendered; A accumulates the current digit's bits; C = remaining
;              group count.
;   Out:       falls into HEX_OCT_OUT_3 to shift the remaining bits of this group.
;   Clobbers:  A,H,L, flags.
;   Algorithm: ADD HL,HL / ADC A,A shifts the high bit of HL into A. This is the hex (4-bit)
;              group entry: _2 contributes 1 bit, _3 two bits, _4 one bit = 4. Octal groups enter
;              at _3 (3 bits: _3 two + _4 one) or, for the short top group, at _4 (1 bit).
; ----------------------------------------------------------------------
HEX_OCT_OUT_2:
        ; shift the next value bit out of HL into A (first bit of a hex nibble)
        ADD HL,HL
        ADC A,A
; ----------------------------------------------------------------------
; HEX_OCT_OUT_3 -- shift two more bits into the current digit (group body)
;   In:        HL = value; A = partial digit; C = group count.
;   Out:       falls into HEX_OCT_OUT_4 for the final bit of the group.
;   Clobbers:  A,H,L, flags.
;   Algorithm: Two ADD HL,HL / ADC A,A pairs shift two further value bits into A. Octal groups
;              (3 bits) re-enter here from HEX_OCT_OUT_7's loop (then _4 = 3 bits total); hex
;              groups (4 bits) flow through from HEX_OCT_OUT_2.
; ----------------------------------------------------------------------
HEX_OCT_OUT_3:
        ADD HL,HL
        ADC A,A
        ADD HL,HL
        ADC A,A
; ----------------------------------------------------------------------
; HEX_OCT_OUT_4 -- finish a digit group and resolve the leading-zero suppression
;   In:        HL = value; A = assembled group value so far; DE = current buffer position;
;              C = remaining group count; (DE) holds the prior emitted byte (0 until a digit
;              has been emitted).
;   Out:       the group value either flows to HEX_OCT_OUT_5 to be formatted/stored, or (a
;              suppressed leading zero) jumps to HEX_OCT_OUT_7 to advance without storing.
;   Clobbers:  A,H,L, flags.
;   Algorithm: Shift the final bit of the group into A (ADD HL,HL/ADC A,A). If A is nonzero it
;              is a real digit -> _5. If A is zero but this is the LAST group (C==1) the zero is
;              still emitted (so a lone/final zero prints). Otherwise a zero is a leading zero:
;              read (DE); if it is still 0 (nothing emitted yet) skip to _7, else fall through
;              with A=0 to emit the zero.
; ----------------------------------------------------------------------
HEX_OCT_OUT_4:
        ADD HL,HL
        ADC A,A
        ; nonzero group value: it is a real digit, go format it
        OR A
        JP NZ,HEX_OCT_OUT_5
        LD A,C
        DEC A
        JP Z,HEX_OCT_OUT_5
        ; zero digit and not the last group: (DE) is the last emitted byte (0 = none yet) -> keep suppressing leading zeros
        LD A,(DE)
        OR A
        JP Z,HEX_OCT_OUT_7
        XOR A
; ----------------------------------------------------------------------
; HEX_OCT_OUT_5 -- convert a 0..15 group value to its ASCII digit character
;   In:        A = group value (0..7 octal, 0..15 hex).
;   Out:       A = ASCII character ('0'..'9','A'..'F'); falls into HEX_OCT_OUT_6 to store.
;   Clobbers:  A, flags.
;   Algorithm: A += '0'; if the result exceeds '9' (CP $3A, no carry) add 7 to skip the
;              ':'..'@' gap so 10..15 map to 'A'..'F'.
; ----------------------------------------------------------------------
HEX_OCT_OUT_5:
        ADD A,$30
        CP $3A
        JP C,HEX_OCT_OUT_6
        ; value 10..15: add 7 to jump the ASCII gap from '9' up to 'A'..'F'
        ADD A,$07
; ----------------------------------------------------------------------
; HEX_OCT_OUT_6 -- store the digit character and seed the 'something emitted' marker forward
;   In:        A = ASCII digit (nonzero); DE = buffer write position.
;   Out:       digit stored at (DE), DE advanced, and the SAME digit byte written one position
;              forward; falls into HEX_OCT_OUT_7.
;   Clobbers:  D,E.
;   Algorithm: LD (DE),A; INC DE; LD (DE),A. The forward copy of the (nonzero) digit makes the
;              next group's leading-zero test at HEX_OCT_OUT_4 (LD A,(DE)/OR A) see a non-zero
;              byte, i.e. 'a digit has been emitted', so later zeros are no longer suppressed. It
;              is NOT a NUL terminator -- the real NUL is written later at HEX_OCT_OUT_8.
; ----------------------------------------------------------------------
HEX_OCT_OUT_6:
        LD (DE),A
        INC DE
        LD (DE),A
; ----------------------------------------------------------------------
; HEX_OCT_OUT_7 -- advance to the next group; loop or finish
;   In:        C = remaining group count; B = base flag (0 octal / 1 hex).
;   Out:       clears A (fresh digit accumulator); if groups remain, loops back to
;              HEX_OCT_OUT_3 (octal, 3-bit) or HEX_OCT_OUT_2 (hex, 4-bit); else falls into
;              HEX_OCT_OUT_8 to terminate.
;   Clobbers:  A,C, flags.
;   Algorithm: XOR A resets the per-digit accumulator; DEC C tests for the last group; the
;              DEC B/INC B re-reads the base flag to pick the correct group width on re-entry.
; ----------------------------------------------------------------------
HEX_OCT_OUT_7:
        XOR A
        ; one group consumed; if none remain, jump to the NUL-terminate tail
        DEC C
        JR Z,HEX_OCT_OUT_8
        ; re-test the base flag to re-enter the 3-bit (octal) or 4-bit (hex) group loop
        DEC B
        INC B
        JP Z,HEX_OCT_OUT_3
        JP HEX_OCT_OUT_2
; ----------------------------------------------------------------------
; HEX_OCT_OUT_8 -- NUL-terminate the rendered string and return its start
;   In:        DE = position just past the last digit; A = 0 (from the XOR A in _7); the buffer
;              start ($0CC2) was pushed at setup.
;   Out:       (DE) = 0 (string terminator); HL = buffer start; RET.
;   Clobbers:  H,L.
;   Algorithm: Store the NUL (A=0), POP HL (the saved $0CC2 pointer) so the caller receives the
;              string start, and return.
; ----------------------------------------------------------------------
HEX_OCT_OUT_8:
        LD (DE),A
        POP HL
        RET
; ----------------------------------------------------------------------
; FAC_NEGATE_VIA -- tail-call trampoline that arranges FP_NEG to run as the caller's return
;   In:        top of stack = the original caller's return address; FAC holds the value
;   Out:       jumps into the routine whose address was on the stack, having spliced FP_NEG in
;              below so that FP_NEG runs (negating the FAC) when that path eventually RETs
;   Clobbers:  HL (and FAC sign once FP_NEG runs)
;   Algorithm: Load HL = FP_NEG, EX (SP),HL to swap it with the saved return address (HL now
;              holds that original return), then JP (HL) to continue there with FP_NEG left on
;              the stack as the eventual return. Used as the conditional-negate hook in FN_SQR's
;              power path and FN_ATN so a sign flip happens on the way back without an explicit
;              CALL/RET pair.
; ----------------------------------------------------------------------
FAC_NEGATE_VIA:
        LD HL,FP_NEG
        ; splice FP_NEG under the caller's return address: FP_NEG will run when this path eventually RETs
        EX (SP),HL
        ; resume at the original return target, with the negate now pending below it on the stack
        JP (HL)
; ----------------------------------------------------------------------
; FN_SQR -- SQR(x) square-root handler (token $07); shares the x^y power kernel body
;   In:        FAC holds x (the radicand)
;   Out:       FAC = sqrt(x); RETs via the pushed CLEAR_EVAL_FLAG_0CB6 tail
;   Clobbers:  FAC, FP work stack, A/BC/DE/HL, L_0CB6
;   Algorithm: SQR is computed as x^0.5. Push x (FAC_PUSH), load the exponent operand 0.5
;              (FP_CONST_HALF_SNG) into the FAC, and fall into the shared power body at FN_SQR_2.
;              The power kernel computes base^exp = EXP(exp * LOG(base)) with special cases:
;              exp==0 -> 1 (via the FN_EXP tail); base==0 (on the exp>0 path) -> 0; an integer/
;              odd-integer exponent of a negative base is allowed and its sign tracked (FIX_SCALE
;              /FCOMP decide integer-ness and parity, FAC_NEGATE_VIA/FP_NEG apply the final sign).
;              LOG(|base|) -> *exp -> EXP gives the result. CLEAR_EVAL_FLAG_0CB6 is pushed as the
;              common exit (zeroes the $0CB6 FP/numeric-eval state flag set to 1 below).
; ----------------------------------------------------------------------
FN_SQR:
        CALL FAC_PUSH
        ; SQR(x) == x^0.5: load 0.5 as the exponent and reuse the power-operator body
        LD HL,FP_CONST_HALF_SNG
        CALL FP_STORE_REGS_LD
        JR FN_SQR_2
POWER_OP_APPLY:
        CALL FN_CSNG
FN_SQR_2:
        POP BC
        POP DE
        LD HL,CLEAR_EVAL_FLAG_0CB6
        PUSH HL
        ; set the $0CB6 FP/numeric-eval state flag; CLEAR_EVAL_FLAG_0CB6 (pushed as the exit) zeroes it on return
        LD A,$01
        LD (L_0CB6),A
        CALL FP_SIGN
        LD A,B
        ; exponent == 0: base^0 = 1, jump to the EXP tail which yields 1.0
        JR Z,FN_EXP
        JP P,FN_SQR_3
        OR A
        JP Z,DIV0_SET_MSG
FN_SQR_3:
        OR A
        ; base == 0 (positive-exponent path): result is 0
        JP Z,FP_SET_ZERO_EXP
        PUSH DE
        PUSH BC
        LD A,C
        OR $7F
        CALL FP_LOAD_FAC
        JP P,FN_SQR_4
        PUSH DE
        PUSH BC
        ; test whether the exponent is a whole number (needed to allow a negative base and to find odd/even parity for the sign)
        CALL FIX_SCALE
        POP BC
        POP DE
        PUSH AF
        CALL FCOMP
        POP HL
        LD A,H
        RRA
FN_SQR_4:
        POP HL
        LD (FACHI),HL
        POP HL
        LD (FAC),HL
        ; negative base with an odd integer exponent: queue a final negate of the result
        CALL C,FAC_NEGATE_VIA
        CALL Z,FP_NEG
        PUSH DE
        PUSH BC
        ; x^y via logarithms: compute LOG(|base|)
        CALL FN_LOG
        POP BC
        POP DE
        ; multiply by the exponent: exp * LOG(base); the fall-through into FN_EXP exponentiates it
        CALL FMUL
; ----------------------------------------------------------------------
; FN_EXP -- EXP(x) e^x handler (token $0B); also the back half of the x^y power kernel
;   In:        FAC holds x (the exponent); reached as a function or by FN_SQR after exp*LOG(base)
;   Out:       FAC = e^x; underflow returns 0, overflow raises via OVERR_POP2
;   Clobbers:  FAC, FP work stack, A/BC/DE/HL, FAC_EXP
;   Algorithm: e^x = 2^(x*log2 e). Multiply x by log2(e) (operand B=$81, C/D/E=$38,$AA,$3B =
;              MBF 1.442695) so the problem becomes 2^v. Magnitude guards on the scaled exponent
;              FAC_EXP: >= $88 -> the large-magnitude path FN_EXP_1, which then splits by the
;              FACHI sign (positive -> OVERR_POP2 overflow, negative -> FP_SET_ZERO underflow=0);
;              < $68 -> v ~ 0, return MBF 1.0 (FN_EXP_4). Otherwise split v into integer part i
;              and fraction f (FIX_SCALE), bias i as an MBF exponent (ADD $81), approximate 2^f
;              with FP_POLY_EXP_COEFFS (POLY_EVAL), then re-apply the integer scale by FMUL with
;              the operand exponent = i and zero mantissa (DE=0, C=0) to get 2^v = e^x.
; ----------------------------------------------------------------------
FN_EXP:
        ; e^x = 2^(x * log2 e): scale x by log2(e) = 1.442695 (MBF exp=$81, mantissa $38,$AA,$3B) so the kernel works in base 2
        LD BC,$8138
        LD DE,$AA3B
        CALL FMUL
        LD A,(FAC_EXP)
        ; magnitude guard: scaled exponent too large -> large-magnitude path (overflow if positive, underflow->0 if negative)
        CP $88
        JP NC,FN_EXP_1
        ; magnitude tiny -> e^x rounds to 1.0 (FN_EXP_4)
        CP $68
        JP C,FN_EXP_4
        CALL FAC_PUSH
        ; split scaled v into integer part (the power of two) and fractional remainder f
        CALL FIX_SCALE
        ADD A,$81
        POP BC
        POP DE
        JP Z,FN_EXP_2
        PUSH AF
        ; isolate the fraction f = v - int(v) for the polynomial
        CALL FSUB
        ; approximate 2^f with the EXP coefficient polynomial
        LD HL,FP_POLY_EXP_COEFFS
        CALL POLY_EVAL
        POP BC
        LD DE,$0000
        LD C,D
        ; re-apply the integer power of two: result = 2^f * 2^int = 2^v = e^x
        JP FMUL
FN_EXP_1:
        CALL FAC_PUSH
FN_EXP_2:
        LD A,(FACHI)
        OR A
        JP P,FN_EXP_3
        POP AF
        POP AF
        ; underflow: e^x rounds to 0
        JP FP_SET_ZERO
FN_EXP_3:
        JP OVERR_POP2
FN_EXP_4:
        ; tiny argument: return exactly 1.0 (MBF exp=$81, mantissa 0)
        LD BC,$8100
        LD DE,$0000
        CALL FP_STORE_FAC
        RET
; [RE] EXP() coefficient pool: MBF polynomial { count byte; N x 4-byte MBF } with count=$07 -> 7 coefficients ($5D3A-$5D55). Evaluated by POLY_EVAL (Horner) from FN_EXP ($5D0F/$5D12) to approximate 2^f for the fractional part f after FN_EXP scales x by log2(e) and splits off the integer exponent (FIX_SCALE).
FP_POLY_EXP_COEFFS:
        DEFB    $07,$7C,$88,$59,$74,$E0,$97,$26,$77,$C4,$1D,$1E,$7A,$5E,$50,$63
        DEFB    $7C,$1A,$FE,$75,$7E,$18,$72,$31,$80,$00,$00,$00,$81
; ----------------------------------------------------------------------
; POLY_EVAL_ODD -- evaluate x * P(x^2): odd-power series wrapper for SIN/TAN/ATN
;   In:        FAC = x; HL -> coefficient table (count byte then MBF coefficients)
;   Out:       FAC = x * P(x^2)
;   Clobbers:  FAC, FP work stack, A/BC/DE/HL
;   Algorithm: Push x (FAC_PUSH). Queue IMUL_6 ('POP BC/POP DE then JP FMUL') as the return so the
;              final step multiplies the polynomial result by the saved x. Push the coefficient
;              pointer, reload x (FP_LOAD_FAC), FMUL it by itself to form x^2 in the FAC, pop the
;              coefficient pointer, and fall into POLY_EVAL to compute P(x^2) by Horner. On its
;              return the queued IMUL_6 pops the saved x and FMULs, giving the odd series
;              x*P(x^2). Used where the series has only odd powers.
; ----------------------------------------------------------------------
POLY_EVAL_ODD:
        CALL FAC_PUSH
        ; queue the final 'multiply by x' step: IMUL_6 pops the saved argument and FMULs it after the polynomial returns
        LD DE,IMUL_6
        PUSH DE
        PUSH HL
        CALL FP_LOAD_FAC
        ; square the argument: evaluate P in x^2 so an odd series becomes x*P(x^2)
        CALL FMUL
        POP HL
; ----------------------------------------------------------------------
; POLY_EVAL -- Horner polynomial evaluator over an MBF coefficient pool (shared transcendental core)
;   In:        FAC = argument t; HL -> table = { count byte N; N consecutive 4-byte MBF coefficients,
;              highest-degree first }
;   Out:       FAC = ((c0*t + c1)*t + c2)... = P(t)
;   Clobbers:  FAC, FP work stack, A/BC/DE/HL
;   Algorithm: Push t (FAC_PUSH). Read N (count), seed the FAC with the first/highest coefficient
;              (FP_STORE_REGS_LD). Loop: FMUL the accumulator by t, then FADD the next coefficient
;              loaded from the table (FP_LOAD_MEM + FADD_ALIGN), decrementing the count to zero.
;              The dual-entry POLY_EVAL_1 cover idiom (the byte $F1 of LD B,$F1 also runs as POP
;              AF when the loop re-enters at POLY_EVAL_1+1) discards the per-iteration PUSH AF and
;              then pops the saved BC/DE each pass. Shared by LOG/EXP/SIN/COS/TAN/ATN.
; ----------------------------------------------------------------------
POLY_EVAL:
        CALL FAC_PUSH
        ; read the coefficient count N (table is N, then N high-to-low MBF coefficients)
        LD A,(HL)
        INC HL
        ; seed the Horner accumulator with the highest-degree coefficient
        CALL FP_STORE_REGS_LD
; [RE] VERIFIED flag-skip. POLY_EVAL_1 ($5D6D) opcode-eating dual entry. First pass (fall-through from FP_STORE_REGS_LD CALL at $5D6A) executes LD B,$F1 (06 F1); the $06 opcode swallows the $F1, so the first iteration pops only BC,DE. The Horner loop re-enters via JR POLY_EVAL_1+1 ($5D6E), running $F1 as POP AF to discard the per-iteration PUSH AF ($5D75) before popping BC,DE. B=$F1 is dead (overwritten by POP BC at $5D6F). Cover is genuinely executed on fall-through; MBASIC twin byte-identical.
POLY_EVAL_1:
        LD B,$F1
        POP BC
        POP DE
        DEC A
        RET Z
        PUSH DE
        PUSH BC
        PUSH AF
        PUSH HL
        ; Horner step: accumulator *= argument t
        CALL FMUL
        POP HL
        ; fetch the next coefficient from the table
        CALL FP_LOAD_MEM
        PUSH HL
        ; Horner step: accumulator += next coefficient
        CALL FADD_ALIGN
        POP HL
        ; loop back through the cover byte (runs $F1 as POP AF) for the next coefficient
        JR POLY_EVAL_1+1
RND_SEED_DEFAULT:
        DEFB    $52,$C7,$4F,$80
POLY_EVAL_2:
        CALL CHRGET
; ----------------------------------------------------------------------
; RND_SEED_RESET -- (mislabeled) RND reseed helper: advance/reseed the RND generator with a fixed argument
;   In:        HL preserved across the call; reached from STMT_RANDOMIZE (the RANDOMIZE statement,
;              which first stores the user seed into RNDX_SEED_WORD) and from the RND-with-no-
;              argument entry POLY_EVAL_2 ($5D89, which CHRGETs then falls through here)
;   Out:       RND state advanced/reseeded; FAC numeric type set to single; HL restored
;   Clobbers:  FAC, A/BC/DE; HL restored
;   Algorithm: It does NOT evaluate a polynomial in sqrt(x) (the prior 'evaluate poly in sqrt(x)'
;              description is unsupported by the bytes). OBSERVED: save HL, load the constant at
;              L_4CA6 (MBF $00,$00,$00,$81 = 1.0) into the FAC registers (FP_STORE_REGS_LD), call
;              FN_RND to fold the generator with that argument, restore HL, then JP into
;              SET_TYPE_DOUBLE_1+1 which runs as LD A,$04 -> VALTYP = single. [RE] this is the RND
;              reseed/advance shim invoked by RANDOMIZE and by RND with no parentheses.
; ----------------------------------------------------------------------
RND_SEED_RESET:
        PUSH HL
        ; load the constant at L_4CA6 (MBF $00,$00,$00,$81 = 1.0) into the FAC registers as the RND argument
        LD HL,L_4CA6
        CALL FP_STORE_REGS_LD
        ; fold that argument through the RND generator to advance/reseed the running random state
        CALL FN_RND
        POP HL
        JP SET_TYPE_DOUBLE_1+1
; ----------------------------------------------------------------------
; FN_RND -- RND(x) pseudo-random number generator (token $08)
;   In:        FAC = x: x<0 reseeds the index/counter state from x; x==0 returns the last value;
;              x>0 advances. State in RNDX_SEED (4-byte MBF) plus the three index/counter cells
;              RND_WRAP_COUNTER/RND_CONST_INDEX/RND_MULT_INDEX
;   Out:       FAC = next pseudo-random value; RNDX_SEED updated (FAC also holds the result)
;   Clobbers:  FAC, A/BC/DE/HL, RNDX_SEED and the three index/counter cells
;   Algorithm: [RE] MS BASIC-80-style linear-congruential-on-MBF RNG. FP_SIGN selects the path.
;              For x<0 (FN_RND_3) the FAC sign byte is written into the THREE index/counter cells
;              RND_MULT_INDEX/RND_CONST_INDEX/RND_WRAP_COUNTER (HL=RND_MULT_INDEX, two DEC HL) to
;              make the index sequence deterministic, then fall into the fold. The advance loads
;              the seed, multiplies it by a constant chosen via RND_MULT_INDEX (AND $07 -> one of
;              8 multiplier slots), and FADDs an additive constant chosen via RND_CONST_INDEX
;              (cycled 0..3, skipping value 1). The result's mantissa is perturbed (XOR $4F, top
;              byte forced $80 to keep it in [0,1)); RND_WRAP_COUNTER counts mod $AB and on wrap
;              perturbs the mantissa (INC C/DEC D/INC E) to lengthen the period. The new value is
;              stored back to RNDX_SEED and returned in the FAC.
; ----------------------------------------------------------------------
FN_RND:
        CALL FP_SIGN
        LD HL,RND_MULT_INDEX
        ; negative argument: deterministic reseed (FN_RND_3 overwrites the three index/counter cells RND_MULT_INDEX/RND_CONST_INDEX/RND_WRAP_COUNTER with the FAC sign byte), then fold
        JP M,FN_RND_3
        LD HL,RNDX_SEED
        CALL FP_STORE_REGS_LD
        LD HL,RND_MULT_INDEX
        ; zero argument: return the previously generated value unchanged
        RET Z
        ADD A,(HL)
        ; pick one of eight multiplier constants for this advance
        AND $07
        LD B,$00
        LD (HL),A
        INC HL
        ADD A,A
        ADD A,A
        LD C,A
        ADD HL,BC
        CALL FP_LOAD_MEM
        ; multiplicative step: seed *= selected multiplier constant
        CALL FMUL
        LD A,(RND_CONST_INDEX)
        INC A
        ; cycle the additive-constant index 0..3 (the CP $01/ADC skips slot 1)
        AND $03
        LD B,$00
        CP $01
        ADC A,B
        LD (RND_CONST_INDEX),A
        LD HL,RNDX_SEED
        ADD A,A
        ADD A,A
        LD C,A
        ADD HL,BC
        ; additive step: += the selected additive constant
        CALL FADD_FROM_MEM
FN_RND_1:
        CALL FP_LOAD_FAC
        LD A,E
        LD E,C
        XOR $4F
        LD C,A
        LD (HL),$80
        DEC HL
        LD B,(HL)
        LD (HL),$80
        LD HL,RND_WRAP_COUNTER
        INC (HL)
        LD A,(HL)
        ; wrap counter reaches $AB: zero it and perturb the mantissa to extend the period
        SUB $AB
        JR NZ,FN_RND_2
        LD (HL),A
        INC C
        DEC D
        INC E
FN_RND_2:
        CALL FADD
        LD HL,RNDX_SEED
        ; store the new value (FAC) back to RNDX_SEED; the FAC still holds it as the return value
        JP FP_MOVE_TO_FAC
FN_RND_3:
        LD (HL),A
        DEC HL
        LD (HL),A
        DEC HL
        LD (HL),A
        JR FN_RND_1
RND_WRAP_COUNTER:
        NOP
RND_CONST_INDEX:
        NOP
RND_MULT_INDEX:
        NOP
        DEC (HL)
        LD C,D
        JP Z,$3999
        INC E
        HALT
        DEFB    $98,$22,$95,$B3,$98,$0A,$DD,$47,$98,$53,$D1,$99,$99,$0A,$1A,$9F
        DEFB    $98,$65,$BC,$CD,$98,$D6,$77,$3E,$98
; [RE] RND seed (RNDX) work cell, low byte of the 4-byte running random state at $5E24-$5E27. CLEAR/RUN re-initializes it from a default constant ($68AE FP_MOVE4 from $5D85); FN_RND multiplies/updates it; also reused as FP scratch by FN_SQR ($5DA3/$5DCC/$5DF4)
RNDX_SEED:
        DEFB    "R"
; [RE] RND seed mantissa word (upper 3 bytes of the RNDX state at $5E25-$5E27): RANDOMIZE stores the new seed here via STMT_RANDOMIZE_3 ($4483 LD ($5E25),HL)
RNDX_SEED_WORD:
        DEFB    $C7,$4F,$80,$68,$B1,$46,$68,$99,$E9,$92,$69,$10,$D1,$75,$68
; ----------------------------------------------------------------------
; FN_COS -- COS(x) cosine handler (token $0C)
;   In:        FAC = x (radians)
;   Out:       FAC = cos(x); falls into FN_SIN
;   Clobbers:  FAC, A/BC/DE/HL
;   Algorithm: cos(x) = sin(x + pi/2). Add the constant pi/2 (FP_CONST_HALFPI) to the FAC and
;              fall straight into FN_SIN, which range-reduces the shifted angle and evaluates the
;              sine series. No separate cosine polynomial exists.
; ----------------------------------------------------------------------
FN_COS:
        ; cos(x) = sin(x + pi/2): add the quarter period (pi/2), then fall into the SIN path
        LD HL,FP_CONST_HALFPI
        CALL FADD_FROM_MEM
; ----------------------------------------------------------------------
; FN_SIN -- SIN(x) sine handler (token $09); also the shared tail of COS and TAN
;   In:        FAC = x (radians); FAC_EXP = FAC exponent
;   Out:       FAC = sin(x)
;   Clobbers:  FAC, FP work stack, A/BC/DE/HL, FACHI
;   Algorithm: Small-angle fast path: if the exponent FAC_EXP < $77 (|x| ~< 2^-8) return x
;              unchanged. Else range-reduce: multiply by 1/(2*pi) (operand B=$7E,C/D/E=$22,$F9,$83
;              = 0.15915) so a full period is 1.0, take the fractional part (FIX_SCALE + FSUB) to
;              land in [0,1). Fold that fraction into the first quadrant via the compares against
;              $7F00 (=0.25) and the $7F80/$8080 (= -0.25/-0.5) FADDs with a conditional FP_NEG,
;              recording the final sign in FACHI's top bit. Evaluate the odd sine series x*P(x^2)
;              over FP_POLY_SIN_COEFFS (POLY_EVAL_ODD), then re-apply the saved sign so the result
;              matches the original quadrant. [RE] the exact quadrant arithmetic is inferred.
; ----------------------------------------------------------------------
FN_SIN:
        LD A,(FAC_EXP)
        CP $77
        ; small-angle shortcut: for tiny |x| (exponent < $77), sin(x) ~= x, return the argument unchanged
        RET C
        ; range-reduce: scale by 1/(2*pi) = 0.15915 so one full revolution becomes 1.0
        LD BC,$7E22
        LD DE,$F983
        CALL FMUL
        CALL FAC_PUSH
        ; drop whole revolutions: keep only the fractional turn in [0,1)
        CALL FIX_SCALE
        POP BC
        POP DE
        CALL FSUB
        LD BC,$7F00
        LD DE,$0000
        CALL FCOMP
        ; [RE] fraction already in the lower range: skip the quadrant-folding adjustments
        JP M,FN_SIN_1
        LD BC,$7F80
        LD DE,$0000
        CALL FADD_ALIGN
        LD BC,$8080
        LD DE,$0000
        CALL FADD_ALIGN
        CALL FP_SIGN
        ; [RE] conditionally reflect the angle to fold it toward the first quadrant
        CALL P,FP_NEG
        LD BC,$7F00
        LD DE,$0000
        CALL FADD_ALIGN
        CALL FP_NEG
FN_SIN_1:
        LD A,(FACHI)
        OR A
        PUSH AF
        JP P,FN_SIN_2
        XOR $80
        LD (FACHI),A
FN_SIN_2:
        ; evaluate the odd sine series x*P(x^2) on the folded angle
        LD HL,FP_POLY_SIN_COEFFS
        CALL POLY_EVAL_ODD
        POP AF
        RET P
        LD A,(FACHI)
        ; re-apply the quadrant sign so the result matches the original argument
        XOR $80
        LD (FACHI),A
        RET
        DEFB    $00,$00,$00,$00,$83,$F9,$22,$7E
; [RE] MBF constant pair for the transcendental code: log2(e)=1.442695 followed by 0.5. FN_EXP loads it ($5E34) to scale x by log2(e); FN_TAN returns with HL pointing here ($5EFE).
FP_CONST_HALFPI:
        DEFB    $DB,$0F,$49,$81,$00,$00,$00,$7F
; [RE] SIN/COS coefficient pool (FP_POLY_SIN_COEFFS): MBF polynomial { count byte; N x 4-byte MBF } with count=$05 -> 5 coefficients ($5EB3-$5EC6, 20 bytes). Evaluated as x*P(x^2) by POLY_EVAL_ODD from FN_SIN ($5E91; the call site label FN_RND_2 is a code-overlap artifact, not RND). DUAL USE: reused as a rotating XOR key table by the protected-program scramble (PROG_UNSCRAMBLE $8152, PROG_SCRAMBLE $817B), indexed mod-11 by the C counter -- name KEPT to preserve both identities.
FP_POLY_SIN_COEFFS:
        DEFB    $05,$FB,$D7,$1E,$86,$65,$26,$99,$87,$58,$34,$23,$87,$E1,$5D,$A5
        DEFB    $86,$DB,$0F,$49,$83
; ----------------------------------------------------------------------
; FN_TAN -- TAN(x) tangent handler (token $0D)
;   In:        FAC = x (radians)
;   Out:       FAC = tan(x) = sin(x)/cos(x); returns via the divide tail
;   Clobbers:  FAC, FP work stack, A/BC/DE/HL
;   Algorithm: tan(x) = sin(x)/cos(x). Push x, compute FN_SIN(x) and stash it (FP_STORE_FAC),
;              restore x and compute FN_COS(x). Finally JP FDIV_POP_ARGS, which pops the saved
;              sine as the dividend operand and FDIVs by the FAC (cosine), since FDIV computes
;              operand/FAC. No dedicated tangent polynomial.
; ----------------------------------------------------------------------
FN_TAN:
        CALL FAC_PUSH
        ; tan(x) = sin(x)/cos(x): compute the numerator sin(x) and stash it
        CALL FN_SIN
        POP BC
        POP HL
        CALL FAC_PUSH
        EX DE,HL
        CALL FP_STORE_FAC
        ; compute the denominator cos(x) (the saved x is reloaded into the FAC first)
        CALL FN_COS
        ; pop the saved sin as the operand and FDIV by cos (FDIV = operand/FAC) -> tan(x)
        JP FDIV_POP_ARGS
; ----------------------------------------------------------------------
; FN_ATN -- ATN(x) arctangent handler (token $0E)
;   In:        FAC = x
;   Out:       FAC = atan(x) in radians, range (-pi/2, pi/2)
;   Clobbers:  FAC, FP work stack, A/BC/DE/HL, FAC_EXP
;   Algorithm: Reduce to a non-negative argument <= 1 via two identities. atan(-x) = -atan(x):
;              for x<0, queue a final negate (FAC_NEGATE_VIA) and take |x| (FP_NEG). atan(x) =
;              pi/2 - atan(1/x) for |x|>=1: if the exponent FAC_EXP >= $81, FDIV 1/x (operand 1.0)
;              and queue FADD_FROM_MEM_1, which on return loads (HL) and SUBTRACTS the series
;              result from it (FADD_FROM_MEM_1 = load then FSUB = operand - FAC). Then evaluate
;              the odd arctangent series x*P(x^2) over FP_POLY_ATN_COEFFS (POLY_EVAL_ODD) and set
;              HL = FP_CONST_HALFPI (pi/2) so the queued subtract yields pi/2 - atan(1/x).
; ----------------------------------------------------------------------
FN_ATN:
        CALL FP_SIGN
        ; atan(-x) = -atan(x): for negative x, queue a final result negate
        CALL M,FAC_NEGATE_VIA
        ; work with |x| from here on
        CALL M,FP_NEG
        LD A,(FAC_EXP)
        ; if exponent >= $81 (|x| >= 1) use atan(x) = pi/2 - atan(1/x) to keep the series argument small
        CP $81
        JR C,FN_ATN_1
        LD BC,$8100
        LD D,C
        LD E,C
        ; reciprocate: operand 1.0 / FAC -> argument becomes 1/x (in [0,1])
        CALL FDIV
        ; queue the pi/2 minus correction: on return, load (HL) and subtract the series result from it (FSUB = operand - FAC)
        LD HL,FADD_FROM_MEM_1
        PUSH HL
FN_ATN_1:
        ; evaluate the odd arctangent series x*P(x^2)
        LD HL,FP_POLY_ATN_COEFFS
        CALL POLY_EVAL_ODD
        ; point HL at pi/2 (FP_CONST_HALFPI) so the queued FADD_FROM_MEM_1 computes pi/2 - result
        LD HL,FP_CONST_HALFPI
        RET
; [RE] ATN() coefficient pool: MBF polynomial { count byte; N x 4-byte MBF } with count=$09 -> 9 coefficients ($5F03-$5F26, 36 bytes). Evaluated as x*P(x^2) by POLY_EVAL_ODD from FN_ATN ($5EF8/$5EFB) (the odd-power series for arctangent). DUAL USE: the protected-program scrambler reuses these raw bytes as a rotating XOR key (PROG_UNSCRAMBLE $8144, PROG_SCRAMBLE $8189), indexed mod-13 by the B counter -- the byte values, not their FP value, are what matter there.
FP_POLY_ATN_COEFFS:
        DEFB    $09,$4A,$D7,$3B,$78,$02,$6E,$84,$7B,$FE,$C1,$2F,$7C,$74,$31,$9A
        DEFB    $7D,$84,$3D,$5A,$7D,$C8,$7F,$91,$7E,$E4,$BB,$4C,$7E,$6C,$AA,$AA
        DEFB    $7F,$00,$00,$00,$81
L_5F27:
        DEFB    $2B,$CD
        DEFW    CHRGET
        DEFB    $C8,$CD
        DEFW    SYNCHR
        DEFB    ","
; ----------------------------------------------------------------------
; PTRGET -- variable-reference front-end: parse a variable name at the BASIC text pointer, resolve its value type, then locate or create its storage.
;   In:        HL -> BASIC text just before the variable name (first letter fetched via LD C,(HL)). PTRGET_SUBSCRIPT_FLAG ($0B52), preset by the caller, selects scalar-only vs array-or-scalar resolution. Entry mode sets the create context: falling in from the PTRGET head (the DIM dispatch DEFW PTRGET at $0112) runs OR $AF, leaving PTRGET_CREATE_FLAG ($0B13) nonzero ('DIM / array-create' context); the 22 CALL PTRGET_1+1 callers run the same byte as XOR A, zeroing it.
;   Out:       DE -> the variable's value storage (located or newly created). VALTYP ($0B14) = resolved type (2=int/3=str/4=sng/8=dbl). The search key is held in C (name char 0), B (name char 1), VALTYP, and VARNAM ($0871 length + $0872+ ext chars). HL advanced past the name and any type suffix.
;   Clobbers:  AF,BC,DE,HL, VALTYP, PTRGET_CREATE_FLAG, VARNAM, plus the table-walk state in PTRGET_SEARCH which it falls into. Consumes PTRGET_SUBSCRIPT_FLAG.
;   Algorithm: Push the L_5F27 continuation tail (rewind+CHRGET+optional SYNCHR ',') as the return address, then set the create-context flag from the entry point (PTRGET_1). Require the first character to be a letter (else SYNTAX ERROR) and keep it in C. Scan following alphanumerics (plus '.') high-bit-set into the VARNAM extension buffer, capping the name length at $27 ext chars. Apply an explicit type suffix if present -- '%' int, '$' string, '!' single, '#' double -- otherwise look up the default type for the first letter in DEFTYPE_TBL. Store the result in VALTYP, CHRGET past the name, and fall into PTRGET_SEARCH to find/allocate the variable (array path if a '(' or '[' follows and the subscript flag permits). [RE] PTRGET_CREATE_FLAG is NOT a search-key field; it is read only in the array path to raise Duplicate Definition under DIM.
; ----------------------------------------------------------------------
PTRGET:
        ; Push the shared post-PTRGET continuation tail (rewind text ptr, re-CHRGET, optionally accept the trailing ',') as the return address so every exit funnels through it.
        LD BC,L_5F27
        PUSH BC
; ----------------------------------------------------------------------
; PTRGET_1 -- dual-entry create-context selector (opcode-eating flag skip).
;   In:        Reached two ways. (1) Fall-through from the PTRGET head: the OR $AF executes and leaves A nonzero (the DIM dispatch path). (2) CALL PTRGET_1+1 from the 22 reference callers: the $AF byte is then executed as XOR A, zeroing A.
;   Out:       PTRGET_CREATE_FLAG ($0B13) = A (nonzero = DIM/array-create context, zero = plain reference). C = (HL) = the name's first character. Falls into PTRGET_2.
;   Clobbers:  A, C, flags, PTRGET_CREATE_FLAG.
;   Algorithm: Store the entry-selected A into PTRGET_CREATE_FLAG, load the first name char into C, and continue into the name scanner. The $F6 (OR n) opcode at PTRGET_1 swallows the following $AF, so falling in runs 'OR $AF' (A stays nonzero) while entering at +1 runs 'XOR A' (A becomes zero) -- one byte serves as both the flag value and its create-context discriminator. [RE] The flag's only observed effect is the array Duplicate-Definition check in PTRGET_SEARCH; it does not gate scalar creation.
; ----------------------------------------------------------------------
PTRGET_1:
        OR $AF
        LD (PTRGET_CREATE_FLAG),A
        LD C,(HL)
; ----------------------------------------------------------------------
; PTRGET_2 -- name-scan head: validate the first letter and seed the scan state.
;   In:        HL -> first character of the variable name; C = that character.
;   Out:       On a valid letter: VARNAM length byte ($0871) cleared to 0, B=0, HL advanced one char, A = the next (second) character; control branches on that char to classify the rest of the name. A non-letter first char raises SYNTAX ERROR.
;   Clobbers:  A, B, HL, flags, VARNAM[0].
;   Algorithm: Require an alphabetic first character (IS_LETTER -> carry on non-letter -> SYNTAX ERROR). Clear the name-extension length and the extension-byte counter (B), step past the first letter, fetch the second character, and classify it: below '.' ($2E) -> end of name (PTRGET_7, suffix/type); '.' itself or a digit '0'-'9' -> accumulate (PTRGET_4); a gap char ('/' or any char >= ':') falls to PTRGET_3 for an explicit letter re-test (a letter accumulates, anything else ends the name).
; ----------------------------------------------------------------------
PTRGET_2:
        ; A variable name must start with a letter; reject anything else (SYNTAX ERROR).
        CALL IS_LETTER
        JP C,RAISE_SYNTAX_ERROR
        XOR A
        LD B,A
        ; Clear the name-extension length (no extra chars accumulated yet).
        LD (VARNAM_EXTLEN),A
        INC HL
        LD A,(HL)
        CP $2E
        JR C,PTRGET_7
        JR Z,PTRGET_4
        CP $3A
        JR NC,PTRGET_3
        CP $30
        JR NC,PTRGET_4
; ----------------------------------------------------------------------
; PTRGET_3 -- classify a non-digit, non-'.' next character as letter-or-terminator.
;   In:        A = the candidate character (reached when it is not below '.', not '.', and not a digit -- i.e. '/' or any char >= ':').
;   Out:       If A is a letter, fall into PTRGET_4 to accumulate it; otherwise the name has ended -> PTRGET_7 (suffix/type resolution).
;   Clobbers:  A unchanged in value, flags.
;   Algorithm: Re-run the letter test (IS_LETTER_A on the char already in A). Carry set => not a letter => end the name (PTRGET_7). Carry clear => a letter => fall into the accumulation entry PTRGET_4.
; ----------------------------------------------------------------------
PTRGET_3:
        CALL IS_LETTER_A
        JR C,PTRGET_7
; ----------------------------------------------------------------------
; PTRGET_4 -- begin accumulating the name-extension characters (chars 3..N).
;   In:        A = an accepted name character (letter or digit) to be the first stored extension byte; HL -> just past it in the text; C = first name char.
;   Out:       BC pushed (C = first name char, B = second name char just placed by LD B,A); B reset to $FF as the extension counter (pre-incremented to 0 on the first store); DE -> VARNAM extension cell ($0871). Falls into the PTRGET_5 store loop.
;   Clobbers:  B, DE, flags; pushes BC.
;   Algorithm: Record the second name char in B and stash BC (the two packed name chars) on the stack, initialise the extension-length counter B to $FF so the first INC B yields 0, point DE at VARNAM, and drop into the per-char store loop. [RE] Note DE points at the $0871 length cell; the first store overwrites it, then the loop walks into $0872+ -- the final length is rewritten into $0871 by PTRGET_6.
; ----------------------------------------------------------------------
PTRGET_4:
        LD B,A
        PUSH BC
        ; Seed the extension-length counter so the first stored char makes it 0.
        LD B,$FF
        LD DE,VARNAM_EXTLEN
; ----------------------------------------------------------------------
; PTRGET_5 -- name-extension store loop: append one identifier char and fetch the next.
;   In:        A = the character to store; DE -> next VARNAM slot; B = chars stored so far; HL -> current text position.
;   Out:       A stored (high bit set) at (DE); DE and HL advanced; B incremented; A = the next text character, classified to either loop again (digit) or exit to PTRGET_6 (>= ':').
;   Clobbers:  A, B, DE, HL, flags, VARNAM[].
;   Algorithm: Mark the char with bit 7 (the name buffer stores high-bit-set ASCII), write it, bump the count and both pointers, then read the next text char. A digit ('0'..'9') loops immediately; anything >= ':' goes to PTRGET_6 for the letter/'.' re-test.
; ----------------------------------------------------------------------
PTRGET_5:
        ; Store identifier chars with bit 7 set (the name buffer's high-bit convention).
        OR $80
        INC B
        LD (DE),A
        INC DE
        INC HL
        LD A,(HL)
        CP $3A
        JR NC,PTRGET_6
        CP $30
        JR NC,PTRGET_5
; ----------------------------------------------------------------------
; PTRGET_6 -- continuation test + name-length cap, then close the name scan.
;   In:        A = the next text character (>= ':'); B = extension chars stored so far; HL -> that char; the packed name BC is on the stack.
;   Out:       If the char still belongs to the name (a letter, or '.') loop back to PTRGET_5. Otherwise: enforce the $27 ext-char limit (SYNTAX ERROR if >= $27), restore BC, write the final extension length into VARNAM[0], reload the terminating char into A, and fall into PTRGET_7.
;   Clobbers:  A, BC (restored), flags, VARNAM[0].
;   Algorithm: A letter (IS_LETTER_A -> no carry) or a '.' continues the name (back to PTRGET_5). On a true terminator, load B and CP $27 -- JP NC raises SYNTAX ERROR when the extension count reaches/exceeds $27. POP the two packed name chars back into BC, write the accumulated extension length (A=B) into VARNAM[0], reload the terminating char, and proceed to type-suffix resolution.
; ----------------------------------------------------------------------
PTRGET_6:
        CALL IS_LETTER_A
        JR NC,PTRGET_5
        CP $2E
        JR Z,PTRGET_5
        LD A,B
        ; Cap the identifier length at $27 name-extension chars; >= $27 is a SYNTAX ERROR.
        CP $27
        JP NC,RAISE_SYNTAX_ERROR
        POP BC
        ; Record the final name-extension length into VARNAM[0].
        LD (VARNAM_EXTLEN),A
        LD A,(HL)
; ----------------------------------------------------------------------
; PTRGET_7 -- explicit type-suffix resolution (%, $, !, #).
;   In:        A = the character terminating the name; HL -> that char.
;   Out:       If A is a type-suffix char, D = the matching VALTYP (%=2 int, $=3 str, !=4 sng, #=8 dbl) and RET returns to the PTRGET_10 address pushed here, so the suffix decides the type and is consumed by PTRGET_10's CHRGET. If A is not a suffix (or is >= '&'), drop the queued PTRGET_10 return and fall into PTRGET_8 for the per-letter default type.
;   Clobbers:  A unchanged, D, flags; pushes then conditionally pops the PTRGET_10 return address.
;   Algorithm: Chars >= '&' ($26) cannot be a suffix -> PTRGET_8. Otherwise push PTRGET_10 as a return target, LD D,$02, then test A against '%','$','!','#'; the first match leaves D at the corresponding VALTYP (INC D after '%' and after '$'; LD D,$08 before '#') and RETs (landing at PTRGET_10). No match falls through to POP AF (discarding the PTRGET_10 return) and PTRGET_8 for the default-type lookup.
; ----------------------------------------------------------------------
PTRGET_7:
        CP $26
        JR NC,PTRGET_8
        ; Queue PTRGET_10 as the return so a matched suffix lands directly on the VALTYP-store with D=type.
        LD DE,PTRGET_10
        PUSH DE
        ; Start the suffix type at integer (2); INC D below advances it for '$' (3) and '!' (4); '#' is forced to 8 (double).
        LD D,$02
        CP $25
        RET Z
        INC D
        CP $24
        RET Z
        INC D
        CP $21
        RET Z
        LD D,$08
        CP $23
        RET Z
        POP AF
; ----------------------------------------------------------------------
; PTRGET_8 -- per-letter default-type setup (no explicit suffix present).
;   In:        C = the name's first character (plain ASCII from text); HL -> the char following the name (the PTRGET_10 return having been discarded in PTRGET_7).
;   Out:       DE = (first-letter code & $7F) as a 16-bit index; HL pushed (saved across the table lookup). Falls into PTRGET_9.
;   Clobbers:  A, DE, flags; pushes HL.
;   Algorithm: Mask the first letter to 7 bits to get its ASCII code ($41..$5A for A..Z), zero-extend to DE as a table index, save the text pointer, and continue into the DEFTYPE_TBL lookup. [RE] C is loaded raw from text so bit 7 is normally already clear; the AND $7F is defensive.
; ----------------------------------------------------------------------
PTRGET_8:
        LD A,C
        ; Mask to 7 bits to get the plain ASCII code of the name's first letter (the DEFTYPE_TBL index).
        AND $7F
        LD E,A
        LD D,$00
        PUSH HL
        LD HL,DEFTYPE_TBL-$41
; ----------------------------------------------------------------------
; PTRGET_9 -- DEFTYPE_TBL lookup: read the default value-type for the name's first letter.
;   In:        HL = DEFTYPE_TBL-$41 (= $0B36); DE = the first letter's ASCII code ($41..$5A); the text pointer is on the stack.
;   Out:       D = the default VALTYP for that letter (the byte from DEFTYPE_TBL); HL restored to the saved text pointer and decremented by one. Falls into PTRGET_10.
;   Clobbers:  D, HL, flags.
;   Algorithm: ADD HL,DE turns the bias base $0B36 into &DEFTYPE_TBL[letter] (so 'A'($41) lands on $0B77 ... 'Z'($5A) on $0B90), load that default-type byte into D, restore the text pointer (POP HL) and DEC HL so the shared PTRGET_10 join's CHRGET re-reads the terminating char (it was not consumed on this path).
; ----------------------------------------------------------------------
PTRGET_9:
        ; Index the per-letter default-type table: base $0B36 + first-letter ASCII code -> DEFTYPE_TBL[letter] ($0B77 for 'A').
        ADD HL,DE
        LD D,(HL)
        POP HL
        DEC HL
; ----------------------------------------------------------------------
; PTRGET_10 -- commit VALTYP and hand off to the variable table search.
;   In:        D = the resolved value type (explicit suffix via PTRGET_7, or the DEFTYPE_TBL default via PTRGET_9). HL -> one before the terminating char (default path, after PTRGET_9's DEC HL) or at the suffix char (suffix path). PTRGET_SUBSCRIPT_FLAG ($0B52) selects the resolution mode.
;   Out:       VALTYP ($0B14) = D. HL advanced past the name/suffix via CHRGET. Then dispatches on the flag: flag==1 -> PTRGET_SEARCH_22+1 (array-table entry); flag>=2 (sign positive after DEC) -> PTRGET_SEARCH (plain table search); flag==0 -> inspect the current char and divert to PTRGET_SEARCH_14 if it is '(' ($28) or '[' ($5B), else continue scalar.
;   Clobbers:  A, HL, flags, VALTYP.
;   Algorithm: Store D into VALTYP, CHRGET past the name/suffix, then LD A,(PTRGET_SUBSCRIPT_FLAG)/DEC A and branch: Z (flag was 1) takes the dedicated array entry PTRGET_SEARCH_22+1; positive sign (flag was >=2) continues to the plain table search; otherwise (flag was 0, A=$FF) read the current char, SUB $28 ('(' -> 0 -> array) and SUB a further $33 ('[' = $5B -> 0 -> array), diverting matches to PTRGET_SEARCH_14 and otherwise falling into the scalar search.
; ----------------------------------------------------------------------
PTRGET_10:
        LD A,D
        ; Publish the resolved value type for the table search and the eventual fetch/assign.
        LD (VALTYP),A
        CALL CHRGET
        ; Branch on the caller's resolution mode: flag 1 -> array-table entry; flag >=2 -> plain scalar search; flag 0 -> array path only if a '(' / '[' subscript follows.
        LD A,(PTRGET_SUBSCRIPT_FLAG)
        DEC A
        JP Z,PTRGET_SEARCH_22+1
        JP P,PTRGET_SEARCH
        LD A,(HL)
        SUB $28
        JP Z,PTRGET_SEARCH_14
        SUB $33
        JP Z,PTRGET_SEARCH_14
; ----------------------------------------------------------------------
; PTRGET_SEARCH -- find or create a simple variable / array element; return the address of its value (MS BASIC-80 PTRGET).
;   In:        C = packed name char 1 (high bit set); B = packed name char 2; VARNAM_EXTLEN ($0871) = scanned-name extra-length byte, $0872.. = extra name chars; VALTYP ($0B14) = required value type/width (VT_INT/STR/SNG/DBL); HL -> BASIC text just past the name (a '(' or '[' here selects the array path). PTRGET_CREATE_FLAG ($0B13) = create/allocate context (nonzero on the DIM/array-head path, zero for ordinary references). FN_ARG_ACTIVE ($0C64) nonzero => a DEF FN body is currently being evaluated, so its saved formal-argument block is searched first.
;   Out:       On a hit, DE -> the variable's value bytes (SIMPLEVAR value field or the addressed ARRAYVAR element) and HL is restored to the saved text pointer (array path leaves HL = the text pointer just past the close paren, reloaded from FOUT_DP_POSITION). On a not-found reference from a read-only caller (one of four recognised return addresses), DE is left zero and FAC is set to a dummy numeric zero or, if VALTYP is string, the canonical empty-string descriptor. The DIM-only array path returns with carry set and no element address. [RE] The exact create/no-create return convention beyond these cases is not separately audited here.
;   Clobbers:  A, BC, DE, HL, F; mutates VARTAB/ARYTAB/STREND and slides the array+string region when a new entry is allocated; uses scan-state cells $0C61/$0C62/$0C63 and the DEF-FN arg-block pointers $0B93/$0B95; writes FAC/VALTYP on the dummy-value path.
;   Algorithm: Linear-scan the SIMPLE-VARIABLE table VARTAB..ARYTAB (optionally the DEF FN formal-argument block first) for an entry whose stored type and 2-byte packed name match; each entry is variable-length so the walk advances by a computed stride (SV_NAMEXTLEN + SV_VALTYP + 1). On a 2-char header match, confirm any long-name tail with VARNAM_COMPARE. On a hit return the value address. On a miss from a writable context, grow the table: STR_COPY_DOWN slides the array+string region up to open a 3-byte gap, bump ARYTAB, write {valtyp,name0,name1}, copy the name tail with VARNAM_STORE, zero the value, and return it; on a miss from a read-only caller return a shared dummy value instead. A '(' / '[' after the name diverts to the array path: evaluate the comma-separated subscripts onto the stack (counting dimensions in D), scan the ARRAY table ARYTAB..STREND by each descriptor's stored block-length stride for the name, and either index the existing array (row-major offset accumulated by ARRAY_INDEX_MUL16, each dimension range-checked against the stored AV_DIMSIZE, out-of-range -> error 9) or, if absent and PTRGET_CREATE_FLAG is set, allocate a fresh ARRAYVAR (data size = product(dimsizes)*elemwidth + headers), zero it, and store its dim list. DIM of an existing array raises 'Redimensioned array'. OPTION BASE (ARRAY_BASE_BIAS, $0C73, value 0 or 1) governs the lower-bound and default dimension size.
; ----------------------------------------------------------------------
PTRGET_SEARCH:
        XOR A
        LD (PTRGET_SUBSCRIPT_FLAG),A
        PUSH HL
        ; If a DEF FN is being evaluated, search the function's formal-argument variable block before the global table
        LD A,(DEFFN_ACTIVE_FLAG)
        OR A
        LD (FN_ARG_SCAN_PHASE),A
        JR Z,PTRGET_SEARCH_6
        ; Compute the FN-argument block end ($0B95 + its length) as the scan limit, then start the scan at the block base $0B95 so a formal parameter shadows any global of the same name
        LD HL,(DEFFN_FRAME_SIZE)
        LD DE,FN_ARG_BLOCK
        ADD HL,DE
        LD (GC_SCAN_LIMIT),HL
        EX DE,HL
        JR PTRGET_SEARCH_5
; [RE] SIMPLE-VARIABLE table scan (SIMPLEVAR walk). DE walks VARTAB..ARYTAB. Per entry: read SV_VALTYP into L ($5FE4), compare SV_NAME0 to C ($5FE9) and live VALTYP $0B14 to L ($5FEC) and SV_NAME1 to B ($5FF3). On a 2-char hit -> PTRGET_SEARCH_10 (checks SV_NAMEXTLEN/long-name match). On miss, fall through to the computed-stride advance: next = cur + (SV_NAMEXTLEN + SV_VALTYP + 1). Sequential walk -- no base+offset access. See msbasic_var.inc.
PTRGET_SEARCH_1:
        ; Simple-variable scan: read SV_VALTYP, then match SV_NAME0 to C, the live VALTYP, and SV_NAME1 to B
        LD A,(DE)
        LD L,A
        INC DE
        LD A,(DE)
        INC DE
        CP C
        JR NZ,PTRGET_SEARCH_2
        LD A,(VALTYP)
        CP L
        JR NZ,PTRGET_SEARCH_2
        LD A,(DE)
        CP B
        JP Z,PTRGET_SEARCH_10
PTRGET_SEARCH_2:
        INC DE
PTRGET_SEARCH_3:
        LD A,(DE)                        ; SV_NAMEXTLEN: A = extra-name-char count for stride
PTRGET_SEARCH_4:
        LD H,$00
        ADD A,L                          ; + SV_VALTYP (L still holds the type/width read at $5FE5); INC A; ADD HL,DE = next entry
        INC A
        LD L,A
        ADD HL,DE
PTRGET_SEARCH_5:
        EX DE,HL
        ; Reached the table limit? If still scanning the FN-arg block, switch to the main VARTAB pass; otherwise the variable does not exist
        LD A,(GC_SCAN_LIMIT)
        CP E
        JP NZ,PTRGET_SEARCH_1
        LD A,(VARSCAN_LIMIT_HI)
        CP D
        JR NZ,PTRGET_SEARCH_1
        LD A,(FN_ARG_SCAN_PHASE)
        OR A
        JR Z,PTRGET_SEARCH_8
        XOR A
        LD (FN_ARG_SCAN_PHASE),A
PTRGET_SEARCH_6:
        ; Set up the main pass: scan VARTAB up to ARYTAB (the end of the simple-variable table)
        LD HL,(ARYTAB)
        LD (GC_SCAN_LIMIT),HL
        LD HL,(VARTAB)
        JR PTRGET_SEARCH_5
PTRGET_SEARCH_7:
        LD D,A
        LD E,A
        POP BC
        EX (SP),HL
        RET
PTRGET_SEARCH_8:
        POP HL
        EX (SP),HL
        PUSH DE
        ; Variable not found: if the caller is one of the read-only reference contexts (these return addresses), hand back a shared dummy value instead of allocating a new variable
        LD DE,FRMEVL_EVAL_OPERAND_4
        CALL CMP_HL_DE
        JR Z,PTRGET_SEARCH_7
        LD DE,STMT_CHAIN_13
        CALL CMP_HL_DE
        JP Z,PTRGET_SEARCH_7
        LD DE,STMT_CHAIN_14
        CALL CMP_HL_DE
        JR Z,PTRGET_SEARCH_7
        LD DE,FRMEVL_PAREN_4
        CALL CMP_HL_DE
        POP DE
        JR Z,PTRGET_SEARCH_12
        EX (SP),HL
        PUSH HL
        PUSH BC
        LD A,(VALTYP)
        LD B,A
        LD A,(VARNAM_EXTLEN)
        ADD A,B
        INC A
        LD C,A
        PUSH BC
        LD B,$00
        INC BC
        INC BC
        INC BC
        LD HL,(STREND)
        PUSH HL
        ADD HL,BC
        POP BC
        PUSH HL
        ; Allocate a new SIMPLEVAR: slide the array+string region up by 3 bytes to open a gap, then bump ARYTAB
        CALL STR_COPY_DOWN
        POP HL
        LD (STREND),HL
        LD H,B
        LD L,C
        LD (ARYTAB),HL
PTRGET_SEARCH_9:
        DEC HL
        LD (HL),$00
        CALL CMP_HL_DE
        JR NZ,PTRGET_SEARCH_9
        POP DE
        LD (HL),D
        INC HL
        POP DE
        LD (HL),E
        INC HL
        LD (HL),D
        ; Copy the new entry's name tail (the type and 2-char packed name were just written inline above)
        CALL VARNAM_STORE
        EX DE,HL
        INC DE
        POP HL
        RET
; [RE] SIMPLE-VARIABLE long-name confirm: a 2-char header matched; now compare SV_NAMEXTLEN (offset $03, $608D) to the scanned name's extra-length ($0871). If both 0 -> exact short-name hit, return DE -> value ($6095 INC DE). Else VARNAM_COMPARE the namext bytes; on mismatch resume the stride walk (PTRGET_SEARCH_4).
PTRGET_SEARCH_10:
        ; Short-name (<=2 char) hit: SV_NAMEXTLEN is 0, so the value follows immediately -- return its address
        INC DE
        LD A,(VARNAM_EXTLEN)
        LD H,A
        LD A,(DE)
        CP H
        JP NZ,PTRGET_SEARCH_3
        OR A
        JR NZ,PTRGET_SEARCH_11
        INC DE
        POP HL
        RET
PTRGET_SEARCH_11:
        EX DE,HL
        ; Long-name confirm: compare the name-extension tail; on mismatch resume the stride walk
        CALL VARNAM_COMPARE
        EX DE,HL
        JP NZ,PTRGET_SEARCH_4
        POP HL
        RET
PTRGET_SEARCH_12:
        ; Read-only reference not found: build a dummy result -- clear FAC to numeric zero, or set FAC to the empty-string descriptor if the required type is string
        LD (FAC_EXP),A
        LD H,A
        LD L,A
        LD (FAC),HL
        CALL FRMEVL_TEST_TYPE
        JR NZ,PTRGET_SEARCH_13
        LD HL,EMPTY_STRING_DESC
        LD (FAC),HL
PTRGET_SEARCH_13:
        POP HL
        RET
PTRGET_SEARCH_14:
        PUSH HL
        ; Array path: stash the create/allocate flag (with VALTYP) and begin evaluating the comma-separated subscript list
        LD HL,(PTRGET_CREATE_FLAG)
        EX (SP),HL
        LD D,A
PTRGET_SEARCH_15:
        PUSH DE
        PUSH BC
        LD DE,VARNAM_EXTLEN
        LD A,(DE)
        OR A
        JR Z,PTRGET_SEARCH_18
        EX DE,HL
        ADD A,$02
        RRA
        LD C,A
        ; Ensure stack room, then re-push the already-evaluated subscripts so this dimension's index can be evaluated on top
        CALL CHECK_STACK_ROOM
        LD A,C
PTRGET_SEARCH_16:
        LD C,(HL)
        INC HL
        LD B,(HL)
        INC HL
        PUSH BC
        DEC A
        JR NZ,PTRGET_SEARCH_16
        PUSH HL
        LD A,(VARNAM_EXTLEN)
        PUSH AF
        EX DE,HL
        ; Evaluate one subscript expression to a non-negative 16-bit integer (0..32767)
        CALL GETINT_CHRGET_POS
        POP AF
        LD (ARRAY_SUBSCRIPT_SAVE),HL
        POP HL
        ADD A,$02
        RRA
PTRGET_SEARCH_17:
        POP BC
        DEC HL
        LD (HL),B
        DEC HL
        LD (HL),C
        DEC A
        JR NZ,PTRGET_SEARCH_17
        LD HL,(ARRAY_SUBSCRIPT_SAVE)
        JR PTRGET_SEARCH_19
PTRGET_SEARCH_18:
        CALL GETINT_CHRGET_POS
        XOR A
        LD (VARNAM_EXTLEN),A
PTRGET_SEARCH_19:
        LD A,(OPTION_BASE_VALUE)
        OR A
        JR Z,PTRGET_SEARCH_20
        LD A,D
        OR E
        DEC DE
        JP Z,PTRGET_SEARCH_27
PTRGET_SEARCH_20:
        POP BC
        POP AF
        EX DE,HL
        EX (SP),HL
        PUSH HL
        EX DE,HL
        INC A
        LD D,A
        LD A,(HL)
        ; ',' means another dimension follows; ')' or ']' closes the subscript list
        CP $2C
        JP Z,PTRGET_SEARCH_15
        CP $29
        JR Z,PTRGET_SEARCH_21
        CP $5D
        JP NZ,RAISE_SYNTAX_ERROR
PTRGET_SEARCH_21:
        CALL CHRGET
        LD (FOUT_DP_POSITION),HL
        POP HL
        LD (PTRGET_CREATE_FLAG),HL
        LD E,$00
        PUSH DE
; [RE] VERIFIED flag-skip. PTRGET_SEARCH_23 ($612C) opcode-eating entry. Fall-through (from PTRGET_SEARCH_22 PUSH DE at $612B) executes LD DE,$F5E5; the $11 opcode swallows E5 F5 so the first pass skips PUSH HL/PUSH AF and loads a dead DE. The two +1 entrants ($612D, JP Z at $5FB8 / CALL at $7389) run E5 F5 as PUSH HL / PUSH AF to save caller state. Both reach LD HL,($0B71) at $612F. Cover genuinely executed; MBASIC twin (SUB_3D4E_6, still machine-labeled) byte-identical.
PTRGET_SEARCH_22:
        ; Scan the ARRAY table (ARYTAB..STREND) for a matching name, stepping by each descriptor's stored block length
        LD DE,$F5E5
        LD HL,(ARYTAB)
; [RE] VERIFIED flag-skip. PTRGET_SEARCH_24 ($6132) opcode-eating loop advance. Fall-through (from $612F) runs LD A,$19 (3E swallows 19); the first array-table pass skips ADD HL,DE because HL is already at the table head. The loop re-enters via JR NZ,PTRGET_SEARCH_24+1 ($6133) at $6159, running 19 as ADD HL,DE to step to the next ARRAYVAR by the stored AV_BLKLEN stride (DE loaded at $6155-$6158). A=$19 is dead (clobbered at $6140). Both reach EX DE,HL / CMP_HL_DE at $6134. Cover genuinely executed; MBASIC twin (SUB_3D4E_7) byte-identical (20 D8). ARRAY-TABLE scan: compares AV_NAME0/$0B14/AV_NAME1 to C/$0B14/B ($6142/$6148/$614C); see msbasic_var.inc.
PTRGET_SEARCH_23:
        LD A,$19
        EX DE,HL
        LD HL,(STREND)
        EX DE,HL
        CALL CMP_HL_DE
        JR Z,PTRGET_SEARCH_29
        LD E,(HL)
        INC HL
        LD A,(HL)
        INC HL
        CP C
        JR NZ,PTRGET_SEARCH_24
        LD A,(VALTYP)
        CP E
        JR NZ,PTRGET_SEARCH_24
        LD A,(HL)
        CP B
        JR Z,PTRGET_SEARCH_28
PTRGET_SEARCH_24:
        INC HL
; [RE] ARRAYVAR advance to next descriptor: at the AV_NAMEXTLEN byte ($6150 LD E,(HL); INC E) skip the variable name extension, then PTRGET_SEARCH_26 ($6155) loads AV_BLKLEN (the stored inter-entry stride word) into DE; the loop top adds it (flag-skip ADD HL,DE at $6132/$6159) to reach the next ARRAYVAR. Stored-stride sequential walk -- no base+offset.
PTRGET_SEARCH_25:
        LD E,(HL)
        INC E
        LD D,$00
        ADD HL,DE
PTRGET_SEARCH_26:
        LD E,(HL)                        ; AV_BLKLEN word -> DE = stride to next array descriptor
        INC HL
        LD D,(HL)
        INC HL
        JR NZ,PTRGET_SEARCH_23+1
        LD A,(PTRGET_CREATE_FLAG)
        OR A
        ; Name absent: if this is a DIM (create flag set) fall through to allocate; an explicit DIM of an existing array is a Redimensioned-array error
        JP NZ,RAISE_DUPLICATE_DEFINITION
        POP AF
        LD B,H
        LD C,L
        JP Z,FMUL_7
        SUB (HL)
        JP Z,PTRGET_SEARCH_34
PTRGET_SEARCH_27:
        LD DE,ERR_SUBSCRIPT_OUT_OF_RANGE
        JP RAISE_ERROR
PTRGET_SEARCH_28:
        INC HL
        LD A,(VARNAM_EXTLEN)
        CP (HL)
        JR NZ,PTRGET_SEARCH_25
        INC HL
        OR A
        JR Z,PTRGET_SEARCH_26
        DEC HL
        CALL VARNAM_COMPARE
        JR PTRGET_SEARCH_26
PTRGET_SEARCH_29:
        ; Allocate a new ARRAYVAR: store element type and name, reserve blklen/ndims, then size the data area from the subscripts
        LD A,(VALTYP)
        LD (HL),A
        INC HL
        LD E,A
        LD D,$00
        POP AF
        JP Z,PTRGET_SEARCH_39
        LD (HL),C
        INC HL
        LD (HL),B
        CALL VARNAM_STORE
        INC HL
        LD C,A
        CALL CHECK_STACK_ROOM
        INC HL
        INC HL
        LD (PRUSING_FORMAT_FLAGS),HL
        LD (HL),C
        INC HL
        LD A,(PTRGET_CREATE_FLAG)
        RLA
        LD A,C
PTRGET_SEARCH_30:
        JR C,PTRGET_SEARCH_31
        PUSH AF
        LD A,(OPTION_BASE_VALUE)
        XOR $0B
        LD C,A
        LD B,$00
        POP AF
        JR NC,PTRGET_SEARCH_32
PTRGET_SEARCH_31:
        POP BC
        INC BC
PTRGET_SEARCH_32:
        LD (HL),C
        PUSH AF
        INC HL
        LD (HL),B
        INC HL
        CALL ARRAY_INDEX_MUL16
        POP AF
        DEC A
        JR NZ,PTRGET_SEARCH_30
        PUSH AF
        LD B,D
        LD C,E
        EX DE,HL
        ADD HL,DE
        JP C,STACK_OVERFLOW_RAISE
        ; Reserve product(dims)*elemsize bytes above the array (collecting garbage / trapping overflow), then zero-fill the new array
        CALL GC_CHECK_AND_COLLECT
        LD (STREND),HL
PTRGET_SEARCH_33:
        DEC HL
        LD (HL),$00
        CALL CMP_HL_DE
        JR NZ,PTRGET_SEARCH_33
        INC BC
        LD D,A
        LD HL,(PRUSING_FORMAT_FLAGS)
        LD E,(HL)
        EX DE,HL
        ADD HL,HL
        ADD HL,BC
        EX DE,HL
        DEC HL
        DEC HL
        LD (HL),E
        INC HL
        LD (HL),D
        INC HL
        POP AF
        JR C,PTRGET_SEARCH_38
PTRGET_SEARCH_34:
        ; Index an existing array: walk the stored DIMSIZE list high-dim-first, accumulating offset = offset*dimsize + index, range-checked per dimension
        LD B,A
        LD C,A
        LD A,(HL)
        INC HL
; [RE] VERIFIED flag-skip. PTRGET_SEARCH_36 ($61EF) opcode-eating dimension loop. Fall-through (from PTRGET_SEARCH_35) runs LD D,$E1 (16 swallows E1); the first array dimension skips POP HL because HL is already valid. The loop re-enters via JR NZ,PTRGET_SEARCH_36+1 ($61F0) at $6205, running E1 as POP HL to restore the per-dimension HL save (EX (SP),HL/PUSH AF at $61F5/$61F6). D=$E1 is dead (clobbered at $61F3). Both reach LD E,(HL) at $61F1. Cover genuinely executed; MBASIC twin (SUB_3D4E_21) byte-identical (20 E9).
PTRGET_SEARCH_35:
        LD D,$E1
        LD E,(HL)                        ; AV_DIMSIZE[i] word (high dim first) -> DE for the index/offset accumulate
        INC HL
        LD D,(HL)
        INC HL
        EX (SP),HL
        PUSH AF
        CALL CMP_HL_DE
        JP NC,PTRGET_SEARCH_27
        CALL ARRAY_INDEX_MUL16
        ADD HL,DE
        POP AF
        DEC A
        LD B,H
        LD C,L
        JR NZ,PTRGET_SEARCH_35+1
        LD A,(VALTYP)
        LD B,H
        LD C,L
        ADD HL,HL
        SUB $04
        JR C,PTRGET_SEARCH_36
        ADD HL,HL
        JR Z,PTRGET_SEARCH_37
        ADD HL,HL
PTRGET_SEARCH_36:
        OR A
        JP PO,PTRGET_SEARCH_37
        ADD HL,BC
PTRGET_SEARCH_37:
        ; Scale the final flat index by the element width and add the array's data base to form the element address
        POP BC
        ADD HL,BC
        EX DE,HL
PTRGET_SEARCH_38:
        ; Restore the text pointer to just past the closing paren and return the element address in DE
        LD HL,(FOUT_DP_POSITION)
        RET
PTRGET_SEARCH_39:
        ; DIM-only path: array just created, no element to return -- signal 'no value' (carry set) and restore the text pointer
        SCF
        SBC A,A
        POP HL
        RET
; ----------------------------------------------------------------------
; VARTAB_SKIP_ENTRY -- advance HL past one length-prefixed name run in a table entry.
;   In:        HL -> a length byte that prefixes a run of bytes (a variable-name tail in a SIMPLEVAR/ARRAYVAR entry).
;   Out:       HL -> the first byte after that run (length byte + that many bytes consumed).
;   Clobbers:  A, F (BC preserved by the VARTAB_ADD_LEN tail).
;   Algorithm: Read the length byte at (HL), step HL past it, then fall into VARTAB_ADD_LEN to add the length to HL. Used while linearly scanning the variable/array tables (PTRGET, GARBAG, ERASE, CHAIN) to jump over an entry's name extension.
; ----------------------------------------------------------------------
VARTAB_SKIP_ENTRY:
        ; Take the entry's name-tail length byte and skip past it, then add that many bytes to HL
        LD A,(HL)
        INC HL
; ----------------------------------------------------------------------
; VARTAB_ADD_LEN -- HL += A (zero-extended), preserving BC.
;   In:        A = byte count to add; HL = pointer.
;   Out:       HL = HL + A.
;   Clobbers:  F only (BC saved/restored).
;   Algorithm: Push BC, load BC = 0:A, ADD HL,BC, pop BC. Separate entry point used when the skip length is already in A (avoids re-reading it). Used to step over name tails during the variable/array table scans.
; ----------------------------------------------------------------------
VARTAB_ADD_LEN:
        PUSH BC
        LD B,$00
        LD C,A
        ADD HL,BC
        POP BC
        RET
; ----------------------------------------------------------------------
; VARNAM_STORE -- copy the scanned name's extra characters into a freshly created table entry.
;   In:        HL -> the byte just before where the name tail should be written (the loop pre-increments HL); VARNAM_EXTLEN ($0871) holds the extra-char count, with the count byte at $0871 followed by the chars at $0872.. .
;   Out:       HL advanced past the stored name tail; the entry's NAMEXTLEN byte and the extra chars are written from the $0871 buffer.
;   Clobbers:  none visible to the caller (A, BC, DE saved/restored); memory at (HL).. written.
;   Algorithm: Copy NAMEXTLEN+1 bytes (the count byte plus that many name chars) from the $0871 buffer to (HL), pre-incrementing HL before each store. AF/BC/DE are preserved so the caller's allocation state survives. Called by PTRGET_SEARCH right after the type and 2-char name have been written inline, to lay down the name extension of a new SIMPLEVAR or ARRAYVAR.
; ----------------------------------------------------------------------
VARNAM_STORE:
        PUSH BC
        PUSH DE
        PUSH AF
        ; Copy the scanned name extension (count byte + extra chars) into the new entry, advancing HL
        LD DE,VARNAM_EXTLEN
        LD A,(DE)
        LD B,A
        INC B
VARNAM_STORE_1:
        LD A,(DE)
        INC DE
        INC HL
        LD (HL),A
        DEC B
        JR NZ,VARNAM_STORE_1
        POP AF
        POP DE
        POP BC
        RET
; ----------------------------------------------------------------------
; VARNAM_COMPARE -- compare a table entry's long-name tail against the scanned name.
;   In:        HL -> the byte before the entry's name-tail bytes (the loop pre-increments HL); A = number of name chars to compare; the scanned chars live at $0872.. .
;   Out:       Z set and HL just past the matched tail on a full match; NZ on mismatch, with HL advanced past the rest of the entry's tail (so the caller can continue the stride walk).
;   Clobbers:  A, F (BC, DE saved/restored).
;   Algorithm: Compare up to A bytes of (HL) against the scanned buffer at $0872. On the first difference, skip the remaining unmatched bytes of the entry (VARTAB_ADD_LEN with the leftover count) and return NZ; if all A bytes match, return Z. Drives the long-name confirmation step of the linear table scan in PTRGET_SEARCH.
; ----------------------------------------------------------------------
VARNAM_COMPARE:
        PUSH DE
        PUSH BC
        ; Compare the entry's name chars against the scanned name; on the first mismatch skip the rest of the entry's name and return NZ
        LD DE,VARNAM_EXTCHARS
        LD B,A
        INC HL
        INC B
VARNAM_COMPARE_1:
        DEC B
        JR Z,VARNAM_COMPARE_2
        LD A,(DE)
        CP (HL)
        INC HL
        INC DE
        JR Z,VARNAM_COMPARE_1
        ; Mismatch: advance HL over the unmatched remainder so the caller's stride walk stays aligned, then return not-equal
        LD A,B
        DEC A
        CALL NZ,VARTAB_ADD_LEN
        XOR A
        DEC A
VARNAM_COMPARE_2:
        POP BC
        POP DE
        RET
; ----------------------------------------------------------------------
; STMT_EDIT_LINENUM -- entry reached from the READY loop when ERRFLG==2: commit the flag, fetch ERR_SAVTXT, and fall into the EDIT path.
;   In:        A = the value to commit to ERRFLG (the READY loop reaches this via 'LD A,(ERRFLG) / SUB $02 / CALL Z,STMT_EDIT_LINENUM', so A = ERRFLG-2 = 0 here). ERR_SAVTXT ($0B60) = the saved error text pointer.
;   Out:       Stores A into ERRFLG. If ERR_SAVTXT = $FFFF (no saved position) returns immediately (Z). Otherwise EX DE,HL leaves DE = ERR_SAVTXT and falls through (JR) to STMT_EDIT_1.
;   Clobbers:  AF,DE,HL.
;   Algorithm: Commit the flag to ERRFLG, load ERR_SAVTXT, and test it for the $FFFF sentinel (OR H / AND L / INC A -> A=0,Z iff $FFFF). EX DE,HL stages ERR_SAVTXT in DE; RET Z when it is $FFFF, else JR into STMT_EDIT_1. [RE]/UNKNOWN: this is plausibly the auto-edit-after-error feature, but STMT_EDIT_1/_2 stores DE into ERRLIN and passes it to FNDLIN as a LINE NUMBER, whereas ERR_SAVTXT is documented elsewhere as a TEXT pointer (see the [FIX/UNKNOWN] note at the ERR/ERL reader). The exact line-identity semantics on this path are not confirmed from the bytes.
; ----------------------------------------------------------------------
STMT_EDIT_LINENUM:
        ; commit the flag byte (this READY-loop path passes 0)
        LD (ERRFLG),A
        LD HL,(ERR_SAVTXT)
        ; test ERR_SAVTXT for the $FFFF 'no saved error position' sentinel (OR H/AND L/INC A -> Z iff $FFFF)
        OR H
        AND L
        INC A
        EX DE,HL
        ; no saved position captured: nothing to do, return to the READY loop
        RET Z
        ; [RE] fall into the EDIT setup with DE = ERR_SAVTXT (treated by STMT_EDIT_2 as a line number for FNDLIN; see header UNKNOWN)
        JR STMT_EDIT_1
; ----------------------------------------------------------------------
; STMT_EDIT -- EDIT statement handler (token $A3): enter the interactive line editor for a program line.
;   In:        HL -> BASIC text after EDIT: a line number, or '.' for the last-referenced line (ERRLIN).
;   Out:       On a valid line number, opens that line in the line editor (via STMT_EDIT_1): detokenizes it into BUF and runs the keystroke-driven edit loop. If the text after the line number is not end-of-statement, RETs without editing (NZ). Undefined line -> ERROR_UL (Undefined line).
;   Clobbers:  AF,BC,DE,HL (and the editor's working set).
;   Algorithm: LINGET_DOT parses the line number into DE (substituting ERRLIN for '.'); a trailing non-end-of-statement token (NZ) RETs. Otherwise fall into STMT_EDIT_1, which discards the dispatcher's return address (the editor owns the stack), records the line in ERRLIN, locates it with FNDLIN (ERROR_UL if missing), detokenizes its crunched text into BUF, prints the line number, and enters the EDIT subcommand loop.
; ----------------------------------------------------------------------
STMT_EDIT:
        ; parse the target line number (or '.' = last-referenced line, ERRLIN) into DE
        CALL LINGET_DOT
        ; anything other than a clean line number ends the statement (no edit)
        RET NZ
; ----------------------------------------------------------------------
; STMT_EDIT_1 -- EDIT setup: seize the stack, locate the line, detokenize it into BUF, and start the edit loop.
;   In:        DE = the line number to edit (from STMT_EDIT via LINGET_DOT; or ERR_SAVTXT via STMT_EDIT_LINENUM -- see that routine's UNKNOWN). One dispatcher return address is on the stack (popped here).
;   Out:       ERRLIN = the line being edited; BUF holds the detokenized source text of the line; the line number has been printed; control enters the editor's per-keystroke loop. On a missing line, jumps to ERROR_UL.
;   Clobbers:  AF,BC,DE,HL,SP.
;   Algorithm: POP the dispatcher return so the editor controls its own return path, then (STMT_EDIT_2) record DE in ERRLIN and FNDLIN to find the line; ERROR_UL if not found. Skip past the line's link + line-number words to its crunched tokens, push that text pointer, and DETOKENIZE_LINE it back into editable ASCII in BUF. Print the line number (FOUT) and fall into the editor's keystroke dispatch.
; ----------------------------------------------------------------------
STMT_EDIT_1:
        ; discard the statement-dispatcher return: the interactive editor manages its own stack/return
        POP HL
STMT_EDIT_2:
        EX DE,HL
        LD (ERRLIN),HL
        EX DE,HL
        ; locate the program line by number; not found -> Undefined line error
        CALL FNDLIN
        JP NC,ERROR_UL
        LD H,B
        LD L,C
        INC HL
        INC HL
        LD C,(HL)
        INC HL
        LD B,(HL)
        INC HL
        PUSH BC
        ; expand the line's crunched tokens back into editable ASCII in BUF
        CALL DETOKENIZE_LINE
STMT_EDIT_3:
        POP HL
STMT_EDIT_4:
        PUSH HL
        LD A,H
        AND L
        INC A
        LD A,$21
        CALL Z,OUTCHR
        CALL NZ,FOUT
        LD A,$20
        CALL OUTCHR
        LD HL,BUF
        PUSH HL
        LD C,$FF
; ----------------------------------------------------------------------
; STMT_EDIT_5 -- measure the editable line: count the characters now sitting in BUF.
;   In:        HL -> start of BUF (the detokenized line, NUL-terminated). C preset to $FF by the caller (STMT_EDIT_4).
;   Out:       C = length of the line in BUF (number of bytes before the NUL); HL restored to BUF start; B := A (= 0 from the terminator), seeding the editor's column/cursor state.
;   Clobbers:  A,C,HL,F.
;   Algorithm: Walk BUF incrementing C until the terminating $00 (INC C precedes each LD A,(HL), so C ends as the count of non-NUL bytes). POP HL back to BUF and set B = A (= 0) for the keystroke loop that follows.
; ----------------------------------------------------------------------
STMT_EDIT_5:
        ; count one more character of the line buffer (C started at $FF so it ends = length)
        INC C
        LD A,(HL)
        INC HL
        ; stop at the NUL terminator that ends the detokenized line
        OR A
        JR NZ,STMT_EDIT_5
        POP HL
        LD B,A
STMT_EDIT_6:
        LD D,$00
STMT_EDIT_7:
        CALL CONIN
        OR A
        JR Z,STMT_EDIT_7
        CALL TOUPPER_A
        SUB $30
        JR C,STMT_EDIT_8
        CP $0A
        JR NC,STMT_EDIT_8
        LD E,A
        LD A,D
        RLCA
        RLCA
        ADD A,D
        RLCA
        ADD A,E
        LD D,A
        JR STMT_EDIT_7
; ----------------------------------------------------------------------
; STMT_EDIT_8 -- EDIT keystroke dispatcher: decode one edit subcommand and branch to its handler.
;   In:        A = the just-read keystroke uppercased and reduced by $30 (digits were already accumulated into D as a repeat count by STMT_EDIT_7); HL/BC/D = the editor's buffer pointer, column, and repeat-count state.
;   Out:       Pushes STMT_EDIT_6 as the return so each subcommand resumes the read-next-key loop, normalizes the repeat count to a default of 1, then JP/JRs to the matching subcommand handler. An unrecognized key falls through to ring the bell (LD A,$07 / OUTCHR).
;   Clobbers:  AF,D,HL,SP (per the dispatched handler).
;   Algorithm: Push STMT_EDIT_6 (the 'await next keystroke' re-entry) as the common return via PUSH HL / LD HL,STMT_EDIT_6 / EX (SP),HL. Normalize the repeat count (DEC D/INC D forces a default of 1 when none was typed). Compare A against the normalized EDIT command codes ($D8/$4F/$DD/$F0 at STMT_EDIT_9; STMT_EDIT_9 then does the >=$31 SUB $20 fold and continues at STMT_EDIT_10) and JP/JR to each handler. [RE] the precise user-facing key letters behind several normalized codes are not pinned from the bytes; named code mappings are deferred to the handlers.
; ----------------------------------------------------------------------
STMT_EDIT_8:
        PUSH HL
        ; make every subcommand return to the 'read next keystroke' loop
        LD HL,STMT_EDIT_6
        EX (SP),HL
        ; normalize the typed repeat count to a default of 1 when no digits preceded the command
        DEC D
        INC D
        JP NZ,STMT_EDIT_9
        INC D
STMT_EDIT_9:
        CP $D8
        JP Z,EDIT_BUF_SHIFT_7
        CP $4F
        JP Z,EDIT_BUF_SHIFT_8
        CP $DD
        JP Z,EDIT_BUF_SHIFT_9
        CP $F0
        JR Z,EDIT_ECHO_SPAN
        CP $31
        JR C,STMT_EDIT_10
        SUB $20
; ----------------------------------------------------------------------
; STMT_EDIT_10 -- EDIT dispatcher tail: the remaining subcommand comparisons after the STMT_EDIT_9 lowercase fold.
;   In:        A = normalized command code (codes below $31 reach here without the $20 fold STMT_EDIT_9 applies to the rest).
;   Out:       Branches to the matching echo-span / buffer-shift edit handler, to PRINT_LIST_ENTRY_1 (the edit-finish path that returns to the READY loop), or falls through to ring the bell (LD A,$07 / JP OUTCHR) on an unrecognized key. Each editing handler returns via the STMT_EDIT_6 address pushed by STMT_EDIT_8.
;   Clobbers:  AF,HL (per the dispatched handler).
;   Algorithm: Continuation of the STMT_EDIT_8/_9 compare chain: CP $21 / $1C / $23 / $19 / $14 / $13 / $15 / $28 / $1B / $18 / $11 each route to the corresponding edit handler. UNKNOWN: the user-facing key letters behind these normalized codes are not confirmed from the bytes; e.g. $1C -> EDIT_ECHO_SPAN_6 (line-list redisplay) and $21 -> PRINT_LIST_ENTRY_1 (discard editor state and return to the READY loop).
; ----------------------------------------------------------------------
STMT_EDIT_10:
        ; [RE] this code -> PRINT_LIST_ENTRY_1, the edit-finish path (pops the editor state and returns to the READY loop); the exact key letter is UNKNOWN (the value is a normalized code, not ASCII '!')
        CP $21
        JP Z,PRINT_LIST_ENTRY_1
        CP $1C
        JP Z,EDIT_ECHO_SPAN_6
        CP $23
        JR Z,EDIT_ECHO_SPAN_2
        CP $19
        JP Z,EDIT_EMIT_BACKSLASH_6
        CP $14
        JP Z,EDIT_ECHO_SPAN_7
        CP $13
        JP Z,EDIT_EMIT_BACKSLASH_1
        CP $15
        JP Z,EDIT_BUF_SHIFT_10
        CP $28
        JP Z,EDIT_EMIT_BACKSLASH_5
        CP $1B
        JR Z,EDIT_ECHO_SPAN_1
        CP $18
        JP Z,EDIT_EMIT_BACKSLASH_4
        CP $11
        LD A,$07
        JP NZ,OUTCHR
        POP BC
        POP DE
        CALL CRLF
        JP STMT_EDIT_2
; [RE] Line-editor helper: echo D characters of the line buffer at (HL) to the console (OUTCHR via OUTCHR_LF_EXPAND), advancing HL and the column count B; ESC ($1B) enters the copy/scan sub-mode (EDIT_COPY_MODE). Part of the EDIT/line-input screen editor.
EDIT_ECHO_SPAN:
        LD A,(HL)
        OR A
        RET Z
        INC B
        CALL OUTCHR_LF_EXPAND
        INC HL
        DEC D
        JR NZ,EDIT_ECHO_SPAN
        RET
EDIT_ECHO_SPAN_1:
        PUSH HL
        LD HL,EDIT_EMIT_BACKSLASH
        EX (SP),HL
        SCF
EDIT_ECHO_SPAN_2:
        PUSH AF
        CALL CONIN
        LD E,A
        POP AF
        PUSH AF
        CALL C,EDIT_EMIT_BACKSLASH
EDIT_ECHO_SPAN_3:
        LD A,(HL)
