        CP $1B
        RET Z
        CP $08
        JR Z,EDIT_EMIT_BACKSLASH_8
        CP $0A
        JR Z,EDIT_BUF_SHIFT_2
        CP $07
        JR Z,EDIT_BUF_SHIFT_2
        CP $09
        JR Z,EDIT_BUF_SHIFT_2
        CP $20
        JR C,EDIT_EMIT_BACKSLASH_6
        CP $5F
        JR NZ,EDIT_BUF_SHIFT_2
EDIT_EMIT_BACKSLASH_7:
        LD A,$5F
EDIT_EMIT_BACKSLASH_8:
