PRINT_LIST_ENTRY_17:
        INC C
        DEC B
        JR Z,PRINT_LIST_ENTRY_20
        LD A,(HL)
        INC HL
        CP $23
        JR Z,PRINT_LIST_ENTRY_17
PRINT_LIST_ENTRY_18:
        PUSH DE
        LD DE,PRINT_LIST_ENTRY_19+1
        PUSH DE
        LD D,H
        LD E,L
        CP $5E
        RET NZ
        CP (HL)
        RET NZ
        INC HL
        CP (HL)
        RET NZ
        INC HL
        CP (HL)
        RET NZ
        INC HL
        LD A,B
        SUB $04
        RET C
        POP DE
        POP DE
        LD B,A
        INC D
        INC HL
; [RE] VERIFIED flag-skip (with nuance). PRINT_LIST_ENTRY_19+1 ($653F) is a RET landing pad, not a JP target. The '^^^^' field parser pushes $653F ($6523/$6526) and saves HL into DE ($6527); the RET NZ/RET C chain returns to $653F to run EX DE,HL / POP DE and unwind. The cover at $653E (CA EB D1) is a genuine, executed JP Z,$D1EB whose Z comes from INC D ($653C) and whose $D1EB target is unreachable BIOS-region junk, so it is effectively never taken -- the CA opcode hides the EB D1 (EX DE,HL/POP DE) on the fall-through. Both reach PRINT_LIST_ENTRY_20 ($6541). MBASIC twin (PRINT_USING_17) byte-identical.
PRINT_LIST_ENTRY_19:
        JP Z,$D1EB
PRINT_LIST_ENTRY_20:
        LD A,D
        DEC HL
        INC E
        AND $08
        JR NZ,PRINT_LIST_ENTRY_22
        DEC E
        LD A,B
        OR A
        JR Z,PRINT_LIST_ENTRY_22
        LD A,(HL)
        SUB $2D
        JR Z,PRINT_LIST_ENTRY_21
        CP $FE
        JR NZ,PRINT_LIST_ENTRY_22
        LD A,$08
PRINT_LIST_ENTRY_21:
        ADD A,$04
        ADD A,D
        LD D,A
        DEC B
PRINT_LIST_ENTRY_22:
        POP HL
        POP AF
        JR Z,PRINT_LIST_ENTRY_29
        PUSH BC
        PUSH DE
        CALL FRMEVL_NOPAREN
        POP DE
        POP BC
        PUSH BC
        PUSH HL
        LD B,E
        LD A,B
        ADD A,C
        CP $19
        JP NC,ERROR_FC
        LD A,D
        OR $80
        CALL FOUT_BODY
        CALL STROUT
PRINT_LIST_ENTRY_23:
        POP HL
        DEC HL
        CALL CHRGET
        SCF
        JR Z,PRINT_LIST_ENTRY_25
        LD (L_0B53),A
        CP $3B
        JR Z,PRINT_LIST_ENTRY_24
        CP $2C
        JP NZ,RAISE_SYNTAX_ERROR
PRINT_LIST_ENTRY_24:
        CALL CHRGET
PRINT_LIST_ENTRY_25:
        POP BC
        EX DE,HL
        POP HL
        PUSH HL
        PUSH AF
        PUSH DE
        LD A,(HL)
        SUB B
        INC HL
        LD C,(HL)
        INC HL
        LD H,(HL)
        LD L,C
        LD D,$00
        LD E,A
        ADD HL,DE
PRINT_LIST_ENTRY_26:
        LD A,B
        OR A
        JP NZ,PRINT_LIST_ENTRY_10
        JR PRINT_LIST_ENTRY_28
PRINT_LIST_ENTRY_27:
        CALL PRINT_USING_PUT_SIGN
        CALL OUTCHR
PRINT_LIST_ENTRY_28:
        POP HL
        POP AF
        JP NZ,PRINT_LIST_ENTRY_3
PRINT_LIST_ENTRY_29:
        CALL C,CRLF
        EX (SP),HL
        CALL FRESTR_DE
        POP HL
        JP PRINT_RESET_STATE
PRINT_LIST_ENTRY_30:
        CALL PRINT_USING_PUT_SIGN
        DEC B
        LD A,(HL)
        INC HL
        CALL OUTCHR
        JR PRINT_LIST_ENTRY_26
PRINT_LIST_ENTRY_31:
        LD C,$FF
        JR PRINT_LIST_ENTRY_34
PRINT_LIST_ENTRY_32:
        LD C,$01
; [RE] VERIFIED flag-skip. PRINT_LIST_ENTRY_34 ($65D1) opcode-eating stack rebalance. Fall-through (numeric/sign field, from PRINT_LIST_ENTRY_33 $65CF) runs LD A,$F1 (3E swallows F1) so no POP; A=$F1 is dead. The '\' string-field entry JP Z,PRINT_LIST_ENTRY_34+1 ($65D2) at $648C runs F1 as POP AF to drop the PUSH the scanner left. (PRINT_LIST_ENTRY_32 at $65CB JRs straight to _35 at $65D3, bypassing the cover.) Both reach DEC B / CALL PRINT_USING_PUT_SIGN at $65D3. Cover genuinely executed on fall-through; MBASIC twin (PRINT_USING_31) byte-identical.
PRINT_LIST_ENTRY_33:
        LD A,$F1
PRINT_LIST_ENTRY_34:
        DEC B
        CALL PRINT_USING_PUT_SIGN
        POP HL
        POP AF
        JR Z,PRINT_LIST_ENTRY_29
        PUSH BC
        CALL FRMEVL_NOPAREN
        CALL REQUIRE_STRING
        POP BC
        PUSH BC
        PUSH HL
        LD HL,(FAC)
        LD B,C
        LD C,$00
        PUSH BC
        CALL LEFT_STR_AND_SUBSTR_TAIL_2+1
        CALL STRPRT
        LD HL,(FAC)
        POP AF
        INC A
        JP Z,PRINT_LIST_ENTRY_23
        DEC A
        SUB (HL)
        LD B,A
        LD A,$20
        INC B
PRINT_LIST_ENTRY_35:
        DEC B
        JP Z,PRINT_LIST_ENTRY_23
        CALL OUTCHR
        JR PRINT_LIST_ENTRY_35
; [RE] PRINT USING helper: if the pending-sign flag in D is set, emit a leading '+' ($2B) via OUTCHR before the formatted field; preserves AF.
PRINT_USING_PUT_SIGN:
        PUSH AF
        LD A,D
        OR A
        LD A,$2B
        CALL NZ,OUTCHR
        POP AF
        RET
; ----------------------------------------------------------------------
; OUTCHR -- emit one character to the currently selected output channel, tracking the print column.
;   In:        A = character to output. PTRFIL ($0840) = current file FCB pointer (0 = no file, i.e.
;              console or printer). PRTFLG ($0838) selects printer (nonzero) vs console (0). OUTPUT_COLUMN
;              ($0837) = active-device output column (here the printer column); PRINTER_WIDTH ($083A) =
;              printer auto-CR width ($FF = unlimited).
;   Out:       The character is sent to the file (PUTC_FILE_RESUME), the console (OUTDO_WIDTH_1), or the
;              printer device (OUTDO_DEVICE). OUTPUT_COLUMN is advanced/reset for the printer path.
;   Clobbers:  AF (A/HL/flags restored or consumed per path); OUTPUT_COLUMN updated.
;   Algorithm: Three-way channel router. If a file is open it diverts to the file writer. With no file and
;              PRTFLG clear it falls through to the console width engine (OUTDO_WIDTH_1). With PRTFLG set it
;              runs the printer column logic itself: backspace decrements the column and emits via OUTDO_DEVICE;
;              TAB ($09) recursively emits spaces to the next 8-column stop; CR ($0D) resets the column to 0;
;              other control codes below CR pass through with no column change; printable characters bump the
;              column and, when it reaches PRINTER_WIDTH, force a CRLF (OUTDO_WIDTH) first. The printer path
;              then falls through into OUTDO_DEVICE to emit the byte. [RE] PRTFLG: the in-file data comment
;              flags an unresolved suppress-vs-printer-redirect CONFLICT; the LPRINT/LLIST set sites and this
;              routing favor printer-redirect, which is the reading used here.
; ----------------------------------------------------------------------
OUTCHR:
        PUSH AF
        PUSH HL
        ; if a file is the current output channel, divert to the file writer instead of console/printer
        LD HL,(PTRFIL)
        LD A,H
        OR L
        JP NZ,PUTC_FILE_RESUME
        POP HL
        ; no file: PRTFLG clear -> console (width engine); set -> handle the printer device below
        LD A,(PRTFLG)
        OR A
        JP Z,OUTDO_WIDTH_1
        POP AF
        PUSH AF
        ; backspace on the printer: step the tracked column back one, then fall to OUTDO_DEVICE to emit it
        CP $08
        JR NZ,OUTCHR_1
        LD A,(OUTPUT_COLUMN)
        DEC A
        LD (OUTPUT_COLUMN),A
        POP AF
        JR OUTDO_DEVICE
OUTCHR_1:
        ; TAB: recursively emit spaces until the printer column reaches the next 8-column stop
        CP $09
        JR NZ,OUTCHR_3
OUTCHR_2:
        LD A,$20
        CALL OUTCHR
        LD A,(OUTPUT_COLUMN)
        AND $07
        JR NZ,OUTCHR_2
        POP AF
        RET
OUTCHR_3:
        POP AF
        PUSH AF
        ; CR resets the column to 0 (A=char-$0D=0 stored); control chars below CR pass through with no column change
        SUB $0D
        JR Z,OUTCHR_5
        JR C,OUTCHR_6
        ; printable char: INC A here sets Z when PRINTER_WIDTH is $FF (unlimited), skipping the auto-CR width check
        LD A,(PRINTER_WIDTH)
        INC A
        LD A,(OUTPUT_COLUMN)
        JR Z,OUTCHR_4
        PUSH HL
        LD HL,PRINTER_WIDTH
        ; at the configured printer width: force a CRLF (OUTDO_WIDTH zeroes the column) before this char and skip the re-count
        CP (HL)
        POP HL
        CALL Z,OUTDO_WIDTH
        JR Z,OUTCHR_6
OUTCHR_4:
        ; advance the printer column unless it is already pinned at $FF
        CP $FF
        JR Z,OUTCHR_6
        INC A
OUTCHR_5:
        LD (OUTPUT_COLUMN),A
OUTCHR_6:
        POP AF
; ----------------------------------------------------------------------
; OUTDO_DEVICE -- low-level printer/LIST device emit through the cold-start-patched BIOS vector.
;   In:        A = character to send to the device.
;   Out:       Character handed to the patched BIOS output entry (in C); all registers preserved.
;   Clobbers:  Nothing (AF/BC/DE/HL saved and restored).
;   Algorithm: Saves all registers, copies the character to C (the CP/M BIOS device-output argument), and
;              CALLs the self-modified $0000 cell. [RE] VERIFIED smc: cold start writes a live BIOS vector
;              into OUTDO_DEVICE_1+1 ($8217; MBASIC twin $5E95), so CD 00 00 becomes CALL <entry> at runtime.
;              [RE] The cold-start jump-table walk ($23842-) reads the BIOS vectors in order CONST, CONIN,
;              CONOUT, LIST; OUTDO_DEVICE_1+1 is patched LAST of these four, so the entry installed here is
;              the BIOS LIST (printer) vector -- NOT CONOUT (an existing in-file comment that says CONOUT is
;              reversed). This matches usage: OUTCHR's printer path and OUTDO_WIDTH's CRLF route through here.
;              (LIST/CONOUT identification rests on the standard CP/M jump-table order, hence [RE].)
; ----------------------------------------------------------------------
OUTDO_DEVICE:
        PUSH AF
        PUSH BC
        PUSH DE
        PUSH HL
        ; CP/M BIOS takes the output byte in C; the CALL below was patched at cold start to the BIOS LIST (printer) entry
        LD C,A
; [RE] VERIFIED smc. OUTDO_DEVICE_1+1 ($6672) is the SMC operand of CALL $0000 ($6671), reached by fall-through from OUTDO_DEVICE ($666C). COLD_START LD (OUTDO_DEVICE_1+1),HL at $8217 patches it to the live CP/M BIOS CONOUT entry (walked from $0001 through the BIOS jump table). The CD 00 00 is a placeholder; +1 is the patch slot, written never jumped-to, and the patched CALL executes on every console output. MBASIC twin patches at $5E95.
OUTDO_DEVICE_1:
        CALL $0000
        POP HL
        POP DE
        POP BC
        POP AF
        RET
; ----------------------------------------------------------------------
; OUTDO_RESET_COL -- clear the printer-redirect flag and, if mid-line, force a fresh line before new output.
;   In:        PRTFLG ($0838) = current printer-redirect selector; OUTPUT_COLUMN ($0837) = active-device column.
;   Out:       PRTFLG cleared to 0 (output back to console). If the column was 0 returns immediately;
;              otherwise falls into OUTDO_WIDTH to emit CRLF and zero the column.
;   Clobbers:  A, flags.
;   Algorithm: Zeroes PRTFLG, then tests OUTPUT_COLUMN: a zero column means we are already at line start so
;              return; a nonzero column drops through to OUTDO_WIDTH so the next output begins on a clean line.
;              [RE] As with PRTFLG generally, the in-file CONFLICT note (suppress vs redirect) applies; the
;              printer-redirect reading is used here.
; ----------------------------------------------------------------------
OUTDO_RESET_COL:
        XOR A
        LD (PRTFLG),A
        ; if already at column 0 we are at line start; otherwise fall into OUTDO_WIDTH to start a fresh line
        LD A,(OUTPUT_COLUMN)
        OR A
        RET Z
; ----------------------------------------------------------------------
; OUTDO_WIDTH -- emit a CRLF on the printer/LIST device and reset its column counter.
;   In:        (none; constants $0D/$0A).
;   Out:       CR then LF sent via OUTDO_DEVICE (the BIOS LIST device); OUTPUT_COLUMN ($0837) zeroed.
;   Clobbers:  A, flags.
;   Algorithm: Calls OUTDO_DEVICE twice (CR, LF) and clears the column. Used by OUTCHR's printer path and
;              OUTDO_RESET_COL to break the line. NOTE: this is a 4-instruction routine ending at its own RET;
;              the local labels OUTDO_WIDTH_1..OUTDO_WIDTH_9 below are NOT continuations of it -- OUTDO_WIDTH_1
;              is the separate console-output width engine that OUTCHR ($6622) and STROUT_PUTC jump into.
;   --
;   OUTDO_WIDTH_1 (console output engine) -- emit one char to the console honoring width, TAB, BS, and paging.
;     In:      The char to emit was PUSHed by the caller (OUTCHR/STROUT_PUTC) and is recovered via POP AF AFTER
;              the Ctrl-O test. CTRL_O_SUPPRESS ($083F), CURSOR_POS ($0B11) console column, PRINT_WIDTH
;              ($083B) console width, CURSOR_ROW ($0B12) cursor row / page-line counter, GFX_STMT_HPLOT_9
;              ($4B97) physical screen width (40 or 80, set at cold start).
;     Out:     Char sent to the console via OUTDO_DEVICE2 (CONOUT) unless Ctrl-O suppression is active; CURSOR_POS
;              advanced, CURSOR_ROW bumped, and an automatic CRLF/page-pause issued at the right-hand margin.
;     Algorithm: If Ctrl-O output suppression is on, discard the char (JP NZ,GETSPA_2 -- its POP AF/RET balances
;              the pushed AF). LF increments the page-line counter (CURSOR_ROW via LINE_COUNT_INC); BS decrements
;              the console column, and when already at column 0 borrows from CURSOR_ROW (decrement row, set column
;              = PRINT_WIDTH-1); TAB expands to the next 8-column stop. A printable char is emitted via
;              OUTDO_DEVICE2 and the column advanced; when the incremented column equals PRINT_WIDTH (and width
;              != $FF) it is at the margin -- if the terminal hardware-wraps at exactly that width
;              (GFX_STMT_HPLOT_9 == PRINT_WIDTH) it only does the line bookkeeping (LIST_NEWLINE_COUNT),
;              otherwise it forces a software CRLF.
; ----------------------------------------------------------------------
OUTDO_WIDTH:
        LD A,$0D
        CALL OUTDO_DEVICE
        LD A,$0A
        CALL OUTDO_DEVICE
        XOR A
        LD (OUTPUT_COLUMN),A
        RET
OUTDO_WIDTH_1:
        ; Ctrl-O active: silently discard this character (reuse GETSPA_2's POP AF/RET tail to balance the pushed AF)
        LD A,(CTRL_O_SUPPRESS)
        OR A
        JP NZ,GETSPA_2
        POP AF
        PUSH BC
        PUSH AF
        ; a line feed bumps the cursor-row / page-line counter (LINE_COUNT_INC)
        CP $0A
        JR NZ,OUTDO_WIDTH_2
        CALL LINE_COUNT_INC
        LD A,$0A
OUTDO_WIDTH_2:
        CP $08
        JR NZ,OUTDO_WIDTH_4
        LD A,(CURSOR_POS)
        OR A
        JR NZ,OUTDO_WIDTH_3
        LD A,(CURSOR_ROW)
        OR A
        JR Z,OUTDO_WIDTH_6
        DEC A
        LD (CURSOR_ROW),A
        ; track the column toward the right margin; INC A here treats width $FF as no auto-wrap
        LD A,(PRINT_WIDTH)
OUTDO_WIDTH_3:
        DEC A
        LD (CURSOR_POS),A
        LD A,$08
        JR OUTDO_WIDTH_8
OUTDO_WIDTH_4:
        ; TAB: emit spaces up to the next 8-column stop
        CP $09
        JR NZ,OUTDO_WIDTH_7
OUTDO_WIDTH_5:
        LD A,$20
        CALL OUTCHR
        LD A,(CURSOR_POS)
        AND $07
        JR NZ,OUTDO_WIDTH_5
OUTDO_WIDTH_6:
        POP AF
        POP BC
        RET
OUTDO_WIDTH_7:
        CP $20
        JR C,OUTDO_WIDTH_8
OUTDO_WIDTH_8:
        POP AF
        PUSH AF
        ; send the character to the console device (BIOS CONOUT)
        CALL OUTDO_DEVICE2
        CP $20
        JR C,OUTDO_WIDTH_9
        LD A,(PRINT_WIDTH)
        INC A
        JR Z,OUTDO_WIDTH_9
        DEC A
        LD B,A
        LD A,(CURSOR_POS)
        INC A
        JR Z,OUTDO_WIDTH_9
        LD (CURSOR_POS),A
        CP B
        JR NZ,OUTDO_WIDTH_9
        ; at the margin: if the screen wraps in hardware (physical width == configured width) just bookkeep the line, else force a CRLF
        LD A,(GFX_STMT_HPLOT_9)
        CP B
        CALL Z,LIST_NEWLINE_COUNT
        CALL NZ,CRLF
OUTDO_WIDTH_9:
        POP AF
        POP BC
        RET
; ----------------------------------------------------------------------
; OUTDO_DEVICE2 -- raw console-byte emit through a second cold-start-patched BIOS output vector.
;   In:        A = character/byte to send.
;   Out:       Byte handed to the patched BIOS console-output entry (in C); all registers preserved.
;   Clobbers:  Nothing (AF/BC/DE/HL saved and restored).
;   Algorithm: Mirror of OUTDO_DEVICE but for the console-output engine: copies the byte to C and CALLs its
;              own self-modified $0000 cell. [RE] VERIFIED smc: cold start patches OUTDO_DEVICE2_1+1 ($820D;
;              MBASIC twin $5E8B). [RE] In the cold-start jump-table walk (order CONST, CONIN, CONOUT, LIST)
;              OUTDO_DEVICE2_1+1 is patched BEFORE OUTDO_DEVICE_1+1, so the entry installed here is BIOS
;              CONOUT -- NOT the LIST/raw-output entry (the existing in-file comment is reversed). This is the
;              actual character emitter for the console engine OUTDO_WIDTH_1, kept distinct from OUTDO_DEVICE
;              (LIST) so the console and printer channels target different BIOS entries. (CONOUT/LIST
;              identification rests on the standard CP/M jump-table order, hence [RE].)
; ----------------------------------------------------------------------
OUTDO_DEVICE2:
        PUSH AF
        PUSH BC
        PUSH DE
        PUSH HL
        ; byte to the BIOS in C; the CALL below was patched at cold start to the BIOS CONOUT (console-output) entry
        LD C,A
; [RE] VERIFIED smc. OUTDO_DEVICE2_1+1 ($670A) is the SMC operand of CALL $0000 ($6709), reached by fall-through from OUTDO_DEVICE2 ($6704). COLD_START LD (OUTDO_DEVICE2_1+1),HL at $820D patches it to the live CP/M BIOS list/raw-output entry (from the BIOS jump-table walk). +1 is the patch slot, not a code entry; the patched CALL executes at runtime. MBASIC twin patches at $5E8B.
OUTDO_DEVICE2_1:
        CALL $0000
        POP HL
        POP DE
        POP BC
        POP AF
        RET
; ----------------------------------------------------------------------
; LIST_NEWLINE_COUNT -- finish the current line's column bookkeeping, then advance the page-line counter.
;   In:        PTRFIL ($0840), PRTFLG ($0838) select which column cell RESET_PRINT_STATE clears.
;   Out:       The active device's column cell zeroed (none if a file is open), then CURSOR_ROW ($0B12)
;              page-line count incremented (clamped at PAGE_LENGTH) with A = 0.
;   Clobbers:  A, B, flags.
;   Algorithm: Calls RESET_PRINT_STATE to clear the column for the current channel (console CURSOR_POS or
;              printer OUTPUT_COLUMN; nothing if a file is the channel), then falls into LINE_COUNT_INC to count
;              the line just completed against the page length. Called from OUTDO_WIDTH_1 when a
;              hardware-wrapping terminal reaches the margin.
; ----------------------------------------------------------------------
LIST_NEWLINE_COUNT:
        CALL RESET_PRINT_STATE
; ----------------------------------------------------------------------
; LINE_COUNT_INC -- count one printed line against the page length, clamping at the bottom of the page.
;   In:        PAGE_LENGTH ($083C) = lines per page; CURSOR_ROW ($0B12) = lines printed on the current page.
;   Out:       CURSOR_ROW incremented unless CURSOR_ROW+1 would reach PAGE_LENGTH (then left unchanged at the
;              limit). Always returns A = 0.
;   Clobbers:  A, B, flags.
;   Algorithm: Loads the page length into B, computes CURSOR_ROW+1, and stores it back only while still below
;              B (JR NC skips the store when CURSOR_ROW+1 >= PAGE_LENGTH); at the page limit it leaves the
;              counter pinned. Returns A = 0 in either case.
; ----------------------------------------------------------------------
LINE_COUNT_INC:
        LD A,(PAGE_LENGTH)
        LD B,A
        LD A,(CURSOR_ROW)
        INC A
        ; store the bumped line count only while below the page length; pin it at the limit
        CP B
        JR NC,LINE_COUNT_INC_1
        LD (CURSOR_ROW),A
LINE_COUNT_INC_1:
        XOR A
        RET
; ----------------------------------------------------------------------
; INCHR -- read the next input character from the current channel (open file or console).
;   In:        PTRFIL ($0840) = current-channel FCB pointer (0 = console). For the file case,
;              the FCB selects the ASCII source being LOADed / MERGEd / CHAINed.
;   Out:       A = next character (7-bit for the console path). Console path falls into and returns
;              through CONIN. On file end-of-data this routine does NOT return a character; it either
;              continues program execution or returns to direct mode (see Algorithm).
;   Clobbers:  A, flags (BC/DE preserved across the file branch; HL is restored/popped on the console
;              and file-success paths).
;   Algorithm: If PTRFIL==0, fall through (via INCHR_1) into CONIN to read one key from the keyboard.
;              Otherwise read the next byte of the open file with GETC_FILE_EOF: on success (NC) return
;              it via FMUL_7 (a borrowed POP HL / RET tail). On end-of-file (CY) this is the end of a
;              LOAD/MERGE/CHAIN text stream: run LOAD_CLEANUP_RESET (close file #0, restore console
;              PRINT state and the resume text pointer); if a CHAIN is in progress (CHAIN_BREAK_FLAG)
;              hand off to the CHAIN continuation (CHAIN_MOVE_STRING_VAR_3); else test
;              RUN_AFTER_LOAD_FLAG -- if set (LOAD ",R") jump through CLEAR_RESET_DATAPTR to rebuild
;              storage and start running the just-loaded program, otherwise print "Ok" (MSG_OK) and RET
;              to direct mode.
;   [RE] The PTRFIL==0 leg has no auto-page 'more' prompt; the only console behaviour here is the
;   fall-through to CONIN. MSG_OK at $0CF2 is "Ok\r\n", the ready prompt, NOT a pause prompt (the older
;   INCHR comment was wrong).
; ----------------------------------------------------------------------
INCHR:
        PUSH HL
        ; select the input channel: PTRFIL==0 means console, nonzero is the open file's FCB
        LD HL,(PTRFIL)
        LD A,H
        OR L
        JR Z,INCHR_1
        ; file channel: pull the next byte; carry set means end of the LOAD/MERGE/CHAIN text stream
        CALL GETC_FILE_EOF
        JP NC,FMUL_7
        PUSH BC
        PUSH DE
        PUSH HL
        ; end of source file: close file #0, restore console PRINT state and the resume text pointer
        CALL LOAD_CLEANUP_RESET
        POP HL
        POP DE
        POP BC
        ; if a CHAIN is mid-flight, divert to the CHAIN continuation instead of the normal post-load path
        LD A,(CHAIN_BREAK_FLAG)
        OR A
        JP NZ,CHAIN_MOVE_STRING_VAR_3
        ; LOAD ",R" auto-run? if so run the loaded program; otherwise fall to the "Ok" prompt
        LD A,(RUN_AFTER_LOAD_FLAG)
        OR A
        ; [RE] auto-run path: stage the per-statement executor before CLEAR_RESET_DATAPTR rebuilds storage and starts the loaded program
        LD HL,STMT_FOR_7
        EX (SP),HL
        JP NZ,CLEAR_RESET_DATAPTR
        EX (SP),HL
        PUSH BC
        PUSH DE
        ; no auto-run: print "Ok" and return to direct mode
        LD HL,MSG_OK
        CALL STROUT
        POP DE
        POP BC
        XOR A
        POP HL
        RET
INCHR_1:
        POP HL
; ----------------------------------------------------------------------
; CONIN -- read one raw console character and service the Ctrl-O output-suppress toggle.
;   In:        none (reads the keyboard through the CP/M BIOS console-in vector).
;   Out:       A = character masked to 7 bits. If the key was Ctrl-O ($0F) the routine instead
;              toggles CTRL_O_SUPPRESS ($083F) and returns A=0 (the Ctrl-O is swallowed, not delivered).
;   Clobbers:  A, flags (BC/DE/HL saved and restored around the BIOS call).
;   Algorithm: CALL the self-modified vector at CONIN_1+1 (patched by cold start to the live CP/M BIOS
;              CONIN entry) to fetch a key, then AND $7F to drop the high bit. If it is not Ctrl-O,
;              return it as-is. For Ctrl-O, toggle the screen-output suppress flag: if suppression was
;              OFF, echo "^O" first (ECHO_CTRL_O, which returns A=0); then CPL/store so CTRL_O_SUPPRESS
;              flips 0<->$FF; if the new state is OFF echo "^O" again before returning. Either way A=0.
;              OUTDO_WIDTH_1 reads CTRL_O_SUPPRESS to discard console output while it is set.
;   [RE] The keyboard input primitive shared by INKEY$, the line editor, and INCHR's console leg.
; ----------------------------------------------------------------------
CONIN:
        PUSH BC
        PUSH DE
        PUSH HL
; [RE] VERIFIED smc. CONIN_1+1 ($6760) is the SMC operand of CALL $0000 ($675F), reached by fall-through from CONIN ($675C). COLD_START LD (CONIN_1+1),HL at $8203 patches it to the live CP/M BIOS CONIN entry (from the BIOS jump-table walk). +1 is the patch slot; the patched CALL executes on every console read. MBASIC twin patches at $5E81.
CONIN_1:
        CALL $0000
        POP HL
        POP DE
        POP BC
        ; strip the high bit so a parity/strobe bit cannot reach the interpreter
        AND $7F
        ; Ctrl-O ($0F): handled locally as the output-suppress toggle, never delivered to the caller
        CP $0F
        RET NZ
        LD A,(CTRL_O_SUPPRESS)
        OR A
        CALL Z,ECHO_CTRL_O
        ; flip the suppress flag (0<->$FF) and store the new state
        CPL
        LD (CTRL_O_SUPPRESS),A
        OR A
        ; newly turned suppression OFF: echo "^O" so the user sees output resume, then return A=0
        JP Z,ECHO_CTRL_O
        XOR A
        RET
; ----------------------------------------------------------------------
; PRINT_CRLF_IF_COL -- emit a newline only if the console cursor is not already at column 0.
;   In:        CURSOR_POS ($0B11) = current console (CRT) output column.
;   Out:       If CURSOR_POS!=0, a CR+LF is emitted (via CRLF) and the print state is reset; if it is
;              already 0, returns immediately leaving the cursor where it is.
;   Clobbers:  A, flags (and whatever CRLF clobbers when it is taken).
;   Algorithm: Test the console column; on zero just RET (already at line start), otherwise JP CRLF to
;              start a fresh line. Called before printing the READY/"Ok" prompt (NEWSTT_READY) and other
;              messages so they do not run onto a partially printed line.
;   [RE] PRINT_CRLF_IF_COL_1 is a SEPARATE entry (not part of the column test): it NUL-terminates the
;   buffer at (HL), loads HL=BUF-1 (so a downstream INC HL lands on BUF[0]), then falls into CRLF. It is
;   reached from PRINT_LIST_ENTRY_1 (end of a PRINT statement) and INLIN_CR_FINISH (CR end-of-line in the
;   auto-quote redisplay mode) -- NOT from the Ctrl-U kill-line (that path is INLIN_RESET_LINE /
;   INLIN_KILL_LINE).
; ----------------------------------------------------------------------
PRINT_CRLF_IF_COL:
        ; at the start of a line already? if so do nothing
        LD A,(CURSOR_POS)
        OR A
        RET Z
        JP CRLF
PRINT_CRLF_IF_COL_1:
        LD (HL),$00
        LD HL,BUF_INPUT_RESET_PTR
; ----------------------------------------------------------------------
; CRLF -- write a carriage-return + line-feed to the console and reset the per-line print state.
;   In:        none.
;   Out:       CR ($0D) and LF ($0A) emitted through OUTCHR; the active device's column counter cleared
;              by RESET_PRINT_STATE (fallen into; a no-op when output is going to a file).
;   Clobbers:  A, flags (plus RESET_PRINT_STATE's effects on the active-device column cell).
;   Algorithm: Emit $0D then $0A via OUTCHR (which routes to the active device and counts columns),
;              then fall straight into RESET_PRINT_STATE to zero the active device's column counter.
;   [RE] The print-newline routine used by the sign-on banner, the "Ok" prompt, and Ctrl-character echo.
; ----------------------------------------------------------------------
CRLF:
        ; emit CR then LF, then fall into RESET_PRINT_STATE to clear the column counter
        LD A,$0D
        CALL OUTCHR
        LD A,$0A
        CALL OUTCHR
; ----------------------------------------------------------------------
; RESET_PRINT_STATE -- after a newline, zero the column counter of the currently active output device.
;   In:        PTRFIL ($0840) selects file vs console/printer; PRTFLG ($0838) selects printer vs console.
;   Out:       A=0. If output is going to a file (PTRFIL!=0) nothing is changed. Otherwise the column
;              counter for the active device is set to 0: OUTPUT_COLUMN ($0837) when the printer is
;              selected (PRTFLG!=0), else the console column CURSOR_POS ($0B11).
;   Clobbers:  A, flags (HL preserved via PUSH/POP).
;   Algorithm: Read PTRFIL; if a file channel is active there is no on-screen/printer column to reset, so
;              return with A=0. For the console/printer case, branch on PRTFLG: printer -> clear the
;              printer column OUTPUT_COLUMN; console -> clear the console column CURSOR_POS. Either way A=0.
;   [RE] This routine does NOT modify PRTFLG (the older prose was imprecise) and touches only ONE of the
;   two column cells (whichever device is active); RESET_PRINT_STATE_1/_2 are those two device arms.
; ----------------------------------------------------------------------
RESET_PRINT_STATE:
        PUSH HL
        ; output to a file? then there is no device column to reset; just return
        LD HL,(PTRFIL)
        LD A,H
        OR L
        POP HL
        JR Z,RESET_PRINT_STATE_1
        XOR A
        RET
RESET_PRINT_STATE_1:
        ; console vs printer: clear the column counter of whichever device is currently selected
        LD A,(PRTFLG)
        OR A
        JR Z,RESET_PRINT_STATE_2
        XOR A
        ; printer path: reset the printer column (LPOS)
        LD (OUTPUT_COLUMN),A
        RET
RESET_PRINT_STATE_2:
        XOR A
        ; console path: reset the CRT column
        LD (CURSOR_POS),A
        XOR A
        RET
; ----------------------------------------------------------------------
; RPC_CONST_POLL -- poll the console for a pending key (BIOS CONST), preserving BC/DE/HL.
;   In:        RPC_CONST_POLL_1+1 holds the BIOS CONST target address, self-modified at COLD_START (the address word read at [($0001)]+4 -- the operand of the BIOS CONST JMP -- stored here at $81F6).
;   Out:       A = console status (0 = no key waiting; nonzero = a key is down); Z set iff no key. RET Z when nothing is pending; otherwise execution FALLS THROUGH into INKEY_SCAN to service the key.
;   Clobbers:  A, flags. BC/DE/HL are saved and restored across the BIOS call.
;   Algorithm: Save BC/DE/HL, invoke the cold-start-patched BIOS console-status routine (CONST) via the self-modified CALL at RPC_CONST_POLL_1, restore the registers, then OR A to set Z from the returned status byte. RET Z on no key. Used by LIST as the between-lines Ctrl-S/Ctrl-C check; when a key IS pending it deliberately falls straight into INKEY_SCAN.
; ----------------------------------------------------------------------
RPC_CONST_POLL:
        PUSH BC
        PUSH DE
        PUSH HL
; [RE] VERIFIED smc. RPC_CONST_POLL_1+1 ($67B2) is the SMC operand of CALL $0000 ($67B1), reached by fall-through from RPC_CONST_POLL ($67AE). COLD_START LD (RPC_CONST_POLL_1+1),HL at $81F6 patches it to the live CP/M BIOS CONST entry (BIOS base+4, the same HL written to INKEY_SCAN_2+1 at $81F3). +1 is the patch slot; the patched CALL executes when polling console status. MBASIC twin patches at $5E74.
RPC_CONST_POLL_1:
        ; ask the BIOS whether a console key is waiting (CONST); operand self-modified at COLD_START to the live BIOS CONST address
        CALL $0000
        POP HL
        POP DE
        POP BC
        ; set Z from the status byte: zero (no key) returns; nonzero falls through into INKEY_SCAN to service it
        OR A
        RET Z
; ----------------------------------------------------------------------
; INKEY_SCAN -- consume a waiting console key: Ctrl-S pause, Ctrl-C break, else stash the key and return.
;   In:        Entered (fall-through from RPC_CONST_POLL, or CALL NZ from STMT_FOR_8) when CONST reported a key pending.
;   Out:       Non-Ctrl-C: the char is left in PENDING_KEY for a later INKEY$/line-input read, and the routine RETURNS to its caller (via the RET NZ at STMT_STOP). Ctrl-C: echoes '^C' and breaks the program (does not return).
;   Clobbers:  A, flags (CONIN also saves/restores BC/DE/HL internally).
;   Algorithm: Read one char with CONIN. If it is Ctrl-S ($13), do a SECOND, blocking CONIN -- the Ctrl-S keystroke paused output and this read holds until the user presses any resume key (the classic Ctrl-S screen pause). Store the resulting char in PENDING_KEY. Test for Ctrl-C ($03): if so, CALL ECHO_CTRL_CHAR (echo '^C' and clear the output flags). Then JP STMT_STOP UNCONDITIONALLY. STMT_STOP begins with RET NZ: the non-Ctrl-C path arrives with NZ (preserved from CP $03 through the skipped ECHO call) and simply returns; the Ctrl-C path arrives with Z (ECHO_CTRL_CHAR ends in JP CRLF, which returns A=0/Z) so STMT_STOP falls through to break the running program.
; ----------------------------------------------------------------------
INKEY_SCAN:
        ; read the key that the CONST poll detected
        CALL CONIN
        ; Ctrl-S = pause: do a second, blocking read that holds until the user presses any key to resume
        CP $13
        CALL Z,CONIN
        ; park the keystroke so a later INKEY$ or line-input read can pick it up
        LD (PENDING_KEY),A
        ; flag whether the key is Ctrl-C (selects break-vs-return at STMT_STOP below)
        CP $03
        CALL Z,ECHO_CTRL_CHAR
        ; unconditional: STMT_STOP's leading RET NZ returns on the non-Ctrl-C path (NZ); the Ctrl-C path arrives Z (from ECHO_CTRL_CHAR/CRLF) and falls through to break
        JP STMT_STOP
; ----------------------------------------------------------------------
; INKEY_SCAN_1 -- INKEY$ function (token $EE): return a 1-character string for any waiting key, else "".
;   In:        Reached by JP Z,INKEY_SCAN_1 from the FRMEVL function dispatcher; text pointer at the INKEY$ keyword; PENDING_KEY may hold a type-ahead char parked by INKEY_SCAN.
;   Out:       A string value: FAC -> a length-1 STRDESC holding the key, or FAC -> EMPTY_STRING_DESC if no key; VALTYP = VT_STR. The pre-call text pointer is restored into HL. Returns to the function dispatcher's caller.
;   Clobbers:  A, BC, DE, HL, flags; FAC, VALTYP; PENDING_KEY (cleared if it supplied the char).
;   Algorithm: Step the text pointer past the keyword (CHRGET) and PUSH it. First try a type-ahead key from PENDING_KEY (GET_PENDING_KEY, NZ if one was present); if none, poll BIOS CONST (the cold-start-patched CALL at INKEY_SCAN_2) and read CONIN only if a key is now ready. Char-obtained path: build a 1-byte string (ALLOC_STR_1) and store the char into it (STR_FN_RETURN_CHAR), which tail-jumps through PUT_STR_TEMP -- that routine sets VALTYP=VT_STR and FAC = the temp descriptor, and its cover-idiom POP HL recovers the saved text pointer and returns one level up; this path NEVER reaches INKEY_SCAN_4. No-key path: JR Z to INKEY_SCAN_4, which points FAC at EMPTY_STRING_DESC, sets VALTYP=VT_STR, restores the text pointer (POP HL) and RETs.
;   [RE] Non-blocking: INKEY$ never waits -- when CONST reports no key the result is the empty string.
; ----------------------------------------------------------------------
INKEY_SCAN_1:
        ; step the interpreter text pointer past the INKEY$ keyword
        CALL CHRGET
        PUSH HL
        ; prefer a type-ahead key already parked by the Ctrl-C/Ctrl-S scan
        CALL GET_PENDING_KEY
        JR NZ,INKEY_SCAN_3
; [RE] VERIFIED smc. INKEY_SCAN_2+1 ($67D6) is the SMC operand of CALL $0000 ($67D5), reached by fall-through from INKEY_SCAN_1 ($67CC) on the no-pending-key path. COLD_START LD (INKEY_SCAN_2+1),HL at $81F3 patches it to the live CP/M BIOS CONST entry for INKEY$ polling (BIOS base+4, same HL also written to RPC_CONST_POLL_1+1 at $81F6). +1 is the patch slot; the patched CALL executes when polling for a key. MBASIC twin uses the same COLD_START BIOS-table walk.
INKEY_SCAN_2:
        ; no type-ahead: ask BIOS CONST if a key is ready now (operand self-modified at COLD_START)
        CALL $0000
        OR A
        ; nothing waiting: take the empty-string path (INKEY$ never blocks)
        JR Z,INKEY_SCAN_4
        ; a key is ready: consume it
        CALL CONIN
INKEY_SCAN_3:
        PUSH AF
        ; build a length-1 string to hold the keystroke (result type/FAC are set later inside PUT_STR_TEMP, not at INKEY_SCAN_4)
        CALL ALLOC_STR_1
        POP AF
        LD E,A
        CALL STR_FN_RETURN_CHAR
INKEY_SCAN_4:
        ; no-key result: the empty string
        LD HL,EMPTY_STRING_DESC
        LD (FAC),HL
        ; empty-string path: mark VALTYP as a string (the char path sets VALTYP in PUT_STR_TEMP instead)
        LD A,VT_STR
        LD (VALTYP),A
        POP HL
        RET
; ----------------------------------------------------------------------
; GET_PENDING_KEY -- read-and-clear the type-ahead key parked in PENDING_KEY by INKEY_SCAN.
;   In:        PENDING_KEY ($0834) = a captured console char, or 0 if none.
;   Out:       If PENDING_KEY was 0: A=0, Z set (no key), cell unchanged. Otherwise A = the key, NZ set, and PENDING_KEY zeroed (one-shot consume).
;   Clobbers:  A, flags; PENDING_KEY (cleared on the key path).
;   Algorithm: Load PENDING_KEY and OR A. On zero, RET Z immediately. Otherwise save the char, zero the cell so the same key cannot be delivered twice, restore the char into A and return NZ. Used by INKEY$ and by the line-input reader to drain a key parked by the Ctrl-C/Ctrl-S scan.
; ----------------------------------------------------------------------
GET_PENDING_KEY:
        LD A,(PENDING_KEY)
        OR A
        ; no key parked: return Z with A=0
        RET Z
        PUSH AF
        XOR A
        ; clear the cell so this key is consumed exactly once
        LD (PENDING_KEY),A
        POP AF
        RET
; ----------------------------------------------------------------------
; OUTCHR_LF_EXPAND -- write one character to the active output channel; after a bare LF, append a CR.
;   In:        A = character to print; output channel selected by PRTFLG/PTRFIL (handled inside OUTCHR).
;   Out:       Character emitted. If it was LF ($0A): a CR ($0D) is emitted AFTER it, the active device's
;              print state is reset (RESET_PRINT_STATE), and A is restored to $0A on return.
;   Clobbers:  A, flags.
;   Algorithm: Send the character through OUTCHR. If it was not LF, return. For LF, the LF has already
;              been emitted, so emit a trailing CR so the device returns to column 0 (net effect: a stored
;              bare LF advances the cursor to the start of the next line), reset the active column counter,
;              and reload A=$0A so the caller still sees the LF it asked to print.
;   [RE] The newline-normalizing console/file writer used by the detokenized-line output loop
;   (PRINT_ZSTRING / LIST / ASCII-SAVE) and the EDIT/line-editor redisplay.
; ----------------------------------------------------------------------
OUTCHR_LF_EXPAND:
        CALL OUTCHR
        ; only LF needs fixing up; any other character is already fully emitted
        CP $0A
        RET NZ
        ; the LF was just emitted; append a CR so the cursor returns to column 0, then reset the column counter
        LD A,$0D
        CALL OUTCHR
        CALL RESET_PRINT_STATE
        ; restore the original LF in A for the caller
        LD A,$0A
        RET
; ----------------------------------------------------------------------
; STR_COPY_DOWN -- garbage-collect if needed, then block-move a region via STR_COPY_DOWN_NOCHK.
;   In:        HL = destination pointer (write side), BC = source pointer (read side),
;              DE = source low-bound sentinel (the move stops when the read pointer reaches DE).
;   Out:       Region copied; on return HL = DE (= read pointer at sentinel), BC = matching write
;              pointer, A = the final (sentinel) byte, Z set.
;   Clobbers:  A, BC, DE, HL, flags.
;   Algorithm: First call GC_CHECK_AND_COLLECT, which may run GARBAG to compact the string heap if this
;              allocation would otherwise collide with variable space (it preserves HL/BC/DE across the
;              collection). Then fall into STR_COPY_DOWN_NOCHK to do the byte move. [RE] This is the MS
;              BASIC block-shift primitive that opens a gap by copying a run from a lower block up to a
;              higher block, processing top-down to avoid overlap loss; used by program-line insert (VARTAB
;              shuffle, $0EFx) and PTRGET variable/array allocation (STREND grow).
; ----------------------------------------------------------------------
STR_COPY_DOWN:
        ; guard the candidate address in HL against FRETOP (GC / 'Out of memory' if it would collide), then fall through to the unguarded copy
        ; compact the string heap first if this move would otherwise overrun variable space
        CALL GC_CHECK_AND_COLLECT
; ----------------------------------------------------------------------
; STR_COPY_DOWN_NOCHK -- top-down byte block move with no prior heap check.
;   In:        HL = destination pointer (write side), BC = source pointer (read side),
;              DE = low-bound sentinel compared against the read pointer.
;   Out:       Bytes copied from the source block to the destination block, both pointers walked down
;              to DE. On return: read pointer = DE, A = the final (sentinel) byte, Z set.
;   Clobbers:  A, BC, DE, HL, flags.
;   Algorithm: PUSH BC / EX (SP),HL / POP BC swaps HL and BC so that after the swap HL is the READ pointer
;              (the caller's BC) and BC is the WRITE pointer (the caller's HL); DE is compared against the
;              read side. Each pass: compare read pointer (HL) vs DE; read one byte (HL) and write it (BC);
;              if the sentinel was reached (Z) return having just written that final byte; otherwise
;              decrement BOTH pointers and repeat. [RE] In the allocation callers the destination (caller
;              HL) is the HIGHER address and the source (caller BC) the lower, so the block is shifted UP
;              toward higher addresses; processing top-to-bottom (both pointers decrement) avoids overlap
;              corruption. (The routine is generic; some callers, e.g. GC string-free, pass a lower HL.)
; ----------------------------------------------------------------------
STR_COPY_DOWN_NOCHK:
        ; exchange HL and BC via the stack so the loop reads from (HL) and writes to (BC)
        ; swap HL and BC: after the swap HL is the read pointer (old BC), BC is the write pointer (old HL)
        PUSH BC
        EX (SP),HL
        POP BC
STR_COPY_DOWN_NOCHK_1:
        ; test the read pointer (HL) against the bottom limit DE (Z when HL==DE, the last byte to move)
        ; compare the read pointer (HL) against the DE low bound (compare only; the byte copy follows)
        CALL CMP_HL_DE
        LD A,(HL)
        ; store this byte to the destination; the DE boundary byte is copied before the RET Z fires
        LD (BC),A
        ; sentinel reached: the final byte was just written, so return
        RET Z
        ; step both pointers down one byte and continue the descending move
        ; step both pointers down by one and continue the top-down move
        DEC BC
        DEC HL
        JR STR_COPY_DOWN_NOCHK_1
; ----------------------------------------------------------------------
; CHECK_STACK_ROOM -- ensure 2*C + 58 bytes of Z-80 stack remain above MEMSIZ before recursing.
;   In:        C = number of 2-byte slots the caller is about to consume (B is forced to 0, so only C matters).
;              SP = current stack pointer. MEMSIZ ($0B23) = top-of-usable-storage pointer (variables/string
;              heap grow upward toward it).
;   Out:       Returns (HL preserved, BC unchanged) when there is room: SP - (2*C + 58) >= MEMSIZ.
;              On shortfall it does not return: sets SAVSTK = STKTOP-2 (TOP_OF_STACK_ROOM-2) and jumps
;              to RAISE_ERROR with DE = ERR_OUT_OF_MEMORY (7).
;   Clobbers:  A, flags (HL saved/restored around the test; BC preserved).
;   Algorithm: Compute HL = SP - (MEMSIZ + 2*C + 58) using a fixed 58-byte ($3A) margin folded as the
;              16-bit constant $FFC6 = -58 (LD A,$C6 / SUB L ; LD A,$FF / SBC A,H). An early borrow from
;              SBC A,H (MEMSIZ+2*C exceeding $FFC6) fails immediately via JR C. Otherwise ADD HL,SP:
;              carry means SP lies far enough above MEMSIZ, so the stack can grow safely and it returns.
;              No carry means the descending stack would crash into ascending variable/string storage,
;              so fall into the out-of-memory path.
; ----------------------------------------------------------------------
CHECK_STACK_ROOM:
        PUSH HL
        ; start from the storage-top limit (lowest address the stack may reach)
        ; [RE] start from the top-of-storage limit MEMSIZ; the stack must stay above this
        LD HL,(MEMSIZ)
        LD B,$00
        ; add the request twice (the second ADD HL,BC): HL = MEMSIZ + 2*C, C counting 2-byte stack slots
        ; begin adding the caller's slot count: two ADD HL,BC add 2*C (B forced to 0 above)
        ADD HL,BC
        ADD HL,BC
        ; form $FFC6 - HL = -(MEMSIZ + 2*C + 58), folding in the 58-byte fixed margin
        ; [RE] fold in a fixed 58-byte ($3A) headroom margin via $FFC6 = -58: builds HL = -(MEMSIZ + 2*C + 58)
        LD A,$C6
        SUB L
        LD L,A
        LD A,$FF
        SBC A,H
        ; MEMSIZ+2*C already past $FFC6 (address wrap) -> out of memory
        JR C,STACK_OVERFLOW_RAISE
        LD H,A
        ; add the live stack pointer; carry set => SP is high enough, room exists
        ; HL = SP - (MEMSIZ + 2*C + 58); carry set iff the stack has the requested room
        ADD HL,SP
        POP HL
        ; enough headroom: return to caller (HL already restored)
        RET C
STACK_OVERFLOW_RAISE:
        ; no room: rewind the stack mark (TOP_OF_STACK_ROOM - 2) and save it to SAVSTK for error recovery
        LD HL,(TOP_OF_STACK_ROOM)
        DEC HL
        DEC HL
        LD (SAVSTK),HL
OUT_OF_MEMORY_RAISE:
        LD DE,ERR_OUT_OF_MEMORY
        JP RAISE_ERROR
; ----------------------------------------------------------------------
; GC_CHECK_AND_COLLECT -- guarantee a pending string-heap allocation fits, compacting if needed.
;   In:        HL = candidate string-heap address the allocation would occupy.
;              FRETOP ($0B48) = bottom of free string space (heap fills downward to here).
;   Out:       Returns with carry clear when HL does not collide with the heap floor (room exists).
;              HL/DE/BC are preserved across the optional collection.
;              If still no room after garbage collection, does not return: raises Out of memory (7)
;              via RAISE_OUT_OF_MEMORY (the RAISE_OUT_OF_MEMORY tail).
;   Clobbers:  A, flags (HL, DE, BC preserved around GARBAG).
;   Algorithm: Compare HL against FRETOP (CMP_STR_VS_VARTOP). If no collision (NC) return. Otherwise
;              save the caller's registers, run GARBAG to compact live strings and reclaim space,
;              restore registers, and re-test. If room now exists return; if not, JR into
;              RAISE_OUT_OF_MEMORY (error 7). [RE] NOTE: the raised error is Out of memory (7), NOT
;              'Out of string space' (14); the dedicated Out-of-string-space allocator is GETSPA ($6C58).
; ----------------------------------------------------------------------
GC_CHECK_AND_COLLECT:
        ; would the candidate address collide with FRETOP? if not (NC), return
        ; would this allocation collide with the string-heap floor (FRETOP)?
        CALL CMP_STR_VS_VARTOP
        ; no collision: enough free string space, return
        RET NC
        PUSH BC
        PUSH DE
        PUSH HL
        ; collision: compact live strings once (HL/DE/BC preserved across the collect)
        ; heap full: compact live strings to reclaim space (caller's HL/DE/BC saved across it)
        CALL GARBAG
        POP HL
        POP DE
        POP BC
        ; re-test after GC; if it still collides, fall through to the out-of-memory raise
        ; re-test after compaction
        CALL CMP_STR_VS_VARTOP
        RET NC
        JR OUT_OF_MEMORY_RAISE
; ----------------------------------------------------------------------
; CMP_STR_VS_VARTOP -- test whether a string-heap address sits at/below the free-space floor.
;   In:        HL = candidate string-heap address to test. FRETOP ($0B48) = bottom of free string space.
;   Out:       Carry set iff FRETOP < HL (candidate lies above the floor => collision / no room);
;              carry clear iff FRETOP >= HL (room available). HL and DE are preserved (restored).
;   Clobbers:  A, flags (HL/DE round-tripped via EX DE,HL and PUSH/POP DE).
;   Algorithm: Swap the candidate into DE, load FRETOP into HL, and run CMP_HL_DE (FRETOP - candidate).
;              Its carry is the collision flag. Swap back so HL again holds the candidate, restore DE.
;              [RE] Despite the prior name 'VARTOP', the cell compared is FRETOP ($0B48), the top-of-free-
;              string-space pointer.
; ----------------------------------------------------------------------
CMP_STR_VS_VARTOP:
        PUSH DE
        EX DE,HL
        ; load FRETOP, then CMP_HL_DE computes FRETOP - candidate; carry => candidate is above FRETOP (collision)
        ; compare the free-space floor FRETOP against the candidate (now in DE)
        LD HL,(FRETOP)
        ; carry := FRETOP < candidate, i.e. the allocation would overrun the heap floor
        CALL CMP_HL_DE
        ; restore HL = candidate address for the caller (compare result left in the flags)
        EX DE,HL
        POP DE
        RET

; ======================================================================
; PROGRAM / VARIABLE MANAGEMENT (CLEAR, NEW, GC)
; ======================================================================
; ----------------------------------------------------------------------
; RUN_CLEAR -- mark every file slot closed, BDOS-close all files, then fall into the full variable clear (RUN/NEW warm-start tail)
;   In:        MAX_FILE_NUM = highest open-file index; FILTAB = packed array of (MAX_FILE_NUM+1) 2-byte little-endian FCB-base pointers (each FCB's byte 0 is FCB.MODE).
;   Out:       Every slot's FCB.MODE byte set to 0 (FCB_MODE_CLOSED), all files BDOS-closed, A=0 (Z set); control falls through STMT_NEW's RET NZ guard into CLEAR_VARS to erase variables.
;   Clobbers:  AF, BC, DE, HL.
;   Algorithm: Walk FILTAB once (B = MAX_FILE_NUM+1 slots): for each slot read its 2-byte FCB-base pointer into DE and store A=0 at (DE) = FCB.MODE, marking that slot closed. Then CLOSE_ALL_FILES performs the actual BDOS close of any still-open file. XOR A leaves A=0/Z set so the RET NZ in STMT_NEW falls through into the variable clear. Entered from WARM_START (CALL at $81BD) as the file-teardown half of RUN/NEW.
; ----------------------------------------------------------------------
RUN_CLEAR:
        ; loop over all (MAX_FILE_NUM+1) FILTAB slots
        LD A,(MAX_FILE_NUM)
        LD B,A
        LD HL,FILTAB
        ; A=0/Z set so STMT_NEW's RET NZ guard falls through into the variable clear
        XOR A
        INC B
RUN_CLEAR_SLOT_LOOP:
        LD E,(HL)
        INC HL
        LD D,(HL)
        INC HL
        ; mark this slot closed: store 0 into FCB.MODE (DE = the FCB base this FILTAB entry points at)
        LD (DE),A
        DJNZ RUN_CLEAR_SLOT_LOOP
        ; BDOS-close any file still physically open
        CALL CLOSE_ALL_FILES
        XOR A
; ----------------------------------------------------------------------
; STMT_NEW -- NEW statement handler (token $94): erase the current program and all variables
;   In:        Z flag set by the statement parser when the char after the NEW token is end-of-statement (bare NEW); NZ if trailing text follows.
;   Out:       On a bare NEW, falls into CLEAR_VARS which writes the empty-program terminator and resets every storage pointer; on trailing text RET NZ returns immediately (caller flags the syntax error).
;   Clobbers:  none on the RET NZ path; on fall-through, see CLEAR_VARS.
;   Algorithm: NEW takes no operand, so reject any trailing character with RET NZ, else fall straight into CLEAR_VARS. RUN_CLEAR also reaches this point with A=0 (Z set) so RUN's file teardown continues through the same RET NZ guard into the variable clear.
; ----------------------------------------------------------------------
STMT_NEW:
        ; NEW takes no argument: any non-end-of-statement char is a syntax error, so bail (caller reports it)
        RET NZ
; ----------------------------------------------------------------------
; CLEAR_VARS -- (CLEARC) wipe the program and all variables: turn trace off, write the empty-program link, and re-base VARTAB just above program text
;   In:        TXTTAB = start of program text in RAM.
;   Out:       TRCFLG cleared (trace off); LOAD_PROTECT_FLAG, AUTFLG and RENUM_PENDING_FLAG cleared; the two link bytes at TXTTAB set to 0 (empty / end-of-program link); VARTAB = TXTTAB+2. Falls into CLEAR_RESET_DATAPTR.
;   Clobbers:  AF, HL.
;   Algorithm: CALL STMT_TRACE+1: the $AF byte of 'LD A,$AF' decodes as XOR A at the +1 entry, so this runs XOR A; LD (TRCFLG),A; RET -- turning trace OFF and returning A=0 in one shot. Reuse that A=0 to clear LOAD_PROTECT_FLAG, AUTFLG and RENUM_PENDING_FLAG and to write the two zero link bytes at TXTTAB (the null BASLINE.LINK of an empty program). Set VARTAB = TXTTAB+2 so the simple-variable table starts right after the now-empty program, then fall into the storage-pointer rebuild.
; ----------------------------------------------------------------------
CLEAR_VARS:
        LD HL,(TXTTAB)
        ; TROFF entry: the +1 lands on the $AF byte (decodes as XOR A), turning trace off and returning A=0, reused as the zero source below
        CALL STMT_TRACE+1
        ; clear LOAD_PROTECT_FLAG (a protection-loaded program is no longer present)
        LD (LOAD_PROTECT_FLAG),A
        LD (AUTFLG),A
        LD (RENUM_PENDING_FLAG),A
        ; write the empty-program terminator: a null forward link (two zero bytes) at the start of program text
        LD (HL),A
        INC HL
        LD (HL),A
        INC HL
        ; place the simple-variable table immediately after the program text (TXTTAB+2)
        LD (VARTAB),HL
; ----------------------------------------------------------------------
; CLEAR_RESET_DATAPTR -- entry that seeds the storage reset with HL = TXTTAB-1 (program start minus one)
;   In:        TXTTAB = start of program text.
;   Out:       HL = TXTTAB-1; falls into CLEAR_RESET_STORAGE which stores it as the restart text pointer.
;   Clobbers:  HL.
;   Algorithm: Load program start and step back one byte so CHRGET's pre-increment will land on the first program byte. The common entry used by CLEAR and by RUN (and by LOAD's CHAIN path) to (re)establish the run cursor before the storage rebuild; CLEAR_VARS reaches it by fall-through after wiping the program.
; ----------------------------------------------------------------------
CLEAR_RESET_DATAPTR:
        LD HL,(TXTTAB)
        ; back up one byte so CHRGET's pre-increment lands on the first program byte
        DEC HL
; ----------------------------------------------------------------------
; CLEAR_RESET_STORAGE -- core CLEAR/NEW/RUN storage-map rebuild: reset DATA/variable/array/string pointers, DEFTYPE, RND seed and trap state, then reset the stack
;   In:        HL = restart text pointer (TXTTAB-1 from the entries above); VARTAB already re-based; CHAIN_PRESERVE_FLAG / CHAIN_BREAK_FLAG select the CHAIN preserve paths; MEMSIZ = top of usable RAM; TOP_OF_STACK_ROOM = stack base.
;   Out:       DATA pointer reset (STMT_RESTORE); ARYTAB=STREND=VARTAB (no arrays, no variables); unless CHAIN keeps variables, OPTION BASE state cleared and DEFTYPE_TBL all set to $04 (VT_SNG); RNDX_SEED reseeded from the default constant and the 3 RND counter cells zeroed; ONEFLG/ON_ERROR_LINE/CONT_TXTPTR cleared; FRETOP=MEMSIZ unless CHAIN preserves the heap; SAVSTK=TOP_OF_STACK_ROOM-2; SP reset to TOP_OF_STACK_ROOM (in RESET_RUN_STATE), into which this falls with HL=TOP_OF_STACK_ROOM.
;   Clobbers:  AF, BC, DE, HL, SP.
;   Algorithm: Save HL as the restart cursor (OPEN_RESUME_TEXT_PTR). Unless CHAIN_PRESERVE_FLAG is set (CHAIN keeping variables): clear the OPTION BASE value+set-flag and fill all 26 DEFTYPE_TBL letters with VT_SNG ($04, default single). Always: copy the 4-byte default RND seed (RND_SEED_DEFAULT) into RNDX_SEED and zero the three RND counter cells (wrap/const-index/mult-index); clear ONEFLG (error trap inactive), ON_ERROR_LINE and CONT_TXTPTR. Set FRETOP=MEMSIZ unless CHAIN_BREAK_FLAG preserves the heap. Reset the DATA read pointer (STMT_RESTORE). Collapse arrays/strings: ARYTAB=STREND=VARTAB. Unless CHAIN preserves variables, CLOSE_ALL_FILES. Discard the caller's return address (POP BC); set SAVSTK=TOP_OF_STACK_ROOM-2 but leave HL=TOP_OF_STACK_ROOM, then fall into RESET_RUN_STATE which does LD SP,HL (so SP := TOP_OF_STACK_ROOM).
; ----------------------------------------------------------------------
CLEAR_RESET_STORAGE:
        ; remember the restart cursor (TXTTAB-1); RESET_RUN_STATE_1 hands it back to the main loop
        LD (OPEN_RESUME_TEXT_PTR),HL
        ; CHAIN keeping variables? then skip the OPTION-BASE and DEFTYPE reset below
        LD A,(CHAIN_PRESERVE_FLAG)
        OR A
        JR NZ,CLEAR_RESET_STORAGE_2
        XOR A
        LD (OPTION_BASE_SET_FLAG),A
        LD (OPTION_BASE_VALUE),A
        ; set all 26 letters' default type to single precision (DEFTYPE_TBL[0..25] := VT_SNG=$04)
        LD B,$1A
        LD HL,DEFTYPE_TBL
CLEAR_RESET_STORAGE_1:
        LD (HL),$04
        INC HL
        DJNZ CLEAR_RESET_STORAGE_1
CLEAR_RESET_STORAGE_2:
        ; re-seed RND: copy the 4-byte default seed constant into RNDX_SEED
        LD DE,RND_SEED_DEFAULT
        LD HL,RNDX_SEED
        CALL FP_MOVE4
        ; zero the three RND counter cells (wrap counter, const index, mult index)
        LD HL,RND_WRAP_COUNTER
        XOR A
        LD (HL),A
        INC HL
        LD (HL),A
        INC HL
        LD (HL),A
        XOR A
        ; clear the error-trap-active flag and the ON ERROR line / CONT resume pointer
        LD (ONEFLG),A
        LD L,A
        LD H,A
        LD (ON_ERROR_LINE),HL
        LD (CONT_TXTPTR),HL
        ; string-heap top := top of RAM, unless CHAIN is preserving the heap (CHAIN_BREAK_FLAG)
        LD HL,(MEMSIZ)
        LD A,(CHAIN_BREAK_FLAG)
        OR A
        JR NZ,CLEAR_RESET_STORAGE_3
        LD (FRETOP),HL
CLEAR_RESET_STORAGE_3:
        XOR A
        ; reset the DATA read pointer to the start of the program (RESTORE with no line)
        CALL STMT_RESTORE
        ; collapse arrays and strings: ARYTAB=STREND=VARTAB (empty variable/array space)
        LD HL,(VARTAB)
        LD (ARYTAB),HL
        LD (STREND),HL
        LD A,(CHAIN_PRESERVE_FLAG)
        OR A
        ; close all files unless CHAIN is preserving variables across the chained program
        CALL Z,CLOSE_ALL_FILES
        ; discard the caller's return address; the stack is about to be reset wholesale
        POP BC
        ; rebuild the stack: SAVSTK := stack base - 2, then fall in with HL = stack base (RESET_RUN_STATE does LD SP,HL)
        LD HL,(TOP_OF_STACK_ROOM)
        DEC HL
        DEC HL
        LD (SAVSTK),HL
        INC HL
        INC HL
; ----------------------------------------------------------------------
; RESET_RUN_STATE -- stack-reset / run-state init trampoline: install SP, empty the temp-string stack, clear DEF FN + print/eval run state, return the restart cursor
;   In:        HL = new stack top (TOP_OF_STACK_ROOM when reached from CLEAR_RESET_STORAGE; (SAVSTK) when entered from the error/print/unwind paths, e.g. ERROR_PRINT_SETUP). OPEN_RESUME_TEXT_PTR holds the text pointer to resume at.
;   Out:       SP reloaded; TEMPPT=TEMPST (temp-string descriptor stack empty); L_0CB6 cleared; a pending partial output line flushed; PRTFLG/PTRFIL reset (PRINT device back to console); the DEF FN runtime cells (DEFFN_DEPTH, DEFFN_ACTIVE_FLAG, DEFFN_FRAME_PTR, DEFFN_FRAME_SIZE, the current-arg cell L_0BFB) and PTRGET_SUBSCRIPT_FLAG zeroed; HL := OPEN_RESUME_TEXT_PTR; RET.
;   Clobbers:  AF, BC, DE, HL, SP.
;   Algorithm: LD SP,HL installs the stack. Point TEMPPT at TEMPST so the temporary-string-descriptor stack is empty. Clear L_0CB6 via CLEAR_EVAL_FLAG_0CB6 ([RE] this cell is dual-use -- an FRMEVL function-eval-in-progress flag AND a screen reverse/INVERSE flag, NOT reconciled in the source, so its exact meaning here is UNKNOWN). Call OUTDO_RESET_COL (clears PRTFLG and, if the output column is nonzero, flushes the pending line with a CRLF) and PRINT_RESET_STATE (clears PRTFLG and PTRFIL back to the console). Zero the DEF FN runtime cells: frame pointer DEFFN_FRAME_PTR, frame size DEFFN_FRAME_SIZE, depth counter DEFFN_DEPTH and its boolean shadow DEFFN_ACTIVE_FLAG, the current-arg cell L_0BFB, and PTRGET_SUBSCRIPT_FLAG. PUSH HL/BC (saved-state slots consumed by the resumed code), then fall into RESET_RUN_STATE_1 which loads HL=OPEN_RESUME_TEXT_PTR and returns. RESET_RUN_STATE_1 is a heavily shared tail (error print, SAVE, MERGE error, GET/PUT buffer-clear, protect-SAVE) that just reloads the restart cursor and returns.
; ----------------------------------------------------------------------
RESET_RUN_STATE:
        ; install the reset stack pointer (caller passed the new top in HL)
        LD SP,HL
        ; empty the temporary string-descriptor stack: TEMPPT := base
        LD HL,TEMPST
        LD (TEMPPT),HL
        CALL CLEAR_EVAL_FLAG_0CB6
        ; clear PRTFLG and flush any partial output line (CRLF if the column is nonzero); the next CALL resets the PRINT device to the console
        CALL OUTDO_RESET_COL
        CALL PRINT_RESET_STATE
        XOR A
        LD H,A
        LD L,A
        ; zero the DEF FN runtime cells (frame pointer/size, depth, current arg) and the subscript-context flag
        LD (DEFFN_FRAME_SIZE),HL
        LD (DEFFN_ACTIVE_FLAG),A
        LD (L_0BFB),HL
        LD (DEFFN_DEPTH),HL
        LD (DEFFN_FRAME_PTR),HL
        LD (PTRGET_SUBSCRIPT_FLAG),A
        PUSH HL
        PUSH BC
RESET_RUN_STATE_1:
        LD HL,(OPEN_RESUME_TEXT_PTR)
        RET
; ----------------------------------------------------------------------
; CMP_HL_DE -- unsigned 16-bit compare of HL against DE (MS BASIC's pervasive pointer compare).
;   In:        HL, DE = the two 16-bit values to compare.
;   Out:       Flags as if HL - DE: Z set iff HL==DE; carry set iff HL < DE (unsigned).
;              A holds the high-byte difference (H-D), or the low-byte difference (L-E) when the highs match.
;              HL and DE are unchanged.
;   Clobbers:  A, flags only.
;   Algorithm: A = H - D; if non-zero the result is settled by the high bytes and it returns (RET NZ).
;              If the high bytes are equal, A = L - E sets the final Z/carry. Called from many sites
;              (the .lst comment cites 68) to order pointers (text/variable/array/string-heap) without
;              disturbing the operands.
; ----------------------------------------------------------------------
CMP_HL_DE:
        LD A,H
        ; high bytes differ => result decided here (carry = HL<DE), return early
        SUB D
        RET NZ
        LD A,L
        ; high bytes equal: low-byte difference sets the final Z/carry
        SUB E
        RET

; ======================================================================
; CORE HELPERS (SYNCHR, FNDLIN, stack/mem checks)
; ======================================================================
; ----------------------------------------------------------------------
; SYNCHR -- verify the current program char matches the literal byte inlined after the CALL, then advance like CHRGET.
;   In:        HL -> current byte in the crunched program/text line. The expected character is
;              stored as a one-byte literal (DEFB) immediately after the CALL SYNCHR, so the
;              return address on the stack points AT that literal (CALL SYNCHR / DEFB <ch>).
;   Out:       On match: HL advanced one byte PAST the matched char; A = next significant char,
;              CHRGOT-classified (spaces skipped, C set iff digit, Z set at end-of-statement);
;              the stacked return address is bumped past the inline literal so execution resumes
;              after the DEFB. On mismatch: tail-jumps to RAISE_SYNTAX_ERROR (never returns).
;   Clobbers:  A, HL, flags. The stacked return address is rewritten (+1) in place.
;   Algorithm: Read the current text char (HL) into A, then EX (SP),HL to bring the inline
;              expected byte (via the return address) into HL; CP (HL) compares A against it.
;              On mismatch raise Syntax error. On match, INC HL steps the return address past
;              the literal, EX (SP),HL writes it back and restores HL = text pointer, INC HL
;              advances past the matched char, then re-classify the next char: RET NC directly
;              if it is >= ':' ($3A, a keyword/operator/letter/token), otherwise fall into
;              CHRGOT_1 to skip spaces / detect end-of-line. The engine-wide 'expect this exact
;              token here' primitive used after keywords (comma, ')', '=', etc.).
; ----------------------------------------------------------------------
SYNCHR:
        LD A,(HL)
        ; Reach the expected byte via the return address: top-of-stack now points at the inline DEFB after CALL SYNCHR.
        EX (SP),HL
        CP (HL)
        ; Text char does not match the expected literal -> Syntax error.
        JR NZ,SYNCHR_MISMATCH
        ; Step the saved return address past the inline literal so the caller resumes after the DEFB.
        INC HL
        ; Restore HL = text pointer (and write the bumped return address back to the stack).
        EX (SP),HL
        ; Advance past the matched char, then re-classify the next char like CHRGET (CHRGOT for < ':' ).
        INC HL
        LD A,(HL)
        CP $3A
        RET NC
        JP CHRGOT_1
SYNCHR_MISMATCH:
        JP RAISE_SYNTAX_ERROR
; ----------------------------------------------------------------------
; STMT_RESTORE -- RESTORE statement handler (token $8C): reset the READ/DATA scan pointer.
;   In:        HL -> text just past the RESTORE token; Z set if no line-number argument follows.
;              (Also called internally by the CLEAR/RUN storage reset with HL = scratch, Z forced.)
;   Out:       DATA_READ_PTR ($0B75, MS BASIC DATPTR) := one byte before the next DATA byte to read
;              -- start-of-program (RESTORE with no line) or the located line. HL restored (EX DE,HL
;              on exit). RET.
;   Clobbers:  AF, BC, DE, HL.
;   Algorithm: Save the caller's text pointer in DE. Default target = TXTTAB (start of program).
;              With a line-number argument, LINGET it and FNDLIN the line; 'Undefined line' if not
;              found, else target = that line's BASLINE node. DEC the target so the next READ's
;              pre-increment lands on the first byte, store it in DATA_READ_PTR, restore HL, return.
;              STMT_READ reads (DATA_READ_PTR) to find where the next DATA item begins.
; ----------------------------------------------------------------------
STMT_RESTORE:
        EX DE,HL
        ; default DATA pointer target = start of program text (RESTORE with no line number)
        LD HL,(TXTTAB)
        JR Z,STMT_RESTORE_1
        EX DE,HL
        ; RESTORE <line>: parse the line number and locate that BASLINE node (FNDLIN)
        CALL LINGET
        PUSH HL
        CALL FNDLIN
        LD H,B
        LD L,C
        POP DE
        ; the requested RESTORE target line does not exist -> Undefined line
        JP NC,ERROR_UL
; ----------------------------------------------------------------------
; STMT_RESTORE_1 / STMT_RESTORE_2 -- common DATA-pointer store tail.
;   In:        HL -> the chosen target (start-of-program or a located BASLINE node).
;   Out:       DATA_READ_PTR := HL-1; HL restored to the caller's text pointer (EX DE,HL). RET.
;   Clobbers:  HL (then restored), DE.
;   Algorithm: Step the target back one byte (so the next READ's CHRGET pre-increment lands on the
;              first program/DATA byte), store it into DATA_READ_PTR, swap the saved caller pointer
;              back into HL, and return. STMT_RESTORE_2 is the store-only entry used when the target
;              is already adjusted (e.g. the STMT_READ rewind path jumps here).
; ----------------------------------------------------------------------
STMT_RESTORE_1:
        ; back up one byte so the next READ's pre-increment lands on the first DATA byte
        DEC HL
STMT_RESTORE_2:
        ; commit the new DATA read pointer (STMT_READ resumes scanning from here)
        LD (DATA_READ_PTR),HL
        EX DE,HL
        RET
; ----------------------------------------------------------------------
; STMT_STOP -- STOP statement handler (token $90): break to direct mode with a 'Break' message.
;   In:        A = the statement-terminator result from CHRGOT (Z = STOP stands alone); HL -> text
;              just past the STOP token.
;   Out:       A := 1 (the 'print Break message' selector); transfers to STMT_END_1 to perform the
;              halt-to-direct-mode sequence. Does not return to the program.
;   Clobbers:  AF.
;   Algorithm: STOP must stand alone: 'RET NZ' bails (returning to the dispatcher to raise Syntax
;              error) if any argument follows. Otherwise A is 0 here, so INC A makes A=1 (the flag
;              RESUME_AT_DIRECT later tests, NZ -> print 'Break'); JP STMT_END_1 shares END's
;              break-to-direct-mode tail.
; ----------------------------------------------------------------------
STMT_STOP:
        ; STOP takes no argument: anything trailing is a syntax error (return to dispatcher)
        RET NZ
        ; A := 1 selects the 'Break' message path in RESUME_AT_DIRECT (END leaves A=0 = silent)
        INC A
        JP STMT_END_1

; ======================================================================
; BASIC-80 statement dispatch handlers (table base $0108, indexed by (token-$81)*2)
; ======================================================================
; ----------------------------------------------------------------------
; STMT_END -- END statement handler (token $81): close files and halt the program to direct mode.
;   In:        A = the statement-terminator result from CHRGOT (Z = END stands alone); HL -> text
;              just past the END token. Reached via the GONE/NEWSTT statement dispatcher (table base
;              $0108, indexed (token-$81)*2).
;   Out:       All open files closed; interpreter returned to direct/command mode silently (A=0,
;              no 'Break' message). Does not return to the program.
;   Clobbers:  AF, BC, DE, HL.
;   Algorithm: END must stand alone ('RET NZ' on trailing junk). With A=0 (Z) close all files
;              (CALL Z,CLOSE_ALL_FILES, A preserved across via PUSH/POP AF) then fall into
;              STMT_END_1, which snapshots the resume pointers and drops to the Ok prompt without
;              printing 'Break'.
; ----------------------------------------------------------------------
STMT_END:
        ; END takes no argument: trailing text is a syntax error (return to dispatcher)
        RET NZ
        PUSH AF
        ; on the plain-END path (A=0) close every open file before halting
        CALL Z,CLOSE_ALL_FILES
        POP AF
; ----------------------------------------------------------------------
; STMT_END_1 / STMT_END_2 -- shared STOP/END halt-to-direct-mode tail.
;   In:        HL = current statement text pointer; A = break selector (0 = END/silent, nonzero =
;              STOP/'Break'). Entered by STOP (after INC A) and END; STMT_END_2+1 is also entered
;              from the three input-abort sites (Ctrl-C during INPUT/RANDOMIZE) where it forces A=$FF.
;   Out:       OLDTXT := current statement pointer (so CONT can later resume here); the temp-string
;              descriptor stack reset (TEMPPT := TEMPST); control falls into RESUME_AT_DIRECT, which
;              (when SAVTXT is not $FFFF) copies SAVTXT->SAVED_ERR_TXTPTR and OLDTXT->CONT_TXTPTR and
;              returns to the Ok/Break prompt.
;   Clobbers:  AF, BC, DE, HL.
;   Algorithm: Record the current statement pointer in OLDTXT (CONT's resume anchor) and reset the
;              temporary string-descriptor stack pointer (TEMPPT := TEMPST). STMT_END_2 then falls
;              into RESUME_AT_DIRECT.
;   [RE] STMT_END_2 is a coded-overlap dual entry: the bytes 21 F6 FF read as 'LD HL,$FFF6' on the
;              fall-through path (the $FFF6 value is dead -- RESUME_AT_DIRECT reloads HL from SAVTXT --
;              so this only absorbs the F6 FF bytes with A preserved). The +1 entry (input-abort
;              sites) runs F6 FF as OR $FF, flagging A=$FF (break).
; ----------------------------------------------------------------------
STMT_END_1:
        ; remember where execution stopped so CONT can pick up here
        LD (OLDTXT),HL
        ; reset the temporary string-descriptor stack (discard any pending intermediate strings)
        LD HL,TEMPST
        LD (TEMPPT),HL
; [RE] Dual entry. Fall-through (END/stop tail from STMT_END_1) runs LD HL,$FFF6 whose value is dead (RESUME_AT_DIRECT at $6969 reloads HL from SAVTXT); its only job is to eat the F6 FF bytes so A is preserved. The three JP C,STMT_END_2+1 sites (after INLIN returns carry = input aborted) enter +1 so F6 FF runs as OR $FF, flagging the break in A=$FF. Both merge at $6968 POP BC.
STMT_END_2:
        LD HL,$FFF6
        POP BC
; [RE] Return to direct/command mode after a statement or error: snapshot SAVTXT ($0844), save the RESUME/CONT pointers, clear the Ctrl-O suppress flag ($083F), reset the output column and emit a pending CRLF, then dispatch to the error-resume path or the 'Ok' ready prompt.
RESUME_AT_DIRECT:
        LD HL,(SAVTXT)
        PUSH HL
        PUSH AF
        LD A,L
        AND H
        INC A
        JR Z,RESUME_AT_DIRECT_1
        LD (SAVED_ERR_TXTPTR),HL
        LD HL,(OLDTXT)
        LD (CONT_TXTPTR),HL
RESUME_AT_DIRECT_1:
        XOR A
        LD (CTRL_O_SUPPRESS),A
        CALL OUTDO_RESET_COL
        CALL PRINT_CRLF_IF_COL
        POP AF
        LD HL,MSG_BREAK
        JP NZ,ERROR_RESUME_FROM_DIRECT
        JP READY_POP_FRAME
; ----------------------------------------------------------------------
; ECHO_CTRL_O -- echo a Ctrl-O as '^O' (caret notation); fixed-character entry into ECHO_CTRL_CHAR.
;   In:        none (the character is fixed at $0F).
;   Out:       '^O' followed by CR/LF written to the console.
;   Clobbers:  A, flags (plus whatever OUTCHR/CRLF clobber).
;   Algorithm: Load A = $0F (Ctrl-O) and fall into ECHO_CTRL_CHAR. Because $0F-$03 != 0, the Ctrl-C-only flag clearing in ECHO_CTRL_CHAR is skipped for Ctrl-O. Called by CONIN when the Ctrl-O output-suppress toggle (CTRL_O_SUPPRESS) flips, echoing the '^O' acknowledgement on BOTH transitions (suppression turning on and turning off).
; ----------------------------------------------------------------------
ECHO_CTRL_O:
        ; Ctrl-O character, then echo it via the shared caret-notation printer
        LD A,$0F
; ----------------------------------------------------------------------
; ECHO_CTRL_CHAR -- echo a control character as caret notation ('^' + letter) + CR/LF; on Ctrl-C also reset output flags.
;   In:        A = the control character (e.g. $03 Ctrl-C, $0F Ctrl-O, $15 Ctrl-U). Callers: INKEY_SCAN, INLIN (Ctrl-C/Ctrl-U), ECHO_CTRL_O.
;   Out:       '^' then (A+$40, the printable letter) then CR/LF on the console. On Ctrl-C ONLY, PRTFLG ($0838) and CTRL_O_SUPPRESS ($083F) are also cleared to 0. Returns with A=0/Z (tail JP CRLF -> RESET_PRINT_STATE).
;   Clobbers:  A, flags; on Ctrl-C also PRTFLG and CTRL_O_SUPPRESS (set to 0).
;   Algorithm: Save the char. Compute A-$03: if the char is Ctrl-C the difference is 0, and that 0 is stored into both PRTFLG and CTRL_O_SUPPRESS to cancel printer-output routing and Ctrl-O output suppression so the following Break message reaches the screen (the SUB doubles as both the Ctrl-C test and the zero value). Then print '^' ($5E), restore and print the char biased by $40 (turning a control code into its caret letter), and emit CR/LF.
;   [RE] The PRTFLG write here intersects the unresolved 'printer-select vs output-suppress' labelling conflict flagged at the PRTFLG cell definition (line 530). Storing 0 restores console output under either reading, so this is annotated rather than treated as settling the conflict.
; ----------------------------------------------------------------------
ECHO_CTRL_CHAR:
        PUSH AF
        ; Ctrl-C test: the difference is 0 iff the char is Ctrl-C, and that 0 doubles as the value stored below
        SUB $03
        JR NZ,ECHO_CTRL_CHAR_1
        ; Ctrl-C only: clear PRTFLG so output is no longer routed away from the console before the Break message
        LD (PRTFLG),A
        ; Ctrl-C only: also cancel Ctrl-O output suppression
        LD (CTRL_O_SUPPRESS),A
ECHO_CTRL_CHAR_1:
        ; print the caret '^'
        LD A,$5E
        CALL OUTCHR
        POP AF
        ; map the control code to its printable letter (Ctrl-C -> 'C') and echo it
        ADD A,$40
        CALL OUTCHR
        ; finish the caret echo with a newline (returns A=0/Z)
        JP CRLF
; ----------------------------------------------------------------------
; STMT_CONT -- CONT statement handler (token $98): resume a stopped program where it left off.
;   In:        CONT_TXTPTR holds the saved OLDTXT snapshot (set by STOP/END/error via
;              RESUME_AT_DIRECT); SAVED_ERR_TXTPTR holds the matching SAVTXT snapshot. HL is
;              irrelevant on entry.
;   Out:       SAVTXT := SAVED_ERR_TXTPTR and execution continues from the saved line (RET into the
;              run loop). Raises 'Can't continue' (err 17) if there is nothing to resume.
;   Clobbers:  AF, DE, HL.
;   Algorithm: Load CONT_TXTPTR purely as a presence sentinel -- if it is $0000 there is no stopped
;              program to continue ('Can't continue'). Otherwise restore the running program pointer
;              SAVTXT from SAVED_ERR_TXTPTR (the saved line pointer) so the next NEWSTT cycle
;              re-executes from the stopped line, and return. (CONT_TXTPTR's value itself is the
;              stopped statement pointer but is only tested for zero here.)
;   [RE] Note: the 'Can't continue' error lives here, not in PROGRAM_END (which raises 'No RESUME').
; ----------------------------------------------------------------------
STMT_CONT:
        ; load the resume sentinel; zero means nothing is stopped to continue
        LD HL,(CONT_TXTPTR)
        LD A,H
        OR L
        ; no resume point set -> 'Can't continue' (a program was edited, NEW'd, or never STOPped)
        LD DE,ERR_CANT_CONTINUE
        JP Z,RAISE_ERROR
        EX DE,HL
        LD HL,(SAVED_ERR_TXTPTR)
        ; restore the running program pointer (from SAVED_ERR_TXTPTR) so execution resumes at the stopped line
        LD (SAVTXT),HL
        EX DE,HL
        RET
; ----------------------------------------------------------------------
; STMT_TRACE -- TRON/TROFF statement handler (tokens $9F/$A0): toggle the execution-trace flag.
;   In:        Entry point selects the mode: STMT_TRACE (TRON, $0144) executes 'LD A,$AF';
;              STMT_TRACE+1 (TROFF $0146, and the CLEAR/program-start trace reset) lands on the $AF
;              byte which decodes as XOR A.
;   Out:       TRCFLG := $AF (trace on) or $00 (trace off). RET.
;   Clobbers:  AF.
;   Algorithm: Single coded-overlap tail. TRON sets A=$AF; TROFF / program start enters one byte
;              later so the $AF runs as XOR A (A=0). Both fall into 'LD (TRCFLG),A; RET'. NEWSTT
;              reads TRCFLG each line ($3393) and, when nonzero, prints '[<linenum>]' before
;              executing it.
;   [RE] The +1 (XOR A) entry is also reused by the CLEAR/RUN reset (CALL STMT_TRACE+1 at $687A) as
;              a one-shot 'turn trace off and return A=0' helper.
;   [RE] The internal token labels are TOK_TRACE ($9F) / TOK_NOTRACE ($A0); the user keywords are
;              TRON/TROFF.
; ----------------------------------------------------------------------
STMT_TRACE:
        ; TRON path: load the trace-on marker (the $AF byte doubles as XOR A for the TROFF +1 entry)
        LD A,$AF
        ; store the trace state ($AF on / $00 off); NEWSTT prints '[line]' per statement when nonzero
        LD (TRCFLG),A
        RET
; ----------------------------------------------------------------------
; STMT_SWAP -- SWAP statement handler (token $A1): exchange the values of two same-type variables in place.
;   In:        HL -> BASIC text after the SWAP token: "var1 , var2".
;   Out:       The two scalar/array-element values exchanged byte-for-byte; HL -> text after var2. RETs to the statement executor. Raises TYPE MISMATCH if the two variables differ in VALTYP, or Illegal function call if resolving var2 grew the array table (which would invalidate var1's saved address).
;   Clobbers:  AF,BC,DE,HL; SWAP_VALUE_TEMP (8-byte scratch).
;   Algorithm: PTRGET var1 -> its storage address in DE; copy its VALTYP-wide value into the SWAP_VALUE_TEMP scratch cell (FP_MOVE_TYPED). Snapshot ARYTAB, then PTRGET var2. Require the two types to match: FRMEVL_TEST_TYPE returns A=VALTYP-3 for each; B holds var1's value, A holds var2's; CP B / TYPE MISMATCH on mismatch. [RE] Re-read ARYTAB and compare it (CMP_HL_DE) to the snapshot: if PTRGET of var2 allocated a new array (ARYTAB moved), var1's saved address is now stale -> Illegal function call. Otherwise copy var2's value into var1's slot (FP_MOVE_TYPED), then copy the saved value out of SWAP_VALUE_TEMP into var2's slot, completing the exchange.
; ----------------------------------------------------------------------
STMT_SWAP:
        CALL PTRGET_1+1
        PUSH DE
        PUSH HL
        ; save var1's value (VALTYP bytes) into the SWAP scratch cell so it survives while var1's slot is overwritten
        LD HL,SWAP_VALUE_TEMP
        CALL FP_MOVE_TYPED
        ; snapshot the array-table top before resolving var2 (to detect a relocation)
        LD HL,(ARYTAB)
        EX (SP),HL
        CALL FRMEVL_TEST_TYPE
        PUSH AF
        CALL SYNCHR
        DEFB    ','                      ; inline char arg consumed by the preceding CALL
        CALL PTRGET_1+1
        POP BC
        CALL FRMEVL_TEST_TYPE
        ; the two variables must have the same type/width (FRMEVL_TEST_TYPE codes), else TYPE MISMATCH
        CP B
        JP NZ,RAISE_TYPE_MISMATCH
        EX (SP),HL
        EX DE,HL
        PUSH HL
        ; [RE] if PTRGET(var2) allocated a new array ARYTAB moved -> var1's saved address is stale -> Illegal function call
        LD HL,(ARYTAB)
        CALL CMP_HL_DE
        JP NZ,ERROR_FC
        POP DE
        POP HL
        EX (SP),HL
        PUSH DE
        ; copy var2's value into var1's slot
        CALL FP_MOVE_TYPED
        POP HL
        ; copy the saved var1 value out of scratch into var2's slot, finishing the swap
        LD DE,SWAP_VALUE_TEMP
        CALL FP_MOVE_TYPED
        POP HL
        RET
; ----------------------------------------------------------------------
; STMT_ERASE -- ERASE statement handler (token $A2): delete a dimensioned array and reclaim its block.
;   In:        HL -> BASIC text at the array name to erase (after the ERASE token, or after a ',' for the 2nd..Nth name).
;   Out:       The named array's ARRAYVAR record (descriptor header + dim list + data) removed; the array table above it slid down to close the hole; STREND lowered by the freed size. Loops on ',' for ERASE A,B,C. On the last name RETs to the statement executor (NEWSTT).
;   Clobbers:  AF,BC,DE,HL; STREND; PTRGET_SUBSCRIPT_FLAG.
;   Algorithm: Force array context (PTRGET_SUBSCRIPT_FLAG=1) and resolve the name through PTRGET_1+1. On the array path PTRGET returns BC -> the array's NDIMS byte (just past the descriptor's blklen word) and DE = AV_BLKLEN (the stored block length covering {ndims, dimsize[], data}). [RE] The descriptor BASE (the VALTYP byte) is recovered by stepping BC BACKWARD: 3 bytes over {ndims byte, blklen word}, then back through the variable-length packed name extension while each byte read has its high bit set (the name chars were stored with bit7 set; the NAMEXTLEN sentinel has bit7 clear and stops the walk), then 2 more over name1/name0 to land on the VALTYP byte. HL was set = BC (the NDIMS pointer) before the walk; HL = NDIMS_ptr + AV_BLKLEN = the next descriptor = this array's END. The bytes from END up to STREND are copied DOWN onto the descriptor base (closing the hole), and STREND is set to base + (STREND - END). If the next text char is ',', CHRGET past it and repeat; otherwise RET.
; ----------------------------------------------------------------------
STMT_ERASE:
        ; Force array (subscripted) context so PTRGET resolves an existing array and returns its block pointer + block length.
        LD A,$01
        LD (PTRGET_SUBSCRIPT_FLAG),A
        ; Resolve the array name on the array path: returns BC -> the NDIMS byte (just past the blklen word) and DE = AV_BLKLEN. [RE] The following JP NZ,ERROR_FC guards against a PTRGET failure return (Illegal function call).
        CALL PTRGET_1+1
        JP NZ,ERROR_FC
        PUSH HL
        LD (PTRGET_SUBSCRIPT_FLAG),A
        ; Copy the returned block pointer (BC) into HL; BC is then walked backward to find the descriptor base while HL stays at the NDIMS byte.
        LD H,B
        LD L,C
        ; Step BC back 3 bytes over the {NDIMS byte, blklen word} that precede the data area.
        DEC BC
        DEC BC
        DEC BC
STMT_ERASE_1:
        ; Walk backward through the packed name extension: name bytes carry bit7 set, so loop while the byte just read is negative; the bit7-clear NAMEXTLEN byte ends the walk.
        LD A,(BC)
        DEC BC
        OR A
        JP M,STMT_ERASE_1
        DEC BC
        DEC BC
        ; HL (= pointer to NDIMS) + AV_BLKLEN = first byte past this array's block, i.e. the next descriptor / this array's END.
        ADD HL,DE
        EX DE,HL
        ; Set up the slide: DE = array END (source), HL = STREND (top of the array table).
        LD HL,(STREND)
STMT_ERASE_2:
        CALL CMP_HL_DE
        LD A,(DE)
        LD (BC),A
        INC DE
        INC BC
        JR NZ,STMT_ERASE_2
        DEC BC
        LD H,B
        LD L,C
        ; New top of the array table = base + (STREND - END); the freed block is now reclaimed.
        LD (STREND),HL
        POP HL
        LD A,(HL)
        ; If the next char is ',', another array name follows (ERASE A,B): consume it and loop; otherwise the statement is done.
        CP $2C
        RET NZ
        CALL CHRGET
        JR STMT_ERASE
STMT_ERASE_3:
        POP AF
        POP HL
        RET
; ----------------------------------------------------------------------
; IS_LETTER -- test (HL): is the current source char an ASCII letter A-Z?
;   In:        HL -> character to test.
;   Out:       Carry CLEAR if (HL) is in $41..$5A (A-Z), Carry SET otherwise. A = (HL).
;   Clobbers:  A, F.
;   Algorithm: Load (HL) into A and fall into IS_LETTER_A. Used to validate the first character of a variable/identifier name. Callers treat carry-set as 'not a letter' (e.g. PTRGET_2: CALL IS_LETTER / JP C,RAISE_SYNTAX_ERROR).
; ----------------------------------------------------------------------
IS_LETTER:
        LD A,(HL)
; ----------------------------------------------------------------------
; IS_LETTER_A -- is the char already in A a letter A-Z?
;   In:        A = character to classify.
;   Out:       Carry CLEAR if A is in $41..$5A (A-Z), Carry SET otherwise. A unchanged.
;   Clobbers:  F.
;   Algorithm: CP $41 returns carry (RET C) for anything below 'A' -> carry set = not a letter. Otherwise CP $5B sets carry for 'A'..'Z' (< '[') and clears it for '[' and up; CCF inverts that, so the FINAL carry is CLEAR for a letter and SET for a non-letter. (The file already documents this polarity at the CRUNCH name-scan: 'carry CLEAR for a letter A-Z and SET for a non-letter'.) Shared by PTRGET, DEFxxx, CRUNCH and the identifier tests.
; ----------------------------------------------------------------------
IS_LETTER_A:
        CP $41
        RET C
        CP $5B
        CCF
        RET
; ----------------------------------------------------------------------
; STMT_CLEAR -- CLEAR statement handler (token $92): clear all variables and optionally relocate the top-of-memory limits.
;   In:        HL -> BASIC text after CLEAR; A = first char (Z if end-of-statement). Grammar accepted: CLEAR [n] [, [m]] [, ...].
;   Out:       All variables/arrays/strings cleared (via CLEAR_RESET_STORAGE). If a memory argument is supplied, TOP_OF_STACK_ROOM and MEMSIZ are recomputed and committed; the string heap is re-seeded by the reset that follows.
;   Clobbers:  AF,BC,DE,HL; MEMSIZ; TOP_OF_STACK_ROOM; plus everything CLEAR_RESET_STORAGE touches.
;   Algorithm: Bare CLEAR (end of statement) jumps straight to CLEAR_RESET_STORAGE. [RE] The first numeric field n is parsed by GETINT_POSITIVE only to validate it as a non-negative integer -- its VALUE is then DISCARDED (lines $6A60-$6A64 overwrite HL=n with TOP_OF_STACK_ROOM). After the comma the code evaluates the memory argument m (FRMEVL_NOPAREN + GETADR, rejecting 0) into DE; if absent it defaults to the current TOP_OF_STACK_ROOM. [RE] STMT_CLEAR_4 (no explicit memory arg) derives DE = TOP_OF_STACK_ROOM - MEMSIZ, i.e. the current stack-room size, to be preserved. STMT_CLEAR_3 then validates and commits: it requires that current stack-room size (DE) be > $004E (78); the candidate new MEMSIZ = m - stack-room-size (SUB_HL_DE) must not borrow; and it must sit at least VARTAB+$14 above the variables. Any failure raises 'Out of memory' (STACK_OVERFLOW_RAISE). On success it stores MEMSIZ = m - stack-room-size and TOP_OF_STACK_ROOM = m, then falls into CLEAR_RESET_STORAGE. [RE] Cell roles: MEMSIZ is the top of the variable/string region and is set BELOW the stack; TOP_OF_STACK_ROOM (STKTOP) is the higher pointer set to the requested m. UNKNOWN: the precise meaning intended for a third comma-separated field (parsed by the second GETINT_POSITIVE) is not fully traced here.
;   Note: the two 'CALL SYNCHR / DEFB ,' pairs use the inline-argument SYNCHR idiom -- SYNCHR consumes the ',' byte placed in-line after the CALL as its expected char.
; ----------------------------------------------------------------------
STMT_CLEAR:
        ; Bare CLEAR with no arguments: just reset all variable/array/string storage and return.
        JP Z,CLEAR_RESET_STORAGE
        CP $2C
        JR Z,STMT_CLEAR_1
        ; [RE] Parse the first numeric field as a non-negative integer; its value is validated but then discarded (HL is overwritten just below).
        CALL GETINT_POSITIVE
        DEC HL
        CALL CHRGET
        JP Z,CLEAR_RESET_STORAGE
STMT_CLEAR_1:
        ; Require a ',' before the memory argument (inline-arg SYNCHR: the DEFB ',' below is its expected char).
        CALL SYNCHR
        DEFB    ','                      ; inline char arg consumed by the preceding CALL
        JP Z,CLEAR_RESET_STORAGE
        EX DE,HL
        ; Default the memory argument to the current TOP_OF_STACK_ROOM; an explicit 'm' overrides it below.
        LD HL,(TOP_OF_STACK_ROOM)
        EX DE,HL
        CP $2C
        JR Z,STMT_CLEAR_2
        ; Evaluate the memory argument m (requested new top-of-stack-room address).
        CALL FRMEVL_NOPAREN
        PUSH HL
        ; Convert m to a 16-bit address; reject 0 as an Illegal function call.
        CALL GETADR
        LD A,H
        OR L
        JP Z,ERROR_FC
        EX DE,HL
        POP HL
STMT_CLEAR_2:
        DEC HL
        CALL CHRGET
        PUSH DE
        JR Z,STMT_CLEAR_4
        CALL SYNCHR
        DEFB    ','                      ; inline char arg consumed by the preceding CALL
        JR Z,STMT_CLEAR_4
        CALL GETINT_POSITIVE
        DEC HL
        CALL CHRGET
        JP NZ,RAISE_SYNTAX_ERROR
STMT_CLEAR_3:
        EX (SP),HL
        PUSH HL
        ; [RE] Compared against DE (the current stack-room size). Require that size to exceed $004E (78 bytes), else Out of memory.
        LD HL,$004E
        CALL CMP_HL_DE
        JP NC,STACK_OVERFLOW_RAISE
        POP HL
        ; [RE] DE = m - stack-room-size = candidate new MEMSIZ; a borrow (carry) means m is too small -> Out of memory.
        CALL SUB_HL_DE
        JP C,STACK_OVERFLOW_RAISE
        PUSH HL
        ; Require the candidate MEMSIZ to sit at least VARTAB+$14 above the variables, leaving working headroom.
        LD HL,(VARTAB)
        LD BC,$0014
        ADD HL,BC
        CALL CMP_HL_DE
        JP NC,STACK_OVERFLOW_RAISE
        EX DE,HL
        ; [RE] Commit MEMSIZ = m - stack-room-size (top of the variable/string region, below the stack); the string heap top is re-seeded from MEMSIZ by the reset that follows.
        LD (MEMSIZ),HL
        POP HL
        ; [RE] Commit TOP_OF_STACK_ROOM = m (the requested high address), then fall into the full storage reset.
        LD (TOP_OF_STACK_ROOM),HL
        POP HL
        JP CLEAR_RESET_STORAGE
STMT_CLEAR_4:
        PUSH HL
        ; [RE] No explicit memory arg given: derive the stack-room size to preserve as TOP_OF_STACK_ROOM - MEMSIZ.
        LD HL,(TOP_OF_STACK_ROOM)
        EX DE,HL
        LD HL,(MEMSIZ)
        LD A,E
        SUB L
        LD E,A
        LD A,D
        SBC A,H
        LD D,A
        POP HL
        JR STMT_CLEAR_3
; ----------------------------------------------------------------------
; SUB_HL_DE -- 16-bit subtract DE = HL - DE.
;   In:        HL = minuend, DE = subtrahend.
;   Out:       DE = HL - DE; carry = borrow out (set if HL < DE). HL unchanged.
;   Clobbers:  A, DE, F.
;   Algorithm: Byte-wise subtract low (LD A,L / SUB E -> E) then high with borrow (LD A,H / SBC A,D -> D). CLEAR uses it (and the resulting borrow) to size and range-check the memory region.
; ----------------------------------------------------------------------
SUB_HL_DE:
        LD A,L
        SUB E
        LD E,A
        LD A,H
        SBC A,D
        LD D,A
        RET
; ----------------------------------------------------------------------
; STMT_NEXT -- NEXT statement handler (token $83): close/advance the current FOR loop (NEXT-entry of the shared FOR/NEXT body).
;   In:        HL -> BASIC text after the NEXT token; the entry flags carry Z set if end-of-statement (bare NEXT) or NZ if a loop-variable name follows ('NEXT i'), as left by the dispatcher's CHRGET.
;   Out:       Marks NEXT_ENTRY_FLAG nonzero (this is a NEXT statement, so STEP is applied), then falls into the shared NEXT body which applies STEP, compares against the limit, and either re-enters the loop or drops the frame and continues after the loop.
;   Clobbers:  AF (the entry flags are saved across the flag store via PUSH/POP AF); then everything the shared body clobbers.
;   Algorithm: PUSH AF to preserve the bare-vs-named entry flags across the flag store, then fall into STMT_NEXT_1. [RE] STMT_NEXT (entered at +0) runs its first opcode 'OR $AF' (A becomes nonzero) -> NEXT_ENTRY_FLAG = nonzero = 'NEXT statement'. The alternate entry STMT_NEXT_1+1 (the JP from STMT_FOR_5, the FOR zero-trip setup) lands on the $AF operand byte, which decodes as 'XOR A' -> NEXT_ENTRY_FLAG = 0 = 'FOR first pass'.
; ----------------------------------------------------------------------
STMT_NEXT:
        ; preserve the entry flags (bare NEXT = Z, 'NEXT i' = NZ) across the NEXT_ENTRY_FLAG store below; restored by POP AF and used to gate the loop-variable PTRGET
        PUSH AF
; ----------------------------------------------------------------------
; STMT_NEXT_1 -- coded dual-entry that records WHICH caller is running the shared FOR/NEXT body.
;   In:        Two distinct entry offsets, and the bare-vs-named entry flags preserved on the stack by STMT_NEXT. Entered AT STMT_NEXT_1 (from STMT_NEXT): the first opcode 'OR $AF' runs, forcing A nonzero. Entered AT STMT_NEXT_1+1 (JP from STMT_FOR_5, the FOR zero-trip setup): the $AF operand byte executes as 'XOR A', forcing A = 0. On entry the FOR frame for this loop is already on the stack.
;   Out:       NEXT_ENTRY_FLAG = A (nonzero = NEXT statement: apply STEP before the limit compare; zero = FOR first pass: skip STEP, just do the initial compare). AF restored to the bare-vs-named entry flags; DE := 0. Falls into the shared NEXT body (NEXT_LOOP_BODY).
;   Clobbers:  AF (restored), DE, NEXT_ENTRY_FLAG.
;   Algorithm: Store A into NEXT_ENTRY_FLAG (the STEP-or-not selector read later at NEXT_LOOP_BODY_1 / NEXT_LOOP_BODY_2), POP AF to restore the bare-vs-named flags (which gate the loop-variable PTRGET in the body), and set DE=0. [RE] DE=0 is the 'match the innermost FOR frame' marker consumed by the stack scan (STKFRAME_SCAN tests LD A,D/OR E and skips the variable-address compare when DE=0); for a named NEXT the body's PTRGET will overwrite DE with the loop variable's address before the scan. This is the classic byte-overlap idiom: opcode $F6 (OR n) vs its operand $AF (XOR A) select the flag value purely by entry offset.
; ----------------------------------------------------------------------
STMT_NEXT_1:
        ; [RE] coded overlap: entered here (STMT_NEXT_1) A becomes nonzero (NEXT statement); the FOR first-pass entry +1 runs this $AF byte as XOR A (flag 0)
        OR $AF
        ; record entry kind: nonzero = NEXT (apply STEP), zero = FOR's first pass (initial compare only)
        LD (NEXT_ENTRY_FLAG),A
        POP AF
        ; DE=0 = 'match the innermost FOR frame' marker for the stack scan; a named NEXT later overwrites DE with the loop variable's address via PTRGET
        LD DE,$0000
; [RE] Core of the NEXT statement: locate the matching FOR frame on the stack ($0CFD search), apply the STEP, compare against the limit, and either re-enter the loop (STMT_FOR_6) or fall through to loop exit; also handles 'NEXT var,var'.
NEXT_LOOP_BODY:
        LD (L_0C6A),HL
        CALL NZ,PTRGET_1+1
        LD (OPEN_RESUME_TEXT_PTR),HL
        CALL STKFRAME_SCAN_INIT
        JP NZ,RAISE_NEXT_WITHOUT_FOR
        LD SP,HL
        PUSH DE
        LD E,(HL)
        INC HL
        LD D,(HL)
        INC HL
        PUSH HL
        LD HL,(L_0C6A)
        CALL CMP_HL_DE
        JP NZ,RAISE_NEXT_WITHOUT_FOR
        POP HL
        POP DE
        PUSH DE
        LD A,(HL)
        PUSH AF
        INC HL
        PUSH DE
        LD A,(HL)
        INC HL
        OR A
        JP M,NEXT_LOOP_BODY_2
        CALL FP_STORE_REGS_LD
        EX (SP),HL
        PUSH HL
        LD A,(NEXT_ENTRY_FLAG)
        OR A
        JR NZ,NEXT_LOOP_BODY_1
        LD HL,FOR_NEXT_VALUE_TEMP
        CALL FP_STORE_REGS_LD
        XOR A
NEXT_LOOP_BODY_1:
        CALL NZ,FADD_FROM_MEM
        POP HL
        CALL FP_MOVE_TO_FAC
        POP HL
        CALL FP_LOAD_MEM
        PUSH HL
        CALL FCOMP
        JR NEXT_LOOP_BODY_5
NEXT_LOOP_BODY_2:
        INC HL
        INC HL
        INC HL
        INC HL
        LD C,(HL)
        INC HL
        LD B,(HL)
        INC HL
        EX (SP),HL
        LD E,(HL)
        INC HL
        LD D,(HL)
        PUSH HL
        LD L,C
        LD H,B
        LD A,(NEXT_ENTRY_FLAG)
        OR A
        JR NZ,NEXT_LOOP_BODY_3
        LD HL,(FOR_NEXT_VALUE_TEMP)
        JR NEXT_LOOP_BODY_4
NEXT_LOOP_BODY_3:
        CALL IADD
        LD A,(VALTYP)
        CP VT_SNG
        JP Z,RAISE_OVERFLOW
NEXT_LOOP_BODY_4:
        EX DE,HL
        POP HL
        LD (HL),D
        DEC HL
        LD (HL),E
        POP HL
        PUSH DE
        LD E,(HL)
        INC HL
        LD D,(HL)
        INC HL
        EX (SP),HL
        CALL INT16_COMP
NEXT_LOOP_BODY_5:
        POP HL
        POP BC
        SUB B
        CALL FP_LOAD_MEM
        JR Z,NEXT_LOOP_BODY_6
        EX DE,HL
        LD (SAVTXT),HL
        LD L,C
        LD H,B
        JP STMT_FOR_6
NEXT_LOOP_BODY_6:
        LD SP,HL
        LD (SAVSTK),HL
        LD HL,(OPEN_RESUME_TEXT_PTR)
        LD A,(HL)
        CP $2C
        JP NZ,STMT_FOR_7
        CALL CHRGET
        CALL NEXT_LOOP_BODY
NEXT_LOOP_BODY_7:
        CALL FRETMP
        LD A,(HL)
        INC HL
        LD C,(HL)
        INC HL
        LD B,(HL)
        POP DE
        PUSH BC
        PUSH AF
        CALL FRESTR1
        POP DE
        LD E,(HL)
        INC HL
        LD C,(HL)
        INC HL
        LD B,(HL)
        POP HL
NEXT_LOOP_BODY_8:
        LD A,E
        OR D
        RET Z
        LD A,D
        SUB $01
        RET C
        XOR A
        CP E
        INC A
        RET NC
        DEC D
        DEC E
        LD A,(BC)
        INC BC
        CP (HL)
        INC HL
        JR Z,NEXT_LOOP_BODY_8
        CCF
        JP FP_SIGN_3
; ----------------------------------------------------------------------
; FN_OCT_STR -- OCT$(x) intrinsic (function token $18): octal-text formatter.
;   In:        FAC = numeric value (HEX_OCT_OUT coerces it to a 16-bit UNSIGNED integer via GETADR).
;   Out:       FAC = a string TEMPORARY (VT_STR) holding the value's octal digits, no leading zeros; returns via the shared FN_STR_1 finalize tail.
;   Clobbers:  A, BC, DE, HL, flags; renderer scratch buffer $0CC2; string heap (GETSPA); temp-descriptor stack.
;   Algorithm: HEX_OCT_OUT renders the integer as octal ASCII (base flag B=0, six 3-bit groups) into the scratch buffer at $0CC2, NUL-terminated, and returns HL -> the buffer start. JR FN_STR_1 then turns that volatile text into an owned string temporary.
; ----------------------------------------------------------------------
FN_OCT_STR:
        ; render the FAC as octal text (B=0 selects the six 3-bit octal groups) into the $0CC2 scratch buffer; HL -> start
        CALL HEX_OCT_OUT
        ; hand the rendered text to the shared finalize tail to materialize it as a returnable string temporary
        JR FN_STR_1
; ----------------------------------------------------------------------
; FN_HEX_STR -- HEX$(x) intrinsic (function token $19): hexadecimal-text formatter.
;   In:        FAC = numeric value (the renderer coerces it to a 16-bit UNSIGNED integer via GETADR).
;   Out:       FAC = a string TEMPORARY (VT_STR) holding the value's hex digits ('0'..'9','A'..'F'), no leading zeros; returns via the shared FN_STR_1 finalize tail.
;   Clobbers:  A, BC, DE, HL, flags; renderer scratch buffer $0CC2; string heap (GETSPA); temp-descriptor stack.
;   Algorithm: Enter the shared HEX/OCT renderer one byte in, at HEX_OCT_OUT_1+1, so the operand bytes of the preceding 'JP NZ,$0106' ($C2 06 01) execute as LD B,$01, selecting the hex width (four 4-bit nibble groups). The digits render into $0CC2 NUL-terminated with HL -> start, then JR FN_STR_1 materializes the owned string temporary.
; ----------------------------------------------------------------------
FN_HEX_STR:
        ; enter the renderer mid-instruction so the '06 01' operand bytes run as LD B,$01 (B!=0 selects hex, four 4-bit nibble groups); text -> $0CC2, HL -> start
        CALL HEX_OCT_OUT_1+1
        ; hand the rendered text to the shared finalize tail to materialize it as a returnable string temporary
        JR FN_STR_1
; ----------------------------------------------------------------------
; FN_STR -- STR$(x) intrinsic (function token $12): decimal-text formatter (the PRINT representation of a number).
;   In:        FAC = numeric value; VALTYP = its type (int / single / double).
;   Out:       FAC = a string TEMPORARY (VT_STR) holding the value's ASCII decimal rendering, including the leading sign/space FOUT emits; returns via the shared FN_STR_1 finalize tail.
;   Clobbers:  A, BC, DE, HL, flags; FOUT scratch buffer $0CC3; string heap (GETSPA); temp-descriptor stack.
;   Algorithm: FOUT_2 formats the FAC as a plain PRINT/STR$ conversion (A=0, no PRINT-USING flags), leaving a NUL-terminated string in the $0CC3 buffer with HL -> its start. Fall straight into FN_STR_1 to copy that volatile text into owned heap and return it as a string value.
; ----------------------------------------------------------------------
FN_STR:
        ; format the number to its PRINT text (leading space-or-'-' sign + digits) in the $0CC3 buffer; HL -> start
        CALL FOUT_2
; ----------------------------------------------------------------------
; FN_STR_1 -- shared finalize tail for OCT$/HEX$/STR$: turn freshly rendered, volatile scratch-buffer text into an owned, returnable string temporary.
;   In:        HL -> a NUL-terminated character string in a renderer scratch buffer ($0CC2 for OCT$/HEX$, $0CC3 for STR$) -- the bytes are transient and would be overwritten by the next conversion.
;   Out:       Returns to its function's caller (FRMEVL) via the pushed STR_FN_RETURN_CHAR_1 continuation, with FAC = a VT_STR temporary whose data has been copied into permanent string heap and pushed onto the temp-descriptor stack. VALTYP := VT_STR.
;   Clobbers:  A, BC, DE, HL, flags; string heap (GETSPA); DSCTMP; temp-descriptor stack (TEMPPT).
;   Algorithm: SCAN_STR_LITERAL measures the scratch text to its NUL terminator, builds a STRDESC, and (falling through into PUT_STR_TEMP, no RET between them) stages it on the temp-descriptor stack, leaving FAC = the staged descriptor's slot address (a leftover internal PUSH HL from the scan absorbs PUT_STR_TEMP's POP HL, so control returns here to CALL FRESTR). FRESTR then loads that slot address from FAC into HL and pops the just-staged temp; because its data lives in the volatile $0CC2/$0CC3 scratch buffer (FRETOP != data_ptr-1), no heap is reclaimed, so HL -> the {LEN, scratch-PTR} STRDESC. Push STR_FN_RETURN_CHAR_1 as the return continuation and fall into STR_BUILD_FROM_DESC, which GETSPAs LEN heap bytes and copies the scratch text into them; on its RET, STR_FN_RETURN_CHAR_1 (POP BC / JP PUT_STR_TEMP) re-stages the now-permanent DSCTMP descriptor as the function's string result and returns to FRMEVL.
; ----------------------------------------------------------------------
FN_STR_1:
        ; measure the scratch text to its NUL and (via the fall-through into PUT_STR_TEMP) stage a temp descriptor for it; FAC := the staged descriptor's slot address
        CALL SCAN_STR_LITERAL
        ; pop that just-staged temp (HL := its STRDESC address from FAC); its data is in volatile scratch, not the heap (FRETOP != data_ptr-1), so nothing is reclaimed -- this only recovers HL -> {LEN, scratch-PTR}
        CALL FRESTR
        ; arrange STR_FN_RETURN_CHAR_1 (POP BC / JP PUT_STR_TEMP) to run on STR_BUILD_FROM_DESC's RET: it re-stages the owned DSCTMP descriptor as the result and returns to FRMEVL
        LD BC,STR_FN_RETURN_CHAR_1
        PUSH BC
; ----------------------------------------------------------------------
; STR_BUILD_FROM_DESC -- materialize a string into freshly owned heap: copy a source STRDESC's bytes into a new GETSPA-allocated block and record the result descriptor in DSCTMP.
;   In:        HL -> a source STRDESC (msbasic_strdesc.inc): LEN byte then a 2-byte data pointer, whose data may live in volatile/foreign space (renderer scratch buffer, program text, a buffer being reloaded).
;   Out:       New heap block (LEN bytes) holds a copy of the source bytes; DSCTMP ($0B45) holds the new {LEN, heap-PTR} descriptor; DE = DSCTMP address (the trailing POP DE recovers the HL=DSCTMP that STORE_STR_DESC returned and that was PUSHed before the copy). HL = source+LEN, BC = source-data-ptr+LEN (advanced by the copy).
;   Clobbers:  A, BC, DE, HL, flags; string heap (GETSPA lowers FRETOP); DSCTMP.
;   Algorithm: Read STRDESC.LEN into A and advance HL past it. GETSPA reserves LEN heap bytes (DE = new block start); the source-descriptor pointer is saved across that call (PUSH HL / POP HL) and the source data pointer is then read into BC (LD C,(HL) low, LD B,(HL) high). STORE_STR_DESC writes the result descriptor (LEN=A, PTR=DE -> the new block) into DSCTMP and returns HL -> DSCTMP, which is PUSHed. L:=A sets the byte count for BLOCK_COPY_BC_TO_DE, which then copies LEN bytes from the source (BC) into the new block (DE). The trailing POP DE restores DE = DSCTMP. [RE] Callers: string formatters (via FN_STR_1), DEF-FN string-result staging (STMT_DEF), the string-argument copy-to-safe-space path near POP_LEN_TO_B, and CHAIN string preservation (CHAIN_MOVE_STRING_VAR).
; ----------------------------------------------------------------------
STR_BUILD_FROM_DESC:
        LD A,(HL)
        INC HL
        PUSH HL
        ; reserve LEN (A) bytes of permanent string heap; DE = first byte of the new block
        CALL GETSPA
        POP HL
        LD C,(HL)
        INC HL
        LD B,(HL)
        ; record the result descriptor {LEN=A, PTR=DE->new block} in DSCTMP; HL := DSCTMP (pushed below, recovered into DE by the trailing POP)
        CALL STORE_STR_DESC
        PUSH HL
        ; set the copy count for BLOCK_COPY_BC_TO_DE (which counts down in L) to LEN bytes
        LD L,A
        ; copy LEN bytes of the source string (from BC) into the freshly owned heap block (DE)
        CALL BLOCK_COPY_BC_TO_DE
        POP DE
        RET
; [RE] Allocate a 1-byte string (A=1) then build its descriptor; convenience entry into the descriptor builder for single-char string results (e.g. CHR$, INKEY$).
ALLOC_STR_1:
        LD A,$01
; [RE] Allocate an A-byte string via GETSPA, then fall into STORE_STR_DESC to record length/pointer.
ALLOC_STR_A:
        CALL GETSPA
; [RE] Store a string descriptor (length A, body pointer DE) into the temporary descriptor cell $0B45..$0B47 and return HL pointing at it.
STORE_STR_DESC:
        LD HL,DSCTMP
; [RE] STR_DESC_STORE: write a STRDESC (see msbasic_strdesc.inc) at (HL) -- STRDESC.LEN=A, STRDESC.PTR=DE (low E at +1, high D at +2); preserves HL. The universal 3-byte string-value-descriptor writer (length byte then heap/text pointer word); used right after GETSPA reserves string space and by SCAN_STR_BODY when measuring a literal.
STR_DESC_STORE:
        PUSH HL
        LD (HL),A
        INC HL
        LD (HL),E
        INC HL
        LD (HL),D
        POP HL
        RET
; [RE] Scan a quoted/argument string starting before (HL): default terminator '"' ($22); measures length to the closing quote/NUL and forms a descriptor. PRINT/string-constant scanner (call sites in CRUNCH/FRMEVL/PRINT).
SCAN_STR_LITERAL:
        DEC HL
; [RE] Entry with B set to the open-quote terminator $22; sets D=B and scans the string body.
SCAN_STR_QUOTE:
        LD B,$22
; [RE] Entry with the terminator byte preset in B; copies to D and scans to that terminator or NUL.
SCAN_STR_TERM:
        LD D,B
; [RE] String-scan inner loop: walk (HL) counting chars in C until a NUL, the B-terminator or D-terminator; trims trailing spaces after a comma terminator and stores the resulting descriptor (length C).
SCAN_STR_BODY:
        PUSH HL
        LD C,$FF
SCAN_STR_BODY_1:
        INC HL
        LD A,(HL)
        INC C
        OR A
        JR Z,SCAN_STR_BODY_2
        CP D
        JR Z,SCAN_STR_BODY_2
        CP B
        JR NZ,SCAN_STR_BODY_1
SCAN_STR_BODY_2:
        CP $22
        CALL Z,CHRGET
        PUSH HL
        LD A,B
        CP $2C
        JR NZ,SCAN_STR_BODY_4
        INC C
SCAN_STR_BODY_3:
        DEC C
        JR Z,SCAN_STR_BODY_4
        DEC HL
        LD A,(HL)
        CP $20
        JR Z,SCAN_STR_BODY_3
SCAN_STR_BODY_4:
        POP HL
        EX (SP),HL
        INC HL
        EX DE,HL
        LD A,C
        CALL STORE_STR_DESC
; ----------------------------------------------------------------------
; PUT_STR_TEMP -- push the freshly-built string descriptor (DSCTMP) onto the fixed-size temporary-descriptor stack (TEMPST/TEMPPT).
;   In:        DSCTMP ($0B45) holds the STRDESC to record (LEN at $0B45, PTR word at $0B46). TEMPPT ($0B25) = live top of the temp-descriptor stack. Entered fall-through (or JP from string-function epilogues) with no extra pointer on the stack; entered via CALL PUT_STR_TEMP_1+1 (DEF-FN string path, $3FD8) which runs the D5 byte as PUSH DE first (see body note).
;   Out:       The 3-byte STRDESC is copied to the slot TEMPPT pointed at; TEMPPT advanced by VALTYP(=3); FAC ($0CB1) = the address of the slot just written (the staged temporary). VALTYP ($0B14) := VT_STR. Returns to the caller (fall-through path returns one stack level higher -- see body note) when room remained.
;   Clobbers:  A, DE, HL, VALTYP, FAC, TEMPPT; flags (from CMP_HL_DE).
;   Algorithm: Point DE at DSCTMP (source), mark the value as a string (VALTYP=VT_STR=3), capture the current TEMPPT into FAC as the destination slot, then FP_MOVE_TYPED copies VALTYP(=3) bytes DSCTMP->slot (DE=source, HL=dest), leaving HL = old TEMPPT + 3. Compare that new top against the FIXED address $0B48 -- the upper bound of the temp-descriptor-stack region (which is also the address of the FRETOP cell, used here only as a sentinel boundary, NOT its contents). Store the new top back as TEMPPT. The dual-entry D5 cover idiom (see body note) decides whether the trailing POP HL discards this routine's return address (fall-through) or recovers a caller-pushed pointer (DEF-FN path). RET NZ exits when the new top has not reached the boundary (Z flag carried from the CMP; the intervening LD A,(HL) does NOT set flags). If the new top equals $0B48 the fixed temp stack is full: raise 'String formula too complex' (ERR=16).
; ----------------------------------------------------------------------
PUT_STR_TEMP:
        LD DE,DSCTMP
; [RE] Two entries to the string-temp store. PUT_STR_TEMP (fall-through, and JP from $6E82) enters $6C1D LD A,$D5 (A dead) so no DE is pushed and the later POP HL ($6C36) takes the return address. CALL PUT_STR_TEMP_1+1 (from $3FD8, DEF-string) enters +1 so the D5 byte runs as PUSH DE, making that POP HL retrieve the descriptor pointer instead.
PUT_STR_TEMP_1:
        ; dual-entry cover byte: D5 = the opcode PUSH DE. Reached as LD A,$D5 (this label, A dead -- overwritten at LD A,VT_STR) the byte is swallowed and no DE is pushed, so the later POP HL discards this routine's own return address (the fall-through callers JP here and want the return to go one level up); reached one byte later (CALL PUT_STR_TEMP_1+1, DEF-FN string path) the D5 runs as PUSH DE so that POP HL instead recovers the caller's pushed pointer and the normal return address survives
        LD A,$D5
        ; record the live top of the temp-descriptor stack as the destination slot for this descriptor
        LD HL,(TEMPPT)
        LD (FAC),HL
        LD A,VT_STR
        LD (VALTYP),A
        ; copy VALTYP(=3) bytes of the STRDESC from DSCTMP (DE=source) up into the new slot (HL=dest); HL ends at old TEMPPT+3
        CALL FP_MOVE_TYPED
        LD DE,FRETOP
        ; [RE] overflow test: compare the new temp-stack top against the FIXED boundary $0B48 (DE was loaded with the ADDRESS, not contents -- this is the end of the small fixed temp-descriptor region, ~11 STRDESC slots from TEMPST $0B27). Equal means the temp stack is full
        CALL CMP_HL_DE
        LD (TEMPPT),HL
        POP HL
        LD A,(HL)
        RET NZ
        ; fixed temp-descriptor stack exhausted (too many nested string intermediates in one formula): raise 'String formula too complex' (ERR=16)
        LD DE,ERR_STRING_FORMULA_TOO_COMPLEX
        JP RAISE_ERROR
PUT_STR_TEMP_2:
        INC HL

; ======================================================================
; CONSOLE / I-O (OUTCHR, CONIN, STROUT, RPC bridge)
; ======================================================================
; ----------------------------------------------------------------------
; STROUT -- scan a pre-built, terminator-delimited string in memory and print it.
;   In:        HL = address of the FIRST character of the string to print (NOT one
;              byte before it; SCAN_STR_LITERAL's leading DEC HL only cancels its
;              inner loop's leading INC HL). The callers that reach STROUT load HL
;              with a direct pointer to NUL-terminated message data (e.g.
;              LD HL,MSG_UNDEFINED_LINE) -- this is a memory string scan, not a
;              CHRGET/CHRGTR scan of tokenized program text.
;   Out:       The string is emitted to the active output channel (OUTCHR). On
;              return D=0 and BC = string start + LEN (STRPRT's exit), since STROUT
;              runs straight on into STRPRT's body after the literal scan.
;   Clobbers:  A, B, C, D, E, H, L, flags; FAC, VALTYP, DSCTMP, TEMPPT, FRETOP,
;              OUTPUT_COLUMN/CURSOR_POS (whatever SCAN_STR_LITERAL, FRESTR, OUTCHR
;              and RESET_PRINT_STATE touch).
;   Algorithm: Front end for printing an in-memory string literal. SCAN_STR_LITERAL
;              measures the body up to its terminator -- which it FIXES internally to
;              '"' ($22) via LD B,$22 / LD D,B, so a caller-supplied B is ignored and
;              the NUL-terminated message strings actually terminate on $00 -- builds
;              a 3-byte STRDESC in DSCTMP, stages it on the temp-descriptor stack
;              (PUT_STR_TEMP sets VALTYP=VT_STR and FAC = the staged slot's address),
;              then continues into STRPRT to emit that staged string VALUE. Used for
;              the sign-on banner, error/'Break' messages, 'Undefined line ', the
;              RANDOMIZE/INPUT prompts, and FOUT-formatted number text.
;   [RE] note: STROUT is the historic 'print a memory string' entry; its quoted-
;              literal scanner is shared with FRMEVL/PRINT, but the bytes printed via
;              STROUT are pre-built message/number strings, not quoted constants read
;              out of the program image.
; ----------------------------------------------------------------------
STROUT:
        ; measure the in-memory string at (HL) (terminator fixed to '"'/NUL), build its STRDESC in DSCTMP, stage it as a temp with FAC = the slot address, then run on into STRPRT to emit it
        CALL SCAN_STR_LITERAL
; ----------------------------------------------------------------------
; STRPRT -- print the string VALUE whose descriptor address is in FAC.
;   In:        FAC ($0CB1) = address of the value's STRDESC (msbasic_strdesc.inc:
;              LEN byte at +0, little-endian data PTR at +1). Reached directly (not via
;              STROUT) by PRINT/LPRINT, the INPUT echo and the WRITE/PRINT-USING string
;              paths ($37C4/$3927/$65EF/$75B4/$75D6).
;   Out:       LEN characters of the string are sent to the active output channel via
;              OUTCHR; on return D=0 and BC = data pointer + LEN (one past the last
;              byte emitted). If the descriptor was the topmost heap allocation, FRESTR
;              has reclaimed its bytes (FRETOP raised). A zero-length string prints
;              nothing.
;   Clobbers:  A, B, C, D, E, H, L, flags; OUTPUT_COLUMN/CURSOR_POS via OUTCHR and the
;              CR reset; FRETOP/TEMPPT via FRESTR.
;   Algorithm: FRESTR loads HL=(FAC) -> the STRDESC address and frees the bytes iff it
;              is the most-recent temp (returns HL = descriptor address either way).
;              FP_LOAD_MEM3 reads the 3 descriptor bytes as D=STRDESC.LEN, C=PTR.lo,
;              B=PTR.hi, so D is the remaining-byte count and BC is the live data
;              pointer. STRPRT_1 emits D bytes from (BC) through OUTCHR; whenever the
;              byte just emitted is CR ($0D) it calls RESET_PRINT_STATE to clear the
;              print column / auto-line state. The leading INC D pairs with the loop's
;              opening DEC D / RET Z so a LEN of 0 exits immediately.
;   [RE] note: STRPRT does not itself read VALTYP; callers are responsible for the
;              value already being a string descriptor.
; ----------------------------------------------------------------------
STRPRT:
        ; resolve FAC -> HL = the value's STRDESC address (and reclaim its heap bytes if it is the topmost temporary string)
        CALL FRESTR
        ; load the descriptor: D = STRDESC.LEN (byte count), BC = STRDESC.PTR (the character-data pointer to walk)
        CALL FP_LOAD_MEM3
        ; pre-bias the count so the loop's opening DEC D / RET Z makes a zero-length string print nothing
        INC D
STRPRT_1:
        ; count down the remaining characters; return when all LEN bytes have been emitted
        DEC D
        RET Z
        ; fetch the next character of the string body from the data pointer
        LD A,(BC)
        CALL OUTCHR
        CP $0D
        ; an embedded carriage return ends a line, so clear the tracked print column / auto-line state
        CALL Z,RESET_PRINT_STATE
        INC BC
        JR STRPRT_1
; ----------------------------------------------------------------------
; GETSPA -- reserve A bytes at the top of the string heap, garbage-collecting and retrying once on exhaustion.
;   In:        A = number of heap bytes requested. FRETOP ($0B48) = current top-of-free string space; STREND ($0B73) = top of the variable/array area (the floor the heap may not cross).
;   Out:       On success: FRETOP lowered by A, DE = first byte of the newly reserved block (new FRETOP + 1), A restored to the saved request. On unrecoverable exhaustion (still no room after one GC): raises 'Out of string space' (ERR=14).
;   Clobbers:  A (restored from the saved copy on the success path), BC, DE, HL, FRETOP; flags.
;   Algorithm: Compute new = FRETOP - A as a two's-complement add: HL=FRETOP, B=$FF and C=~A (CPL of the request), then ADD HL,BC / INC HL gives HL = FRETOP - A. If that does NOT borrow below STREND, store it as the new FRETOP and hand back the block. If it does, GETSPA_3 forces Z (CP A), pushes the saved request+flags, pushes GETSPA_1+1 as GARBAG's return address, and falls into GARBAG to compact. GARBAG RETs into GETSPA_1+1, where the planted F1 byte runs as POP AF (popping the AF pushed in GETSPA_3, with Z still set), and the whole allocation is retried. On the retry, that preserved Z routes a second consecutive failure straight to the error (JP Z,RAISE_ERROR) instead of collecting again.
; ----------------------------------------------------------------------
GETSPA:
        OR A
; [RE] GC-retry tail. GETSPA falls into $6C59 LD C,$F1 (sentinel, C overwritten at $6C64) then PUSH AF and checks the heap. On exhaustion GETSPA_3 (after CP A) pushes GETSPA_1+1 ($6C5A) as GARBAG's return address; GARBAG RETs into +1 where the F1 byte runs as POP AF (undo the $6C7D saved-flags push) and the allocation is retried.
GETSPA_1:
        ; plant byte F1 = the opcode POP AF: on the GC retry GARBAG returns into GETSPA_1+1 (one byte past here) where this F1 executes as POP AF, popping the AF that GETSPA_3 pushed (CP A had set Z) so the allocation re-runs with Z preserved; on the first/normal entry the byte is the harmless LD C,$F1 (C is overwritten at LD C,A below)
        LD C,$F1
        PUSH AF
        LD HL,(STREND)
        EX DE,HL
        ; compute the prospective new heap top = FRETOP - A using the two's-complement (B=$FF, C=~A) ADD HL,BC / INC HL idiom that follows
        LD HL,(FRETOP)
        CPL
        LD C,A
        LD B,$FF
        ADD HL,BC
        INC HL
        ; heap-full test: would the new top borrow below STREND (the top of the variable/array area)?
        CALL CMP_HL_DE
        JR C,GETSPA_3
        ; room exists: commit the lowered FRETOP, then hand back the block's first byte (new FRETOP + 1) in DE
        LD (FRETOP),HL
        INC HL
        EX DE,HL
GETSPA_2:
        POP AF
        RET
GETSPA_3:
        POP AF
        ; exhausted; the Z flag set on the retry pass routes the second consecutive failure straight to 'Out of string space' (ERR=14)
        LD DE,ERR_OUT_OF_STRING_SPACE
        JP Z,RAISE_ERROR
        ; first failure: force Z so the post-GC retry can tell itself apart, then collect once
        CP A
        PUSH AF
        ; push GETSPA_1+1 as GARBAG's return address so the collector returns into the retry (where the planted F1 = POP AF restores the saved request+Z before re-trying)
        LD BC,GETSPA_1+1
        PUSH BC
; ----------------------------------------------------------------------
; GARBAG -- compact the string heap (MS BASIC-80 garbage collector): repeatedly find the live string with the HIGHEST start address still at or below the watermark and slide it up to FRETOP, lowering the watermark, until no live string remains below it.
;   In:        MEMSIZ ($0B23) = highest usable RAM; the live-string sources -- the temporary-descriptor stack (TEMPST..TEMPPT), the simple-variable table (VARTAB..ARYTAB), the DEF-FN saved-frame chain (FN_FRAME_LIST_HEAD->...), and the array table (ARYTAB..STREND).
;   Out:       FRETOP packed down so every live string sits contiguously just below the original MEMSIZ, with the now-vacated low end reclaimed as free space; descriptor PTR fields rewritten to the moved data. No registers returned meaningfully.
;   Clobbers:  A, BC, DE, HL, FRETOP, the scratch cells GC_SCAN_LIMIT/GC_FRAME_CURSOR/GC_ARRAY_ELEM_END; uses the stack for the running candidate record.
;   Algorithm: Set the watermark FRETOP=MEMSIZ and push a two-word candidate record (best-descriptor=0; best-PTR=STREND -- the lowest possible, so any live string beats it). Scan four sources -- temporaries, simple string variables, the DEF-FN saved-variable frames, and string arrays (with a per-element scan) -- handing every string descriptor to GARBAG_FIX_STR_PTR, which keeps the descriptor of the HIGHEST-addressed string still at-or-below FRETOP. After the scans, GARBAG_FIX_STR_PTR_1 slides that one string up against FRETOP, rewrites its descriptor, lowers FRETOP just below it, and JP GARBAG_1 to rescan. Exactly one string is relocated per full pass (strings pack from the top of memory downward), so the collector is O(n^2); it ends when a pass finds no live string below the watermark.
; ----------------------------------------------------------------------
GARBAG:
        LD HL,(MEMSIZ)
GARBAG_1:
        ; begin a pass: set the collection watermark FRETOP = MEMSIZ (top of usable RAM)
        LD (FRETOP),HL
        ; push the running candidate record for the highest live string below the watermark: slot1 = best descriptor address (none yet = 0); slot2 = best string PTR (initialized to STREND, the lowest possible, so the first eligible string wins), pushed next
        LD HL,$0000
        PUSH HL
        ; PHASE 3 -- scan the array table ARYTAB..STREND (string arrays get a per-element descriptor scan); when the walk reaches STREND every array is done, so finalize this pass via GARBAG_FIX_STR_PTR_1
        LD HL,(STREND)
        PUSH HL
        ; PHASE 1 -- scan the temporary-descriptor stack TEMPST..TEMPPT (intermediate string results)
        LD HL,TEMPST
GARBAG_2:
        EX DE,HL
        LD HL,(TEMPPT)
        EX DE,HL
        CALL CMP_HL_DE
        LD BC,GARBAG_2
        ; for each temp slot still below TEMPPT, fix its descriptor against the candidate (GARBAG_9 pushes the loop-back label then falls into GARBAG_FIX_STR_PTR)
        JP NZ,GARBAG_9
        LD HL,FN_FRAME_LIST_HEAD
        LD (GC_FRAME_CURSOR),HL
        LD HL,(ARYTAB)
        LD (GC_SCAN_LIMIT),HL
        ; PHASE 2 -- prime the simple-variable walk: scan limit = ARYTAB, frame cursor seeded to FN_FRAME_LIST_HEAD; walk VARTAB upward fixing every string variable's descriptor, then follow the DEF-FN saved-frame chain
        LD HL,(VARTAB)
; [RE] GC simple-variable walk over SIMPLEVAR records (VARTAB..ARYTAB, cmp to $0C62). Per entry: SV_VALTYP ($6CBA), skip 3-byte header ($6CBB-BD), VARTAB_SKIP_ENTRY consumes SV_NAMEXTLEN+namext ($6CBF) leaving HL at value; if VALTYP==3 (string) fix its descriptor (GARBAG_FIX_STR_PTR $6CC7) else add SV_VALTYP to step past the value ($6CCB-CE). Sequential walk.
GARBAG_3:
        EX DE,HL
        LD HL,(GC_SCAN_LIMIT)
        EX DE,HL
        CALL CMP_HL_DE
        JR Z,GARBAG_5
        LD A,(HL)
        INC HL
        INC HL
        INC HL
        PUSH AF
        CALL VARTAB_SKIP_ENTRY
        POP AF
        CP $03
        JR NZ,GARBAG_4
        CALL GARBAG_FIX_STR_PTR
        XOR A
GARBAG_4:
        LD E,A
        LD D,$00
        ADD HL,DE
        JR GARBAG_3
GARBAG_5:
        ; after the simple vars, follow the DEF-FN saved-frame chain: load the frame cursor and dereference its link word; a null link ends the frame phase, otherwise scan that frame's saved SIMPLEVAR block (limit = block end) via GARBAG_3
        LD HL,(GC_FRAME_CURSOR)
        LD A,(HL)
        INC HL
        LD H,(HL)
        LD L,A
        OR H
        EX DE,HL
        LD HL,(ARYTAB)
        JR Z,GARBAG_7
        EX DE,HL
        LD (GC_FRAME_CURSOR),HL
        INC HL
        INC HL
        LD E,(HL)
        INC HL
        LD D,(HL)
        INC HL
        EX DE,HL
        ADD HL,DE
        LD (GC_SCAN_LIMIT),HL
        EX DE,HL
        JR GARBAG_3
GARBAG_6:
        POP BC
; [RE] GC array-table walk over ARRAYVAR records (ARYTAB..STREND, cmp to $0B73). Per entry: read AV_VALTYP ($6CFD), skip the 3-byte header ($6D00-01 + the type byte already consumed) and the name via VARTAB_SKIP_ENTRY ($6D02), load AV_BLKLEN ($6D05-08) to find the next descriptor; only VALTYP==3 (string) arrays have their element descriptors scanned (loop GARBAG_8 $6D1A using AV_NDIMS at $6D14 to size the element block). Sequential, stored-stride.
GARBAG_7:
        EX DE,HL
        LD HL,(STREND)
        EX DE,HL
        CALL CMP_HL_DE
        JP Z,GARBAG_FIX_STR_PTR_1
        LD A,(HL)
        INC HL
        PUSH AF
        INC HL
        INC HL
        CALL VARTAB_SKIP_ENTRY
        LD C,(HL)
        INC HL
        LD B,(HL)
        INC HL
        POP AF
        PUSH HL
        ADD HL,BC
        CP $03
        JR NZ,GARBAG_6
        LD (GC_ARRAY_ELEM_END),HL
        POP HL
        LD C,(HL)
        LD B,$00
        ADD HL,BC
        ADD HL,BC
        INC HL
GARBAG_8:
        EX DE,HL
        LD HL,(GC_ARRAY_ELEM_END)
        EX DE,HL
        CALL CMP_HL_DE
        JR Z,GARBAG_7
        LD BC,GARBAG_8
GARBAG_9:
        PUSH BC
; ----------------------------------------------------------------------
; GARBAG_FIX_STR_PTR -- per-descriptor candidate test: if the string at (HL) is live, at or below the watermark, and HIGHER-addressed than the current best, make it the new compaction candidate.
;   In:        HL -> a STRDESC (LEN byte then 2-byte data PTR). FRETOP = current watermark. On the stack: the caller's loop-continuation address (pushed by GARBAG_9) above the running candidate record (best-descriptor, best-PTR).
;   Out:       HL advanced past the 3-byte descriptor. If this string is a better (higher-addressed, still <= FRETOP) candidate, the on-stack candidate record is overwritten with this descriptor's end-pointer and PTR. Returns to the loop-continuation either way.
;   Clobbers:  A, BC, DE, HL; rewrites the two candidate stack slots when it wins.
;   Algorithm: Read LEN (RET Z if zero -- empty string, ignore) and the data PTR into DE, stepping HL past all 3 bytes. Reject strings already above the watermark (FRETOP < PTR => already relocated this pass: RET C). Otherwise compare this PTR against the current best PTR held on the stack; if this one is NOT higher (best-PTR >= this-PTR) RET NC and keep the old candidate. If it is higher, drop the old candidate slots and re-push so the record now names THIS descriptor (its end-pointer and its PTR), then RET to the loop. Net effect across a full scan: the candidate ends up naming the live string with the LARGEST start address at or below FRETOP.
; ----------------------------------------------------------------------
GARBAG_FIX_STR_PTR:
        ; read the descriptor: A=LEN, DE=data PTR, HL stepped past all 3 bytes
        XOR A
        OR (HL)
        INC HL
        LD E,(HL)
        INC HL
        LD D,(HL)
        INC HL
        ; empty string (LEN==0): nothing in the heap to move, skip
        RET Z
        LD B,H
        LD C,L
        LD HL,(FRETOP)
        ; is this string already above the watermark (FRETOP < its PTR)? then it was relocated earlier this pass -- skip via the RET C below
        CALL CMP_HL_DE
        LD H,B
        LD L,C
        RET C
        POP HL
        EX (SP),HL
        ; compare this string's PTR against the current best candidate's PTR (held on the stack); keep the HIGHER-addressed one (the collector packs strings from the top down, one per pass)
        CALL CMP_HL_DE
        EX (SP),HL
        PUSH HL
        LD H,B
        LD L,C
        RET NC
        ; this string wins (higher-addressed than the prior best): discard the old candidate slots and re-push so the record now names this descriptor's end-pointer and its data PTR, then RET to the scan loop
        POP BC
        POP AF
        POP AF
        PUSH HL
        PUSH DE
        PUSH BC
        RET
; ----------------------------------------------------------------------
; GARBAG_FIX_STR_PTR_1 -- end-of-pass mover: slide the chosen HIGHEST live string up against FRETOP, fix its descriptor, lower FRETOP, and rescan.
;   In:        On the stack, the candidate record left by the scan: the best string's descriptor end-pointer (or 0 if none) and its data PTR. FRETOP = current watermark.
;   Out:       If a candidate exists: its bytes are block-copied up so its last byte sits at FRETOP, the descriptor's PTR is rewritten to the new location, FRETOP is lowered to just below the moved data, and control JP GARBAG_1 to start another pass. If no candidate (descriptor end-pointer 0): the heap is fully compacted, so RET (ends GARBAG).
;   Clobbers:  A, BC, DE, HL, FRETOP, the moved descriptor's PTR field.
;   Algorithm: Pop the candidate (DE=PTR, HL=descriptor end-pointer); RET Z if zero (no live string left below the watermark -> done). Otherwise read the descriptor's PTR (BC) and LEN, compute the source's top byte (PTR+LEN-1) and start (PTR), and run a descending block move (STR_COPY_DOWN_NOCHK) that copies LEN bytes UP so the string ends at FRETOP. Write the new PTR back into the descriptor, set FRETOP to one below the moved block's new base, and JP GARBAG_1 to rescan for the next-highest string.
; ----------------------------------------------------------------------
GARBAG_FIX_STR_PTR_1:
        ; retrieve the pass winner: DE = best string PTR, HL = end-pointer of its descriptor (0 if the scan found no live string below the watermark)
        POP DE
        POP HL
        LD A,L
        OR H
        ; no candidate left below FRETOP: the heap is fully packed, garbage collection is complete
        RET Z
        DEC HL
        LD B,(HL)
        DEC HL
        LD C,(HL)
        PUSH HL
        DEC HL
        LD L,(HL)
        LD H,$00
        ADD HL,BC
        LD D,B
        LD E,C
        DEC HL
        LD B,H
        LD C,L
        ; set up the descending block move: copy this string's bytes up so its last byte lands at FRETOP (source top in BC, source start in DE)
        LD HL,(FRETOP)
        CALL STR_COPY_DOWN_NOCHK
        POP HL
        ; rewrite the string's descriptor PTR to its new (higher) address
        LD (HL),C
        INC HL
        LD (HL),B
        LD L,C
        LD H,B
        DEC HL
        ; FRETOP now lowered to just below the freshly moved block; rescan from the top to relocate the next-highest live string (one per pass)
        JP GARBAG_1
; [RE] FRESTR/movestring helper: pull a string's descriptor (via FRMEVL_EVAL_OPERAND), free its data with FRESTR1, then copy the bytes into freshly-allocated string space (STR_COPY_DESCR_DATA block copies); returns through FRMEVL fixup.
STR_CONCAT:
        PUSH BC
        PUSH HL
        LD HL,(FAC)
        EX (SP),HL
        CALL FRMEVL_EVAL_OPERAND
        EX (SP),HL
        CALL REQUIRE_STRING
        LD A,(HL)
        PUSH HL
        LD HL,(FAC)
        PUSH HL
        ADD A,(HL)
        LD DE,ERR_STRING_TOO_LONG
        JP C,RAISE_ERROR
        CALL ALLOC_STR_A
        POP DE
        CALL FRESTR1
        EX (SP),HL
        CALL FRESTR_DE
        PUSH HL
        LD HL,(DSCTMP_PTR)
        EX DE,HL
        CALL STR_COPY_DESCR_DATA
        CALL STR_COPY_DESCR_DATA
        LD HL,FRMEVL_OPLOOP_1
        EX (SP),HL
        PUSH HL
        JP PUT_STR_TEMP
; [RE] copy one string-descriptor's data: pops the descriptor (len in A, addr in BC) off the caller's stack and block-copies len bytes from (BC) to (DE) via BLOCK_COPY_BC_TO_DE.
STR_COPY_DESCR_DATA:
        POP HL
        EX (SP),HL
        LD A,(HL)
        INC HL
        LD C,(HL)
        INC HL
        LD B,(HL)
        LD L,A
; ----------------------------------------------------------------------
; BLOCK_COPY_BC_TO_DE -- ascending copy of L bytes from (BC) to (DE).
;   In:        L = byte count (0..255), BC = source pointer, DE = destination pointer.
;   Out:       BC = source+count, DE = dest+count, L = 0, Z set, A = last byte copied (or unchanged if count 0).
;   Clobbers:  A, L, BC, DE, flags.
;   Algorithm: Use L as an 8-bit down-counter. The entry pre-increments L so the DEC L / RET Z test at
;              the loop top exits cleanly, including the zero-length case (L=0 -> INC L=1 -> DEC L=0 -> RET Z).
;              Each pass copies one byte (BC)->(DE) and advances both pointers. [RE] Both documented callers
;              (STR_BUILD_FROM_DESC, STR_COPY_DESCR_DATA) set L from A (the string length) just before the
;              call, so L == A there; the routine itself only reads L.
; ----------------------------------------------------------------------
BLOCK_COPY_BC_TO_DE:
        INC L
BLOCK_COPY_BC_TO_DE_1:
        ; count down; exit when all L bytes have been copied
        DEC L
        RET Z
        ; copy one byte from source to destination, both ascending
        LD A,(BC)
        LD (DE),A
        INC BC
        INC DE
        JR BLOCK_COPY_BC_TO_DE_1
; ----------------------------------------------------------------------
; FRETMP -- free the most-recent temporary string, validating it is a string first
;   In:        FAC ($0CB1) holds a string VALUE pointer (a STRDESC address); VALTYP ($0B14) set by the prior FRMEVL.
;   Out:       HL = the string's STRDESC address; if it was the topmost heap allocation, FRETOP ($0B48) is advanced past its bytes and the temp-descriptor stack (TEMPPT) is popped. Raises 'Type mismatch' if the value is not a string.
;   Clobbers:  A, B, C, D, E, H, L, F.
;   Algorithm: Assert the current value is a string (REQUIRE_STRING, which returns on a string VALTYP==3 and JPs to Type mismatch on any numeric), then fall straight into FRESTR to reclaim the temporary's heap space. The single-string-argument functions (LEN/ASC/VAL/CVx/RSET/file-name) call here to retire and locate their argument string in one step.
; ----------------------------------------------------------------------
FRETMP:
        ; require a string argument (Type mismatch otherwise), then fall into FRESTR to free it
        CALL REQUIRE_STRING
; ----------------------------------------------------------------------
; FRESTR -- free the string whose STRDESC pointer is currently in the FAC
;   In:        FAC ($0CB1) = address of the value's STRDESC (msbasic_strdesc.inc).
;   Out:       HL = the STRDESC address; FRETOP advanced and the temp stack popped iff this was the topmost heap string (see FRESTR1).
;   Clobbers:  A, B, C, D, E, H, L, F.
;   Algorithm: Load the descriptor address from the FAC into HL and fall into FRESTR_DE, which EX DE,HL into the form FRESTR1's reclaim test expects. Used wherever a string value already lives in the FAC (PRINT/STRPRT, FRE string arg, assignment fixups).
; ----------------------------------------------------------------------
FRESTR:
        ; take the string's descriptor address from the FAC, then free via the shared tail
        LD HL,(FAC)
; ----------------------------------------------------------------------
; FRESTR_DE -- FRESTR entry when the STRDESC address is already in HL
;   In:        HL = address of the string's STRDESC.
;   Out:       Same as FRESTR1 (heap reclaimed iff topmost allocation); HL = STRDESC address on return.
;   Clobbers:  A, B, C, D, E, H, L, F.
;   Algorithm: Swap the descriptor address into DE (where FREE_TOP_TEMP_DESCR's match test in FRESTR1 expects it) and fall into FRESTR1. This is the entry callers use when they already hold the descriptor pointer in HL and need not route through the FAC.
; ----------------------------------------------------------------------
FRESTR_DE:
        ; move the descriptor address into DE for the topmost-allocation test below
        EX DE,HL
; ----------------------------------------------------------------------
; FRESTR1 -- return a string's heap bytes only if it is the topmost (most recently allocated) string
;   In:        DE = address of the string's STRDESC (LEN at +0, data PTR at +1,+2).
;   Out:       HL = the STRDESC address. If the descriptor sits at the very top of the temp-descriptor stack AND its data lies at the bottom of allocated string space (FRETOP == data_ptr-1), FRETOP ($0B48) is bumped up by LEN, reclaiming the bytes in place; otherwise the heap is left untouched (those bytes become garbage GARBAG must later collect). When the descriptor is the top temp, TEMPPT is also popped (inside FREE_TOP_TEMP_DESCR).
;   Clobbers:  A, B, C, D, E, H, L, F.
;   Algorithm: Pop/test the temp-descriptor stack via FREE_TOP_TEMP_DESCR (returns BC = the top temp's stored data PTR, HL = TEMPPT-3 = the top temp's base, and Z iff DE == that base). EX DE,HL now puts the input descriptor address back in HL and TEMPPT-3 in DE. If DE was NOT the top temp (NZ) return immediately (HL = descriptor). Otherwise PUSH the matched base, set DE = data_ptr-1 (from BC), load C = STRDESC.LEN via (HL), and compare FRETOP against data_ptr-1: an exact match means this string sits immediately above FRETOP, so ADD its length to FRETOP. POP HL restores the descriptor address.
;   Algorithm-note: [RE] on the reclaim path HL is POPped from the matched temp base (TEMPPT-3), which equals the input descriptor address precisely because FREE_TOP_TEMP_DESCR only matched when TEMPPT-3 == descriptor; so HL = STRDESC address on both exits.
;   Algorithm-note: [RE] LD B,A after the equal compare relies on CMP_HL_DE leaving A = L-E = 0 on equality, so BC = (0,LEN) and ADD HL,BC advances FRETOP by exactly LEN.
; ----------------------------------------------------------------------
FRESTR1:
        ; test/pop the temp-descriptor stack; returns BC = the top temp's data pointer, HL = its base, NZ if our descriptor was not the top temp
        CALL FREE_TOP_TEMP_DESCR
        EX DE,HL
        RET NZ
        PUSH DE
        LD D,B
        LD E,C
        DEC DE
        LD C,(HL)
        ; reclaim only if the string sits at the bottom of the heap: FRETOP must equal data_ptr-1
        LD HL,(FRETOP)
        CALL CMP_HL_DE
        JR NZ,FRESTR1_1
        LD B,A
        ADD HL,BC
        LD (FRETOP),HL
FRESTR1_1:
        POP HL
        RET
; ----------------------------------------------------------------------
; FREE_TOP_TEMP_DESCR -- pop the most-recent temporary string descriptor off the TEMPPT stack if it matches
;   In:        DE = a candidate STRDESC address.
;   Out:       BC = the top temp descriptor's stored data PTR (its PTR-word bytes, read high-then-low into B then C). HL = TEMPPT-3 (the top descriptor's base). A = (TEMPPT-3) - DE high/low difference (0 on match). If DE equals that base (the top temp), TEMPPT ($0B25) is retracted by one STRDESC (3 bytes) and Z is set; otherwise TEMPPT is unchanged and NZ is returned.
;   Clobbers:  A, B, C, H, L, F. (D, E untouched.)
;   Algorithm: Load TEMPPT (points just past the live top descriptor), DEC and read the descriptor's PTR high byte into B, DEC and read PTR low into C, DEC to land HL on the descriptor base (TEMPPT-3 = the LEN byte). Compare HL against DE (CMP_HL_DE): on mismatch return NZ leaving the stack intact; on match write HL back to TEMPPT, popping the descriptor. Callers (FRESTR1, and LET's stack balancing at STMT_LET) use this both to free a temp and to retrieve its data pointer.
; ----------------------------------------------------------------------
FREE_TOP_TEMP_DESCR:
        ; walk back from the temp-stack top to read the descriptor's data pointer into BC and its base into HL
        LD HL,(TEMPPT)
        DEC HL
        LD B,(HL)
        DEC HL
        LD C,(HL)
        DEC HL
        CALL CMP_HL_DE
        RET NZ
        ; DE was the top temp: pop it by retracting TEMPPT one descriptor (3 bytes)
        LD (TEMPPT),HL
        RET
; ----------------------------------------------------------------------
; FN_LEN -- LEN(a$) intrinsic (FUNC_DISPATCH_TBL index 16, function token $11): length of a string into the FAC.
;   In:        The string argument has just been evaluated by the function dispatcher; its STRDESC pointer is in the FAC, VALTYP=VT_STR. FRMEVL_PAREN_2 is armed as this handler's return continuation.
;   Out:       FAC = the string's length (0..255) as a VT_INT value; the temporary argument string is freed (FRETMP).
;   Clobbers:  A, B, C, D, E, H, L, F, FAC, VALTYP.
;   Algorithm: Pre-push FP_LOAD_INT_TO_FAC as a return continuation, then fall into GET_STR_DESCR_PTR. That helper frees/locates the argument descriptor and returns with A = STRDESC.LEN; on its RET the pushed FP_LOAD_INT_TO_FAC runs with A=LEN and stores LEN as a 16-bit integer in the FAC (FP_LOAD_INT_TO_FAC zero-extends A into HL by itself). LEN accepts the empty string (length 0 is a valid result, so it does NOT FC-error, unlike ASC).
; ----------------------------------------------------------------------
FN_LEN:
        ; pre-push the "store A as a 16-bit integer in the FAC" continuation; GET_STR_DESCR_PTR returns A = string length and RETs straight into it
        LD BC,FP_LOAD_INT_TO_FAC
        PUSH BC
; ----------------------------------------------------------------------
; GET_STR_DESCR_PTR -- shared single-string-arg fetch: retire the argument string and locate its descriptor.
;   In:        FAC holds the just-evaluated argument's STRDESC pointer; VALTYP=VT_STR (asserted inside FRETMP via REQUIRE_STRING).
;   Out:       HL = address of the argument's STRDESC; A = STRDESC.LEN; D = 0; Z set iff the string is empty (LEN==0). The temporary's heap bytes are reclaimed if it was the topmost allocation.
;   Clobbers:  A, B, C, D, E, H, L, F.
;   Algorithm: FRETMP asserts the value is a string (Type mismatch otherwise) and frees/locates it, returning HL = its STRDESC. XOR A then LD D,A sets D=0; [RE] D=0 is NOT consumed here -- it is carried out for the FN_VAL caller, which writes it (LD (HL),D) as a NUL terminator at the end of the string before FIN parsing. Then LD A=STRDESC.LEN (byte at HL) and OR A sets Z when the length is zero. Shared by LEN (fall-through from FN_LEN), ASC (via FN_VAL_BODY) and FN_VAL.
; ----------------------------------------------------------------------
GET_STR_DESCR_PTR:
        ; free and locate the argument string: HL -> its STRDESC (Type mismatch if the value is not a string)
        CALL FRETMP
        XOR A
        ; D=0 (from the preceding XOR A): carried out as the NUL terminator that the FN_VAL caller stores past the string before FIN parsing
        LD D,A
        ; A = STRDESC.LEN; the following OR A sets Z iff the string is empty
        LD A,(HL)
        OR A
        RET
; ----------------------------------------------------------------------
; FN_ASC -- ASC(a$) intrinsic (FUNC_DISPATCH_TBL index 19, function token $14): character code of the string's first byte into the FAC.
;   In:        The string argument is evaluated; its STRDESC pointer is in the FAC, VALTYP=VT_STR. FRMEVL_PAREN_2 is armed as the handler's return continuation.
;   Out:       FAC = code of the first character (0..255) as a VT_INT value; the argument temporary is freed. Raises 'Illegal function call' (FC) if the string is empty.
;   Clobbers:  A, B, C, D, E, H, L, F, FAC, VALTYP.
;   Algorithm: Pre-push FP_LOAD_INT_TO_FAC as a return continuation, then fall into FN_VAL_BODY which (via GET_STR_DESCR_PTR) FC-errors on the empty string and otherwise returns A = the first character byte. On FN_VAL_BODY's RET the pushed continuation stores A as a 16-bit integer in the FAC.
; ----------------------------------------------------------------------
FN_ASC:
        ; pre-push the integer-to-FAC continuation; FN_VAL_BODY returns A = the first character code, which RETs into it
        LD BC,FP_LOAD_INT_TO_FAC
        PUSH BC
; ----------------------------------------------------------------------
; FN_VAL_BODY -- fetch a string argument's descriptor and read its FIRST character (the ASC body; NOT the VAL body).
;   In:        FAC holds the argument's STRDESC pointer (VALTYP=VT_STR).
;   Out:       A = the string's first character byte; DE = STRDESC.PTR (address of the character data); HL = descriptor+2; the argument temporary is freed. Raises FC if the string is empty.
;   Clobbers:  A, B, C, D, E, H, L, F.
;   Algorithm: GET_STR_DESCR_PTR frees/locates the descriptor and returns A=STRDESC.LEN with Z iff empty; an empty string is an FC error. Otherwise step HL across the LEN byte and read STRDESC.PTR into DE (E=low at +1, D=high at +2), then LD A,(DE) to fetch the first data byte. [RE] Reused TWO ways: ASC (fall-through from FN_ASC) and FN_STRING_FROM_STR (the fill character for STRING$). FN_VAL does NOT call this -- it calls GET_STR_DESCR_PTR directly and inlines a different descriptor walk (loading STRDESC.PTR into HL, not DE), so despite the name this is not VAL's body.
; ----------------------------------------------------------------------
FN_VAL_BODY:
        CALL GET_STR_DESCR_PTR
        ; empty string has no first character -> Illegal function call
        JP Z,ERROR_FC
        ; step past STRDESC.LEN to STRDESC.PTR and load the data pointer into DE (E=low, D=high)
        INC HL
        LD E,(HL)
        INC HL
        LD D,(HL)
        ; A = the string's first character byte
        LD A,(DE)
        RET
; ----------------------------------------------------------------------
; FN_CHR -- CHR$(n) intrinsic (FUNC_DISPATCH_TBL index 20, function token $15): build a one-byte string holding character n.
;   In:        The numeric argument is evaluated into the FAC. The handler was reached via FRMEVL_FUNC_DISPATCH with FRMEVL_PAREN_2 armed and the saved text pointer parked beneath it on the stack.
;   Out:       A new 1-byte string temporary is pushed on the temp-descriptor stack and made the current value (VALTYP=VT_STR); control returns to the FRMEVL operand-eval caller via PUT_STR_TEMP (HL = text pointer recovered there).
;   Clobbers:  A, B, C, D, E, H, L, F, FAC, VALTYP, DSCTMP, the string heap, TEMPPT.
;   Algorithm: ALLOC_STR_1 reserves one byte of heap and records its descriptor in DSCTMP (DSCTMP.PTR = the new byte's address). CONINT narrows the FAC to a single byte (FC on overflow), returning the character code in A=E. Fall into STR_FN_RETURN_CHAR, which writes E into the allocated byte and stages the temporary via PUT_STR_TEMP.
; ----------------------------------------------------------------------
FN_CHR:
        ; reserve one heap byte and record its descriptor in DSCTMP (DSCTMP.PTR -> the new byte)
        CALL ALLOC_STR_1
        ; narrow the FAC argument to a byte 0..255 (FC on overflow); E = the character code
        CALL CONINT
; ----------------------------------------------------------------------
; STR_FN_RETURN_CHAR -- single-char string-result epilogue: deposit one character into the freshly allocated buffer and stage the temporary.
;   In:        DSCTMP describes a 1-byte string just allocated (DSCTMP.PTR = its data address); E = the character to store. The stack holds (top-down) a word that POP BC will discard and then the saved text pointer that PUT_STR_TEMP recovers. [RE]
;   Out:       The character is written to the allocated byte; the descriptor is pushed onto the temp-descriptor stack and becomes the current string value; control returns to the FRMEVL operand-eval caller via PUT_STR_TEMP, with HL = the recovered text pointer. [RE]
;   Clobbers:  A, B, C, D, E, H, L, F, FAC, VALTYP, TEMPPT.
;   Algorithm: Load HL = DSCTMP.PTR (data pointer of the just-built descriptor) and store the character E there, then fall into STR_FN_RETURN_CHAR_1. Used by CHR$ and reached from the STRING$/SPACE$ fill helper (STR_FILL_ALLOC) when the count is zero.
; ----------------------------------------------------------------------
STR_FN_RETURN_CHAR:
        ; HL = DSCTMP.PTR (the new string's data address); store the result character there
        LD HL,(DSCTMP_PTR)
        LD (HL),E
; ----------------------------------------------------------------------
; STR_FN_RETURN_CHAR_1 -- string-result hand-off: drop one stacked word and stage the built descriptor.
;   In:        DSCTMP holds the completed result STRDESC. The stack holds (top-down) one word to discard, then the saved program text pointer, then the FRMEVL operand-eval return address. The word discarded differs by entry: for the FUNC_DISPATCH_TBL string builders (CHR$/STR$/HEX$/OCT$/MKx$) it is the armed FRMEVL_PAREN_2 continuation; for STRING$/SPACE$ it is STR_FILL_ALLOC's own CALL return. [RE]
;   Out:       Tail-jumps to PUT_STR_TEMP, which copies DSCTMP onto the temp-descriptor stack, sets VALTYP=VT_STR and FAC = the staged slot, then its own POP HL recovers the saved text pointer and RETs to the FRMEVL operand-eval caller. Net effect: control returns one level higher than a plain RET would, with HL = text pointer.
;   Clobbers:  A, B, C, D, E, H, L, F, FAC, VALTYP, TEMPPT.
;   Algorithm: POP BC discards the top stacked word so that, after PUT_STR_TEMP's own POP HL absorbs the parked text pointer, its RET delivers control to the FRMEVL caller (not back here). Then JP PUT_STR_TEMP. Common exit for the string-building handlers (CHR$, STR$/HEX$/OCT$, MKI$/MKS$/MKD$, STRING$/SPACE$), which all pre-push or reach it with the descriptor already in DSCTMP. [RE]
; ----------------------------------------------------------------------
STR_FN_RETURN_CHAR_1:
        ; discard the top stacked word (the armed FRMEVL return for the dispatch-table builders, or STR_FILL_ALLOC's return for STRING$/SPACE$); PUT_STR_TEMP's own POP HL then recovers the text pointer and returns to the FRMEVL caller
        POP BC
        JP PUT_STR_TEMP
; ----------------------------------------------------------------------
; FN_STRING_STR -- STRING$(count, char) intrinsic (operand-level token $E7): build a string of 'count' identical characters.
;   In:        HL -> program text positioned at the STRING$ token (the '(' follows). This is the direct operand-fetch entry (FRMEVL_EVAL_OPERAND_5, JP from CP $E7), NOT a FUNC_DISPATCH_TBL handler; the stack top is the FRMEVL operand-eval return address (no FRMEVL_PAREN_2 armed). NOT MID$.
;   Out:       A new string of 'count' copies of the fill character is left as the current string value (built via STR_FILL_ALLOC) and staged on the temp stack; returns to the FRMEVL caller with HL = text pointer past the ')'.
;   Clobbers:  A, B, C, D, E, H, L, F, FAC, VALTYP, DSCTMP, string heap, TEMPPT.
;   Algorithm: Step past the token (CHRGET), require '(', parse the repeat count as a byte (GETBYT -> DE, D=0) and save it (PUSH DE). Require ',', evaluate the fill argument (FRMEVL_NOPAREN -> FAC), require ')'. Then EX (SP),HL / PUSH HL parks the program text pointer on the stack UNDER a fresh copy of the count (so HL now holds the count, not the text pointer) -- the text pointer is recovered later by PUT_STR_TEMP's POP HL. Classify the fill value: if it is a string (FRMEVL_TEST_TYPE -> Z) branch to FN_STRING_FROM_STR to take its first byte as the pad character; otherwise CONINT narrows the numeric fill to a byte code in E (its HL side effects are discarded -- HL holds the count here, not a text pointer) and joins the fill path at STR_FN_RETURN_CHAR_4.
; ----------------------------------------------------------------------
FN_STRING_STR:
        ; advance past the STRING$ token to its argument list
        CALL CHRGET
        CALL SYNCHR
        DEFB    '('                      ; inline char arg consumed by the preceding CALL
        ; parse the repeat count as a byte (0..255) into DE; save it on the stack
        CALL GETBYT
        PUSH DE
        CALL SYNCHR
        DEFB    ','                      ; inline char arg consumed by the preceding CALL
        ; evaluate the fill argument (a numeric char code or a string whose first byte is the pad char) into the FAC
        CALL FRMEVL_NOPAREN
        CALL SYNCHR
        DEFB    ')'                      ; inline char arg consumed by the preceding CALL
        ; park the text pointer on the stack and copy the count above it; HL now holds the count (NOT the text pointer -- the text pointer is recovered later by PUT_STR_TEMP's POP HL)
        EX (SP),HL
        PUSH HL
        ; Z => string fill (take its first byte via FN_STRING_FROM_STR); else numeric fill (use its byte value as the char code)
        CALL FRMEVL_TEST_TYPE
        JR Z,FN_STRING_FROM_STR
        ; numeric fill: coerce the FAC to a byte char code in E (FC on overflow); CONINT's HL update is junk here and discarded
        CALL CONINT
        JR STR_FN_RETURN_CHAR_4
; ----------------------------------------------------------------------
; FN_STRING_FROM_STR -- STRING$ branch when the fill argument is a string: take its first character as the pad byte.
;   In:        Reached from FN_STRING_STR with the fill value being a string (FAC = its STRDESC, VALTYP=VT_STR) and the repeat count still saved on the stack.
;   Out:       Falls into STR_FN_RETURN_CHAR_4 / STR_FILL_ALLOC with A (=E only after the path sets it) = the pad character; the count is popped at STR_FN_RETURN_CHAR_4. Raises FC if the fill string is empty (inside FN_VAL_BODY).
;   Clobbers:  A, B, C, D, E, H, L, F, FAC, VALTYP, DSCTMP, string heap, TEMPPT.
;   Algorithm: CALL FN_VAL_BODY to free/locate the fill string and return A = its first character; then fall through into the shared fill path (STR_FN_RETURN_CHAR_4 pops the count into DE, STR_FILL_ALLOC allocates and fills).
; ----------------------------------------------------------------------
FN_STRING_FROM_STR:
        ; use the fill string's first byte as the pad character (FC if the string is empty)
        CALL FN_VAL_BODY
STR_FN_RETURN_CHAR_4:
        POP DE
        CALL STR_FILL_ALLOC
; ----------------------------------------------------------------------
; FN_SPACE -- SPACE$(n) handler (function token $17): build a string of n blanks.
;   In:        FAC = the evaluated numeric argument n (single parenthesised arg; reached via FRMEVL_FUNC_ARG_PAREN since SPACE$ is dispatch index $16, doubled >= 5); text cursor past the argument.
;   Out:       Function result = a freshly allocated n-byte string filled with $20 (space), registered as a string temporary via the shared STR_FILL_ALLOC builder. Returns through the FRMEVL string-temp path (PUT_STR_TEMP).
;   Clobbers:  A, B, C, D, E, H, L, F, FAC, DSCTMP, the string heap.
;   Algorithm: CONINT narrows n to a byte 0..255 (returns A=E=n, D=0; FC on overflow), set the pad character A=$20, then fall into the shared STR_FILL_ALLOC builder which reserves E heap bytes and fills them with A. SPACE$(n) is exactly STRING$(n," ").
; ----------------------------------------------------------------------
FN_SPACE:
        CALL CONINT
        LD A,$20
; ----------------------------------------------------------------------
; STR_FILL_ALLOC -- shared STRING$/SPACE$ builder: allocate an E-byte string and fill it with the pad char A.
;   In:        E = string length (0..255); A = the fill/pad character. Entered from FN_SPACE (A=$20) and from the STRING$ epilogue (STR_FN_RETURN_CHAR_4: A = caller-chosen pad char, E = the count arg recovered from the stack).
;   Out:       A new E-byte string filled with A; its descriptor is built in DSCTMP (via ALLOC_STR_A) and control continues into the string-function epilogue STR_FN_RETURN_CHAR_1, which registers it as a string temporary via PUT_STR_TEMP. Does not return to its caller; exits through the epilogue's POP BC / JP PUT_STR_TEMP.
;   Clobbers:  A, B, C, D, E, H, L, F, FAC, DSCTMP, the string heap.
;   Algorithm: Save the pad char (PUSH AF), reserve E heap bytes via ALLOC_STR_A (which GETSPAs E bytes and writes len/data-ptr into the working descriptor DSCTMP, returning A=E). Keep the length in B; restore the pad char. If the length is zero (INC B/DEC B sets Z), skip straight to the epilogue. Otherwise load the new buffer's data pointer from DSCTMP.PTR (DSCTMP_PTR) and run STR_FILL_LOOP to write the pad char into all B bytes, then jump to the epilogue.
; ----------------------------------------------------------------------
STR_FILL_ALLOC:
        PUSH AF
        ; reserve E (the requested length) heap bytes for the new string
        LD A,E
        CALL ALLOC_STR_A
        LD B,A
        ; restore the pad/fill character to write
        POP AF
        INC B
        DEC B
        ; zero-length string: nothing to fill, go register the empty result
        JR Z,STR_FN_RETURN_CHAR_1
        ; point HL at the freshly allocated buffer (the data pointer just stored in DSCTMP)
        LD HL,(DSCTMP_PTR)
; ----------------------------------------------------------------------
; STR_FILL_LOOP -- write the pad character into every byte of the new string buffer.
;   In:        HL = first byte of the freshly allocated buffer; B = byte count (>0); A = pad character.
;   Out:       B bytes at the buffer set to A; HL = one past the buffer end; jumps to STR_FN_RETURN_CHAR_1 (the string-temp epilogue).
;   Clobbers:  B, H, L, F.
;   Algorithm: Classic store-and-count loop: LD (HL),A / INC HL / DJNZ until B bytes are written, then JR to the epilogue (STR_FN_RETURN_CHAR_1) to register the filled string as a temporary.
; ----------------------------------------------------------------------
STR_FILL_LOOP:
        LD (HL),A
        INC HL
        DJNZ STR_FILL_LOOP
        JR STR_FN_RETURN_CHAR_1
; ----------------------------------------------------------------------
; LEFT_STR_AND_SUBSTR_TAIL -- LEFT$(s$,n) handler (dispatch slot 0 / sub-token $81) AND the shared substring allocate-and-copy tail for LEFT$/RIGHT$/MID$.
;   In:        DE = text cursor (positioned at the count expression's terminator ')'); stack (top-down): caller return, count word (D=0,E=n staged by FRMEVL_FUNC_TOKEN_1), source string's STRDESC address.
;   Out:       Function result = a new string holding the selected substring, registered as a string temporary; the source temp is freed if it was the topmost heap allocation (FRESTR1). Exits via JP PUT_STR_TEMP.
;   Clobbers:  A, B, C, D, E, H, L, F, FAC, DSCTMP, the string heap.
;   Algorithm: As the LEFT$ entry: PARSE_BYTE_ARG consumes ')' and recovers the requested count into B (leaving the source STRDESC address on the stack, cursor in HL), then XOR A sets the copy offset to 0 (start of string). Falls into the common tail at LEFT_STR_AND_SUBSTR_TAIL_1: with offset in A->C and requested count in B, clamp the copy length to the source length, GETSPA a buffer, compute copy source = source_data_ptr + offset, BLOCK_COPY_BC_TO_DE the bytes in, build the result descriptor (STORE_STR_DESC), free the source (FRESTR1) and register the result (PUT_STR_TEMP). RIGHT$ and MID$ reach this tail at later entry points after computing their own offset/length.
; ----------------------------------------------------------------------
LEFT_STR_AND_SUBSTR_TAIL:
        ; LEFT$: consume ')' and recover the requested length n into B (source descriptor left on the stack)
        CALL PARSE_BYTE_ARG
        ; LEFT$ copies from offset 0 (the start of the string)
        XOR A
LEFT_STR_AND_SUBSTR_TAIL_1:
        EX (SP),HL
        LD C,A
; [RE] Substring alloc tail, two entries. LEFT$/MID$/RIGHT$ fall into $6E5B LD A,$E5 (A dead) and push HL once at _3 ($6E5D). PRINT-USING (CALL +1 from $65EC) enters $6E5C so the E5 byte runs as PUSH HL, then _3 pushes HL again, giving the second stacked HL that the normal callers supply via the pre-pushed descriptor.
LEFT_STR_AND_SUBSTR_TAIL_2:
        LD A,$E5
LEFT_STR_AND_SUBSTR_TAIL_3:
        PUSH HL
        LD A,(HL)
        CP B
        JR C,LEFT_STR_AND_SUBSTR_TAIL_4+1
        LD A,B
; [RE] Length-clamp merge. No-carry (source>=requested) clamps A=B then runs LD DE,$000E (DE unused -> filler) and PRESERVES the copy-offset in C (set at $6E5A). The JR C from $6E60 (source<requested) enters +1 so the 0E 00 bytes run as LD C,$00, RESETTING the copy-offset to 0 while keeping A=source length. Both merge at $6E66 PUSH BC; CALL GETSPA; C is consumed at $6E74 ADD HL,BC. The 11 opcode hides the LD C,$00 on the no-carry path. (Refines prior 'value-neutral' note: C IS affected.)
LEFT_STR_AND_SUBSTR_TAIL_4:
        LD DE,$000E
        PUSH BC
        CALL GETSPA
        POP BC
        POP HL
        PUSH HL
        INC HL
        LD B,(HL)
        INC HL
        LD H,(HL)
        LD L,B
        LD B,$00
        ADD HL,BC
        LD B,H
        LD C,L
        CALL STORE_STR_DESC
        LD L,A
        CALL BLOCK_COPY_BC_TO_DE
        POP DE
        CALL FRESTR1
        JP PUT_STR_TEMP

; ======================================================================
; BASIC-80 function dispatch handlers (table base $01B2, indexed by token*2; dispatcher at $3D8E)
; ======================================================================
; ----------------------------------------------------------------------
; FN_RIGHTDOLLAR -- RIGHT$(s$,n) handler (dispatch slot 1 / sub-token $82): rightmost n characters of a string.
;   In:        DE = text cursor at the count terminator ')'; stack (top-down): caller return, count word (D=0,E=n), source STRDESC address (same stager state as LEFT$).
;   Out:       Function result = the last n characters of the source string, registered as a string temporary (built by the shared substring tail).
;   Clobbers:  A, B, C, D, E, H, L, F, FAC, DSCTMP, the string heap.
;   Algorithm: PARSE_BYTE_ARG consumes ')' and recovers the requested count into B (source descriptor left on the stack). POP DE / PUSH DE recovers the source STRDESC address into DE; read source_len = (DE) and compute the copy OFFSET = source_len - n (SUB B). Jump into the shared tail at LEFT_STR_AND_SUBSTR_TAIL_1 with that offset (in A) and count B, which clamps and copies n bytes starting at offset = the rightmost n chars.
;   Algorithm-note: [RE] Identified as RIGHT$ (not LEFT$) from the offset computation source_len - n, the MS BASIC-80 RIGHT$ start index, AND from the dispatch arithmetic (RIGHT$ token $02 -> $FF $82 -> sub-token-$81 = index 1 = this slot). The previous label FN_RIGHTDOLLAR was a mislabel; the real LEFT$ is the offset-0 slot 0 at $6E55.
; ----------------------------------------------------------------------
FN_RIGHTDOLLAR:
        ; RIGHT$: consume ')' and recover the requested count n into B
        CALL PARSE_BYTE_ARG
        POP DE
        PUSH DE
        ; A = source string length
        LD A,(DE)
        ; copy offset = source_len - n (start so the last n chars are taken)
        SUB B
        JR LEFT_STR_AND_SUBSTR_TAIL_1
; ----------------------------------------------------------------------
; FN_MIDDOLLAR -- MID$(s$,start[,len]) handler (dispatch slot 2 / sub-token $83): substring from 1-based position 'start'.
;   In:        DE = text cursor positioned at the char AFTER the 'start' expression (',' for the 3-arg form or ')' for the 2-arg form); stack (top-down): caller return, start word (D=0,E=start), source STRDESC address.
;   Out:       Function result = up to 'len' characters of the source starting at 1-based position 'start' (or to end of string if len omitted), registered as a string temporary. Empty string if start is past the end.
;   Clobbers:  A, B, C, D, E, H, L, F, FAC, DSCTMP, the string heap.
;   Algorithm: EX DE,HL moves the text cursor into HL and LD A,(HL) PEEKS the next source char so PARSE_OPT_LEN_ARG can later test it (',' vs ')') -- this is NOT the source length. POP_LEN_TO_B recovers 'start' into B; INC B/DEC B rejects start=0 (Illegal function call). Save start (PUSH BC), parse the optional length argument (PARSE_OPT_LEN_ARG: if the peeked char is ')' default E=$FF=to end, else SYNCHR ',' then a length byte into E, then ')'); recover start into A (POP AF). Reload HL = source STRDESC address (EX (SP),HL) and arm the shared tail by pushing LEFT_STR_AND_SUBSTR_TAIL_3 as the return. DEC A makes offset = start-1; CP (HL) against source_len: if offset >= source_len return empty (LD B,$00 / RET NC). Otherwise set offset C = start-1, available = source_len - offset (LD A,(HL)/SUB C); copy length B = min(available, requested E) (CP E / LD B,A / RET C, else LD B,E). RET drops into the pushed tail entry _3 which allocates and copies.
;   Algorithm-note: [RE] CORRECTION vs the reviewed draft: at handler entry DE = text cursor (not the source descriptor), so EX DE,HL parks the CURSOR in HL and the leading LD A,(HL) reads the next SOURCE CHARACTER (for the optional-length test), not the source length. The source-length compare (CP (HL)) happens later, after EX (SP),HL reloads HL with the descriptor address.
; ----------------------------------------------------------------------
FN_MIDDOLLAR:
        EX DE,HL
        ; peek the next source char (',' for 3-arg MID$ or ')' for 2-arg) for the optional-length test below
        LD A,(HL)
        ; recover the 1-based start position into B
        CALL POP_LEN_TO_B
        INC B
        DEC B
        ; start position 0 is illegal (positions are 1-based)
        JP Z,ERROR_FC
        PUSH BC
        ; parse the optional length (default $FF = take everything to end of string)
        CALL PARSE_OPT_LEN_ARG
        POP AF
        EX (SP),HL
        ; arm the shared allocate/copy tail as the return target
        LD BC,LEFT_STR_AND_SUBSTR_TAIL_3
        PUSH BC
        ; convert 1-based start to a 0-based copy offset
        DEC A
        ; offset >= source length: return empty (LD B,$00 / RET NC)
        CP (HL)
        LD B,$00
        RET NC
        LD C,A
        LD A,(HL)
        ; available chars = source_len - offset
        SUB C
        ; clamp the copy length to the requested length
        CP E
        LD B,A
        RET C
        ; requested length fits: copy exactly that many
        LD B,E
        RET
; ----------------------------------------------------------------------
; FN_VAL -- VAL(a$) handler (function token $13): numeric value parsed from a string.
;   In:        The a$ argument has ALREADY been evaluated by the function-dispatch caller (single-arg paren path FRMEVL_PAREN/FRMEVL_FUNC_ARG_PAREN), so its string result sits as the current FRMEVL string temp; its STRDESC (msbasic_strdesc.inc) is reached via GET_STR_DESCR_PTR, which frees that temp and returns HL -> STRDESC, A = STRDESC.LEN, D = 0, Z iff empty. The saved program-text pointer is on the stack under the armed FRMEVL_PAREN_2 (POP HL; RET) return.
;   Out:       FAC ($0CB1) = the number FIN parsed from the string's leading characters (0 for an empty string or non-numeric lead). FN_VAL RETs into FRMEVL_PAREN_2, which restores the saved program-text pointer.
;   Clobbers:  A, B, C, D, E, H, L, F, FAC.
;   Algorithm: Empty string -> Z from GET_STR_DESCR_PTR -> tail to FP_LOAD_INT_TO_FAC with A=0, returning VAL("")=0. Otherwise compute the address one past the string's last character (STRDESC.PTR + LEN), SAVE the byte living there, and OVERWRITE it with 0 (a NUL the parser stops on) -- FIN scans a NUL-terminated buffer, so this fences the parse to exactly the string's own data bytes (which live in the string heap, not program text). DEC HL then CHRGET repositions to the string's first character, CALL FIN parses the number into the FAC, then RESTORE the saved byte so neighbouring memory (the next string, heap, or program text) is left intact.
;   Algorithm-note: D is 0 on entry (GET_STR_DESCR_PTR did XOR A / LD D,A), so 'LD (HL),D' is the NUL store; the original byte was captured in B first and written back via 'LD (HL),B'.
;   Algorithm-note: [RE] FIN advances HL through the string's heap DATA buffer (a temporary), not through program text; FN_VAL itself does not move the program-text cursor -- that pointer is restored by the FRMEVL_PAREN_2 return armed by the function dispatcher.
; ----------------------------------------------------------------------
FN_VAL:
        CALL GET_STR_DESCR_PTR
        ; empty string: VAL("") is 0 -- load 0 (A) into the FAC and return
        JP Z,FP_LOAD_INT_TO_FAC
        LD E,A
        INC HL
        LD A,(HL)
        INC HL
        LD H,(HL)
        LD L,A
        PUSH HL
        ; point one past the last character (data pointer + length)
        ADD HL,DE
        ; save the byte just past the string, then plant a NUL there so FIN stops at the string's end
        LD B,(HL)
        LD (HL),D
        EX (SP),HL
        PUSH BC
        DEC HL
        CALL CHRGET
        ; parse the now-NUL-terminated text into the FAC
        CALL FIN
        POP BC
        POP HL
        ; restore the byte we overwrote with the NUL
        LD (HL),B
        RET
; ----------------------------------------------------------------------
; PARSE_BYTE_ARG -- consume the closing ')' of a single-count string function, then recover its count and source.
;   In:        DE = text cursor (positioned at the char that should be ')'); stack (top-down): this routine's caller return, count word (D=0,E=count), source STRDESC address.
;   Out:       B = the requested count; the count word has been popped (leaving the source STRDESC address under the return); HL = text cursor advanced past ')'.
;   Clobbers:  A, B, C, D, E, H, L, F (and consumes one stack word).
;   Algorithm: EX DE,HL puts the text cursor in HL, SYNCHR ')' verifies and steps past the closing paren (Syntax error otherwise), then falls into POP_LEN_TO_B to lift the stacked count into B while preserving the return address. Shared by LEFT$ and RIGHT$, whose single numeric argument is a plain count.
; ----------------------------------------------------------------------
PARSE_BYTE_ARG:
        ; move the text cursor into HL for SYNCHR
        EX DE,HL
        CALL SYNCHR
        DEFB    ')'                      ; inline char arg consumed by the preceding CALL
; ----------------------------------------------------------------------
; POP_LEN_TO_B -- lift the stacked numeric argument (count/start) into B, keeping the return address on top.
;   In:        Stack (top-down): caller return address, the staged numeric-arg word (D=0,E=value from GETBYT) left by the FRMEVL argument stager.
;   Out:       B = value (the low byte E of that word); the word removed from the stack; the return address remains on top so a normal RET returns to the caller. DE = the popped word.
;   Clobbers:  B, C, D, E (and removes one stack word).
;   Algorithm: POP the return address into BC, POP the staged arg word into DE, PUSH the return address back, then LD B,E so B holds the value. Used directly by MID$ (to fetch the 1-based start position) and as the fall-through of PARSE_BYTE_ARG for LEFT$/RIGHT$ (where the value is the requested count).
;   Algorithm-note: [RE] The popped word is the numeric argument the FRMEVL stager left on the stack (D=0,E=value from GETBYT) -- a count for LEFT$/RIGHT$ or the start position for MID$ -- NOT a string-length byte; the prior 'source length byte' wording was wrong.
; ----------------------------------------------------------------------
POP_LEN_TO_B:
        ; save the return address
        POP BC
        ; pull the stacked numeric argument (E = value)
        POP DE
        PUSH BC
        ; deliver the argument value in B
        LD B,E
        RET
; ----------------------------------------------------------------------
; FN_INSTR -- INSTR([start,] hay$, needle$) handler (function token $E9): 1-based position of needle$ within hay$.
;   In:        HL -> program text at the '(' of INSTR(...) (FN_INSTR is multi-arg dispatched at token $E9 and parses its own arguments; its first CHRGET steps to the first argument token).
;   Out:       FAC = 1-based index where needle$ first occurs in hay$ at or after 'start' (0 if absent). Returns via the stacked FP_LOAD_INT_TO_FAC -> FMUL_7 chain, which loads the byte index into the FAC and restores the saved program-text pointer (FMUL_7 = POP HL; RET).
;   Clobbers:  A, B, C, D, E, H, L, F, FAC; consumes/rebuilds several stack frames.
;   Algorithm: Parse an OPTIONAL leading start position: FRMEVL the first item, then FRMEVL_TEST_TYPE -- if it is a STRING (Z, VALTYP==3) it is actually hay$ (no start given) so default start=1 and branch into the two-string path at INSTR_PARSE_SEARCH_STR; if NUMERIC, CONINT it to a 0..255 byte then OR A / JP Z,ERROR_FC reject 0 (so start is 1..255), SYNCHR ',', then FRMEVL_NOPAREN hay$. INSTR_PARSE_SEARCH_STR: SYNCHR ',', evaluate needle$, SYNCHR ')'. Both string temps are freed (FRETMP/FRESTR_DE) and a return chain is stacked so the final RET delivers the index byte to the FAC. Early outs: (start-1) >= len(hay$) -> 0 (start past end); len(needle$)==0 -> start (empty needle matches at start). Otherwise set HL to hay$.data + (start-1), B = remaining positions to try (len(hay) - (start-1)), DE = needle$.data, C = len(needle$), and run the brute-force matcher (INSTR_TRY_POSITION).
;   Algorithm-note: at each candidate position INSTR_MATCH_CHARS compares up to len(needle$) bytes; INSTR_FOUND computes index = positions_advanced + (start-1) + 1 to convert to a 1-based offset from the start of hay$.
; ----------------------------------------------------------------------
FN_INSTR:
        CALL CHRGET
        CALL FRMEVL
        ; first argument: a string means no start was given (it is hay$); a number is the optional start position
        CALL FRMEVL_TEST_TYPE
        LD A,$01
        PUSH AF
        ; string => start defaults to 1 (already pushed); join the two-string path
        JR Z,INSTR_PARSE_SEARCH_STR
        POP AF
        ; coerce the start expression to a byte (0..255; >255 raises FC inside CONINT)
        CALL CONINT
        OR A
        ; start of 0 is illegal (positions are 1-based)
        JP Z,ERROR_FC
        PUSH AF
        CALL SYNCHR
        DEFB    ','                      ; inline char arg consumed by the preceding CALL
        CALL FRMEVL_NOPAREN
        CALL REQUIRE_STRING
; ----------------------------------------------------------------------
; INSTR_PARSE_SEARCH_STR -- INSTR continuation: parse needle$, free the temps, and stack the index-return chain.
;   In:        HL -> program text at the ',' before needle$. Stack top = the start byte (pushed as AF: A=1 on the no-start path, or the validated 1..255 start on the start-given path); nothing else of this routine's frame is on the stack yet. FAC currently holds hay$'s STRDESC pointer (hay$ has been parsed on both arrival paths).
;   Out:       Falls into the matcher setup with HL=hay$ STRDESC addr, DE=needle$ STRDESC addr, A=start. A return chain (FP_LOAD_INT_TO_FAC over FMUL_7 over the saved program-text pointer) is on the stack so the matcher's final RET delivers the result to the FAC and restores the cursor.
;   Clobbers:  A, B, C, D, E, H, L, F.
;   Algorithm: SYNCHR ','; PUSH the current text cursor, then stash hay$'s STRDESC pointer (LD HL,(FAC) / EX (SP),HL) beneath it; FRMEVL_NOPAREN needle$; SYNCHR ')'. Free needle$ (FRETMP) into DE and recover hay$ STRDESC (HL) and start (A) off the stack. Re-push the text cursor, then stack FMUL_7 and FP_LOAD_INT_TO_FAC as the return chain. Free hay$'s temp (FRESTR_DE, descriptor in HL). The matcher setup (see FN_INSTR) follows.
; ----------------------------------------------------------------------
INSTR_PARSE_SEARCH_STR:
        CALL SYNCHR
        DEFB    ','                      ; inline char arg consumed by the preceding CALL
        PUSH HL
        ; stash hay$'s descriptor pointer beneath the just-saved text cursor while we evaluate needle$
        LD HL,(FAC)
        EX (SP),HL
        CALL FRMEVL_NOPAREN
        CALL SYNCHR
        DEFB    ')'                      ; inline char arg consumed by the preceding CALL
        PUSH HL
        ; consume/free needle$ and get its descriptor address
        CALL FRETMP
        EX DE,HL
        POP BC
        POP HL
        POP AF
        PUSH BC
        LD BC,FMUL_7
        PUSH BC
        LD BC,FP_LOAD_INT_TO_FAC
        PUSH BC
        PUSH AF
        PUSH DE
        ; free hay$'s temporary too (descriptor in HL); HL stays pointing at its descriptor
        CALL FRESTR_DE
        POP DE
        POP AF
        LD B,A
        DEC A
        LD C,A
        CP (HL)
        LD A,$00
        RET NC
        LD A,(DE)
        OR A
        LD A,B
        RET Z
        LD A,(HL)
        INC HL
        LD B,(HL)
        INC HL
        LD H,(HL)
        LD L,B
        LD B,$00
        ADD HL,BC
        SUB C
        LD B,A
        PUSH BC
        PUSH DE
        EX (SP),HL
        LD C,(HL)
        INC HL
        LD E,(HL)
        INC HL
        LD D,(HL)
        POP HL
; ----------------------------------------------------------------------
; INSTR_TRY_POSITION -- attempt a needle$ match anchored at the current position in hay$ (outer search loop).
;   In:        HL = current candidate position in hay$'s data; DE = needle$ data pointer; B = remaining candidate positions from this anchor; C = len(needle$). Beneath on the stack: the (B=initial remaining, C=start-1) snapshot used to compute the final index.
;   Out:       Falls into INSTR_MATCH_CHARS with the position/pointers/counters saved on the stack for restoration on mismatch.
;   Clobbers:  none here (pure save); the inner loop consumes the registers.
;   Algorithm: PUSH the candidate position (HL), the needle$ pointer (DE), and the loop counters (BC), then run the character comparison.
; ----------------------------------------------------------------------
INSTR_TRY_POSITION:
        PUSH HL
        PUSH DE
        PUSH BC
; ----------------------------------------------------------------------
; INSTR_MATCH_CHARS -- compare needle$ against hay$ byte-by-byte at the current position (inner search loop).
;   In:        DE -> next needle$ char; HL -> next hay$ char; C = needle$ chars still to match; B = hay$ chars still available from this anchor. Saved frame (position, ptr, counters) on the stack from INSTR_TRY_POSITION.
;   Out:       On full match (C reaches 0) -> INSTR_FOUND. On a byte mismatch -> INSTR_ADVANCE_POSITION. On running out of hay$ mid-match (B exhausted via DJNZ) -> drop the saved frame and fall into INSTR_NOT_FOUND.
;   Clobbers:  A, C, D, E, H, L, B, F.
;   Algorithm: Compare (DE) with (HL); mismatch -> advance to the next start position. On equal, step needle$ (INC DE), decrement the needle$ remaining count (DEC C) -- zero means every needle$ char matched (INSTR_FOUND). Otherwise step hay$ (INC HL) and DJNZ on the hay$-remaining count B; if hay$ is exhausted before needle$ completes, the match cannot finish anywhere (later anchors have fewer chars), so discard the saved frame and report not-found.
; ----------------------------------------------------------------------
INSTR_MATCH_CHARS:
        LD A,(DE)
        CP (HL)
        ; characters differ: give up here and try the next start position
        JR NZ,INSTR_ADVANCE_POSITION
        INC DE
        DEC C
        ; all of needle$ matched -> found
        JR Z,INSTR_FOUND
        INC HL
        ; more hay$ available: compare the next character pair
        DJNZ INSTR_MATCH_CHARS
        POP DE
        POP DE
        POP BC
; ----------------------------------------------------------------------
; INSTR_NOT_FOUND -- needle$ does not occur in hay$ at or after the start position.
;   In:        Stack top = the (initial remaining, start-1) snapshot to be discarded.
;   Out:       A = 0; RET (into the FP_LOAD_INT_TO_FAC -> FMUL_7 chain, yielding INSTR()=0).
;   Clobbers:  A, D, E, F.
;   Algorithm: Drop the index-bookkeeping snapshot off the stack (POP DE), zero A, and return 0 through the stacked result chain.
; ----------------------------------------------------------------------
INSTR_NOT_FOUND:
        POP DE
        XOR A
        RET
; ----------------------------------------------------------------------
; INSTR_FOUND -- needle$ matched; compute and return its 1-based position within hay$.
;   In:        Stack (top-down): the per-anchor loop counters pushed at INSTR_TRY_POSITION (B=remaining positions counted from this anchor), the needle$ pointer, the matched-position pointer, and the (B=initial remaining, C=start-1) snapshot.
;   Out:       A = 1-based index of the match; RET into the result chain (FP_LOAD_INT_TO_FAC -> FMUL_7).
;   Clobbers:  A, B, C, D, E, H, L, F.
;   Algorithm: Unwind the four saved words. POP HL lands the per-anchor counter pair, so H = the remaining-positions count recorded when this anchor began. Discard the needle$ pointer and the matched-position pointer (two POP DE). POP BC lands the snapshot, so B = initial remaining (= len(hay$)-(start-1)), C = start-1. index = (B - H) + C + 1 = positions_advanced + (start-1) + 1, converting the advance count into a 1-based offset from the start of hay$.
; ----------------------------------------------------------------------
INSTR_FOUND:
        POP HL
        POP DE
        POP DE
        POP BC
        LD A,B
        ; positions advanced from the scan start = initial_remaining - remaining_at_anchor
        SUB H
        ; add (start-1) to rebase onto the start of hay$
        ADD A,C
        ; convert the 0-based offset to a 1-based INSTR index
        INC A
        RET
; ----------------------------------------------------------------------
; INSTR_ADVANCE_POSITION -- mismatch at the current position; restore state and try the next start.
;   In:        Stack (top-down): the per-anchor loop counters, the needle$ pointer, the candidate-position pointer (all from INSTR_TRY_POSITION).
;   Out:       On more positions remaining -> re-enter INSTR_TRY_POSITION one character further along; otherwise -> INSTR_NOT_FOUND.
;   Clobbers:  B, C, D, E, H, L, F.
;   Algorithm: Restore the saved counters (BC: B=remaining positions at this anchor, C=len(needle$)), needle$ pointer (DE), and candidate position (HL); INC HL to step to the next start position; DJNZ on the remaining-positions count B back to INSTR_TRY_POSITION, or fall through (JR) to INSTR_NOT_FOUND when exhausted.
; ----------------------------------------------------------------------
INSTR_ADVANCE_POSITION:
        POP BC
        POP DE
        POP HL
        ; slide the anchor one character forward in hay$
        INC HL
        ; positions left: retry the match at the new anchor
        DJNZ INSTR_TRY_POSITION
        JR INSTR_NOT_FOUND
; ----------------------------------------------------------------------
; STMT_MID_ASSIGN -- LET MID$(var$, start [, len]) = src$ assignment STATEMENT (overwrites characters in place).
;   STATEMENT scope: this is the MID$ on the LEFT of '=' (the assignment form), reached from the statement path when a line begins with the MID$ token, NOT the MID$() function. The applier should treat it as a statement handler, not a FRMEVL function.
;   In:        HL -> program text at the '(' of MID$(...) (just past the MID$ token).
;   Out:       The selected character range of var$ is overwritten with src$'s bytes (var$'s overall length unchanged). Returns via the stacked FMUL_7 (POP HL; RET, restores the program-text pointer). Raises FC if start is 0 or beyond len(var$).
;   Clobbers:  A, B, C, D, E, H, L, F; var$'s heap copy and STRDESC if relocation was needed.
;   Algorithm: PTRGET the target string variable (DE -> its STRDESC); REQUIRE_STRING. If var$'s data currently lives in the program text or the variable/array area (its data pointer falls between TXTTAB and STREND, i.e. NOT in the writable string heap), copy var$ to fresh heap (STR_BUILD_FROM_DESC) and repoint the variable at the copy (FP_MOVE_TYPED) so we never scribble over a string constant. At MID_ASSIGN_LEN_ARG: parse start (GETBYT, FC if 0), the optional length (PARSE_OPT_LEN_ARG -> E, default $FF = rest of string), and the '='-prefixed source expression (EVAL_EXPR_AFTER_SYNCHR); free src$ (FRETMP). Stack FMUL_7 as the return tail. Clamp the copy count to min(requested len, len(var$)-start+1 room, len(src$)) and overwrite var$[start..] in place via MID_ASSIGN_COPY.
;   Algorithm-note: the TXTTAB/STREND window test distinguishes 'data is in a read-only/relocatable region' (must duplicate first) from 'data already in the freely-writable string heap' (overwrite directly).
; ----------------------------------------------------------------------
STMT_MID_ASSIGN:
        CALL SYNCHR
        DEFB    '('                      ; inline char arg consumed by the preceding CALL
        ; locate the target string variable; DE -> its descriptor
        CALL PTRGET_1+1
        ; the MID$ target must be a string variable
        CALL REQUIRE_STRING
        PUSH HL
        PUSH DE
        EX DE,HL
        INC HL
        LD E,(HL)
        INC HL
        LD D,(HL)
        ; if var$'s data lies between TXTTAB and STREND (program text / variable area, not yet owned string heap), copy it to an owned heap block so the slice can be overwritten safely; data already in the heap or below TXTTAB is left in place
        ; is the string's data inside the program text / variable area (TXTTAB..STREND) rather than the writable heap?
        LD HL,(STREND)
        CALL CMP_HL_DE
        JR C,MID_ASSIGN_AFTER_COPYOUT
        LD HL,(TXTTAB)
        CALL CMP_HL_DE
        JR NC,MID_ASSIGN_AFTER_COPYOUT
        POP HL
        PUSH HL
        ; yes: copy var$ into fresh heap so we do not overwrite a program string constant
        CALL STR_BUILD_FROM_DESC
        POP HL
        PUSH HL
        ; repoint the variable's descriptor at the new heap copy
        CALL FP_MOVE_TYPED
MID_ASSIGN_AFTER_COPYOUT:
        POP HL
        EX (SP),HL
        CALL SYNCHR
        DEFB    ','                      ; inline char arg consumed by the preceding CALL
        ; read the 1-based start position; 0 is an Illegal function call
        ; parse the 1-based start position
        CALL GETBYT
        OR A
        JP Z,ERROR_FC
        PUSH AF
        LD A,(HL)
        ; read the optional length (default $FF = to end of source) and consume the closing ')'
        ; parse the optional length (E = $FF means to the end of var$)
        CALL PARSE_OPT_LEN_ARG
        PUSH DE
        ; require '=' then evaluate the source string expression
        ; consume '=' and evaluate the source string expression
        CALL EVAL_EXPR_AFTER_SYNCHR
        PUSH HL
        CALL FRETMP
        EX DE,HL
        POP HL
        POP BC
        POP AF
        LD B,A
        EX (SP),HL
        PUSH HL
        ; push the shared POP HL/RET tail (FMUL_7) as the return so HL is restored and we return to the caller on exit
        ; install FMUL_7 (POP HL; RET) as the return tail so the final RET restores the program-text pointer
        LD HL,FMUL_7
        EX (SP),HL
        LD A,C
        OR A
        RET Z
        ; len(var$): compute how many characters are available from 'start' to the end
        LD A,(HL)
        SUB B
        ; start is past the end of var$ -> illegal function call
        JP C,ERROR_FC
        INC A
        ; clamp the copy length to whichever is smaller: available room or requested length
        CP C
        JR C,MID_ASSIGN_CLAMP_LEN
        LD A,C
MID_ASSIGN_CLAMP_LEN:
        LD C,B
        DEC C
        LD B,$00
        PUSH DE
        INC HL
        LD E,(HL)
        INC HL
        LD H,(HL)
        LD L,E
        ; destination = var$ data + (start-1): first character to overwrite
        ADD HL,BC
        LD B,A
        POP DE
        EX DE,HL
        LD C,(HL)
        INC HL
        LD A,(HL)
        INC HL
        LD H,(HL)
        LD L,A
        EX DE,HL
        LD A,C
        OR A
        RET Z
; ----------------------------------------------------------------------
; MID_ASSIGN_COPY -- overwrite a slice of var$ with src$'s bytes (the MID$-assignment inner copy).
;   In:        HL -> destination (the first var$ character to overwrite); DE -> src$ data; B = clamped copy count (min of available room and requested length); C = len(src$).
;   Out:       min(B, C) bytes copied from src$ into var$; HL, DE advanced; RET (into the stacked FMUL_7 -> caller).
;   Clobbers:  A, B, C, D, E, H, L, F.
;   Algorithm: Copy one byte at a time, advancing both pointers. Stop when either the source length runs out (DEC C -> RET Z) or the clamped count is reached (DJNZ on B falls through to RET). So exactly min(B, C) characters are written and var$'s overall length is never changed.
; ----------------------------------------------------------------------
MID_ASSIGN_COPY:
        LD A,(DE)
        LD (HL),A
        INC DE
        INC HL
        DEC C
        ; stop when the source string is exhausted
        RET Z
        ; continue until the clamped copy count is reached
        DJNZ MID_ASSIGN_COPY
        RET
; ----------------------------------------------------------------------
; PARSE_OPT_LEN_ARG -- parse an optional ', len' argument and the closing ')', shared by RIGHT$ and MID$=.
;   Callers:    FN_MIDDOLLAR (RIGHT$, token $02) and STMT_MID_ASSIGN. (INSTR does NOT use this -- it parses its own optional start inline; verified the only two callers are $6E99 and $6F9D.)
;   In:        A = the current token/char (the char (HL) the caller just loaded); HL -> program text at that char.
;   Out:       E = the length argument (default $FF = 'to end of string' when no length is given; else the GETBYT value); HL advanced past the ')'. Raises Syntax error if the expected ',' or ')' is missing.
;   Clobbers:  A, B, C, D, E, H, L, F (when a length expression is evaluated).
;   Algorithm: Default E = $FF. If the current char is ')' there is no length -> fall through to consume ')'. Otherwise SYNCHR ',' and GETBYT the length (returned in A and E, D=0). PARSE_OPT_LEN_ARG_1 then SYNCHR-asserts the closing ')'.
;   Algorithm-note: $FF is the 'whole remaining string' sentinel the callers clamp against the actual available length; GETBYT leaves the value in both A and E so the caller can read E.
; ----------------------------------------------------------------------
PARSE_OPT_LEN_ARG:
        ; default length = $FF (take the rest of the string)
        LD E,$FF
        CP $29
        ; next char is ')': no length given, keep the default
        JR Z,PARSE_OPT_LEN_ARG_1
        CALL SYNCHR
        DEFB    ','                      ; inline char arg consumed by the preceding CALL
        ; evaluate the explicit length byte (returned in A and E)
        CALL GETBYT
; ----------------------------------------------------------------------
; PARSE_OPT_LEN_ARG_1 -- tail of PARSE_OPT_LEN_ARG: require and consume the closing ')'.
;   In:        HL -> program text at the expected ')'.
;   Out:       HL advanced past ')'; E unchanged (carries the length set by the caller). Raises Syntax error if ')' is absent.
;   Clobbers:  A, F (SYNCHR re-reads the char).
;   Algorithm: SYNCHR ')' (the inline DEFB ')' is the char SYNCHR matches), then RET. Separate entry so the 'no length' path can jump straight here after defaulting E.
; ----------------------------------------------------------------------
PARSE_OPT_LEN_ARG_1:
        CALL SYNCHR
        DEFB    ')'                      ; inline char arg consumed by the preceding CALL
        RET
; ----------------------------------------------------------------------
; FN_FRE -- FRE() function (token $0F): report free string-heap space, optionally forcing a GC first
;   In:        FAC holds the evaluated argument; VALTYP ($0B14) set by FRMEVL. FRE(numeric) skips GC; FRE(string$) forces one.
;   Out:       FAC = (FRETOP - STREND) as a single-precision number: the count of bytes free between STREND ($0B73, first free byte above the array table) and FRETOP ($0B48, bottom of allocated string space).
;   Clobbers:  A, B, C, D, E, H, L, F.
;   Algorithm: Classify the argument type (FRMEVL_TEST_TYPE sets Z iff string). A non-string (NZ) jumps straight to FN_FRE_1. A string argument (Z) falls through to free that string (FRESTR) and run a full garbage-collection pass (GARBAG) so the reported figure reflects truly reclaimable space. FN_FRE_1 then loads STREND into DE (via LD HL,(STREND)/EX DE,HL) and FRETOP into HL and tail-calls FP_INT_SUB_TO_FAC.
;   Algorithm-note: FP_INT_SUB_TO_FAC computes HL-DE = FRETOP - STREND then INT_TO_SNG; the difference is the free gap because string space grows downward from FRETOP while variables/arrays grow upward to STREND.
; ----------------------------------------------------------------------
FN_FRE:
        ; string argument forces a garbage-collection pass so the free count is accurate; numeric argument skips it
        CALL FRMEVL_TEST_TYPE
        JP NZ,FN_FRE_1
        CALL FRESTR
        CALL GARBAG
FN_FRE_1:
        ; free bytes = FRETOP (bottom of string heap) minus STREND (top of variable/array area)
        LD HL,(STREND)
        EX DE,HL
        LD HL,(FRETOP)
        JP FP_INT_SUB_TO_FAC
; ----------------------------------------------------------------------
; QINLIN -- emit the '? ' INPUT prompt, then read a console line via INLIN.
;   In:        none (output goes to the current console device).
;   Out:       HL -> the returned input line (BUF_INPUT_RESET_PTR holds a ',' sentinel; line body at BUF=$0A0E, NUL-terminated); CY=1 if the user typed Ctrl-C (line aborted). Same return contract as INLIN.
;   Clobbers:  A, BC, DE, HL, flags.
;   Algorithm: Print '?' ($3F) then ' ' ($20) through OUTCHR, then JP INLIN_RESET_LINE, which clears the editor scratch cells and falls into INLIN to read and edit one console line. Used by the INPUT statement and the RANDOMIZE seed prompt.
; ----------------------------------------------------------------------
QINLIN:
        LD A,$3F
        CALL OUTCHR
        LD A,$20
        CALL OUTCHR
        ; prompt drawn; reset the editor scratch cells and run the line editor (returns the edited line, or Ctrl-C carry, to our caller)
        JP INLIN_RESET_LINE
; ----------------------------------------------------------------------
; INLIN_GETCH -- fetch the next input char and route it; Ctrl-A leaves to EDIT-mode redisplay.
;   In:        HL -> current append position in BUF; B = 1-based char count; DEL_ECHO_FLAG = rubout-echo state.
;   Out:       on an ordinary char, tail-jumps to INLIN_DISPATCH (no return); on Ctrl-A ($01) NUL-terminates the line and jumps into the EDIT redisplay (INLIN_1 -> STMT_EDIT_4) which never returns here.
;   Clobbers:  A, flags (plus whatever INCHR and the dispatch path touch).
;   Algorithm: Read one char via INCHR (from the current file if PTRFIL!=0, else CONIN from the keyboard with the high bit masked off). If it is not Ctrl-A, dispatch it as an editing key. If it is Ctrl-A, write $00 at (HL) to terminate the buffer and divert to the full-screen line EDIT path.
; ----------------------------------------------------------------------
INLIN_GETCH:
        CALL INCHR
        CP $01
        JP NZ,INLIN_DISPATCH
        ; Ctrl-A: NUL-terminate the line so far before handing it to the EDIT redisplay
        LD (HL),$00
        JR INLIN_1
; ----------------------------------------------------------------------
; INLIN_PUT_AND_RESET -- write the count byte (=0 here) as the terminator, then restart the input line.
;   In:        HL -> first BUF byte; B = 0 (entered only from the empty-line rubout branch, where DEC B from B=1 made the count 0).
;   Out:       falls into INLIN_RESET_LINE -> INLIN; does not return.
;   Clobbers:  (HL) written; then the restart clears the editor scratch cells.
;   Algorithm: Store B (=0) to (HL) to NUL-terminate the now-empty buffer, then fall through to clear the editor scratch cells and re-read the line from scratch. Entered when the user rubs out the only character on the line.
; ----------------------------------------------------------------------
INLIN_PUT_AND_RESET:
        ; empty line was rubbed out: B is 0 here, so this writes the NUL terminator before restarting
        LD (HL),B
; ----------------------------------------------------------------------
; INLIN_RESET_LINE -- clear the editor scratch cells, then (re)start reading the current input line.
;   In:        none required.
;   Out:       falls into INLIN; PENDING_KEY and the INLIN CR-suppress scratch cell L_0C93 are zeroed.
;   Clobbers:  A.
;   Algorithm: Zero PENDING_KEY (the INKEY$/break captured-key cell) and L_0C93 (a shared scratch cell whose INLIN role gates the CR-finish CRLF echo), then fall into INLIN. Reached from QINLIN, from Ctrl-U line-kill and a bare LF (restart the same line), and from the prompt setup -- the canonical 'begin a fresh console line' entry.
; ----------------------------------------------------------------------
INLIN_RESET_LINE:
        XOR A
        ; drop any key the INKEY$/Ctrl-C poll had stashed in PENDING_KEY; this is a fresh line
        LD (PENDING_KEY),A
        XOR A
        ; [RE] clear the INLIN CR-suppress scratch flag (L_0C93) so the next CR emits the normal CRLF; the cell is shared scratch (also detokenizer spacing / FIELD length), set nonzero only when an INPUT prompt ends in ';'
        LD (L_0C93),A
; ----------------------------------------------------------------------
; INLIN -- console line-input editor: read and edit one input line, return it to the caller.
;   In:        none (console is the input device unless PTRFIL!=0 selects a file).
;   Out:       HL -> the returned line: BUF_INPUT_RESET_PTR ($0A0D) holds a ',' sentinel and the line body at BUF=$0A0E is NUL-terminated; B = 1+length. CY=1 if the line was aborted with Ctrl-C (callers test JP C, and on CY=1 the HL value is don't-care).
;   Clobbers:  A, BC, DE, HL, flags; PENDING_KEY / DEL_ECHO_FLAG / L_0C93 editor scratch cells.
;   Algorithm: Snapshot the print column for Tab alignment (INLIN_SAVE_COLUMN), read the first key via INCHR. Ctrl-A ($01) at line start diverts to the full-screen EDIT redisplay (INLIN_1: CRLF, HL=$FFFF, STMT_EDIT_4) and never returns here. Otherwise drop into INLIN_6 to initialize the buffer (HL=BUF, B=1, DEL_ECHO_FLAG=0) and loop in the dispatcher echoing printable chars into BUF and acting on control keys until CR/Ctrl-C ends the line.
; ----------------------------------------------------------------------
INLIN:
        ; remember where the prompt left the cursor so Tab stops in the edited line line up
        CALL INLIN_SAVE_COLUMN
        CALL INCHR
        CP $01
        ; ordinary first key: set up the buffer and enter the edit loop
        JR NZ,INLIN_6
INLIN_1:
        CALL CRLF
        ; Ctrl-A at line start: HL=$FFFF flags the EDIT redisplay path (STMT_EDIT_4 tests for $FFFF and prints the '!' EDIT marker instead of a line number)
        LD HL,$FFFF
        JP STMT_EDIT_4
; ----------------------------------------------------------------------
; INLIN_DELETE_CHAR -- DEL/rubout ($7F): remove the last buffered char with backslash-echo feedback.
;   In:        HL -> just past the last buffered char; B = 1+count; DEL_ECHO_FLAG = backslash-echo state (0 = first rubout of a run, nonzero = a '\\' is already shown).
;   Out:       loops back via INLIN_GETCH for the next key; restarts the line (INLIN_PUT_AND_RESET) if it was already empty; or reinitializes (INLIN_KILL_LINE) if this rubout emptied it.
;   Clobbers:  A, B, HL, flags; sets DEL_ECHO_FLAG = $5C.
;   Algorithm: Load A=$5C ('\\') and set DEL_ECHO_FLAG=$5C unconditionally, then branch on the OLD flag value: on the first DEL of a run (was 0) echo the '\\' to open the visible-rubout bracket; on later DELs skip the echo. Then DEC B / DEC HL: if the line was already empty restart it, if this DEC emptied it reinitialize, otherwise re-echo the char just removed (LD A,(HL)) so the user sees it and wait for the next key.
; ----------------------------------------------------------------------
INLIN_DELETE_CHAR:
        ; sample the OLD backslash-echo flag (first rubout vs continuation); A is then overwritten with '\\' and the flag set unconditionally
        LD A,(DEL_ECHO_FLAG)
        OR A
        LD A,$5C
        LD (DEL_ECHO_FLAG),A
        ; continuation rubout: backslash already shown, skip the open-bracket echo
        JR NZ,INLIN_3
        DEC B
        ; line was already empty (B went 1->0): nothing to delete, restart it
        JR Z,INLIN_PUT_AND_RESET
        ; first rubout: echo the opening '\\' (still in A) to bracket the removed chars
        CALL OUTCHR
        INC B
INLIN_3:
        DEC B
        DEC HL
        JR Z,INLIN_KILL_LINE
        ; re-echo the character being deleted so the visible rubout shows what was removed
        LD A,(HL)
        CALL OUTCHR
        JR INLIN_GETCH
; ----------------------------------------------------------------------
; INLIN_ECHO_DELETED -- [UNKNOWN: unreachable dead bytes; intended function not determined].
;   In:        (would be) HL -> char to erase, B = count, A = char to echo.
;   Out:       (would) echo one char and loop to INLIN_GETCH while B != 0.
;   Clobbers:  not executed; the bytes are DEC B / DEC HL / CALL OUTCHR / JR NZ,INLIN_GETCH.
;   Algorithm: UNKNOWN. No instruction or data word references $705A and the preceding instruction (JR INLIN_GETCH at $7058) is unconditional, so these 5 bytes are unreachable. They resemble INLIN_3's erase-and-loop tail but are NOT a copy of it -- they lack the LD A,(HL) before OUTCHR (so they would echo whatever is in A, not the deleted char) and use JR NZ (loop) instead of JR (fall through). Kept verbatim for byte-identical reassembly; no caller invented.
; ----------------------------------------------------------------------
INLIN_ECHO_DELETED:
        DEC B
        DEC HL
        CALL OUTCHR
        JR NZ,INLIN_GETCH
; ----------------------------------------------------------------------
; INLIN_KILL_LINE -- finish a rubout-to-empty or a Ctrl-X cancel: echo a mark char, newline, reinit the buffer.
;   In:        A = the char to echo. From the rubout-to-empty path (INLIN_3) A holds '\\' ($5C, the rubout-bracket char left in A by INLIN_DELETE_CHAR); from the Ctrl-X handler A holds '#' ($23).
;   Out:       falls into INLIN_6 -> INLIN_DISPATCH with HL=BUF, B=1, DEL_ECHO_FLAG=0 (empty buffer, ready to retype); A is preserved across the flag clear (INLIN_6 PUSH AF/.../POP AF).
;   Clobbers:  BC, HL, flags (A preserved).
;   Algorithm: Echo the mark char (OUTCHR), emit CRLF to drop to a clean line, then fall into INLIN_6 which resets the buffer pointer to BUF, the count B to 1, and clears DEL_ECHO_FLAG. Reached from rubout-back-to-empty (INLIN_3) and from the Ctrl-X handler.
; ----------------------------------------------------------------------
INLIN_KILL_LINE:
        CALL OUTCHR
        CALL CRLF
INLIN_6:
        ; fresh empty line: point at the start of the input buffer
        LD HL,BUF
        ; count back to 1 (1-based; B==1 means the buffer is empty)
        LD B,$01
        PUSH AF
        XOR A
        ; clear DEL_ECHO_FLAG: no rubout run is open on a fresh line
        LD (DEL_ECHO_FLAG),A
        POP AF
; ----------------------------------------------------------------------
; INLIN_DISPATCH -- classify one input char and act on it; printable chars fall through to storage.
;   In:        A = the input char; HL -> append position; B = 1+count; DEL_ECHO_FLAG = rubout-echo state.
;   Out:       branches per key: DEL -> INLIN_DELETE_CHAR; Ctrl-C -> sets CY and RETs (abort); CR -> INLIN_CR_FINISH; Tab/Bell -> store; LF -> restart-if-empty else store; Ctrl-U -> restart line; BS -> erase (or JP INLIN to restart if the line is empty); Ctrl-X -> cancel; Ctrl-R -> retype; other <$20 -> ignore (loop); printable -> INLIN_STORE_CHAR.
;   Clobbers:  A, C, flags; may clear DEL_ECHO_FLAG and echo a closing '\\'.
;   Algorithm: Stash the char in C. If it is DEL ($7F) rub out a char. Otherwise, if a backslash-echo rubout run is open, close it (echo '\\', clear DEL_ECHO_FLAG). Then compare C against the control set: $07 Bell and $09 Tab store literally; $03 Ctrl-C echoes '^C' and aborts with CY=1; $0D CR ends the line; $0A LF restarts an empty line else stores; $15 Ctrl-U echoes and restarts; $08 BS erases (or restarts if empty); $18 Ctrl-X cancels; $12 Ctrl-R retypes; any other char below $20 is ignored. Printable chars ($20+) fall into INLIN_STORE_CHAR.
; ----------------------------------------------------------------------
INLIN_DISPATCH:
        ; keep the raw char in C; A is reused for comparisons and echoing
        LD C,A
        CP $7F
        ; DEL ($7F): rub out the previous character
        JR Z,INLIN_DELETE_CHAR
        LD A,(DEL_ECHO_FLAG)
        OR A
        JR Z,INLIN_8
        ; a rubout run was open: close the visible-rubout bracket with a '\\'
        LD A,$5C
        CALL OUTCHR
        XOR A
        LD (DEL_ECHO_FLAG),A
INLIN_8:
        LD A,C
        CP $07
        ; Bell ($07): keep it in the line verbatim
        JR Z,INLIN_STORE_CHAR
        CP $03
        ; Ctrl-C ($03): echo '^C' and clear the printer/Ctrl-O suppress flags; this also returns with Z set
        CALL Z,ECHO_CTRL_CHAR
        ; set carry for the line-abort, then RET Z below fires ONLY for Ctrl-C (ECHO_CTRL_CHAR left Z set); on any other key Z is clear from CP $03 so this carry is harmlessly overwritten by the later compares
        SCF
        RET Z
        CP $0D
        ; CR ($0D): line complete, terminate and return it
        JP Z,INLIN_CR_FINISH
        CP $09
        ; Tab ($09): stored as-is; column expansion happens on echo
        JR Z,INLIN_STORE_CHAR
        CP $0A
        ; not LF: continue classifying further control keys
        JR NZ,INLIN_9
        DEC B
        ; LF on an empty line (B was 1): restart the line
        JP Z,INLIN_RESET_LINE
        INC B
        ; LF with text already typed: store it (INLIN_STORE_CHAR then detects the stored LF and runs the multi-line continuation echo)
        JR INLIN_STORE_CHAR
INLIN_9:
        CP $15
        CALL Z,ECHO_CTRL_CHAR
        JP Z,INLIN_RESET_LINE
        CP $08
        JR NZ,INLIN_CTRL_X
        DEC B
        JP Z,INLIN
        CALL INLIN_BACKSPACE
        JP INLIN_GETCH
; ----------------------------------------------------------------------
; INLIN_CTRL_X -- editor dispatch arm: Ctrl-X (line cancel)
;   In:        A = the control char being classified (already proven != BS/Ctrl-H by the preceding arm); B = 1-based char count, HL = next write slot in BUF, C = the same char
;   Out:       on Ctrl-X, does not return -- loads '#' into A and jumps to INLIN_KILL_LINE (which echoes that '#', emits CRLF, resets the buffer pointer and restarts the line); on any other char, jumps to INLIN_CTRL_R to continue the dispatch chain
;   Clobbers:  A (set to '#' = $23 on the cancel path)
;   Algorithm: One arm of the INLIN control-char dispatch chain. If A != Ctrl-X ($18) defer to INLIN_CTRL_R. On Ctrl-X, load '#' ($23) into A and JP INLIN_KILL_LINE; that routine OUTCHRs the '#' as the visible abandon marker, then CRLFs and reprompts. [RE] '#' as the line-cancel echo is the MS-BASIC convention.
; ----------------------------------------------------------------------
INLIN_CTRL_X:
        CP $18
        JP NZ,INLIN_CTRL_R
        ; Ctrl-X line-cancel: echo '#' as the abandon marker, then restart the input line
        LD A,$23
        JP INLIN_KILL_LINE
; ----------------------------------------------------------------------
; INLIN_CTRL_R -- editor dispatch arm: Ctrl-R (retype / redisplay current line)
;   In:        A = the control char being classified; B = 1-based char count, HL = next write slot just past the last stored char in BUF, C = the same char
;   Out:       on Ctrl-R, redisplays the typed-so-far line and resumes the per-char loop at INLIN_GETCH with BC/DE/HL restored to their entry values; on any other char, falls through to INLIN_REJECT_LOW_CTRL (the < $20 ignore guard)
;   Clobbers:  none visible to the caller (BC, DE, HL are pushed and popped); writes a temporary $00 into BUF at HL (overwritten by the next stored char)
;   Algorithm: If A != Ctrl-R ($12) defer to INLIN_REJECT_LOW_CTRL. On Ctrl-R: push BC/DE/HL, write $00 at (HL) so the buffer prints as a $00-terminated string, CRLF, then PRINT_ZSTRING from BUF to re-echo a clean copy of what has been typed so far (useful after rubouts have littered the line). Restore BC/DE/HL and JP INLIN_GETCH so editing continues exactly where it left off.
; ----------------------------------------------------------------------
INLIN_CTRL_R:
        CP $12
        JR NZ,INLIN_REJECT_LOW_CTRL
        PUSH BC
        PUSH DE
        PUSH HL
        ; $00-terminate the typed-so-far buffer in place so PRINT_ZSTRING stops at the right point
        LD (HL),$00
        CALL CRLF
        LD HL,BUF
        ; re-echo a clean copy of the line accumulated so far from BUF
        CALL PRINT_ZSTRING
        POP HL
        POP DE
        POP BC
        JP INLIN_GETCH
INLIN_REJECT_LOW_CTRL:
        ; any other char below space is an unhandled control code -- ignore it and fetch the next key
        CP $20
        JP C,INLIN_GETCH
; ----------------------------------------------------------------------
; INLIN_STORE_CHAR -- accept one character into the line, with full-buffer guard
;   In:        B = 1-based count of chars already in the line ($01 = empty; the buffer is full when B has reached $FF, i.e. 254 chars stored), HL = next write slot in BUF, C = char to store, PTRFIL ($0840) = active input file pointer (0 = console)
;   Out:       if room, falls into INLIN_APPEND_ECHO to store and echo C; if full and reading from the console (PTRFIL == 0), jumps to INLIN_ECHO_AND_TEST_LF with A = Bell ($07) to ring the bell WITHOUT storing; if full while reading from a file (PTRFIL != 0), does not return -- jumps to CRUNCH_EMIT_OVERFLOW (ERR_LINE_BUFFER_OVERFLOW = 23)
;   Clobbers:  A; on the file-overflow path also HL/DE (LINGET, SAVTXT)
;   Algorithm: Overflow test: copy B into A and INC A -- the result is zero (sets Z) only when B == $FF, i.e. the 254-char buffer is already full (B is NOT modified). Not full: append. Full: read PTRFIL; if it is 0 the line is console input, so set A = Bell ($07) and reuse the shared echo tail (INLIN_ECHO_AND_TEST_LF) to beep and keep waiting for CR/edits without growing the line; if PTRFIL is nonzero the line came from a file and cannot be truncated silently, so re-crunch the buffered line (LINGET reads its line number, EX DE,HL and store into SAVTXT) and raise the line-too-long error.
; ----------------------------------------------------------------------
INLIN_STORE_CHAR:
        LD A,B
        ; buffer is full iff the count B == $FF: copy B into A and INC A sets Z only then (B itself is left unchanged)
        INC A
        JR NZ,INLIN_APPEND_ECHO
        PUSH HL
        ; on overflow, decide the source: PTRFIL == 0 means console input, nonzero means an active input file
        LD HL,(PTRFIL)
        LD A,H
        OR L
        POP HL
        ; console overflow: ring the Bell (do not store) and keep editing
        LD A,$07
        JR Z,INLIN_ECHO_AND_TEST_LF
        LD HL,BUF
        ; file overflow cannot be truncated: re-parse the buffered line and raise line-too-long
        CALL LINGET
        EX DE,HL
        LD (SAVTXT),HL
        JP CRUNCH_EMIT_OVERFLOW
; ----------------------------------------------------------------------
; INLIN_APPEND_ECHO -- store the accepted char, advance, echo, and detect a hard LF
;   In:        C = char to store, HL = next write slot in BUF, B = 1-based char count
;   Out:       stores C at (HL), HL++, B++; then (via the shared tail) echoes the char with OUTCHR; if the char was LF ($0A) zeroes CURSOR_POS, echoes CR, and drops into INLIN_WAIT_AFTER_LF; otherwise resumes the per-char loop at INLIN_GETCH
;   Clobbers:  A, HL, B; CURSOR_POS ($0B11) on the LF path
;   Algorithm: Append: copy C into the buffer, bump the write pointer and the count. The shared tail (INLIN_ECHO_AND_TEST_LF, also reached from the console-overflow Bell where nothing was stored) echoes A then computes A - $0A: nonzero -> ordinary char, loop for the next key; zero -> the user typed a literal line feed, so reset the echo column to 0 (LD (CURSOR_POS),A with A == 0), echo a CR to physically return the cursor, and fall into the after-LF poll. This lets a multi-line reply be typed with embedded LFs while keeping the column count correct.
; ----------------------------------------------------------------------
INLIN_APPEND_ECHO:
        LD A,C
        ; append the accepted char to the line buffer and advance the pointer and count
        LD (HL),C
        INC HL
        INC B
INLIN_ECHO_AND_TEST_LF:
        CALL OUTCHR
        ; was the echoed char a hard LF? (A becomes 0 iff char == $0A)
        SUB $0A
        JP NZ,INLIN_GETCH
        ; literal LF typed: reset the echo column to 0 (A is 0 here), then echo a CR to return the cursor
        LD (CURSOR_POS),A
        LD A,$0D
        CALL OUTCHR
; ----------------------------------------------------------------------
; INLIN_WAIT_AFTER_LF -- pause after a hard LF until the next real key
;   In:        (none) -- polls the console via INCHR
;   Out:       on CR ($0D) resumes the per-char loop at INLIN_GETCH (the CR after a typed LF is swallowed, not treated as end-of-line); on any other non-null key re-enters the dispatcher at INLIN_DISPATCH to process it; $00 keys are ignored
;   Clobbers:  A
;   Algorithm: After the editor echoes a typed line feed, terminals commonly send a paired CR; this loop absorbs it. Read keys (INCHR), skipping NULs (OR A; JR Z back to self). A CR is consumed silently by looping back to fetch another key. Anything else is a genuine keystroke and is routed back through the full control-char dispatch (INLIN_DISPATCH) so it edits the line normally.
; ----------------------------------------------------------------------
INLIN_WAIT_AFTER_LF:
        CALL INCHR
        ; spin until a non-null key arrives
        OR A
        JR Z,INLIN_WAIT_AFTER_LF
        ; swallow a CR that pairs with the LF just typed; any other key is re-dispatched as normal input
        CP $0D
        JP Z,INLIN_GETCH
        JP INLIN_DISPATCH
; ----------------------------------------------------------------------
; INLIN_CR_FINISH -- Enter/CR pressed: terminate and return the edited line
;   In:        HL = next write slot just past the last char in BUF, B = char count, L_0C93 ($0C93) = the INPUT-prompt newline-suppress flag (0 = emit the trailing newline, nonzero = suppress it; set by INPUT_PROMPT_SEP when the prompt string was followed by ';')
;   Out:       Both paths $00-terminate the buffer and return HL = BUF_INPUT_RESET_PTR ($0A0D, the ',' byte one before BUF). They differ only in the trailing newline: flag clear -> tail-calls PRINT_CRLF_IF_COL_1 which $00-terminates, sets HL = BUF_INPUT_RESET_PTR, then UNCONDITIONALLY emits CR+LF and resets the print state; flag set -> $00-terminates, sets HL = BUF_INPUT_RESET_PTR, and returns WITHOUT emitting CR+LF.
;   Clobbers:  A; writes the terminating $00 at (HL)
;   Algorithm: [RE] Read L_0C93. If clear, ordinary line entry: defer to PRINT_CRLF_IF_COL_1 (terminate, point HL at the leading ',', echo the closing CRLF, reset print state). If set, the INPUT statement asked to suppress the auto-newline (';' separator), so terminate, point HL at the leading ',', and return immediately with no CRLF. UNKNOWN: whether any path additionally pre-seeds BUF with a default reply; what is OBSERVED is only the newline-suppress behaviour and that HL = $0A0D in both cases (the ',' acts as a leading field separator when the returned line is re-scanned). NOTE: PRINT_CRLF_IF_COL_1 is NOT the column-conditional CRLF (that is PRINT_CRLF_IF_COL, no _1 suffix); _1 always emits the newline.
; ----------------------------------------------------------------------
INLIN_CR_FINISH:
        ; newline-suppress flag? (set by INPUT_PROMPT_SEP when the prompt string ended with ';')
        LD A,(L_0C93)
        OR A
        JP Z,PRINT_CRLF_IF_COL_1
        XOR A
        LD (HL),A
        ; return HL at the ',' one byte before BUF, so the re-scan sees a leading field separator
        LD HL,BUF_INPUT_RESET_PTR
        RET
; ----------------------------------------------------------------------
; INPUT_PROMPT_SEP -- INPUT/LINE-INPUT prompt separator: ';' after the prompt suppresses the auto newline
;   In:        A = current source char from CHRGET (the char following the prompt-string literal in an INPUT statement)
;   Out:       clears L_0C93 ($0C93) unconditionally; if A == ';' ($3B) re-stores A (= $3B, nonzero) into L_0C93 to set the flag and tail-jumps to CHRGET to advance past the ';'; if A != ';' returns with A preserved and the flag cleared
;   Clobbers:  L_0C93; A is preserved across the unconditional clear (PUSH AF/POP AF)
;   Algorithm: Parses the separator between an INPUT prompt string and its variable list. Default: clear L_0C93 (enable the normal trailing prompt/newline). If the char is ';' the BASIC convention is to suppress that trailing newline, so store the char ($3B, nonzero) into L_0C93 to set the flag and CHRGET past the ';'. A is saved around the unconditional clear so the CP $3B still sees the original char. [RE] L_0C93 is a shared scratch byte; here it carries the INPUT newline-suppress flag, later read by INLIN_CR_FINISH.
; ----------------------------------------------------------------------
INPUT_PROMPT_SEP:
        PUSH AF
        ; default: clear the newline-suppress flag (normal trailing newline enabled)
        LD A,$00
        LD (L_0C93),A
        POP AF
        ; ';' after the prompt string suppresses the newline -- set the flag (store the char) and skip the ';'
        CP $3B
        RET NZ
        LD (L_0C93),A
        JP CHRGET
; ----------------------------------------------------------------------
; INLIN_SAVE_COLUMN -- snapshot the prompt column as the Tab-stop origin for this input line
;   In:        CURSOR_POS ($0B11) = current print column (where the prompt left the cursor)
;   Out:       copies CURSOR_POS into the self-stored data cell at INLIN_TAB_BASE_COLUMN ($719D); returns
;   Clobbers:  A, the byte at INLIN_TAB_BASE_COLUMN
;   Algorithm: Called once at INLIN entry. The backspace-over-Tab logic counts buffer columns to find the previous tab stop, but column 0 of the buffer did not start at screen column 0 -- it started wherever the prompt ended. This stores that starting column into the cell INLIN_BACKSPACE_TAB_AT_BUFSTART reads to bias the count so Tab erasure backs up to the correct physical column. [RE] The destination ($719D) is a one-byte data cell (a $00/NOP) used purely as storage, not executed code.
; ----------------------------------------------------------------------
INLIN_SAVE_COLUMN:
        LD A,(CURSOR_POS)
        LD (INLIN_TAB_BASE_COLUMN),A
        RET
; ----------------------------------------------------------------------
; INLIN_BACKSPACE -- delete the last buffered char, undoing its on-screen echo correctly
;   In:        HL = next write slot one past the last stored char in BUF, B = remaining 1-based char count (the caller has ALREADY decremented it for this deletion before calling), INLIN_TAB_BASE_COLUMN ($719D) = prompt start column
;   Out:       backs the visual cursor over exactly one logical input char and leaves HL = the deleted char's slot (= entry HL - 1, the new next-write position); for a plain char erases one cell, for a Tab erases back to the previous 8-aligned tab stop, for a LF re-echoes the surviving line; BC and DE are preserved (HL is intentionally moved back one slot -- it is NOT preserved)
;   Clobbers:  A internally; HL moved back one slot; BC/DE saved and restored on each sub-path
;   Algorithm: DEC HL, then A = (HL) = the char being deleted. Three cases by char class:
;     (1) LF ($0A): the deleted char ended a physical line, so there is no single cell to rub out. PUSH BC, DEC B; if the buffer is now empty (B == 0) just POP BC and return; otherwise re-echo the whole surviving buffer from BUF for B chars (INLIN_REDISPLAY_LINE) so the screen matches the shortened line, then POP BC and return. On this path HL ends at BUF+B (the new write slot).
;     (2) Tab ($09): a Tab expanded to a variable number of spaces. PUSH HL/BC/DE, D = 0, scan backward (INLIN_BACKSPACE_TAB_SCAN) from the Tab counting intervening columns in D until the previous Tab/LF or buffer start; at buffer start fold in the saved prompt column (INLIN_BACKSPACE_TAB_AT_BUFSTART). Then erase 8 - (D mod 8) cells, computed via AND $07 / CPL / ADD $09 (INLIN_BACKSPACE_TAB_ERASE). POP DE/BC/HL.
;     (3) any other char (INLIN_BACKSPACE_ONE_CHAR): A = 1 and erase exactly one cell via INLIN_ERASE_N_COLS.
;   [RE] Tab stops are every 8 columns; INLIN_ERASE_N_COLS performs the physical BS/space/BS rubout.
; ----------------------------------------------------------------------
INLIN_BACKSPACE:
        DEC HL
        LD A,(HL)
        ; deleting over a LF: no single cell to rub out, re-echo the surviving line instead
        CP $0A
        JR NZ,INLIN_BACKSPACE_NOT_LF
        PUSH BC
        DEC B
        JR Z,INLIN_BACKSPACE_LF_DONE
        ; re-echo the whole surviving buffer (B chars) so the screen matches the shortened line
        LD HL,BUF
; ----------------------------------------------------------------------
; INLIN_REDISPLAY_LINE -- re-echo B buffered chars starting at HL
;   In:        HL = first char to echo (BUF on the LF-backspace path), B = count of chars to echo
;   Out:       OUTCHRs each char to the console, HL advanced past them (HL = start + B), B = 0; falls through into INLIN_BACKSPACE_LF_DONE which pops BC and returns
;   Clobbers:  A, HL, B
;   Algorithm: DJNZ loop echoing the buffer contents to rebuild the visible line. Used by INLIN_BACKSPACE when the deleted char was a LF, where rubbing out single cells cannot work, so the surviving line is reprinted.
; ----------------------------------------------------------------------
INLIN_REDISPLAY_LINE:
        LD A,(HL)
        CALL OUTCHR
        INC HL
        DJNZ INLIN_REDISPLAY_LINE
INLIN_BACKSPACE_LF_DONE:
        POP BC
        RET
INLIN_BACKSPACE_NOT_LF:
        CP $09
        JR NZ,INLIN_BACKSPACE_ONE_CHAR
        PUSH HL
        PUSH BC
        PUSH DE
        LD D,$00
INLIN_BACKSPACE_TAB_SCAN:
        DEC HL
        LD A,(HL)
        CP $09
        JR Z,INLIN_BACKSPACE_TAB_ERASE
        CP $0A
        JR Z,INLIN_BACKSPACE_TAB_ERASE
        DEC B
        JR Z,INLIN_BACKSPACE_TAB_AT_BUFSTART
        INC D
        JR INLIN_BACKSPACE_TAB_SCAN
INLIN_BACKSPACE_TAB_AT_BUFSTART:
        LD A,(INLIN_TAB_BASE_COLUMN)
        ADD A,D
        LD D,A
INLIN_BACKSPACE_TAB_ERASE:
        LD A,D
        AND $07
        CPL
        ADD A,$09
        CALL INLIN_ERASE_N_COLS
        POP DE
        POP BC
        POP HL
        RET
INLIN_BACKSPACE_ONE_CHAR:
        LD A,$01
; ----------------------------------------------------------------------
; INLIN_ERASE_N_COLS -- visually rub out A character cells
;   In:        A = number of cells to erase
;   Out:       for each cell emits BS, space, BS ($08/$20/$08) so A characters disappear from the display; BC preserved
;   Clobbers:  A; B is used internally as the loop counter but the caller's BC is saved and restored
;   Algorithm: PUSH BC, set B = A, then loop A times sending $08/$20/$08 -- the destructive-backspace sequence that erases the character to the left and leaves the cursor on the now-blank cell. POP BC, return. Called for ordinary single-char rubout (A = 1 via INLIN_BACKSPACE_ONE_CHAR) and for Tab rubout (A = columns to the previous tab stop). [RE] The byte at $719D immediately after this loop is the separate one-byte data cell INLIN_TAB_BASE_COLUMN (the prompt-column store), not part of this routine.
; ----------------------------------------------------------------------
INLIN_ERASE_N_COLS:
        PUSH BC
        ; erase A cells; B is the loop counter
        LD B,A
INLIN_ERASE_N_COLS_LOOP:
        ; destructive backspace: BS, space, BS leaves one blank cell with the cursor on it
        LD A,$08
        CALL OUTCHR
        LD A,$20
        CALL OUTCHR
        LD A,$08
        CALL OUTCHR
        DJNZ INLIN_ERASE_N_COLS_LOOP
        POP BC
        RET
INLIN_TAB_BASE_COLUMN:
        NOP
; ----------------------------------------------------------------------
; STMT_WHILE -- WHILE statement handler (token $AF): open a WHILE/WEND loop and push its stack frame.
;   In:        HL -> BASIC text after WHILE (the loop condition expression).
;   Out:       A WHILE frame (saved SAVTXT, loop key, condition text pointer) is pushed; any stale frame for the same loop is discarded; control evaluates the condition (falls into STMT_WEND_1). The matching WEND has been located ahead by BLOCK_SCAN_WHILE (WHILE without WEND error if absent).
;   Clobbers:  AF,BC,DE,HL,SP; SAVSTK; L_0B4E (loop-key cell, shared with FOR).
;   Algorithm: Record the condition's text pointer as this loop's key in L_0B4E. BLOCK_SCAN_WHILE forward-scans the program for the matching WEND (raising WHILE without WEND, err 29, on run-off). CHRGET past the marker; WHILE_FIND_FRAME walks the stack (skipping nested $82 FOR frames) for an existing $AF WHILE frame of this same loop (a re-entry, e.g. a GOTO back in): on a match (Z) rewind SP/SAVSTK to drop the stale frame and its nested frames. Then (STMT_WHILE_1) push the saved SAVTXT, the loop key, and the condition pointer to build the frame, and join STMT_WEND_1 to evaluate the condition for the first iteration.
; ----------------------------------------------------------------------
STMT_WHILE:
        LD (L_0B4E),HL
        ; forward-scan for the matching WEND now (WHILE without WEND error if the program runs out)
        CALL BLOCK_SCAN_WHILE
        CALL CHRGET
        EX DE,HL
        ; look for an existing frame of THIS loop (a re-entry); a match means we jumped back in
        CALL WHILE_FIND_FRAME
        INC SP
        INC SP
        JR NZ,STMT_WHILE_1
        ADD HL,BC
        LD SP,HL
        LD (SAVSTK),HL
; ----------------------------------------------------------------------
; STMT_WHILE_1 -- build the WHILE stack frame, then fall into the condition test.
;   In:        DE = the loop condition's text pointer; L_0B4E = this loop's key; SAVTXT = current source-line pointer; SP positioned (stale frame already dropped by STMT_WHILE).
;   Out:       Three words pushed onto the stack (saved SAVTXT, loop key, condition pointer). Falls into STMT_WEND_1 to evaluate the condition.
;   Clobbers:  HL,SP.
;   Algorithm: PUSH (SAVTXT) so a WEND can restore the line, PUSH the loop key (L_0B4E), PUSH DE (the condition text pointer re-evaluated each pass), then JR into STMT_WEND_1 (FRMEVL on the condition). [RE] The $AF marker byte that WHILE_FIND_FRAME later matches is NOT pushed here -- it is a separate 1-byte tag pushed by STMT_WEND_1 (LD BC,$00AF / PUSH BC / INC SP) on each iteration the condition is true.
; ----------------------------------------------------------------------
STMT_WHILE_1:
        LD HL,(SAVTXT)
        PUSH HL
        LD HL,(L_0B4E)
        PUSH HL
        ; frame the condition text pointer so WEND can re-evaluate it each iteration
        PUSH DE
        JR STMT_WEND_1
; ----------------------------------------------------------------------
; STMT_WEND -- WEND statement handler (token $B0): re-evaluate the WHILE condition; loop back if true, exit if false.
;   In:        On arrival the Z flag reflects the dispatcher's end-of-statement check (Z = nothing after WEND); HL -> text after WEND. The runtime stack holds the open WHILE frame(s).
;   Out:       Locates the innermost matching WHILE frame (WHILE_FIND_FRAME); WEND without WHILE error if none. Restores SP/SAVSTK to that frame, sets SAVTXT to the WHILE condition's text, and falls into STMT_WEND_1 to test the condition: nonzero -> re-enter the loop body; zero -> pop the frame and continue after WEND.
;   Clobbers:  AF,BC,DE,HL,SP; SAVSTK; SAVTXT; L_0C71.
;   Algorithm: Reject trailing text (SYNTAX ERROR). WHILE_FIND_FRAME scans the stack (skipping nested $82 FOR frames) for the $AF WHILE frame whose key matches the current WEND position; WEND without WHILE if absent. Rewind SP/SAVSTK to the frame. Save the current SAVTXT (the source-line pointer) into L_0C71 so STMT_WEND_2 can restore it on loop exit, then read the framed words to reload SAVTXT = the WHILE condition's text pointer, and fall into STMT_WEND_1.
; ----------------------------------------------------------------------
STMT_WEND:
        ; WEND takes no operand: trailing text is a syntax error
        JP NZ,RAISE_SYNTAX_ERROR
        EX DE,HL
        ; find the open WHILE frame this WEND closes; none -> WEND without WHILE
        CALL WHILE_FIND_FRAME
        JP NZ,WEND_NO_WHILE_ERR
        LD SP,HL
        LD (SAVSTK),HL
        EX DE,HL
        LD HL,(SAVTXT)
        ; save the current SAVTXT (source-line pointer) into L_0C71 so the loop-exit path (STMT_WEND_2) can restore it
        LD (L_0C71),HL
        EX DE,HL
        INC HL
        INC HL
        LD E,(HL)
        INC HL
        LD D,(HL)
        INC HL
        LD A,(HL)
        INC HL
        LD H,(HL)
        LD L,A
        ; set the source pointer back to the WHILE condition so it is re-evaluated
        LD (SAVTXT),HL
        EX DE,HL
; ----------------------------------------------------------------------
; STMT_WEND_1 -- evaluate the WHILE condition and decide loop-continue vs loop-exit.
;   In:        HL -> the WHILE condition's text pointer (set by STMT_WHILE_1 on entry, or by STMT_WEND after restoring the frame). The WHILE frame is on the stack.
;   Out:       If the condition is zero/false branch to STMT_WEND_2 to pop the frame and leave the loop. Otherwise re-push the $AF WHILE marker and re-enter the loop body via the shared per-statement executor (STMT_FOR_7).
;   Clobbers:  AF,BC,HL,SP.
;   Algorithm: FRMEVL_NOPAREN evaluates the condition into the FAC; FP_TEST_SIGN reduces it to a sign/zero test. If false (Z), STMT_WEND_2 unwinds. If true, push the $AF marker byte (LD BC,$00AF / LD B,C / PUSH BC / INC SP keeps just the marker) so WHILE_FIND_FRAME can locate the frame, and JP STMT_FOR_7 -- the shared 'execute the next statement' re-entry -- so the loop body runs with the console poll and CONT/error bookkeeping.
; ----------------------------------------------------------------------
STMT_WEND_1:
        CALL FRMEVL_NOPAREN
        PUSH HL
        ; reduce the WHILE condition to true(nonzero)/false(zero)
        CALL FP_TEST_SIGN
        POP HL
        ; condition false: leave the loop
        JR Z,STMT_WEND_2
        LD BC,$00AF
        LD B,C
        PUSH BC
        INC SP
        ; condition true: re-enter the loop body via the shared per-statement executor
        JP STMT_FOR_7
; ----------------------------------------------------------------------
; STMT_WEND_2 -- WHILE loop exit: drop the WHILE frame and resume execution after WEND.
;   In:        L_0C71 = the saved SAVTXT (source-line pointer) stashed by STMT_WEND. The WHILE frame (3 words) is on top of the stack.
;   Out:       SAVTXT restored to the saved source-line pointer; the WHILE frame popped (condition ptr, key, saved SAVTXT); control continues with the statement after WEND via STMT_FOR_7.
;   Clobbers:  AF,HL,SP; SAVTXT.
;   Algorithm: Reload SAVTXT from L_0C71, POP the three frame words off the stack to discard the loop frame, and JP STMT_FOR_7 to execute the statement following WEND.
; ----------------------------------------------------------------------
STMT_WEND_2:
        ; restore SAVTXT from the source-line pointer saved by STMT_WEND
        LD HL,(L_0C71)
        LD (SAVTXT),HL
        ; discard the WHILE frame (condition ptr / key / saved SAVTXT) now that the loop is done
        POP HL
        POP AF
        POP AF
        JP STMT_FOR_7
; [RE] WHILE/WEND helper: walk the runtime stack frames (skipping FOR entries, marker $82) looking for a matching WHILE frame (marker $AF) whose loop-text pointer matches; returns the frame in HL with Z set on match.
WHILE_FIND_FRAME:
        LD HL,$0004
        ADD HL,SP
WHILE_FIND_FRAME_1:
        LD A,(HL)
        INC HL
        LD BC,$0082
        CP C
        JR NZ,WHILE_FIND_FRAME_2
        LD BC,$0010
        ADD HL,BC
        JR WHILE_FIND_FRAME_1
WHILE_FIND_FRAME_2:
        LD BC,$00AF
        CP C
WHILE_FIND_FRAME_3:
        RET NZ
        PUSH HL
        LD C,(HL)
        INC HL
        LD B,(HL)
        LD H,B
        LD L,C
        CALL CMP_HL_DE
        POP HL
        LD BC,$0006
        RET Z
        ADD HL,BC
        JR WHILE_FIND_FRAME_1
; [RE] WEND without matching WHILE: raise coded error $1E ('WEND without WHILE') via the error dispatcher at RAISE_ERROR.
WEND_NO_WHILE_ERR:
        LD DE,ERR_WEND_WITHOUT_WHILE
        JP RAISE_ERROR
; ----------------------------------------------------------------------
; STMT_CALL -- CALL statement handler (token $B1): invoke an external machine-code routine, with two forms (native Z-80, or '%'-prefixed SoftCard 6502 call).
;   In:        HL -> BASIC text after CALL: "[%] addr-expr [(arg[,arg...])]". A leading '%' ($25) selects the SoftCard 6502-call form.
;   Out:       The named address is called as a subroutine. Native Z-80 form: arguments (CALL addr(v1,v2,...)) are resolved by PTRGET and their addresses passed in HL/DE/BC or via a parameter block; control transfers to the routine which returns via STMT_CALL_4. 6502 form: jumps to STMT_CALL_INVOKE_6502 to stage A/X/Y and bridge to the 6502.
;   Clobbers:  AF,BC,DE,HL,SP; PTRGET_SUBSCRIPT_FLAG; L_0C93 (call-target address); OPEN_RESUME_TEXT_PTR.
;   Algorithm: Set PTRGET_SUBSCRIPT_FLAG=$80. Peek for a leading '%' (CP $25; PUSH AF; CALL Z,CHRGET past it); the saved Z flag later selects the 6502 path. PTRGET + FRMEVL_TEST_TYPE + FP_ARG_SETUP1 + FN_CINT evaluate the address expression to a 16-bit integer, stored in L_0C93. If '%' was present (POP AF, Z) JP STMT_CALL_INVOKE_6502. Otherwise the native path reserves stack room (CHECK_STACK_ROOM C=$20), opens a 64-byte parameter area below SP (LD HL,$FFC0 / ADD HL,SP / LD SP,HL), and if an argument list follows ('(') resolves each argument's address (STMT_CALL_1); then STMT_CALL_2/_3 set up a return into STMT_CALL_4 and jump to the target in L_0C93.
;   Note:      [RE] '%' for the SoftCard 6502-call form is inferred from the dispatch into STMT_CALL_INVOKE_6502 (which stages the Apple $45/$46/$47 register cells); the exact published syntax letter is not confirmed from the bytes.
; ----------------------------------------------------------------------
STMT_CALL:
        LD A,$80
        LD (PTRGET_SUBSCRIPT_FLAG),A
        LD A,(HL)
        ; leading '%' selects the SoftCard 6502-call form (vs a native Z-80 CALL)
        CP $25
        PUSH AF
        CALL Z,CHRGET
        CALL PTRGET_1+1
        EX (SP),HL
        PUSH HL
        EX DE,HL
        CALL FRMEVL_TEST_TYPE
        CALL FP_ARG_SETUP1
        ; coerce the address expression to a 16-bit integer = the call target
        CALL FN_CINT
        ; stash the resolved call-target address for the invoke step
        LD (L_0C93),HL
        POP AF
        ; '%' present: hand off to the 6502 RPC path
        JP Z,STMT_CALL_INVOKE_6502
        LD C,$20
        CALL CHECK_STACK_ROOM
        POP DE
        ; open a 64-byte parameter area below the stack for the argument-address block
        LD HL,$FFC0
        ADD HL,SP
        LD SP,HL
        EX DE,HL
        LD C,$20
        DEC HL
        CALL CHRGET
        LD (OPEN_RESUME_TEXT_PTR),HL
        JR Z,STMT_CALL_3
        CALL SYNCHR
        DEFB    '('                      ; inline char arg consumed by the preceding CALL
; ----------------------------------------------------------------------
; STMT_CALL_1 -- native CALL argument loop: resolve each argument variable and push its address into the parameter block.
;   In:        HL -> text at an argument expression; DE -> next free slot in the parameter area; C = remaining slot count; '(' already consumed.
;   Out:       Each comma-separated argument variable is resolved by PTRGET and its address stored (low,high) into the parameter block; HL advanced past the list; C decremented per argument. On the non-comma char (closing ')') falls into STMT_CALL_2.
;   Clobbers:  AF,BC,DE,HL.
;   Algorithm: For each argument: PUSH BC/DE, PTRGET the variable -> address in DE, store it into the parameter slot (EX (SP),HL then LD (HL),E / INC HL / LD (HL),D), POP back DE/BC. If the next char is ',', DEC C and CHRGET past it and loop; otherwise drop to STMT_CALL_2 to require ')'. The parameter block becomes an array of pointers the called routine can read.
; ----------------------------------------------------------------------
STMT_CALL_1:
        PUSH BC
        PUSH DE
        ; resolve this argument variable to its storage address
        CALL PTRGET_1+1
        EX (SP),HL
        ; store the argument's address (low,high) into the parameter block
        LD (HL),E
        INC HL
        LD (HL),D
        INC HL
        EX (SP),HL
        POP DE
        POP BC
        LD A,(HL)
        CP $2C
        JR NZ,STMT_CALL_2
        ; one fewer parameter slot remaining
        DEC C
        CALL CHRGET
        JR STMT_CALL_1
; ----------------------------------------------------------------------
; STMT_CALL_2 -- native CALL finalize: require ')', compute the argument count, and hand the parameter block to the routine.
;   In:        HL -> text at the closing ')'; C = remaining-slot counter (so $21-C = how many arguments were supplied); the parameter-address block built by STMT_CALL_1 is below SP.
;   Out:       OPEN_RESUME_TEXT_PTR = text after ')'. For 1/2/3 arguments the routine pops the corresponding argument addresses into HL/DE/BC; for more, BC -> the parameter block. Falls into STMT_CALL_3 which sets up the return-to-STMT_CALL_4 trampoline and jumps to the target.
;   Clobbers:  AF,BC,DE,HL,SP; OPEN_RESUME_TEXT_PTR.
;   Algorithm: SYNCHR ')', save the post-call text pointer. Derive the argument count from $21-C (DEC A chain): 1 arg -> POP HL (HL=&arg1); 2 args -> also POP DE; 3 args -> also POP BC; passing the three common cases in registers. For >3 arguments, point BC at the parameter block on the stack (LD HL,$0002 / ADD HL,SP). STMT_CALL_3 then pushes STMT_CALL_4 as the return address and the target (L_0C93) and RETs into the routine.
;   Note:      [RE] This register-passing convention (1=HL, 2=+DE, 3=+BC, >3 via BC->block) is the standard MS BASIC USR/CALL argument protocol; it is read from the DEC A / POP chain here.
; ----------------------------------------------------------------------
STMT_CALL_2:
        CALL SYNCHR
        DEFB    ')'                      ; inline char arg consumed by the preceding CALL
        LD (OPEN_RESUME_TEXT_PTR),HL
        ; compute the argument count from the slot counter C ($21 - C)
        LD A,$21
        SUB C
        ; 1 argument: pass its address in HL
        POP HL
        DEC A
        JR Z,STMT_CALL_3
        ; 2nd argument's address in DE
        POP DE
        DEC A
        JR Z,STMT_CALL_3
        ; 3rd argument's address in BC
        POP BC
        DEC A
        JR Z,STMT_CALL_3
        PUSH BC
        PUSH HL
        ; more than 3 arguments: point BC at the parameter-address block on the stack
        LD HL,$0002
        ADD HL,SP
        LD B,H
        LD C,L
        POP HL
STMT_CALL_3:
        PUSH HL
        LD HL,STMT_CALL_4
        EX (SP),HL
        PUSH HL
        LD HL,(L_0C93)
        EX (SP),HL
        RET
STMT_CALL_4:
        LD HL,(SAVSTK)
        LD SP,HL
        LD HL,(OPEN_RESUME_TEXT_PTR)
        JP STMT_FOR_7
; [RE] CHAIN statement handler (token $B4): load and run another program, optionally preserving variables.
STMT_CHAIN:
        XOR A
        LD (CHAIN_PRESERVE_FLAG),A
        LD (L_0C9B),A
        LD A,(HL)
        LD DE,$00BE
        CP E
        JR NZ,STMT_CHAIN_1
        LD (CHAIN_PRESERVE_FLAG),A
        INC HL
STMT_CHAIN_1:
        DEC HL
        CALL CHRGET
        CALL LOAD_OPEN_INPUT
        PUSH HL
        LD HL,$0000
        LD (L_0CA1),HL
        POP HL
        DEC HL
        CALL CHRGET
        JP Z,STMT_CHAIN_5
        CALL SYNCHR
        DEFB    ','                      ; inline char arg consumed by the preceding CALL
        CP $2C
        JR Z,STMT_CHAIN_2
        CALL FRMEVL_NOPAREN
        PUSH HL
        CALL GETADR
        LD (L_0CA1),HL
        POP HL
        DEC HL
        CALL CHRGET
        JR Z,STMT_CHAIN_5
STMT_CHAIN_2:
        CALL SYNCHR
        DEFB    ','                      ; inline char arg consumed by the preceding CALL
        LD DE,$00A6
        CP E
        JR Z,STMT_CHAIN_3
        CALL SYNCHR
        DEFB    'A'                      ; inline char arg consumed by the preceding CALL
        CALL SYNCHR
        DEFB    'L'                      ; inline char arg consumed by the preceding CALL
        CALL SYNCHR
        DEFB    'L'                      ; inline char arg consumed by the preceding CALL
        JP Z,CHAIN_SCAN_STRINGS
        CALL SYNCHR
        DEFB    ','                      ; inline char arg consumed by the preceding CALL
        CP E
        JP NZ,RAISE_SYNTAX_ERROR
        OR A
STMT_CHAIN_3:
        PUSH AF
        LD (L_0C9B),A
        CALL CHRGET
        CALL SCAN_LINE_RANGE
        PUSH BC
        CALL RENUM_FIXUP_IF_PENDING
        POP BC
        POP DE
        PUSH BC
        LD H,B
        LD L,C
        LD (L_0C9E),HL
        CALL FNDLIN
        JR NC,STMT_CHAIN_4
        LD D,H
        LD E,L
        LD (L_0C9C),HL
        POP HL
        CALL CMP_HL_DE
STMT_CHAIN_4:
        JP NC,ERROR_FC
        POP AF
        JP NZ,CHAIN_SCAN_STRINGS
STMT_CHAIN_5:
        LD HL,(TXTTAB)
        DEC HL
STMT_CHAIN_6:
        INC HL
        LD A,(HL)
        INC HL
        OR (HL)
        JP Z,CHAIN_MARK_VAR_6
        INC HL
        LD E,(HL)
        INC HL
        LD D,(HL)
        EX DE,HL
        LD (SAVTXT),HL
        EX DE,HL
STMT_CHAIN_7:
        CALL CHRGET
STMT_CHAIN_8:
        OR A
        JR Z,STMT_CHAIN_6
        CP $3A
        JR Z,STMT_CHAIN_7
        LD DE,$00B3
        CP E
        JR Z,STMT_CHAIN_9
        CALL CHRGET
        CALL STMT_DATA
        DEC HL
        JR STMT_CHAIN_7
STMT_CHAIN_9:
        CALL CHRGET
        JR Z,STMT_CHAIN_8
STMT_CHAIN_10:
        PUSH HL
        LD A,$01
        LD (PTRGET_SUBSCRIPT_FLAG),A
        CALL PTRGET_1+1
        JR Z,CHAIN_MARK_VAR_2
        LD A,B
        OR $80
        LD B,A
        XOR A
        CALL PTRGET_SEARCH_22+1
        LD A,$00
        LD (PTRGET_SUBSCRIPT_FLAG),A
        JR NZ,STMT_CHAIN_11
        LD A,(HL)
        CP $28
        JR NZ,STMT_CHAIN_12
        POP AF
        JR CHAIN_MARK_VAR_4
STMT_CHAIN_11:
        LD A,(HL)
        CP $28
        JP Z,ERROR_FC
STMT_CHAIN_12:
        POP HL
        CALL PTRGET_1+1
STMT_CHAIN_13:
        LD A,D
        OR E
        JR NZ,STMT_CHAIN_15
        LD A,B
        OR $80
        LD B,A
        LD A,(VALTYP)
        LD D,A
        CALL PTRGET_SEARCH
STMT_CHAIN_14:
        LD A,D
        OR E
        JP Z,ERROR_FC
STMT_CHAIN_15:
        PUSH HL
        LD B,D
        LD C,E
        LD HL,CHAIN_MARK_VAR_3
        PUSH HL
; [RE] CHAIN-ALL/COMMON helper: set the high bit (preserve flag) on a named variable so the post-CHAIN cleanup keeps it across the program reload.
CHAIN_MARK_VAR:
        DEC BC
CHAIN_MARK_VAR_1:
        LD A,(BC)
        DEC BC
        OR A
        JP M,CHAIN_MARK_VAR_1
        LD A,(BC)
        OR $80
        LD (BC),A
        RET
CHAIN_MARK_VAR_2:
        LD (PTRGET_SUBSCRIPT_FLAG),A
        LD A,(HL)
        CP $28
        JR NZ,STMT_CHAIN_12
        EX (SP),HL
        DEC BC
        DEC BC
        CALL CHAIN_MARK_VAR
CHAIN_MARK_VAR_3:
        POP HL
        DEC HL
        CALL CHRGET
        JP Z,STMT_CHAIN_8
        CP $28
        JR NZ,CHAIN_MARK_VAR_5
CHAIN_MARK_VAR_4:
        CALL CHRGET
        CALL SYNCHR
        DEFB    ')'                      ; inline char arg consumed by the preceding CALL
        JP Z,STMT_CHAIN_8
CHAIN_MARK_VAR_5:
        CALL SYNCHR
        DEFB    ','                      ; inline char arg consumed by the preceding CALL
        JP STMT_CHAIN_10
CHAIN_MARK_VAR_6:
        LD HL,(ARYTAB)
        EX DE,HL
        LD HL,(VARTAB)
CHAIN_MARK_VAR_7:
        CALL CMP_HL_DE
        JR Z,CHAIN_SCAN_ARRAYS
        PUSH HL
        LD C,(HL)
        INC HL
        INC HL
        LD A,(HL)
        OR A
        PUSH AF
        AND $7F
        LD (HL),A
        INC HL
        CALL VARTAB_SKIP_ENTRY
        LD B,$00
        ADD HL,BC
        POP AF
        POP BC
        JP M,CHAIN_MARK_VAR_7
        PUSH BC
        CALL CHAIN_COPY_VAR_BLOCK
        LD HL,(ARYTAB)
        ADD HL,DE
        LD (ARYTAB),HL
        EX DE,HL
        POP HL
        JR CHAIN_MARK_VAR_7
; [RE] CHAIN preserve pass: relocate kept simple/array variables, copying their bytes up out of the way (via CMP_HL_DE compare and block move) and adjusting the variable/array area pointers ($0B71/$0B73) so they survive the new program load.
CHAIN_COPY_VAR_BLOCK:
        EX DE,HL
        LD HL,(STREND)
CHAIN_COPY_VAR_BLOCK_1:
        CALL CMP_HL_DE
        LD A,(DE)
        LD (BC),A
        INC DE
        INC BC
        JR NZ,CHAIN_COPY_VAR_BLOCK_1
        LD A,C
        SUB L
        LD E,A
        LD A,B
        SBC A,H
        LD D,A
        DEC DE
        DEC BC
        LD H,B
        LD L,C
        LD (STREND),HL
        RET
; [RE] CHAIN preserve pass over arrays: walk the array table, temporarily clearing each entry's preserve bit, summing sizes (VARTAB_SKIP_ENTRY) and relocating the kept ones.
CHAIN_SCAN_ARRAYS:
        LD HL,(STREND)
        EX DE,HL
CHAIN_COPY_VAR_BLOCK_3:
        CALL CMP_HL_DE
        JR Z,CHAIN_SCAN_STRINGS
        PUSH HL
        INC HL
        INC HL
        LD A,(HL)
        OR A
        PUSH AF
        AND $7F
        LD (HL),A
        INC HL
        CALL VARTAB_SKIP_ENTRY
        LD C,(HL)
        INC HL
        LD B,(HL)
        INC HL
        ADD HL,BC
        POP AF
        POP BC
        JP M,CHAIN_COPY_VAR_BLOCK_3
        PUSH BC
        CALL CHAIN_COPY_VAR_BLOCK
        EX DE,HL
        POP HL
        JR CHAIN_COPY_VAR_BLOCK_3
; [RE] CHAIN preserve pass over string variables/arrays: walk simple-variable and array storage ($0B6F/$0B71), freeing/relocating string descriptors (type 3) of kept variables via CHAIN_MOVE_STRING_VAR.
CHAIN_SCAN_STRINGS:
        LD HL,(VARTAB)
CHAIN_COPY_VAR_BLOCK_5:
        EX DE,HL
        LD HL,(ARYTAB)
        EX DE,HL
        CALL CMP_HL_DE
        JR Z,CHAIN_COPY_VAR_BLOCK_8
        LD A,(HL)
        INC HL
        INC HL
        INC HL
        PUSH AF
        CALL VARTAB_SKIP_ENTRY
        POP AF
        CP $03
        JR NZ,CHAIN_COPY_VAR_BLOCK_6
        CALL CHAIN_MOVE_STRING_VAR
        XOR A
CHAIN_COPY_VAR_BLOCK_6:
        LD E,A
        LD D,$00
        ADD HL,DE
        JR CHAIN_COPY_VAR_BLOCK_5
CHAIN_COPY_VAR_BLOCK_7:
        POP BC
CHAIN_COPY_VAR_BLOCK_8:
        EX DE,HL
        LD HL,(STREND)
        EX DE,HL
        CALL CMP_HL_DE
        JR Z,CHAIN_COMPACT_STRINGS
        LD A,(HL)
        INC HL
        INC HL
        PUSH AF
        INC HL
        CALL VARTAB_SKIP_ENTRY
        LD C,(HL)
        INC HL
        LD B,(HL)
        INC HL
        POP AF
        PUSH HL
        ADD HL,BC
        CP $03
        JR NZ,CHAIN_COPY_VAR_BLOCK_7
        LD (PRUSING_FORMAT_FLAGS),HL
        POP HL
        LD C,(HL)
        LD B,$00
        ADD HL,BC
        ADD HL,BC
        INC HL
CHAIN_COPY_VAR_BLOCK_9:
        EX DE,HL
        LD HL,(PRUSING_FORMAT_FLAGS)
        EX DE,HL
        CALL CMP_HL_DE
        JR Z,CHAIN_COPY_VAR_BLOCK_8
        LD BC,CHAIN_COPY_VAR_BLOCK_9
        PUSH BC
; [RE] move one kept string's data during CHAIN: if the string lives in program/heap space that the reload will clobber, copy it up into safe string space (STR_BUILD_FROM_DESC/FP_MOVE_LOOP) and rewrite its descriptor pointer.
CHAIN_MOVE_STRING_VAR:
        XOR A
        OR (HL)
        INC HL
        LD E,(HL)
        INC HL
        LD D,(HL)
        INC HL
        RET Z
        PUSH HL
        LD HL,(VARTAB)
        CALL CMP_HL_DE
        POP HL
        RET C
        PUSH HL
        LD HL,(TXTTAB)
        CALL CMP_HL_DE
        POP HL
        RET NC
        PUSH HL
        DEC HL
        DEC HL
        DEC HL
        PUSH HL
        CALL STR_BUILD_FROM_DESC
        POP HL
        LD B,$03
        CALL FP_MOVE_LOOP
        POP HL
        RET
; [RE] CHAIN string-space compaction: garbage-collect, then slide the preserved string heap (between $0B6F/$0B71/$0B73) to its new base, recording the move delta for descriptor fixups.
CHAIN_COMPACT_STRINGS:
        CALL GARBAG
        LD HL,(STREND)
        LD B,H
        LD C,L
        LD HL,(VARTAB)
        EX DE,HL
        LD HL,(ARYTAB)
        LD A,L
        SUB E
        LD L,A
        LD A,H
        SBC A,D
        LD H,A
        LD (GC_FRAME_CURSOR),HL
        LD HL,(FRETOP)
        LD (L_0C95),HL
        CALL STR_COPY_DOWN_NOCHK
        LD H,B
        LD L,C
        DEC HL
        LD (FRETOP),HL
        LD A,(L_0C9B)
        OR A
        JR Z,CHAIN_MOVE_STRING_VAR_2
        LD HL,(L_0C9E)
        LD B,H
        LD C,L
        LD HL,(L_0C9C)
        CALL BLOCK_MOVE_TO_VARTAB
        CALL CHEAD
CHAIN_MOVE_STRING_VAR_2:
        LD A,$01
        LD (CHAIN_BREAK_FLAG),A
        LD A,(CHAIN_PRESERVE_FLAG)
        OR A
        JP NZ,STMT_MERGE_1
        LD A,(MAX_FILE_NUM)
        LD (L_084B),A
        JP LOAD_PROGRAM_2
CHAIN_MOVE_STRING_VAR_3:
        XOR A
        LD (CHAIN_BREAK_FLAG),A
        LD (CHAIN_PRESERVE_FLAG),A
        LD HL,(VARTAB)
        LD B,H
        LD C,L
        LD HL,(GC_FRAME_CURSOR)
        ADD HL,BC
        LD (ARYTAB),HL
        LD HL,(FRETOP)
        INC HL
        EX DE,HL
        LD HL,(L_0C95)
        LD (FRETOP),HL
CHAIN_MOVE_STRING_VAR_4:
        CALL CMP_HL_DE
        LD A,(DE)
        LD (BC),A
        INC DE
        INC BC
        JR NZ,CHAIN_MOVE_STRING_VAR_4
        DEC BC
        LD H,B
        LD L,C
        LD (STREND),HL
        LD HL,(L_0CA1)
        LD A,H
        OR L
        EX DE,HL
        LD HL,(TXTTAB)
        DEC HL
        JP Z,STMT_FOR_7
        CALL FNDLIN
        JP NC,ERROR_UL
        DEC BC
        LD H,B
        LD L,C
        JP STMT_FOR_7
        DEFB    $C3
        DEFW    STMT_DATA
; ----------------------------------------------------------------------
; STMT_WRITE -- WRITE# / WRITE statement handler (token).
;   In:        HL -> source text after WRITE; C preset $02 (sequential-output mode required).
;   Out:       Each expression in the list emitted to the selected channel (file via PTRFIL, else
;              console) as a comma-separated, quoted-string record terminated by CRLF.
;   Clobbers:  AF, BC, DE, HL; PRTFLG and PTRFIL reset to console at exit.
;   Algorithm: Parse optional '#file,' prefix (PARSE_FILENUM_HASH with required mode=output), then
;              loop over the value list: evaluate each item (FRMEVL_NOPAREN); a string is emitted
;              wrapped in double-quotes, a number is formatted (FOUT) with its leading sign-space
;              stripped; items are separated by emitting ','. WRITE writes the value list with the
;              quoting/comma conventions that INPUT# can read back. The list ends at end-of-line or
;              a separator; then fall into STMT_WRITE_6.
; ----------------------------------------------------------------------
STMT_WRITE:
        LD C,$02
        ; parse optional '#file,' prefix; C=$02 requires the file be open for sequential output
        CALL PARSE_FILENUM_HASH
        DEC HL
        CALL CHRGET
        JR Z,STMT_WRITE_6
; ----------------------------------------------------------------------
; STMT_WRITE_1 -- WRITE# numeric-item branch / list-loop top.
;   In:        HL -> next text item; current channel = PTRFIL.
;   Out:       The numeric value formatted (FOUT) and emitted with its leading blank trimmed.
;   Clobbers:  AF, DE, HL.
;   Algorithm: Evaluate the item; if string type, divert to STMT_WRITE_5 (quoted emit). Otherwise
;              FOUT_2 builds the number's text and SCAN_STR_LITERAL forms a string descriptor for it;
;              the FAC word at $0CB1 then points at that descriptor. The code reads the body pointer,
;              and if the first byte is FOUT's leading-sign space ($20) it shortens the descriptor by
;              one so WRITE emits no leading blank, then STRPRT outputs it.
; ----------------------------------------------------------------------
STMT_WRITE_1:
        CALL FRMEVL_NOPAREN
        PUSH HL
        ; string operand (Z) -> quote-and-emit path; numeric (NZ) -> format-and-emit
        CALL FRMEVL_TEST_TYPE
        JR Z,STMT_WRITE_5
        CALL FOUT_2
        CALL SCAN_STR_LITERAL
        ; [RE] FAC word at $0CB1 -> the FOUT result string descriptor (length byte then body pointer)
        LD HL,(FAC)
        INC HL
        LD E,(HL)
        INC HL
        LD D,(HL)
        LD A,(DE)
        ; strip FOUT's leading sign-space so WRITE has no padding before the number
        CP $20
        JR NZ,STMT_WRITE_2
        INC DE
        LD (HL),D
        DEC HL
        LD (HL),E
        DEC HL
        DEC (HL)
; ----------------------------------------------------------------------
; STMT_WRITE_2 -- WRITE# emit formatted numeric text.
;   In:        FAC word $0CB1 points at the (possibly de-padded) number-text descriptor.
;   Out:       Text sent to the current channel via STRPRT.
;   Clobbers:  AF, DE, HL.
;   Algorithm: STRPRT the formatted number, then fall into the separator handler STMT_WRITE_3.
; ----------------------------------------------------------------------
STMT_WRITE_2:
        CALL STRPRT
; ----------------------------------------------------------------------
; STMT_WRITE_3 -- WRITE# inter-item separator / list continuation.
;   In:        Saved text pointer on stack; HL invalid until POP.
;   Out:       On ',' or ';' continues the list emitting a comma; at end-of-line finishes (STMT_WRITE_6).
;   Clobbers:  AF, HL.
;   Algorithm: Restore the text pointer, CHRGET the next token; end-of-line -> STMT_WRITE_6. A ';'
;              behaves like ',' (STMT_WRITE_4); a ',' is required otherwise (SYNCHR ','). WRITE always
;              separates output items with a comma regardless of the source ';'/',' separator.
; ----------------------------------------------------------------------
STMT_WRITE_3:
        POP HL
        DEC HL
        CALL CHRGET
        JR Z,STMT_WRITE_6
        CP $3B
        JR Z,STMT_WRITE_4
        ; require a ',' or ';' between list items (syntax error otherwise)
        CALL SYNCHR
        DEFB    ','                      ; inline char arg consumed by the preceding CALL
        DEC HL
; ----------------------------------------------------------------------
; STMT_WRITE_4 -- WRITE# emit the ',' item separator and loop.
;   In:        HL -> next item text.
;   Out:       ',' sent to the current channel; control returns to STMT_WRITE_1 for the next value.
;   Clobbers:  AF.
;   Algorithm: CHRGET past the separator, OUTCHR a ',' to the channel, jump back to the list top.
; ----------------------------------------------------------------------
STMT_WRITE_4:
        CALL CHRGET
        LD A,$2C
        CALL OUTCHR
        JR STMT_WRITE_1
; ----------------------------------------------------------------------
; STMT_WRITE_5 -- WRITE# string-item branch: emit a quoted string.
;   In:        FAC/temp descriptor holds the string operand.
;   Out:       '"' + string body + '"' sent to the current channel.
;   Clobbers:  AF.
;   Algorithm: OUTCHR an opening double-quote, STRPRT the string body, OUTCHR a closing double-quote,
;              then rejoin the separator handler (STMT_WRITE_3). The surrounding quotes are what let
;              INPUT# re-read a string containing commas/leading spaces verbatim.
; ----------------------------------------------------------------------
STMT_WRITE_5:
        LD A,$22
        CALL OUTCHR
        CALL STRPRT
        LD A,$22
        CALL OUTCHR
        JR STMT_WRITE_3
; ----------------------------------------------------------------------
; STMT_WRITE_6 -- WRITE# end-of-record: terminate and (random files) pad the record.
;   In:        PTRFIL = current-file FCB base (or 0 for console).
;   Out:       For a RANDOM-mode file the remaining bytes of the 128-byte FIELD record are space-filled;
;              then a CRLF is written and PRINT state is reset.
;   Clobbers:  AF, BC, DE, HL.
;   Algorithm: If PTRFIL is nonzero and FCB.MODE (offset $00) == FCB_MODE_RANDOM ($03), compute how
;              many bytes remain free in the field record (FILE_BUF_REMAIN returns the FIELD position
;              vs buffer base; subtract, then add -2 (LD DE,$FFFE / ADD HL) to reserve the trailing
;              CRLF). If room remains (no carry) fall into STMT_WRITE_7 to blank-fill so the fixed-
;              length random record is fully written; otherwise skip to the CRLF terminator.
; ----------------------------------------------------------------------
STMT_WRITE_6:
        PUSH HL
        LD HL,(PTRFIL)
        LD A,H
        OR L
        JR Z,STMT_WRITE_8
        LD A,(HL)
        ; only RANDOM-mode files (FCB.MODE==3) get their fixed-length record space-padded
        CP $03
        JR NZ,STMT_WRITE_8
        ; DE = FIELD current-position ptr, HL = buffer base ptr; the WRITE code then computes bytes still free
        CALL FILE_BUF_REMAIN
        LD A,L
        SUB E
        LD L,A
        LD A,H
        SBC A,D
        LD H,A
        ; add -2: reserve 2 bytes for the terminating CRLF before padding
        LD DE,$FFFE
        ADD HL,DE
        JR NC,STMT_WRITE_8
; ----------------------------------------------------------------------
; STMT_WRITE_7 -- WRITE# random-record space-pad loop.
;   In:        HL = count of pad bytes to emit (>0).
;   Out:       HL spaces written to the current channel.
;   Clobbers:  AF, HL.
;   Algorithm: OUTCHR a space and decrement HL until zero, filling the remainder of the fixed-length
;              random record so the on-disk record is exactly one CP/M record long.
; ----------------------------------------------------------------------
STMT_WRITE_7:
        LD A,$20
        CALL OUTCHR
        DEC HL
        LD A,H
        OR L
        JR NZ,STMT_WRITE_7
; ----------------------------------------------------------------------
; STMT_WRITE_8 -- WRITE# record terminator / PRINT-state reset epilogue.
;   In:        Saved text pointer on stack.
;   Out:       CRLF written to the channel; PRTFLG and PTRFIL reset to console.
;   Clobbers:  AF, HL.
;   Algorithm: Restore HL, emit CRLF (CRLF), then tail-jump PRINT_RESET_STATE which clears the printer
;              selector PRTFLG ($0838) and the current-file pointer PTRFIL ($0840) back to console.
; ----------------------------------------------------------------------
STMT_WRITE_8:
        POP HL
        CALL CRLF
        JP PRINT_RESET_STATE
; ----------------------------------------------------------------------
; GET_FILENUM_PREFIX_C1 -- enter PARSE_FILENUM_HASH with default/required mode = sequential input ($01).
;   In:        A = current source char; HL -> source text.
;   Out:       Falls into PARSE_FILENUM_HASH with C=$01.
;   Clobbers:  C.
;   Algorithm: Set C=FCB_MODE_SEQ_IN as the required access mode, then fall through. Used by the read
;              side (INPUT#/LINE INPUT#) where the file must be open for input.
; ----------------------------------------------------------------------
GET_FILENUM_PREFIX_C1:
        LD C,$01
; ----------------------------------------------------------------------
; PARSE_FILENUM_HASH -- parse an optional leading '#file,' channel prefix and select that file.
;   In:        A = current char; HL -> source text; C = required access mode (1=input, 2=output).
;   Out:       If '#' present: file resolved, PTRFIL set to its FCB, and a following ',' consumed; if
;              absent, returns immediately leaving the default channel.
;   Clobbers:  AF, BC, DE, HL.
;   Algorithm: If the next char is not '#' ($23), return (no file prefix). Otherwise FILE_NUM_TO_FCB
;              evaluates the file-number expression and returns the FCB mode byte in A; the required
;              mode C is recovered into E (POP DE) and compared (CP E): a mismatch is allowed only when
;              the actual mode is RANDOM ($03), else raise 'Bad file mode'. Require the trailing ','
;              (SYNCHR) and fall into STORE_CUR_FCB_PTR to record the selection.
; ----------------------------------------------------------------------
PARSE_FILENUM_HASH:
        CP $23
        RET NZ
        PUSH BC
        ; evaluate the file-number expression -> BC=FCB base, A=mode byte
        CALL FILE_NUM_TO_FCB
        POP DE
        CP E
        JR Z,PARSE_FILENUM_HASH_1
        ; a mode mismatch is tolerated only when the file is actually RANDOM; otherwise the open mode is wrong
        CP FCB_MODE_RANDOM
        JP NZ,RAISE_BAD_FILE_MODE
; ----------------------------------------------------------------------
; PARSE_FILENUM_HASH_1 -- consume the ',' after a valid '#file' prefix, then record the channel.
;   In:        BC = resolved FCB base; HL -> char after the file-number expression.
;   Out:       ',' consumed (syntax error if absent); falls into STORE_CUR_FCB_PTR.
;   Clobbers:  AF, DE, HL.
;   Algorithm: SYNCHR a comma separating the file number from the I/O list, then store PTRFIL.
; ----------------------------------------------------------------------
PARSE_FILENUM_HASH_1:
        CALL SYNCHR
        DEFB    ','                      ; inline char arg consumed by the preceding CALL
; ----------------------------------------------------------------------
; STORE_CUR_FCB_PTR -- set the current-file pointer PTRFIL ($0840) = BC (the resolved FCB base).
;   In:        BC = FCB base of the selected file (0 selects console).
;   Out:       PTRFIL := BC; HL preserved (swapped out and back).
;   Clobbers:  DE.
;   Algorithm: Move BC into HL, store to PTRFIL, restore HL. After this the PRINT/INPUT char routers
;              (OUTCHR/GETC) route I/O to this file instead of the console until PTRFIL is recleared.
; ----------------------------------------------------------------------
STORE_CUR_FCB_PTR:
        EX DE,HL
        LD H,B
        LD L,C
        LD (PTRFIL),HL
        EX DE,HL
        RET
; ----------------------------------------------------------------------
; FILE_NUM_TO_FCB -- evaluate a file-number expression and resolve it to its FCB base + mode byte.
;   In:        HL -> source text positioned just before the file number (possibly a leading '#').
;   Out:       BC = FCB base for that file; A = FCB mode byte (FCB_MODE_*), flags from OR A;
;              HL advanced past the expression.
;   Clobbers:  AF, BC, DE, HL.
;   Algorithm: CHRGET, skip an optional '#', FRMEVL the numeric file-number expression, then fall
;              through to coerce it to an integer and index FILTAB. The resolved FCB's mode byte is
;              returned so callers can verify the file is open and in the right mode.
; ----------------------------------------------------------------------
FILE_NUM_TO_FCB:
        DEC HL
        CALL CHRGET
        CP $23
        ; skip the '#' if present before evaluating the file number
        CALL Z,CHRGET
        CALL FRMEVL_NOPAREN
; ----------------------------------------------------------------------
; FILE_NUM_TO_FCB_NZ -- coerce the evaluated file-number to an integer, then resolve to FCB+mode.
;   In:        FAC holds the file-number value.
;   Out:       BC = FCB base; A = mode byte with flags set (Z => file not open).
;   Clobbers:  AF, BC, DE, HL.
;   Algorithm: CONINT converts the FAC to a 0..255 integer file number, then falls into
;              FILE_NUM_TO_FCB_A. Callers test Z to detect a closed file.
; ----------------------------------------------------------------------
FILE_NUM_TO_FCB_NZ:
        CALL CONINT
; ----------------------------------------------------------------------
; FILE_NUM_TO_FCB_A -- given an integer file number in A, resolve FILTAB to the FCB base + mode.
;   In:        A = file number (0..max).
;   Out:       E = file number; BC = FCB base; A = mode byte (Z if 0/closed).
;   Clobbers:  AF, BC, DE, HL.
;   Algorithm: Move A into E and fall into FCB_MODE_BYTE, the shared FILTAB index/lookup.
; ----------------------------------------------------------------------
FILE_NUM_TO_FCB_A:
        LD E,A
; ----------------------------------------------------------------------
; FCB_MODE_BYTE -- index FILTAB by file number E to get the FCB base (BC) and its mode byte (A).
;   In:        E = file number; MAX_FILE_NUM ($0870) = highest valid file number (max open files).
;   Out:       BC = FILTAB[E] (FCB base); A = FCB.MODE with flags (Z => closed); HL preserved.
;   Clobbers:  AF, BC, DE.
;   Algorithm: Range-check E against MAX_FILE_NUM (RAISE_BAD_FILE_NUMBER if E exceeds it). FILTAB
;              ($0850) is a packed array of 2-byte little-endian FCB pointers; index by 2*E to fetch
;              BC, then read the FCB's first byte (FCB.MODE) and OR it so Z indicates a closed slot.
; ----------------------------------------------------------------------
FCB_MODE_BYTE:
        LD A,(MAX_FILE_NUM)
        CP E
        JP C,RAISE_BAD_FILE_NUMBER
        LD D,$00
        PUSH HL
        ; FILTAB[file#] is a 2-byte little-endian pointer to that file's FCB; index by 2*E
        LD HL,FILTAB
        ADD HL,DE
        ADD HL,DE
        LD C,(HL)
        INC HL
        LD B,(HL)
        ; FCB.MODE: 0=closed, 1=seq-in, 2=seq-out, 3=random
        LD A,(BC)
        OR A
        POP HL
        RET
; ----------------------------------------------------------------------
; FCB_BUFFER_PTR -- return DE = pointer to the file's data buffer within its FCB, per access mode.
;   In:        E = file number.
;   Out:       DE -> FCB.SEQ_BUF (offset $29) for sequential files, or FCB.RND_BUF ($B2) for random;
;              BC = FCB base; A = mode byte.
;   Clobbers:  AF, BC, DE, HL.
;   Algorithm: FCB_MODE_BYTE resolves the FCB and mode. Default the buffer offset to FCB.SEQ_BUF; if
;              the mode is RANDOM ($03) use FCB.RND_BUF (the FIELD window) instead, then add the FCB
;              base to form the absolute buffer pointer in DE.
; ----------------------------------------------------------------------
FCB_BUFFER_PTR:
        CALL FCB_MODE_BYTE
        LD HL,FCB.SEQ_BUF
        CP FCB_MODE_RANDOM
        JR NZ,FCB_BUFFER_PTR_1
        LD HL,FCB.RND_BUF
; ----------------------------------------------------------------------
; FCB_BUFFER_PTR_1 -- finalize FCB_BUFFER_PTR: add the FCB base and return the pointer in DE.
;   In:        HL = chosen buffer field offset ($29 or $B2); BC = FCB base.
;   Out:       DE = HL + BC (absolute buffer address).
;   Clobbers:  HL, DE.
;   Algorithm: ADD HL,BC; EX DE,HL.
; ----------------------------------------------------------------------
FCB_BUFFER_PTR_1:
        ADD HL,BC
        EX DE,HL
        RET
; ----------------------------------------------------------------------
; FN_MKI_STR -- MKI$() function (token TOK_MKIS $31): pack a numeric into a 2-byte INT string.
;   In:        Numeric argument already in the FAC (entered via FUNC_DISPATCH_TBL slot $0212).
;   Out:       Returns a 2-byte string whose bytes are the integer image of the argument.
;   Clobbers:  AF, BC, DE, HL.
;   Algorithm: [RE] MISLABEL CORRECTED -- this is MKI$, not LOF(); the real LOF() is FN_LOF_VALUE.
;              FUNC_DISPATCH_TBL slot index = token-1, so $0212/$0214/$0216 = tokens $31/$32/$33 =
;              MKI$/MKS$/MKD$, and the body BUILDS and returns a STRING. A=$02 selects the result
;              width; FRMEVL_APPLY_OP(A&7) coerces the FAC to the matching numeric type via
;              OPERATOR_ROUTINE_TBL (A&7=2 -> FN_CINT). ALLOC_STR_A allocates A bytes of string heap
;              (the heap body pointer lands in DSCTMP.PTR $0B46), FP_ARG_SETUP2 copies the FAC bytes
;              (source FAC $0CB1/$0CAD) into that heap buffer (HL = $0B46 contents = destination),
;              and STR_FN_RETURN_CHAR_1 pushes the result onto the string-temp stack. The leading 01
;              byte at FN_MKS_STR is the LD BC,nn skip-prefix idiom (preserve).
; ----------------------------------------------------------------------
FN_MKI_STR:
        LD A,$02
; ----------------------------------------------------------------------
; FN_MKS_STR -- MKS$() function (token TOK_MKSS $32): pack a numeric into a 4-byte SNG string.
;   In:        Entered at FN_MKS_STR+1 ($0214) with A preset $04; numeric arg in the FAC.
;   Out:       Returns a 4-byte string holding the single-precision image of the argument.
;   Clobbers:  AF, BC, DE, HL.
;   Algorithm: [RE] MISLABEL CORRECTED -- MKS$, not part of LOF. Same path as FN_MKI_STR with width
;              A=$04 so FRMEVL_APPLY_OP(A&7=4) coerces to SNG (-> FN_CSNG) and a 4-byte string is built.
;              The 01 prefix here is the LD BC,nn skip idiom swallowing the 'LD A,$04' on the fall-
;              through path (already documented; preserve).
; ----------------------------------------------------------------------
FN_MKS_STR:
        LD BC,$043E
; ----------------------------------------------------------------------
; FN_MKD_STR -- MKD$() function (token TOK_MKDS $33): pack a numeric into an 8-byte DBL string.
;   In:        Entered at FN_MKD_STR+1 ($0216) with A preset $08; numeric arg in the FAC.
;   Out:       Returns an 8-byte string holding the double-precision image of the argument.
;   Clobbers:  AF, BC, DE, HL.
;   Algorithm: [RE] MISLABEL CORRECTED -- MKD$, the convergence point of the MKI$/MKS$/MKD$ trio.
;              A=$08 -> FRMEVL_APPLY_OP(A&7=0) coerces to DBL (-> FN_CDBL); ALLOC_STR_A(8) reserves the
;              string (body ptr -> DSCTMP.PTR $0B46), FP_ARG_SETUP2 copies the 8 FAC bytes (from the
;              FAC, $0CB1/$0CAD) into the heap buffer at HL=$0B46 contents, and STR_FN_RETURN_CHAR_1
;              returns it as a string temp. The 01 prefix is again the LD BC,nn skip idiom.
; ----------------------------------------------------------------------
FN_MKD_STR:
        LD BC,$083E
        PUSH AF
        ; coerce the FAC to the result numeric type (A&7 indexes OPERATOR_ROUTINE_TBL -> CINT/CSNG/CDBL) before extracting its bytes
        CALL FRMEVL_APPLY_OP
        POP AF
        ; allocate A (2/4/8) bytes of string heap for the packed value; the heap body pointer lands in DSCTMP.PTR ($0B46)
        CALL ALLOC_STR_A
        LD HL,(DSCTMP_PTR)
        CALL FP_ARG_SETUP2
        JP STR_FN_RETURN_CHAR_1
; ----------------------------------------------------------------------
; FN_CVI -- CVI() function (token TOK_CVI $2A): reinterpret a >=2-byte string's bytes as an integer.
;   In:        String argument's descriptor reached via FUNC_DISPATCH_TBL slot $0204; A preset $01.
;   Out:       FAC = the numeric value formed from the first 2 bytes of the string; VALTYP=INT ($02).
;   Clobbers:  AF, BC, DE, HL.
;   Algorithm: A holds (min length - 1): $01 for CVI. FRETMP frees/locates the argument string temp;
;              the descriptor's length must EXCEED A (CP (HL) then JP NC,ERROR_FC: error if A >= len),
;              else 'Illegal function call'. Then INC A -> A=2 is written to VALTYP ($0B14) so the value
;              is typed INT, the string's body pointer is loaded into HL, and FP_ARG_SETUP1 moves those
;              bytes into the FAC. CVI is the inverse of MKI$. The 01 byte before LD BC at FN_CVI_1 is
;              the LD BC,nn skip-prefix idiom (preserve).
; ----------------------------------------------------------------------
FN_CVI:
        LD A,$01
; ----------------------------------------------------------------------
; FN_CVS -- CVS() function (token TOK_CVS $2B): reinterpret a >=4-byte string as a single.
;   In:        Entered at FN_CVS+1 ($0206) with A preset $03 (min length-1 = 3).
;   Out:       FAC = single-precision value from the string's first 4 bytes; VALTYP=SNG ($04).
;   Clobbers:  AF, BC, DE, HL.
;   Algorithm: Same body as FN_CVI with width selector $03; INC A -> 4 stored to VALTYP. Inverse of
;              MKS$. The 01 prefix is the LD BC,nn skip idiom over the fall-through 'LD A,$03'.
; ----------------------------------------------------------------------
FN_CVI_1:
        LD BC,$033E
; ----------------------------------------------------------------------
; FN_CVD -- CVD() function (token TOK_CVD $2C): reinterpret a >=8-byte string as a double.
;   In:        Entered at FN_CVD+1 ($0208) with A preset $07 (min length-1 = 7).
;   Out:       FAC = double-precision value from the string's first 8 bytes; VALTYP=DBL ($08).
;   Clobbers:  AF, BC, DE, HL.
;   Algorithm: Convergence body for CVI/CVS/CVD. After the length check, INC A types VALTYP, and
;              FP_ARG_SETUP1 loads the bytes into the FAC. Inverse of MKD$.
; ----------------------------------------------------------------------
FN_CVI_2:
        LD BC,$073E
        PUSH AF
        ; release/locate the argument string temp; HL -> its descriptor (length byte then body ptr)
        CALL FRETMP
        POP AF
        ; string length must EXCEED A (need >=2/4/8 bytes); too short -> Illegal function call
        CP (HL)
        JP NC,ERROR_FC
        INC A
        INC HL
        LD C,(HL)
        INC HL
        LD H,(HL)
        LD L,C
        ; set VALTYP to the result type (INT=2 / SNG=4 / DBL=8) so the FAC is read with the right width
        LD (VALTYP),A
        JP FP_ARG_SETUP1
; ----------------------------------------------------------------------
; INPUT_FILE_SCAN -- INPUT#/READ# value scanner: parse one numeric/string field from the current file.
;   In:        HL -> the variable being assigned; PTRFIL = current-file FCB (nonzero; the file branch
;              of STMT_READ_4 does JP NZ,here when PTRFIL!=0).
;   Out:       One field parsed from the file stream and assigned; HL advanced.
;   Clobbers:  AF, BC, DE, HL.
;   Algorithm: [RE] This is the file-INPUT scanner, NOT part of CVI -- it sits next to it in file order.
;              FRMEVL_TEST_TYPE sets Z=string/NZ=numeric. Sets BC=STMT_READ_7 (the value-assign
;              finisher) and DE=$2C20 (D=',' E=' '). On NZ (NUMERIC field) it jumps to the scan loop
;              with those delimiters, so a numeric field ends on a comma OR a space. On Z (STRING
;              field) it first does LD E,D (E=','), so a string field's two terminators are both ','
;              -- it ends only at a comma, letting embedded spaces be kept. Joins the common scan loop
;              at INPUT_FILE_SCAN_5.
; ----------------------------------------------------------------------
INPUT_FILE_SCAN:
        CALL FRMEVL_TEST_TYPE
        LD BC,STMT_READ_7
        ; D=',' E=' ': the NUMERIC-field delimiter pair (ends on comma or space). The string path below does LD E,D so a string field ends only on a comma
        LD DE,$2C20
        JR NZ,INPUT_FILE_SCAN_5
        LD E,D
        JR INPUT_FILE_SCAN_5
; ----------------------------------------------------------------------
; LINE_INPUT_FILE -- LINE INPUT# entry: read a whole line (to CR) from the file into a string var.
;   In:        HL -> '#file' text (a '#' was just detected by STMT_LINE, which JP Z,here).
;   Out:       The destination string variable receives the rest of the line up to CR; PTRFIL selected.
;   Clobbers:  AF, BC, DE, HL.
;   Algorithm: [RE] LINE INPUT# path, not CVI. GET_FILENUM_PREFIX_C1 parses '#file,' requiring input
;              mode and sets PTRFIL. PTRGET locates the target string variable; REQUIRE_STRING validates
;              it. Pushes the PRINT_RESET_STATE epilogue and the variable pointer, then sets the scan to
;              'read until CR with no delimiter trimming' (BC=STMT_DATA_4 finisher; D=E=0 = no comma/
;              space delimiter) before joining the scan loop -- so the whole remaining line is captured.
; ----------------------------------------------------------------------
LINE_INPUT_FILE:
        ; parse '#file,' (file must be open for input) and select it via PTRFIL
        CALL GET_FILENUM_PREFIX_C1
        CALL PTRGET_1+1
        CALL REQUIRE_STRING
        LD BC,PRINT_RESET_STATE
        PUSH BC
        PUSH DE
        ; use the LINE-INPUT finisher; D=E=0 means no delimiter so the whole line to CR is read
        LD BC,STMT_DATA_4
        XOR A
        LD D,A
        LD E,A
; ----------------------------------------------------------------------
; INPUT_FILE_SCAN_5 -- common entry to the INPUT#/LINE-INPUT# field scan loop.
;   In:        A/BC/HL set by the INPUT_FILE_SCAN or LINE_INPUT_FILE setup; D/E = delimiter config.
;   Out:       Saves scan context (AF,BC,HL) and falls into the leading-space skipper.
;   Clobbers:  stack.
;   Algorithm: Push the type/finisher/var context, then fall into INPUT_FILE_SCAN_6 to begin reading
;              characters from the file via GETC_FILE_EOF.
; ----------------------------------------------------------------------
INPUT_FILE_SCAN_5:
        PUSH AF
        PUSH BC
        PUSH HL
; ----------------------------------------------------------------------
; INPUT_FILE_SCAN_6 -- skip leading spaces before a field.
;   In:        D = leading-blank flag (nonzero when blanks should be skipped).
;   Out:       A = first non-space char; carry from GETC_FILE_EOF signals premature EOF.
;   Clobbers:  AF.
;   Algorithm: GETC_FILE_EOF reads the next file byte; carry -> 'Input past end' error. Loops while the
;              char is a space ($20) and D!=0 (leading blanks are eaten).
; ----------------------------------------------------------------------
INPUT_FILE_SCAN_6:
        ; read next byte from the current file; carry => EOF -> Input past end
        CALL GETC_FILE_EOF
        JP C,RAISE_INPUT_PAST_END
        CP $20
        JR NZ,INPUT_FILE_SCAN_7
        INC D
        DEC D
        JR NZ,INPUT_FILE_SCAN_6
; ----------------------------------------------------------------------
; INPUT_FILE_SCAN_7 -- detect a leading quote to start a quoted-string field.
;   In:        A = first significant char of the field; E = the field's primary delimiter.
;   Out:       If a '"' opens a (comma-delimited) string field, arms the quote terminator in D/E and
;              reads the next char; otherwise falls into the unquoted accumulation path.
;   Clobbers:  AF, BC, DE.
;   Algorithm: If A=='"' and E==',' (a string field), arm a quoted string: set D=E=quote so only a
;              closing '"' terminates the body, and GETC_FILE_EOF the first body char (EOF -> finish at
;              INPUT_FILE_FINISH). Else continue to the byte-accumulation loop.
; ----------------------------------------------------------------------
INPUT_FILE_SCAN_7:
        ; a leading quote opens a quoted string field (commas/spaces become literal until the closing quote)
        CP $22
        JR NZ,INPUT_FILE_SCAN_8
        LD B,A
        LD A,E
        CP $2C
        LD A,B
        JR NZ,INPUT_FILE_SCAN_8
        LD D,B
        LD E,B
        CALL GETC_FILE_EOF
        JR C,INPUT_FILE_FINISH
; ----------------------------------------------------------------------
; INPUT_FILE_SCAN_8 -- initialize the field accumulation buffer.
;   In:        A = current char to begin storing.
;   Out:       HL = BUF (console input buffer reused as the field staging area); B=$FF max-count guard.
;   Clobbers:  HL, B.
;   Algorithm: Point HL at BUF and set B=$FF (the field-length limit counter used by INPUT_BUF_STORE),
;              then fall into the per-character accumulation loop.
; ----------------------------------------------------------------------
INPUT_FILE_SCAN_8:
        ; stage the field in BUF; B=$FF caps the field length (INPUT_BUF_STORE counts down)
        LD HL,BUF
        LD B,$FF
; ----------------------------------------------------------------------
; INPUT_FILE_SCAN_9 -- per-character field accumulation loop with CR/LF record handling.
;   In:        A = current char; D/E = active terminators; HL -> BUF write cursor; B = remaining room.
;   Out:       Characters stored to BUF until a terminator/EOF; control transfers to the finish path.
;   Clobbers:  AF, BC, HL.
;   Algorithm: [RE] Inside a quoted field (D=='"') jump straight to the store/terminator test. A CR
;              ($0D) goes to the CR/LF separator handler (INPUT_FILE_CR). A bare LF ($0A) not preceded
;              by CR is stored into the field unless the field is comma-delimited (E==','), then the
;              next byte is read and a following CR is examined. Other chars fall to the store-or-stop
;              test (INPUT_FILE_SCAN_10).
; ----------------------------------------------------------------------
INPUT_FILE_SCAN_9:
        LD C,A
        LD A,D
        CP $22
        LD A,C
        JR Z,INPUT_FILE_SCAN_10
        CP $0D
        PUSH HL
        JR Z,INPUT_FILE_CR
        POP HL
        CP $0A
        JR NZ,INPUT_FILE_SCAN_10
        LD C,A
        LD A,E
        CP $2C
        LD A,C
        ; [RE] store this bare LF into the field unless the field is comma-delimited (E==',')
        CALL NZ,INPUT_BUF_STORE
        CALL GETC_FILE_EOF
        JR C,INPUT_FILE_FINISH
        CP $0D
        JR NZ,INPUT_FILE_SCAN_10
        LD A,E
        CP $20
        JR Z,INPUT_FILE_SCAN_11
        CP $2C
        LD A,$0D
        JR Z,INPUT_FILE_SCAN_11
; ----------------------------------------------------------------------
; INPUT_FILE_SCAN_10 -- terminator test then store-or-stop for the accumulation loop.
;   In:        A = current char; D/E = the active terminator characters.
;   Out:       On a terminator (NUL/D/E) branches to finish; otherwise stores the char and continues.
;   Clobbers:  AF, HL.
;   Algorithm: A NUL ends the field; if the char equals the D or E delimiter, finish (INPUT_FILE_FINISH);
;              else INPUT_BUF_STORE it and fall into INPUT_FILE_SCAN_11 to fetch the next char.
; ----------------------------------------------------------------------
INPUT_FILE_SCAN_10:
        OR A
        JR Z,INPUT_FILE_SCAN_11
        CP D
        JR Z,INPUT_FILE_FINISH
        CP E
        JR Z,INPUT_FILE_FINISH
        CALL INPUT_BUF_STORE
; ----------------------------------------------------------------------
; INPUT_FILE_SCAN_11 -- fetch the next field character and continue the loop.
;   In:        HL -> BUF cursor.
;   Out:       A = next file byte; loops back to INPUT_FILE_SCAN_9 unless EOF.
;   Clobbers:  AF.
;   Algorithm: GETC_FILE_EOF; on carry (EOF) fall into the finish path, else continue scanning.
; ----------------------------------------------------------------------
INPUT_FILE_SCAN_11:
        CALL GETC_FILE_EOF
        JR NC,INPUT_FILE_SCAN_9
; ----------------------------------------------------------------------
; INPUT_FILE_FINISH -- field terminated: consume a trailing delimiter, then convert/assign.
;   In:        A = terminator char; saved scan context on stack.
;   Out:       Cursor positioned past the field's trailing delimiter(s); falls into the converter.
;   Clobbers:  AF, BC, HL.
;   Algorithm: If the field ended on a closing quote ('"') or a space, skip following whitespace via
;              INPUT_FILE_SKIPWS so the next field starts clean; otherwise go straight to the value
;              finalizer (INPUT_FILE_CONVERT).
; ----------------------------------------------------------------------
INPUT_FILE_FINISH:
        PUSH HL
        CP $22
        JR Z,INPUT_FILE_SKIPWS
        CP $20
        JR NZ,INPUT_FILE_CONVERT
; ----------------------------------------------------------------------
; INPUT_FILE_SKIPWS -- skip the inter-field delimiter run (spaces, one comma, optional CRLF).
;   In:        Current file position just after a field body.
;   Out:       File positioned at the start of the next field or at EOF.
;   Clobbers:  AF.
;   Algorithm: GETC_FILE_EOF and fall into INPUT_FILE_SKIPWS_14 to test the byte.
; ----------------------------------------------------------------------
INPUT_FILE_SKIPWS:
        CALL GETC_FILE_EOF
; ----------------------------------------------------------------------
; INPUT_FILE_SKIPWS_14 -- classify the delimiter byte while skipping inter-field whitespace.
;   In:        A = candidate byte (carry => EOF).
;   Out:       Loops on spaces; stops on ',' (consumes it) or CR; otherwise treats as field start.
;   Clobbers:  AF.
;   Algorithm: EOF -> finish. Space ($20) loops (INPUT_FILE_SKIPWS). Comma ($2C) is the field
;              separator -> done (INPUT_FILE_CONVERT). CR ($0D) starts the CRLF handling at
;              INPUT_FILE_CR; any other byte is the next field and is handled at INPUT_FILE_PUSHBACK
;              (re-presents it by bumping the in-buffer counter).
; ----------------------------------------------------------------------
INPUT_FILE_SKIPWS_14:
        JR C,INPUT_FILE_CONVERT
        CP $20
        JR Z,INPUT_FILE_SKIPWS
        CP $2C
        JP Z,INPUT_FILE_CONVERT
        CP $0D
        JR NZ,INPUT_FILE_PUSHBACK
; ----------------------------------------------------------------------
; INPUT_FILE_CR -- handle a CR field separator and swallow a following LF.
;   In:        A = CR; current file position after the CR.
;   Out:       A trailing LF (if present) is consumed; control reaches the value converter.
;   Clobbers:  AF.
;   Algorithm: GETC_FILE_EOF the byte after CR; if it is LF ($0A) consume it (CRLF pair) and finish at
;              INPUT_FILE_CONVERT; EOF here also finishes; a non-LF byte falls into INPUT_FILE_PUSHBACK
;              to be re-presented.
; ----------------------------------------------------------------------
INPUT_FILE_CR:
        CALL GETC_FILE_EOF
        JR C,INPUT_FILE_CONVERT
        CP $0A
        JR Z,INPUT_FILE_CONVERT
; ----------------------------------------------------------------------
; INPUT_FILE_PUSHBACK -- non-delimiter look-ahead byte: re-present it on the next read.
;   In:        PTRFIL = current-file FCB; a non-delimiter byte was read past the field.
;   Out:       FCB.BUF_REM (offset $28) incremented so the over-read byte is re-presented next read.
;   Clobbers:  AF, BC, HL.
;   Algorithm: [RE] BUF_REM is the count of still-unread bytes in the FCB record (GETC_FILE decrements
;              it on each read). One byte was consumed past the field; INC (HL) on PTRFIL+FCB.BUF_REM
;              increases the remaining count by one so the next GETC_FILE re-reads that byte. This is
;              the scanner's one-character look-ahead pushback.
; ----------------------------------------------------------------------
INPUT_FILE_PUSHBACK:
        LD HL,(PTRFIL)
        LD BC,FCB.BUF_REM
        ADD HL,BC
        ; [RE] increment FCB.BUF_REM (remaining-bytes count) so the next read re-presents the look-ahead byte
        INC (HL)
; ----------------------------------------------------------------------
; INPUT_FILE_CONVERT -- terminate the staged field text and dispatch numeric vs string conversion.
;   In:        HL -> end of the field text in BUF; E = delimiter mode (space => numeric path).
;   Out:       Falls into the NUL-terminate + convert step.
;   Clobbers:  HL.
;   Algorithm: Restore the BUF write cursor and fall into INPUT_FILE_CONVERT_18 to NUL-terminate and
;              convert.
; ----------------------------------------------------------------------
INPUT_FILE_CONVERT:
        POP HL
; ----------------------------------------------------------------------
; INPUT_FILE_CONVERT_18 -- NUL-terminate the field and convert it to a string or numeric value.
;   In:        HL -> field end in BUF; E = delimiter mode; B/D scan state.
;   Out:       The variable identified by the saved pointer is assigned the parsed value.
;   Clobbers:  AF, BC, DE, HL.
;   Algorithm: Write a terminating NUL after the field text. If E indicates a numeric field (E==space,
;              so E-$20==0) jump to INPUT_FILE_CONVERT_NUM to run the numeric reader. Otherwise treat
;              the field as a string: SCAN_STR_BODY measures it and builds a string descriptor from BUF,
;              which the caller's READ/INPUT assignment consumes.
; ----------------------------------------------------------------------
INPUT_FILE_CONVERT_18:
        LD (HL),$00
        LD HL,BUF_INPUT_RESET_PTR
        LD A,E
        ; E==space ($20) marks a numeric field -> numeric reader; otherwise build a string from BUF
        SUB $20
        JR Z,INPUT_FILE_CONVERT_NUM
        LD B,D
        LD D,$00
        CALL SCAN_STR_BODY
        POP HL
        RET
; ----------------------------------------------------------------------
; INPUT_FILE_CONVERT_NUM -- numeric-field path: parse the staged digits into the FAC.
;   In:        HL -> the field text in BUF (NUL-terminated).
;   Out:       FAC = parsed number (integer-form via FIN_1+1, else general via FIN).
;   Clobbers:  AF, BC, DE, HL.
;   Algorithm: Test the value type, then run the number reader: the carry from CHRGET's first-char
;              classification selects FIN_1+1 (integer form) vs FIN (general numeric). The parsed value
;              becomes the field assigned to the INPUT#/READ target.
; ----------------------------------------------------------------------
INPUT_FILE_CONVERT_NUM:
        CALL FRMEVL_TEST_TYPE
        PUSH AF
        CALL CHRGET
        POP AF
        PUSH AF
        CALL C,FIN_1+1
        POP AF
        CALL NC,FIN
        POP HL
        RET
; ----------------------------------------------------------------------
; INPUT_BUF_STORE -- store one field byte into the staging buffer with an overflow guard.
;   In:        A = byte to store; HL = BUF write cursor; B = remaining room counter.
;   Out:       Byte stored, HL advanced, B decremented; on B underflow the caller's return is popped
;              and the field is force-finished.
;   Clobbers:  AF, BC, HL.
;   Algorithm: A NUL is dropped (RET Z). Otherwise store (HL)<-A, INC HL, DEC B; while B>0 return to
;              the loop. If B hits 0 the field overran its limit, so POP the caller and jump to
;              INPUT_FILE_CONVERT_18 to terminate and convert what was collected.
; ----------------------------------------------------------------------
INPUT_BUF_STORE:
        OR A
        RET Z
        LD (HL),A
        INC HL
        DEC B
        RET NZ
        ; field hit the length limit: discard the loop's return and force-finish the field
        POP BC
        JR INPUT_FILE_CONVERT_18
; ----------------------------------------------------------------------
; LOAD_OPEN_INPUT -- LOAD/MERGE entry: set D=1 (FCB_MODE_SEQ_IN), fall into LOAD_OPEN_CHANNEL0 to open the program file on channel #0 for sequential input.
; ----------------------------------------------------------------------
LOAD_OPEN_INPUT:
        LD D,$01
; ----------------------------------------------------------------------
; LOAD_OPEN_CHANNEL0 -- XOR A selects file #0, JP STMT_OPEN_2 with the mode in D. File #0 is the reserved program-image channel.
; ----------------------------------------------------------------------
LOAD_OPEN_CHANNEL0:
        XOR A
        JP STMT_OPEN_2
; ----------------------------------------------------------------------
; LOAD_PROGRAM -- LOAD/RUN handler: flag-skip ($AF=opcode of XOR A; +1 entry = plain LOAD) sets the run disposition, PUSH AF, open file #0, save MAX_FILE_NUM to L_084B, parse ,R; no ,R -> LOAD_PROGRAM_3+1 (POP AF), ,R -> LOAD_PROGRAM_2.
; ----------------------------------------------------------------------
LOAD_PROGRAM:
        OR $AF
        PUSH AF
        CALL LOAD_OPEN_INPUT
        LD A,(MAX_FILE_NUM)
        LD (L_084B),A
        DEC HL
        CALL CHRGET
        JR Z,LOAD_PROGRAM_3+1
        CALL SYNCHR
        DEFB    ','                      ; inline char arg consumed by the preceding CALL
        CALL SYNCHR
        DEFB    'R'                      ; inline char arg consumed by the preceding CALL
        JP NZ,RAISE_SYNTAX_ERROR
        POP AF
; ----------------------------------------------------------------------
; LOAD_PROGRAM_2 -- the ,R-PRESENT arm: XOR A; LD (MAX_FILE_NUM),A zeroes MAX_FILE_NUM (MAX_FILE_NUM, NOT the run flag); OR $F1 in LOAD_PROGRAM_3 then sets the run flag. The no-,R path skips this routine.
; ----------------------------------------------------------------------
LOAD_PROGRAM_2:
        XOR A
        LD (MAX_FILE_NUM),A
; ----------------------------------------------------------------------
; LOAD_PROGRAM_3 -- store RUN_AFTER_LOAD_FLAG (entered at +1=POP AF on no-,R), FILTAB:=$0080, CLEAR_VARS, restore MAX_FILE_NUM, reload FILTAB[0]/PTRFIL from FILTAB_SLOT0_SEED ([RE] file #0 FCB base $81D1). [RE] SAVTXT guard fires only when SAVTXT==$FFFE, setting $FFFF; intent UNKNOWN.
; ----------------------------------------------------------------------
LOAD_PROGRAM_3:
        OR $F1
        LD (RUN_AFTER_LOAD_FLAG),A
        LD HL,$0080
        LD (HL),$00
        LD (FILTAB),HL
        CALL CLEAR_VARS
        LD A,(L_084B)
        LD (MAX_FILE_NUM),A
        LD HL,(FILTAB_SLOT0_SEED)
        LD (FILTAB),HL
        LD (PTRFIL),HL
        LD HL,(SAVTXT)
        INC HL
        LD A,H
        AND L
        INC A
        JR NZ,LOAD_PROGRAM_4
        LD (SAVTXT),HL
; ----------------------------------------------------------------------
; LOAD_PROGRAM_4 -- GETC_FILE_EOF the lead byte: empty -> DIRECT_LINE_DISPATCH; $FE -> set LOAD_PROTECT_FLAG (LOAD_PROTECT_FLAG) then read; else LOAD_PROGRAM_5.
; ----------------------------------------------------------------------
LOAD_PROGRAM_4:
        CALL GETC_FILE_EOF
        JP C,DIRECT_LINE_DISPATCH
        CP $FE
        JR NZ,LOAD_PROGRAM_5
        LD (LOAD_PROTECT_FLAG),A
        JR LOAD_PROGRAM_6
; ----------------------------------------------------------------------
; LOAD_PROGRAM_5 -- INC A; $FF -> binary (fall through); else JP STMT_MERGE_2 (ASCII source).
; ----------------------------------------------------------------------
LOAD_PROGRAM_5:
        INC A
        JP NZ,STMT_MERGE_2
; ----------------------------------------------------------------------
; LOAD_PROGRAM_6 -- FILE_READ_RECORDS reads to TXTTAB, returns end into VARTAB; PROG_SCRAMBLE if protected; CHEAD relinks; save/restore MAX_FILE_NUM around CLEAR_RESET_DATAPTR; then CHAIN -> string-move, RUN_AFTER_LOAD_FLAG clear -> READY, else JP STMT_FOR_7.
; ----------------------------------------------------------------------
LOAD_PROGRAM_6:
        LD HL,(TXTTAB)
        CALL FILE_READ_RECORDS
        LD (VARTAB),HL
        LD A,(LOAD_PROTECT_FLAG)
        OR A
        CALL NZ,PROG_SCRAMBLE
        CALL CHEAD
        INC HL
        INC HL
        LD (VARTAB),HL
        LD HL,MAX_FILE_NUM
        LD A,(HL)
        LD (L_084B),A
        LD (HL),$00
        CALL CLEAR_RESET_DATAPTR
        LD A,(L_084B)
        LD (MAX_FILE_NUM),A
        LD A,(CHAIN_BREAK_FLAG)
        OR A
        JP NZ,CHAIN_MOVE_STRING_VAR_3
        LD A,(RUN_AFTER_LOAD_FLAG)
        OR A
        JP Z,NEWSTT_READY
        JP STMT_FOR_7
; ----------------------------------------------------------------------
; LOAD_CLEANUP_RESET -- PRINT_RESET_STATE clears PRTFLG/PTRFIL (leaves A=0); FILE_CLOSE_ONE with A=0 closes FILE #0; JP RESET_RUN_STATE_1 reloads HL from OPEN_RESUME_TEXT_PTR. Tail of SAVE and the MERGE error path.
; ----------------------------------------------------------------------
LOAD_CLEANUP_RESET:
        CALL PRINT_RESET_STATE
        CALL FILE_CLOSE_ONE
        JP RESET_RUN_STATE_1
; ----------------------------------------------------------------------
; RUN_NO_FILENAME -- CLEAR_VARS then JP STACK_OVERFLOW_RAISE; STRING_SPACE_ROOM_CHECK jumps here on string overflow.
; ----------------------------------------------------------------------
RUN_NO_FILENAME:
        CALL CLEAR_VARS
        JP STACK_OVERFLOW_RAISE
; ----------------------------------------------------------------------
; STMT_MERGE -- POP BC discards the dispatcher return (MERGE jumps into the line dispatcher), open file #0 for input, require end-of-statement. Text-only; shares the LOAD-ASCII path.
; ----------------------------------------------------------------------
STMT_MERGE:
        POP BC
        CALL LOAD_OPEN_INPUT
        DEC HL
        CALL CHRGET
        JR Z,STMT_MERGE_1
        CALL LOAD_CLEANUP_RESET
        JP RAISE_SYNTAX_ERROR
; ----------------------------------------------------------------------
; STMT_MERGE_1 -- zero RUN_AFTER_LOAD_FLAG (MERGE never auto-runs), GETC_FILE_EOF: empty -> DIRECT_LINE_DISPATCH; $FF binary -> RAISE_BAD_FILE_MODE.
; ----------------------------------------------------------------------
STMT_MERGE_1:
        XOR A
        LD (RUN_AFTER_LOAD_FLAG),A
        CALL GETC_FILE_EOF
        JP C,DIRECT_LINE_DISPATCH
        INC A
        JP Z,RAISE_BAD_FILE_MODE
; ----------------------------------------------------------------------
; STMT_MERGE_2 -- via PTRFIL INC FCB.BUF_REM (remaining-bytes counter, offset $28) so the next GETC re-delivers the consumed byte (ungetc; index = BUF_CNT-BUF_REM), JP DIRECT_LINE_DISPATCH. Shared LOAD-ASCII/MERGE reader.
; ----------------------------------------------------------------------
STMT_MERGE_2:
        LD HL,(PTRFIL)
        LD BC,FCB.BUF_REM
        ADD HL,BC
        INC (HL)
        JP DIRECT_LINE_DISPATCH
; ----------------------------------------------------------------------
; DIRECT_STMT_EXEC -- PTRFIL != 0 -> RAISE_ERROR ERR_DIRECT_STATEMENT_IN_FILE; else restore HL and JP NEWSTT_NEXTLINE_2.
; ----------------------------------------------------------------------
DIRECT_STMT_EXEC:
        PUSH HL
        LD HL,(PTRFIL)
        LD A,H
        OR L
        LD DE,ERR_DIRECT_STATEMENT_IN_FILE
        JP NZ,RAISE_ERROR
        POP HL
        JP NEWSTT_NEXTLINE_2
; ----------------------------------------------------------------------
; STMT_SAVE -- D=mode 2, open file #0; no suffix -> STMT_SAVE_1 ($FF); ,P -> protected writer (SAVE_PROTECTED_PROGRAM, mislabeled); ,A -> JP STMT_LIST (ASCII).
; ----------------------------------------------------------------------
STMT_SAVE:
        LD D,$02
        CALL LOAD_OPEN_CHANNEL0
        DEC HL
        CALL CHRGET
        JR Z,STMT_SAVE_1
        CALL SYNCHR
        DEFB    ','                      ; inline char arg consumed by the preceding CALL
        CP $50
        JP Z,SAVE_PROTECTED_PROGRAM
        CALL SYNCHR
        DEFB    'A'                      ; inline char arg consumed by the preceding CALL
        JP STMT_LIST
; ----------------------------------------------------------------------
; STMT_SAVE_1 -- RENUM_PATCH_LINEREFS (RENUM_PENDING_FLAG=0) VALIDATES GOTO/GOSUB/THEN line refs ('Undefined line'; NOT a relink); ILLEGAL_DIRECT_CHECK tests LOAD_PROTECT_FLAG (LOAD_PROTECT_FLAG) -> ERROR_FC if a protected program is plain-SAVEd; A=$FF, fall into SAVE_WRITE_PROGRAM.
; ----------------------------------------------------------------------
STMT_SAVE_1:
        CALL RENUM_PATCH_LINEREFS
        CALL ILLEGAL_DIRECT_CHECK
        LD A,$FF
; ----------------------------------------------------------------------
; SAVE_WRITE_PROGRAM -- PUTC_FILE the lead byte in A, DE=VARTAB (end), HL=TXTTAB (start), fall into the copy loop. Shared by tokenized ($FF) and protected ($FE) SAVE.
; ----------------------------------------------------------------------
SAVE_WRITE_PROGRAM:
        CALL PUTC_FILE
        LD HL,(VARTAB)
        EX DE,HL
        LD HL,(TXTTAB)
; ----------------------------------------------------------------------
; SAVE_WRITE_PROGRAM_1 -- CMP_HL_DE; equal -> JP LOAD_CLEANUP_RESET (close); else read (HL), advance, preserve DE across PUTC_FILE, write, loop.
; ----------------------------------------------------------------------
SAVE_WRITE_PROGRAM_1:
        CALL CMP_HL_DE
        JP Z,LOAD_CLEANUP_RESET
        LD A,(HL)
        INC HL
        PUSH DE
        CALL PUTC_FILE
        POP DE
        JR SAVE_WRITE_PROGRAM_1
; ----------------------------------------------------------------------
; STMT_CLOSE -- BC=FILE_CLOSE_ONE; dispatcher Z: NZ -> JR STMT_CLOSE_4 (#n list); Z(no args) -> A=MAX_FILE_NUM seeds the count-down close-all loop. Also the A=0 entry from CLOSE_ALL_FILES; LD A,(MAX_FILE_NUM) does not change Z.
; ----------------------------------------------------------------------
STMT_CLOSE:
        LD BC,FILE_CLOSE_ONE
        LD A,(MAX_FILE_NUM)
        JR NZ,STMT_CLOSE_4
        PUSH HL
; ----------------------------------------------------------------------
; STMT_CLOSE_1 -- PUSH BC, PUSH AF, stage CLOSE_ALL_LOOP_NEXT as the return, PUSH/RET to FILE_CLOSE_ONE so closing file #A loops back.
; ----------------------------------------------------------------------
STMT_CLOSE_1:
        PUSH BC
        PUSH AF
        LD DE,CLOSE_ALL_LOOP_NEXT
        PUSH DE
        PUSH BC
        RET
; ----------------------------------------------------------------------
; CLOSE_ALL_LOOP_NEXT -- close-all loop tail (executable PUSH/RET target): POP index (AF)+BC, DEC A; JP P -> STMT_CLOSE_1, else POP HL/RET. CODE, not data.
; ----------------------------------------------------------------------
CLOSE_ALL_LOOP_NEXT:
        POP AF
        POP BC
        DEC A
        JP P,STMT_CLOSE_1
        POP HL
        RET
; ----------------------------------------------------------------------
; CLOSE_ONE_THEN_COMMA -- POP BC+text pointer; (HL) != ',' -> RET; on ',' CHRGET past it, fall into STMT_CLOSE_4. PUSH/RET return target, not data.
; ----------------------------------------------------------------------
CLOSE_ONE_THEN_COMMA:
        POP BC
        POP HL
        LD A,(HL)
        CP $2C
        RET NZ
        CALL CHRGET
; ----------------------------------------------------------------------
; STMT_CLOSE_4 -- skip optional '#', GETBYT the file number, swap onto the stack, stage CLOSE_ONE_THEN_COMMA as the return, JP (HL) to FILE_CLOSE_ONE; the comma list continues.
; ----------------------------------------------------------------------
STMT_CLOSE_4:
        PUSH BC
        LD A,(HL)
        CP $23
        CALL Z,CHRGET
        CALL GETBYT
        EX (SP),HL
        PUSH HL
        LD DE,CLOSE_ONE_THEN_COMMA
        PUSH DE
        JP (HL)
; ----------------------------------------------------------------------
; CLOSE_ALL_FILES -- save BC/DE, XOR A, CALL STMT_CLOSE (closes files MAX_FILE_NUM..0), restore BC/DE, return A=0. Invoked by NEW/CLEAR/RUN, SYSTEM, RESET.
; ----------------------------------------------------------------------
CLOSE_ALL_FILES:
        PUSH DE
        PUSH BC
        XOR A
        CALL STMT_CLOSE
        POP BC
        POP DE
        XOR A
        RET
; ----------------------------------------------------------------------
; STMT_FIELD -- FIELD statement (token $B9): bind FIELD string variables to fixed-width windows inside a random file's record buffer.
;   In:        HL = BASIC text cursor just past FIELD; the file/record-buffer FCB is resolved from the '#n' that follows (FILE_NUM_TO_FCB -> BC = FCB base, A = mode byte).
;   Out:       Each named string variable's 3-byte descriptor is rewritten so its body pointer aims at the next slice of FCB.RND_BUF; RET at the comma-less end of the field list.
;   Clobbers:  A,BC,DE,HL; scratch word L_0C93 (the record length, used here as the field-overflow limit) and RND_SECTOR_NUM (running field offset accumulator).
;   Algorithm: Require a mode-3 (random) FCB else 'Bad file mode'. Read the record length from FCB.FLD_BUF_PTR and save it to L_0C93 as the overflow limit; seed the running field offset (RND_SECTOR_NUM) to 0. Then loop (STMT_FIELD_1): each entry is 'width AS strvar' -- read the byte width, PTRGET the string variable, bump the running offset by the width, and if it exceeds the record length raise 'FIELD overflow'; otherwise overwrite the variable's descriptor with {len=width, ptr=RND_BUF + previous_offset} so the variable maps onto that window. Continue while the next char is ','. [RE] FCB.FLD_BUF_PTR is read here as a length/count, not a pointer, despite the include's 'buffer base pointer' name.
; ----------------------------------------------------------------------
STMT_FIELD:
        CALL FILE_NUM_TO_FCB
        JP Z,RAISE_BAD_FILE_NUMBER
        SUB $03
        ; FIELD requires a random (mode 3) file
        JP NZ,RAISE_BAD_FILE_MODE
        EX DE,HL
        LD HL,FCB.FLD_BUF_PTR
        ADD HL,BC
        LD A,(HL)
        INC HL
        LD H,(HL)
        LD L,A
        ; remember the record length as the field-overflow limit
        LD (L_0C93),HL
        LD HL,$0000
        ; running byte offset of the next field within the buffer = 0
        LD (RND_SECTOR_NUM),HL
        LD A,H
        EX DE,HL
        ; fields are mapped into the random data buffer (the FIELD window)
        LD DE,FCB.RND_BUF
; ----------------------------------------------------------------------
; STMT_FIELD_1 -- FIELD field-list loop body: consume one 'width AS variable' clause and map the variable onto the next buffer slice.
;   In:        BC = FCB base, DE/HL carry the running RND_BUF window pointer and text cursor; loop entry after each field.
;   Out:       On ',' processes the next field then re-enters; on any other char RET (end of FIELD list).
;   Clobbers:  A,BC,DE,HL; updates RND_SECTOR_NUM (cumulative offset) and the target variable's descriptor.
;   Algorithm: If the next text char is not ',' the field list is done -> RET. Otherwise parse the leading byte width (GETBYT_CHRGET), require the 'AS' keyword (SYNCHR 'A','S'), PTRGET the destination string variable, integer-type-check it (REQUIRE_STRING), add the width to the cumulative offset (RND_SECTOR_NUM), range-check the new offset against the record length (L_0C93) raising 'FIELD overflow' on excess, then write the variable's descriptor = {len=width, ptr=RND_BUF+old_offset}.
; ----------------------------------------------------------------------
STMT_FIELD_1:
        EX DE,HL
        ADD HL,BC
        LD B,A
        EX DE,HL
        LD A,(HL)
        ; ',' separates fields; anything else ends the FIELD list
        CP $2C
        RET NZ
        PUSH DE
        PUSH BC
        ; parse this field's byte width
        CALL GETBYT_CHRGET
        PUSH AF
        CALL SYNCHR
        DEFB    'A'                      ; inline char arg consumed by the preceding CALL
        CALL SYNCHR
        DEFB    'S'                      ; inline char arg consumed by the preceding CALL
        ; locate the destination string variable's descriptor
        CALL PTRGET_1+1
        CALL REQUIRE_STRING
        POP AF
        POP BC
        EX (SP),HL
        LD C,A
        PUSH DE
        PUSH HL
        LD HL,(RND_SECTOR_NUM)
        LD B,$00
        ADD HL,BC
        LD (RND_SECTOR_NUM),HL
        EX DE,HL
        LD HL,(L_0C93)
        CALL CMP_HL_DE
        ; fields would overrun the record buffer
        JP C,RAISE_FIELD_OVERFLOW
        POP HL
        POP DE
        EX DE,HL
        ; rewrite the variable as a fixed-width window onto the buffer: len=width, ptr=RND_BUF+offset
        LD (HL),C
        INC HL
        LD (HL),E
        INC HL
        LD (HL),D
        POP HL
        JR STMT_FIELD_1
; ----------------------------------------------------------------------
; STMT_RSET -- RSET statement (token $C3): right-justify a string value into a FIELD buffer variable. LSET (token $C2) enters at STMT_RSET+1 with the swallowed SCF giving the opposite carry.
;   In:        HL = text cursor past RSET/LSET; statement form is 'fieldvar = expr$'. The OR $37 (RSET) vs swallowed $37=SCF (LSET) flag-skip sets carry to distinguish the two; the carry is saved via PUSH AF and read later for pad direction.
;   Out:       The FIELD variable's window is overwritten with the source string, left-justified (LSET) or right-justified (RSET) and space-padded to the field width; RET.
;   Clobbers:  A,BC,DE,HL and the string temporaries/heap.
;   Algorithm: PTRGET the destination FIELD string variable and integer-type-check it; FRMEVL the right-hand string expression (EVAL_EXPR_AFTER_SYNCHR); FRETMP to resolve/free the source string temp leaving HL at its {len, ptr} descriptor. If the source length is 0 branch to STMT_RSET_5 (nothing to copy). [RE] Otherwise, if the source body lives in the movable dynamic string area (DE >= VARTAB and STREND+len > FRETOP) copy it to a fresh string temporary first (FIELD_PAD_SPACES_2 path) so the field move is stable; sources in program text are used directly (STMT_RSET_2). Then compute copy count = min(srclen, fieldwidth); for RSET pre-pad the leading bytes with spaces (NC path), copy the bytes, and for LSET trailing-pad with spaces (STMT_RSET_6).
; ----------------------------------------------------------------------
STMT_RSET:
        OR $37
        PUSH AF
        ; locate the destination FIELD variable (its descriptor = field width + buffer pointer)
        CALL PTRGET_1+1
        CALL REQUIRE_STRING
        PUSH DE
        ; evaluate the right-hand '= expr$' source string
        CALL EVAL_EXPR_AFTER_SYNCHR
        POP BC
        EX (SP),HL
        PUSH HL
        PUSH BC
        ; resolve/free the source string temp; HL -> its {len, ptr} descriptor
        CALL FRETMP
        LD B,(HL)
        EX (SP),HL
        LD A,(HL)
        LD C,A
        PUSH BC
        PUSH HL
        PUSH AF
        INC HL
        LD E,(HL)
        INC HL
        LD D,(HL)
        OR A
        ; empty source string -> skip the copy, just pad the field
        JP Z,STMT_RSET_5
        LD HL,(TXTTAB)
        CALL CMP_HL_DE
        JR NC,STMT_RSET_2
        LD HL,(VARTAB)
        CALL CMP_HL_DE
        JR C,STMT_RSET_2
        LD E,C
        LD D,$00
        LD HL,(STREND)
        ADD HL,DE
        EX DE,HL
        LD HL,(FRETOP)
        CALL CMP_HL_DE
        ; [RE] source lives in movable string space -> stage it to a fresh temp first
        JP C,FIELD_PAD_SPACES_2
; ----------------------------------------------------------------------
; STMT_RSET_1 -- LSET/RSET: allocate fresh string space for a movable source, copy it in, and rejoin the justify path.
;   In:        Saved source length and descriptor pointers on the stack from STMT_RSET / FIELD_PAD_SPACES_2.
;   Out:       The source string is materialised in newly allocated heap space whose descriptor pointer is patched in; falls into STMT_RSET_2 to perform the justified copy.
;   Clobbers:  A,BC,DE,HL; allocates string heap via GETSPA.
;   Algorithm: GETSPA(C) reserves field-width bytes of string space, FRETMP retires the temporary source descriptor, the new heap pointer is written back into the source descriptor, and control falls through to the descriptor-unpack + copy in STMT_RSET_2.
; ----------------------------------------------------------------------
STMT_RSET_1:
        POP AF
        LD A,C
        ; reserve fresh string space the field copy can safely move into
        CALL GETSPA
        POP HL
        POP BC
        EX (SP),HL
        PUSH DE
        PUSH BC
        CALL FRETMP
        POP BC
        POP DE
        EX (SP),HL
        PUSH BC
        PUSH HL
        INC HL
        LD (HL),E
        INC HL
        LD (HL),D
        PUSH AF
; ----------------------------------------------------------------------
; STMT_RSET_2 -- LSET/RSET justify core: unpack both descriptors and clamp the copy count.
;   In:        Stacked descriptor pointers for destination (FIELD var) and source string; the saved LSET/RSET carry flag is on the stack.
;   Out:       HL = source body ptr, DE = destination (FIELD-window) body ptr, B = copy count = min(srclen, fieldwidth); falls into STMT_RSET_3.
;   Clobbers:  A,BC,DE,HL.
;   Algorithm: Pop and unpack the two descriptors (each {len/width, ptr}); arrange source ptr in HL and field-window ptr in DE; compare source length (C) with field width (B) and set B = min(srclen, width) as the number of bytes to copy. Fall through to compute the pad count and dispatch the justified move. [RE] The exact register that holds width vs source-length through the stack juggling is not separately verified; the net effect (B = clamped copy count) is.
; ----------------------------------------------------------------------
STMT_RSET_2:
        POP AF
        POP HL
        INC HL
        LD E,(HL)
        INC HL
        LD D,(HL)
        POP BC
        POP HL
        PUSH DE
        INC HL
        LD E,(HL)
        INC HL
        LD D,(HL)
        EX DE,HL
        POP DE
        LD A,C
        ; clamp the copy count to the field width
        CP B
        JR NC,STMT_RSET_3
        LD B,A
; ----------------------------------------------------------------------
; STMT_RSET_3 -- compute pad count and perform the RSET right-justify pre-pad.
;   In:        B = bytes-to-copy; the saved LSET/RSET carry flag selects justification.
;   Out:       C = pad count = fieldwidth - copylen; for RSET (NC) the leading C bytes of the field are space-filled; then the byte copy proceeds in STMT_RSET_4.
;   Clobbers:  A,BC,DE.
;   Algorithm: pad = fieldwidth - copylen -> C; restore the saved justify flag; on the RSET branch (CALL NC,FIELD_PAD_SPACES) blank that many leading bytes so the data lands flush-right; INC B to prime the copy loop counter; then enter the copy loop.
; ----------------------------------------------------------------------
STMT_RSET_3:
        ; pad count = field width - bytes to copy
        SUB B
        LD C,A
        POP AF
        ; RSET: blank the leading bytes so the data is right-justified
        CALL NC,FIELD_PAD_SPACES
        INC B
; ----------------------------------------------------------------------
; STMT_RSET_4 -- byte-copy loop: move B bytes from source (HL) into the FIELD window (DE).
;   In:        B = byte count (pre-incremented), HL = source ptr, DE = destination ptr.
;   Out:       B bytes copied; on B reaching 0 branch to STMT_RSET_6 to apply any LSET trailing pad.
;   Clobbers:  A,B,DE,HL.
;   Algorithm: DEC B and test; copy (HL)->(DE), INC both, repeat until B reaches 0.
; ----------------------------------------------------------------------
STMT_RSET_4:
        DEC B
        JR Z,STMT_RSET_6
        LD A,(HL)
        LD (DE),A
        INC HL
        INC DE
        JP STMT_RSET_4
; ----------------------------------------------------------------------
; STMT_RSET_5 -- LSET/RSET empty-source path: discard the staged work frames when the source string has zero length.
;   In:        Reached from STMT_RSET when the source string length is 0 (the OR A / JP Z test).
;   Out:       Five staged work words are dropped; falls into STMT_RSET_6, which space-fills the whole field on the LSET (carry) path.
;   Clobbers:  BC, SP (frame cleanup).
;   Algorithm: Five POP BC instructions unwind the descriptor/length/flag frames pushed by STMT_RSET, then fall through to the common exit where an empty source means the field is fully padded.
; ----------------------------------------------------------------------
STMT_RSET_5:
        ; drop the five staged work words (empty source, nothing to copy)
        POP BC
        POP BC
        POP BC
        POP BC
        POP BC
; ----------------------------------------------------------------------
; STMT_RSET_6 -- LSET/RSET common exit: apply the LSET trailing pad and return.
;   In:        Carry (the saved justify flag) set for LSET, with C = remaining pad count and DE = current field position.
;   Out:       For LSET the unused tail of the field is space-filled; the saved text cursor is restored to HL; RET.
;   Clobbers:  A,C,DE,HL.
;   Algorithm: On carry (LSET) call FIELD_PAD_SPACES to blank the trailing bytes after the copied data; POP HL restores the caller's text cursor; RET.
; ----------------------------------------------------------------------
STMT_RSET_6:
        ; LSET: blank the trailing bytes so the data is left-justified
        CALL C,FIELD_PAD_SPACES
        POP HL
        RET
; ----------------------------------------------------------------------
; FIELD_PAD_SPACES -- fill C bytes at (DE) with ASCII spaces; the LSET/RSET field-blanking primitive.
;   In:        C = byte count, DE = destination pointer.
;   Out:       C bytes set to $20 (space); DE advanced past them; RET when the count reaches 0.
;   Clobbers:  A,C,DE.
;   Algorithm: Load A=$20, INC C, then store-decrement in the FIELD_PAD_SPACES_1 loop until the count is exhausted.
; ----------------------------------------------------------------------
FIELD_PAD_SPACES:
        LD A,$20
        INC C
; ----------------------------------------------------------------------
; FIELD_PAD_SPACES_1 -- inner loop of FIELD_PAD_SPACES: store A (space) at (DE)++ while decrementing C.
;   In:        A = $20, C = remaining count, DE = destination.
;   Out:       RET when C reaches 0.
;   Clobbers:  C,DE.
;   Algorithm: DEC C; RET Z; store A at (DE); INC DE; repeat.
; ----------------------------------------------------------------------
FIELD_PAD_SPACES_1:
        DEC C
        RET Z
        LD (DE),A
        INC DE
        JR FIELD_PAD_SPACES_1
; ----------------------------------------------------------------------
; FIELD_PAD_SPACES_2 -- RSET/LSET movable-source handler: when the source string body lives in the dynamic string area, copy it to a string temporary before the field move.
;   In:        Stacked descriptor/flag frames from STMT_RSET; B = source length.
;   Out:       The source body is staged into a fresh temporary descriptor (when the type discriminator requires it); rejoins via FIELD_PAD_SPACES_3 -> STMT_RSET_1.
;   Clobbers:  A,BC,DE,HL; may allocate via ALLOC_STR_A and stage via PUT_STR_TEMP.
;   Algorithm: Pop the saved flags/pointers; [RE] if a non-zero discriminator is set, ALLOC_STR_A(B) reserves space and PUT_STR_TEMP records the temporary; then re-push the working frames and fall into FIELD_PAD_SPACES_3.
; ----------------------------------------------------------------------
FIELD_PAD_SPACES_2:
        POP AF
        POP HL
        POP BC
        EX (SP),HL
        EX DE,HL
        JR NZ,FIELD_PAD_SPACES_3
        PUSH BC
        LD A,B
        ; copy the movable source to a fresh string temporary so the field move is stable
        CALL ALLOC_STR_A
        CALL PUT_STR_TEMP
        POP BC
; ----------------------------------------------------------------------
; FIELD_PAD_SPACES_3 -- re-stack the working frames and jump back into the RSET allocate/copy path.
;   In:        Working pointers in HL/BC and saved flags around the stack from FIELD_PAD_SPACES_2.
;   Out:       Re-pushes the frames and JP STMT_RSET_1 to finish the justified store.
;   Clobbers:  HL,BC, stack.
;   Algorithm: EX (SP),HL / PUSH BC / PUSH HL / PUSH AF to rebuild the expected frame layout, then JP STMT_RSET_1.
; ----------------------------------------------------------------------
FIELD_PAD_SPACES_3:
        EX (SP),HL
        PUSH BC
        PUSH HL
        PUSH AF
        JP STMT_RSET_1
; ----------------------------------------------------------------------
; FN_INPUT_DOLLAR -- INPUT$() function handler (FRMEVL function dispatch on TOK_INPUT at $3450): read exactly N characters from the console or an open file into a string.
;   In:        HL = text cursor at 'INPUT$' call; syntax INPUT$(count [,#filenum]).
;   Out:       FAC holds a string descriptor for the N collected characters (staged via PUT_STR_TEMP); on Ctrl-C from the console it aborts to direct mode.
;   Clobbers:  A,BC,DE,HL; allocates string space; sets the current file via PTRFIL when a file source is given.
;   Algorithm: CHRGET, then require '$' and '(' (SYNCHR), GETBYT the character count. If a ',' follows, CHRGET past it, FILE_NUM_TO_FCB the file number (reject mode 2 = sequential-output as 'Bad file mode'), set it current (STORE_CUR_FCB_PTR) and select the file source (XOR A => Z); else select the console source. Require ')'. Reject count 0 ('Illegal function call'). ALLOC_STR_A reserves count bytes, then FN_INPUT_DOLLAR_2 fills them from either the file (GETC_FILE_EOF) or the pending-key/CONIN console read.
; ----------------------------------------------------------------------
FN_INPUT_DOLLAR:
        CALL CHRGET
        CALL SYNCHR
        DEFB    '$'                      ; inline char arg consumed by the preceding CALL
        CALL SYNCHR
        DEFB    '('                      ; inline char arg consumed by the preceding CALL
        ; parse the character count
        CALL GETBYT
        PUSH DE
        LD A,(HL)
        ; ',' introduces an optional '#filenum' source
        CP $2C
        JR NZ,FN_INPUT_DOLLAR_1
        CALL CHRGET
        CALL FILE_NUM_TO_FCB
        CP $02
        ; INPUT$ cannot read from a mode-2 sequential-output file
        JP Z,RAISE_BAD_FILE_MODE
        ; make this file the current input source
        CALL STORE_CUR_FCB_PTR
        XOR A
; ----------------------------------------------------------------------
; FN_INPUT_DOLLAR_1 -- INPUT$ source-selected join point: require the closing ')' and validate the count.
;   In:        A/flags hold the console-vs-file source selector (Z = file); the count is staged on the stack.
;   Out:       Falls through to the allocate-and-read body; raises 'Illegal function call' if the count is 0.
;   Clobbers:  A,HL, stack.
;   Algorithm: SYNCHR ')', recover the count into L, reject 0 (ERROR_FC), then ALLOC_STR_A the result string and continue into the read loop.
; ----------------------------------------------------------------------
FN_INPUT_DOLLAR_1:
        PUSH AF
        CALL SYNCHR
        DEFB    ')'                      ; inline char arg consumed by the preceding CALL
        POP AF
        EX (SP),HL
        PUSH AF
        LD A,L
        OR A
        ; INPUT$(0) is illegal
        JP Z,ERROR_FC
        PUSH HL
        ; reserve count bytes for the result string
        CALL ALLOC_STR_A
        EX DE,HL
        POP BC
; ----------------------------------------------------------------------
; FN_INPUT_DOLLAR_2 -- INPUT$ character-collection loop: gather one character per iteration from the selected source.
;   In:        HL = next byte slot in the allocated string, C = remaining count, the source selector saved on the stack (Z = file).
;   Out:       Loops to FN_INPUT_DOLLAR_4 to store each char; on the file source jumps to FN_INPUT_DOLLAR_6.
;   Clobbers:  A,HL,C.
;   Algorithm: Restore the source flag; if file-source (Z) go to FN_INPUT_DOLLAR_6 (GETC_FILE_EOF). Otherwise read the console: take a pending typed-ahead key if any (GET_PENDING_KEY), else CONIN.
; ----------------------------------------------------------------------
FN_INPUT_DOLLAR_2:
        POP AF
        PUSH AF
        ; file source: read the next file byte instead of the console
        JR Z,FN_INPUT_DOLLAR_6
        ; consume a typed-ahead key if one is pending
        CALL GET_PENDING_KEY
        JR NZ,FN_INPUT_DOLLAR_3
        ; otherwise read a raw character from the console
        CALL CONIN
; ----------------------------------------------------------------------
; FN_INPUT_DOLLAR_3 -- INPUT$ Ctrl-C test before storing a console character.
;   In:        A = freshly read console character.
;   Out:       On Ctrl-C ($03) abort to direct mode (FN_INPUT_DOLLAR_5); else fall into FN_INPUT_DOLLAR_4 to store the byte.
;   Clobbers:  none beyond the branch.
;   Algorithm: CP $03; JP Z to the break path; otherwise continue to store the byte.
; ----------------------------------------------------------------------
FN_INPUT_DOLLAR_3:
        CP $03
        JP Z,FN_INPUT_DOLLAR_5
; ----------------------------------------------------------------------
; FN_INPUT_DOLLAR_4 -- INPUT$ store-and-count: write the character and finish when the count reaches 0.
;   In:        A = character, HL = destination slot, C = remaining count.
;   Out:       When all characters are collected, resets print state (PRINT_RESET_STATE) and stages the string via PUT_STR_TEMP (the function result).
;   Clobbers:  A,HL,C.
;   Algorithm: Store A at (HL), INC HL, DEC C; loop back to FN_INPUT_DOLLAR_2 while C != 0; when done, PRINT_RESET_STATE then JP PUT_STR_TEMP to return the descriptor.
; ----------------------------------------------------------------------
FN_INPUT_DOLLAR_4:
        LD (HL),A
        INC HL
        DEC C
        JR NZ,FN_INPUT_DOLLAR_2
        POP AF
        CALL PRINT_RESET_STATE
        ; all characters collected -> return the string value
        JP PUT_STR_TEMP
; ----------------------------------------------------------------------
; FN_INPUT_DOLLAR_5 -- INPUT$ console Ctrl-C abort: drop to direct-command mode.
;   In:        Ctrl-C detected during a console INPUT$.
;   Out:       Stack reset to SAVSTK; control transferred to the direct-mode resume point (never returns).
;   Clobbers:  SP,HL.
;   Algorithm: Reload SP from SAVSTK to discard the pending expression frames, then JP RESUME_AT_DIRECT.
; ----------------------------------------------------------------------
FN_INPUT_DOLLAR_5:
        LD HL,(SAVSTK)
        LD SP,HL
        JP RESUME_AT_DIRECT
; ----------------------------------------------------------------------
; FN_INPUT_DOLLAR_6 -- INPUT$ file-source character read: fetch one byte from the open file, trapping EOF.
;   In:        The current file (PTRFIL) is the input source; HL/C are the collection cursor/count.
;   Out:       A = next file byte; on EOF raises 'Input past end' (error 62); otherwise rejoins FN_INPUT_DOLLAR_4 to store the byte.
;   Clobbers:  A (and whatever GETC_FILE_EOF touches).
;   Algorithm: CALL GETC_FILE_EOF; on carry (EOF) JP RAISE_INPUT_PAST_END; else JP FN_INPUT_DOLLAR_4 to store the byte.
; ----------------------------------------------------------------------
FN_INPUT_DOLLAR_6:
        ; read the next byte from the file source
        CALL GETC_FILE_EOF
        ; ran off the end of the file
        JP C,RAISE_INPUT_PAST_END
        JP FN_INPUT_DOLLAR_4
; ----------------------------------------------------------------------
; FN_EOF -- EOF() function (token TOK_EOF $2E): test whether the file's input stream is at end.
;   In:        File-number expression in source (FUNC_DISPATCH_TBL slot $020C).
;   Out:       FAC = -1 (true) at end-of-file, 0 (false) otherwise.
;   Clobbers:  AF, BC, DE, HL.
;   Algorithm: Resolve the file number to its FCB; 'Bad file number' if closed, 'Bad file mode' if the
;              file is open for output (mode $02). Then fall into FN_EOF_1 to inspect the read buffer.
; ----------------------------------------------------------------------
FN_EOF:
        CALL FILE_NUM_TO_FCB_NZ
        JP Z,RAISE_BAD_FILE_NUMBER
        ; EOF is meaningless on a sequential-output file -> Bad file mode
        CP $02
        JP Z,RAISE_BAD_FILE_MODE
; ----------------------------------------------------------------------
; FN_EOF_1 -- EOF core: determine end-of-file by examining/refilling the file buffer.
;   In:        BC = FCB base.
;   Out:       Result truth value computed and tail-jumped to INT16_TO_FP (A entering FN_EOF_3:
;              $00 => not-EOF, otherwise => EOF).
;   Clobbers:  AF, BC, DE, HL.
;   Algorithm: Read FCB.BUF_CNT (offset $27, record fill level). If 0 the buffer is empty => EOF
;              (FN_EOF_3 with A=0). [RE] Otherwise, if the file is RANDOM (FCB.MODE $03) it jumps to
;              FN_EOF_3 carrying A=$03, which maps to NOT-EOF (false) -- EOF on a buffered random file
;              reports false here. Else check FCB.BUF_REM (offset $28): if bytes remain, go to FN_EOF_2
;              to look for a Ctrl-Z; if the buffer is exhausted (BUF_REM 0) but the status byte allows,
;              read the next record (FILE_READ_RECORD_FCB) and retry. This look-ahead lets sequential
;              EOF report true exactly when only the $1A marker / nothing remains.
; ----------------------------------------------------------------------
FN_EOF_1:
        ; FCB.BUF_CNT ($27): how many bytes the current record holds; 0 => buffer empty => EOF
        LD HL,FCB.BUF_CNT
        ADD HL,BC
        LD A,(HL)
        OR A
        JR Z,FN_EOF_3
        LD A,(BC)
        CP $03
        JR Z,FN_EOF_3
        INC HL
        LD A,(HL)
        OR A
        JR NZ,FN_EOF_2
        PUSH BC
        LD H,B
        LD L,C
        ; buffer drained: read the next sequential record into the FCB buffer and re-test
        CALL FILE_READ_RECORD_FCB
        POP BC
        JR FN_EOF_1
; ----------------------------------------------------------------------
; FN_EOF_2 -- EOF: test for the Ctrl-Z ($1A) text end-of-file marker at the buffer's next byte.
;   In:        HL at FCB.BUF_REM ($28); FCB buffer holds the current record.
;   Out:       A = 0 if the next unread byte is the $1A EOF mark, nonzero otherwise.
;   Clobbers:  AF, BC, HL.
;   Algorithm: Compute the position of the next unread byte within the 128-byte record as
;              ($80 - BUF_REM), index into SEQ_BUF, load that byte and SUB $1A so a $1A (Ctrl-Z, CP/M
;              text EOF) yields zero. Fall into FN_EOF_3 to turn the test into the BASIC truth value.
; ----------------------------------------------------------------------
FN_EOF_2:
        LD A,$80
        SUB (HL)
        LD C,A
        LD B,$00
        ADD HL,BC
        INC HL
        LD A,(HL)
        ; $1A = Ctrl-Z, the CP/M soft end-of-file marker for text files
        SUB $1A
; ----------------------------------------------------------------------
; FN_EOF_3 -- EOF: convert the at-end test into a BASIC boolean and return it as a number.
;   In:        A = 0 when at end-of-file, nonzero otherwise (from the buffer/marker tests above).
;   Out:       FAC = -1 (true) or 0 (false) via INT16_TO_FP.
;   Clobbers:  AF, HL.
;   Algorithm: SUB $01 / SBC A,A maps A==0 -> $FF (true) and A!=0 -> $00 (false), then INT16_TO_FP
;              sign-extends A into a 16-bit integer FAC (the BASIC TRUE/FALSE convention).
; ----------------------------------------------------------------------
FN_EOF_3:
        SUB $01
        SBC A,A
        JP INT16_TO_FP
; ----------------------------------------------------------------------
; FILE_FLUSH_RECORD -- flush the current output record to disk, then advance the record number
;   In:        BC = FCB base of the open output file
;   Out:       FCB.SEQ_RECNO incremented; record written via BDOS
;   Clobbers:  A, DE, HL, flags
;   Algorithm: Sets DE = &FCB.CPM (BC+1) for the BDOS call, then falls into
;              FILE_FLUSH_RECORD_CK which clears BUF_CNT, points the CP/M DMA at the
;              record buffer, issues the BDOS record-write (function code held in
;              BDOS_FN_RECWRITE -- random-write $22 on CP/M 2.x / sequential-write
;              $15 on 1.x, selected at cold start), maps the result to a BASIC error,
;              and bumps SEQ_RECNO.
; ----------------------------------------------------------------------
FILE_FLUSH_RECORD:
        LD D,B
        LD E,C
        ; DE = &FCB.CPM (FCB base + 1) -- the pointer every BDOS file call expects
        INC DE
; ----------------------------------------------------------------------
; FILE_FLUSH_RECORD_CK -- write one 128-byte record to disk and translate the BDOS result
;   In:        BC = FCB base; DE = &FCB.CPM (BC+1)
;   Out:       record written; on the disk-full code the file is closed and DISK FULL is raised
;   Clobbers:  A, HL, BC/DE (BC popped back in the success tail), flags
;   Algorithm: Zeroes FCB.BUF_CNT (record now empty), sets the CP/M DMA to the
;              record buffer, then issues the record write through BDOS_FILE_CALL
;              using the cold-start-selected function code BDOS_FN_RECWRITE. Decodes
;              BDOS_FILE_CALL's (already-partially-translated) return: $FF -> too many
;              files; $01 -> disk I/O error; $02 -> zero the MODE byte, BDOS-close the
;              FCB, and raise DISK FULL; any other value -> the success tail
;              FILE_FLUSH_RECORD_CK_1.
;   [RE] Several BDOS result codes are pre-mapped inside BDOS_FILE_CALL on the 2.x
;   random-write path, so the $FF/$01/$02 split here is this routine's view of the
;   already-translated code, not the raw BDOS return.
; ----------------------------------------------------------------------
FILE_FLUSH_RECORD_CK:
        LD HL,FCB.BUF_CNT
        ADD HL,BC
        PUSH BC
        ; disk full: zero the MODE byte (FCB base) so the slot reads as closed
        XOR A
        ; reset BUF_CNT = 0: the record buffer is now considered empty
        LD (HL),A
        ; aim the CP/M DMA at this file's 128-byte record buffer before the write
        CALL BDOS_SET_DMA_FCB
        ; load the write function code chosen at startup (random-write on 2.x, seq-write on 1.x)
        LD A,(BDOS_FN_RECWRITE)
        CALL BDOS_FILE_CALL
        ; [RE] $FF -> too many open files
        CP $FF
        JP Z,RAISE_TOO_MANY_FILES
        DEC A
        ; translated code $01 = disk I/O error
        JP Z,RAISE_DISK_I_O_ERROR
        DEC A
        JP NZ,FILE_FLUSH_RECORD_CK_1
        POP DE
        XOR A
        LD (DE),A
        ; BDOS Close-File on the FCB before raising DISK FULL
        LD C,F_CLOSE
        INC DE
        CALL BDOS
        JP RAISE_DISK_FULL
; ----------------------------------------------------------------------
; FILE_FLUSH_RECORD_CK_1 -- success tail of the record write: bump the sequential record number
;   In:        A = (translated) BDOS result, already known to be neither $FF/$01/$02; BC = FCB base (on stack, popped here)
;   Out:       FCB.SEQ_RECNO incremented by 1
;   Clobbers:  A, BC, DE, HL, flags
;   Algorithm: Loads the 16-bit SEQ_RECNO from the FCB, increments it, and stores it
;              back so the next write targets the following record.
;   [RE] The leading INC A / JP Z,RAISE_TOO_MANY_FILES is a redundant guard: the
;   only path here is the JP NZ for result != $02, and result $01 (which INC A would
;   catch) was already diverted to RAISE_DISK_I_O_ERROR upstream, so it never fires
;   under the current decode (likely a vestige of generic BDOS-result handling).
; ----------------------------------------------------------------------
FILE_FLUSH_RECORD_CK_1:
        INC A
        JP Z,RAISE_TOO_MANY_FILES
        POP BC
        ; advance the 16-bit sequential record counter for the next write
        LD HL,FCB.SEQ_RECNO
        ADD HL,BC
        LD E,(HL)
        INC HL
        LD D,(HL)
        INC DE
        LD (HL),D
        DEC HL
        LD (HL),E
        RET
; ----------------------------------------------------------------------
; FILE_CLOSE_ONE -- close one open file: pad/flush, BDOS close, and clear the FCB slot
;   In:        E = file number (from the caller via FILE_NUM_TO_FCB_A, which also sets BC = FCB base)
;   Out:       file closed on disk; the FCB header ($29 bytes) zeroed (MODE back to closed)
;   Clobbers:  A, BC, DE, HL, flags
;   Algorithm: Resolves the file number to its FCB; if already closed (MODE=0) jumps
;              straight to the slot-clear. For a sequential-output file (MODE=2) it
;              appends a trailing Ctrl-Z/EOF byte (via the PUTC_FILE_1 path) and
;              flushes the final partial record, then issues BDOS F_CLOSE, and finally
;              zeroes the FCB header so the slot reads as closed.
;   [RE] When MODE=2 AND the file number is 0 (the program / LOAD-SAVE channel) it
;   first zeroes the MODE byte before padding -- exact reason for the file#0
;   special-case is UNKNOWN.
; ----------------------------------------------------------------------
FILE_CLOSE_ONE:
        ; resolve file number -> BC=FCB base, A=MODE byte; Z if the slot is already closed
        CALL FILE_NUM_TO_FCB_A
        JR Z,FILE_CLOSE_ONE_4
        LD L,E
        PUSH BC
        LD A,(BC)
        LD D,B
        LD E,C
        INC DE
        PUSH DE
        ; only sequential-output files (MODE=2) need the Ctrl-Z pad and final-record flush
        CP $02
        JR NZ,FILE_CLOSE_ONE_3
        INC L
        DEC L
        JR NZ,FILE_CLOSE_ONE_1
        XOR A
        LD (BC),A
; ----------------------------------------------------------------------
; FILE_CLOSE_ONE_1 -- emit the trailing Ctrl-Z EOF marker into the output buffer
;   In:        BC = FCB base of the sequential-output file
;   Out:       Ctrl-Z ($1A) appended to the buffer (record flushed first if it filled)
;   Clobbers:  A, BC, DE, HL, flags; returns into FILE_CLOSE_ONE_2
;   Algorithm: Pushes the return address FILE_CLOSE_ONE_2 twice (PUTC_FILE_1's tail
;              does POP HL/RET, so the first copy satisfies its saved-HL POP and the
;              second is the actual return), sets HL = FCB base, A = $1A, and jumps
;              into PUTC_FILE_1 to append the EOF byte through the buffered-write path.
; ----------------------------------------------------------------------
FILE_CLOSE_ONE_1:
        LD HL,FILE_CLOSE_ONE_2
        PUSH HL
        PUSH HL
        LD H,B
        LD L,C
        ; A = Ctrl-Z (CP/M text EOF); append it via the buffered PUTC path
        LD A,$1A
        JR PUTC_FILE_1
; ----------------------------------------------------------------------
; FILE_CLOSE_ONE_2 -- after EOF byte: flush the final partial record if non-empty
;   In:        BC = FCB base
;   Out:       any buffered bytes written to disk
;   Clobbers:  A, HL, DE, flags; falls into FILE_CLOSE_ONE_3
;   Algorithm: Reads FCB.BUF_CNT; if non-zero (a partly-filled record remains) calls
;              FILE_FLUSH_RECORD_CK to write it, then falls through to the BDOS close.
; ----------------------------------------------------------------------
FILE_CLOSE_ONE_2:
        LD HL,FCB.BUF_CNT
        ADD HL,BC
        LD A,(HL)
        OR A
        ; flush the last partial record only if it holds data
        CALL NZ,FILE_FLUSH_RECORD_CK
; ----------------------------------------------------------------------
; FILE_CLOSE_ONE_3 -- issue BDOS Close-File on the FCB
;   In:        FCB+1 (&FCB.CPM) saved on the stack; FCB base also on the stack
;   Out:       file directory entry committed by the BDOS; BC = FCB base recovered
;   Clobbers:  A, BC, DE, HL, flags; falls into FILE_CLOSE_ONE_4
;   Algorithm: Pops DE = &FCB.CPM, sets the DMA via BDOS_SET_DMA_FCB (carried over;
;              F_CLOSE itself does not use the DMA), then calls BDOS F_CLOSE ($10) to
;              commit the directory entry, and pops BC = FCB base for the slot-clear.
; ----------------------------------------------------------------------
FILE_CLOSE_ONE_3:
        POP DE
        CALL BDOS_SET_DMA_FCB
        ; BDOS Close-File: commit the directory entry to disk
        LD C,F_CLOSE
        CALL BDOS
        POP BC
; ----------------------------------------------------------------------
; FILE_CLOSE_ONE_4 -- prepare to wipe the FCB header
;   In:        BC = FCB base
;   Out:       D = $29 (byte count to clear), A = 0
;   Clobbers:  A, D; falls into FILE_CLOSE_ONE_5
;   Algorithm: Loads the clear length D = $29 (offsets $00..$28: MODE + 36-byte CP/M
;              FCB + SEQ_RECNO + BUF_CNT + BUF_REM, i.e. everything before SEQ_BUF) and
;              A = 0 fill byte.
; ----------------------------------------------------------------------
FILE_CLOSE_ONE_4:
        ; $29 bytes = the FCB header (MODE + CP/M FCB + SEQ_RECNO + BUF_CNT/BUF_REM), i.e. through the byte before SEQ_BUF ($29)
        LD D,$29
        XOR A
; ----------------------------------------------------------------------
; FILE_CLOSE_ONE_5 -- zero-fill loop that clears the FCB header
;   In:        BC = FCB base; D = byte count; A = 0
;   Out:       D bytes from FCB base cleared to 0 (MODE=0 -> slot reads as closed)
;   Clobbers:  BC (advanced), D (to 0), flags
;   Algorithm: Stores A=0 into (BC), increments BC, decrements D, loops until D=0,
;              then returns.
; ----------------------------------------------------------------------
FILE_CLOSE_ONE_5:
        LD (BC),A
        INC BC
        DEC D
        JR NZ,FILE_CLOSE_ONE_5
        RET
; ----------------------------------------------------------------------
; FN_LOC_VALUE -- LOC() function (token TOK_LOC $2F): current record/position number of a file.
;   In:        File-number expression in source (FUNC_DISPATCH_TBL slot $020E).
;   Out:       FAC = the file's current 16-bit record number.
;   Clobbers:  AF, BC, DE, HL.
;   Algorithm: Resolve the file number to its FCB ('Bad file number' if closed). Select the record-
;              number field by mode: random (mode $03) uses FCB.RND_RECNO ($AD), sequential uses
;              FCB.SEQ_RECNO ($25). It points HL at the field's HIGH byte (+1) and falls into
;              FN_LOC_VALUE_1, which assembles the FULL 16-bit value into the FAC (not just the high
;              byte).
; ----------------------------------------------------------------------
FN_LOC_VALUE:
        CALL FILE_NUM_TO_FCB_NZ
        JP Z,RAISE_BAD_FILE_NUMBER
        ; random files report RND_RECNO ($AD); sequential files report SEQ_RECNO ($25)
        CP $03
        LD HL,FCB.SEQ_RECNO+1
        JR NZ,FN_LOC_VALUE_1
        LD HL,FCB.RND_RECNO+1
; ----------------------------------------------------------------------
; FN_LOC_VALUE_1 -- LOC() tail: load the selected 16-bit record number into the FAC.
;   In:        HL = FCB-relative high-byte address of the chosen record-number field; BC = FCB base.
;   Out:       FAC = the 16-bit record number (loaded via FP_LOAD_INT_TO_FAC_1).
;   Clobbers:  AF, HL.
;   Algorithm: ADD HL,BC to make it absolute, read the high byte (A) then DEC HL and read the low byte
;              (L), so HL=record number; FP_LOAD_INT_TO_FAC_1 (LD H,A) stores it as an integer in the FAC.
; ----------------------------------------------------------------------
FN_LOC_VALUE_1:
        ADD HL,BC
        LD A,(HL)
        DEC HL
        LD L,(HL)
        JP FP_LOAD_INT_TO_FAC_1
; ----------------------------------------------------------------------
; FN_LOF_VALUE -- LOF() function (token TOK_LOF $30): length of the open file, in CP/M records.
;   In:        File-number expression in source (FUNC_DISPATCH_TBL slot $0210).
;   Out:       FAC = the record count from the FCB's current extent (0..128).
;   Clobbers:  AF, BC, DE, HL.
;   Algorithm: [RE] This is the REAL LOF(); the similarly named FN_MKI_STR/_1/_2 above are actually MKI$/
;              MKS$/MKD$. Resolve the file number to its FCB ('Bad file number' if closed), read the
;              single byte FCB.CPM.RC (offset $0F, record count in the current extent) and return it as
;              a number via FP_LOAD_INT_TO_FAC (8-bit, high byte 0). [RE] this reports the size of the
;              current extent, not necessarily the whole multi-extent file -- consistent with CP/M's RC
;              field semantics.
; ----------------------------------------------------------------------
FN_LOF_VALUE:
        CALL FILE_NUM_TO_FCB_NZ
        JP Z,RAISE_BAD_FILE_NUMBER
        ; FCB.CPM.RC ($0F): record count in the current extent = file length in 128-byte records
        LD HL,FCB.CPM.RC
        ADD HL,BC
        LD A,(HL)
        JP FP_LOAD_INT_TO_FAC
; ----------------------------------------------------------------------
; PUTC_FILE_RESUME -- restore caller context and fall into the file-byte writer.
;   In:        Two saved words on the stack: AF (the char) and HL, pushed by OUTCHR before it
;              jumped here (OUTCHR does JP NZ,here when PTRFIL!=0).
;   Out:       Restores HL and AF, then falls into PUTC_FILE to emit the byte to the current file.
;   Clobbers:  AF, HL.
;   Algorithm: [RE] Despite the PUTC_FILE_RESUME name this is part of the file-output character path, not
;              LOF. OUTCHR (PUSH AF/PUSH HL, then detects PTRFIL!=0) jumps here; this POPs HL and AF so
;              PUTC_FILE can buffer the byte and flush full records. Naming-only mismatch (it shares
;              the address region with the LOF code).
; ----------------------------------------------------------------------
PUTC_FILE_RESUME:
        POP HL
        POP AF
; ----------------------------------------------------------------------
; PUTC_FILE -- write one byte to the open file, dispatching on file mode
;   In:        A = byte to write; PTRFIL ($0840) = current file's FCB base
;   Out:       byte routed to the sequential buffer, or to the random/FIELD-store path
;   Clobbers:  A, HL, flags (the saved A/HL are popped per path)
;   Algorithm: Pushes HL and A, reads the current file's MODE byte. MODE=1 (seq
;              input) -> STMT_ERASE_3, which simply pops the saved A/HL and RETs to the
;              caller (the byte is discarded -- this is NOT an error raise). MODE=3
;              (random) -> PUTC_FILE_RANDOM, the FIELD-buffer store path. Otherwise (seq
;              output, MODE=2) it pops A and falls into PUTC_FILE_1 to append the byte.
;   [RE] Writing to a MODE=1 (input) file is silently a no-op here; if BASIC reports
;   a 'bad file mode' it must do so elsewhere -- UNKNOWN whether any error surfaces.
; ----------------------------------------------------------------------
PUTC_FILE:
        PUSH HL
        PUSH AF
        ; HL = current file's FCB base; (HL) = its MODE byte
        LD HL,(PTRFIL)
        LD A,(HL)
        CP $01
        ; MODE=1 (sequential input): pop saved A/HL and return to caller -- the byte is discarded
        JP Z,STMT_ERASE_3
        CP $03
        ; MODE=3 (random): divert to the FIELD-buffer store path
        JP Z,PUTC_FILE_RANDOM
        POP AF
; ----------------------------------------------------------------------
; PUTC_FILE_1 -- append one byte to the sequential output record buffer
;   In:        A = byte; HL = FCB base; (an extra saved HL is on the stack per the caller contract)
;   Out:       byte stored into SEQ_BUF at the current fill offset; record flushed first if it was full
;   Clobbers:  A, BC, DE, HL, flags (the byte and a saved HL are consumed)
;   Algorithm: If FCB.BUF_CNT == $80 the 128-byte record is full, so it calls
;              FILE_FLUSH_RECORD to write it and reset the count; then it increments
;              BUF_CNT to claim the next slot and computes BC = new BUF_CNT. It also
;              maintains FCB.BUF_REM ($28) as a per-file output column counter: a CR
;              byte ($0D) resets it to 0, otherwise it adds 1 for a printable byte
;              (>= $20). Finally it stores the byte into the buffer via PUTC_FILE_2.
;   [RE] BUF_REM ($28) is dual-use: a per-file print-column counter on the write
;   path (here) and the remaining-bytes/EOF status on the read path. Its exact role
;   in PRINT# TAB/comma-zone alignment is inferred, not verified.
; ----------------------------------------------------------------------
PUTC_FILE_1:
        PUSH DE
        PUSH BC
        LD B,H
        LD C,L
        PUSH AF
        LD DE,FCB.BUF_CNT
        ADD HL,DE
        LD A,(HL)
        ; BUF_CNT == 128: the record is full, flush it before adding more
        CP $80
        PUSH HL
        ; write the full record and reset the fill count
        CALL Z,FILE_FLUSH_RECORD
        POP HL
        ; claim the next buffer slot: BUF_CNT++
        INC (HL)
        LD C,(HL)
        LD B,$00
        INC HL
        POP AF
        PUSH AF
        LD D,(HL)
        ; [RE] CR resets the per-file output column counter (FCB.BUF_REM); other printable bytes increment it
        CP $0D
        LD (HL),B
        JR Z,PUTC_FILE_2
        ADD A,$E0
        LD A,D
        ADC A,B
        LD (HL),A
; ----------------------------------------------------------------------
; PUTC_FILE_2 -- store the byte at the computed buffer offset and restore state
;   In:        HL = FCB+$28 (one before SEQ_BUF); BC = new BUF_CNT; saved A/BC/DE/HL on stack
;   Out:       byte written into SEQ_BUF at the just-claimed slot
;   Clobbers:  HL; restores A, BC, DE, HL from the stack
;   Algorithm: Adds BC (new BUF_CNT) to HL so HL = FCB+$28+BUF_CNT = &SEQ_BUF[BUF_CNT-1],
;              pops the saved byte and registers, writes the byte, and returns.
; ----------------------------------------------------------------------
PUTC_FILE_2:
        ; HL = FCB+$28 + BUF_CNT -> the SEQ_BUF slot for this byte
        ADD HL,BC
        POP AF
        POP BC
        POP DE
        LD (HL),A
        POP HL
        RET
; ----------------------------------------------------------------------
; PUTC_FILE_3 -- random GET/PUT: position the CP/M record from SEQ_RECNO, then read or flush
;   In:        HL = &FCB.SEQ_RECNO+1; DE = record number; FCB base reachable via the stacked caller frame
;   Out:       SEQ_RECNO and FCB.CPM.R0/R1/R2 set from the (decremented) record number; record read or flushed
;   Clobbers:  A, BC, DE, HL, flags
;   Algorithm: Decrements the 16-bit record number (DE), stores it back into
;              SEQ_RECNO, and marks the buffer full by writing $80 into both BUF_CNT
;              and BUF_REM. Recovers BC = FCB base and copies the record number into
;              the CP/M random-record fields R0 (low), R1 (high), R2=0 so a random
;              BDOS call addresses that record. Then on FIELD_WRITE_FLAG (FIELD_WRITE_FLAG): if
;              clear (GET / read-modify) it refills the record via FILE_READ_RECORD_FCB;
;              if set (PUT) it falls to PUTC_FILE_4 to flush via FILE_FLUSH_RECORD and
;              reset the print state.
;   [RE] This is the bridge that lets random GET/PUT reuse the sequential buffer
;   engine: it positions by record number through R0/R1/R2.
; ----------------------------------------------------------------------
PUTC_FILE_3:
        DEC DE
        DEC HL
        LD (HL),E
        INC HL
        LD (HL),D
        INC HL
        ; mark the buffer full: BUF_CNT = BUF_REM = $80 before positioning the record
        LD (HL),$80
        INC HL
        LD (HL),$80
        POP HL
        EX (SP),HL
        LD B,H
        LD C,L
        PUSH HL
        ; copy the BASIC record number into the CP/M random-record fields R0/R1, R2=0
        LD HL,FCB.CPM.R0
        ADD HL,BC
        LD (HL),E
        INC HL
        LD (HL),D
        INC HL
        LD (HL),$00
        POP HL
        ; FIELD write-flag: 0 = GET/read-modify (refill record), nonzero = PUT (flush record)
        LD A,(FIELD_WRITE_FLAG)
        OR A
        JR NZ,PUTC_FILE_4
        ; GET / read-before-write: load the existing record into the buffer
        CALL FILE_READ_RECORD_FCB
        POP HL
        RET
PUTC_FILE_4:
        CALL FILE_FLUSH_RECORD
        POP HL
        JP PRINT_RESET_STATE
; ----------------------------------------------------------------------
; COPY_128_BLOCK -- copy one 128-byte CP/M record (LDIR), preserving BC
;   In:        HL = source, DE = destination
;   Out:       128 bytes copied HL->DE; HL/DE advanced past the block
;   Clobbers:  HL, DE, flags (BC saved and restored)
;   Algorithm: Saves BC, sets BC = $80, LDIRs 128 bytes, restores BC, returns.
; ----------------------------------------------------------------------
COPY_128_BLOCK:
        PUSH BC
        LD BC,$0080
        LDIR
        POP BC
        RET
; ----------------------------------------------------------------------
; GETC_FILE -- read the next byte from the open input file, refilling the buffer at end of record
;   In:        PTRFIL ($0840) = current file's FCB base
;   Out:       A = next byte, NC; at EOF A = Ctrl-Z ($1A) with carry set
;   Clobbers:  A, flags (BC/HL saved and restored)
;   Algorithm: For a random file (MODE=3) it diverts to the FIELD-read path
;              (GETC_FILE_RANDOM). Otherwise it checks FCB.BUF_REM (remaining-byte
;              count): if bytes remain it returns the next one from SEQ_BUF (index =
;              BUF_CNT - decremented BUF_REM) and decrements the count; if the record
;              is exhausted (BUF_REM=0) it falls into GETC_FILE_2 to refill or signal
;              EOF.
; ----------------------------------------------------------------------
GETC_FILE:
        PUSH BC
        PUSH HL
; ----------------------------------------------------------------------
; GETC_FILE_1 -- re-entry point after a successful refill (re-read mode and remaining count)
;   In:        PTRFIL = FCB base
;   Out:       same as GETC_FILE (A = next byte / EOF)
;   Clobbers:  A, BC, HL, flags
;   Algorithm: Identical to the GETC_FILE body but without re-pushing BC/HL; reached
;              after FILE_READ_RECORD loads a fresh record so the next byte can be
;              returned.
; ----------------------------------------------------------------------
GETC_FILE_1:
        LD HL,(PTRFIL)
        LD A,(HL)
        CP $03
        ; MODE=3 (random): read from the FIELD buffer instead
        JP Z,GETC_FILE_RANDOM
        ; FCB.BUF_REM = bytes still available in the current record
        LD BC,FCB.BUF_REM
        ADD HL,BC
        LD A,(HL)
        OR A
        ; no bytes left in this record -> refill or hit EOF
        JR Z,GETC_FILE_2
        DEC HL
        LD A,(HL)
        INC HL
        DEC (HL)
        SUB (HL)
        LD C,A
        ADD HL,BC
        LD A,(HL)
        OR A
        POP HL
        POP BC
        RET
; ----------------------------------------------------------------------
; GETC_FILE_2 -- record exhausted: refill from disk or report EOF
;   In:        HL = FCB+$28 (BUF_REM); PTRFIL = FCB base
;   Out:       on more data: loops back to GETC_FILE_1; on EOF: falls into GETC_FILE_3
;   Clobbers:  A, BC, DE, HL, flags
;   Algorithm: Reads the EOF status byte FCB.BUF_CNT (the 0/$80 marker set by the
;              last read): if it is $00 (EOF latched) it signals end-of-file; otherwise
;              it calls FILE_READ_RECORD to fetch the next record and, if that returned
;              data (NZ), loops back to deliver the first byte.
; ----------------------------------------------------------------------
GETC_FILE_2:
        DEC HL
        LD A,(HL)
        OR A
        JR Z,GETC_FILE_3
        ; fetch the next 128-byte record from disk into the buffer
        CALL FILE_READ_RECORD
        JR NZ,GETC_FILE_1
; ----------------------------------------------------------------------
; GETC_FILE_3 -- end-of-file return: carry set, A = Ctrl-Z
;   In:        (none)
;   Out:       CY=1, A = $1A (Ctrl-Z); BC/HL restored
;   Clobbers:  A, flags
;   Algorithm: Sets carry as the EOF flag, restores HL/BC, loads A = Ctrl-Z, returns.
; ----------------------------------------------------------------------
GETC_FILE_3:
        SCF
        POP HL
        POP BC
        ; return Ctrl-Z as the EOF sentinel byte
        LD A,$1A
        RET
; ----------------------------------------------------------------------
; FILE_READ_RECORD -- read the next record of the CURRENT file (loads PTRFIL first)
;   In:        PTRFIL ($0840) = current file's FCB base
;   Out:       next record loaded into SEQ_BUF; status bytes set (see FILE_READ_RECORD_FCB)
;   Clobbers:  A, BC, DE, HL, flags (DE saved/restored inside the FCB entry)
;   Algorithm: Loads HL = current FCB base from PTRFIL and falls into
;              FILE_READ_RECORD_FCB to do the actual BDOS read.
; ----------------------------------------------------------------------
FILE_READ_RECORD:
        LD HL,(PTRFIL)
; ----------------------------------------------------------------------
; FILE_READ_RECORD_FCB -- read one record into SEQ_BUF and set the data/EOF status
;   In:        HL = FCB base
;   Out:       record read into SEQ_BUF ($29); FCB.BUF_CNT and FCB.BUF_REM both set to
;              $80 if data was read, $00 at EOF; A = that status; OR A sets Z on EOF
;   Clobbers:  A, BC, DE, HL, flags
;   Algorithm: Sets DE = FCB+1 (&FCB.CPM) for the DMA/BDOS calls, increments the
;              16-bit SEQ_RECNO, advances HL to BUF_REM ($28), zeroes it and LDIR-clears
;              the following 127 bytes (BUF_REM + SEQ_BUF[0..126]) so a short record
;              reads as zeros, points the DMA at SEQ_BUF, and issues the BDOS record
;              read using the cold-start-selected function code BDOS_FN_RECREAD
;              (random-read $21 on 2.x / sequential-read $14 on 1.x). A nonzero BDOS
;              return (no data / EOF) yields status $00; a zero return (data) yields
;              $80; the status is stored into BUF_CNT and BUF_REM and Z is set on EOF.
; ----------------------------------------------------------------------
FILE_READ_RECORD_FCB:
        PUSH DE
        LD D,H
        LD E,L
        INC DE
        LD BC,FCB.SEQ_RECNO
        ADD HL,BC
        LD C,(HL)
        INC HL
        LD B,(HL)
        ; advance the 16-bit sequential record number before the read
        INC BC
        DEC HL
        LD (HL),C
        INC HL
        LD (HL),B
        INC HL
        INC HL
        PUSH HL
        ; pre-clear BUF_REM + SEQ_BUF[0..126] to 0 so a short/partial record reads as zeros
        LD BC,$007F
        LD (HL),$00
        PUSH DE
        LD D,H
        LD E,L
        INC DE
        LDIR
        POP DE
        ; aim the CP/M DMA at SEQ_BUF for the read
        CALL BDOS_SET_DMA_FCB
        ; load the read function code chosen at startup (random-read on 2.x, seq-read on 1.x)
        LD A,(BDOS_FN_RECREAD)
        CALL BDOS_FILE_CALL
        OR A
        LD A,$00
        JR NZ,FILE_READ_RECORD_FCB_1
        ; data was read: mark the buffer status as 'data present' ($80)
        LD A,$80
; ----------------------------------------------------------------------
; FILE_READ_RECORD_FCB_1 -- store the buffer status into BUF_CNT/BUF_REM and set Z on EOF
;   In:        A = status ($00 EOF / $80 data); HL = FCB+$28 (BUF_REM)
;   Out:       status written into FCB.BUF_REM ($28) and FCB.BUF_CNT ($27); OR A sets Z when A=0 (EOF)
;   Clobbers:  A, HL, DE, flags
;   Algorithm: Writes A into BUF_REM ($28) then BUF_CNT ($27), does OR A so the
;              caller's branch tests EOF, restores DE, returns.
; ----------------------------------------------------------------------
FILE_READ_RECORD_FCB_1:
        POP HL
        LD (HL),A
        DEC HL
        LD (HL),A
        OR A
        POP DE
        RET
; ----------------------------------------------------------------------
; BDOS_SET_DMA_FCB -- point the CP/M DMA at this file's 128-byte record buffer (SEQ_BUF)
;   In:        DE = &FCB.CPM (FCB base + 1) -- as passed by every caller in this cluster
;   Out:       CP/M DMA address set to &FCB.SEQ_BUF (= DE + $28 = FCB base + $29)
;   Clobbers:  none (BC/DE/HL saved and restored)
;   Algorithm: Computes HL = DE + $28, moves it into DE, and calls BDOS F_DMAOFF
;              ($1A) Set-DMA so the next read/write transfers into this file's record
;              buffer.
;   [RE] The added offset is $28 (the FCB.BUF_REM field offset), but because callers
;   pass DE = FCB base + 1 (&FCB.CPM), the resulting DMA address is FCB base + $29 =
;   SEQ_BUF exactly. The 128-byte DMA window is SEQ_BUF[0..127]; it does NOT include
;   the BUF_CNT/BUF_REM status bytes that sit ahead of SEQ_BUF.
; ----------------------------------------------------------------------
BDOS_SET_DMA_FCB:
        PUSH BC
        PUSH DE
        PUSH HL
        LD HL,FCB.BUF_REM
        ADD HL,DE
        EX DE,HL
        ; BDOS Set-DMA: route the next disk transfer into this file's SEQ_BUF
        LD C,F_DMAOFF
        CALL BDOS
        POP HL
        POP DE
        POP BC
        RET
; ----------------------------------------------------------------------
; GETC_FILE_EOF -- GETC_FILE wrapper that treats Ctrl-Z as a hard EOF and latches it in the FCB
;   In:        PTRFIL = current file's FCB base
;   Out:       A = byte, NC on data; on EOF (real or Ctrl-Z) CY=1 and FCB.BUF_CNT/
;              BUF_REM are zeroed so subsequent reads stay at EOF
;   Clobbers:  A, flags (BC/HL saved and restored)
;   Algorithm: Calls GETC_FILE; if it already returned carry (EOF) returns as-is. The
;              SCF/CCF pair clears carry so a non-Ctrl-Z byte returns with CY=0. If the
;              byte is Ctrl-Z ($1A) it zeroes BUF_CNT and BUF_REM (sticky EOF) and sets
;              carry.
; ----------------------------------------------------------------------
GETC_FILE_EOF:
        CALL GETC_FILE
        RET C
        ; Ctrl-Z = CP/M text EOF marker: treat it as hard end-of-file
        CP $1A
        SCF
        CCF
        RET NZ
        PUSH BC
        PUSH HL
        LD HL,(PTRFIL)
        LD BC,FCB.BUF_CNT
        ADD HL,BC
        ; latch EOF: zero BUF_CNT then BUF_REM so further reads keep returning EOF
        LD (HL),$00
        INC HL
        LD (HL),$00
        SCF
        POP HL
        POP BC
        RET
; ----------------------------------------------------------------------
; PARSE_FILENAME_TO_FCB -- evaluate a string filename and parse "d:NAME.EXT" into the scratch CP/M FCB.
;   In:        HL = BASIC text pointer at the filename expression.
;   Out:       SCRATCH_FCB ($08AA) = a freshly built CP/M FCB: DR byte = drive (0=default, 1.. = A:..),
;              8-byte name + 3-byte type space-padded; SCRATCH_FCB_EX ($08B6, the EX byte) zeroed. HL = text
;              pointer past the consumed expression. Returned CY = an extension separator ('.') was seen.
;   Clobbers:  A, BC, DE, HL; writes SCRATCH_FCB.. through the EX byte.
;   Algorithm: FRMEVL the expression, FRETMP-free the result string, reject an empty string (Bad file name).
;              Point HL at the string body via its descriptor; if a 2nd char is ':' treat the 1st as a drive
;              letter -> DR = (letter-$40); range-check 0..26 (0=default). Then copy up to 8 name chars; on
;              '.' pad the name field with spaces and switch to the 3-char type; finally FCB_PAD_FIELD pads
;              any short field. Raises Bad file name on empty/over-length fields.
; ----------------------------------------------------------------------
PARSE_FILENAME_TO_FCB:
        ; evaluate the filename string expression
        CALL FRMEVL_NOPAREN
        PUSH HL
        CALL FRETMP
        LD A,(HL)
        OR A
        ; empty filename string -> Bad file name
        JP Z,RAISE_BAD_FILE_NAME
        PUSH AF
        INC HL
        LD E,(HL)
        INC HL
        LD H,(HL)
        LD L,E
        LD E,A
        CP $02
        JR C,PARSE_FILENAME_TO_FCB_1
        LD C,(HL)
        INC HL
        LD A,(HL)
        DEC E
        ; second char is ':' ? then the first char is a drive letter (d:)
        CP $3A
        JR Z,PARSE_FILENAME_TO_FCB_2
        DEC HL
        INC E
; ----------------------------------------------------------------------
; PARSE_FILENAME_TO_FCB_1 -- no-drive-prefix entry: default the drive and rewind to the name start.
;   In:        HL points one past the (rejected) drive area; E = remaining char count.
;   Out:       C = '@' ($40) so the drive byte computes to 0 (default drive); HL/E rewound to the name.
;   Clobbers:  C, E, HL.
;   Algorithm: Back HL/E up and seed C with '@' so the shared (C-$40) drive computation yields the
;              default-drive code 0; falls into the common validation at PARSE_FILENAME_TO_FCB_2.
; ----------------------------------------------------------------------
PARSE_FILENAME_TO_FCB_1:
        DEC HL
        INC E
        ; no drive prefix: seed C='@' ($40) so (C-$40)=0 selects the default drive
        LD C,$40
; ----------------------------------------------------------------------
; PARSE_FILENAME_TO_FCB_2 -- validate drive code and store FCB.CPM.DR, then begin the name copy.
;   In:        C = drive char ('@'+n), E = remaining filename length, HL -> first name char.
;   Out:       SCRATCH_FCB.DR set; BC -> SCRATCH_FCB_NAME; D = $0B field width counter (8 name + 3 type).
;   Clobbers:  A, BC, D.
;   Algorithm: Reject an empty remaining name (Bad file name); compute drive = C-$40, range-check it
;              (carry, i.e. C<'@', or >=27 -> Bad file name; 0=default); store it as the FCB drive byte; set
;              D=$0B and fall into the per-character copy loop.
; ----------------------------------------------------------------------
PARSE_FILENAME_TO_FCB_2:
        DEC E
        JP Z,RAISE_BAD_FILE_NAME
        LD A,C
        ; convert drive letter to CP/M drive number (A:->1 ..); range-check 0..26, 0 = default
        SUB $40
        JP C,RAISE_BAD_FILE_NAME
        CP $1B
        JP NC,RAISE_BAD_FILE_NAME
        ; store the drive byte as FCB.CPM.DR, then advance BC to the 11-byte name+type area
        LD BC,SCRATCH_FCB
        LD (BC),A
        INC BC
        LD D,$0B
; ----------------------------------------------------------------------
; PARSE_FILENAME_TO_FCB_3 -- advance past the '.' separator and continue copying into the type field.
;   In:        HL -> the '.' just matched; BC -> the type field; D = remaining field width; AF saved on stack.
;   Out:       HL advanced past '.'; loop continues into the 3-char type field.
;   Clobbers:  HL.
;   Algorithm: Skip the dot and re-enter the copy loop (the SCF/PUSH AF in the caller records that the
;              extension separator was seen, surfacing as the returned CY).
; ----------------------------------------------------------------------
PARSE_FILENAME_TO_FCB_3:
        INC HL
; ----------------------------------------------------------------------
; PARSE_FILENAME_TO_FCB_4 -- per-character copy loop body: emit one name/type byte to the FCB.
;   In:        HL -> source char, E = input chars left (signed), BC -> FCB dest, D = field bytes left.
;   Out:       on input exhausted (E goes negative) jumps to FCB_PAD_FIELD_1 to space-fill the rest;
;              on '.' calls FCB_PAD_FIELD then PARSE_FILENAME_TO_FCB_3 to switch to the type field.
;   Clobbers:  A, BC, D, E, HL.
;   Algorithm: Decrement the input counter; if no more input, pad the field; if the char is '.', finish the
;              current field (pad to width) and move to the type field; otherwise store the char and loop
;              until the 11-byte name+type area (D) is full. (Characters are stored verbatim; no upper-case
;              fold here -- only the OPEN mode letter is upper-cased.)
; ----------------------------------------------------------------------
PARSE_FILENAME_TO_FCB_4:
        DEC E
        ; input exhausted -> space-pad the remaining FCB field bytes
        JP M,FCB_PAD_FIELD_1
        LD A,(HL)
        ; '.' starts the extension: pad the name field then switch to the type field
        CP $2E
        JR NZ,PARSE_FILENAME_TO_FCB_5
        CALL FCB_PAD_FIELD
        POP AF
        SCF
        PUSH AF
        JR PARSE_FILENAME_TO_FCB_3
; ----------------------------------------------------------------------
; PARSE_FILENAME_TO_FCB_5 -- store one ordinary filename character into the FCB and advance.
;   In:        A = char to store, BC -> FCB dest, HL -> source, D = field bytes left.
;   Out:       char written; BC,HL advanced; D decremented; loops back to PARSE_FILENAME_TO_FCB_4 until full.
;   Clobbers:  BC, D, HL.
;   Algorithm: Write the byte to the FCB, bump both pointers, and decrement the field-width counter D;
;              when D reaches 0 (all 11 bytes placed) fall into PARSE_FILENAME_TO_FCB_6 to finish.
; ----------------------------------------------------------------------
PARSE_FILENAME_TO_FCB_5:
        LD (BC),A
        INC BC
        INC HL
        DEC D
        JR NZ,PARSE_FILENAME_TO_FCB_4
; ----------------------------------------------------------------------
; PARSE_FILENAME_TO_FCB_6 -- finish parsing: clear the FCB extent byte and restore the caller's state.
;   In:        SCRATCH_FCB name/type fully built; AF (carry=ext-seen) and HL saved on stack.
;   Out:       SCRATCH_FCB_EX ($08B6, EX byte) = 0; HL restored to the post-filename text pointer; CY from
;              the popped AF = extension-separator-seen; RET.
;   Clobbers:  A.
;   Algorithm: Zero the current-extent byte (so a fresh OPEN starts at extent 0), pop the saved AF (whose
;              carry flag tells the caller whether a '.' extension was present) and the saved text pointer,
;              and return.
; ----------------------------------------------------------------------
PARSE_FILENAME_TO_FCB_6:
        XOR A
        ; clear the FCB current-extent (EX) byte for a fresh open
        LD (SCRATCH_FCB_EX),A
        POP AF
        POP HL
        RET
; ----------------------------------------------------------------------
; FCB_PAD_FIELD -- space-pad the rest of the current FCB field when a separator/end is hit early.
;   In:        D = bytes remaining in the 11-byte name+type window; BC -> next FCB dest byte.
;   Out:       writes ' ' ($20) until D hits the field boundary; returns when the field is full.
;   Clobbers:  A, BC, D.
;   Algorithm: Validate position (D==$0B means a leading '.' with empty name, or D<3 means an over-long
;              name -> Bad file name); if exactly at the type boundary (D==3) return; otherwise pad with
;              spaces toward the next field boundary. Used to right-pad the name to 8 chars before the type.
; ----------------------------------------------------------------------
FCB_PAD_FIELD:
        LD A,D
        CP $0B
        ; field counter still full ($0B) -> a leading '.' / empty name -> Bad file name
        JP Z,RAISE_BAD_FILE_NAME
        CP $03
        ; fewer than 3 bytes left means the name over-ran the 8-char field -> Bad file name
        JP C,RAISE_BAD_FILE_NAME
        RET Z
        LD A,$20
        LD (BC),A
        INC BC
        DEC D
        JR FCB_PAD_FIELD
; ----------------------------------------------------------------------
; FCB_PAD_FIELD_1 -- end-of-input entry: if any field bytes remain, space-fill them, else finish.
;   In:        D = FCB field bytes left (0 means exactly filled).
;   Out:       branches to PARSE_FILENAME_TO_FCB_6 when nothing remains; else falls into the pad loop.
;   Clobbers:  sets Z via INC D / DEC D (D otherwise unchanged).
;   Algorithm: Test D for zero without disturbing it; if the name+type area is already full go finish,
;              otherwise fall into FCB_PAD_FIELD_2 to space-fill the remainder.
; ----------------------------------------------------------------------
FCB_PAD_FIELD_1:
        INC D
        DEC D
        JR Z,PARSE_FILENAME_TO_FCB_6
; ----------------------------------------------------------------------
; FCB_PAD_FIELD_2 -- fill the remaining D FCB name/type bytes with spaces.
;   In:        D = bytes to fill, BC -> next FCB dest byte.
;   Out:       D bytes set to ' ' ($20); jumps to PARSE_FILENAME_TO_FCB_6 to finish.
;   Clobbers:  A, BC, D.
;   Algorithm: Store ' ' and advance until D is exhausted, then complete the parse (zero EX, restore HL).
; ----------------------------------------------------------------------
FCB_PAD_FIELD_2:
        LD A,$20
        LD (BC),A
        INC BC
        DEC D
        JR NZ,FCB_PAD_FIELD_2
        JR PARSE_FILENAME_TO_FCB_6
; ----------------------------------------------------------------------
; STMT_NAME -- NAME statement: rename a disk file (NAME "old" AS "new").
;   In:        HL = BASIC text pointer after the NAME token.
;   Out:       file renamed on disk; HL = text pointer past the statement. Raises File not found,
;              File already exists, or 'FC' on a drive mismatch.
;   Clobbers:  A, BC, DE, HL; uses SCRATCH_FCB ($08AA) and the rename block at $089A.
;   Algorithm: Parse the old filename into SCRATCH_FCB; set the BDOS DMA back to the default $0080 buffer;
;              OPEN the old file (FF -> File not found). Copy its 12-byte FCB (drive+name+type) into the
;              low half of the rename block at $089A. Then SYNCHR the 'AS' keyword and parse the new name
;              into SCRATCH_FCB. Require the same drive byte (else FC), and verify the new name does NOT
;              already exist via F_OPEN (success -> File already exists). Finally BDOS F_RENAME with DE
;              pointing at the rename block (old FCB at +0, new drive+name at +16).
; ----------------------------------------------------------------------
STMT_NAME:
        CALL PARSE_FILENAME_TO_FCB
        PUSH HL
        ; restore the BDOS DMA to the standard $0080 buffer before the directory ops
        LD DE,$0080
        LD C,F_DMAOFF
        CALL BDOS
        LD DE,SCRATCH_FCB
        ; open the old file to confirm it exists (and resolves its directory entry)
        LD C,F_OPEN
        CALL BDOS
        ; BDOS $FF (not found) + 1 = 0 -> File not found
        INC A
        JP Z,RAISE_FILE_NOT_FOUND
        ; copy the resolved old FCB (12 bytes: drive+8 name+3 type) into the low half of the F_RENAME block
        LD HL,RENAME_FCB
        LD DE,SCRATCH_FCB
        LD B,$0C
; ----------------------------------------------------------------------
; STMT_NAME_1 -- copy loop: move the 12-byte resolved old FCB into the rename block.
;   In:        DE -> SCRATCH_FCB, HL -> RENAME_FCB, B = 12.
;   Out:       12 bytes (DR+name+type) copied; HL/DE advanced past them.
;   Clobbers:  A, B, DE, HL.
;   Algorithm: Byte copy of the just-opened old FCB into the rename block's first half so F_RENAME can
;              pair it with the new drive+name written into the second half.
; ----------------------------------------------------------------------
STMT_NAME_1:
        LD A,(DE)
        LD (HL),A
        INC HL
        INC DE
        DJNZ STMT_NAME_1
        POP HL
        ; require the literal 'AS' between the two filenames
        CALL SYNCHR
        DEFB    'A'                      ; inline char arg consumed by the preceding CALL
        CALL SYNCHR
        DEFB    'S'                      ; inline char arg consumed by the preceding CALL
        CALL PARSE_FILENAME_TO_FCB
        PUSH HL
        LD A,(SCRATCH_FCB)
        LD HL,RENAME_FCB
        ; old and new must name the same drive (compare scratch DR vs saved DR) else FC
        CP (HL)
        JP NZ,ERROR_FC
        LD DE,SCRATCH_FCB
        LD C,F_OPEN
        CALL BDOS
        INC A
        ; new name already opens -> target exists -> File already exists
        JP NZ,RAISE_FILE_ALREADY_EXISTS
        ; BDOS rename: DE -> 32-byte block holding old FCB (+0) and new drive+name (+16)
        LD C,F_RENAME
        LD DE,RENAME_FCB
        CALL BDOS
        POP HL
        RET
; ----------------------------------------------------------------------
; STMT_OPEN -- OPEN statement: OPEN mode$, [#] filenum, name$  -- open a disk file on a channel.
;   In:        HL = BASIC text pointer after the OPEN token.
;   Out:       the file's per-file FCB entry initialised (MODE set, CP/M FCB built, buffers cleared) and
;              registered in FILTAB; for sequential input it pre-reads the first record. HL = text past the
;              statement. Raises Bad file mode / Bad file number / File already open / File not found /
;              Too many files.
;   Clobbers:  A, BC, DE, HL; SCRATCH_FCB; the chosen FCB entry; PTRFIL; OPEN_RESUME_TEXT_PTR.
;   Algorithm: Push PRINT_RESET_STATE as a return so PRINT state is reset on exit. FRMEVL the mode string;
;              its first letter (upper-cased via AND $DF) selects FCB_MODE_SEQ_OUT('O'), FCB_MODE_SEQ_IN('I')
;              or FCB_MODE_RANDOM('R') (else Bad file mode). SYNCHR ',', optional '#', GETBYT the file number
;              (0 -> Bad file number), SYNCHR ','. Verify the slot is free (FILE_NUM_TO_FCB_A returns the
;              slot mode in A; nonzero -> File already open). Parse the filename into SCRATCH_FCB. Copy
;              SCRATCH_FCB into the entry's CP/M-FCB slot, zero EX and CR, set DMA, then: for output
;              DELETE+MAKE (handle extents/Too many files), for input/random OPEN (auto-MAKE on $03
;              not-found from the RAM trampoline). Stamp MODE, and for sequential-input pre-read the first
;              record; for random zero-fill the buffer. (NOTE: FILE_NUM_TO_FCB_A, not FILE_NUM_TO_FCB_2,
;              resolves the entry pointer BC.)
; ----------------------------------------------------------------------
STMT_OPEN:
        ; arrange to reset PRINT state when OPEN returns (pushed as the return address)
        LD BC,PRINT_RESET_STATE
        PUSH BC
        CALL FRMEVL_NOPAREN
        PUSH HL
        CALL FRETMP
        LD A,(HL)
        OR A
        JP Z,RAISE_BAD_FILE_MODE
        INC HL
        LD C,(HL)
        INC HL
        LD B,(HL)
        LD A,(BC)
        ; upper-case the mode letter so 'o'/'i'/'r' match 'O'/'I'/'R'
        AND $DF
        LD D,FCB_MODE_SEQ_OUT
        CP $4F
        JR Z,STMT_OPEN_1
        LD D,FCB_MODE_SEQ_IN
        CP $49
        JR Z,STMT_OPEN_1
        LD D,FCB_MODE_RANDOM
        CP $52
        JP NZ,RAISE_BAD_FILE_MODE
; ----------------------------------------------------------------------
; STMT_OPEN_1 -- OPEN mode resolved: parse the file-number argument.
;   In:        D = selected FCB mode; HL -> text pointer at the comma after the mode.
;   Out:       A/E = file number (1..); D still = mode; raises Bad file number on 0.
;   Clobbers:  A, E, HL.
;   Algorithm: SYNCHR the ',', skip an optional '#', GETBYT the channel number, SYNCHR the next ','; a
;              zero channel raises Bad file number. Mode is carried on the stack across the parse.
; ----------------------------------------------------------------------
STMT_OPEN_1:
        POP HL
        CALL SYNCHR
        DEFB    ','                      ; inline char arg consumed by the preceding CALL
        PUSH DE
        ; optional '#' before the file number -- skip it if present
        CP $23
        CALL Z,CHRGET
        CALL GETBYT
        CALL SYNCHR
        DEFB    ','                      ; inline char arg consumed by the preceding CALL
        LD A,E
        OR A
        JP Z,RAISE_BAD_FILE_NUMBER
        POP DE
; ----------------------------------------------------------------------
; STMT_OPEN_2 -- check the channel is free, parse the filename, and (random) read the FIELD argument.
;   In:        A = file number, D = mode.
;   Out:       BC = base of the resolved per-file FCB entry; OPEN_RESUME_TEXT_PTR = the post-args BASIC
;              text pointer; AF restored from the parse (CY = extension-was-typed).
;   Clobbers:  A, BC, DE, HL.
;   Algorithm: FILE_NUM_TO_FCB_A resolves the entry (BC) and returns its mode -> if already open, File
;              already open. Parse the filename into SCRATCH_FCB. Then FILE_NUM_TO_FCB_2 (A = mode) parses
;              the optional FIELD record/buffer argument for a RANDOM file and returns HL = the continuation
;              text pointer, saved to OPEN_RESUME_TEXT_PTR. [RE] If no extension was typed (NC) and E==0 and
;              the type field is blank, default the filetype to 'BAS'.
; ----------------------------------------------------------------------
STMT_OPEN_2:
        LD E,A
        PUSH DE
        ; resolve the slot's FCB entry (BC) and return its mode in A; nonzero means it is already open
        CALL FILE_NUM_TO_FCB_A
        ; slot already has an open file -> File already open
        JP NZ,RAISE_FILE_ALREADY_OPEN
        POP DE
        PUSH BC
        PUSH DE
        ; parse the name$ into the scratch CP/M FCB
        CALL PARSE_FILENAME_TO_FCB
        POP DE
        POP BC
        PUSH BC
        PUSH AF
        LD A,D
        CALL FILE_NUM_TO_FCB_2
        POP AF
        LD (OPEN_RESUME_TEXT_PTR),HL
        JR C,STMT_OPEN_3
        LD A,E
        OR A
        JP NZ,STMT_OPEN_3
        ; no extension typed: default the filetype to 'BAS'
        LD HL,SCRATCH_FCB_TYPE
        LD A,(HL)
        CP $20
        JR NZ,STMT_OPEN_3
        LD (HL),$42
        INC HL
        LD (HL),$41
        INC HL
        LD (HL),$53
; ----------------------------------------------------------------------
; STMT_OPEN_3 -- copy the scratch FCB into the channel's entry and clear its open-state bytes.
;   In:        D = mode; entry pointer on the stack (-> HL); SCRATCH_FCB holds the parsed name.
;   Out:       PTRFIL = entry base; entry's CP/M FCB filled from SCRATCH_FCB with EX ($0C) and CR ($20)
;              zeroed; DE -> the entry's CP/M FCB (entry+1) for the upcoming BDOS calls; mode saved on stack.
;   Clobbers:  A, C, DE, HL.
;   Algorithm: Set PTRFIL to this entry; copy the 12-byte drive+name+type from SCRATCH_FCB into entry+1
;              (=FCB.CPM), then store 0 at the EX byte ($0C) and, $14 further on, at the CR byte ($20, the
;              current-record cursor) so the file opens at extent 0 / record 0. DE is left at the CP/M FCB
;              for OPEN/MAKE/DELETE.
; ----------------------------------------------------------------------
STMT_OPEN_3:
        POP HL
        LD A,D
        PUSH AF
        ; make this entry the current file (PTRFIL) for the rest of OPEN
        LD (PTRFIL),HL
        PUSH HL
        INC HL
        LD DE,SCRATCH_FCB
        LD C,$0C
; ----------------------------------------------------------------------
; STMT_OPEN_4 -- copy loop: move the 12-byte parsed FCB (drive+name+type) into the channel entry.
;   In:        DE -> SCRATCH_FCB, HL -> entry's CP/M FCB, C = 12.
;   Out:       12 bytes copied; HL left just past the type; then the EX byte ($0C) and the CR byte ($20)
;              are zeroed.
;   Clobbers:  A, C, DE, HL.
;   Algorithm: Byte-copy drive+name+type, then clear the EX byte ($0C) and (after a +$14 step) the CR byte
;              ($20) so the file opens at extent 0 / record 0.
; ----------------------------------------------------------------------
STMT_OPEN_4:
        LD A,(DE)
        LD (HL),A
        INC DE
        INC HL
        DEC C
        JR NZ,STMT_OPEN_4
        LD (HL),$00
        LD DE,$0014
        ADD HL,DE
        LD (HL),$00
        POP DE
        PUSH DE
        INC DE
        CALL BDOS_SET_DMA_FCB
        POP HL
        POP AF
        PUSH AF
        PUSH HL
        CP FCB_MODE_SEQ_OUT
        JR NZ,STMT_OPEN_6
        PUSH DE
        LD C,F_DELETE
        CALL BDOS
        POP DE
; ----------------------------------------------------------------------
; STMT_OPEN_5 -- create the output file (BDOS F_MAKE), failing with Too many files if the directory is full.
;   In:        DE -> the channel's CP/M FCB.
;   Out:       file created; on BDOS $FF (no directory room) raises Too many files; else continues at
;              STMT_OPEN_7.
;   Clobbers:  A, C.
;   Algorithm: BDOS F_MAKE; ($FF+1)==0 means the directory is full -> Too many files.
; ----------------------------------------------------------------------
STMT_OPEN_5:
        LD C,F_MAKE
        CALL BDOS
        ; BDOS $FF (directory full) + 1 = 0 -> Too many files
        INC A
        JP Z,RAISE_TOO_MANY_FILES
        JR STMT_OPEN_7
; ----------------------------------------------------------------------
; STMT_OPEN_6 -- open an existing file for input/random; auto-create on a missing extent.
;   In:        DE -> the channel's CP/M FCB.
;   Out:       file open; on not-found, may advance the extent and retry MAKE, or raise File not found.
;   Clobbers:  A, C, DE.
;   Algorithm: BDOS F_OPEN; success -> STMT_OPEN_7. On failure call the RAM dispatch trampoline (extended
;              error class); class $03 means the requested extent doesn't exist -> bump the extent byte and
;              go MAKE it (STMT_OPEN_5); any other class -> File not found.
; ----------------------------------------------------------------------
STMT_OPEN_6:
        LD C,F_OPEN
        CALL BDOS
        INC A
        JR NZ,STMT_OPEN_7
        ; consult the extended-error path; A=$03 means the extent is missing (create it) rather than a hard not-found
        CALL RAM_DISPATCH_TRAMPOLINE
        CP $03
        JP NZ,RAISE_FILE_NOT_FOUND
        INC DE
        JR STMT_OPEN_5
; ----------------------------------------------------------------------
; STMT_OPEN_7 -- finalise the open: stamp the file mode and clear the sequential record/position cells.
;   In:        entry pointer and mode saved on the stack.
;   Out:       entry MODE byte set; FCB.SEQ_RECNO and the following 3 bytes zeroed; A = mode.
;   Clobbers:  A, DE, HL.
;   Algorithm: Write the mode to the entry's MODE byte, then zero the 4-byte sequential bookkeeping block
;              at FCB.SEQ_RECNO (record number word + buffer count/status). Dispatch on mode: random ->
;              STMT_OPEN_8 (clear the record buffer); sequential-input -> pre-read first record then return
;              the resume text pointer; sequential-output -> just reset run state.
; ----------------------------------------------------------------------
STMT_OPEN_7:
        POP DE
        POP AF
        ; stamp the channel's MODE byte (1/2/3) marking it open
        LD (DE),A
        PUSH DE
        LD HL,FCB.SEQ_RECNO
        ADD HL,DE
        XOR A
        LD (HL),A
        INC HL
        LD (HL),A
        INC HL
        LD (HL),A
        INC HL
        LD (HL),A
        POP HL
        LD A,(HL)
        CP FCB_MODE_RANDOM
        JP Z,STMT_OPEN_8
        CP FCB_MODE_SEQ_IN
        JP NZ,RESET_RUN_STATE_1
        ; sequential input: pre-read the first 128-byte record into the buffer
        CALL FILE_READ_RECORD
        LD HL,(OPEN_RESUME_TEXT_PTR)
        RET
; ----------------------------------------------------------------------
; STMT_OPEN_8 -- random-mode open tail: zero the 128-byte record buffer (SEQ_BUF), then finish.
;   In:        HL -> the channel entry (MODE byte).
;   Out:       the 128-byte FCB.SEQ_BUF region cleared to 0 (stores B, which = 0 here); then resets run
;              state and returns the resume text pointer.
;   Clobbers:  A, BC, HL.
;   Algorithm: Point at FCB.SEQ_BUF (entry+$29) and store B (=0, the high byte of the LD BC,$0029 just
;              executed) across 128 bytes to clear the record buffer, then JP RESET_RUN_STATE_1 which
;              returns OPEN_RESUME_TEXT_PTR in HL.
; ----------------------------------------------------------------------
STMT_OPEN_8:
        ; point at the 128-byte record buffer (offset $29) to clear for the freshly opened random file
        LD BC,FCB.SEQ_BUF
        ADD HL,BC
        LD C,$80
; ----------------------------------------------------------------------
; STMT_OPEN_9 -- buffer-clear loop for the random open: zero 128 buffer bytes.
;   In:        HL -> buffer, C = 128, B = 0.
;   Out:       128 bytes set to 0; jumps to RESET_RUN_STATE_1.
;   Clobbers:  C, HL.
;   Algorithm: Store B (0) and advance until C exhausts the 128-byte record.
; ----------------------------------------------------------------------
STMT_OPEN_9:
        LD (HL),B
        INC HL
        DEC C
        JR NZ,STMT_OPEN_9
        JP RESET_RUN_STATE_1
; ----------------------------------------------------------------------
; STMT_SYSTEM -- SYSTEM statement: close all files and exit BASIC back to CP/M.
;   In:        Z flag from the statement-end check (RET NZ if extra text follows).
;   Out:       does not return to BASIC; closes files, restores the text screen, then warm-boots CP/M.
;   Clobbers:  all.
;   Algorithm: Refuse trailing garbage (RET NZ), CLOSE_ALL_FILES, switch the Apple to text mode
;              (STMT_TEXT), then fall into STMT_SYSTEM_WBOOT which jumps to the CP/M WBOOT vector.
; ----------------------------------------------------------------------
STMT_SYSTEM:
        RET NZ
        ; flush and close every open file before leaving BASIC
        CALL CLOSE_ALL_FILES
        CALL STMT_TEXT
; ----------------------------------------------------------------------
; STMT_SYSTEM_WBOOT -- self-modified jump to the CP/M warm-boot (WBOOT) vector; leaves BASIC.
;   In:        (none) -- the JP operand was patched at cold start.
;   Out:       transfers control to CP/M's WBOOT; never returns.
;   Clobbers:  n/a.
;   Algorithm: The image holds JP $0000 here; COLD_START reads the BIOS WBOOT vector from base-page
;              $0001..$0002 and writes it into this JP's operand, so running SYSTEM jumps to the live
;              warm-boot entry. (Self-modifying code; comment preserved.)
; ----------------------------------------------------------------------
STMT_SYSTEM_WBOOT:
        JP $0000
; ----------------------------------------------------------------------
; STMT_RESET -- RESET statement: close all files and re-log the disk system, preserving the current drive.
;   In:        Z flag from the statement-end check (RET NZ if extra text follows).
;   Out:       all files closed, BDOS disk system reset, the previously-current drive reselected; HL preserved.
;   Clobbers:  A, C, E (HL saved/restored).
;   Algorithm: CLOSE_ALL_FILES, read the current drive (BDOS DRV_GET), reset the whole disk system
;              (BDOS DRV_ALLRESET, which logs out all drives and re-reads directories), then reselect the
;              saved drive (BDOS DRV_SET) so the user's default is unchanged.
; ----------------------------------------------------------------------
STMT_RESET:
        RET NZ
        PUSH HL
        ; close every open file before resetting the disk system
        CALL CLOSE_ALL_FILES
        ; remember the current drive so it can be reselected after the reset
        LD C,DRV_GET
        CALL BDOS
        PUSH AF
        ; BDOS reset disk system: log out all drives and force directory re-read
        LD C,DRV_ALLRESET
        CALL BDOS
        POP AF
        LD E,A
        LD C,DRV_SET
        CALL BDOS
        POP HL
        RET
; ----------------------------------------------------------------------
; STMT_KILL -- KILL statement: delete a disk file by name.
;   In:        HL = BASIC text pointer after the KILL token.
;   Out:       the named file deleted from disk; HL past the statement. Raises File not found if absent.
;   Clobbers:  A, BC, DE, HL; uses SCRATCH_FCB.
;   Algorithm: Parse the filename into SCRATCH_FCB; restore BDOS DMA to $0080; OPEN the file to confirm
;              it exists (and so an open directory entry is closed first). If found, CLOSE it then
;              BDOS F_DELETE; if not found, raise File not found.
; ----------------------------------------------------------------------
STMT_KILL:
        CALL PARSE_FILENAME_TO_FCB
        PUSH HL
        LD DE,$0080
        LD C,F_DMAOFF
        CALL BDOS
        LD DE,SCRATCH_FCB
        PUSH DE
        ; open to confirm the file exists before deleting (FF -> not found)
        LD C,F_OPEN
        CALL BDOS
        INC A
        POP DE
        PUSH DE
        PUSH AF
; ----------------------------------------------------------------------
; STMT_KILL_1 -- KILL tail: close the just-opened file (if present), then delete it.
;   In:        Z flag = file-not-found indicator; DE -> SCRATCH_FCB; A (saved) = open+1 result.
;   Out:       file closed and deleted, or File not found raised.
;   Clobbers:  A, C, DE, HL.
;   Algorithm: If the OPEN succeeded (NZ), BDOS F_CLOSE the directory entry; if it failed (Z) raise File
;              not found; then BDOS F_DELETE to remove the file.
; ----------------------------------------------------------------------
STMT_KILL_1:
        ; close the entry the confirming OPEN left open (only if it was found)
        LD C,F_CLOSE
        CALL NZ,BDOS
        POP AF
        POP DE
        JP Z,RAISE_FILE_NOT_FOUND
        ; BDOS delete the file
        LD C,F_DELETE
        CALL BDOS
        POP HL
        RET
; ----------------------------------------------------------------------
; STMT_FILES -- FILES statement: list directory entries matching an optional filespec.
;   In:        Z flag = 'no argument' indicator; HL = text pointer (filespec expression if present).
;   Out:       prints matching 11-char filenames (NAME.EXT) in columns to the console; HL past statement.
;              Raises File not found if nothing matches.
;   Clobbers:  A, BC, DE, HL; SCRATCH_FCB.
;   Algorithm: With no argument, build an all-'?' wildcard FCB ('????????.???'); with an argument parse it
;              into SCRATCH_FCB. Turn any leading '*' in the name (8) or type (3) field into all-'?'
;              (FCB_WILD_IF_STAR). Set DMA to $0080, BDOS Search-First; loop Search-Next, printing each
;              directory entry's 11 name bytes via OUTCHR with a '.' inserted before a non-blank extension,
;              wrapping columns using the print width and current column.
; ----------------------------------------------------------------------
STMT_FILES:
        JR NZ,STMT_FILES_1
        PUSH HL
        LD HL,SCRATCH_FCB
        LD (HL),$00
        INC HL
        LD C,$0B
        ; no filespec: fill the 11-byte name+type with '?' to match every file
        CALL FCB_WILD_EXPAND
        POP HL
; ----------------------------------------------------------------------
; STMT_FILES_1 -- prepare the search FCB: expand leading '*' wildcards and issue Search-First.
;   In:        SCRATCH_FCB holds the parsed/wildcard filespec.
;   Out:       BDOS Search-First done; A = directory index (0..3) of the first match, or File not found.
;   Clobbers:  A, BC, DE, HL.
;   Algorithm: Zero the EX byte; if the name field starts with '*' fill 8 chars with '?'; if the type field
;              starts with '*' fill 3 chars with '?'. Set DMA to $0080 and BDOS F_SFIRST; $FF -> File not
;              found.
; ----------------------------------------------------------------------
STMT_FILES_1:
        ; a filespec was supplied: parse it into the scratch FCB
        CALL NZ,PARSE_FILENAME_TO_FCB
        XOR A
        LD (SCRATCH_FCB_EX),A
        PUSH HL
        LD HL,SCRATCH_FCB_NAME
        LD C,$08
        CALL FCB_WILD_IF_STAR
        LD HL,SCRATCH_FCB_TYPE
        LD C,$03
        CALL FCB_WILD_IF_STAR
        LD DE,$0080
        LD C,F_DMAOFF
        CALL BDOS
        LD DE,SCRATCH_FCB
        ; BDOS search-first: A returns the matched entry's index (0..3) within the $0080 buffer
        LD C,F_SFIRST
        CALL BDOS
        CP $FF
        JP Z,RAISE_FILE_NOT_FOUND
; ----------------------------------------------------------------------
; STMT_FILES_2 -- locate the matched directory entry in the DMA buffer and start printing its name.
;   In:        A = BDOS search return (low 2 bits select which of the 4 entries in the $0080 buffer).
;   Out:       HL -> the entry's 11-byte filename; C = 11 (byte counter) for the print loop.
;   Clobbers:  A, BC, HL.
;   Algorithm: Each directory record holds 4 entries of 32 bytes; A&3 picks one, *32 (five ADD A,A) gives
;              its offset, +$0081 skips the per-entry user-code byte to the 11-char name; set C=11 and print.
; ----------------------------------------------------------------------
STMT_FILES_2:
        ; BDOS returns the entry index; the buffer holds 4 directory entries of 32 bytes each
        AND $03
        ADD A,A
        ADD A,A
        ADD A,A
        ADD A,A
        ADD A,A
        LD C,A
        LD B,$00
        ; $0080+1 skips the entry's drive/user byte to its 11-char name+type
        LD HL,$0081
        ADD HL,BC
        LD C,$0B
; ----------------------------------------------------------------------
; STMT_FILES_3 -- print-name loop: emit each filename char, inserting '.' before a non-blank extension.
;   In:        HL -> next name byte, C = bytes left (counts 11..1).
;   Out:       characters written via OUTCHR; '.' printed between name and a non-blank type.
;   Clobbers:  A, HL.
;   Algorithm: Output the current char; when 8 name chars have been printed (C==4, i.e. 3 type bytes left)
;              and the next (type) byte is non-blank, output '.' first; loop until all 11 chars are shown.
; ----------------------------------------------------------------------
STMT_FILES_3:
        LD A,(HL)
        INC HL
        CALL OUTCHR
        LD A,C
        ; after the 8-char name (3 type bytes remain) decide whether to print the '.' separator
        CP $04
        JR NZ,STMT_FILES_5
        LD A,(HL)
        CP $20
        JR Z,STMT_FILES_4
        LD A,$2E
; ----------------------------------------------------------------------
; STMT_FILES_4 -- emit the chosen name/extension boundary byte.
;   In:        A = '.' ($2E, when the extension is non-blank) or the actual type byte (when ext is blank).
;   Out:       one char written via OUTCHR.
;   Clobbers:  A.
;   Algorithm: Output the separator (or the falls-through type byte), then continue the 11-char print loop.
; ----------------------------------------------------------------------
STMT_FILES_4:
        CALL OUTCHR
; ----------------------------------------------------------------------
; STMT_FILES_5 -- name-loop counter and end-of-name column handling.
;   In:        C = remaining name bytes; PRINT_WIDTH and the current print column ($0B11) for layout.
;   Out:       loops back while bytes remain; at end, prints two spaces to tab to the next column, or sets
;              CY to wrap to a new line.
;   Clobbers:  A, D.
;   Algorithm: Decrement C and loop until the 11-char name is printed; then compute (column+$0F) and
;              compare PRINT_WIDTH to it -- if PRINT_WIDTH < column+$0F the next column would overflow (CY
;              set) so skip the spaces and let STMT_FILES_6 CRLF; otherwise print two spaces to tab over.
; ----------------------------------------------------------------------
STMT_FILES_5:
        DEC C
        JR NZ,STMT_FILES_3
        LD A,(CURSOR_POS)
        ADD A,$0F
        LD D,A
        ; decide whether the next column fits on the current line
        LD A,(PRINT_WIDTH)
        CP D
        JR C,STMT_FILES_6
        LD A,$20
        CALL OUTCHR
        CALL OUTCHR
; ----------------------------------------------------------------------
; STMT_FILES_6 -- advance to the next matching entry (Search-Next) or finish the listing.
;   In:        CY from the column test (set -> wrap line); SCRATCH_FCB still holds the search pattern.
;   Out:       prints a CRLF if wrapping, BDOS Search-Next; loops to STMT_FILES_2 on a match, else RET.
;   Clobbers:  A, C, DE.
;   Algorithm: Optionally CRLF (CALL C,CRLF), then BDOS F_SNEXT; A=$FF ends the listing (restore HL and
;              return), any other value loops back to print the next name.
; ----------------------------------------------------------------------
STMT_FILES_6:
        CALL C,CRLF
        LD DE,SCRATCH_FCB
        ; BDOS search-next: fetch the next matching directory entry, $FF ends the listing
        LD C,F_SNEXT
        CALL BDOS
        CP $FF
        JR NZ,STMT_FILES_2
        POP HL
        RET
; ----------------------------------------------------------------------
; FCB_WILD_IF_STAR -- if an FCB name/type field begins with '*', expand it to all-'?' wildcards.
;   In:        HL -> start of the field; C = field width (8 for name, 3 for type).
;   Out:       if (HL)=='*', the C bytes are set to '?'; otherwise the field is unchanged. RET.
;   Clobbers:  A (and, when expanding, C, HL via the fall-through).
;   Algorithm: Test the first byte; if not '*' return immediately, else fall into FCB_WILD_EXPAND to fill
;              the field with '?' so BDOS directory search matches any name/extension.
; ----------------------------------------------------------------------
FCB_WILD_IF_STAR:
        LD A,(HL)
        CP $2A
        RET NZ
; ----------------------------------------------------------------------
; FCB_WILD_EXPAND -- fill C FCB field bytes with '?' ($3F) (a match-anything wildcard for BDOS search).
;   In:        HL -> field, C = byte count.
;   Out:       C bytes set to '?'; HL advanced past them; RET.
;   Clobbers:  C, HL.
;   Algorithm: Store '?' across C bytes. Used to build the default all-files pattern and to expand a
;              leading '*' wildcard.
; ----------------------------------------------------------------------
FCB_WILD_EXPAND:
        LD (HL),$3F
        INC HL
        DEC C
        JR NZ,FCB_WILD_EXPAND
        RET
; ----------------------------------------------------------------------
; BDOS_FILE_CALL -- shared BDOS file-op wrapper: issue the call, advance the random record number, map result.
;   In:        A = BDOS function number, DE = FCB pointer (= &FCB.CPM, i.e. entry+1).
;   Out:       For read-random (C==$22 on return) returns a mapped BASIC status in A and flags: 0/Z on
;              success, 1 on 'reading unwritten data' ($03), else 2; dir-full ($05) -> Too many files. For
;              other functions returns the raw BDOS A.
;   Clobbers:  A, BC, HL; increments the 3-byte random record number R0/R1/R2 of the FCB.
;   Algorithm: Call BDOS with C=A, DE=FCB; on return increment the 24-bit random record number with carry
;              -- the operand FCB.CPM.CR assembles to $21 and is added to DE (=entry+1), so the first byte
;              touched is R0 (CPMFCB offset $21), then R1 ($22), then R2 ($23); CR ($20) is NOT touched here.
;              If the function was read-random ($22), translate the BDOS error code into BASIC's small codes;
;              otherwise pass the BDOS result through unchanged. [RE] The R0/R1/R2 bump advances the random
;              record cursor so a subsequent random op addresses the following record.
; ----------------------------------------------------------------------
BDOS_FILE_CALL:
        PUSH DE
        LD C,A
        PUSH BC
        ; perform the requested BDOS file operation (C=function, DE=FCB)
        CALL BDOS
        POP BC
        POP DE
        PUSH AF
        ; advance the 24-bit random record number R0/R1/R2 with carry (operand $21 added to DE=entry+1 lands on R0); next random op reads the following record
        LD HL,FCB.CPM.CR
        ADD HL,DE
        INC (HL)
        JR NZ,BDOS_FILE_CALL_1
        INC HL
        INC (HL)
        JR NZ,BDOS_FILE_CALL_1
        INC HL
        INC (HL)
; ----------------------------------------------------------------------
; BDOS_FILE_CALL_1 -- result-mapping arm for a read-random BDOS call.
;   In:        C = the BDOS function that was called; BDOS A-result saved on the stack.
;   Out:       A = mapped BASIC status (0 ok, 1 for code 3, 2 otherwise); errors jumped out above.
;   Clobbers:  A.
;   Algorithm: If the function was read-random ($22): success -> RET Z; code 5 -> Too many files;
;              code 3 (reading unwritten data) -> A=1 RET; any other -> A=2 RET. Non-random calls fall
;              to BDOS_FILE_CALL_2 which returns the raw result.
; ----------------------------------------------------------------------
BDOS_FILE_CALL_1:
        LD A,C
        ; only read-random ($22) results get translated to BASIC codes; others pass through
        CP $22
        JR NZ,BDOS_FILE_CALL_2
        POP AF
        OR A
        RET Z
        CP $05
        ; BDOS code 5 (no directory space) -> Too many files
        JP Z,RAISE_TOO_MANY_FILES
        CP $03
        LD A,$01
        RET Z
        INC A
        RET
; ----------------------------------------------------------------------
; BDOS_FILE_CALL_2 -- pass-through arm: return the raw BDOS result for non-read-random functions.
;   In:        BDOS A-result saved on the stack.
;   Out:       A = original BDOS result; RET.
;   Clobbers:  A.
;   Algorithm: Pop the saved BDOS A and return it unmodified.
; ----------------------------------------------------------------------
BDOS_FILE_CALL_2:
        POP AF
        RET
; ----------------------------------------------------------------------
; FILE_READ_RECORDS -- read DE bytes of a file as whole 128-byte sequential records into the data buffer.
;   In:        HL/DE describe the transfer: on entry EX DE,HL makes DE = byte/record count; PTRFIL = file.
;   Out:       successive 128-byte records read via BDOS into the file's buffer and copied out until the
;              count is exhausted.
;   Clobbers:  A, BC, DE, HL.
;   Algorithm: Check string space (STRING_SPACE_ROOM_CHECK); then loop: copy the current 128-byte record
;              out of FCB.SEQ_BUF, decrement the remaining count, bump the FCB current-record byte CR, set
;              DMA and BDOS F_READ the next record, until DE reaches zero.
; ----------------------------------------------------------------------
FILE_READ_RECORDS:
        EX DE,HL
        ; ensure free string space remains before buffering more file data
        CALL STRING_SPACE_ROOM_CHECK
        LD HL,(PTRFIL)
        PUSH HL
        LD BC,FCB.SEQ_BUF+1
        ADD HL,BC
; ----------------------------------------------------------------------
; FILE_READ_RECORDS_1 -- per-record body: copy one buffered record out and advance the file record cursor.
;   In:        HL -> file entry base (from PTRFIL, on stack), DE = records/bytes remaining.
;   Out:       128 bytes copied; DE decremented; FCB current-record (CR, offset $20) incremented.
;   Clobbers:  A, BC, DE, HL.
;   Algorithm: COPY_128_BLOCK out of the file buffer, decrement the count, then add the FCB.CPM.CR offset
;              ($21) to the entry base HL (=entry+$21 = CR at CPMFCB $20) and INC it so the next BDOS read
;              fetches the following record.
; ----------------------------------------------------------------------
FILE_READ_RECORDS_1:
        CALL COPY_128_BLOCK
        DEC DE
        POP HL
        LD BC,FCB.CPM.CR
        ADD HL,BC
        INC (HL)
; ----------------------------------------------------------------------
; FILE_READ_RECORDS_2 -- fetch the next 128-byte record from disk via BDOS read-sequential.
;   In:        DE = remaining count; PTRFIL = file entry.
;   Out:       one record read into the file's buffer at PTRFIL+1; A = BDOS status.
;   Clobbers:  A, BC, DE, HL.
;   Algorithm: Room-check string space, set DMA to the default buffer, point DE at the file buffer
;              (PTRFIL+1), BDOS F_READ, and fall into the count test.
; ----------------------------------------------------------------------
FILE_READ_RECORDS_2:
        CALL STRING_SPACE_ROOM_CHECK
        PUSH DE
        LD C,F_DMAOFF
        CALL BDOS
        LD HL,(PTRFIL)
        INC HL
        EX DE,HL
        ; BDOS read-sequential one 128-byte record into the file buffer
        LD C,F_READ
        CALL BDOS
        OR A
        POP DE
; ----------------------------------------------------------------------
; FILE_READ_RECORDS_3 -- loop test: stop on a short/last record, else fetch another.
;   In:        A = BDOS read status (NZ at EOF/short), DE = remaining count.
;   Out:       returns when the read hit end-of-file; otherwise loops to read the next record.
;   Clobbers:  DE, HL.
;   Algorithm: Advance the destination by 128 ($0080); if the last BDOS read returned non-zero (no more
;              data) RET, else swap and loop back to FILE_READ_RECORDS_2.
; ----------------------------------------------------------------------
FILE_READ_RECORDS_3:
        LD HL,$0080
        ADD HL,DE
        RET NZ
        EX DE,HL
        JR FILE_READ_RECORDS_2
; ----------------------------------------------------------------------
; STRING_SPACE_ROOM_CHECK -- guard that enough free string space remains before buffering more data.
;   In:        FRETOP = top of free string area; DE = the pointer about to be used.
;   Out:       RET if (FRETOP - $D6) >= DE (room ok); otherwise jumps to RUN_NO_FILENAME (Out of string
;              space cleanup).
;   Clobbers:  A, BC, HL.
;   Algorithm: Compute FRETOP minus a $D6-byte safety margin (LD BC,$FF2A; ADD HL,BC) and compare to DE;
;              carry-clear (enough room) returns, else divert to the string-space exhaustion handler.
; ----------------------------------------------------------------------
STRING_SPACE_ROOM_CHECK:
        LD HL,(FRETOP)
        LD BC,$FF2A
        ADD HL,BC
        CALL CMP_HL_DE
        RET NC
        JP RUN_NO_FILENAME
; ----------------------------------------------------------------------
; FILE_NUM_TO_FCB_2 -- for a RANDOM file, parse the optional FIELD record/buffer argument and seed its cursors.
;   In:        A = the file MODE (CP $03 tests FCB_MODE_RANDOM); BC -> the file's FCB entry; HL = text pointer.
;   Out:       For a non-random file: returns immediately, HL unchanged (= continuation text pointer). For
;              random: FCB.FLD_BUF_PTR (+$A9) = the FIELD buffer pointer (DE; default $0080 or the parsed
;              value), the following 7 FIELD descriptor/position bytes zeroed, and HL = the post-argument
;              text pointer. FC if the pointer exceeds FIELD_BUF_ADDR_LIMIT.
;   Clobbers:  A, DE, HL.
;   Algorithm: If A != FCB_MODE_RANDOM ($03) RET NZ (sequential files take no FIELD arg). Otherwise step
;              back, CHRGET; if the next token is a number parse it (GETINT_CHRGET_POS) as the FIELD buffer
;              address, else default DE=$0080; verify DE <= FIELD_BUF_ADDR_LIMIT (else FC), store it as the
;              FIELD buffer pointer in the FCB, and zero the following 7 FIELD descriptor/position cells.
; ----------------------------------------------------------------------
FILE_NUM_TO_FCB_2:
        ; only a RANDOM-mode file (mode 3) reads the optional FIELD record/buffer argument; others return at once
        CP $03
        RET NZ
        DEC HL
        CALL CHRGET
        PUSH DE
        LD DE,$0080
        JR Z,FILE_NUM_TO_FCB_2_1
        PUSH BC
        CALL GETINT_CHRGET_POS
        POP BC
; ----------------------------------------------------------------------
; FILE_NUM_TO_FCB_2_1 -- common tail: validate the FIELD pointer and store it into the FCB.
;   In:        DE = FIELD buffer pointer (parsed or default $0080); BC -> FCB entry.
;   Out:       FCB.FLD_BUF_PTR set; following 7 FIELD bytes zeroed; HL/DE restored. FC on overflow.
;   Clobbers:  A, HL.
;   Algorithm: Compare FIELD_BUF_ADDR_LIMIT to DE (carry, i.e. limit<DE -> FC), write DE into
;              FCB.FLD_BUF_PTR, then fall into the zero-fill of the FIELD descriptor/position cursors.
; ----------------------------------------------------------------------
FILE_NUM_TO_FCB_2_1:
        PUSH HL
        ; [RE] range-check the FIELD buffer pointer against the configured buffer-address limit
        LD HL,(FIELD_BUF_ADDR_LIMIT)
        CALL CMP_HL_DE
        JP C,ERROR_FC
        ; store the FIELD buffer base pointer into the FCB
        LD HL,FCB.FLD_BUF_PTR
        ADD HL,BC
        LD (HL),E
        INC HL
        LD (HL),D
        XOR A
        LD E,$07
; ----------------------------------------------------------------------
; FILE_NUM_TO_FCB_2_2 -- zero the FIELD descriptor/position cursor bytes after the buffer pointer.
;   In:        HL -> just past FCB.FLD_BUF_PTR, E = 7 (count), A = 0.
;   Out:       7 bytes (FIELD descriptor + record number + position pointers) cleared.
;   Clobbers:  E, HL.
;   Algorithm: Store 0 across the 7 FIELD bookkeeping bytes so a fresh FIELD/GET/PUT starts clean.
; ----------------------------------------------------------------------
FILE_NUM_TO_FCB_2_2:
        INC HL
        LD (HL),A
        DEC E
        JR NZ,FILE_NUM_TO_FCB_2_2
        POP HL
        POP DE
        RET
; ----------------------------------------------------------------------
; STMT_PUT -- PUT statement (token $BB): write a random-file record. GET (token $BA) enters one byte later at STMT_PUT+1.
;   In:        HL = text cursor; syntax PUT[#]filenum[,recordnum]. PUT runs OR $AF (A != 0 = write, NZ); GET runs the swallowed $AF = XOR A (A = 0 = read, Z).
;   Out:       The direction byte is latched in RND_GET_PUT_DIR; FILE_NUM_TO_FCB resolves the channel; falls into GET_PUT_RECORD_CORE which performs the transfer.
;   Clobbers:  A,BC,DE,HL.
;   Algorithm: Latch A (the direction) into RND_GET_PUT_DIR. The GET entry (Z) calls EVAL_CHANNEL_OR_ITEM (which parses the '#' channel); the PUT entry (NZ) skips that call. Then FILE_NUM_TO_FCB and fall into the shared record core. [RE] The exact reason only the GET entry calls EVAL_CHANNEL_OR_ITEM (the OR $AF/XOR A Z flag, not a 'channel already parsed' flag) is not fully explained by these bytes.
; ----------------------------------------------------------------------
STMT_PUT:
        OR $AF
        ; latch transfer direction: PUT=write (nonzero), GET=read (zero)
        LD (RND_GET_PUT_DIR),A
        CALL Z,EVAL_CHANNEL_OR_ITEM
        CALL FILE_NUM_TO_FCB
; ----------------------------------------------------------------------
; GET_PUT_RECORD_CORE -- shared GET/PUT random-record engine: validate the file, resolve the record number, map it to a CP/M sector + offset, and read or write the FIELD window record.
;   In:        BC = FCB base, A = FCB mode byte, HL = text cursor; RND_GET_PUT_DIR already latched (0=GET/read, nonzero=PUT/write).
;   Out:       The requested record is transferred between the file's sector buffer (FCB.SEQ_BUF) and the FIELD window (FCB.RND_BUF); FCB.RND_RECNO updated to the record used; RET.
;   Clobbers:  A,BC,DE,HL; scratch words RND_SECTOR_NUM, RND_FIELD_PTR, RND_SECTOR_PTR.
;   Algorithm: Require mode 3 (random) else 'Bad file mode'. Default record = FCB.RND_RECNO+1; if a ',' follows parse an explicit record number (GETINT_CHRGET_POS), requiring end-of-statement after it. Reject record 0 ('Bad record number'); store the 1-based record back to FCB.RND_RECNO; convert to 0-based (DEC DE). Zero FCB.FLD_POS_PTR. [RE] Multiply the record length (FCB.FLD_BUF_PTR, read as a count) by (record-1) as a 16x16->32-bit product (GET_PUT_RECORD_CORE_2..8), splitting the byte offset into RND_SECTOR_NUM = offset/128 (the CP/M sector index) and DE = offset mod 128 (within-sector position). When the length equals 128 a shortcut sets DE=0 and skips the multiply (GET_PUT_RECORD_CORE_9). Then loop (GET_PUT_RECORD_CORE_10): set the FIELD pointer (RND_BUF base) and the sector pointer (SEQ_BUF + within-sector offset), copy min(bytes-left, 128-position) bytes between them in the latched direction, calling FIELD_WRITE_RECORD to flush/read each sector, until the whole record is transferred.
; ----------------------------------------------------------------------
GET_PUT_RECORD_CORE:
        CP $03
        ; GET/PUT require a random (mode 3) file
        JP NZ,RAISE_BAD_FILE_MODE
        PUSH BC
        PUSH HL
        LD HL,FCB.RND_RECNO
        ADD HL,BC
        LD E,(HL)
        INC HL
        LD D,(HL)
        ; default record = last record used + 1
        INC DE
        EX (SP),HL
        LD A,(HL)
        CP $2C
; ----------------------------------------------------------------------
; GET_PUT_RECORD_CORE_1 -- parse the optional explicit record number and validate the statement tail.
;   In:        A = current text char (',' if a record number is present), HL = text cursor, DE = default record.
;   Out:       DE = chosen record number; HL repositioned; 'Syntax error' if extra tokens follow.
;   Clobbers:  A,DE,HL.
;   Algorithm: If the char is ',' call GETINT_CHRGET_POS to read the record number into DE; then CHRGET must reach end-of-statement (else 'Syntax error').
; ----------------------------------------------------------------------
GET_PUT_RECORD_CORE_1:
        ; ',' present -> read the explicit record number
        CALL Z,GETINT_CHRGET_POS
        DEC HL
        CALL CHRGET
        ; nothing else may follow the record number
        JP NZ,RAISE_SYNTAX_ERROR
        EX (SP),HL
        LD A,E
        OR D
        ; record numbers are 1-based; 0 is invalid
        JP Z,RAISE_BAD_RECORD_NUMBER
        DEC HL
        LD (HL),E
        INC HL
        LD (HL),D
        DEC DE
        POP HL
        POP BC
        PUSH HL
        PUSH BC
        LD HL,FCB.FLD_POS_PTR
        ADD HL,BC
        XOR A
        LD (HL),A
        INC HL
        LD (HL),A
        LD HL,FCB.FLD_BUF_PTR
        ADD HL,BC
        LD A,(HL)
        INC HL
        LD H,(HL)
        LD L,A
        EX DE,HL
        PUSH DE
        PUSH HL
        LD HL,$0080
        CALL CMP_HL_DE
        POP HL
        JR NZ,GET_PUT_RECORD_CORE_2
        LD DE,$0000
        JR GET_PUT_RECORD_CORE_9
; ----------------------------------------------------------------------
; GET_PUT_RECORD_CORE_2 -- record-offset multiply setup: prime a 32-bit shift-add product of the record length by the record index.
;   In:        DE = record length (from FCB.FLD_BUF_PTR), HL = (record-1) the 0-based record index.
;   Out:       BC = length (multiplicand), DE = record index (multiplier), HL=0 (product low) and a 0 word pushed (product high), A = 16 (iteration count); falls into the shift-add loop.
;   Clobbers:  A,BC,DE,HL, stack.
;   Algorithm: Copy the length into BC, set A=16, swap the index into DE, clear the low product word (HL) and push a zero high word -- a classic 16x16->32 binary multiply seed.
; ----------------------------------------------------------------------
GET_PUT_RECORD_CORE_2:
        LD B,D
        LD C,E
        ; 16-bit multiply: 16 shift-add iterations
        LD A,$10
        EX DE,HL
        LD HL,$0000
        PUSH HL
; ----------------------------------------------------------------------
; GET_PUT_RECORD_CORE_3 -- multiply loop top: shift the 32-bit partial product left by one bit.
;   In:        HL = product low word, stack top = product high word.
;   Out:       Product shifted left 1 bit (carry threaded low->high); continues into the multiplier-bit test.
;   Clobbers:  HL, stack.
;   Algorithm: ADD HL,HL on the low word, propagate carry into the high word on the stack (the +INC HL form when carry is set).
; ----------------------------------------------------------------------
GET_PUT_RECORD_CORE_3:
        ADD HL,HL
        EX (SP),HL
        JR NC,GET_PUT_RECORD_CORE_4
        ADD HL,HL
        INC HL
        JR GET_PUT_RECORD_CORE_5
; ----------------------------------------------------------------------
; GET_PUT_RECORD_CORE_4 -- multiply loop: high-word shift, no carry-in case.
;   In:        Product high word in HL (just exchanged off the stack).
;   Out:       High word shifted left without the +1 carry bit; falls into the merge.
;   Clobbers:  HL.
;   Algorithm: ADD HL,HL only (carry-clear branch of the partial-product shift).
; ----------------------------------------------------------------------
GET_PUT_RECORD_CORE_4:
        ADD HL,HL
; ----------------------------------------------------------------------
; GET_PUT_RECORD_CORE_5 -- multiply loop: shift the multiplier and conditionally add the multiplicand.
;   In:        Stack/HL hold the partial product; DE = multiplier, BC = multiplicand (record length).
;   Out:       If the multiplier's top bit was set, the multiplicand is added into the 32-bit product (with carry into the high word).
;   Clobbers:  A,DE,HL, stack.
;   Algorithm: Shift the multiplier (DE) left one bit; on a 1 bit add BC to the product low word and propagate carry into the high word; otherwise skip the add (GET_PUT_RECORD_CORE_7).
; ----------------------------------------------------------------------
GET_PUT_RECORD_CORE_5:
        EX (SP),HL
        EX DE,HL
        ADD HL,HL
        EX DE,HL
        JR NC,GET_PUT_RECORD_CORE_7
        ; multiplier bit set -> add the record length into the product
        ADD HL,BC
        EX (SP),HL
        JR NC,GET_PUT_RECORD_CORE_6
        INC HL
; ----------------------------------------------------------------------
; GET_PUT_RECORD_CORE_6 -- multiply loop: carry the add into the product high word.
;   In:        Carry out of the low-word add; product high word on stack.
;   Out:       High word incremented when the add carried; rejoins the loop counter step.
;   Clobbers:  HL, stack.
;   Algorithm: EX (SP),HL to bring the high word into HL where the preceding INC HL applied the carry, then continue.
; ----------------------------------------------------------------------
GET_PUT_RECORD_CORE_6:
        EX (SP),HL
; ----------------------------------------------------------------------
; GET_PUT_RECORD_CORE_7 -- multiply loop counter and extraction of the within-sector offset.
;   In:        A = remaining iteration count; on loop end HL/stack hold the 32-bit product = record_index * record_length.
;   Out:       On loop end: DE = product & $7F (byte offset within a 128-byte sector); continues to derive the sector number.
;   Clobbers:  A,DE,HL.
;   Algorithm: DEC A and re-loop while non-zero. When done, mask the low product byte to 7 bits (offset mod 128) into DE and fall through to compute the sector index = offset / 128.
; ----------------------------------------------------------------------
GET_PUT_RECORD_CORE_7:
        DEC A
        JR NZ,GET_PUT_RECORD_CORE_3
        LD A,L
        ; byte position within the 128-byte sector = offset mod 128
        AND $7F
        LD E,A
        LD D,$00
        POP BC
        LD A,L
        LD L,H
        LD H,C
        ADD HL,HL
        JP C,ERROR_FC
        RLA
        JR NC,GET_PUT_RECORD_CORE_8
        INC HL
; ----------------------------------------------------------------------
; GET_PUT_RECORD_CORE_8 -- finish the sector-number derivation and overflow-check it.
;   In:        HL holds the realigned product bytes; B = the product's top byte.
;   Out:       HL = CP/M sector index (byte offset / 128); 'Illegal function call' if it overflows; falls into GET_PUT_RECORD_CORE_9.
;   Clobbers:  A,HL.
;   Algorithm: Realign the product bytes and shift right by 7 (byte-swap + ADD HL,HL + RLA carry-in) to obtain offset/128 in HL; if the carry out of ADD HL,HL or any remaining high byte (B) is non-zero the record is past the addressable limit -> FC error.
; ----------------------------------------------------------------------
GET_PUT_RECORD_CORE_8:
        LD A,B
        OR A
        ; record offset exceeds the addressable sector range
        JP NZ,ERROR_FC
; ----------------------------------------------------------------------
; GET_PUT_RECORD_CORE_9 -- latch the sector index and set up the FIELD-window pointer.
;   In:        HL = CP/M sector index for the record start, DE = within-sector byte offset; BC restored to the FCB base.
;   Out:       RND_SECTOR_NUM = sector index; RND_FIELD_PTR = FCB.RND_BUF base; falls into the per-sector transfer loop.
;   Clobbers:  HL, scratch words.
;   Algorithm: Store HL to RND_SECTOR_NUM, recover the FCB base, and record the FIELD-window pointer (RND_BUF) in RND_FIELD_PTR.
; ----------------------------------------------------------------------
GET_PUT_RECORD_CORE_9:
        ; RND_SECTOR_NUM = CP/M sector index of the field start
        LD (RND_SECTOR_NUM),HL
        POP HL
        POP BC
        PUSH HL
        LD HL,FCB.RND_BUF
        ADD HL,BC
        ; RND_FIELD_PTR = FIELD window base (RND_BUF)
        LD (RND_FIELD_PTR),HL
; ----------------------------------------------------------------------
; GET_PUT_RECORD_CORE_10 -- per-sector transfer loop top: point at the within-sector position and size this chunk.
;   In:        BC = FCB base, DE = within-sector byte offset, RND_FIELD_PTR set; the stack holds the field bytes still to transfer.
;   Out:       RND_SECTOR_PTR = FCB.SEQ_BUF + offset; HL = min(bytes-remaining, 128 - offset) = this iteration's byte count; dispatches the read or write path.
;   Clobbers:  A,DE,HL, scratch RND_SECTOR_PTR.
;   Algorithm: Compute the sector-buffer pointer (SEQ_BUF + within-sector offset) into RND_SECTOR_PTR; chunk = 128 - offset, clamped to the remaining field bytes; branch on RND_GET_PUT_DIR (GET -> GET_PUT_RECORD_CORE_15 read path; PUT -> the write path).
; ----------------------------------------------------------------------
GET_PUT_RECORD_CORE_10:
        LD HL,FCB.SEQ_BUF
        ADD HL,BC
        ADD HL,DE
        ; RND_SECTOR_PTR = sector buffer (SEQ_BUF) + within-sector offset
        LD (RND_SECTOR_PTR),HL
        POP HL
        PUSH HL
        LD HL,$0080
        LD A,L
        SUB E
        LD L,A
        LD A,H
        SBC A,D
        LD H,A
        POP DE
        PUSH DE
        CALL CMP_HL_DE
        JR C,GET_PUT_RECORD_CORE_11
        LD H,D
        LD L,E
; ----------------------------------------------------------------------
; GET_PUT_RECORD_CORE_11 -- PUT path: on a full-sector chunk, read the existing sector first, then size the copy.
;   In:        HL = this chunk's byte count, BC = FCB base.
;   Out:       If the chunk fills a whole 128-byte sector, the sector is first read in (FIELD_WRITE_RECORD+1); HL preserved as the chunk size.
;   Clobbers:  A,DE,HL, stack.
;   Algorithm: Read RND_GET_PUT_DIR; on the write path compare the chunk size with $0080 and, when it is a full sector, CALL FIELD_WRITE_RECORD+1 to load the existing sector before overwriting part of it.
; ----------------------------------------------------------------------
GET_PUT_RECORD_CORE_11:
        LD A,(RND_GET_PUT_DIR)
        OR A
        JR Z,GET_PUT_RECORD_CORE_15
        LD DE,$0080
        CALL CMP_HL_DE
        JR NC,GET_PUT_RECORD_CORE_12
        PUSH HL
        CALL FIELD_WRITE_RECORD+1
        POP HL
; ----------------------------------------------------------------------
; GET_PUT_RECORD_CORE_12 -- PUT path: set up the copy length for this sector chunk.
;   In:        HL = chunk byte count, BC = FCB base.
;   Out:       BC = chunk byte count for BLOCK_COPY_BC; FCB base saved on the stack; falls into the copy+flush step.
;   Clobbers:  BC, stack.
;   Algorithm: Save the FCB base, move the chunk count into BC for the block copier.
; ----------------------------------------------------------------------
GET_PUT_RECORD_CORE_12:
        PUSH BC
        LD B,H
        LD C,L
; ----------------------------------------------------------------------
; GET_PUT_RECORD_CORE_13 -- PUT path: copy FIELD-window bytes into the sector buffer and flush the sector.
;   In:        RND_SECTOR_PTR = dest (in the sector buffer), RND_FIELD_PTR = source (FIELD window), BC = chunk count.
;   Out:       Chunk copied; RND_FIELD_PTR advanced; FIELD_WRITE_RECORD invoked to write the sector when the boundary is crossed; falls into the loop-bottom bookkeeping.
;   Clobbers:  A,BC,DE,HL, scratch RND_FIELD_PTR.
;   Algorithm: Set DE=RND_SECTOR_PTR, HL=RND_FIELD_PTR, BLOCK_COPY_BC the chunk (field -> sector), store the advanced FIELD pointer back to RND_FIELD_PTR, restore BC=FCB base, then CALL FIELD_WRITE_RECORD to commit the sector.
; ----------------------------------------------------------------------
GET_PUT_RECORD_CORE_13:
        LD HL,(RND_SECTOR_PTR)
        EX DE,HL
        LD HL,(RND_FIELD_PTR)
        ; copy the FIELD-window bytes into the sector buffer
        CALL BLOCK_COPY_BC
        LD (RND_FIELD_PTR),HL
        LD D,B
        LD E,C
        POP BC
        ; advance the cursor and flush the sector when the boundary is reached
        CALL FIELD_WRITE_RECORD
; ----------------------------------------------------------------------
; GET_PUT_RECORD_CORE_14 -- per-sector loop bottom: subtract this chunk, advance the sector, and continue or finish.
;   In:        Stack top = field bytes remaining, DE = bytes transferred this chunk, RND_SECTOR_NUM = current sector.
;   Out:       Remaining count reduced; RND_SECTOR_NUM incremented; loops to GET_PUT_RECORD_CORE_10 while bytes remain, else cleans up the stack and RET.
;   Clobbers:  A,DE,HL, scratch RND_SECTOR_NUM.
;   Algorithm: remaining -= transferred; reset the within-sector offset (DE=0) for the next full sector; INC RND_SECTOR_NUM; re-loop if remaining != 0, otherwise pop the work frames and return.
; ----------------------------------------------------------------------
GET_PUT_RECORD_CORE_14:
        POP HL
        LD A,L
        SUB E
        LD L,A
        LD A,H
        SBC A,D
        LD H,A
        OR L
        LD DE,$0000
        PUSH HL
        LD HL,(RND_SECTOR_NUM)
        ; advance to the next CP/M sector
        INC HL
        LD (RND_SECTOR_NUM),HL
        ; more field bytes -> transfer the next sector
        JR NZ,GET_PUT_RECORD_CORE_10
        POP HL
        POP HL
        RET
; ----------------------------------------------------------------------
; GET_PUT_RECORD_CORE_15 -- GET path: read the sector then copy its bytes into the FIELD window.
;   In:        HL = chunk byte count, BC = FCB base, RND_SECTOR_PTR = source (sector buffer), RND_FIELD_PTR = dest (FIELD window).
;   Out:       The disk sector is loaded (FIELD_WRITE_RECORD+1 read/no-flush entry), the chunk copied into the FIELD window, RND_FIELD_PTR advanced; rejoins the loop bottom.
;   Clobbers:  A,BC,DE,HL, scratch RND_FIELD_PTR.
;   Algorithm: CALL FIELD_WRITE_RECORD+1 to read the sector into the buffer, BLOCK_COPY_BC the chunk from RND_SECTOR_PTR -> RND_FIELD_PTR, store the advanced destination back to RND_FIELD_PTR (via EX DE,HL), and JR to GET_PUT_RECORD_CORE_14.
; ----------------------------------------------------------------------
GET_PUT_RECORD_CORE_15:
        PUSH HL
        ; GET: load the disk sector into the buffer (no-flush entry)
        CALL FIELD_WRITE_RECORD+1
        POP HL
        PUSH BC
        LD B,H
        LD C,L
        LD HL,(RND_FIELD_PTR)
        EX DE,HL
        LD HL,(RND_SECTOR_PTR)
        ; copy the sector bytes into the FIELD window
        CALL BLOCK_COPY_BC
        EX DE,HL
        LD (RND_FIELD_PTR),HL
        LD D,B
        LD E,C
        POP BC
        JR GET_PUT_RECORD_CORE_14
; ----------------------------------------------------------------------
; FIELD_WRITE_RECORD -- random-record sector-commit helper: advance the running sector cursor and, when it crosses the tracked boundary (or the flush flag forces it), dispatch the CP/M record read/write via PUTC_FILE_3. Entered at +1 (skip the OR $AF) for the read/no-flush variant.
;   In:        BC = FCB base; the running cursor lives in RND_SECTOR_NUM; full entry runs OR $AF (flush/write), entry+1 runs the swallowed XOR A (no-flush/read).
;   Out:       RND_WRITE_FLAG latched; FCB.FLD_DESC_PTR updated to the new cursor; on a boundary crossing (or with the flush flag set) PUTC_FILE_3 performs the record I/O; registers restored; RET.
;   Clobbers:  A,BC,DE,HL (PUSH/POP-saved around the body).
;   Algorithm: Latch the direction into RND_WRITE_FLAG. Save registers, then in FIELD_WRITE_RECORD_1 advance the cursor: read RND_SECTOR_NUM, compare (RND_SECTOR_NUM+1) against FCB.FLD_DESC_PTR, store the incremented cursor back into FCB.FLD_DESC_PTR. [RE] If they differ (boundary reached) OR the flush flag is set, dispatch the record I/O through PUTC_FILE_3 (passing FCB.SEQ_RECNO+1) which itself selects read vs write from RND_WRITE_FLAG; otherwise just return.
; ----------------------------------------------------------------------
FIELD_WRITE_RECORD:
        OR $AF
        ; latch direction: full entry = write/flush, +1 entry = read/no-flush
        LD (FIELD_WRITE_FLAG),A
        PUSH BC
        PUSH DE
        PUSH HL
; ----------------------------------------------------------------------
; FIELD_WRITE_RECORD_1 -- cursor-advance + boundary test inside FIELD_WRITE_RECORD.
;   In:        BC = FCB base; RND_SECTOR_NUM = current cursor; FCB.FLD_DESC_PTR = the previously-stored cursor/boundary.
;   Out:       FCB.FLD_DESC_PTR updated to (RND_SECTOR_NUM+1); the compare result and flush flag decide whether to commit the record.
;   Clobbers:  A,DE,HL.
;   Algorithm: DE = RND_SECTOR_NUM; read FCB.FLD_DESC_PTR into HL; INC DE; compare; write the incremented cursor (DE) back into FCB.FLD_DESC_PTR. If the compare matched (no crossing) and the flush flag (RND_WRITE_FLAG) is clear, skip the I/O (FIELD_WRITE_RECORD_3); otherwise dispatch the record I/O.
; ----------------------------------------------------------------------
FIELD_WRITE_RECORD_1:
        LD HL,(RND_SECTOR_NUM)
        EX DE,HL
        LD HL,FCB.FLD_DESC_PTR
        ADD HL,BC
        PUSH HL
        LD A,(HL)
        INC HL
        LD H,(HL)
        LD L,A
        INC DE
        CALL CMP_HL_DE
        POP HL
        LD (HL),E
        INC HL
        LD (HL),D
        JR NZ,FIELD_WRITE_RECORD_2
        ; no crossing; only commit if the flush flag is set
        LD A,(FIELD_WRITE_FLAG)
        OR A
        JR Z,FIELD_WRITE_RECORD_3
; ----------------------------------------------------------------------
; FIELD_WRITE_RECORD_2 -- commit one random-file record via the sequential record handler.
;   In:        BC = FCB base; the random record number is taken from FCB.SEQ_RECNO+1.
;   Out:       The sector buffer is read or written by PUTC_FILE_3 (direction from RND_WRITE_FLAG); returns to FIELD_WRITE_RECORD_3.
;   Clobbers:  A,BC,DE,HL.
;   Algorithm: Stage FIELD_WRITE_RECORD_3 as the return point and the FCB base on the stack, point HL at FCB.SEQ_RECNO+1, and JP PUTC_FILE_3 to perform the record I/O.
; ----------------------------------------------------------------------
FIELD_WRITE_RECORD_2:
        LD HL,FIELD_WRITE_RECORD_3
        PUSH HL
        PUSH BC
        PUSH HL
        LD HL,FCB.SEQ_RECNO+1
        ADD HL,BC
        ; read or write the sector for this record number (PUTC_FILE_3 picks the direction)
        JP PUTC_FILE_3
; ----------------------------------------------------------------------
; FIELD_WRITE_RECORD_3 -- FIELD_WRITE_RECORD epilogue: restore registers and return.
;   In:        Saved HL/DE/BC on the stack from the routine entry.
;   Out:       Registers restored; RET.
;   Clobbers:  none (restores).
;   Algorithm: POP HL/DE/BC; RET.
; ----------------------------------------------------------------------
FIELD_WRITE_RECORD_3:
        POP HL
        POP DE
        POP BC
        RET
; ----------------------------------------------------------------------
; BLOCK_COPY_BC -- copy BC bytes from (HL) to (DE) for FIELD/GET/PUT record buffering; preserves BC.
;   In:        HL = source, DE = destination, BC = byte count.
;   Out:       BC bytes copied; HL and DE advanced past the block; BC restored to its original value; RET.
;   Clobbers:  A,DE,HL (BC preserved via PUSH/POP).
;   Algorithm: Save BC, then a byte-at-a-time LD (HL)->(DE)/INC/DEC-BC loop until BC reaches 0, then restore BC. (Byte loop rather than LDIR because BC must survive the call.)
; ----------------------------------------------------------------------
BLOCK_COPY_BC:
        PUSH BC
; ----------------------------------------------------------------------
; BLOCK_COPY_BC_1 -- BLOCK_COPY_BC inner copy loop.
;   In:        HL = source, DE = dest, BC = remaining count.
;   Out:       Loops until BC=0.
;   Clobbers:  A,BC,DE,HL.
;   Algorithm: A=(HL); (DE)=A; INC HL; INC DE; DEC BC; repeat while B|C nonzero.
; ----------------------------------------------------------------------
BLOCK_COPY_BC_1:
        LD A,(HL)
        LD (DE),A
        INC HL
        INC DE
        DEC BC
        LD A,B
        OR C
        JR NZ,BLOCK_COPY_BC_1
        POP BC
        RET
; ----------------------------------------------------------------------
; PUTC_FILE_RANDOM -- random-mode byte-output entry from PUTC_FILE: place one character into the current random FIELD position, tracking the field cursor and print column.
;   In:        On stack: the caller's saved return/registers and the byte to output; HL = FCB base via PTRFIL; the file is mode 3.
;   Out:       The character is stored at FCB.FLD_POS_PTR+1 within the FIELD window, the position cursor advanced (FCB_STORE_POSPTR), and the output column (FCB.BUF_REM) updated; on a full buffer raises 'FIELD overflow'.
;   Clobbers:  A,BC,DE,HL (restores the caller's saved registers).
;   Algorithm: Reorder the stacked frame; compute remaining FIELD space (FILE_BUF_REMAIN_BC); if exhausted raise 'FIELD overflow'. Advance and store the position pointer (FCB_STORE_POSPTR), write the byte at FCB.FLD_POS_PTR+1+offset, and maintain FCB.BUF_REM: reset to 0 on CR, else increment by 1 when the char is printable (the ADD A,$E0 / ADC carry idiom, matching PUTC_FILE).
; ----------------------------------------------------------------------
PUTC_FILE_RANDOM:
        POP AF
        PUSH DE
        PUSH BC
        PUSH AF
        LD B,H
        LD C,L
        ; how many bytes of FIELD space remain
        CALL FILE_BUF_REMAIN_BC
        ; no room left in the FIELD buffer
        JP Z,RAISE_FIELD_OVERFLOW
        ; advance and save the FIELD write position
        CALL FCB_STORE_POSPTR
        LD HL,FCB.FLD_POS_PTR+1
        ADD HL,BC
        ADD HL,DE
        POP AF
        LD (HL),A
        PUSH AF
        LD HL,FCB.BUF_REM
        ADD HL,BC
        LD D,(HL)
        LD (HL),$00
        ; CR resets the print column; printable chars bump it
        CP $0D
        JR Z,PUTC_FILE_RANDOM_1
        ADD A,$E0
        LD A,D
        ADC A,$00
        LD (HL),A
; ----------------------------------------------------------------------
; PUTC_FILE_RANDOM_1 -- PUTC_FILE_RANDOM epilogue: restore registers and return.
;   In:        Saved AF/BC/DE/HL on the stack.
;   Out:       Caller's registers restored; RET.
;   Clobbers:  none (restores).
;   Algorithm: POP AF/BC/DE/HL; RET.
; ----------------------------------------------------------------------
PUTC_FILE_RANDOM_1:
        POP AF
        POP BC
        POP DE
        POP HL
        RET
; ----------------------------------------------------------------------
; GETC_FILE_RANDOM -- random-mode byte-input entry from GETC_FILE: fetch one character from the current random FIELD position.
;   In:        DE saved on entry; HL = FCB base via PTRFIL; the file is mode 3.
;   Out:       A = the byte at the current FIELD position; the position cursor advanced; on an exhausted buffer raises 'FIELD overflow'; flags reflect the byte (OR A); RET.
;   Clobbers:  A,BC,DE,HL (restores the caller's saved DE/HL/BC).
;   Algorithm: Compute remaining FIELD bytes (FILE_BUF_REMAIN); if none raise 'FIELD overflow'; advance/store the position pointer (FCB_STORE_POSPTR); read the byte at FCB.FLD_POS_PTR+1+offset and OR A to set flags; restore registers and RET.
; ----------------------------------------------------------------------
GETC_FILE_RANDOM:
        PUSH DE
        ; how many bytes of FIELD data remain to read
        CALL FILE_BUF_REMAIN
        ; FIELD buffer exhausted
        JP Z,RAISE_FIELD_OVERFLOW
        ; advance and save the FIELD read position
        CALL FCB_STORE_POSPTR
        LD HL,FCB.FLD_POS_PTR+1
        ADD HL,BC
        ADD HL,DE
        LD A,(HL)
        OR A
        POP DE
        POP HL
        POP BC
        RET
; ----------------------------------------------------------------------
; FCB_LOAD_BUFPTR -- load the word at FCB.FLD_BUF_PTR (offset $A9) into DE.
;   In:        BC = FCB base.
;   Out:       DE = the 16-bit value at FCB.FLD_BUF_PTR.
;   Clobbers:  HL,DE.
;   Algorithm: Point HL at FCB.FLD_BUF_PTR and fall into FCB_LOAD_POSPTR_1 to read the little-endian word into DE. [RE] This field holds the record length (a count), not an address, despite the include's 'buffer base pointer' name.
; ----------------------------------------------------------------------
FCB_LOAD_BUFPTR:
        LD HL,FCB.FLD_BUF_PTR
        JR FCB_LOAD_POSPTR_1
; ----------------------------------------------------------------------
; FCB_LOAD_POSPTR -- load the word at FCB.FLD_POS_PTR (offset $B0) into DE: the random read/write position index within the FIELD window.
;   In:        BC = FCB base.
;   Out:       DE = the 16-bit value at FCB.FLD_POS_PTR (a within-record byte index, used as FCB_base+$B1+pos for the data byte).
;   Clobbers:  HL,DE.
;   Algorithm: Point HL at FCB.FLD_POS_PTR and fall into FCB_LOAD_POSPTR_1.
; ----------------------------------------------------------------------
FCB_LOAD_POSPTR:
        LD HL,FCB.FLD_POS_PTR
; ----------------------------------------------------------------------
; FCB_LOAD_POSPTR_1 -- shared little-endian word loader: DE = word at FCB_base + (HL offset).
;   In:        BC = FCB base, HL = field offset within the FCB.
;   Out:       DE = the 16-bit value stored at that FCB field.
;   Clobbers:  HL,DE.
;   Algorithm: HL += BC; E = (HL); INC HL; D = (HL); RET.
; ----------------------------------------------------------------------
FCB_LOAD_POSPTR_1:
        ADD HL,BC
        LD E,(HL)
        INC HL
        LD D,(HL)
        RET
; ----------------------------------------------------------------------
; FCB_STORE_POSPTR -- advance (INC DE) and store the FIELD current-position index (FCB.FLD_POS_PTR, offset $B0).
;   In:        BC = FCB base, DE = the position value to store after incrementing.
;   Out:       FCB.FLD_POS_PTR = DE+1; DE incremented.
;   Clobbers:  HL.
;   Algorithm: INC DE; point HL at FCB.FLD_POS_PTR; write E then D (little-endian); RET.
; ----------------------------------------------------------------------
FCB_STORE_POSPTR:
        INC DE
        LD HL,FCB.FLD_POS_PTR
        ADD HL,BC
        LD (HL),E
        INC HL
        LD (HL),D
        RET
; ----------------------------------------------------------------------
; FILE_BUF_REMAIN -- set BC = FCB base (from HL) then test whether the FIELD buffer position has reached the record length.
;   In:        HL = FCB base.
;   Out:       Z set when the FIELD position index equals the record length (buffer used up); compare result in flags.
;   Clobbers:  A,BC,DE,HL.
;   Algorithm: Copy HL into BC, then fall into FILE_BUF_REMAIN_BC to compare the position index (FCB.FLD_POS_PTR) against the record length (FCB.FLD_BUF_PTR).
; ----------------------------------------------------------------------
FILE_BUF_REMAIN:
        LD B,H
        LD C,L
; ----------------------------------------------------------------------
; FILE_BUF_REMAIN_BC -- FIELD position-vs-length test with BC already = FCB base.
;   In:        BC = FCB base.
;   Out:       Flags from comparing FCB.FLD_POS_PTR vs FCB.FLD_BUF_PTR; Z when the position index has reached the record length (buffer full/exhausted).
;   Clobbers:  A,DE,HL.
;   Algorithm: Load the position index (FCB_LOAD_POSPTR) and the record length (FCB_LOAD_BUFPTR), arrange them in HL/DE, and CMP_HL_DE to set the zero/carry result the random-I/O entries use to detect FIELD overflow/exhaustion.
; ----------------------------------------------------------------------
FILE_BUF_REMAIN_BC:
        CALL FCB_LOAD_POSPTR
        PUSH DE
        CALL FCB_LOAD_BUFPTR
        EX DE,HL
        POP DE
        ; position index vs record length -> Z when the FIELD buffer is full/used up
        CALL CMP_HL_DE
        RET
; ----------------------------------------------------------------------
; SAVE_PROTECTED_PROGRAM -- SAVE ... ,P entry: write the current program to disk in obfuscated ('protected') form.
;   In:        HL = text cursor after the ',P' option; the program occupies the text area; the output file is already open (STMT_SAVE opened it with D=2).
;   Out:       The program is transformed in place, written via SAVE_WRITE_PROGRAM with the $FE 'protected' file tag, then transformed back to its plain in-memory form; JP RESET_RUN_STATE_1.
;   Clobbers:  A,BC,DE,HL and program memory (the two transforms are reversible in place).
;   Algorithm: CHRGET past the option, save the cursor (OPEN_RESUME_TEXT_PTR), fix up line references (RENUM_PATCH_LINEREFS), CALL PROG_UNSCRAMBLE, SAVE_WRITE_PROGRAM with A=$FE (protected file type), CALL PROG_SCRAMBLE, then JP RESET_RUN_STATE_1. [RE] The code calls PROG_UNSCRAMBLE *before* the write and PROG_SCRAMBLE *after*; the encode/decode roles of those two routines are labeled elsewhere and not re-verified here -- the order of calls (UNSCRAMBLE, write, SCRAMBLE) is what is observed.
;   Note: This is NOT part of the random-file FIELD cluster -- it is the protected-SAVE path reached by JP Z,SAVE_PROTECTED_PROGRAM from STMT_SAVE (CP $50 = 'P'), physically adjacent to FILE_BUF_REMAIN_BC and mis-chained as its _1 local.
; ----------------------------------------------------------------------
SAVE_PROTECTED_PROGRAM:
        CALL CHRGET
        LD (OPEN_RESUME_TEXT_PTR),HL
        CALL RENUM_PATCH_LINEREFS
        ; transform the in-memory program before writing the protected copy
        CALL PROG_UNSCRAMBLE
        LD A,$FE
        ; write the program with the $FE protected-file tag
        CALL SAVE_WRITE_PROGRAM
        ; transform the in-memory program back to its plain running form
        CALL PROG_SCRAMBLE
        JP RESET_RUN_STATE_1
; ----------------------------------------------------------------------
; PROG_UNSCRAMBLE -- decode a protected (SAVE ",P") program image in place to runnable tokens.
;   In:        TXTTAB = program start, VARTAB = program end; the program bytes are encoded.
;   Out:       the program text from TXTTAB..VARTAB decoded in place; RET when the end is reached.
;   Clobbers:  A, BC, DE, HL.
;   Algorithm: MS BASIC-80 protected-program cipher. Two rotating key indices B (starts 13, cycles 13) and
;              C (starts 11, cycles 11) walk independently; B indexes the SIN coefficient table and C indexes
;              the ATN coefficient table. For each program byte: b = ((byte - B) XOR atn_key[C]); then
;              b = (b XOR sin_key[B]) + C; store b; then C decrements (wrapping 0->reload 11) and B
;              decrements (wrapping 0->reload 13). The FP polynomial coefficient tables double as cipher
;              keys -- their raw bytes, not their FP value, matter here. PROG_SCRAMBLE is the exact inverse.
; ----------------------------------------------------------------------
PROG_UNSCRAMBLE:
        LD BC,$0D0B
        LD HL,(TXTTAB)
        EX DE,HL
; ----------------------------------------------------------------------
; PROG_UNSCRAMBLE_1 -- decode-loop body: test for program end, then decode one byte with the dual key.
;   In:        DE -> current program byte, B/C = the two rotating key indices.
;   Out:       RET when DE == VARTAB (whole program decoded); else one byte decoded and DE advanced.
;   Clobbers:  A, HL (and updates the byte at DE).
;   Algorithm: Compare DE to VARTAB (end); if equal return; otherwise apply (byte-B) XOR atn[C], then
;              XOR sin[B], then +C, and store; fall into the key-index update.
; ----------------------------------------------------------------------
PROG_UNSCRAMBLE_1:
        LD HL,(VARTAB)
        CALL CMP_HL_DE
        RET Z
        ; first key stream: index the ATN coefficient bytes by C
        LD HL,FP_POLY_ATN_COEFFS
        LD A,L
        ADD A,C
        LD L,A
        LD A,H
        ADC A,$00
        LD H,A
        LD A,(DE)
        SUB B
        XOR (HL)
        PUSH AF
        ; second key stream: index the SIN coefficient bytes by B
        LD HL,FP_POLY_SIN_COEFFS
        LD A,L
        ADD A,B
        LD L,A
        LD A,H
        ADC A,$00
        LD H,A
        POP AF
        XOR (HL)
        ADD A,C
        ; store the decoded program byte back in place
        LD (DE),A
        INC DE
        DEC C
        JR NZ,PROG_UNSCRAMBLE_2
        LD C,$0B
; ----------------------------------------------------------------------
; PROG_UNSCRAMBLE_2 -- advance the dual key indices (B cycles 13, C cycles 11) for the next byte.
;   In:        B, C = key indices.
;   Out:       C decremented (reloaded to 11 at 0), B decremented (reloaded to 13 at 0); loops to decode next.
;   Clobbers:  B, C.
;   Algorithm: Step both rotating counters with wrap-around so the two key streams cycle at periods 11 and
;              13, then re-enter the decode loop.
; ----------------------------------------------------------------------
PROG_UNSCRAMBLE_2:
        DEC B
        JR NZ,PROG_UNSCRAMBLE_1
        LD B,$0D
        JR PROG_UNSCRAMBLE_1
; ----------------------------------------------------------------------
; PROG_SCRAMBLE -- re-encode the in-memory program for protected (SAVE ",P") storage; inverse of UNSCRAMBLE.
;   In:        TXTTAB = program start, VARTAB = program end; program is in plain token form.
;   Out:       the program text encoded in place; RET at the end.
;   Clobbers:  A, BC, DE, HL.
;   Algorithm: Exact inverse of PROG_UNSCRAMBLE using the same two key streams in mirrored order: for each
;              byte, b = ((byte - C) XOR sin_key[B]); then b = (b XOR atn_key[C]) + B; store; then step C
;              (cycle 11) and B (cycle 13). Produces the encoded image written by a protected SAVE so a LIST
;              cannot reveal it.
; ----------------------------------------------------------------------
PROG_SCRAMBLE:
        LD BC,$0D0B
        LD HL,(TXTTAB)
        EX DE,HL
; ----------------------------------------------------------------------
; PROG_SCRAMBLE_1 -- encode-loop body: end test then encode one byte with the dual key.
;   In:        DE -> current program byte, B/C = rotating key indices.
;   Out:       RET at VARTAB; else one byte encoded, DE advanced.
;   Clobbers:  A, HL (and the byte at DE).
;   Algorithm: Compare DE to VARTAB; if at end return; else (byte-C) XOR sin[B], XOR atn[C], +B, store;
;              fall into the key-index update.
; ----------------------------------------------------------------------
PROG_SCRAMBLE_1:
        LD HL,(VARTAB)
        CALL CMP_HL_DE
        RET Z
        ; first key stream (encode swaps the two): index SIN coefficient bytes by B
        LD HL,FP_POLY_SIN_COEFFS
        LD A,L
        ADD A,B
        LD L,A
        LD A,H
        ADC A,$00
        LD H,A
        LD A,(DE)
        SUB C
        XOR (HL)
        PUSH AF
        ; second key stream: index ATN coefficient bytes by C
        LD HL,FP_POLY_ATN_COEFFS
        LD A,L
        ADD A,C
        LD L,A
        LD A,H
        ADC A,$00
        LD H,A
        POP AF
        XOR (HL)
        ADD A,B
        LD (DE),A
        INC DE
        DEC C
        JR NZ,PROG_SCRAMBLE_2
        LD C,$0B
; ----------------------------------------------------------------------
; PROG_SCRAMBLE_2 -- advance the dual key indices for the encoder (C cycles 11, B cycles 13).
;   In:        B, C = key indices.
;   Out:       C stepped (reload 11), B stepped via DJNZ (reload 13); loops to encode the next byte.
;   Clobbers:  B, C.
;   Algorithm: Step both rotating counters with wrap-around (mirroring PROG_UNSCRAMBLE_2) so encode and
;              decode use identical key cycles.
; ----------------------------------------------------------------------
PROG_SCRAMBLE_2:
        DJNZ PROG_SCRAMBLE_1
        LD B,$0D
        JR PROG_SCRAMBLE_1
; [RE] RET unless SAVTXT ($0844) == $FFFF, in which case fall into the function-call guard.
DIRECT_MODE_GUARD:
        PUSH HL
        LD HL,(SAVTXT)
        LD A,H
        AND L
        POP HL
        INC A
        RET NZ
; [RE] Illegal-direct guard: if the 'running a program' flag ($0C99) is clear -> $0D5C (Illegal direct), else RET preserving AF. Statements that need a stored line call here.
ILLEGAL_DIRECT_CHECK:
        PUSH AF
        LD A,(LOAD_PROTECT_FLAG)
        OR A
        JP NZ,ERROR_FC
        POP AF
        RET
RND_SECTOR_NUM:
        NOP
        NOP
RND_FIELD_PTR:
        NOP
        NOP
RND_SECTOR_PTR:
        NOP
        NOP
RND_GET_PUT_DIR:
        NOP

; ======================================================================
; COLD / WARM START + SIGN-ON
; ======================================================================
; [RE] Warm-start (READY/Ok) re-entry: re-init the program-end sentinel ($0846), then enter the direct-mode main loop. ILLEGAL_DIRECT_CHECK_6 ($81C6) falls through to the immediate-statement executor at $0E23 if the start-up command pointer ($0850/$8350) is non-empty, else jumps to NEWSTT.
WARM_START:
        CALL RUN_CLEAR
        LD HL,(TXTTAB)
        DEC HL
        LD (HL),$00
        LD HL,(COLD_SET_WIDTH_11)
        LD A,(HL)
        OR A
        JP NZ,LOAD_PROGRAM
        JP NEWSTT_READY
SUB_81C6_1:
        NOP
        NOP
; [RE] Interpreter cold-start entry (the $1000 relocator JPs here after copying the body up to $3000). Initializes the runtime: BDOS handshake, RAM-top, the BASIC work cells, the RPC trigger patch (see $8240), and the console width from the SoftCard card config (see $827A).
COLD_START:
        LD HL,COLD_STACK_BASE
        LD SP,HL
        XOR A
        LD (LOAD_PROTECT_FLAG),A
        LD (TOP_OF_STACK_ROOM),HL
        LD (SAVSTK),HL
        LD HL,($0001)
        LD (STMT_SYSTEM_WBOOT+1),HL
        LD A,H
        LD ($0107),A
        LD BC,$0004
        ADD HL,BC
        LD E,(HL)
        INC HL
        LD D,(HL)
        EX DE,HL
        LD (INKEY_SCAN_2+1),HL
        LD (RPC_CONST_POLL_1+1),HL
        LD (STMT_FOR_8+1),HL
        EX DE,HL
        INC HL
        INC HL
        LD E,(HL)
        INC HL
        LD D,(HL)
        EX DE,HL
        LD (CONIN_1+1),HL
        EX DE,HL
        INC HL
        INC HL
        LD E,(HL)
        INC HL
        LD D,(HL)
        EX DE,HL
        LD (OUTDO_DEVICE2_1+1),HL
        EX DE,HL
        INC HL
        INC HL
        LD E,(HL)
        INC HL
        LD D,(HL)
        EX DE,HL
        LD (OUTDO_DEVICE_1+1),HL
        EX DE,HL
        LD DE,$F1F8
        ADD HL,DE
        LD DE,DISK_RAISE_DISK_I_O_ERROR
        LD (HL),E
        INC HL
        LD (HL),D
        INC HL
        LD DE,DISK_RAISE_DRIVE_SELECT_ERROR
        LD (HL),E
        INC HL
        LD (HL),D
        INC HL
        LD DE,DISK_RAISE_DISK_READ_ONLY
        LD (HL),E
        INC HL
        LD (HL),D
        INC HL
        LD DE,DISK_RAISE_FILE_READ_ONLY
        LD (HL),E
        INC HL
        LD (HL),D
        LD HL,DISK_RAISE_RESET_ERROR
        LD ($0001),HL
        LD HL,(Z_CPU)
        LD (RPC_TRIGGER_STORE+1),HL
        LD C,S_BDOSVER
        CALL BDOS
        LD (L_08CB),A
        OR A
        LD HL,$1514
        JP Z,SUB_8240_1
        LD HL,$2221
SUB_8240_1:
        LD (BDOS_FN_RECREAD),HL
        LD HL,$FFFE
        LD (SAVTXT),HL
        XOR A
        LD (CTRL_O_SUPPRESS),A
        LD (L_0B10),A
        LD (CHAIN_BREAK_FLAG),A
        LD (CHAIN_PRESERVE_FLAG),A
        LD (ERRFLG),A
        LD HL,$0000
        LD (OUTPUT_COLUMN),HL
        LD (COLOR),A
        LD A,(SLTTYP3)
        SUB $03
        JR Z,COLD_SET_WIDTH+1
        DEC A
        JR Z,COLD_SET_WIDTH+1
        LD A,$28
; [RE] Select terminal line width during cold start: reads the configured console type ($F3BB) and sets the line-width work cell (GFX_READ_COORD_PAIR_12, $4B97) to 40 ($28) or the wide default, then initializes the file-control / disk-parameter pointers (WIDTH_SET_CONSOLE).
; [RE] 40/80 line-width flag-skip. Default console falls through $8284 LD A,$28 (40), and 01 at $8286 swallows 3E 50 so A stays $28. JR Z,COLD_SET_WIDTH+1 ($827F/$8282, console type 3/4) enters $8287 = LD A,$50 (80). Converge at $8289 store of the width cell.
COLD_SET_WIDTH:
        LD BC,$503E
        LD (GFX_STMT_HPLOT_9),A
        CALL WIDTH_SET_CONSOLE
        LD HL,$0080
        LD (FIELD_BUF_ADDR_LIMIT),HL
        LD HL,TEMPST
        LD (TEMPPT),HL
        LD HL,DEFFN_FRAME_PTR
        LD (FN_FRAME_LIST_HEAD),HL
        LD HL,($0006)
        LD (MEMSIZ),HL
        LD A,$03
        LD (MAX_FILE_NUM),A
        LD HL,COLD_SET_WIDTH_10
        LD (COLD_SET_WIDTH_11),HL
        LD A,(COLD_SET_WIDTH_12)
        OR A
        JP NZ,COLD_SET_WIDTH_13
        INC A
        LD (COLD_SET_WIDTH_12),A
        LD HL,$0080
        LD A,(HL)
        OR A
        LD (COLD_SET_WIDTH_11),HL
        JP Z,COLD_SET_WIDTH_13
        LD B,(HL)
        INC HL
COLD_SET_WIDTH_1:
        LD A,(HL)
        DEC HL
        LD (HL),A
        INC HL
        INC HL
        DEC B
        JP NZ,COLD_SET_WIDTH_1
        DEC HL
        LD (HL),$00
        LD (COLD_SET_WIDTH_11),HL
        LD HL,$007F
        CALL CHRGET
        OR A
        JP Z,COLD_SET_WIDTH_13
        CP $2F
        JR Z,COLD_SET_WIDTH_3
        DEC HL
        LD (HL),$22
        LD (COLD_SET_WIDTH_11),HL
        INC HL
COLD_SET_WIDTH_2:
        CP $2F
        JR Z,COLD_SET_WIDTH_3
        CALL CHRGET
        OR A
        JR NZ,COLD_SET_WIDTH_2
        JP COLD_SET_WIDTH_13
COLD_SET_WIDTH_3:
        LD (HL),$00
COLD_SET_WIDTH_4:
        CALL CHRGET
COLD_SET_WIDTH_5:
        CP $53
        JR Z,COLD_SET_WIDTH_9
        CP $4D
        PUSH AF
        JP Z,COLD_SET_WIDTH_6
        CP $46
        JP NZ,RAISE_SYNTAX_ERROR
COLD_SET_WIDTH_6:
        CALL CHRGET
        CALL SYNCHR
        DEFB    ':'                      ; inline char arg consumed by the preceding CALL
        CALL LINGET_OR_AMP
        POP AF
        JR Z,COLD_SET_WIDTH_7
        LD A,D
        OR A
        JP NZ,ERROR_FC
        LD A,E
        CP $10
        JP NC,ERROR_FC
        LD (MAX_FILE_NUM),A
        JR COLD_SET_WIDTH_8
COLD_SET_WIDTH_7:
        EX DE,HL
        LD (MEMSIZ),HL
        EX DE,HL
COLD_SET_WIDTH_8:
        DEC HL
        CALL CHRGET
        JR Z,COLD_SET_WIDTH_13
        CALL SYNCHR
        DEFB    '/'                      ; inline char arg consumed by the preceding CALL
        JP COLD_SET_WIDTH_5
COLD_SET_WIDTH_9:
        CALL CHRGET
        CALL SYNCHR
        DEFB    ':'                      ; inline char arg consumed by the preceding CALL
        CALL LINGET_OR_AMP
        EX DE,HL
        LD (FIELD_BUF_ADDR_LIMIT),HL
        EX DE,HL
        JR COLD_SET_WIDTH_8
COLD_SET_WIDTH_10:
        NOP
COLD_SET_WIDTH_11:
        NOP
        NOP
COLD_SET_WIDTH_12:
        NOP
COLD_SET_WIDTH_13:
        DEC HL
        LD HL,(MEMSIZ)
        PUSH HL
        POP HL
        DEC HL
        LD (MEMSIZ),HL
        DEC HL
        PUSH HL
        LD A,(MAX_FILE_NUM)
        LD HL,SUB_81C6_1
        LD (FILTAB_SLOT0_SEED),HL
        LD DE,FILTAB
        LD (MAX_FILE_NUM),A
        INC A
        LD BC,FCB.FLD_BUF_PTR
COLD_SET_WIDTH_14:
        EX DE,HL
        LD (HL),E
        INC HL
        LD (HL),D
        INC HL
        EX DE,HL
        ADD HL,BC
        PUSH HL
        LD HL,(FIELD_BUF_ADDR_LIMIT)
        LD BC,FCB.RND_BUF
        ADD HL,BC
        LD B,H
        LD C,L
        POP HL
        DEC A
        JR NZ,COLD_SET_WIDTH_14
        INC HL
        LD (TXTTAB),HL
        LD (SAVSTK),HL
        POP DE
        LD A,E
        SUB L
        LD L,A
        LD A,D
        SBC A,H
        LD H,A
        JP C,STACK_OVERFLOW_RAISE
        LD B,$03
COLD_SET_WIDTH_15:
        OR A
        LD A,H
        RRA
        LD H,A
        LD A,L
        RRA
        LD L,A
        DJNZ COLD_SET_WIDTH_15
        LD A,H
        CP $02
        JR C,COLD_SET_WIDTH_16
        LD HL,$0200
COLD_SET_WIDTH_16:
        LD A,E
        SUB L
        LD L,A
        LD A,D
        SBC A,H
        LD H,A
        JP C,STACK_OVERFLOW_RAISE
        LD (MEMSIZ),HL
        EX DE,HL
        LD (TOP_OF_STACK_ROOM),HL
        LD (FRETOP),HL
        LD SP,HL
        LD (SAVSTK),HL
        LD HL,(TXTTAB)
        EX DE,HL
        CALL GC_CHECK_AND_COLLECT
        LD A,L
        SUB E
        LD L,A
        LD A,H
        SBC A,D
        LD H,A
        DEC HL
        DEC HL
        PUSH HL
        CALL GFX_STMT_HOME
        LD HL,SIGNON_BANNER_HEADER
        CALL STROUT
        POP HL
        CALL FOUT
        LD HL,MSG_BYTES_FREE
        CALL STROUT
        LD HL,STROUT
        LD (STROUT_CALL_VECTOR),HL
        CALL CRLF
        LD HL,SUB_0D28
        LD ($0101),HL
        JP WARM_START
        DEFB    "\r\n\n"
        DEFB    "Owned by Microsoft"     ; string
        DEFB    $0D                      ; terminator
        DEFB    "\n\0"
; Data string ' Bytes free'+CRLF -- free-memory suffix printed after the byte count in the cold sign-on banner (loaded at $83DF, emitted via STROUT)
MSG_BYTES_FREE:
        DEFB    " Bytes free"            ; string
        DEFB    $0D                      ; terminator
        DEFB    "\n\0"
; Data string: leading sign-on banner text (CRLF CRLF CRLF then 'BASIC-80 ...'), printed first by COLD_SIGNON ($83D5 LD HL,$841D / STROUT) ahead of the free-bytes count
SIGNON_BANNER_HEADER:
        DEFB    "\r\n\r\n\r\nBASIC-80 Rev"
        DEFB    ". 5.2\r\n[Apple CP/M Version]\r\nCopyright (C) 1980 by Micro"
        DEFB    "soft\r\nCreated: 26-Aug-80\r\n\0"
        DEFB    "\0"
; [RE] Top of the relocated interpreter (LDDR copy boundary): the $1000 relocator copies INTERP_RUN_START..INTERP_COPY_END-1 ($3000-$8482) up from the load image. $8483-$84F1 is dead .COM padding (not copied).
INTERP_COPY_END:
        DEFS    69, $00                  ; fill
; [RE] Cold-start stack base: cold start does LD SP,COLD_STACK_BASE ($81D6) and seeds the stack-room pointer (TOP_OF_STACK_ROOM $0842) and SAVSTK from it, then resizes the work-area from CP/M memory top ($0001). The byte here is $00 (head of the 42-byte zero fill) and doubles as the link-null sentinel before program text, so TXTTAB = COLD_STACK_BASE+1.
COLD_STACK_BASE:
        DEFS    42, $00                  ; fill
INTERP_RUN_TOP:
    IFDEF GBASIC
    ENT
    ENDIF

    IFDEF GBASIC
    SAVEBIN "GBASIC.bin", $0100, $6400
    ELSE
    SAVEBIN "MBASIC.bin", $0100, $6000
    ENDIF
